    private let pdfCacheLock = NSLock()
        private var pdfCacheStorage: PDFCacheManager?
    private var pdfCache: PDFCacheManager {
        if let cache = pdfCacheStorage { return cache }
        pdfCacheLock.lock()
        defer { pdfCacheLock.unlock() }
        if let cache = pdfCacheStorage { return cache }
        let cache = PDFCacheManager()
        pdfCacheStorage = cache
        return cache
    }

