    private func currentBackingScale() -> CGFloat {
        max(1.0,
            window?.backingScaleFactor
            ?? window?.screen?.backingScaleFactor
            ?? NSScreen.main?.backingScaleFactor
            ?? 2.0)
    }

    private func ceilToDevicePixels(_ value: CGFloat, scale: CGFloat) -> CGFloat {
        guard value.isFinite, value > 0, scale.isFinite, scale > 0 else { return max(0, value) }
        return ceil(value * scale) / scale
    }

    private func floorToDevicePixels(_ value: CGFloat, scale: CGFloat) -> CGFloat {
        guard value.isFinite, value > 0, scale.isFinite, scale > 0 else { return max(0, value) }
        return floor(value * scale) / scale
    }

    private func attributedSingleLineTypographicWidth(_ s: NSAttributedString) -> CGFloat {
        let line = CTLineCreateWithAttributedString(s)
        let w = CTLineGetTypographicBounds(line, nil, nil, nil)
        return CGFloat(w)
    }

    private func leftAuthorYearHeaderAttributes(paragraphStyle: NSParagraphStyle) -> [NSAttributedString.Key: Any] {
        let headerColor = leftTablePanelTextColors(isSelected: false, isActive: true).title
        let attributes: [NSAttributedString.Key: Any] = [
            .font: resolvedUIFontFromSettings(defaultSize: 12.5, weight: .medium),
            .foregroundColor: headerColor,
            .kern: -0.15,
            .paragraphStyle: paragraphStyle
        ]
        return attributes
    }

    private func invalidateSidebarHardMinWidthCache() {
        sidebarHardMinWidthCache = 0
        sidebarHardMinWidthCacheScale = 0
        invalidateSidebarPageContentWidthCache()
    }

    private func invalidateSidebarPageContentWidthCache() {
        sidebarPageContentWidthCache = 0
        sidebarPageContentWidthCachePage = -1
        sidebarPageContentWidthCacheRange = 0..<0
        sidebarPageContentWidthCacheScale = 0
        sidebarPageContentWidthCacheFilteredCount = 0
        sidebarPageContentWidthCacheKeywordsCount = 0
    }

    private func sidebarHardMinWidth() -> CGFloat {
        let scale = currentBackingScale()
        if sidebarHardMinWidthCache.isFinite,
           sidebarHardMinWidthCache > 0,
           sidebarHardMinWidthCacheScale.isFinite,
           abs(sidebarHardMinWidthCacheScale - scale) < 0.01 {
            return sidebarHardMinWidthCache
        }

        let pstyle = NSMutableParagraphStyle()
        pstyle.lineBreakMode = .byClipping

        // Match the exact typography used by the real sidebar header label
        // (`updateLeftHeaderText()`), otherwise the computed minimum can be
        // a few points too small and appear slightly off-center.
        applyTwoColumnTabStops(to: pstyle)
        let attr = NSAttributedString(
            string: "Author & Year",
            attributes: [
                .font: resolvedUIFontFromSettings(defaultSize: 12, weight: .semibold),
                .foregroundColor: leftHeaderTextColor(),
                .paragraphStyle: pstyle
            ]
        )
        let labelW = attributedSingleLineTypographicWidth(attr)

        // Enclosing glass card bezel: PANEL_INSET (card inset) + leftRowTextInset (list text inset).
        // Apply symmetrically so the centering constraint is exact.
        let bezelX = PANEL_INSET + leftRowTextInset
        var needed = labelW + (2 * bezelX)
        needed = ceilToDevicePixels(needed, scale: scale)

        sidebarHardMinWidthCache = max(0, needed)
        sidebarHardMinWidthCacheScale = scale
        return sidebarHardMinWidthCache
    }

    private func sidebarHardMinWidthFast() -> CGFloat {
        let scale = currentBackingScale()
        if sidebarHardMinWidthCache.isFinite,
           sidebarHardMinWidthCache > 0,
           sidebarHardMinWidthCacheScale.isFinite,
           abs(sidebarHardMinWidthCacheScale - scale) < 0.01 {
            return sidebarHardMinWidthCache
        }

        if AnimationGuard.shouldDeferHeavyWork {
            if !sidebarHardMinWidthWarmupScheduled {
                sidebarHardMinWidthWarmupScheduled = true
                AnimationGuard.deferWork(label: "sidebar_min_width_warmup") { [weak self] in
                    guard let self else { return }
                    _ = self.sidebarHardMinWidth()
                    self.sidebarHardMinWidthWarmupScheduled = false
                }
            }
            return max(220, lastSidebarWidth)
        }

        return sidebarHardMinWidth()
    }

    private func sidebarTableContentDrivenWidth(maxLeft: CGFloat) -> CGFloat? {
        guard didAdoptTableDrivenSidebarWidth else { return nil }
        guard maxLeft.isFinite, maxLeft > 0 else { return nil }
        guard !filtered.isEmpty else { return nil }

        // We want the sidebar width to match the publications table's *content* width for the
        // currently visible page (the point where no keyword text truncates).
        let range = launchPageRangeForSidebarSizing()
        let scale = currentBackingScale()
        if !sidebarPageContentWidthCacheIsValid(range: range, scale: scale) {
            refreshSidebarPageContentWidthCache(reason: "sidebar_min_width")
        }
        let neededColumnWidth = sidebarPageContentWidthCache
        guard neededColumnWidth.isFinite, neededColumnWidth > 0 else {
            return min(maxLeft, sidebarHardMinWidth())
        }

        // Convert from table content width (scrollable document width) to the outer left panel width.
        // `layoutLeftContainerSubviews()` sets `tableScroll.frame.width = leftContentView.width - (2 * PANEL_INSET)`.
        let neededSidebarWidth = neededColumnWidth + (2 * PANEL_INSET)

        return min(maxLeft, max(sidebarHardMinWidth(), neededSidebarWidth))
    }

    private func sidebarPageContentWidthCacheIsValid(range: Range<Int>, scale: CGFloat) -> Bool {
        guard sidebarPageContentWidthCache.isFinite, sidebarPageContentWidthCache > 0 else { return false }
        guard sidebarPageContentWidthCachePage == currentPageIndex else { return false }
        guard sidebarPageContentWidthCacheRange == range else { return false }
        guard sidebarPageContentWidthCacheFilteredCount == filtered.count else { return false }
        guard sidebarPageContentWidthCacheKeywordsCount == keywordsFromAppleScript.count else { return false }
        guard sidebarPageContentWidthCacheScale.isFinite, abs(sidebarPageContentWidthCacheScale - scale) < 0.01 else { return false }
        return true
    }

    private func refreshSidebarPageContentWidthCache(reason: String) {
        _ = reason
        guard !filtered.isEmpty else {
            invalidateSidebarPageContentWidthCache()
            return
        }
        let range = launchPageRangeForSidebarSizing()
        guard !range.isEmpty else {
            invalidateSidebarPageContentWidthCache()
            return
        }

        if cachedMaxLeftTextWidth <= 0 {
            rebuildLeftRowContentMetrics()
        }

        let gutter: CGFloat = 10
        let leftColumn = max(180, cachedMaxLeftTextWidth + gutter)
        let keywordWidth = maxKeywordWidthForRange(range)
        let rightColumn = max(keywordWidth, leftKeywordMinColumnWidth())

        let contentExtent = leftRowTextInset + leftColumn + keywordSeparatorGap + rightColumn + leftRowTextInset
        let scale = currentBackingScale()
        let columnWidth = ceilToDevicePixels(max(220, contentExtent), scale: scale)

        sidebarPageContentWidthCache = columnWidth
        sidebarPageContentWidthCacheScale = scale
        sidebarPageContentWidthCachePage = currentPageIndex
        sidebarPageContentWidthCacheRange = range
        sidebarPageContentWidthCacheFilteredCount = filtered.count
        sidebarPageContentWidthCacheKeywordsCount = keywordsFromAppleScript.count
    }

