    private func terminalDefaultProfileBackgroundColor() -> NSColor? {
        let defaults = UserDefaults(suiteName: "com.apple.Terminal")
        guard let profile = defaults?.string(forKey: "Default Window Settings"),
              let windowSettings = defaults?.dictionary(forKey: "Window Settings"),
              let profileDict = windowSettings[profile] as? [String: Any] else {
            return nil
        }
        let data = (profileDict["BackgroundColor"] as? Data) ?? (profileDict["Background Color"] as? Data)
        guard let data else { return nil }
        guard let color = try? NSKeyedUnarchiver.unarchivedObject(ofClass: NSColor.self, from: data) else {
            return nil
        }
        return color.usingColorSpace(.sRGB) ?? color
    }

    private func terminalDefaultProfileFallbackColor() -> NSColor {
        NSColor(srgbRed: 0.3916090727, green: 0.08498670906, blue: 0.06663744152, alpha: 0.4927956587)
    }

    private func glassAppearanceIsDark() -> Bool {
        let settings = AppSettingsStore.shared.current.appearance
        let style = settings.glassStyleEnabled ? settings.glassStyle : .followApp
        switch style {
        case .light:
            return false
        case .dark:
            return true
        case .followApp:
            // NSGlassEffectView has no per-view light/dark override, so we only override
            // glass styling/tint when the user explicitly chooses Light/Dark. Otherwise
            // we track the window appearance to avoid visual regressions.
            let appearance = window?.effectiveAppearance ?? NSApplication.shared.effectiveAppearance
            return (appearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua)
        }
    }

    private func resolvedGlassTintBaseColor(isDark: Bool) -> NSColor {
        let settings = AppSettingsStore.shared.current.appearance
        let source: AppSettings.Appearance.GlassTintSource = settings.glassTintSourceEnabled ? settings.glassTintSource : .none
        switch source {
        case .none:
            let base = resolvedSystemColor(.windowBackgroundColor)
            let neutral = isDark ? NSColor.black : NSColor.white
            return blend(base, neutral, t: isDark ? 0.35 : 0.18)
        case .appAccent:
            let accent = resolvedAppAccentColor()
            let rgb = accent.usingColorSpace(.deviceRGB) ?? accent
            return rgb.withAlphaComponent(1.0)
        case .custom:
            guard settings.customGlassTintEnabled else {
                return resolvedAppAccentColor()
            }
            if let color = colorFromHex(settings.customGlassTintHex) {
                let rgb = color.usingColorSpace(.deviceRGB) ?? color
                return rgb.withAlphaComponent(1.0)
            }
            return resolvedAppAccentColor()
        }
    }

