    private func updateNavControlAccentAppearance() {
        let fill = navControlAccentFillColor()
        if let glass = navControlBackground as? NSGlassEffectView {
            glass.style = .regular
            glass.tintColor = fill
        } else if let effect = navControlBackground as? NSVisualEffectView {
            effect.material = .headerView
            effect.blendingMode = .withinWindow
            effect.state = .active
            effect.isEmphasized = false
            effect.layer?.backgroundColor = fill.cgColor
        }
        navControlBackground.wantsLayer = true
        navControlBackground.layer?.backgroundColor = fill.cgColor
        navControlBackground.layer?.shadowOpacity = 0
        navControlBackground.layer?.shadowRadius = 0
        navControlBackground.layer?.shadowOffset = .zero
        navControlBackground.layer?.masksToBounds = true
        if #available(macOS 10.13, *) {
            navControlBackground.layer?.cornerCurve = .continuous
        }
        enforceActiveVisualEffectState(navControlBackground)
        navControlOrnamentOverlay.isHidden = true
    }

    private func updateSidebarToggleAccentAppearance() {
        let fill = navControlAccentFillColor()
        if ToolbarAutoScale.isEnabled {
            if let glass = sidebarControlBackground as? NSGlassEffectView {
                glass.style = .regular
                glass.tintColor = fill
            } else if let effect = sidebarControlBackground as? NSVisualEffectView {
                effect.material = .headerView
                effect.blendingMode = .withinWindow
                effect.state = .active
                effect.isEmphasized = false
                effect.layer?.backgroundColor = fill.cgColor
            }
            sidebarControlBackground.wantsLayer = true
            sidebarControlBackground.layer?.backgroundColor = fill.cgColor
            sidebarControlBackground.layer?.shadowOpacity = 0
            sidebarControlBackground.layer?.shadowRadius = 0
            sidebarControlBackground.layer?.shadowOffset = .zero
            sidebarControlBackground.layer?.masksToBounds = true
            if #available(macOS 10.13, *) {
                sidebarControlBackground.layer?.cornerCurve = .continuous
            }
            enforceActiveVisualEffectState(sidebarControlBackground)
            sidebarControlOrnamentOverlay.isHidden = true
            sidebarToggleButton.layer?.backgroundColor = NSColor.clear.cgColor
            sidebarMenuButton.layer?.backgroundColor = NSColor.clear.cgColor
        } else {
            sidebarControlOrnamentOverlay.isHidden = false
            sidebarToggleButton.layer?.backgroundColor = NSColor.clear.cgColor
            sidebarMenuButton.layer?.backgroundColor = NSColor.clear.cgColor
        }
    }

    private func toolbarSeparatorPalette() -> (fill: NSColor, glow: NSColor, glowOpacity: Float) {
        let base = (baseGlassStyleTintColor().usingColorSpace(.deviceRGB) ?? baseGlassStyleTintColor())
        let isDark = (window?.effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua)
        let isActive = isWindowActiveForAppearance()
        let fillAlpha: CGFloat = isDark ? (isActive ? 0.18 : 0.12) : (isActive ? 0.12 : 0.08)
        let glowAlpha: CGFloat = isDark ? (isActive ? 0.35 : 0.22) : (isActive ? 0.26 : 0.18)
        let glowOpacity: Float = isDark ? (isActive ? 0.42 : 0.24) : (isActive ? 0.30 : 0.18)
        let fill = NSColor(srgbRed: base.redComponent,
                           green: base.greenComponent,
                           blue: base.blueComponent,
                           alpha: fillAlpha)
        let glowBase = isDark ? NSColor.white : NSColor.black
        let glow = glowBase.withAlphaComponent(glowAlpha)
        return (fill, glow, glowOpacity)
    }

    private func splitDividerPalette() -> (fill: NSColor, glow: NSColor, glowOpacity: Float) {
        let base = toolbarSeparatorPalette()
        let fill = base.fill.withAlphaComponent(min(1, base.fill.alphaComponent + 0.08))
        let glow = base.glow.withAlphaComponent(min(1, base.glow.alphaComponent + 0.06))
        let glowOpacity = min(1, base.glowOpacity + 0.08)
        return (fill, glow, glowOpacity)
    }

    private func toolbarSeparatorForegroundColor() -> NSColor {
        // Use the search bar's actual foreground as the ground truth.
        let base = cachedSearchForegroundColor
            ?? searchField.textColor
            ?? (searchField.cell as? NSSearchFieldCell)?.textColor
            ?? ToolbarForegroundTheme.shared.palette.primary
        var resolved = base
        searchField.effectiveAppearance.performAsCurrentDrawingAppearance {
            resolved = base.usingColorSpace(.deviceRGB) ?? base
        }
        return resolved
    }

