        sidebarMenuButton.restingTintColor = foreground
        backButton.restingTintColor = foreground
        forwardButton.restingTintColor = foreground
        rightAuxHeaderLabel.textColor = foreground
        annotationsPanelController?.setEmptyMessageColor(foreground)
        sidebarDivider.apply(fill: foreground, glow: .clear, glowOpacity: 0)
        navDivider.apply(fill: foreground, glow: .clear, glowOpacity: 0)
