    private func applyPDFFindButtonGlassTheme() {
        let tint = pdfFindGlassTintColor()
        let targets = [pdfFindPrevGlassBackground, pdfFindNextGlassBackground].compactMap { $0 }
        for card in targets {
            var config = dropdownGlassConfig()
            config.cornerRadius = card.cornerRadius
            config.tint = tint
            card.updateConfig(config)
            card.invalidateGlass(reason: "pdf_find_tint")
        }
    }

    private func applyRootGlassTintToUI(reason: String, deferHeavyLayout: Bool) {
        let shouldRefreshResolvedColors = (reason == "startup"
                                           || reason == "system_colors"
                                           || reason == "appearance"
                                           || reason == "settings")
        applyLiquidGlassPanelTints()
        applyShortcutResultGlassTint()
        updateWindowGlassTintIfNeeded()

        updateToolbarGlassTint()
        updateCardEdgeGlowIntensity()
        applyEmbeddedSearchBarTheme(to: searchBackground)
        applyEmbeddedSearchBarTheme(to: rightAuxAskBackground)
        applySearchBarTheme(to: pdfFindBackgroundView, tintOverride: pdfFindGlassTintColor())
        applyPDFFindButtonGlassTheme()
        if let layer = pdfFindBackgroundView.layer {
            layer.shadowOpacity = 0
            layer.shadowRadius = 0
            layer.shadowOffset = .zero
        }
        let shouldDefer = deferHeavyLayout || AnimationGuard.shouldDeferHeavyWork
        let heavyWork = { [weak self] in
            guard let self else { return }
            self.rootGlassTintHeavyWorkItem = nil
            self.updateEmbeddedSearchAppearance(animated: false)
            self.updatePDFFindCapsuleGeometry()
            if shouldRefreshResolvedColors {
                self.refreshResolvedSystemColors()
                self.updateHoverTooltipAppearance()
                self.updateSearchFieldIconColorForCurrentState()
            }
            // Ensure keyword highlights stay unified with RootGlassTint.
            if self.isShowingPDF == false { self.updateDetails() }
        }
        if shouldDefer {
            rootGlassTintHeavyWorkItem?.cancel()
            let work = DispatchWorkItem(block: heavyWork)
            rootGlassTintHeavyWorkItem = work
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.08, execute: work)
        } else {
            heavyWork()
        }
    }

    private func applyGlassTint(_ tint: NSColor, to view: NSView?) {
        guard let view else { return }
        clearGlassFallbackOverlay(for: view)
        if let glass = view as? NSGlassEffectView {
            glass.tintColor = tint
        } else if let effect = view as? NSVisualEffectView {
            effect.layer?.backgroundColor = tint.cgColor
        } else {
            view.layer?.backgroundColor = tint.cgColor
        }
    }

    private func setGlassFallbackOverlay(for view: NSView?, color: NSColor, enabled: Bool) {
        guard let view else { return }
        let id = ObjectIdentifier(view)
        if !enabled {
            if let overlay = glassFallbackOverlays.removeValue(forKey: id) {
                overlay.removeFromSuperview()
            }
            return
        }
        let overlay: NSView
        if let existing = glassFallbackOverlays[id], existing.superview === view {
            overlay = existing
        } else {
            let v = PassthroughView(frame: .zero)
            v.translatesAutoresizingMaskIntoConstraints = false
            v.wantsLayer = true
            v.layer?.masksToBounds = true
            let anchor = view.subviews.first
            view.addSubview(v, positioned: .below, relativeTo: anchor)
            NSLayoutConstraint.activate([
                v.leadingAnchor.constraint(equalTo: view.leadingAnchor),
                v.trailingAnchor.constraint(equalTo: view.trailingAnchor),
                v.topAnchor.constraint(equalTo: view.topAnchor),
                v.bottomAnchor.constraint(equalTo: view.bottomAnchor)
            ])
            glassFallbackOverlays[id] = v
            overlay = v
        }
        overlay.layer?.backgroundColor = color.cgColor
        let radius: CGFloat
        if let glass = view as? NSGlassEffectView {
            radius = glass.cornerRadius
        } else {
            radius = view.layer?.cornerRadius ?? 0
        }
        overlay.layer?.cornerRadius = radius
        if #available(macOS 10.13, *) {
            overlay.layer?.cornerCurve = view.layer?.cornerCurve ?? .continuous
        }
        overlay.isHidden = false
    }

    private func clearGlassFallbackOverlay(for view: NSView?) {
        setGlassFallbackOverlay(for: view, color: .clear, enabled: false)
    }

    private func applyGlassFallback(_ view: NSView?, baseColor: NSColor, clearChrome: Bool = false) {
        guard let view else { return }
        let base = (baseColor.usingColorSpace(.deviceRGB) ?? baseColor).withAlphaComponent(1.0)
        if clearChrome {
            clearGlassBorder(for: view)
            clearGlassShadow(for: view)
        }
        if let card = view as? GlassCardView {
            clearGlassFallbackOverlay(for: card)
            card.setGlassEnabled(false, fallbackColor: base)
            return
        }
        setGlassFallbackOverlay(for: view, color: base, enabled: true)
        if let glass = view as? NSGlassEffectView {
            glass.tintColor = base
            glass.wantsLayer = true
            glass.layer?.backgroundColor = base.cgColor
        } else if let effect = view as? NSVisualEffectView {
            effect.wantsLayer = true
            effect.layer?.backgroundColor = base.cgColor
        } else {
            view.wantsLayer = true
            view.layer?.backgroundColor = base.cgColor
        }
    }

