    }

    private func applyLeftHeaderGlassTint() {
        applyGlassTint(leftPanelGlassTintColor(), to: leftHeaderGlassBackground)
    }

    private func applyLiquidGlassPanelTints() {
        let settings = AppSettingsStore.shared.current.appearance
        let leftEnabled = settings.leftPanelGlassEnabled
        let rightEnabled = settings.rightAuxGlassEnabled
        let tint = panelClearGlassTintColor()
        let baseConfig = baseLiquidGlassConfig()

        func updateCard(_ card: GlassCardView?, tint: NSColor, flatFill: Bool = false) {
            guard let card else { return }
            card.setGlassEnabled(true, fallbackColor: nil)
            clearGlassFallbackOverlay(for: card)
            var config = card.config
            config.tint = tint
            config.transmission = baseConfig.transmission
            config.diffusionAmount = baseConfig.diffusionAmount
            config.flatFill = flatFill
            card.updateConfig(config)
        }

        if leftEnabled {
            if let leftCard = leftContainer as? GlassCardView {
                updateCard(leftCard, tint: leftPanelGlassTintColor(), flatFill: true)
            } else {
                applyGlassTint(leftPanelGlassTintColor(), to: leftContainer)
            }
            clearGlassChrome(for: leftContainer)
            applyLeftHeaderGlassTint()
            leftCardGlowView?.isHidden = false
        } else {
            let base = windowBackgroundSolidColor()
            applyGlassFallback(leftContainer, baseColor: base, clearChrome: true)
            applyGlassFallback(leftHeaderGlassBackground, baseColor: base, clearChrome: true)
            leftCardGlowView?.isHidden = true
        }

        if rightEnabled {
            if rightAuxContainer is GlassCardView {
                updateCard(rightAuxContainer as? GlassCardView, tint: tint)
            } else {
                applyRightAuxGlassTint()
            }
            applyShortcutResultGlassStyle(to: rightAuxContainer)
            clearGlassBorder(for: rightAuxContainer)
        } else {
            let base = windowBackgroundSolidColor()
            applyGlassFallback(rightAuxContainer, baseColor: base, clearChrome: true)
        }
        updateCard(rightSecondaryContainer, tint: tint)
        if let card = suggestionsBackground as? GlassCardView {
            updateCard(card, tint: tint)
        }
        if let card = menuBackground as? GlassCardView {
            updateCard(card, tint: tint)
        }

        if let underlay = leftTableUnderlayView {
            if leftEnabled {
                let tintColor = leftTableUnderlayTintColor()
                clearGlassFallbackOverlay(for: underlay)
                if let glass = underlay as? NSGlassEffectView {
                    glass.tintColor = tintColor
                } else if let effect = underlay as? NSVisualEffectView {
                    effect.layer?.backgroundColor = tintColor.cgColor
                } else {
                    underlay.layer?.backgroundColor = tintColor.cgColor
                }
            } else {
                applyGlassFallback(underlay, baseColor: windowBackgroundSolidColor(), clearChrome: true)
            }
        }
    }

    private func updateWindowGlassTintIfNeeded() {
        let bg = windowBackgroundView
        let tint = windowBackgroundGlassTintColor()
        if let glass = bg as? NSGlassEffectView {
            glass.tintColor = tint
        } else if let effect = bg as? NSVisualEffectView {
            effect.layer?.backgroundColor = tint.cgColor
        } else {
            bg.layer?.backgroundColor = tint.cgColor
        }
        installTitlebarTintBackground()
    }

    private func refreshResolvedSystemColors() {
        updateSharedToolbarForegroundPalette()
        applySearchFieldTheme(searchField,
                              placeholder: "Search")

        let leftHeaderText = leftHeaderTextColor()
        leftHeaderLabel.textColor = leftHeaderText
        rightAuxHeaderLabel.textColor = rightAuxHeaderTextColor()
        updateLeftHeaderText()
        updateRightAuxAskSeparatorStyle()
        leftHeaderRule.layer?.backgroundColor = resolvedSystemColor(.separatorColor).cgColor
        rightAuxHeaderRule.layer?.backgroundColor = resolvedSystemColor(.separatorColor).cgColor
        rightContainer.layer?.borderColor = resolvedSystemColor(.separatorColor).cgColor
        loadingLabel.textColor = resolvedForegroundColor(base: windowBackgroundSolidColor(),
                                                         tint: panelClearGlassTintColor(),
                                                         role: .primaryText)

        sidebarToggleButton.updateTint()
        sidebarMenuButton.updateTint()
        backButton.updateTint()
        forwardButton.updateTint()
        pageMenuButton.updateTint()
        updateToolbarSeparatorStyle()

        rightPanelLeftEdgeButton.updateTint()
        rightPanelZoteroEdgeButton.updateTint()
        rightPanelRightEdgeButton.updateTint()
        rightPanelSettingsEdgeButton.updateTint()

        updatePageStepperAppearance()
        updateShortcutResultPanelAppearance()
        updateLoadingOverlayAppearance()
        updateRightAuxAskSendIconAppearance()
        updateRightAuxAskFieldAppearance()
        updatePDFFindAppearance()
        applyRightPanelBaseColor()
        annotationsPanelController?.updateAppearance()

        updateVisibleRowSelectionStyling()
        refreshSuggestionTextColors()
        refreshMenuTextColors()
        rightPanelPillControl.refreshForegroundColors()
        annotationController?.refreshComposerAppearance()
        updateTitlebarTitleAppearance()
    }

    private func updatePageStepperAppearance() {
        pagePrevButton.updateTint()
        pageNextButton.updateTint()
    }

    private func updatePDFFindAppearance() {
        let tint = pdfFindGlassTintColor()
        let base = pdfFindBaseBackgroundColor()
        let text = ForegroundResolver.color(base: base, tint: tint, role: .primaryText)
        let secondary = ForegroundResolver.color(base: base, tint: tint, role: .secondaryText)
        let disabled = ForegroundResolver.color(base: base, tint: tint, role: .disabledIcon)
        let clearTint = ForegroundResolver.color(base: base,
                                                 tint: tint,
                                                 role: .icon,
                                                 context: "pdfFind.clear")
        let background = effectiveBackgroundColor(base: base, tint: tint)

        applySearchFieldTheme(pdfFindField,
                              placeholder: "Find in PDF",
                              textColor: text,
                              placeholderColor: secondary,
                              iconColor: text)
        if let cell = pdfFindField.cell as? NSSearchFieldCell {
            cell.cancelButtonCell = nil
        }

        pdfFindCountLabel.textColor = text
        pdfFindPrevButton.restingTintColor = text
        pdfFindNextButton.restingTintColor = text
        pdfFindPrevButton.disabledTintColor = disabled
        pdfFindNextButton.disabledTintColor = disabled
        pdfFindPrevButton.contrastBackgroundColor = background
        pdfFindNextButton.contrastBackgroundColor = background
        pdfFindPrevButton.updateTint()
        pdfFindNextButton.updateTint()

        let clearConfig = NSImage.SymbolConfiguration(pointSize: 11.5, weight: .regular)
        if let clearImage = NSImage(systemSymbolName: "xmark.circle.fill", accessibilityDescription: "Clear")?
            .withSymbolConfiguration(clearConfig) {
            clearImage.isTemplate = true
            pdfFindClearButton.image = clearImage
        }
        pdfFindClearButton.contentTintColor = clearTint
        if ContrastDebug.enabled {
            ContrastDebug.logApplied(context: "pdfFind.clear",
                                     role: .icon,
                                     background: background,
                                     foreground: clearTint,
                                     note: "apply")
        }
    }

    private func updateShortcutResultPanelAppearance() {
        let palette = shortcutResultTextPalette()
        let base = shortcutResultEffectiveBackgroundColor()
        let baseRGB = (base.usingColorSpace(.deviceRGB) ?? base)
        let isLight = relativeLuminance(baseRGB) > 0.55
        let chipBase = isLight ? NSColor.black : NSColor.white
        let chipBgAlpha: CGFloat = isLight ? 0.08 : 0.12
        let chipBorderAlpha: CGFloat = isLight ? 0.18 : 0.28

        applyShortcutResultTextPalette(palette)

        shortcutResultDoneButton.contentTintColor = palette.primary
        shortcutResultDoneButton.layer?.backgroundColor = chipBase.withAlphaComponent(chipBgAlpha).cgColor
        shortcutResultDoneButton.layer?.borderColor = chipBase.withAlphaComponent(chipBorderAlpha).cgColor
        applyShortcutResultButtonTitleColor(shortcutResultDoneButton, color: palette.primary)

        shortcutResultAddToAnnotationsButton.contentTintColor = palette.primary
        shortcutResultAddToAnnotationsButton.layer?.backgroundColor = chipBase.withAlphaComponent(chipBgAlpha).cgColor
        shortcutResultAddToAnnotationsButton.layer?.borderColor = chipBase.withAlphaComponent(chipBorderAlpha).cgColor
        applyShortcutResultButtonTitleColor(shortcutResultAddToAnnotationsButton, color: palette.primary)

        shortcutResultLoadingView.layer?.backgroundColor = chipBase.withAlphaComponent(isLight ? 0.06 : 0.08).cgColor
        shortcutResultLoadingView.layer?.borderColor = chipBase.withAlphaComponent(isLight ? 0.12 : 0.20).cgColor
        shortcutResultLoadingLabel.textColor = palette.secondary

        if shortcutResultSpinner.responds(to: Selector(("setContentTintColor:"))) {
            shortcutResultSpinner.setValue(palette.secondary.withAlphaComponent(isLight ? 0.88 : 0.92), forKey: "contentTintColor")
        }
    }

    private func updateLoadingOverlayAppearance() {
        let tint = panelClearGlassTintColor()
        let base = windowBackgroundSolidColor()
        let text = resolvedForegroundColor(base: base, tint: tint, role: .primaryText)
        loadingLabel.textColor = text
        if loadingSpinner.responds(to: Selector(("setContentTintColor:"))) {
            loadingSpinner.setValue(text.withAlphaComponent(0.9), forKey: "contentTintColor")
        }
    }

    private func windowGlassTintColor() -> NSColor {
        // Compatibility shim: “window glass” no longer exists at the root; use the next dominant glass layer.
        let base = rootGlassTheme().rootTint.usingColorSpace(.deviceRGB) ?? rootGlassTheme().rootTint
        let baseAlpha = glassAppearanceIsDark() ? WINDOW_GLASS_TINT_ALPHA : WINDOW_GLASS_TINT_ALPHA_LIGHT
        let alpha = glassAlpha(max(0.0, min(1.0, baseAlpha)))
        return NSColor(srgbRed: base.redComponent, green: base.greenComponent, blue: base.blueComponent, alpha: alpha)
    }

    private func windowBackgroundGlassTintColor() -> NSColor {
        if !AppSettingsStore.shared.current.appearance.liquidGlassEnabled {
            return resolvedSystemColor(.windowBackgroundColor)
        }
        let base = rootGlassTheme().rootTint.usingColorSpace(.deviceRGB) ?? rootGlassTheme().rootTint
        let baseAlpha = glassAppearanceIsDark() ? WINDOW_BACKGROUND_GLASS_TINT_ALPHA : WINDOW_BACKGROUND_GLASS_TINT_ALPHA_LIGHT
        let alpha = windowBackgroundAlpha(max(0.0, min(1.0, baseAlpha)))
        return NSColor(srgbRed: base.redComponent,
                       green: base.greenComponent,
                       blue: base.blueComponent,
                       alpha: alpha)
    }

	    private func windowGlassAdjustedTintColor() -> NSColor {
	        // Kept for call-site stability; window-level underlay adjustments no longer apply.
	        windowGlassTintColor()
	    }

	    private func toolbarAccentTintColor() -> NSColor {
	        let accent = resolvedAppAccentDisplayColor()
	        let rgb = accent.usingColorSpace(.deviceRGB) ?? accent
	        let baseAlpha = glassAppearanceIsDark() ? WINDOW_GLASS_TINT_ALPHA : WINDOW_GLASS_TINT_ALPHA_LIGHT
	        let alpha = glassAlpha(max(0.0, min(1.0, baseAlpha)))
	        return NSColor(srgbRed: rgb.redComponent,
	                       green: rgb.greenComponent,
	                       blue: rgb.blueComponent,
	                       alpha: alpha)
	    }

		    private func baseGlassStyleTintColor() -> NSColor {
		        // Authoritative base for UI that previously referenced “window glass”.
		        // Derived from RootGlassTint, but with a lighter alpha so it reads as a subtle top-level reference.
		        let root = rootGlassTheme().rootTint.usingColorSpace(.deviceRGB) ?? rootGlassTheme().rootTint
		        let baseAlpha = glassAppearanceIsDark() ? WINDOW_GLASS_TINT_ALPHA : WINDOW_GLASS_TINT_ALPHA_LIGHT
		        let a = glassAlpha(max(0.0, min(1.0, baseAlpha)))
		        return NSColor(srgbRed: root.redComponent, green: root.greenComponent, blue: root.blueComponent, alpha: a)
		    }

            private func isToolbarEdgeButtonBackground(_ background: NSView?) -> Bool {
                guard let background else { return false }
                return background === rightPanelLeftEdgeButtonBackground
                    || background === rightPanelZoteroEdgeButtonBackground
                    || background === rightPanelRightEdgeButtonBackground
                    || background === rightPanelSettingsEdgeButtonBackground
            }

            private func searchBarBaseBackgroundColor(for background: NSView?) -> NSColor {
                if background === searchBackground || isToolbarEdgeButtonBackground(background) {
                    return leftPanelEffectiveBackgroundColor()
                }
                if background === rightAuxAskBackground {
                    return rightAuxEffectiveBackgroundColor()
                }
                return windowBackgroundSolidColor()
            }

            private func searchBarTintBoost(for background: NSView?) -> CGFloat {
                if background === searchBackground || isToolbarEdgeButtonBackground(background) {
                    return SPOTLIGHT_SEARCH_GLASS_ALPHA_MULTIPLIER
                }
                return 1.0
            }

            private func searchBarTintColor(for background: NSView?) -> NSColor {
                let base = searchBarBaseBackgroundColor(for: background)
                let boost = searchBarTintBoost(for: background)
                let raw = toolbarAccentTintColor()
                let rawRGB = raw.usingColorSpace(.deviceRGB) ?? raw
                let boostedAlpha = min(1.0, rawRGB.alphaComponent * boost)
                let boosted = NSColor(srgbRed: rawRGB.redComponent,
                                      green: rawRGB.greenComponent,
                                      blue: rawRGB.blueComponent,
                                      alpha: boostedAlpha)
                let target: CGFloat = glassAppearanceIsDark() ? 1.22 : 1.35
                let maxAlpha: CGFloat = glassAppearanceIsDark() ? 0.55 : 0.7
                return adjustedTintForBackgroundContrast(base: base,
                                                         tint: boosted,
                                                         target: target,
                                                         maxAlpha: maxAlpha)
            }

            // Canonical resolver for any embedded-search-style glass surface.
            private func embeddedSearchBaseTint(for background: NSView?,
                                                baseOverride: NSColor? = nil,
                                                tintOverride: NSColor? = nil) -> (base: NSColor, tint: NSColor) {
                let base = baseOverride ?? searchBarBaseBackgroundColor(for: background)
                let tint = tintOverride ?? searchBarTintColor(for: background)
                return (base, tint)
            }

            private func embeddedSearchResolvedTint(for background: NSView?) -> NSColor? {
                if let card = background as? GlassCardView, let tint = card.config.tint {
                    return tint
                }
                if #available(macOS 26.0, *), let glass = background as? NSGlassEffectView {
                    return glass.tintColor
                }
                if let effect = background as? NSVisualEffectView,
                   let cg = effect.layer?.backgroundColor,
                   let color = NSColor(cgColor: cg) {
                    return color
                }
                if let cg = background?.layer?.backgroundColor,
                   let color = NSColor(cgColor: cg) {
                    return color
                }
                return nil
            }

            private func embeddedSearchEffectiveBackground(for background: NSView?,
                                                           baseOverride: NSColor? = nil,
                                                           tintOverride: NSColor? = nil) -> NSColor {
                let pair = embeddedSearchBaseTint(for: background,
                                                  baseOverride: baseOverride,
                                                  tintOverride: tintOverride)
                return effectiveBackgroundColor(base: pair.base, tint: pair.tint)
            }

            private func embeddedSearchForegroundColor(for background: NSView?,
                                                       baseOverride: NSColor? = nil,
                                                       tintOverride: NSColor? = nil,
                                                       role: ForegroundRole,
                                                       minContrast: CGFloat? = nil,
                                                       context: String? = nil) -> NSColor {
                let pair = embeddedSearchBaseTint(for: background,
                                                  baseOverride: baseOverride,
                                                  tintOverride: tintOverride)
                return ForegroundResolver.color(base: pair.base,
                                                tint: pair.tint,
                                                role: role,
                                                minContrast: minContrast,
                                                context: context)
            }

            private func searchBarEffectiveBackgroundColor(for background: NSView?) -> NSColor {
                embeddedSearchEffectiveBackground(for: background)
            }

            private func searchBarTextColors(for background: NSView?) -> (text: NSColor, placeholder: NSColor) {
                let context = (background === searchBackground) ? "searchBar.main" : "searchBar.other"
                let text = NSColor.labelColor
                let placeholder = NSColor.secondaryLabelColor
                if ContrastDebug.enabled {
                    let effective = embeddedSearchEffectiveBackground(for: background)
                    ContrastDebug.recordSearchBar(background: effective, textColor: text, context: context)
                }
                return (text, placeholder)
            }

            private func updateSharedToolbarForegroundPalette() -> ToolbarForegroundPalette {
                let colors = searchBarTextColors(for: searchBackground)
                let background = searchBarEffectiveBackgroundColor(for: searchBackground)
                let primary = colors.text
                let secondary = colors.placeholder
                let disabled = NSColor.disabledControlTextColor
                let palette = ToolbarForegroundPalette(primary: primary,
                                                       secondary: secondary,
                                                       disabled: disabled,
                                                       background: background)
                ToolbarForegroundTheme.shared.update(palette)
                return ToolbarForegroundTheme.shared.palette
            }

		    private func spotlightSearchTintColor() -> NSColor {
                searchBarTintColor(for: searchBackground)
		    }

		    private func compensatedSearchBarTintColor() -> NSColor {
	        // Inverse-blend compensation:
	        // Goal/acceptance test: search bar fill matches the window glass around the top-left buttons.
	        // Because the search bar sits above the left glass card, the card’s tint “double-tints” the blur.
	        // We approximate the stack and solve the inverse alpha composite per channel (linear space):
	        // C_out = a * C_tint + (1 - a) * C_under  =>  C_tint = (C_target - (1 - a) * C_under) / a
	        let target = (windowGlassAdjustedTintColor().usingColorSpace(.deviceRGB) ?? windowGlassAdjustedTintColor())
	        let searchAlpha = max(0.02, min(0.9, target.alphaComponent))

	        // Approximate what the search bar sits on: left card tint composited over the window glass tint.
	        let cardTint = (cardGlassTintColor().usingColorSpace(.deviceRGB) ?? cardGlassTintColor())
	        let targetRGB = (srgbToLinear(target.redComponent), srgbToLinear(target.greenComponent), srgbToLinear(target.blueComponent))
	        let cardRGB = (srgbToLinear(cardTint.redComponent), srgbToLinear(cardTint.greenComponent), srgbToLinear(cardTint.blueComponent))
	        let underRGB = compositeRGBLinear(sourceRGB: cardRGB, sourceAlpha: cardTint.alphaComponent, destRGB: targetRGB)

	        let neededRGB = inverseCompositeRGBLinear(targetRGB: targetRGB, underRGB: underRGB, sourceAlpha: searchAlpha)
	        let out = NSColor(srgbRed: linearToSrgb(neededRGB.0),
	                          green: linearToSrgb(neededRGB.1),
	                          blue: linearToSrgb(neededRGB.2),
	                          alpha: searchAlpha)
	        // User-facing adjustment: tweak perceived brightness without changing the blend math above.
	        let adj = max(-1.0, min(1.0, SEARCH_BAR_TINT_BRIGHTNESS_ADJUST))
	        if adj >= 0 {
	            let white = NSColor.white.withAlphaComponent(out.alphaComponent)
	            return blend(out, white, t: adj)
	        } else {
	            let black = NSColor.black.withAlphaComponent(out.alphaComponent)
	            return blend(out, black, t: -adj)
	        }
	    }

    private func spotlightSearchOutlineColor() -> NSColor {
        let background = searchBarEffectiveBackgroundColor(for: searchBackground)
        let lum = relativeLuminance(background)
        if lum < 0.5 {
            return NSColor.white.withAlphaComponent(SPOTLIGHT_SEARCH_OUTLINE_LIGHT_ALPHA)
        }
        return NSColor.black.withAlphaComponent(SPOTLIGHT_SEARCH_OUTLINE_DARK_ALPHA)
    }

    private func spotlightSearchHighlightColors() -> [CGColor] {
        [
            NSColor.white.withAlphaComponent(SPOTLIGHT_SEARCH_HIGHLIGHT_TOP_ALPHA).cgColor,
            NSColor.white.withAlphaComponent(SPOTLIGHT_SEARCH_HIGHLIGHT_MID_ALPHA).cgColor,
            NSColor.clear.cgColor
        ]
    }

    private func spotlightSearchFalloffColors() -> [CGColor] {
        [
            NSColor.clear.cgColor,
            NSColor.black.withAlphaComponent(SPOTLIGHT_SEARCH_FALLOFF_ALPHA).cgColor
        ]
    }

    private func windowGlassFallbackOverlayColor() -> NSColor {
        let tint = windowGlassTintColor()
        return tint.withAlphaComponent(min(1.0, tint.alphaComponent * 0.7))
    }

    private struct SearchBarTheme {
        let tintColor: NSColor
        let fallbackMaterial: NSVisualEffectView.Material
        let fallbackBlending: NSVisualEffectView.BlendingMode
        let fallbackState: NSVisualEffectView.State
        let emphasized: Bool
        let shadowColor: NSColor
        let shadowOpacity: Float
        let shadowRadius: CGFloat
        let shadowOffset: CGSize
        let font: NSFont
        let secondaryFont: NSFont
        let textColor: NSColor
        let placeholderColor: NSColor
    }

    private func currentSearchBarTheme() -> SearchBarTheme {
        let base = searchBarBaseBackgroundColor(for: searchBackground)
        let tint = searchBarTintColor(for: searchBackground)
        let effectiveBackground = effectiveBackgroundColor(base: base, tint: tint)
        let isLightBG = relativeLuminance(effectiveBackground) > 0.55
        let font = NSFont.systemFont(ofSize: 14.5, weight: .medium)
        let secondaryFont = NSFont.systemFont(ofSize: 11, weight: .regular)
        let palette = ToolbarForegroundTheme.shared.palette
        let textColor = palette.primary
        let placeholderColor = NSColor.placeholderTextColor
        let shadowColor = NSColor.black.withAlphaComponent(isLightBG ? 0.22 : 0.35)
        let shadowOpacity: Float = isLightBG ? 0.16 : 0.22
        let shadowRadius: CGFloat = isLightBG ? 8 : 10
        let shadowOffset = CGSize(width: 0, height: isLightBG ? -0.6 : -1.0)
        let fallbackMaterial: NSVisualEffectView.Material = isLightBG ? .underWindowBackground : .headerView
        let emphasized = !isLightBG
        return SearchBarTheme(
            tintColor: tint,
            fallbackMaterial: fallbackMaterial,
            fallbackBlending: .withinWindow,
            fallbackState: .active,
            emphasized: emphasized,
            shadowColor: shadowColor,
            shadowOpacity: shadowOpacity,
            shadowRadius: shadowRadius,
            shadowOffset: shadowOffset,
            font: font,
            secondaryFont: secondaryFont,
            textColor: textColor,
            placeholderColor: placeholderColor
        )
    }

    // MARK: iMessage-style glass compose field

    private struct IMessageGlassFieldTheme {
        let tintColor: NSColor
        let fallbackMaterial: NSVisualEffectView.Material
        let fallbackBlending: NSVisualEffectView.BlendingMode
        let fallbackState: NSVisualEffectView.State
        let emphasized: Bool
        let font: NSFont
        let textColor: NSColor
        let placeholderColor: NSColor
        let strokeAlpha: CGFloat
        let innerStrokeAlpha: CGFloat
        let highlightTopAlpha: CGFloat
        let innerShadowBottomAlpha: CGFloat
        let shadowColor: NSColor
        let shadowOpacity: Float
        let shadowRadius: CGFloat
        let shadowOffset: CGSize
    }

    private func currentIMessageGlassFieldTheme() -> IMessageGlassFieldTheme {
        let isDark = glassAppearanceIsDark()

        // Warm, softly tinted glass (still translucent).
        let base = (baseGlassStyleTintColor().usingColorSpace(.deviceRGB) ?? baseGlassStyleTintColor())
        let warm = (resolvedSystemColor(.systemYellow).usingColorSpace(.deviceRGB) ?? NSColor.systemYellow)
        let tint = blend(base.withAlphaComponent(1.0), warm.withAlphaComponent(1.0), t: 0.60)
            .withAlphaComponent(glassAlpha(isDark ? 0.26 : 0.22))

        let font = NSFont.systemFont(ofSize: 17, weight: .regular)
        // iMessage-like placeholder reads as lighter text on warm glass.
        let text = resolvedForegroundColor(base: windowBackgroundSolidColor(), tint: tint, role: .primaryText)
        let placeholder = resolvedForegroundColor(base: windowBackgroundSolidColor(), tint: tint, role: .secondaryText)

        // Hairline stroke & shaping.
        let strokeAlpha: CGFloat = isDark ? 0.16 : 0.12
        let innerStrokeAlpha: CGFloat = isDark ? 0.07 : 0.06
        let highlightTopAlpha: CGFloat = isDark ? 0.11 : 0.08
        let innerShadowBottomAlpha: CGFloat = isDark ? 0.06 : 0.04

        // Minimal lift.
        let shadowColor = NSColor.black.withAlphaComponent(isDark ? 0.42 : 0.24)
        let shadowOpacity: Float = isDark ? 0.14 : 0.09
        let shadowRadius: CGFloat = isDark ? 10 : 7
        let shadowOffset = CGSize(width: 0, height: isDark ? -0.6 : -0.4)
        let fallbackMaterial: NSVisualEffectView.Material = isDark ? .hudWindow : .underWindowBackground

        return IMessageGlassFieldTheme(
            tintColor: tint,
            fallbackMaterial: fallbackMaterial,
            fallbackBlending: .withinWindow,
            fallbackState: .active,
            emphasized: isDark,
            font: font,
            textColor: text,
            placeholderColor: placeholder,
            strokeAlpha: strokeAlpha,
            innerStrokeAlpha: innerStrokeAlpha,
            highlightTopAlpha: highlightTopAlpha,
            innerShadowBottomAlpha: innerShadowBottomAlpha,
            shadowColor: shadowColor,
            shadowOpacity: shadowOpacity,
            shadowRadius: shadowRadius,
            shadowOffset: shadowOffset
        )
    }

    private func iMessagePlaceholder(_ text: String, theme: IMessageGlassFieldTheme) -> NSAttributedString {
        let style = NSMutableParagraphStyle()
        style.lineBreakMode = .byClipping
        return NSAttributedString(
            string: text,
            attributes: [
                .foregroundColor: theme.placeholderColor,
                .font: theme.font,
                .paragraphStyle: style
            ]
        )
    }

    private func applyIMessageGlassFieldTheme(_ field: NSSearchField, placeholder: String) {
        let theme = currentIMessageGlassFieldTheme()
        let placeholderAttr = iMessagePlaceholder(placeholder, theme: theme)

        let previousCell = field.cell as? NSSearchFieldCell
        let preservedMenuTemplate = previousCell?.searchMenuTemplate?.copy() as? NSMenu
            ?? previousCell?.searchMenuTemplate
        let cell = (previousCell as? CenteredSearchFieldCell) ?? CenteredSearchFieldCell(textCell: "")
        if let menuTemplate = preservedMenuTemplate {
            cell.searchMenuTemplate = menuTemplate
        }
        cell.font = theme.font
        cell.placeholderAttributedString = placeholderAttr
        cell.controlSize = .large
        cell.usesSingleLineMode = true
        cell.wraps = false
        cell.isScrollable = true
        cell.lineBreakMode = .byClipping
        cell.truncatesLastVisibleLine = false
        cell.backgroundColor = .clear
        cell.drawsBackground = false
        cell.textColor = theme.textColor
        field.cell = cell

        field.font = theme.font
        field.textColor = theme.textColor
        field.placeholderString = placeholder
        field.placeholderAttributedString = placeholderAttr
        field.lineBreakMode = .byClipping
        field.usesSingleLineMode = true
        field.maximumNumberOfLines = 1
        field.drawsBackground = false
        field.isBordered = false
        field.isBezeled = false
        field.focusRingType = .none
        field.isEditable = true
        field.isSelectable = true
        field.isEnabled = true
        field.controlSize = .large
    }

    private func applyIMessageGlassBackgroundTheme(to background: NSView) {
        let theme = currentIMessageGlassFieldTheme()
        if let glass = background as? NSGlassEffectView {
            glass.style = .regular
            glass.tintColor = theme.tintColor
        } else if let effect = background as? NSVisualEffectView {
            effect.material = theme.fallbackMaterial
            effect.blendingMode = theme.fallbackBlending
            effect.state = theme.fallbackState
            effect.isEmphasized = theme.emphasized
            effect.layer?.backgroundColor = theme.tintColor.cgColor
        }

        background.wantsLayer = true
        background.layer?.shadowColor = theme.shadowColor.cgColor
        background.layer?.shadowOpacity = theme.shadowOpacity
        background.layer?.shadowRadius = theme.shadowRadius
        background.layer?.shadowOffset = theme.shadowOffset
        enforceStableVisualEffectState(background)
    }

    private func enforceStableVisualEffectState(_ view: NSView) {
        // iMessage-like fields should not collapse/shift when window becomes inactive.
        if let effect = view as? NSVisualEffectView {
            effect.state = .active
        }
    }

	    private func searchBarPlaceholder(_ text: String, theme: SearchBarTheme, color: NSColor? = nil) -> NSAttributedString {
	        let style = NSMutableParagraphStyle()
	        style.lineBreakMode = .byClipping
	        let placeholderColor = color ?? theme.placeholderColor
	        return NSAttributedString(
	            string: text,
	            attributes: [
	                .foregroundColor: placeholderColor,
	                .font: theme.font,
	                .kern: -0.15,
	                .paragraphStyle: style
	            ]
	        )
	    }

    private func applySearchBarTheme(to background: NSView, tintOverride: NSColor? = nil) {
        let theme = currentSearchBarTheme()
        // Match the main search bar glass tint exactly (avoid the extra Spotlight-style boost used elsewhere).
        let tint = tintOverride ?? embeddedSearchTintColor(focused: false, hovered: false)
            ?? toolbarGlassTintColor()
        if let glass = background as? NSGlassEffectView {
            glass.style = .regular
            glass.tintColor = tint
        } else if let effect = background as? NSVisualEffectView {
            effect.material = theme.fallbackMaterial
            effect.blendingMode = theme.fallbackBlending
            effect.state = theme.fallbackState
            effect.isEmphasized = theme.emphasized
            effect.layer?.backgroundColor = tint.cgColor
        } else if let card = background as? GlassCardView {
            var config = card.config
            let base = tint.usingColorSpace(.deviceRGB) ?? tint
            config.tint = base
            card.updateConfig(config)
        } else {
            background.wantsLayer = true
            background.layer?.backgroundColor = (tint.usingColorSpace(.deviceRGB) ?? tint).withAlphaComponent(1.0).cgColor
        }

        background.wantsLayer = true
        background.layer?.shadowColor = theme.shadowColor.cgColor
        background.layer?.shadowOpacity = theme.shadowOpacity
        background.layer?.shadowRadius = theme.shadowRadius
        background.layer?.shadowOffset = theme.shadowOffset
        enforceActiveVisualEffectState(background)
    }
	
	    // MARK: Embedded search bar (inset, carved-into-glass look)
	
            private func embeddedSearchTintColor(focused: Bool, hovered: Bool) -> NSColor? {
		        _ = focused
		        _ = hovered
		        // Match the app accent (system or custom) so search + pill stay in sync with the accent picker.
                return searchBarTintColor(for: nil)
		    }

            private struct EmbeddedSearchOrnaments {
                let outlineLayer: CAShapeLayer
                let innerOutlineLayer: CAShapeLayer
                let highlightLayer: CAGradientLayer
                let falloffLayer: CAGradientLayer
                let centerGlowLayer: CAGradientLayer
                let maskLayer: CAShapeLayer
            }

            private var embeddedSearchOrnamentsByView: [ObjectIdentifier: EmbeddedSearchOrnaments] = [:]

            private func ensureEmbeddedSearchOrnaments(on background: NSView) {
                guard let layer = background.layer else { return }
                let id = ObjectIdentifier(background)
                if embeddedSearchOrnamentsByView[id] != nil { return }

                let outline = CAShapeLayer()
                let inner = CAShapeLayer()
                let highlight = CAGradientLayer()
                let falloff = CAGradientLayer()
                let centerGlow = CAGradientLayer()
                let mask = CAShapeLayer()

                outline.fillColor = NSColor.clear.cgColor
                inner.fillColor = NSColor.clear.cgColor
                outline.lineJoin = .round
                outline.lineCap = .round
                inner.lineJoin = .round
                inner.lineCap = .round

                let scale = max(1.0, background.window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
                outline.contentsScale = scale
                inner.contentsScale = scale
                highlight.contentsScale = scale
                falloff.contentsScale = scale
                centerGlow.contentsScale = scale
                mask.contentsScale = scale

                outline.lineWidth = SPOTLIGHT_SEARCH_OUTLINE_WIDTH
                inner.lineWidth = SPOTLIGHT_SEARCH_OUTLINE_WIDTH

                highlight.startPoint = CGPoint(x: 0.5, y: 1.0)
                highlight.endPoint = CGPoint(x: 0.5, y: 0.0)
                falloff.startPoint = CGPoint(x: 0.5, y: 1.0)
                falloff.endPoint = CGPoint(x: 0.5, y: 0.0)
                if #available(macOS 10.14, *) {
                    centerGlow.type = .radial
                }
                centerGlow.startPoint = CGPoint(x: 0.5, y: 0.5)
                centerGlow.endPoint = CGPoint(x: 1.0, y: 1.0)

                layer.addSublayer(centerGlow)
                layer.addSublayer(highlight)
                layer.addSublayer(falloff)
                layer.addSublayer(inner)
                layer.addSublayer(outline)
                layer.mask = mask

                embeddedSearchOrnamentsByView[id] = EmbeddedSearchOrnaments(
                    outlineLayer: outline,
                    innerOutlineLayer: inner,
                    highlightLayer: highlight,
                    falloffLayer: falloff,
                    centerGlowLayer: centerGlow,
                    maskLayer: mask
                )
            }

            private func updateEmbeddedSearchOrnaments(_ background: NSView,
                                                      cornerRadius: CGFloat,
                                                      uniformCorners: Bool = false) {
                guard let layer = background.layer else { return }
                let id = ObjectIdentifier(background)
                guard let o = embeddedSearchOrnamentsByView[id] else { return }

                // Match the Share-style outline recipe, tuned for light/dark backgrounds.
                let dark = glassAppearanceIsDark()
                let borderAlpha: CGFloat = dark ? 0.78 : 0.52
                let innerBorderAlpha: CGFloat = dark ? 0.34 : 0.20
                let highlightTopAlpha: CGFloat = dark ? 0.18 : 0.10
                let highlightMidAlpha: CGFloat = dark ? 0.06 : 0.04
                let falloffAlpha: CGFloat = dark ? 0.18 : 0.12
                // Disable radial center glow for large glass panels to avoid darker corners.
                let centerGlowAlpha: CGFloat = uniformCorners ? 0.0 : (dark ? 0.07 : 0.05)

                let bounds = background.bounds
                let outerRect = bounds.insetBy(dx: SPOTLIGHT_SEARCH_OUTLINE_WIDTH / 2, dy: SPOTLIGHT_SEARCH_OUTLINE_WIDTH / 2)
                let innerRect = bounds.insetBy(dx: SPOTLIGHT_SEARCH_OUTLINE_WIDTH / 2 + 1.0, dy: SPOTLIGHT_SEARCH_OUTLINE_WIDTH / 2 + 1.0)
                let outerPath = CGPath(roundedRect: outerRect,
                                       cornerWidth: max(0, cornerRadius - (SPOTLIGHT_SEARCH_OUTLINE_WIDTH / 2)),
                                       cornerHeight: max(0, cornerRadius - (SPOTLIGHT_SEARCH_OUTLINE_WIDTH / 2)),
                                       transform: nil)
                let innerPath = CGPath(roundedRect: innerRect,
                                       cornerWidth: max(0, cornerRadius - (SPOTLIGHT_SEARCH_OUTLINE_WIDTH / 2) - 1.0),
                                       cornerHeight: max(0, cornerRadius - (SPOTLIGHT_SEARCH_OUTLINE_WIDTH / 2) - 1.0),
                                       transform: nil)
                let maskPath = CGPath(roundedRect: bounds,
                                      cornerWidth: cornerRadius,
                                      cornerHeight: cornerRadius,
                                      transform: nil)

                CATransaction.begin()
                CATransaction.setDisableActions(true)
                o.outlineLayer.frame = bounds
                o.innerOutlineLayer.frame = bounds
                o.highlightLayer.frame = bounds
                o.falloffLayer.frame = bounds
                o.centerGlowLayer.frame = bounds
                o.maskLayer.frame = bounds

                o.outlineLayer.path = outerPath
                o.innerOutlineLayer.path = innerPath
                o.maskLayer.path = maskPath

                let outlineBase = dark ? NSColor.white : NSColor.black
                o.outlineLayer.strokeColor = outlineBase.withAlphaComponent(borderAlpha).cgColor
                o.innerOutlineLayer.strokeColor = outlineBase.withAlphaComponent(innerBorderAlpha).cgColor
                o.highlightLayer.colors = [
                    NSColor.white.withAlphaComponent(highlightTopAlpha).cgColor,
                    NSColor.white.withAlphaComponent(highlightMidAlpha).cgColor,
                    NSColor.clear.cgColor
                ]
                o.falloffLayer.colors = [
                    NSColor.clear.cgColor,
                    NSColor.black.withAlphaComponent(falloffAlpha).cgColor
                ]
                if centerGlowAlpha <= 0.0001 {
                    o.centerGlowLayer.colors = [NSColor.clear.cgColor, NSColor.clear.cgColor]
                } else {
                    o.centerGlowLayer.colors = [
                        NSColor.white.withAlphaComponent(centerGlowAlpha).cgColor,
                        NSColor.clear.cgColor
                    ]
                }
                // Keep the layer itself clean; the ornamentation defines the capsule edge.
                layer.shadowOpacity = 0
                layer.shadowRadius = 0
                layer.shadowOffset = .zero
                CATransaction.commit()
            }
	
    private func applyEmbeddedSearchBarTheme(to background: NSView, tintOverride: NSColor? = nil) {
        let tint = tintOverride ?? searchBarTintColor(for: background)
        if let glass = background as? NSGlassEffectView {
            glass.style = .regular
            glass.tintColor = tint
        } else if let effect = background as? NSVisualEffectView {
            let theme = currentSearchBarTheme()
            effect.material = theme.fallbackMaterial
            effect.blendingMode = theme.fallbackBlending
            effect.state = theme.fallbackState
            effect.isEmphasized = theme.emphasized
            effect.layer?.backgroundColor = tint.cgColor
        } else {
            background.wantsLayer = true
            background.layer?.backgroundColor = (tint.usingColorSpace(.deviceRGB) ?? tint).withAlphaComponent(1.0).cgColor
        }

        background.wantsLayer = true
        background.layer?.shadowOpacity = 0
        background.layer?.shadowRadius = 0
        background.layer?.shadowOffset = .zero
        enforceActiveVisualEffectState(background)
    }

            private struct ToolbarEdgeOutlineOrnaments {
                let overlay: NSView
                let edgeOrnaments: MaterialEdgeStack
            }

            private var toolbarEdgeOutlineByView: [ObjectIdentifier: ToolbarEdgeOutlineOrnaments] = [:]

            private func ensureToolbarEdgeOutline(on background: NSView) -> ToolbarEdgeOutlineOrnaments {
                let id = ObjectIdentifier(background)
                if let existing = toolbarEdgeOutlineByView[id], existing.overlay.superview === background {
                    return existing
                }

                let overlay = PassthroughView(frame: background.bounds)
                overlay.translatesAutoresizingMaskIntoConstraints = true
                overlay.wantsLayer = true
                overlay.layer?.masksToBounds = false
                background.addSubview(overlay, positioned: .above, relativeTo: nil)

                let edgeOrnaments = MaterialEdgeStack()
                if let layer = overlay.layer {
                    edgeOrnaments.attach(to: layer)
                }

                let entry = ToolbarEdgeOutlineOrnaments(overlay: overlay, edgeOrnaments: edgeOrnaments)
                toolbarEdgeOutlineByView[id] = entry
                return entry
            }

            private func updateToolbarEdgeOutline(_ background: NSView, state: GlassCardKit.State) {
                let entry = ensureToolbarEdgeOutline(on: background)
                let overlay = entry.overlay
                overlay.frame = background.bounds

                let bounds = overlay.bounds
                let side = min(bounds.width, bounds.height)
                guard side > 2 else { return }

                let circleBounds = NSRect(
                    x: bounds.midX - (side / 2),
                    y: bounds.midY - (side / 2),
                    width: side,
                    height: side
                )

                let scale = max(1.0, background.window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
                let edgePx = 1.0 / scale
                let maxInset = max(0.0, (side / 2) - 0.5)
                let edgeInset = min(edgePx, maxInset)
                let edgeInnerInset = min(edgePx * 2.0, maxInset)

                let outerPath = CGPath(ellipseIn: circleBounds, transform: nil)
                let outerInnerPath = CGPath(ellipseIn: circleBounds.insetBy(dx: edgeInset, dy: edgeInset), transform: nil)
                let innerOuterPath = outerInnerPath
                let innerInnerPath = CGPath(ellipseIn: circleBounds.insetBy(dx: edgeInnerInset, dy: edgeInnerInset), transform: nil)
                let outerBandPath = MaterialEdgeStack.ringPath(outer: outerPath, inner: outerInnerPath)
                let innerBandPath = MaterialEdgeStack.ringPath(outer: innerOuterPath, inner: innerInnerPath)

                let bands = ToolbarOutlineTokens.edgeBands(for: state)

                CATransaction.begin()
                CATransaction.setDisableActions(true)
                entry.edgeOrnaments.setContentsScale(scale)
                entry.edgeOrnaments.setFrames(bounds: overlay.bounds)
                entry.edgeOrnaments.maskLayer.path = outerPath
                entry.edgeOrnaments.outerBandLayer.path = outerBandPath
                entry.edgeOrnaments.innerBandLayer.path = innerBandPath
                entry.edgeOrnaments.applyEdgeStyle(outerBand: bands.outer, innerRim: bands.inner)
                CATransaction.commit()
            }

            private func applyToolbarEdgeOutline(to background: NSView, state: GlassCardKit.State) {
                background.wantsLayer = true
                updateToolbarEdgeOutline(background, state: state)
            }

    private func updateToolbarEdgeButtonBorders() {
        let backgrounds = [
            rightPanelLeftEdgeButtonBackground,
            rightPanelZoteroEdgeButtonBackground,
            rightPanelRightEdgeButtonBackground,
            rightPanelSettingsEdgeButtonBackground
        ].compactMap { $0 }
        let outlineState = rightPanelPillControl.toolbarOutlineState
        for background in backgrounds {
            applyToolbarEdgeOutline(to: background, state: outlineState)
        }
    }
	
	    private func updateEmbeddedSearchAppearance(animated: Bool) {
            let focused = searchFocused
            let hovered = searchHover
            let hasQuery = !searchField.stringValue.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            let engaged = focused || suggestionsVisible || hasQuery
            updateEmbeddedSearchAppearance(
                background: searchBackground,
                focused: focused,
                hovered: hovered,
                engaged: engaged,
                outlineLayer: searchOutlineLayer,
                innerOutlineLayer: searchInnerOutlineLayer,
                highlightLayer: searchHighlightLayer,
                falloffLayer: searchFalloffLayer,
                centerGlowLayer: searchCenterGlowLayer,
                animated: animated
            )
            updateSearchEdgeOrnaments(focused: focused, hovered: hovered, engaged: engaged, animated: animated)
	    }

        private func updateEmbeddedSearchAppearance(background: NSView,
                                                   focused: Bool,
                                                   hovered: Bool,
                                                   engaged: Bool,
                                                   outlineLayer: CAShapeLayer,
                                                   innerOutlineLayer: CAShapeLayer,
                                                   highlightLayer: CAGradientLayer,
                                                   falloffLayer: CAGradientLayer,
                                                   centerGlowLayer: CAGradientLayer,
                                                   animated: Bool) {
            guard let layer = background.layer else { return }
            let reduce = shouldReduceMotion || !animated

            let borderAlphaBase: CGFloat = engaged ? 0.20 : (hovered ? 0.12 : 0.09)
            let innerBorderAlphaBase: CGFloat = engaged ? 0.12 : (hovered ? 0.08 : 0.06)

            let highlightTopAlphaBase: CGFloat = engaged ? 0.32 : (hovered ? 0.24 : 0.18)
            let highlightMidAlphaBase: CGFloat = engaged ? 0.14 : (hovered ? 0.09 : 0.06)
            let falloffAlphaBase: CGFloat = engaged ? 0.34 : (hovered ? 0.28 : 0.26)
            let centerGlowAlphaBase: CGFloat = engaged ? 0.14 : (hovered ? 0.08 : 0.07)

            let isLightBG = relativeLuminance(searchBarEffectiveBackgroundColor(for: background)) > 0.55

            let borderAlpha: CGFloat = isLightBG ? min(0.34, borderAlphaBase + 0.06) : borderAlphaBase
            let innerBorderAlpha: CGFloat = isLightBG ? min(0.22, innerBorderAlphaBase + 0.04) : innerBorderAlphaBase
            let highlightTopAlpha: CGFloat = isLightBG ? max(0.08, highlightTopAlphaBase - 0.10) : highlightTopAlphaBase
            let highlightMidAlpha: CGFloat = isLightBG ? max(0.04, highlightMidAlphaBase - 0.06) : highlightMidAlphaBase
            let falloffAlpha: CGFloat = isLightBG ? min(0.40, falloffAlphaBase + 0.04) : falloffAlphaBase
            let centerGlowAlpha: CGFloat = isLightBG ? max(0.03, centerGlowAlphaBase - 0.04) : centerGlowAlphaBase

            let outlineBase = isLightBG ? NSColor.black : NSColor.white
            let centerGlowBase = isLightBG ? NSColor.black : NSColor.white
            let tint = searchBarTintColor(for: background)

            CATransaction.begin()
            if reduce {
                CATransaction.setDisableActions(true)
            } else {
                CATransaction.setAnimationDuration(0.14)
                CATransaction.setAnimationTimingFunction(CAMediaTimingFunction(name: .easeInEaseOut))
            }

            // Ensure any previous “floating pill” transforms/shadows are cleared.
            layer.transform = CATransform3DIdentity
            layer.shadowOpacity = 0
            layer.shadowRadius = 0
            layer.shadowOffset = .zero

            outlineLayer.strokeColor = outlineBase.withAlphaComponent(borderAlpha).cgColor
            innerOutlineLayer.strokeColor = outlineBase.withAlphaComponent(innerBorderAlpha).cgColor

            highlightLayer.colors = [
                NSColor.white.withAlphaComponent(highlightTopAlpha).cgColor,
                NSColor.white.withAlphaComponent(highlightMidAlpha).cgColor,
                NSColor.clear.cgColor
            ]
            falloffLayer.colors = [
                NSColor.clear.cgColor,
                NSColor.black.withAlphaComponent(falloffAlpha).cgColor
            ]
            centerGlowLayer.colors = [
                centerGlowBase.withAlphaComponent(centerGlowAlpha).cgColor,
                NSColor.clear.cgColor
            ]

            if let glass = background as? NSGlassEffectView {
                glass.tintColor = tint
            } else if let effect = background as? NSVisualEffectView {
                effect.layer?.backgroundColor = tint.cgColor
            }

            CATransaction.commit()
        }

    private func updateSearchEdgeOrnaments(focused: Bool,
                                           hovered: Bool,
                                           engaged: Bool,
                                           animated: Bool) {
        let state: GlassCardKit.State
        if !searchField.isEnabled {
            state = .disabled
        } else if focused {
            state = .pressed
        } else if hovered {
            state = .hover
        } else if engaged {
            state = .selected
        } else {
            state = .normal
        }

        let reduce = shouldReduceMotion || !animated
        let bands = ToolbarOutlineTokens.edgeBands(for: state)

        CATransaction.begin()
        if reduce {
            CATransaction.setDisableActions(true)
        } else {
            CATransaction.setAnimationDuration(0.14)
            CATransaction.setAnimationTimingFunction(CAMediaTimingFunction(name: .easeInEaseOut))
        }
        searchEdgeOrnaments.applyEdgeStyle(outerBand: bands.outer, innerRim: bands.inner)
        CATransaction.commit()
    }

    private func applySearchFieldTheme(_ field: NSSearchField,
                                       placeholder: String,
                                       textColor: NSColor? = nil,
                                       placeholderColor: NSColor? = nil,
                                       iconColor: NSColor? = nil) {
        let theme = currentSearchBarTheme()
        let resolvedTextColor = textColor ?? theme.textColor
        let resolvedPlaceholderColor = placeholderColor ?? theme.placeholderColor
        let placeholderAttr = searchBarPlaceholder(placeholder, theme: theme, color: resolvedPlaceholderColor)

        let previousCell = field.cell as? NSSearchFieldCell
        let preservedMenuTemplate = previousCell?.searchMenuTemplate?.copy() as? NSMenu
            ?? previousCell?.searchMenuTemplate
        let cell = (previousCell as? CenteredSearchFieldCell) ?? CenteredSearchFieldCell(textCell: "")
        if let menuTemplate = preservedMenuTemplate {
            // Keep the stock search menu so the magnifier button still drops down the history template.
            cell.searchMenuTemplate = menuTemplate
        }
        cell.font = theme.font
        cell.placeholderAttributedString = placeholderAttr
        cell.controlSize = .large
        cell.usesSingleLineMode = true
        cell.wraps = false
        cell.isScrollable = true
        cell.lineBreakMode = .byClipping
        cell.truncatesLastVisibleLine = false
        cell.backgroundColor = .clear
        cell.drawsBackground = false
        cell.textColor = resolvedTextColor
        field.cell = cell

        field.font = theme.font
        field.textColor = resolvedTextColor
        field.placeholderString = placeholder
        field.placeholderAttributedString = placeholderAttr
        field.lineBreakMode = .byClipping
        field.usesSingleLineMode = true
        field.maximumNumberOfLines = 1
        field.drawsBackground = false
        field.isBordered = false
        field.isBezeled = false
        field.focusRingType = .none
        field.isEditable = true
        field.isSelectable = true
        field.isEnabled = true
        field.controlSize = .large

        let isEmpty = field.stringValue.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        let resolvedIconColor = iconColor ?? (isEmpty ? resolvedPlaceholderColor : resolvedTextColor)
        if field === searchField {
            cachedSearchForegroundColor = resolvedIconColor
            searchFieldLastEmpty = isEmpty
            updateToolbarSeparatorStyle()
        }
        applySearchFieldIconColor(field, color: resolvedIconColor)
    }

    private func applySearchFieldIconColor(_ field: NSSearchField, color: NSColor) {
        guard let cell = field.cell as? NSSearchFieldCell else { return }
	        if let image = cell.searchButtonCell?.image {
	            image.isTemplate = true
	            cell.searchButtonCell?.image = image
	        }
	        if let image = cell.searchButtonCell?.alternateImage {
	            image.isTemplate = true
	            cell.searchButtonCell?.alternateImage = image
	        }
	        if let image = cell.cancelButtonCell?.image {
	            image.isTemplate = true
	            cell.cancelButtonCell?.image = image
	        }
	        if let image = cell.cancelButtonCell?.alternateImage {
	            image.isTemplate = true
	            cell.cancelButtonCell?.alternateImage = image
	        }
        if #available(macOS 10.14, *) {
            _ = setValueIfPossible(field, key: "contentTintColor", value: color)
        }
    }

    private func updateSearchFieldIconColorForCurrentState() {
        let isEmpty = searchField.stringValue.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        let theme = currentSearchBarTheme()
        let placeholderColor = theme.placeholderColor
        let textColor = searchField.textColor ?? theme.textColor
        let iconColor = isEmpty ? placeholderColor : textColor
        cachedSearchForegroundColor = iconColor
        searchFieldLastEmpty = isEmpty
        applySearchFieldIconColor(searchField, color: iconColor)
        updateToolbarSeparatorStyle()
    }

    private func applySearchBarDepth(to view: NSView, focused: Bool, hovered: Bool, animated: Bool) {
        guard let layer = view.layer else { return }
        let reduce = shouldReduceMotion

        let focusBoost: CGFloat = focused ? SPOTLIGHT_SEARCH_FOCUS_SCALE_BOOST : 0.0
        let hoverBoost: CGFloat = hovered ? SPOTLIGHT_SEARCH_HOVER_SCALE_BOOST : 0.0
        let targetScale = 1.0 + min(0.025, focusBoost + hoverBoost)
        let targetShadowOpacity: Float = focused ? 0.32 : (hovered ? 0.22 : currentSearchBarTheme().shadowOpacity)
        let targetShadowRadius: CGFloat = focused ? 8 : (hovered ? 6 : currentSearchBarTheme().shadowRadius)
        let targetShadowOffset = CGSize(width: 0, height: focused ? -0.9 : -0.5)
        let transform = CATransform3DMakeScale(targetScale, targetScale, 1.0)

        if animated {
            animateLayer(layer, keyPath: "transform", to: transform, preset: .microBounce, reduceMotion: reduce, basicDuration: 0.16)
            animateLayer(layer, keyPath: "shadowOpacity", to: targetShadowOpacity, preset: .microBounce, reduceMotion: reduce, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowRadius", to: targetShadowRadius, preset: .microBounce, reduceMotion: reduce, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOffset", to: targetShadowOffset, preset: .microBounce, reduceMotion: reduce, basicDuration: 0.14)
        } else {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.transform = transform
            layer.shadowOpacity = targetShadowOpacity
            layer.shadowRadius = targetShadowRadius
            layer.shadowOffset = targetShadowOffset
            CATransaction.commit()
        }
    }

    private func panelClearGlassTintColor() -> NSColor {
        let strength = glassTintStrengthSetting()
        let baseAlpha = glassAppearanceIsDark() ? PANEL_CLEAR_GLASS_TINT_ALPHA : PANEL_CLEAR_GLASS_TINT_ALPHA_LIGHT
        let alpha = max(0.0, min(1.0, baseAlpha * strength))
        let base = rootGlassTheme().rootTint
        let rgb = base.usingColorSpace(.deviceRGB) ?? base
        return NSColor(srgbRed: rgb.redComponent, green: rgb.greenComponent, blue: rgb.blueComponent, alpha: alpha)
    }

    private func panelEffectiveBackgroundColor() -> NSColor {
        let pair = glassBackgroundPair(base: windowBackgroundSolidColor(), tint: panelClearGlassTintColor())
        return pair.alt ?? pair.primary
    }

    private func shortcutResultEffectiveBackgroundColor() -> NSColor {
        let pair = glassBackgroundPair(base: windowBackgroundSolidColor(), tint: shortcutResultAccentTintColor())
        return pair.alt ?? pair.primary
    }

    private func shortcutResultTextPalette() -> TextPalette {
        adaptiveTextPalette(baseColor: shortcutResultEffectiveBackgroundColor(), linkHex: RIGHT_LINK_COLOR_HEX)
    }

    private func applyShortcutResultTextPalette(_ palette: TextPalette) {
        shortcutResultTextView.textColor = palette.primary
        shortcutResultTextView.linkTextAttributes = [.foregroundColor: palette.link]
        var typing = shortcutResultTextView.typingAttributes
        typing[.foregroundColor] = palette.primary
        if typing[.font] == nil {
            typing[.font] = shortcutResultTextView.font ?? NSFont.systemFont(ofSize: 14, weight: .regular)
        }
        shortcutResultTextView.typingAttributes = typing

        guard let storage = shortcutResultTextView.textStorage, storage.length > 0 else { return }
        let full = NSRange(location: 0, length: storage.length)
        storage.beginEditing()
        storage.enumerateAttributes(in: full, options: []) { attrs, range, _ in
            let target = (attrs[.link] != nil) ? palette.link : palette.primary
            storage.addAttribute(.foregroundColor, value: target, range: range)
        }
        storage.endEditing()
        shortcutResultTextView.refreshInlineMathAttachmentStyles(in: full)
    }

    private func applyShortcutResultButtonTitleColor(_ button: NSButton, color: NSColor) {
        let title = button.title
        let font = button.font ?? NSFont.systemFont(ofSize: 14, weight: .semibold)
        let attrs: [NSAttributedString.Key: Any] = [
            .font: font,
            .foregroundColor: color
        ]
        button.attributedTitle = NSAttributedString(string: title, attributes: attrs)
    }

    private func shortcutResultAccentTintColor() -> NSColor {
        let settings = AppSettingsStore.shared.current.appearance
        let raw = CGFloat(settings.liquidGlassTintStrength)
        let strength = max(0.0, min(2.0, raw.isFinite ? raw : 1.0))
        let alpha = max(0.06, min(0.35, PANEL_CLEAR_GLASS_TINT_ALPHA * max(0.6, strength)))
        let accent = resolvedAppAccentDisplayColor()
        let rgb = accent.usingColorSpace(.deviceRGB) ?? accent
        return NSColor(srgbRed: rgb.redComponent, green: rgb.greenComponent, blue: rgb.blueComponent, alpha: alpha)
    }

    private func annotationComposerTintColor() -> NSColor {
        annotationComposerTintColorSetting()
    }

    private func leftPanelTintBaseColor() -> NSColor {
        let settings = AppSettingsStore.shared.current.appearance
        let trimmed = settings.leftPanelTintHex.trimmingCharacters(in: .whitespacesAndNewlines)
        if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
            let rgb = color.usingColorSpace(.deviceRGB) ?? color
            return NSColor(srgbRed: rgb.redComponent, green: rgb.greenComponent, blue: rgb.blueComponent, alpha: 1.0)
        }
        let base = rootGlassTheme().rootTint
        let rgb = base.usingColorSpace(.deviceRGB) ?? base
        return NSColor(srgbRed: rgb.redComponent, green: rgb.greenComponent, blue: rgb.blueComponent, alpha: 1.0)
    }

    private func leftPanelGlassTintColor() -> NSColor {
        let settings = AppSettingsStore.shared.current.appearance
        guard settings.leftPanelGlassEnabled else {
            return windowBackgroundSolidColor().withAlphaComponent(1.0)
        }
        let alpha = max(0.0, min(1.0, CGFloat(settings.leftPanelTintAlpha)))
        return leftPanelTintBaseColor().withAlphaComponent(alpha)
    }

    private func leftPanelEffectiveBackgroundColor() -> NSColor {
        let pair = glassBackgroundPair(base: windowBackgroundSolidColor(), tint: leftPanelGlassTintColor())
        return pair.alt ?? pair.primary
    }

    private func rightAuxEffectiveBackgroundColor() -> NSColor {
        let pair = glassBackgroundPair(base: windowBackgroundSolidColor(), tint: rightAuxFixedGlassTintColor())
        return pair.alt ?? pair.primary
    }

    private func baseLiquidGlassConfig() -> GlassCardKit.GlassCardConfig {
        var config = GlassCardKit.GlassCardConfig()
        let dark = glassAppearanceIsDark()
        let transmissionScale: CGFloat = dark ? 0.88 : 1.08
        let diffusionScale: CGFloat = dark ? 1.15 : 0.88
        config.transmission = max(0.0, min(1.0, DROPDOWN_GLASS_TRANSMISSION * transmissionScale))
        config.diffusionAmount = max(0.0, min(1.0, DROPDOWN_GLASS_DIFFUSION_AMOUNT * diffusionScale))
        return config
    }

    private func dropdownGlassConfig() -> GlassCardKit.GlassCardConfig {
        var config = baseLiquidGlassConfig()
        config.cornerRadius = menuCornerRadius
        config.tint = panelClearGlassTintColor()
        return config
    }

    private func makeDropdownGlassCard() -> GlassCardView {
        let config = dropdownGlassConfig()
        let card = GlassCardKit.makeGlassCard(config: config) { [weak self] rectInWindow, scale in
            self?.captureWindowBackgroundRegion(in: rectInWindow, scale: scale)
        }
        card.translatesAutoresizingMaskIntoConstraints = true
        card.wantsLayer = true
        if #available(macOS 10.13, *) {
            card.layer?.cornerCurve = .continuous
        }
        return card
    }

