    private func makePDFFindGlassCard(tint: NSColor, refractionOnly: Bool = false) -> GlassCardView {
        // Match the liquid-glass popup recipe (refraction + tint) used by toolbar dropdowns.
        var config = dropdownGlassConfig()
        config.cornerRadius = 10
        config.tint = tint
        if refractionOnly {
            // Legacy: crisper bar with reduced diffusion/refraction.
            config.forceTransparent = false
            config.tintBoost = 12.0
            config.fillBoost = 12.0
            config.transmission = 0.88
            config.diffusionAmount = 0.06
            config.specularIntensity = 1.15
            config.fresnelStrength = 0.55
            config.refractionStrength = 1.0
            config.refractionScale = 28.0
        }
        let card = GlassCardKit.makeGlassCard(config: config) { [weak self] rectInWindow, scale in
            self?.capturePDFFindBackgroundRegion(in: rectInWindow, scale: scale)
        }
        card.translatesAutoresizingMaskIntoConstraints = true
        card.wantsLayer = true
        if #available(macOS 10.13, *) {
            card.layer?.cornerCurve = .continuous
        }
        return card
    }

