	    private func leftTableUnderlayTintColor() -> NSColor {
	        let settings = AppSettingsStore.shared.current.appearance
	        guard settings.leftPanelGlassEnabled else {
	            return windowBackgroundSolidColor().withAlphaComponent(1.0)
	        }
	        if settings.leftTablePanelBackgroundMode == .custom {
	            let trimmed = settings.leftTablePanelBackgroundHex.trimmingCharacters(in: .whitespacesAndNewlines)
	            if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
	                let rgb = color.usingColorSpace(.deviceRGB) ?? color
	                return NSColor(srgbRed: rgb.redComponent,
	                               green: rgb.greenComponent,
	                               blue: rgb.blueComponent,
	                               alpha: 1.0)
	            }
	        }
	        let baseTint = rootGlassTheme().rootTint
	        return tablePanelAutomaticTintColor(baseTint: baseTint, isDark: glassAppearanceIsDark())
	    }

	    private func leftTablePanelBackgroundPair() -> (primary: NSColor, alt: NSColor?) {
	        let base = leftPanelEffectiveBackgroundColor()
	        let tint = leftTableUnderlayTintColor()
	        return glassBackgroundPair(base: base, tint: tint, intensity: 1.0)
	    }

	    private func leftTablePanelTextColors(isSelected: Bool, isActive: Bool) -> (title: NSColor, secondary: NSColor) {
	        let pair = leftTablePanelBackgroundPair()
	        let backgrounds = [pair.primary, pair.alt].compactMap { $0 }

	        func adjustedColor(for role: ForegroundRole) -> NSColor {
	            var candidate = resolvedForegroundColor(background: pair.primary,
	                                                    altBackground: pair.alt,
	                                                    role: role,
	                                                    minContrast: 4.5)
	            if !isActive {
	                candidate = blend(candidate, pair.primary, t: 0.10)
	            } else if isSelected {
	                let nudge = relativeLuminance(pair.primary) > 0.55 ? NSColor.black : NSColor.white
	                candidate = blend(candidate, nudge, t: 0.04)
	            }
	            return ensureMinimumContrast(candidate, backgrounds: backgrounds, target: 4.5)
	        }

	        return (adjustedColor(for: .primaryText), adjustedColor(for: .secondaryText))
	    }

    private func rightCardBaseColor() -> NSColor {
        let glassBase = isAppLightAppearance()
            ? DETAILS_PANEL_LIGHT_BG
            : windowGlassTintColor().withAlphaComponent(1.0)
        if let image = rightCardBackgroundImageView?.image,
           let avg = averageColor(from: image) {
            let t = max(0.0, min(1.0, RIGHT_CARD_BACKGROUND_IMAGE_ALPHA))
            return blend(glassBase, avg, t: t)
        }
        if let image = windowBackgroundImageView?.image,
           let avg = averageColor(from: image) {
            let t = max(0.0, min(1.0, WINDOW_BACKGROUND_IMAGE_ALPHA * 0.6))
            return blend(glassBase, avg, t: t)
        }
        return glassBase
    }

