        let docURL = pdfView.document?.documentURL?.path ?? "-"
        let windowVisible = window?.isVisible ?? false
        let state = describeRightPanelState(rightPanelTransitionState)
        NSLog("[SamplePDF] \(label) pages=\(docPages) url=\(docURL) showingPDF=\(isShowingPDF) pdfHidden=\(pdfView.isHidden) detailsHidden=\(detailsWebView.isHidden) loadingHidden=\(loadingOverlay.isHidden) windowVisible=\(windowVisible) state=\(state)")
