    private func ensureSamplePDFOnDisk(using doc: PDFDocument? = nil) -> URL? {
        let candidates = [
            "sample.pdf",
            "Docs/sample.pdf",
            "/tmp/sample.pdf"
        ]
        for path in candidates {
            let url = URL(fileURLWithPath: path)
            if FileManager.default.fileExists(atPath: url.path) {
                return url
            }
        }

        let target = URL(fileURLWithPath: "/tmp/sample.pdf")
        let source = doc ?? makeSampleTextPDFDocument()
        guard source.pageCount > 0 else {
            NSLog("[SamplePDF] failed_generate pages=0")
            return nil
        }
        if source.write(to: target) {
            NSLog("[SamplePDF] wrote path=\(target.path)")
            return target
        }
        NSLog("[SamplePDF] failed_write path=\(target.path)")
        return nil
    }

