    private func noteResizeDragEvent(source: String) {
        if resizeDiagnosticsEnabled {
            resizeDiagnosticsDragCount += 1
            resizeDiagnosticsLastDragNs = monotonicNowNs()
            emitResizeDiagnostics(reason: "drag:\(source)")
        }
        ResizePerfTrace.shared.noteDragEvent()
    }

    private func noteResizeLayoutEvent(name: String) {
        guard resizeDiagnosticsEnabled else { return }
        resizeDiagnosticsLayoutCount += 1
        resizeDiagnosticsLastLayoutNs = monotonicNowNs()
        emitResizeDiagnostics(reason: "layout:\(name)")
    }

    private func emitResizeDiagnostics(reason: String, force: Bool = false) {
        guard resizeDiagnosticsEnabled else { return }
        let now = monotonicNow()
        if resizeDiagnosticsWindowStart == 0 {
            resizeDiagnosticsWindowStart = now
            resizeDiagnosticsLastReport = now
        }
        let elapsed = now - resizeDiagnosticsLastReport
        if !force, elapsed < 0.25 { return }
        let dragHz = elapsed > 0 ? Double(resizeDiagnosticsDragCount) / elapsed : 0
        let layoutHz = elapsed > 0 ? Double(resizeDiagnosticsLayoutCount) / elapsed : 0
        let dragToLayoutMs: Double = {
            guard resizeDiagnosticsLastDragNs > 0, resizeDiagnosticsLastLayoutNs > 0 else { return -1 }
            let delta = resizeDiagnosticsLastLayoutNs &- resizeDiagnosticsLastDragNs
            return Double(delta) / 1_000_000.0
        }()
        let leftW = leftContainer.frame.width
        let rightW = rightSplitContainer.frame.width
        let auxW = rightAuxPanelVisible ? rightAuxPanelWidth() : 0
        let leftHidden = leftContainer.isHidden
        let auxHidden = rightAuxContainer.isHidden
        let auxAlpha = rightAuxContainer.alphaValue
        let leftUnderlayHidden = leftTableUnderlayView?.isHidden ?? true
        let leftUnderlayAlpha = leftTableUnderlayView?.alphaValue ?? -1
        let leftUnderlayH = leftTableUnderlayView?.frame.height ?? -1
        let auxSuperviewMissing = rightAuxContainer.superview == nil
        let leftInvalid = !leftW.isFinite || leftW <= 0
        let auxInvalid = rightAuxPanelVisible && (!auxW.isFinite || auxW <= 0)

        NSLog("[RESIZE_DIAG] reason=\(reason) dragHz=\(String(format: "%.1f", dragHz)) layoutHz=\(String(format: "%.1f", layoutHz)) dragToLayoutMs=\(String(format: "%.2f", dragToLayoutMs)) leftW=\(Int(leftW)) rightW=\(Int(rightW)) auxW=\(Int(auxW)) leftHidden=\(leftHidden) auxHidden=\(auxHidden) auxAlpha=\(String(format: "%.2f", auxAlpha)) auxSuperviewMissing=\(auxSuperviewMissing) underlayHidden=\(leftUnderlayHidden) underlayAlpha=\(String(format: "%.2f", leftUnderlayAlpha)) underlayH=\(Int(leftUnderlayH)) leftRaster=\(leftPanelRasterizationActive) auxRaster=\(rightAuxRasterizationActive) winRaster=\(windowBackgroundRasterizationActive) dividerDrag=\(dividerDragActive) rightDrag=\(rightSplitDividerDragActive) liveResize=\(window?.inLiveResize == true) invalidLeft=\(leftInvalid) invalidAux=\(auxInvalid)")

        resizeDiagnosticsDragCount = 0
        resizeDiagnosticsLayoutCount = 0
        resizeDiagnosticsLastReport = now
    }

    private func applyResizeRasterization(active: Bool, to view: NSView?) {
        guard let view else { return }
        view.wantsLayer = true
        if let layer = view.layer {
            layer.shouldRasterize = active
            if active {
                layer.rasterizationScale = window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0
            }
        }
    }

    private func disableRasterization(for view: NSView?) {
        guard let view, let layer = view.layer else { return }
        if layer.shouldRasterize {
            layer.shouldRasterize = false
        }
    }

    private func updateLeftPanelRasterizationState(reason: String) {
        _ = reason
        if !leftPanelRasterizationActive { return }
        leftPanelRasterizationActive = false
        applyResizeRasterization(active: false, to: leftContainer)
        disableRasterization(for: leftTableUnderlayView)
        disableRasterization(for: leftHeaderGlassBackground)
        applyResizeRasterization(active: false, to: leftCardBackgroundImageView)
        applyResizeRasterization(active: false, to: leftCardGlowView)
        leftContainer.needsDisplay = true
        leftTableUnderlayView?.needsDisplay = true
        leftHeaderGlassBackground?.needsDisplay = true
        ResizePerfTrace.shared.noteInvalidation(name: "left_panel.needsDisplay")
    }

    private func updateRightAuxRasterizationState(reason: String) {
        _ = reason
        if !rightAuxRasterizationActive { return }
        rightAuxRasterizationActive = false
        applyResizeRasterization(active: false, to: rightAuxContainer)
        rightAuxContainer.needsDisplay = true
        ResizePerfTrace.shared.noteInvalidation(name: "right_aux.needsDisplay")
    }

    private func updateWindowBackgroundRasterizationState(reason: String) {
        _ = reason
        // Only rasterize during live resize; avoid move-time rasterization that can flash a black fill.
        let shouldRasterize = windowBackgroundFrozenByLiveResize || windowBackgroundFrozenBySnap
        if shouldRasterize == windowBackgroundRasterizationActive { return }
        windowBackgroundRasterizationActive = shouldRasterize
        applyResizeRasterization(active: shouldRasterize, to: windowBackgroundView)
        if !shouldRasterize {
            windowBackgroundView.needsDisplay = true
            ResizePerfTrace.shared.noteInvalidation(name: "window_background.needsDisplay")
        }
    }

    private func installSamplePDFIfNeeded() {
        guard samplePDFEnabled else { return }
        let doc = makeSampleTextPDFDocument()
        pdfView.document = doc
        pdfView.displayBox = .mediaBox
        _ = ensureSamplePDFOnDisk(using: doc)
        var shouldForceTop = false
        // Restore position or go to top
        if let position = pdfPositions["sample"], let page = doc.page(at: position.pageIndex) {
            pdfView.autoScales = false
            pdfZoomPreset = .free
            applyPDFScale(position.scale)
            pdfView.go(to: page)
            if let scrollView = pdfView.primaryScrollView() {
                var origin = scrollView.contentView.bounds.origin
                origin.y = position.scrollY
                scrollView.contentView.setBoundsOrigin(origin)
            }
        } else {
            pdfView.autoScales = false
            pdfZoomPreset = .pageWidth
            pdfView.goToFirstPage(nil)
            if let scrollView = pdfView.primaryScrollView() {
                scrollView.contentView.setBoundsOrigin(.zero)
            }
            shouldForceTop = true
        }
        applyPDFZoomPresetIfNeeded()
        if shouldForceTop {
            scrollPDFToDocumentTop()
        }
        hideLoading()
        hidePDFFindHUD()
        showPDFPanel(animated: false)
        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            self.applyPDFZoomPresetIfNeeded()
            if shouldForceTop {
                self.scrollPDFToDocumentTop()
            }
        }
        logSamplePDFState("install")
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) { [weak self] in
            self?.forceSamplePDFVisible(reason: "post_install")
        }
        pdfSelectLog("installed_sample_pdf pages=\(doc.pageCount)")
    }

    private func forceSamplePDFVisible(reason: String) {
        guard samplePDFEnabled else { return }
        if pdfView.document == nil || (pdfView.document?.pageCount ?? 0) == 0 {
            let doc = makeSampleTextPDFDocument()
            pdfView.document = doc
            pdfView.displayBox = .mediaBox
            _ = ensureSamplePDFOnDisk(using: doc)
        }
        if !loadingOverlay.isHidden {
            hideLoading()
        }
        showPDFPanel(animated: false)
        logSamplePDFState("force_\(reason)")
    }

    private func makeSampleTextPDFDocument() -> PDFDocument {
        let data = NSMutableData()
        guard let consumer = CGDataConsumer(data: data as CFMutableData) else {
            return PDFDocument()
        }

        var mediaBox = CGRect(x: 0, y: 0, width: 612, height: 792) // US Letter @ 72 dpi
        guard let ctx = CGContext(consumer: consumer, mediaBox: &mediaBox, nil) else {
            return PDFDocument()
        }

        ctx.beginPDFPage(nil)
        ctx.setFillColor(NSColor.white.cgColor)
        ctx.fill(mediaBox)

        let text = """
    WATCHER FAKE PDF (selection test)

Drag to highlight this text.
Use Shift+Arrow keys to extend selection once the PDF view is focused.

The quick brown fox jumps over the lazy dog.
0123456789 — Symbols: α β γ ∑ ∫ ≤ ≥ ≠
"""

        let attr = NSAttributedString(
            string: text,
            attributes: [
                .font: NSFont.systemFont(ofSize: 16, weight: .regular),
                .foregroundColor: NSColor.black
            ]
        )

        ctx.saveGState()
        // ctx.textMatrix = .identity
        // ctx.translateBy(x: 0, y: mediaBox.height)
        // ctx.scaleBy(x: 1, y: -1)

        let frameRect = CGRect(x: 72, y: mediaBox.height - 72 - 200, width: 468, height: 200)
        let path = CGPath(rect: frameRect, transform: nil)
        let framesetter = CTFramesetterCreateWithAttributedString(attr as CFAttributedString)
        let frame = CTFramesetterCreateFrame(framesetter, CFRange(location: 0, length: attr.length), path, nil)
        CTFrameDraw(frame, ctx)

        ctx.restoreGState()
        ctx.endPDFPage()
        ctx.closePDF()

        return PDFDocument(data: data as Data) ?? PDFDocument()
    }

