    private func debugConstraintDescription(_ constraint: NSLayoutConstraint) -> String {
        func describeItem(_ item: AnyObject?) -> String {
            guard let item else { return "nil" }
            if let view = item as? NSView {
                let addr = Unmanaged.passUnretained(view).toOpaque()
                let id = view.identifier?.rawValue ?? ""
                let label = debugViewLabel(view)
                let labelPart = label.isEmpty ? "" : " label=\(label)"
                let idPart = id.isEmpty ? "" : " id=\(id)"
                return "\(type(of: view)):\(addr)\(labelPart)\(idPart)"
            }
            return "\(item)"
        }

        let first = describeItem(constraint.firstItem)
        let second = describeItem(constraint.secondItem)
        let relation: String
        switch constraint.relation {
        case .lessThanOrEqual: relation = "<="
        case .equal: relation = "=="
        case .greaterThanOrEqual: relation = ">="
        @unknown default: relation = "?"
        }
        let id = constraint.identifier ?? ""
        return "[\(id)] \(first).\(constraint.firstAttribute) \(relation) \(second).\(constraint.secondAttribute) + \(String(format: "%.2f", constraint.constant)) pri=\(Int(constraint.priority.rawValue)) active=\(constraint.isActive)"
    }

    private func debugViewChain(from view: NSView, maxDepth: Int = 10) -> String {
        var parts: [String] = []
        var current: NSView? = view
        var depth = 0
        while let v = current, depth < maxDepth {
            let addr = Unmanaged.passUnretained(v).toOpaque()
            let id = v.identifier?.rawValue ?? ""
            let label = debugViewLabel(v)
            var piece = "\(type(of: v)):\(addr)"
            if !label.isEmpty { piece += " label=\(label)" }
            if !id.isEmpty { piece += " id=\(id)" }
            parts.append(piece)
            current = v.superview
            depth += 1
        }
        return parts.joined(separator: " -> ")
    }

    private func debugLogConstraints(for view: NSView, label: String) {
        let h = view.constraintsAffectingLayout(for: .horizontal)
        let v = view.constraintsAffectingLayout(for: .vertical)
        uiLog("constraints \(label) h=\(h.count) v=\(v.count)")
        for c in h { uiLog("  H \(debugConstraintDescription(c))") }
        for c in v { uiLog("  V \(debugConstraintDescription(c))") }
        if let superview = view.superview {
            let related = superview.constraints.filter { $0.firstItem as? NSView === view || $0.secondItem as? NSView === view }
            uiLog("  superview constraints \(label) count=\(related.count)")
            for c in related { uiLog("    S \(debugConstraintDescription(c))") }
        }
    }

    private func launchAuditConstraintConstants(reason: String, threshold: CGFloat = 1_000_000) {
        guard launchDebugEnabled, let root = window?.contentView else { return }
        var seen = Set<ObjectIdentifier>()
        var anomalies: [NSLayoutConstraint] = []

        func consider(_ constraint: NSLayoutConstraint) {
            let id = ObjectIdentifier(constraint)
            guard !seen.contains(id) else { return }
            seen.insert(id)
            let constant = constraint.constant
            if !constant.isFinite || abs(constant) > threshold {
                anomalies.append(constraint)
            }
        }

        func walk(_ view: NSView) {
            for c in view.constraints { consider(c) }
            for c in view.constraintsAffectingLayout(for: .horizontal) { consider(c) }
            for c in view.constraintsAffectingLayout(for: .vertical) { consider(c) }
            for sub in view.subviews { walk(sub) }
        }

        walk(root)
        launchLog("constraint_audit reason=\(reason) anomalies=\(anomalies.count)")
        for c in anomalies {
            launchLog("constraint_anomaly \(debugConstraintDescription(c))")
			if let v = c.firstItem as? NSView {
				launchLog("constraint_anomaly_firstItem_chain \(debugViewChain(from: v))")
			}
        }
    }

    private func debugViewLabel(_ view: NSView) -> String {
        if view === splitView { return "SplitView" }
        if view === leftContainer { return "LeftPanel" }
        if view === rightContainer { return "RightPanel" }
        if view === searchContainer { return "SearchContainer" }
        if view === headerControlsContainer { return "HeaderControls" }
        if view === suggestionsContainer { return "SuggestionsContainer" }
        if view === menuContainer { return "MenuContainer" }
        return ""
    }

    private func debugDumpViewTree(from view: NSView, depth: Int = 0) {
        let indent = String(repeating: "  ", count: depth)
        let addr = Unmanaged.passUnretained(view).toOpaque()
        let label = debugViewLabel(view)
        let frame = view.frame
        uiLog("\(indent)\(type(of: view)) \(addr) \(label) frame=\(String(format: "%.1f", frame.origin.x)),\(String(format: "%.1f", frame.origin.y)) \(String(format: "%.1f", frame.size.width))x\(String(format: "%.1f", frame.size.height)) tamic=\(view.translatesAutoresizingMaskIntoConstraints) hidden=\(view.isHidden)")
        for (index, sub) in view.subviews.enumerated() {
            uiLog("\(indent)  [\(index)]")
            debugDumpViewTree(from: sub, depth: depth + 1)
        }
    }

    private func debugDumpViewHierarchy(reason: String) {
        guard uiDebugEnabled, let root = window?.contentView else { return }
        uiLog("view_tree_begin reason=\(reason)")
        debugDumpViewTree(from: root)
        debugLogConstraints(for: splitView, label: "splitView")
        debugLogConstraints(for: leftContainer, label: "leftContainer")
        debugLogConstraints(for: rightContainer, label: "rightContainer")
        if let rect = dividerRectInWindow() {
            uiLog("divider_rect window=\(String(format: "%.1f", rect.origin.x)),\(String(format: "%.1f", rect.origin.y)) \(String(format: "%.1f", rect.size.width))x\(String(format: "%.1f", rect.size.height))")
        } else {
            uiLog("divider_rect window=nil")
        }
        uiLog("view_tree_end reason=\(reason)")
    }

    private func debugProbeDividerHitTest(reason: String) {
        guard uiDebugEnabled, let root = window?.contentView,
              let rect = dividerRectInWindow() else { return }
        let point = NSPoint(x: rect.midX, y: rect.midY)
        let hit = root.hitTest(point)
        var chain: [String] = []
        var current = hit
        while let view = current {
            chain.append(String(describing: type(of: view)))
            current = view.superview
        }
        let chainText = chain.joined(separator: " -> ")
        uiLog("divider_probe reason=\(reason) point=\(String(format: "%.1f", point.x)),\(String(format: "%.1f", point.y)) hit=\(describeHitView(hit)) chain=\(chainText)")
    }

    private func debugProbeToolbarHitTests(reason: String) {
        guard uiDebugEnabled, let root = window?.contentView else { return }

        func probe(_ view: NSView, name: String) {
            guard let viewWindow = view.window, let rootWindow = root.window, viewWindow === rootWindow else {
                uiLog("hit_probe skip name=\(name) reason=\(reason) window_mismatch")
                return
            }
            let rectInWindow = view.convert(view.bounds, to: nil)
            let point = NSPoint(x: rectInWindow.midX, y: rectInWindow.midY)
            let hit = root.hitTest(point)
            var chain: [String] = []
            var current = hit
            while let v = current {
                chain.append(String(describing: type(of: v)))
                current = v.superview
            }
            let pointText = "\(String(format: "%.1f", point.x)),\(String(format: "%.1f", point.y))"
            let chainText = chain.joined(separator: " -> ")
            uiLog("hit_probe name=\(name) reason=\(reason) point=\(pointText) hit=\(describeHitView(hit)) chain=\(chainText)")
        }

        probe(sidebarToggleButton, name: "sidebar_toggle")
        probe(sidebarMenuButton, name: "sidebar_menu")
        probe(backButton, name: "nav_back")
        probe(forwardButton, name: "nav_forward")
        probe(rightPanelPillControl, name: "pill")
    }

    private func debugProbeViewerHitTest(reason: String) {
        guard uiDebugEnabled, let root = window?.contentView else { return }
        guard let viewWindow = rightPanelContentHost.window,
              let rootWindow = root.window,
              viewWindow === rootWindow else {
            uiLog("viewer_probe skip reason=\(reason) window_mismatch")
            return
        }
        let rectInWindow = rightPanelContentHost.convert(rightPanelContentHost.bounds, to: nil)
        let point = NSPoint(x: rectInWindow.midX, y: rectInWindow.midY)
        let hit = root.hitTest(point)
        uiLog("viewer_probe reason=\(reason) host=\(Int(rectInWindow.width))x\(Int(rectInWindow.height)) isShowingPDF=\(isShowingPDF) pdfHidden=\(pdfView.isHidden) detailsHidden=\(detailsWebView.isHidden) hit=\(describeHitView(hit))")
    }

    private func dividerRectInWindow() -> NSRect? {
        guard splitView.subviews.count >= 2 else { return nil }
        let rect = splitView.dividerRect(at: 0)
        guard rect.width > 0, rect.height > 0 else { return nil }
        return splitView.convert(rect, to: nil)
    }

    private func rightSplitDividerRectInWindow() -> NSRect? {
        guard rightSplitView.subviews.count >= 2 else { return nil }
        let rect = rightSplitView.dividerRect(at: 0)
        guard rect.width > 0, rect.height > 0 else { return nil }
        return rightSplitView.convert(rect, to: nil)
    }

    private func logDividerState(_ event: String) {
        guard uiDebugEnabled else { return }
        let leftW = leftContainer.frame.width
        let rightW = rightContainer.frame.width
        let totalW = splitView.bounds.width
        let dividerX = splitView.dividerRect(at: 0).minX
        uiLog("divider_\(event) left=\(Int(leftW)) right=\(Int(rightW)) total=\(Int(totalW)) pos=\(Int(dividerX))")
    }

    private func describeHitView(_ view: NSView?) -> String {
        guard let view else { return "nil" }
        let name = String(describing: type(of: view))
        let frame = view.frame
        return "\(name) frame=\(Int(frame.origin.x)),\(Int(frame.origin.y)) \(Int(frame.size.width))x\(Int(frame.size.height)) hidden=\(view.isHidden)"
    }

    private func logSearchDebug(_ message: String) {
        guard searchDebugEnabled else { return }
        NSLog("[SearchDebug] \(message)")
    }

    private func enforceActiveVisualEffectState(_ view: NSView) {
        // Keep effect views stable across active/inactive and appearance changes.
        // Do NOT force emphasis here; emphasis affects perceived brightness (especially in Light Mode).
        if let effect = view as? NSVisualEffectView {
            effect.state = .followsWindowActiveState
        }
    }

    private func makeGlassEffectView(passthrough: Bool = false,
                                     cornerRadius: CGFloat = 0,
                                     tintColor: NSColor? = nil,
                                     style: NSGlassEffectView.Style = .regular,
                                     fallbackMaterial: NSVisualEffectView.Material = .hudWindow,
                                     fallbackBlending: NSVisualEffectView.BlendingMode = .withinWindow,
                                     fallbackState: NSVisualEffectView.State = .active,
                                     emphasized: Bool = true,
                                     forceVisualEffectFallback: Bool = false) -> NSView {
        if !forceVisualEffectFallback, #available(macOS 26.0, *) {
            let view: NSGlassEffectView = passthrough ? PassthroughGlassEffectView(frame: .zero) : NSGlassEffectView(frame: .zero)
            view.cornerRadius = cornerRadius
            view.tintColor = tintColor
            view.style = style
            view.translatesAutoresizingMaskIntoConstraints = false
            enforceActiveVisualEffectState(view)
            return view
        }

        let view: NSVisualEffectView = passthrough ? PassthroughVisualEffectView(frame: .zero) : NSVisualEffectView(frame: .zero)
        let isDark = glassAppearanceIsDark()
        let resolvedMaterial: NSVisualEffectView.Material = (!isDark && fallbackMaterial == .hudWindow) ? .underWindowBackground : fallbackMaterial
        view.blendingMode = fallbackBlending
        view.material = resolvedMaterial
        view.state = fallbackState
        view.isEmphasized = isDark ? emphasized : false
        view.translatesAutoresizingMaskIntoConstraints = false
        view.wantsLayer = true
        view.layer?.cornerRadius = cornerRadius
        view.layer?.masksToBounds = true
        if #available(macOS 10.13, *) {
            view.layer?.cornerCurve = .continuous
        }
        if let tint = tintColor {
            view.layer?.backgroundColor = tint.cgColor
        }
        enforceActiveVisualEffectState(view)
        return view
    }

    private func applyShortcutResultGlassStyle(to view: NSView) {
        view.wantsLayer = true
        if let layer = view.layer {
            layer.shadowColor = NSColor.black.cgColor
            layer.shadowOpacity = 0.25
            layer.shadowRadius = 24
            layer.shadowOffset = CGSize(width: 0, height: -8)
            layer.borderWidth = 1.0
            layer.borderColor = NSColor.white.withAlphaComponent(0.25).cgColor
        }
    }

    private func clearGlassBorder(for view: NSView) {
        view.wantsLayer = true
        if let layer = view.layer {
            layer.borderWidth = 0
            layer.borderColor = NSColor.clear.cgColor
        }
    }

    private func clearGlassShadow(for view: NSView) {
        view.wantsLayer = true
        if let layer = view.layer {
            layer.shadowColor = NSColor.clear.cgColor
            layer.shadowOpacity = 0
            layer.shadowRadius = 0
            layer.shadowOffset = .zero
            layer.shadowPath = nil
        }
    }

    private func clearGlassChrome(for view: NSView) {
        clearGlassBorder(for: view)
        clearGlassShadow(for: view)
    }

    private func updateLeftPanelFreezeState(reason: String) {
        updateLeftPanelRasterizationState(reason: reason)
    }

    private func makeShortcutResultGlassBase(cornerRadius: CGFloat = SHORTCUT_RESULT_GLASS_CORNER_RADIUS,
                                             tint: NSColor? = nil) -> NSView {
        let glass = makeGlassEffectView(
            passthrough: false,
            cornerRadius: cornerRadius,
            tintColor: tint ?? shortcutResultAccentTintColor(),
            style: .regular,
            fallbackMaterial: .hudWindow,
            fallbackBlending: .behindWindow,
            fallbackState: .active,
            emphasized: false
        )
        applyShortcutResultGlassStyle(to: glass)
        return glass
    }

    private func makeShortcutResultGlassBackground(cornerRadius: CGFloat) -> NSView {
        let glass = makeGlassEffectView(
            passthrough: true,
            cornerRadius: cornerRadius,
            tintColor: shortcutResultAccentTintColor(),
            style: .regular,
            fallbackMaterial: .hudWindow,
            fallbackBlending: .behindWindow,
            fallbackState: .active,
            emphasized: false
        )
        applyShortcutResultGlassStyle(to: glass)
        glass.layer?.masksToBounds = false
        return glass
    }

    private func embedContentView(_ content: NSView, into host: NSView) {
        if #available(macOS 26.0, *), let glass = host as? NSGlassEffectView {
            glass.contentView = content
            content.frame = glass.bounds
            content.autoresizingMask = [.width, .height]
        } else {
            if let effect = host as? NSVisualEffectView {
                effect.addSubview(content)
            } else {
                host.addSubview(content)
            }
            content.frame = host.bounds
            content.autoresizingMask = [.width, .height]
        }
    }

    private func installGlassContainerIfAvailable(on content: NSView) -> NSView {
        glassContainerView = nil
        glassContainerContentView = nil
        return content
    }

	    init() {
        launchLog("PickerWindowController.init start")

	        let window = NSWindow(
            contentRect: NSRect(x: 0, y: 0, width: 1700, height: 900),
            styleMask: [.titled, .closable, .resizable, .miniaturizable],
            backing: .buffered,
            defer: false
        )
        window.title = APP_EFFECTIVE_NAME
        window.center()
        launchLog("window created frame=\(NSStringFromRect(window.frame))")

        super.init(window: window)
        window.delegate = self
            baseWindowContentMinSize = window.contentMinSize
            defaultWindowContentSize = window.contentRect(forFrameRect: window.frame).size
            if let screen = window.screen ?? NSScreen.main {
                let screenWidth = screen.frame.width
                if screenWidth.isFinite, screenWidth > 1, let contentSize = defaultWindowContentSize {
                    let ratio = contentSize.width / screenWidth
                    defaultWindowMinWidthScreenRatio = max(0.1, min(maxWindowMinWidthScreenRatio, ratio))
                }
            }

        configureWindowAppearance()
        launchLog("configureWindowAppearance done")
	        setupUI()
        launchLog("setupUI done")
        installSettingsObservers()
        installRootGlassTintObservers()
        setupPinnedHeader()
        setupRightPanelViews()
        setupPDFFindHUD()
        setupLoadingOverlay()
        applySettingsChange(reason: "startup")
        installSamplePDFIfNeeded()
        runRightPanelTransitionStressTestIfRequested()
        installCacheLifecycleObservers()
        pdfDocumentCache.countLimit = 12

        launchLog("PickerWindowController.init end window=\(window.isVisible ? "visible" : "hidden")")
    }

    required init?(coder: NSCoder) { fatalError() }

	    deinit {
        if let keyMonitor { NSEvent.removeMonitor(keyMonitor) }
        if let pdfWheelMonitor { NSEvent.removeMonitor(pdfWheelMonitor) }
        if let selectionClearMonitor { NSEvent.removeMonitor(selectionClearMonitor) }
        if let dividerDragEndMonitor { NSEvent.removeMonitor(dividerDragEndMonitor) }
        if let windowResizeObserver { NotificationCenter.default.removeObserver(windowResizeObserver) }
        if let splitResizeObserver { NotificationCenter.default.removeObserver(splitResizeObserver) }
        if let splitWillResizeObserver { NotificationCenter.default.removeObserver(splitWillResizeObserver) }
        if let hitTestMoveMonitor { NSEvent.removeMonitor(hitTestMoveMonitor) }
        if let hitTestDownMonitor { NSEvent.removeMonitor(hitTestDownMonitor) }
        if let hitTestUpMonitor { NSEvent.removeMonitor(hitTestUpMonitor) }
        if let panelActivationDownMonitor { NSEvent.removeMonitor(panelActivationDownMonitor) }
        if let pdfSelectDownMonitor { NSEvent.removeMonitor(pdfSelectDownMonitor) }
        if let pdfSelectDragMonitor { NSEvent.removeMonitor(pdfSelectDragMonitor) }
        if let pdfSelectUpMonitor { NSEvent.removeMonitor(pdfSelectUpMonitor) }
        if let pillClickMonitor { NSEvent.removeMonitor(pillClickMonitor) }
        for obs in windowFocusObservers { NotificationCenter.default.removeObserver(obs) }
        if let windowLiveResizeStartObserver { NotificationCenter.default.removeObserver(windowLiveResizeStartObserver) }
        if let windowLiveResizeEndObserver { NotificationCenter.default.removeObserver(windowLiveResizeEndObserver) }
        if let windowMoveObserver { NotificationCenter.default.removeObserver(windowMoveObserver) }
        if let windowScreenObserver { NotificationCenter.default.removeObserver(windowScreenObserver) }
        removeSidebarTogglePDFScrollObserver()
        for obs in rootGlassTintObservers { NotificationCenter.default.removeObserver(obs) }
        rootGlassTintObservers.removeAll()
        for obs in rootGlassTintDistributedObservers { DistributedNotificationCenter.default().removeObserver(obs) }
        rootGlassTintDistributedObservers.removeAll()
	        dividerSettleWorkItem?.cancel()
        viewModeTransitionWorkItem?.cancel()
	        if let u = lastTempHTMLURL { try? FileManager.default.removeItem(at: u) }
        if let searchBackgroundFrameObserver { NotificationCenter.default.removeObserver(searchBackgroundFrameObserver) }
        if let tableScrollObserver { NotificationCenter.default.removeObserver(tableScrollObserver) }
        if let settingsChangeObserver { NotificationCenter.default.removeObserver(settingsChangeObserver) }
        if let appTerminationObserver { NotificationCenter.default.removeObserver(appTerminationObserver) }
        windowBackgroundFreezeMoveWorkItem?.cancel()
        sidebarTogglePDFSnapshotClearWorkItem?.cancel()
        sidebarTogglePDFScrollLockTimer?.invalidate()
        sidebarTogglePDFScrollLockTimer = nil
        if let session = appleIntelligenceSession {
            session.popover.close()
            appleIntelligenceSession = nil
        }
        splitDividerSpringTimer?.invalidate()
        if let observer = pdfFindScrollObserver {
            NotificationCenter.default.removeObserver(observer)
            pdfFindScrollObserver = nil
        }
        pdfFindBackgroundRefreshWorkItem?.cancel()
        pdfFindLiveGlassStopWorkItem?.cancel()
        pdfFindLiveGlassTimer?.invalidate()
        if pdfCacheCleanupState != .cleaned, let cache = pdfCacheStorage {
            cache.cleanupOnExit()
        }
	    }

    func windowWillClose(_ notification: Notification) {
        beginPDFCacheCleanup(reason: "window_close", terminateAfter: true)
    }

    func windowDidBecomeKey(_ notification: Notification) {
        window?.acceptsMouseMovedEvents = true
        installHoverTooltipMonitor()
        ensureDefaultSelectionIfNeeded(reason: "window-key")
    }

	    private func beginPDFCacheCleanup(reason: String, terminateAfter: Bool) {
	        if pdfCacheCleanupState == .cleaned {
	            if terminateAfter { NSApp.terminate(nil) }
	            return
	        }
	        if pdfCacheCleanupState == .cleaning { return }
            guard let cache = pdfCacheStorage else {
                pdfCacheCleanupState = .cleaned
                if terminateAfter { NSApp.terminate(nil) }
                return
            }
	        pdfCacheCleanupState = .cleaning

	        let dir = cache.sessionDirectory.path
	        NSLog("[PDFEager] cleanup_start reason=\(reason) dir=\(dir)")
	        DispatchQueue.global(qos: .utility).async { [weak self] in
	            guard let self else { return }
	            cache.cleanupOnExit()
	            self.pdfDocumentCache.removeAllObjects()
	            DispatchQueue.main.async {
	                self.pdfCacheCleanupState = .cleaned
	                if terminateAfter { NSApp.terminate(nil) }
	            }
	        }
	    }

    // Public entry point so main() can apply STDIN payload immediately (fixes “does nothing”).
    func ingestPayloadIfPresent(_ payload: Payload?) {
        ingestPayload(payload, allowEmpty: false)
    }

    func ingestPayload(_ payload: Payload?, allowEmpty: Bool) {
        guard let payload else { return }
        if !allowEmpty && payload.papers.isEmpty { return }
        DispatchQueue.main.async {
            self.applyPayload(payload)
        }
    }

    func setLoadingVisible(_ visible: Bool, message: String?) {
        if visible {
            showLoading(message ?? "Loading…")
        } else {
            hideLoading()
        }
    }

    // MARK: UI setup

    private func configureWindowAppearance() {
        guard let window else { return }
        if liquidGlassEnabled {
            // Keep the window transparent so the system glass can sample behind it.
            window.isOpaque = false
            window.backgroundColor = .clear
            window.contentView?.wantsLayer = true
            window.contentView?.layer?.backgroundColor = NSColor.clear.cgColor
            installTitlebarTintBackground()
        } else {
            window.isOpaque = true
            let bg = resolvedSystemColor(.windowBackgroundColor)
            window.backgroundColor = bg
            window.contentView?.wantsLayer = true
            window.contentView?.layer?.backgroundColor = bg.cgColor
            window.titlebarAppearsTransparent = false
            if #available(macOS 11.0, *) {
                window.titlebarSeparatorStyle = .automatic
            }
            removeTitlebarTintViews()
        }

        // Enforce window size limits.
        window.minSize = NSSize(width: 760, height: 480)
        window.maxSize = NSSize(width: 3200, height: 2400)
    }

    private func removeTitlebarTintViews() {
        titlebarDividerHeightConstraint?.isActive = false
        titlebarDividerHeightConstraint = nil
        titlebarDividerView?.removeFromSuperview()
        titlebarDividerView = nil
        titlebarTintView?.removeFromSuperview()
        titlebarTintView = nil
        titlebarSeamCoverTopConstraint?.isActive = false
        titlebarSeamCoverHeightConstraint?.isActive = false
        titlebarSeamCoverTopConstraint = nil
        titlebarSeamCoverHeightConstraint = nil
        titlebarSeamCoverView?.removeFromSuperview()
        titlebarSeamCoverView = nil
        removeTitlebarTitleLabel()
    }

    private func updateTitlebarTitleAppearance() {
        guard let label = titlebarTitleLabel else { return }
        label.stringValue = APP_EFFECTIVE_NAME
        label.font = NSFont.titleBarFont(ofSize: 0)
        let base = windowBackgroundSolidColor()
        let tint = windowBackgroundGlassTintColor()
        label.textColor = resolvedForegroundColor(base: base, tint: tint, role: .primaryText)
    }

    private func removeTitlebarTitleLabel() {
        titlebarTitleLeadingConstraint?.isActive = false
        titlebarTitleCenterYConstraint?.isActive = false
        titlebarTitleTrailingConstraint?.isActive = false
        titlebarTitleLeadingConstraint = nil
        titlebarTitleCenterYConstraint = nil
        titlebarTitleTrailingConstraint = nil
        titlebarTitleLabel?.removeFromSuperview()
        titlebarTitleLabel = nil
        titlebarTitleContainer?.removeFromSuperview()
        titlebarTitleContainer = nil
        if let window {
            window.titleVisibility = .visible
        }
    }

    private func installTitlebarTitleLabel() {
        guard let window else { return }
        guard let titlebarContainer = window.standardWindowButton(.closeButton)?.superview else {
            window.titleVisibility = .visible
            return
        }

        let container: PassthroughView
        if let existing = titlebarTitleContainer, existing.superview === titlebarContainer {
            container = existing
        } else {
            titlebarTitleContainer?.removeFromSuperview()
            let v = PassthroughView(frame: .zero)
            v.translatesAutoresizingMaskIntoConstraints = false
            titlebarContainer.addSubview(v, positioned: .above, relativeTo: nil)
            titlebarTitleContainer = v
            container = v
        }

        let label: NSTextField
        if let existing = titlebarTitleLabel, existing.superview === container {
            label = existing
        } else {
            titlebarTitleLabel?.removeFromSuperview()
            let tf = NSTextField(labelWithString: APP_EFFECTIVE_NAME)
            tf.translatesAutoresizingMaskIntoConstraints = false
            tf.isEditable = false
            tf.isSelectable = false
            tf.isBezeled = false
            tf.drawsBackground = false
            tf.alignment = .left
            tf.lineBreakMode = .byTruncatingTail
            tf.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)
            tf.setContentHuggingPriority(.defaultHigh, for: .horizontal)
            container.addSubview(tf)
            NSLayoutConstraint.activate([
                tf.leadingAnchor.constraint(equalTo: container.leadingAnchor),
                tf.trailingAnchor.constraint(equalTo: container.trailingAnchor),
                tf.topAnchor.constraint(equalTo: container.topAnchor),
                tf.bottomAnchor.constraint(equalTo: container.bottomAnchor)
            ])
            titlebarTitleLabel = tf
            label = tf
        }

        titlebarTitleLeadingConstraint?.isActive = false
        titlebarTitleCenterYConstraint?.isActive = false
        titlebarTitleTrailingConstraint?.isActive = false
        let closeButton = window.standardWindowButton(.closeButton)
        let miniButton = window.standardWindowButton(.miniaturizeButton)
        let zoomButton = window.standardWindowButton(.zoomButton)
        let anchorButton = zoomButton ?? miniButton ?? closeButton
        let anchor = anchorButton?.trailingAnchor ?? titlebarContainer.leadingAnchor
        let centerAnchor = anchorButton?.centerYAnchor ?? titlebarContainer.centerYAnchor
        titlebarTitleLeadingConstraint = container.leadingAnchor.constraint(equalTo: anchor, constant: 8)
        titlebarTitleCenterYConstraint = container.centerYAnchor.constraint(equalTo: centerAnchor)
        titlebarTitleTrailingConstraint = container.trailingAnchor.constraint(lessThanOrEqualTo: titlebarContainer.trailingAnchor, constant: -12)
        NSLayoutConstraint.activate([
            titlebarTitleLeadingConstraint!,
            titlebarTitleCenterYConstraint!,
            titlebarTitleTrailingConstraint!
        ])

        updateTitlebarTitleAppearance()
        window.titleVisibility = .hidden
    }

    private func windowBackgroundHostView(for content: NSView) -> NSView {
        if let frameView = window?.contentView?.superview {
            return frameView
        }
        return content
    }

    private func installTitlebarTintBackground() {
        guard let window else { return }
        guard liquidGlassEnabled else {
            removeTitlebarTintViews()
            window.titlebarAppearsTransparent = false
            if #available(macOS 11.0, *) {
                window.titlebarSeparatorStyle = .automatic
            }
            return
        }
        // Make the system titlebar background transparent so our custom tint can show through.
        window.titlebarAppearsTransparent = true
        if #available(macOS 11.0, *) {
            window.titlebarSeparatorStyle = .none
        }
        if let frameView = window.contentView?.superview,
           windowBackgroundView.superview === frameView {
            removeTitlebarTintViews()
            installTitlebarTitleLabel()
            return
        }

        guard let titlebarContainer = window.standardWindowButton(.closeButton)?.superview else { return }
        let desiredTint = windowBackgroundGlassTintColor()

        let tintView: NSView
        if let existing = titlebarTintView {
            // If we previously installed a non-effect view, replace it so the tint actually matches the search glass.
            let isEffect = (existing is NSVisualEffectView) || (existing is NSGlassEffectView)
            if !isEffect {
                existing.removeFromSuperview()
                titlebarTintView = nil
            }
        }
        if let existing = titlebarTintView {
            tintView = existing
        } else {
            // Use a passthrough glass/effect view so the titlebar reads like the same surface as the search bar.
            if #available(macOS 26.0, *) {
                let v = PassthroughGlassEffectView(frame: titlebarContainer.bounds)
                v.translatesAutoresizingMaskIntoConstraints = false
                v.wantsLayer = true
                v.layer?.masksToBounds = true
                if #available(macOS 10.13, *) { v.layer?.cornerCurve = .continuous }
                titlebarContainer.addSubview(v, positioned: .below, relativeTo: nil)
                NSLayoutConstraint.activate([
                    v.leadingAnchor.constraint(equalTo: titlebarContainer.leadingAnchor),
                    v.trailingAnchor.constraint(equalTo: titlebarContainer.trailingAnchor),
                    v.topAnchor.constraint(equalTo: titlebarContainer.topAnchor),
                    v.bottomAnchor.constraint(equalTo: titlebarContainer.bottomAnchor),
                ])
                titlebarTintView = v
                tintView = v
            } else {
                let v = PassthroughVisualEffectView(frame: titlebarContainer.bounds)
                v.translatesAutoresizingMaskIntoConstraints = false
                v.wantsLayer = true
                v.layer?.masksToBounds = true
                if #available(macOS 10.13, *) { v.layer?.cornerCurve = .continuous }
                // Match the search bar's fallback material choices.
                v.material = currentSearchBarTheme().fallbackMaterial
                v.blendingMode = currentSearchBarTheme().fallbackBlending
                v.state = currentSearchBarTheme().fallbackState
                v.isEmphasized = currentSearchBarTheme().emphasized
                titlebarContainer.addSubview(v, positioned: .below, relativeTo: nil)
                NSLayoutConstraint.activate([
                    v.leadingAnchor.constraint(equalTo: titlebarContainer.leadingAnchor),
                    v.trailingAnchor.constraint(equalTo: titlebarContainer.trailingAnchor),
                    v.topAnchor.constraint(equalTo: titlebarContainer.topAnchor),
                    v.bottomAnchor.constraint(equalTo: titlebarContainer.bottomAnchor),
                ])
                titlebarTintView = v
                tintView = v
            }
        }

        if tintView.translatesAutoresizingMaskIntoConstraints {
            tintView.frame = titlebarContainer.bounds
        }
        if #available(macOS 26.0, *), let glass = tintView as? NSGlassEffectView {
            glass.style = .regular
            glass.tintColor = desiredTint
        } else if let effect = tintView as? NSVisualEffectView {
            // Ensure the layer color is driven explicitly; otherwise the titlebar can drift on some appearances.
            effect.layer?.backgroundColor = desiredTint.cgColor
        } else {
            tintView.wantsLayer = true
            tintView.layer?.backgroundColor = desiredTint.cgColor
        }

        installTitlebarSeamCover(tint: desiredTint)
        installTitlebarTitleLabel()
    }

    private func installTitlebarDivider(in tintView: NSView) {
        let divider: NSView
        if let existing = titlebarDividerView, existing.superview === tintView {
            divider = existing
        } else {
            let v = PassthroughView(frame: .zero)
            v.translatesAutoresizingMaskIntoConstraints = false
            v.wantsLayer = true
            tintView.addSubview(v)
            let edgeConstraint: NSLayoutConstraint
            if tintView.isFlipped {
                edgeConstraint = v.bottomAnchor.constraint(equalTo: tintView.bottomAnchor)
            } else {
                edgeConstraint = v.topAnchor.constraint(equalTo: tintView.topAnchor)
            }
            NSLayoutConstraint.activate([
                v.leadingAnchor.constraint(equalTo: tintView.leadingAnchor),
                v.trailingAnchor.constraint(equalTo: tintView.trailingAnchor),
                edgeConstraint,
            ])
            titlebarDividerView = v
            divider = v
        }

        let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
        let thickness = 1.0 / scale
        titlebarDividerHeightConstraint?.isActive = false
        titlebarDividerHeightConstraint = divider.heightAnchor.constraint(equalToConstant: thickness)
        titlebarDividerHeightConstraint?.isActive = true
        divider.layer?.contentsScale = scale
        let isDark = (window?.effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua)
        let base = resolvedSystemColor(.separatorColor)
        let color = (isDark ? NSColor.black : base).withAlphaComponent(isDark ? 0.55 : 0.75)
        divider.layer?.backgroundColor = color.cgColor
    }

    private func installTitlebarSeamCover(tint: NSColor) {
        guard let window, let content = window.contentView else { return }
        let host = windowBackgroundHostView(for: content)
        let cover: NSView
        if let existing = titlebarSeamCoverView, existing.superview === host {
            cover = existing
        } else {
            let v = PassthroughView(frame: .zero)
            v.translatesAutoresizingMaskIntoConstraints = false
            v.wantsLayer = true
            host.addSubview(v, positioned: .above, relativeTo: nil)
            let top = v.topAnchor.constraint(equalTo: content.topAnchor)
            let height = v.heightAnchor.constraint(equalToConstant: 1.0)
            NSLayoutConstraint.activate([
                v.leadingAnchor.constraint(equalTo: host.leadingAnchor),
                v.trailingAnchor.constraint(equalTo: host.trailingAnchor),
                top,
                height
            ])
            titlebarSeamCoverView = v
            titlebarSeamCoverTopConstraint = top
            titlebarSeamCoverHeightConstraint = height
            cover = v
        }

        let scale = max(1.0, window.backingScaleFactor)
        let thickness = 1.0 / scale
        titlebarSeamCoverTopConstraint?.constant = -thickness
        titlebarSeamCoverHeightConstraint?.constant = thickness * 2.0
        cover.layer?.contentsScale = scale
        cover.layer?.backgroundColor = tint.cgColor
    }

    private func leftCardCornerRadius() -> CGFloat {
        if #available(macOS 26.0, *), let glass = leftContainer as? NSGlassEffectView {
            return glass.cornerRadius
        }
        return leftContainer.layer?.cornerRadius ?? PANEL_CORNER_RADIUS
    }

    private func rightCardCornerRadius() -> CGFloat {
        if #available(macOS 26.0, *), let glass = rightContainer as? NSGlassEffectView {
            return glass.cornerRadius
        }
        return rightContainer.layer?.cornerRadius ?? PANEL_CORNER_RADIUS
    }

    private func setupWindowBackgroundImage(in content: NSView) {
        let trimmedPath = WINDOW_BACKGROUND_IMAGE_PATH.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedPath.isEmpty else {
            cachedTitlebarTintFromWindowBackground = nil
            if let existing = windowBackgroundImageView {
                existing.removeFromSuperview()
                windowBackgroundImageView = nil
            }
            invalidateWindowBackgroundFreezeSnapshot(reason: "window_bg_image_clear")
            return
        }
        let host = windowBackgroundHostView(for: content)
        if let existing = windowBackgroundImageView {
            if existing.superview !== host {
                existing.removeFromSuperview()
                host.addSubview(existing, positioned: .below, relativeTo: nil)
                NSLayoutConstraint.activate([
                    existing.leadingAnchor.constraint(equalTo: host.leadingAnchor),
                    existing.trailingAnchor.constraint(equalTo: host.trailingAnchor),
                    existing.topAnchor.constraint(equalTo: host.topAnchor),
                    existing.bottomAnchor.constraint(equalTo: host.bottomAnchor)
                ])
            }
            return
        }
        let maxPx = recommendedBackgroundMaxPixelDim(for: window)
        guard let image = loadBackgroundImage(from: trimmedPath, maxPixelDim: maxPx, preserveAnimated: true) else {
            cachedTitlebarTintFromWindowBackground = nil
            return
        }
        let imageView = StaticBackgroundImageView(frame: .zero)
        imageView.translatesAutoresizingMaskIntoConstraints = false
        // Window background underlay: only shown when an image is configured.
        imageView.baseColor = windowBackgroundSolidColor()
        imageView.image = image
        imageView.alphaValue = WINDOW_BACKGROUND_IMAGE_ALPHA
        if let screen = window?.screen ?? NSScreen.main {
            imageView.updateBackingScale(screen.backingScaleFactor)
        }
        // The window background must fill the full window rect (no rounded clipping at the top edges/titlebar).
        imageView.layer?.cornerRadius = 0
        imageView.layer?.masksToBounds = true

        host.addSubview(imageView, positioned: .below, relativeTo: nil)
        NSLayoutConstraint.activate([
            imageView.leadingAnchor.constraint(equalTo: host.leadingAnchor),
            imageView.trailingAnchor.constraint(equalTo: host.trailingAnchor),
            imageView.topAnchor.constraint(equalTo: host.topAnchor),
            imageView.bottomAnchor.constraint(equalTo: host.bottomAnchor)
        ])

        windowBackgroundImageView = imageView
        invalidateWindowBackgroundFreezeSnapshot(reason: "window_bg_image_set")

        // Keep the titlebar tint consistent with the window background when a wallpaper is present.
        // We use the dominant hue (not a hand-tuned constant) so the UI bar tracks the image.
        if let dominant = dominantHueColor(from: image) {
            let base = (window?.backgroundColor ?? NSColor.black).usingColorSpace(.deviceRGB) ?? NSColor.black
            let d = dominant.usingColorSpace(.deviceRGB) ?? dominant
            let a = max(0.0, min(1.0, WINDOW_BACKGROUND_IMAGE_ALPHA))
            let r = a * d.redComponent + (1.0 - a) * base.redComponent
            let g = a * d.greenComponent + (1.0 - a) * base.greenComponent
            let b = a * d.blueComponent + (1.0 - a) * base.blueComponent
            cachedTitlebarTintFromWindowBackground = NSColor(srgbRed: r, green: g, blue: b, alpha: 1.0)
        } else {
            cachedTitlebarTintFromWindowBackground = nil
        }
        installTitlebarTintBackground()
        // Background underlay changed; recompute RootGlassTint compensation (amortized).
        cachedRootGlassThemeSignature = nil
        cachedRootGlassTheme = nil
        scheduleRootGlassTintApply(reason: "window_bg_image", delay: 0.0)

        // Background changed; re-render panel liquid glass textures (amortized by the card view).
        (leftContainer as? GlassCardView)?.invalidateGlass(reason: "window_bg_image")
        (rightContainer as? GlassCardView)?.invalidateGlass(reason: "window_bg_image")
        rightSecondaryContainer?.invalidateGlass(reason: "window_bg_image")
        sidebarControlBackground.needsDisplay = true
        sidebarControlBackground.layer?.setNeedsDisplay()
        rightPanelLeftEdgeButtonBackground?.needsDisplay = true
        rightPanelLeftEdgeButtonBackground?.layer?.setNeedsDisplay()
        rightPanelRightEdgeButtonBackground?.needsDisplay = true
        rightPanelRightEdgeButtonBackground?.layer?.setNeedsDisplay()
        navControlBackground.needsDisplay = true
        navControlBackground.layer?.setNeedsDisplay()
    }

    private func captureWindowBackgroundRegion(in rectInWindow: CGRect, scale: CGFloat) -> CGImage? {
        guard let bgView = windowBackgroundImageView else { return nil }
        let rectInBG = bgView.convert(rectInWindow, from: nil)
        return bgView.snapshotCGImage(in: rectInBG, scale: scale)
    }

    private func snapshotViewCGImage(_ view: NSView, rectInView: CGRect) -> CGImage? {
        PerfLogger.begin("render.snapshot.view")
        defer { PerfLogger.end("render.snapshot.view") }
        let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
        defer {
            if resizePerfEnabled {
                ResizePerfTrace.shared.recordWork(name: "snapshot.view", durationNs: monotonicNowNs() &- perfStart)
            }
        }
        let rect = rectInView.intersection(view.bounds)
        guard rect.width > 2, rect.height > 2 else { return nil }
        guard let rep = view.bitmapImageRepForCachingDisplay(in: rect) else { return nil }
        PerfLogger.measure("render.snapshot.cache_display") {
            view.cacheDisplay(in: rect, to: rep)
        }
        return rep.cgImage
    }

    private func imageLumaStats(_ image: CGImage, sampleSize: Int = 12) -> (mean: CGFloat, variance: CGFloat, min: CGFloat, max: CGFloat) {
        let w = max(2, min(sampleSize, image.width))
        let h = max(2, min(sampleSize, image.height))
        let bytesPerRow = w * 4
        var data = [UInt8](repeating: 0, count: w * h * 4)
        let bitmapInfo = CGImageAlphaInfo.premultipliedLast.rawValue
        guard let ctx = CGContext(data: &data,
                                  width: w,
                                  height: h,
                                  bitsPerComponent: 8,
                                  bytesPerRow: bytesPerRow,
                                  space: CGColorSpaceCreateDeviceRGB(),
                                  bitmapInfo: bitmapInfo) else {
            return (0, 0, 0, 0)
        }
        ctx.interpolationQuality = .low
        ctx.draw(image, in: CGRect(x: 0, y: 0, width: w, height: h))

        let count = CGFloat(w * h)
        var sum: CGFloat = 0
        var sumSq: CGFloat = 0
        var minLuma: CGFloat = 1.0
        var maxLuma: CGFloat = 0.0
        var i = 0
        for _ in 0..<(w * h) {
            let r = CGFloat(data[i]) / 255.0
            let g = CGFloat(data[i + 1]) / 255.0
            let b = CGFloat(data[i + 2]) / 255.0
            let luma = 0.2126 * r + 0.7152 * g + 0.0722 * b
            sum += luma
            sumSq += luma * luma
            minLuma = min(minLuma, luma)
            maxLuma = max(maxLuma, luma)
            i += 4
        }
        let mean = sum / max(1, count)
        let variance = max(0, (sumSq / max(1, count)) - (mean * mean))
        return (mean, variance, minLuma, maxLuma)
    }

    private func imageLooksBlank(_ image: CGImage) -> Bool {
        let stats = imageLumaStats(image)
        let range = stats.max - stats.min
        if range > 0.05 { return false }
        if stats.variance > 0.0006 { return false }
        return stats.mean > 0.97 || stats.mean < 0.03
    }

    private func renderPDFPageRegion(rectInPDFView: CGRect, scale: CGFloat) -> CGImage? {
        PerfLogger.begin("render.pdf.page_region")
        defer { PerfLogger.end("render.pdf.page_region") }
        let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
        defer {
            if resizePerfEnabled {
                ResizePerfTrace.shared.recordWork(name: "pdf.render.page_region", durationNs: monotonicNowNs() &- perfStart)
            }
        }
        let mid = CGPoint(x: rectInPDFView.midX, y: rectInPDFView.midY)
        guard let page = pdfView.page(for: mid, nearest: true) else { return nil }
        let rectInPage = pdfView.convert(rectInPDFView, to: page).standardized
        let pageBounds = page.bounds(for: pdfView.displayBox)
        guard rectInPage.intersects(pageBounds) else { return nil }

        let outputScale = max(1.0, scale)
        let widthPx = max(2, Int(round(rectInPDFView.width * outputScale)))
        let heightPx = max(2, Int(round(rectInPDFView.height * outputScale)))
        let bitmapInfo = CGImageAlphaInfo.premultipliedLast.rawValue
        guard let ctx = CGContext(data: nil,
                                  width: widthPx,
                                  height: heightPx,
                                  bitsPerComponent: 8,
                                  bytesPerRow: widthPx * 4,
                                  space: CGColorSpaceCreateDeviceRGB(),
                                  bitmapInfo: bitmapInfo) else {
            return nil
        }
        ctx.interpolationQuality = .high
        ctx.setFillColor(NSColor.white.cgColor)
        ctx.fill(CGRect(x: 0, y: 0, width: CGFloat(widthPx), height: CGFloat(heightPx)))

        let viewScale = max(0.01, pdfView.scaleFactor) * outputScale
        ctx.scaleBy(x: viewScale, y: viewScale)
        ctx.translateBy(x: -rectInPage.minX, y: -rectInPage.minY)
        PerfLogger.measure("render.pdf.page_draw") {
            page.draw(with: pdfView.displayBox, to: ctx)
        }
        return ctx.makeImage()
    }

    private func capturePDFFindBackgroundRegion(in rectInWindow: CGRect, scale: CGFloat) -> CGImage? {
        PerfLogger.begin("render.pdf.find_background")
        defer { PerfLogger.end("render.pdf.find_background") }
        guard isShowingPDF else { return nil }
        // Clamp into the PDF view so the HUD never samples itself when it's outside the PDF bounds.
        func clampedRect(_ rect: CGRect, within bounds: CGRect) -> CGRect {
            let width = min(rect.width, bounds.width)
            let height = min(rect.height, bounds.height)
            guard width > 0, height > 0 else { return .zero }
            let minX = bounds.minX
            let maxX = bounds.maxX - width
            let minY = bounds.minY
            let maxY = bounds.maxY - height
            let x = min(max(rect.minX, minX), maxX)
            let y = min(max(rect.minY, minY), maxY)
            return CGRect(x: x, y: y, width: width, height: height)
        }

        let rectInPDFView = pdfView.convert(rectInWindow, from: nil)
        let pdfSampleRect = clampedRect(rectInPDFView, within: pdfView.bounds)
        if pdfSampleRect.width > 2, pdfSampleRect.height > 2 {
            // Prefer a direct page render so the glass tracks scroll without relying on view snapshots.
            if let img = renderPDFPageRegion(rectInPDFView: pdfSampleRect, scale: scale) {
                return img
            }
            if let img = snapshotViewCGImage(pdfView, rectInView: pdfSampleRect),
               !imageLooksBlank(img) {
                return img
            }
        }
        if let scrollView = pdfView.primaryScrollView(),
           let docView = scrollView.documentView {
            let rectInDoc = docView.convert(rectInWindow, from: nil)
            let docSampleRect = clampedRect(rectInDoc, within: docView.bounds)
            if docSampleRect.width > 2, docSampleRect.height > 2,
               let img = snapshotViewCGImage(docView, rectInView: docSampleRect),
               !imageLooksBlank(img) {
                return img
            }
        }
        return nil
    }

    private func updateWindowBackgroundBackingScale() {
        guard let imageView = windowBackgroundImageView else { return }
        if let screen = window?.screen ?? NSScreen.main {
            imageView.updateBackingScale(screen.backingScaleFactor)
        }
    }

    private func capturePDFResizeSnapshot(allowLayout: Bool) -> NSImage? {
        PerfLogger.begin("render.pdf.resize_snapshot")
        defer { PerfLogger.end("render.pdf.resize_snapshot") }
        let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
        defer {
            if resizePerfEnabled {
                ResizePerfTrace.shared.recordWork(name: "pdf.resize_snapshot", durationNs: monotonicNowNs() &- perfStart)
            }
        }
        guard isShowingPDF, pdfView.document != nil else { return nil }
        let bounds = pdfView.bounds
        guard bounds.width > 2, bounds.height > 2 else { return nil }
        let shouldLayout = allowLayout && pdfView.needsLayout
        if shouldLayout {
            let snapshotLayoutStart = resizePerfEnabled ? monotonicNowNs() : 0
            PerfLogger.measure("autolayout.pdfView.resize_snapshot") {
                pdfView.layoutSubtreeIfNeeded()
            }
            if resizePerfEnabled {
                ResizePerfTrace.shared.noteAutoLayout(name: "pdfView.resize_snapshot", durationNs: monotonicNowNs() &- snapshotLayoutStart)
            }
        }
        guard let cg = snapshotViewCGImage(pdfView, rectInView: bounds),
              !imageLooksBlank(cg) else { return nil }
        return NSImage(cgImage: cg, size: bounds.size)
    }

    private func cachedPDFResizeFreezeSnapshot() -> NSImage? {
        guard let doc = pdfView.document else { return nil }
        let docID = ObjectIdentifier(doc)
        guard pdfResizeFreezeSnapshotDocumentID == docID else { return nil }
        return pdfResizeFreezeSnapshot
    }

    private func invalidatePDFResizeFreezeSnapshot(reason: String) {
        _ = reason
        pdfResizeFreezeSnapshot = nil
        pdfResizeFreezeSnapshotDocumentID = nil
        pdfResizeFreezeCaptureWorkItem?.cancel()
        pdfResizeFreezeCaptureWorkItem = nil
    }

    private func schedulePDFResizeFreezeSnapshotCapture(reason: String, delay: TimeInterval = 0.12) {
        _ = reason
        guard isShowingPDF, let doc = pdfView.document else { return }
        guard !pdfResizeFreezeActive, !pdfInteractiveResizeActive else { return }
        guard window?.inLiveResize != true else { return }
        let docID = ObjectIdentifier(doc)
        if pdfResizeFreezeSnapshot != nil, pdfResizeFreezeSnapshotDocumentID == docID { return }
        pdfResizeFreezeCaptureWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            self.pdfResizeFreezeCaptureWorkItem = nil
            guard !AnimationGuard.shouldDeferHeavyWork else { return }
            guard self.isShowingPDF, let doc = self.pdfView.document else { return }
            guard !self.pdfResizeFreezeActive, !self.pdfInteractiveResizeActive else { return }
            guard self.window?.inLiveResize != true else { return }
            let docID = ObjectIdentifier(doc)
            if self.pdfResizeFreezeSnapshot != nil, self.pdfResizeFreezeSnapshotDocumentID == docID { return }
            if let snapshot = self.capturePDFResizeSnapshot(allowLayout: true) {
                self.pdfResizeFreezeSnapshot = snapshot
                self.pdfResizeFreezeSnapshotDocumentID = docID
            }
        }
        pdfResizeFreezeCaptureWorkItem = work
        if delay <= 0 {
            DispatchQueue.main.async(execute: work)
        } else {
            DispatchQueue.main.asyncAfter(deadline: .now() + delay, execute: work)
        }
    }

    private func applyPDFResizeFreezeIfNeeded(reason: String) {
        _ = reason
        guard !pdfResizeFreezeActive else { return }
        guard isShowingPDF, pdfView.document != nil else { return }
        guard let snapshot = cachedPDFResizeFreezeSnapshot() else { return }
        pdfResizeFreezeCaptureWorkItem?.cancel()
        pdfResizeFreezeCaptureWorkItem = nil

        let freezeView = PassthroughImageView(frame: rightPanelContentHost.bounds)
        freezeView.translatesAutoresizingMaskIntoConstraints = true
        freezeView.autoresizingMask = [.width, .height]
        freezeView.imageScaling = .scaleAxesIndependently
        freezeView.animates = false
        freezeView.wantsLayer = true
        freezeView.layer?.magnificationFilter = .linear
        freezeView.layer?.minificationFilter = .linear
        freezeView.image = snapshot

        rightPanelContentHost.addSubview(freezeView, positioned: .above, relativeTo: pdfView)
        pdfResizeFreezeView = freezeView
        pdfResizeFreezeActive = true

        // Root cause: PDFKit retiles aggressively during live resize, causing flicker/jitter.
        // Fix: freeze a snapshot during interactive resize and hide the live PDF view.
        pdfView.isHidden = true
        annotationController?.setOverlayHidden(true)
        pdfInteractiveResizeWorkItem?.cancel()
        pdfInteractiveResizeWorkItem = nil
    }

    private func removePDFResizeFreezeIfNeeded(reason: String) {
        _ = reason
        guard pdfResizeFreezeActive else { return }
        pdfResizeFreezeView?.removeFromSuperview()
        pdfResizeFreezeView = nil
        pdfResizeFreezeActive = false
        pdfView.isHidden = !isShowingPDF
        annotationController?.setOverlayHidden(!isShowingPDF)
    }

    private func updatePDFResizeFreezeState(reason: String) {
        let shouldFreeze = pdfInteractiveResizeActive && isShowingPDF && pdfView.document != nil
        if shouldFreeze {
            applyPDFResizeFreezeIfNeeded(reason: reason)
        } else {
            removePDFResizeFreezeIfNeeded(reason: reason)
            schedulePDFResizeFreezeSnapshotCapture(reason: reason)
        }
    }

    private func setupLeftCardBackgroundImage(in root: NSView, below view: NSView) {
        guard leftCardBackgroundImageView == nil else { return }
        let maxPx = recommendedBackgroundMaxPixelDim(for: window)
        guard let image = loadBackgroundImage(from: BACKGROUND_IMAGE_PATH, maxPixelDim: maxPx, preserveAnimated: true) else { return }
        let imageView = StaticBackgroundImageView(frame: .zero)
        imageView.translatesAutoresizingMaskIntoConstraints = true
        imageView.image = image
        imageView.alphaValue = LEFT_CARD_BACKGROUND_IMAGE_ALPHA
        if let screen = window?.screen ?? NSScreen.main {
            imageView.updateBackingScale(screen.backingScaleFactor)
        }

        root.addSubview(imageView, positioned: .below, relativeTo: view)
        leftCardBackgroundImageView = imageView
        updateLeftCardBackgroundFrame()
    }

    private func updateLeftCardBackgroundFrame() {
        guard let root = splitView.superview else { return }
        let leftFrameInRoot = leftContainer.convert(leftContainer.bounds, to: root)

        if let imageView = leftCardBackgroundImageView {
            if imageView.frame != leftFrameInRoot {
                imageView.frame = leftFrameInRoot
            }

            if let layer = imageView.layer {
                let radius = leftCardCornerRadius()
                layer.cornerRadius = radius
                layer.masksToBounds = true
                if #available(macOS 10.13, *) {
                    layer.cornerCurve = leftContainer.layer?.cornerCurve ?? .continuous
                }
            }

            imageView.needsLayout = true
            ResizePerfTrace.shared.noteInvalidation(name: "left_card_background.needsLayout")
            if let screen = window?.screen ?? NSScreen.main {
                imageView.updateBackingScale(screen.backingScaleFactor)
            }
        }

        updateLeftCardEdgeGlowFrame()
    }

    private func setupRightCardBackgroundImage(in root: NSView, below view: NSView) {
        guard rightCardBackgroundImageView == nil else { return }
        let maxPx = recommendedBackgroundMaxPixelDim(for: window)
        guard let image = loadBackgroundImage(from: RIGHT_CARD_BACKGROUND_IMAGE_PATH, maxPixelDim: maxPx, preserveAnimated: true) else { return }
        let imageView = StaticBackgroundImageView(frame: .zero)
        imageView.translatesAutoresizingMaskIntoConstraints = true
        imageView.image = image
        imageView.alphaValue = RIGHT_CARD_BACKGROUND_IMAGE_ALPHA
        if let screen = window?.screen ?? NSScreen.main {
            imageView.updateBackingScale(screen.backingScaleFactor)
        }

        root.addSubview(imageView, positioned: .below, relativeTo: view)
        rightCardBackgroundImageView = imageView
        updateRightCardBackgroundFrame()
    }

    private func cardEdgeGlowColor() -> NSColor {
        // Match the primary accent fill so the card halo stays in sync with the toolbar pills.
        primaryAccentFillColor()
    }

    private func applyCardEdgeGlowStyle(_ view: CardEdgeGlowView) {
        let active = isWindowActiveForAppearance()
        view.glowColor = cardEdgeGlowColor()
        view.strokeAlpha = active ? 0.36 : 0.24
        view.glowOpacity = active ? 0.55 : 0.36
        view.glowRadius = active ? 20 : 16
        view.glowOffset = .zero
    }

    private func setupLeftCardEdgeGlow(in root: NSView, below view: NSView) {
        guard leftCardGlowView == nil else { return }
        guard leftContainer is GlassCardView else { return }
        let glowView = CardEdgeGlowView(frame: .zero)
        glowView.translatesAutoresizingMaskIntoConstraints = true
        applyCardEdgeGlowStyle(glowView)
        root.addSubview(glowView, positioned: .below, relativeTo: view)
        leftCardGlowView = glowView
        updateLeftCardEdgeGlowFrame()
    }

    private func setupRightCardEdgeGlow(in root: NSView, below view: NSView) {
        guard rightCardGlowView == nil else { return }
        let glowView = CardEdgeGlowView(frame: .zero)
        glowView.translatesAutoresizingMaskIntoConstraints = true
        applyCardEdgeGlowStyle(glowView)
        root.addSubview(glowView, positioned: .below, relativeTo: view)
        rightCardGlowView = glowView
        updateRightCardEdgeGlowFrame()
    }

    private func updateRightCardBackgroundFrame() {
        guard let root = splitView.superview else { return }
        let rightFrameInRoot = rightContainer.convert(rightContainer.bounds, to: root)

        if let imageView = rightCardBackgroundImageView {
            if imageView.frame != rightFrameInRoot {
                imageView.frame = rightFrameInRoot
            }

            if let layer = imageView.layer {
                let radius = rightCardCornerRadius()
                layer.cornerRadius = radius
                layer.masksToBounds = true
                if #available(macOS 10.13, *) {
                    layer.cornerCurve = rightContainer.layer?.cornerCurve ?? .continuous
                }
            }

            imageView.needsLayout = true
            ResizePerfTrace.shared.noteInvalidation(name: "right_card_background.needsLayout")
            if let screen = window?.screen ?? NSScreen.main {
                imageView.updateBackingScale(screen.backingScaleFactor)
            }
        }

        updateRightCardEdgeGlowFrame()
    }

    private func updateLeftCardEdgeGlowFrame() {
        guard let glowView = leftCardGlowView else { return }
        guard let root = splitView.superview else { return }
        let leftFrameInRoot = leftContainer.convert(leftContainer.bounds, to: root)
        if glowView.frame != leftFrameInRoot {
            glowView.frame = leftFrameInRoot
        }
        glowView.cornerRadius = leftCardCornerRadius()
    }

    private func updateRightCardEdgeGlowFrame() {
        guard let glowView = rightCardGlowView else { return }
        guard let root = splitView.superview else { return }
        let rightFrameInRoot = rightContainer.convert(rightContainer.bounds, to: root)
        if glowView.frame != rightFrameInRoot {
            glowView.frame = rightFrameInRoot
        }
        glowView.cornerRadius = rightCardCornerRadius()
    }

    func updateSplitDividerHandleFrame() {
        guard let root = splitView.superview,
              let handle = splitDividerHandle else { return }
        guard splitView.subviews.count >= 2 else {
            handle.isHidden = true
            return
        }
        let rect = splitView.dividerRect(at: 0)
        guard rect.width > 0, rect.height > 0 else {
            handle.isHidden = true
            return
        }
        let rectInRoot = splitView.convert(rect, to: root)
        if handle.frame != rectInRoot {
            handle.frame = rectInRoot
            handle.needsLayout = true
            ResizePerfTrace.shared.noteInvalidation(name: "divider_handle.needsLayout")
        }
        if handle.isHidden { handle.isHidden = false }
    }

    private func updateRightSplitDividerHandleFrame() {
        guard let root = splitView.superview,
              let handle = rightSplitDividerHandle else { return }
        guard rightAuxPanelVisible, rightSplitView.subviews.count >= 2 else {
            handle.isHidden = true
            return
        }
        let rect = rightSplitView.dividerRect(at: 0)
        guard rect.width > 0, rect.height > 0 else {
            handle.isHidden = true
            return
        }
        let rectInRoot = rightSplitView.convert(rect, to: root)
        if handle.frame != rectInRoot {
            handle.frame = rectInRoot
            handle.needsLayout = true
            ResizePerfTrace.shared.noteInvalidation(name: "right_divider_handle.needsLayout")
        }
        if handle.isHidden { handle.isHidden = false }
    }

    private func updateCardEdgeGlowIntensity() {
        if let leftGlow = leftCardGlowView { applyCardEdgeGlowStyle(leftGlow) }
        if let rightGlow = rightCardGlowView { applyCardEdgeGlowStyle(rightGlow) }
    }

    private func setupWindowBackgroundMaterial(in content: NSView) {
        windowBackgroundFrozenByLiveResize = false
        windowBackgroundFrozenByMove = false
        windowBackgroundFreezeMoveWorkItem?.cancel()
        removeWindowBackgroundFreezeIfNeeded(reason: "setup_window_background")
        invalidateWindowBackgroundFreezeSnapshot(reason: "setup_window_background")
        if windowBackgroundView.superview != nil {
            windowBackgroundView.removeFromSuperview()
        }
        if !windowBackgroundConstraints.isEmpty {
            NSLayoutConstraint.deactivate(windowBackgroundConstraints)
            windowBackgroundConstraints.removeAll()
        }

        guard liquidGlassEnabled else {
            windowBackgroundView = PassthroughView(frame: .zero)
            installTitlebarTintBackground()
            return
        }

        let host = windowBackgroundHostView(for: content)
        let backgroundGlass = makeGlassEffectView(
            passthrough: true,
            cornerRadius: 0,
            tintColor: windowBackgroundGlassTintColor(),
            style: .regular,
            fallbackMaterial: .hudWindow,
            fallbackBlending: .behindWindow,
            fallbackState: .active,
            emphasized: true
        )
        if let imageView = windowBackgroundImageView, imageView.superview === host {
            host.addSubview(backgroundGlass, positioned: .above, relativeTo: imageView)
        } else {
            host.addSubview(backgroundGlass, positioned: .below, relativeTo: nil)
        }
        windowBackgroundConstraints = [
            backgroundGlass.leadingAnchor.constraint(equalTo: host.leadingAnchor),
            backgroundGlass.trailingAnchor.constraint(equalTo: host.trailingAnchor),
            backgroundGlass.topAnchor.constraint(equalTo: host.topAnchor),
            backgroundGlass.bottomAnchor.constraint(equalTo: host.bottomAnchor)
        ]
        NSLayoutConstraint.activate(windowBackgroundConstraints)
        windowBackgroundView = backgroundGlass
        installTitlebarTintBackground()
    }

    private func captureWindowSnapshotImage() -> NSImage? {
        guard let bgView = windowBackgroundView as NSView?,
              bgView.bounds.width > 2,
              bgView.bounds.height > 2 else {
            return nil
        }
        if let cg = snapshotViewCGImage(bgView, rectInView: bgView.bounds),
           !imageLooksBlank(cg) {
            return NSImage(cgImage: cg, size: bgView.bounds.size)
        }
        if let imageView = windowBackgroundImageView,
           let window = window {
            let scale = max(1.0, window.backingScaleFactor)
            if let cg = imageView.snapshotCGImage(in: imageView.bounds, scale: scale),
               !imageLooksBlank(cg) {
                return NSImage(cgImage: cg, size: imageView.bounds.size)
            }
        }
        return nil
    }

    private func captureWindowFullSnapshotImage() -> NSImage? {
        guard let host = window?.contentView?.superview ?? window?.contentView else { return nil }
        guard host.bounds.width > 2, host.bounds.height > 2 else { return nil }
        let freezeHidden = windowBackgroundFreezeView?.isHidden ?? false
        windowBackgroundFreezeView?.isHidden = true
        defer { windowBackgroundFreezeView?.isHidden = freezeHidden }
        guard let cg = snapshotViewCGImage(host, rectInView: host.bounds),
              !imageLooksBlank(cg) else { return nil }
        return NSImage(cgImage: cg, size: host.bounds.size)
    }

    private func cachedWindowFreezeSnapshot(for mode: WindowFreezeMode) -> NSImage? {
        switch mode {
        case .background:
            return windowBackgroundFreezeSnapshot
        case .fullWindow:
            return windowFullFreezeSnapshot
        }
    }

    private func setCachedWindowFreezeSnapshot(_ snapshot: NSImage, mode: WindowFreezeMode) {
        switch mode {
        case .background:
            windowBackgroundFreezeSnapshot = snapshot
        case .fullWindow:
            windowFullFreezeSnapshot = snapshot
        }
    }

    private func invalidateWindowBackgroundFreezeSnapshot(reason: String) {
        _ = reason
        windowBackgroundFreezeSnapshot = nil
        windowFullFreezeSnapshot = nil
        windowBackgroundFreezeCaptureWorkItem?.cancel()
        windowBackgroundFreezeCaptureWorkItem = nil
    }

    private func scheduleWindowBackgroundFreezeSnapshotCapture(reason: String,
                                                               mode: WindowFreezeMode,
                                                               delay: TimeInterval = 0.12) {
        _ = reason
        guard liquidGlassEnabled else { return }
        guard !windowBackgroundFrozenByLiveResize, !windowBackgroundFrozenByMove else { return }
        guard window?.inLiveResize != true else { return }
        guard cachedWindowFreezeSnapshot(for: mode) == nil else { return }
        windowBackgroundFreezeCaptureWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            self.windowBackgroundFreezeCaptureWorkItem = nil
            guard !AnimationGuard.shouldDeferHeavyWork else { return }
            guard self.liquidGlassEnabled else { return }
            guard !self.windowBackgroundFrozenByLiveResize, !self.windowBackgroundFrozenByMove else { return }
            guard self.window?.inLiveResize != true else { return }
            guard self.cachedWindowFreezeSnapshot(for: mode) == nil else { return }
            let snapshot: NSImage?
            switch mode {
            case .background:
                snapshot = self.captureWindowSnapshotImage()
            case .fullWindow:
                snapshot = self.captureWindowFullSnapshotImage()
            }
            guard let snapshot else { return }
            self.setCachedWindowFreezeSnapshot(snapshot, mode: mode)
        }
        windowBackgroundFreezeCaptureWorkItem = work
        if delay <= 0 {
            DispatchQueue.main.async(execute: work)
        } else {
            DispatchQueue.main.asyncAfter(deadline: .now() + delay, execute: work)
        }
    }

    private func updateWindowBackgroundFreezeState(reason: String) {
        // Do not freeze the main background during window moves; it can flash a black snapshot.
        if windowBackgroundFrozenByLiveResize {
            applyWindowBackgroundFreezeIfNeeded(reason: reason, mode: .background, allowCapture: false)
            updateWindowBackgroundRasterizationState(reason: reason)
            return
        }
        if windowBackgroundFrozenBySnap {
            applyWindowBackgroundFreezeIfNeeded(reason: reason, mode: .background, allowCapture: false)
            updateWindowBackgroundRasterizationState(reason: reason)
            return
        }
        removeWindowBackgroundFreezeIfNeeded(reason: reason)
        updateWindowBackgroundRasterizationState(reason: reason)
        scheduleWindowBackgroundFreezeSnapshotCapture(reason: reason, mode: .background)
    }

    private func applyWindowBackgroundFreeze(snapshot: NSImage, mode: WindowFreezeMode, host: NSView) {
        let freezeView = PassthroughImageView(frame: .zero)
        freezeView.translatesAutoresizingMaskIntoConstraints = false
        freezeView.imageScaling = .scaleAxesIndependently
        freezeView.animates = false
        freezeView.wantsLayer = true
        freezeView.layer?.masksToBounds = true

        freezeView.image = snapshot
        freezeView.layer?.backgroundColor = nil

        if mode == .fullWindow {
            host.addSubview(freezeView, positioned: .above, relativeTo: nil)
        } else {
            if let content = window?.contentView, content.superview === host {
                host.addSubview(freezeView, positioned: .below, relativeTo: content)
            } else {
                host.addSubview(freezeView, positioned: .above, relativeTo: nil)
            }
        }
        NSLayoutConstraint.activate([
            freezeView.leadingAnchor.constraint(equalTo: host.leadingAnchor),
            freezeView.trailingAnchor.constraint(equalTo: host.trailingAnchor),
            freezeView.topAnchor.constraint(equalTo: host.topAnchor),
            freezeView.bottomAnchor.constraint(equalTo: host.bottomAnchor)
        ])
        windowBackgroundFreezeView = freezeView
        windowBackgroundFreezeActive = true
        windowBackgroundFreezeMode = mode
    }

    private func applyWindowBackgroundFreezeIfNeeded(reason: String, mode: WindowFreezeMode, allowCapture: Bool = true) {
        PerfLogger.begin("window.background.freeze")
        defer { PerfLogger.end("window.background.freeze") }
        if windowBackgroundFreezeActive {
            if windowBackgroundFreezeMode == mode { return }
            removeWindowBackgroundFreezeIfNeeded(reason: "window_freeze_mode_change")
        }
        guard liquidGlassEnabled else { return }
        guard let host = window?.contentView?.superview ?? window?.contentView else { return }
        if let cached = cachedWindowFreezeSnapshot(for: mode) {
            applyWindowBackgroundFreeze(snapshot: cached, mode: mode, host: host)
            return
        }
        guard allowCapture else { return }
        let snapshot: NSImage?
        switch mode {
        case .background:
            snapshot = captureWindowSnapshotImage()
        case .fullWindow:
            snapshot = captureWindowFullSnapshotImage()
        }
        guard let snapshot else {
            if windowBackgroundFreezeActive {
                removeWindowBackgroundFreezeIfNeeded(reason: "window_freeze_missing_snapshot")
            }
            return
        }
        setCachedWindowFreezeSnapshot(snapshot, mode: mode)
        applyWindowBackgroundFreeze(snapshot: snapshot, mode: mode, host: host)
    }

    private func removeWindowBackgroundFreezeIfNeeded(reason: String) {
        guard windowBackgroundFreezeActive else { return }
        if let freezeView = windowBackgroundFreezeView {
            freezeView.removeFromSuperview()
            windowBackgroundFreezeView = nil
        }
        windowBackgroundFreezeActive = false
        windowBackgroundFreezeMode = .background
    }

    private func handleWindowDidMove() {
        guard liquidGlassEnabled else { return }
        windowBackgroundFrozenByMove = true
        updateWindowBackgroundFreezeState(reason: "window_move")
        updateLeftPanelRasterizationState(reason: "window_move")
        updateRightAuxRasterizationState(reason: "window_move")
        windowBackgroundFreezeMoveWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            self.windowBackgroundFrozenByMove = false
            self.updateWindowBackgroundFreezeState(reason: "window_move_end")
            self.updateLeftPanelRasterizationState(reason: "window_move_end")
            self.updateRightAuxRasterizationState(reason: "window_move_end")
        }
        windowBackgroundFreezeMoveWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.12, execute: work)
    }

    private func restoreSidebarStateFromDefaults() {
        let defaults = UserDefaults.standard
        let storedWidthValue = (defaults.object(forKey: sidebarWidthDefaultsKey) as? Double)
            ?? (defaults.object(forKey: legacySidebarWidthDefaultsKey) as? Double)
            ?? 0
        if storedWidthValue.isFinite, storedWidthValue > 0 {
            lastSidebarWidth = CGFloat(storedWidthValue)
        }

        var forcedToVisible = false
        let hasNewVisibleKey = (defaults.object(forKey: sidebarVisibleDefaultsKey) != nil)
        let hasLegacyVisibleKey = (defaults.object(forKey: legacySidebarVisibleDefaultsKey) != nil)
        if hasNewVisibleKey || hasLegacyVisibleKey {
            let storedVisible = hasNewVisibleKey
                ? defaults.bool(forKey: sidebarVisibleDefaultsKey)
                : defaults.bool(forKey: legacySidebarVisibleDefaultsKey)
            if storedVisible {
                sidebarVisible = true
            } else if storedWidthValue > 12 {
                sidebarVisible = false
            } else {
                sidebarVisible = true
                forcedToVisible = true
            }
        }

        if forcedToVisible {
            persistSidebarVisibility(true)
            persistSidebarWidth(lastSidebarWidth)
        }
    }

    private func persistSidebarWidth(_ width: CGFloat) {
        UserDefaults.standard.set(Double(width), forKey: sidebarWidthDefaultsKey)
        UserDefaults.standard.set(Double(width), forKey: legacySidebarWidthDefaultsKey)
    }

    private func persistSidebarVisibility(_ visible: Bool) {
        UserDefaults.standard.set(visible, forKey: sidebarVisibleDefaultsKey)
        UserDefaults.standard.set(visible, forKey: legacySidebarVisibleDefaultsKey)
    }

    private func restoreRightAuxWidthFromDefaults() {
        let defaults = UserDefaults.standard
        let storedWidthValue = (defaults.object(forKey: rightAuxWidthDefaultsKey) as? Double)
            ?? (defaults.object(forKey: legacyRightAuxWidthDefaultsKey) as? Double)
            ?? 0
        if storedWidthValue.isFinite, storedWidthValue > 0 {
            lastRightAuxPanelWidth = CGFloat(storedWidthValue)
        }
    }

    private func persistRightAuxWidth(_ width: CGFloat) {
        UserDefaults.standard.set(Double(width), forKey: rightAuxWidthDefaultsKey)
        UserDefaults.standard.set(Double(width), forKey: legacyRightAuxWidthDefaultsKey)
    }

    private var sidebarClampInProgress = false

    private var toolbarGapCachedParams: (minGap: CGFloat, baseHeight: CGFloat, buttonWidth: CGFloat, edgeInset: CGFloat, leftClusterMaxX: CGFloat, pillOffset: CGFloat, insetDelta: CGFloat)?
    private var toolbarGapCachedMinOuterRightWidth: CGFloat = 0

    private func desiredMinSidebarWidthForCurrentPage(maxLeft: CGFloat) -> CGFloat {
        // Absolute minimum for the leftContainer when visible.
        // Default (initial launch): match the exact width used to center "Author & Year".
        // After the publications table is populated: use the table's max internal scroll width.
        guard maxLeft.isFinite, maxLeft > 0 else { return 0 }
        if let tableDriven = sidebarTableContentDrivenWidth(maxLeft: maxLeft) {
            return tableDriven
        }
        return min(maxLeft, sidebarHardMinWidth())
    }

    private func enforceSidebarWidthBounds(reason: String) {
        guard !sidebarClampInProgress else { return }
        guard !sidebarTransitionInProgress else { return }
        guard !dividerDragActive else { return }

        let total = splitView.bounds.width
        guard total > 80 else { return }

        let divider = splitView.dividerThickness
        let maxLeftPotential = total - divider - minOuterRightContainerWidth()
        let maxLeft = cappedSidebarMaxWidth(forPotential: maxLeftPotential)
        let minLeft = sidebarVisible ? desiredMinSidebarWidthForCurrentPage(maxLeft: maxLeft) : 0
        let current = leftContainer.frame.width

        let desired: CGFloat = sidebarVisible
            ? min(maxLeft, max(minLeft, current))
            : 0

        if abs(desired - current) < 0.5 { return }

        layoutLog("sidebar_clamp_calc reason=\(reason) total=\(Int(total)) divider=\(Int(divider)) rightMin=\(Int(minOuterRightContainerWidth())) current=\(Int(current)) desired=\(Int(desired)) maxLeft=\(Int(maxLeft)) potentialLeft=\(Int(maxLeftPotential))")

        sidebarClampInProgress = true
        let prevAllowCollapse = allowSidebarCollapse
        if !sidebarVisible { allowSidebarCollapse = true }
        splitView.setPosition(desired, ofDividerAt: 0)
        splitView.adjustSubviews()
        allowSidebarCollapse = prevAllowCollapse
        sidebarClampInProgress = false

        // IMPORTANT: clamping the split position changes `leftContainer` width. The search bar glass
        // is explicitly framed from `leftContainer` in `layoutLeftContainerSubviews()`, so we must
        // re-run that layout pass after any clamp to keep the horizontal extent slaved.
        layoutLeftContainerSubviews()

        if sidebarVisible {
            let clampedStored = min(maxLeft, max(minLeft, lastSidebarWidth))
            if abs(clampedStored - lastSidebarWidth) >= 0.5 {
                lastSidebarWidth = clampedStored
                persistSidebarWidth(clampedStored)
            }
        }

        uiLog("sidebar_clamp reason=\(reason) current=\(Int(current)) desired=\(Int(desired)) maxLeft=\(Int(maxLeft)) total=\(Int(total))")
    }

