    private func setupSplitDividerHandle(in root: NSView) {
        guard splitDividerHandle == nil else { return }
        let handle = SplitDividerHandleView(frame: .zero)
        handle.translatesAutoresizingMaskIntoConstraints = true
        handle.isHidden = true
        handle.debugName = "outer_divider_handle"
        handle.paletteProvider = { [weak self] in
            self?.splitDividerPalette() ?? (
                fill: resolvedSystemColor(.separatorColor).withAlphaComponent(0.2),
                glow: NSColor.white.withAlphaComponent(0.2),
                glowOpacity: 0.2
            )
        }
        handle.positionProvider = { [weak self] in
            self?.leftContainer.frame.width ?? 0
        }
        handle.clampPosition = { [weak self] proposed in
            self?.clampSidebarWidth(proposed) ?? proposed
        }
        handle.applyPosition = { [weak self] position in
            guard let self else { return }
            PerfLogger.begin("divider.apply.outer")
            defer { PerfLogger.end("divider.apply.outer") }
            self.splitView.setPosition(position, ofDividerAt: 0)
            self.splitView.adjustSubviews()
            ResizePerfTrace.shared.noteConstraintAdjust(name: "splitView.adjustSubviews")
            self.rightSplitContainer.needsLayout = true
            self.rightSplitView.needsLayout = true
            PerfLogger.measure("autolayout.rightSplitContainer.outer_drag") {
                AnimationGuard.measure("autolayout.rightSplitContainer.outer_drag") {
                    self.rightSplitContainer.layoutSubtreeIfNeeded()
                }
            }
            self.updateSplitDividerHandleFrame()
            self.updateLayoutDebugOverlay(reason: "divider_apply")
        }
        handle.onDragBegin = { [weak self] in
            guard let self else { return }
            self.cancelSplitDividerSpringAnimation()
            if self.rightPanelSplitModeActive {
                self.setRightPanelSplitMode(false, animated: false)
            }
            self.dividerDragActive = true
            self.logDividerState("drag_begin")
            self.updateLayoutDebugOverlay(reason: "drag_begin")
        }
        handle.onDragEnd = { [weak self] in
            guard let self else { return }
            if self.dividerDragActive {
                self.logDividerState("drag_end")
            }
            self.dividerDragActive = false
            self.schedulePanelSettle()
            self.scheduleDividerDragReflow()
            self.debugDumpViewHierarchy(reason: "divider_drag_end")
            self.debugProbeDividerHitTest(reason: "divider_drag_end")
            self.updateLayoutDebugOverlay(reason: "drag_end")
        }
        root.addSubview(handle, positioned: .above, relativeTo: splitView)
        splitDividerHandle = handle
        updateSplitDividerHandleFrame()
        handle.refreshStyle()
    }

    private func setupRightSplitDividerHandle(in root: NSView) {
        guard rightSplitDividerHandle == nil else { return }
        let handle = SplitDividerHandleView(frame: .zero)
        handle.translatesAutoresizingMaskIntoConstraints = true
        handle.isHidden = true
        handle.debugName = "right_divider_handle"
        handle.paletteProvider = { [weak self] in
            self?.splitDividerPalette() ?? (
                fill: resolvedSystemColor(.separatorColor).withAlphaComponent(0.2),
                glow: NSColor.white.withAlphaComponent(0.2),
                glowOpacity: 0.2
            )
        }
        handle.positionProvider = { [weak self] in
            self?.rightCompositeContainer.frame.width ?? 0
        }
        handle.clampPosition = { [weak self] proposed in
            self?.clampRightAuxDividerPosition(proposed) ?? proposed
        }
        handle.applyPosition = { [weak self] position in
            guard let self else { return }
            PerfLogger.begin("divider.apply.right")
            defer { PerfLogger.end("divider.apply.right") }
            // Keep right-divider drags geometry-only; defer heavy layout until drag end.
            self.rightSplitView.setPosition(position, ofDividerAt: 0)
            self.rightSplitView.adjustSubviews()
            ResizePerfTrace.shared.noteConstraintAdjust(name: "rightSplitView.adjustSubviews")
            self.updateRightSplitDividerHandleFrame()
            if self.rightAuxPanelVisible {
                self.layoutRightAuxPanelSubviews(interactive: true)
            }
            self.updateLayoutDebugOverlay(reason: "right_divider_apply")
        }
        handle.onDragBegin = { [weak self] in
            guard let self else { return }
            self.cancelRightSplitDividerSpringAnimation()
            self.rightSplitDividerDragActive = true
            self.updateRightAuxRasterizationState(reason: "right_divider_drag_begin")
            self.updatePDFResizeFreezeState(reason: "right_divider_drag_begin")
            ResizeLatencyProbe.shared.beginDrag(reason: "right_divider")
            ResizePerfTrace.shared.beginSession(reason: "right_divider")
        }
        handle.onDragEnd = { [weak self] in
            guard let self else { return }
            self.rightSplitDividerDragActive = false
            self.updateRightAuxRasterizationState(reason: "right_divider_drag_end")
            ResizeLatencyProbe.shared.endDrag(reason: "right_divider")
            ResizePerfTrace.shared.endSession(reason: "right_divider")
            self.finishPDFInteractiveResize(reason: "right_divider_drag_end", applyPendingScale: true)
            self.updatePDFResizeFreezeState(reason: "right_divider_drag_end")
            if self.rightAuxPanelVisible {
                let w = self.rightAuxPanelWidth()
                if w.isFinite, w > 0 {
                    self.lastRightAuxPanelWidth = w
                    self.persistRightAuxWidth(w)
                }
            }
            self.scheduleRightAuxResizeSync(reason: "right_divider_drag_end", delay: 0.0)
            self.schedulePanelSettle()
        }
        root.addSubview(handle, positioned: .above, relativeTo: splitView)
        rightSplitDividerHandle = handle
        updateRightSplitDividerHandleFrame()
        handle.refreshStyle()
    }

    private func installHitTestDebugging(in root: NSView) {
        guard uiDebugEnabled else { return }
        window?.acceptsMouseMovedEvents = true

        UserDefaults.standard.set(true, forKey: "NSConstraintBasedLayoutLogUnsatisfiable")

        if hitTestOverlay == nil {
            let overlay = DebugHitTestOverlayView(frame: root.bounds)
            overlay.translatesAutoresizingMaskIntoConstraints = true
            overlay.autoresizingMask = [.width, .height]
            root.addSubview(overlay, positioned: .above, relativeTo: menuContainer)
            hitTestOverlay = overlay
        }

        if hitTestMoveMonitor == nil {
            hitTestMoveMonitor = NSEvent.addLocalMonitorForEvents(matching: .mouseMoved) { [weak self] event in
                guard let self else { return event }
                guard let rootView = self.window?.contentView,
                      let overlay = self.hitTestOverlay else { return event }
                let hit = rootView.hitTest(event.locationInWindow)
                if let hit {
                    let rect = hit.convert(hit.bounds, to: overlay)
                    overlay.update(rect: rect)
                } else {
                    overlay.hide()
                }
                if let dividerRect = self.dividerRectInWindow(),
                   dividerRect.contains(event.locationInWindow) {
                    NSCursor.resizeLeftRight.set()
                    if !self.dividerHovering {
                        self.dividerHovering = true
                        self.uiLog("divider_hover begin location=\(String(format: "%.1f", event.locationInWindow.x)),\(String(format: "%.1f", event.locationInWindow.y))")
                    }
                } else if self.dividerHovering {
                    self.dividerHovering = false
                    self.uiLog("divider_hover end")
                }
                return event
            }
        }

        if hitTestDownMonitor == nil {
            hitTestDownMonitor = NSEvent.addLocalMonitorForEvents(matching: .leftMouseDown) { [weak self] event in
                guard let self else { return event }
                if let rootView = self.window?.contentView {
                    let hit = rootView.hitTest(event.locationInWindow)
                    var chain: [String] = []
                    var current = hit
                    while let view = current {
                        chain.append(String(describing: type(of: view)))
                        current = view.superview
                    }
                    let chainText = chain.joined(separator: " -> ")
                    self.uiLog("mouse_down location=\(String(format: "%.1f", event.locationInWindow.x)),\(String(format: "%.1f", event.locationInWindow.y)) hit=\(self.describeHitView(hit)) chain=\(chainText)")
                }
                if let dividerRect = self.dividerRectInWindow(),
                   dividerRect.contains(event.locationInWindow) {
                    self.cancelSplitDividerSpringAnimation()
                    if self.rightPanelSplitModeActive {
                        self.setRightPanelSplitMode(false, animated: false)
                    }
                    self.dividerDragActive = true
                    self.logDividerState("drag_begin")
                }
                return event
            }
        }

        if hitTestUpMonitor == nil {
            hitTestUpMonitor = NSEvent.addLocalMonitorForEvents(matching: .leftMouseUp) { [weak self] event in
                guard let self else { return event }
                if self.dividerDragActive {
                    self.logDividerState("drag_end")
                    self.dividerDragActive = false
                    self.debugDumpViewHierarchy(reason: "divider_drag_end")
                    self.debugProbeDividerHitTest(reason: "divider_drag_end")
                }
                return event
            }
        }
    }

    private func installPDFSelectionDebuggingIfNeeded() {
        guard pdfSelectDebugEnabled else { return }

        func chainText(from hit: NSView?) -> String {
            var chain: [String] = []
            var current = hit
            while let view = current {
                chain.append(String(describing: type(of: view)))
                current = view.superview
            }
            return chain.joined(separator: " -> ")
        }

        func snapshotSelection() -> (length: Int, pages: Int) {
            guard let selection = pdfView.currentSelection else { return (0, 0) }
            let length = selection.string?.count ?? 0
            let pages = selection.pages.count
            return (length, pages)
        }

        if pdfSelectDownMonitor == nil {
            pdfSelectDownMonitor = NSEvent.addLocalMonitorForEvents(matching: .leftMouseDown) { [weak self] event in
                guard let self else { return event }
                guard let root = self.window?.contentView else { return event }
                let hit = root.hitTest(event.locationInWindow)
                let inPDF = (hit != nil) ? (hit!.isDescendant(of: self.pdfView) || hit === self.pdfView) : false
                let sel = snapshotSelection()
                self.pdfSelectLog("down loc=\(String(format: "%.1f", event.locationInWindow.x)),\(String(format: "%.1f", event.locationInWindow.y)) isShowingPDF=\(self.isShowingPDF) loadingHidden=\(self.loadingOverlay.isHidden) hit=\(self.describeHitView(hit)) inPDF=\(inPDF) selLen=\(sel.length) selPages=\(sel.pages) chain=\(chainText(from: hit))")
                return event
            }
        }

        if pdfSelectDragMonitor == nil {
            pdfSelectDragMonitor = NSEvent.addLocalMonitorForEvents(matching: .leftMouseDragged) { [weak self] event in
                guard let self else { return event }
                guard let root = self.window?.contentView else { return event }
                let hit = root.hitTest(event.locationInWindow)
                let inPDF = (hit != nil) ? (hit!.isDescendant(of: self.pdfView) || hit === self.pdfView) : false
                let sel = snapshotSelection()
                self.pdfSelectLog("drag loc=\(String(format: "%.1f", event.locationInWindow.x)),\(String(format: "%.1f", event.locationInWindow.y)) hit=\(self.describeHitView(hit)) inPDF=\(inPDF) selLen=\(sel.length)")
                return event
            }
        }

        if pdfSelectUpMonitor == nil {
            pdfSelectUpMonitor = NSEvent.addLocalMonitorForEvents(matching: .leftMouseUp) { [weak self] event in
                guard let self else { return event }
                guard let root = self.window?.contentView else { return event }
                let hit = root.hitTest(event.locationInWindow)
                let inPDF = (hit != nil) ? (hit!.isDescendant(of: self.pdfView) || hit === self.pdfView) : false
                let sel = snapshotSelection()
                self.pdfSelectLog("up loc=\(String(format: "%.1f", event.locationInWindow.x)),\(String(format: "%.1f", event.locationInWindow.y)) hit=\(self.describeHitView(hit)) inPDF=\(inPDF) selLen=\(sel.length) selPages=\(sel.pages)")
                return event
            }
        }
    }

	    private func setupUI() {
        launchLog("setupUI start")
	        guard let content = window?.contentView else {
                launchLog("setupUI abort: window contentView nil")
                return
            }

            let root = installGlassContainerIfAvailable(on: content)
            layoutDebugRootView = root
            if debugLayoutEnabled, layoutDebugOverlay == nil {
                let overlay = DebugLayoutOverlayView(frame: root.bounds)
                overlay.translatesAutoresizingMaskIntoConstraints = true
                overlay.autoresizingMask = [.width, .height]
                root.addSubview(overlay, positioned: .above, relativeTo: nil)
                layoutDebugOverlay = overlay
            }
            installLayoutDebugEventTracing()

	        setupWindowBackgroundImage(in: content)
	        setupWindowBackgroundMaterial(in: content)
        restoreSidebarStateFromDefaults()
        restoreRightAuxWidthFromDefaults()

	        searchField.delegate = self
	        searchField.target = self
	        searchField.action = #selector(searchChanged)
	        searchField.translatesAutoresizingMaskIntoConstraints = false
	        searchField.controlSize = .large
	        searchField.wantsLayer = false
	        searchField.refusesFirstResponder = false
	        searchField.setContentHuggingPriority(.defaultLow, for: .horizontal)
	        searchField.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)

        // Match the PDF find bar typography (same font + metrics) while keeping semantic search colors.
        applySearchFieldTheme(searchField,
                              placeholder: "Search")

	        let searchTheme = currentSearchBarTheme()
		        searchBackground = makeGlassEffectView(
		            passthrough: true,
		            cornerRadius: 14,
		            tintColor: nil,
	            style: .regular,
	            fallbackMaterial: searchTheme.fallbackMaterial,
	            fallbackBlending: searchTheme.fallbackBlending,
	            fallbackState: searchTheme.fallbackState,
	            emphasized: searchTheme.emphasized
	        )
	        applyEmbeddedSearchBarTheme(to: searchBackground)
	        searchBackground.postsFrameChangedNotifications = true
	        searchOutlineLayer.fillColor = NSColor.clear.cgColor
	        searchOutlineLayer.strokeColor = NSColor.white.withAlphaComponent(0.09).cgColor
	        searchOutlineLayer.lineWidth = SPOTLIGHT_SEARCH_OUTLINE_WIDTH
	        searchOutlineLayer.lineJoin = .round
	        searchOutlineLayer.lineCap = .round
	        searchOutlineLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
	        searchInnerOutlineLayer.fillColor = NSColor.clear.cgColor
	        searchInnerOutlineLayer.strokeColor = NSColor.white.withAlphaComponent(0.06).cgColor
	        searchInnerOutlineLayer.lineWidth = SPOTLIGHT_SEARCH_OUTLINE_WIDTH
	        searchInnerOutlineLayer.lineJoin = .round
	        searchInnerOutlineLayer.lineCap = .round
	        searchInnerOutlineLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
	        if #available(macOS 10.14, *) {
	            searchCenterGlowLayer.type = .radial
	        }
	        searchCenterGlowLayer.startPoint = CGPoint(x: 0.5, y: 0.5)
	        searchCenterGlowLayer.endPoint = CGPoint(x: 1.0, y: 1.0)
	        searchCenterGlowLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
	        searchHighlightLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
	        searchFalloffLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
	        searchHighlightLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
	        searchHighlightLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
	        searchFalloffLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
	        searchFalloffLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
	        searchBackground.layer?.addSublayer(searchCenterGlowLayer)
	        searchBackground.layer?.addSublayer(searchHighlightLayer)
	        searchBackground.layer?.addSublayer(searchFalloffLayer)
	        searchBackground.layer?.addSublayer(searchInnerOutlineLayer)
	        searchBackground.layer?.addSublayer(searchOutlineLayer)
	        searchBackground.layer?.mask = searchMaskLayer
	        searchCenterGlowLayer.opacity = 0
	        searchHighlightLayer.opacity = 0
	        searchFalloffLayer.opacity = 0
	        searchInnerOutlineLayer.opacity = 0
	        searchOutlineLayer.opacity = 0

	        searchEdgeOverlay.translatesAutoresizingMaskIntoConstraints = false
	        searchEdgeOverlay.wantsLayer = true
	        searchEdgeOverlay.layer?.masksToBounds = false
	        if let layer = searchEdgeOverlay.layer {
	            searchEdgeOrnaments.attach(to: layer)
	        }

        setupToolbarControls()
        installAppleIntelligenceTextView(in: root)
        installPillClickFallbackMonitor()
        setupAppleIntelligenceToast(in: root)
        setupShortcutResultPanel(in: root)
        setupReportingOverlay(in: root)
        setupSuggestionsDropdown()
		        setupMenuPanel()
		        updateToolbarEmphasis()

        splitView.isVertical = true
        splitView.dividerStyle = .thin
        splitView.gap = PANEL_INTER_CARD_GAP
        splitView.translatesAutoresizingMaskIntoConstraints = false

        // Keep divider draggable, and remove “hard line” look
        splitView.setValue(NSColor.clear, forKey: "dividerColor")
        splitView.delegate = self

        setupLeftPanelChrome()
        setupTable()
        setupPageStepper()
        setupRightPanelChrome()
        setupRightCompositeContainer()
            setupRightAuxPanelChrome()
            setupRightSplitContainer()
        installAnnotationsPanelObservers()
        refreshAnnotationsPanel(reason: "setup")

        leftHeaderBar.translatesAutoresizingMaskIntoConstraints = true
        leftHeaderRule.translatesAutoresizingMaskIntoConstraints = true
        tableScroll.translatesAutoresizingMaskIntoConstraints = true

	        leftContentView.addSubview(leftHeaderBar)
	        leftContentView.addSubview(leftHeaderRule)
	        leftContentView.addSubview(tableScroll)
            leftContentView.addSubview(pageStepperContainer)
	        setupLeftTableUnderlay()

            splitView.addArrangedSubview(leftContainer)
            splitView.addArrangedSubview(rightSplitContainer)

            // Ensure the viewer pane stays meaningfully sized.
            // Without explicit priorities, a bad persisted width or intrinsic sizing can cause the left
            // pane to dominate and make the divider feel "stuck".
            splitView.setHoldingPriority(.defaultLow, forSubviewAt: 0)
            splitView.setHoldingPriority(.defaultHigh, forSubviewAt: 1)
            leftContainer.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)
            rightSplitContainer.setContentCompressionResistancePriority(.defaultHigh, for: .horizontal)

        searchContainer.translatesAutoresizingMaskIntoConstraints = true
        searchContainer.wantsLayer = true
        searchContainer.layer?.backgroundColor = NSColor.clear.cgColor
        searchContainerClipLayer.fillColor = NSColor.white.cgColor
        searchContainer.layer?.mask = searchContainerClipLayer
        searchContainer.focusTarget = searchField
	        searchContainer.addSubview(searchBackground) // background first
	        searchContainer.addSubview(searchEdgeOverlay)
	        searchContainer.addSubview(searchContentView)

	        searchContentView.translatesAutoresizingMaskIntoConstraints = false
	        searchContentView.wantsLayer = false
        searchContentView.addSubview(searchField)

        headerControlsContainer.translatesAutoresizingMaskIntoConstraints = true
        headerControlsContainer.wantsLayer = false
        headerControlsContainer.addSubview(toolbarControls)

        root.addSubview(splitView)
        setupSplitDividerHandle(in: root)
            setupRightSplitDividerHandle(in: root)
        root.addSubview(searchContainer, positioned: .above, relativeTo: splitView)
        root.addSubview(headerControlsContainer, positioned: .above, relativeTo: searchContainer)
        if let leftGlass = rightPanelLeftEdgeButtonBackground {
            root.addSubview(leftGlass)
        }
        if let zoteroGlass = rightPanelZoteroEdgeButtonBackground {
            root.addSubview(zoteroGlass)
        }
        if let rightGlass = rightPanelRightEdgeButtonBackground {
            root.addSubview(rightGlass)
        }
        if let settingsGlass = rightPanelSettingsEdgeButtonBackground {
            root.addSubview(settingsGlass)
        }
        root.addSubview(rightPanelLeftEdgeButton)
        root.addSubview(rightPanelZoteroEdgeButton)
        root.addSubview(rightPanelRightEdgeButton)
        root.addSubview(rightPanelSettingsEdgeButton)

        rightPanelPillControl.onExpansionStateChanged = { [weak self] _ in
            // Keep the pill tab centered on the viewer after every expand/collapse cycle.
            // Defer to the next runloop tick so we don't fight in-flight CoreAnimation commits.
            DispatchQueue.main.async { [weak self] in
                self?.layoutViewerAnchoredHeaderControls()
                self?.refreshHoverTooltipLayoutIfNeeded()
            }
            guard let self, !self.disablePillToolbarAnimations else { return }
            // Also re-center after the morph animation fully settles; the bounce preset can drift
            // slightly while its transform scales, so schedule a second layout after the animation
            // duration has elapsed.
            DispatchQueue.main.asyncAfter(deadline: .now() + (self.rightPanelPillControl.pathAnimationDuration + 0.05)) { [weak self] in
                self?.layoutViewerAnchoredHeaderControls()
                self?.refreshHoverTooltipLayoutIfNeeded()
            }
        }

        root.addSubview(rightPanelPillControl, positioned: .above, relativeTo: headerControlsContainer)
        root.addSubview(appleIntelligenceToast, positioned: .above, relativeTo: rightPanelPillControl)
        root.addSubview(menuShield, positioned: .above, relativeTo: headerControlsContainer)
        root.addSubview(menuContainer, positioned: .above, relativeTo: menuShield)
        root.addSubview(suggestionsContainer, positioned: .above, relativeTo: nil)
        installHoverTooltipSystem(in: root)
        if let layer = suggestionsContainer.layer {
            layer.zPosition = 10_000
        }
	        setupLeftCardBackgroundImage(in: root, below: splitView)
	        setupRightCardBackgroundImage(in: root, below: splitView)
	        setupLeftCardEdgeGlow(in: root, below: splitView)
	        // Right-card edge glow is purely decorative and can appear as an unintended underlay under some tints.
	        // Keep it disabled to avoid any “ghost layer” behind the right glass card.
        installHitTestDebugging(in: root)
        installPDFSelectionDebuggingIfNeeded()
        updateLayoutDebugOverlay(reason: "setup")

        // Track explicit mouse-initiated panel activation ordering.
        // This is the single source of truth used to resolve narrow-window entry decisions.
        if panelActivationDownMonitor == nil {
            panelActivationDownMonitor = NSEvent.addLocalMonitorForEvents(matching: .leftMouseDown) { [weak self] event in
                guard let self else { return event }
                guard event.window === self.window else { return event }
                guard let rootView = self.window?.contentView else { return event }
                let hit = rootView.hitTest(event.locationInWindow)
                if let hit, (hit === self.leftContainer || hit.isDescendant(of: self.leftContainer)) {
                    self.lastUserActivatedPanel = .leftContainer
                } else if let hit, (hit === self.rightAuxContainer || hit.isDescendant(of: self.rightAuxContainer)) {
                    self.lastUserActivatedPanel = .annotations
                }
                return event
            }
        }

	        logSearchDebug("searchField placeholder=\(searchField.placeholderString ?? "") textColor=\(String(describing: searchField.textColor)) wantsLayer=\(searchField.wantsLayer)")
	        if let cell = searchField.cell as? NSSearchFieldCell {
	            logSearchDebug("searchField cell placeholder=\(cell.placeholderAttributedString?.string ?? "") icon=\(String(describing: cell.searchButtonCell?.image))")
	        }

        let searchMinWidth = searchField.widthAnchor.constraint(greaterThanOrEqualToConstant: searchFieldMinimumWidth)
        searchMinWidth.priority = .defaultLow

	        NSLayoutConstraint.activate([
	            searchBackground.leadingAnchor.constraint(equalTo: searchContainer.leadingAnchor),
	            searchBackground.trailingAnchor.constraint(equalTo: searchContainer.trailingAnchor),
	            searchBackground.topAnchor.constraint(equalTo: searchContainer.topAnchor),
	            searchBackground.bottomAnchor.constraint(equalTo: searchContainer.bottomAnchor),

	            searchEdgeOverlay.leadingAnchor.constraint(equalTo: searchContainer.leadingAnchor),
	            searchEdgeOverlay.trailingAnchor.constraint(equalTo: searchContainer.trailingAnchor),
	            searchEdgeOverlay.topAnchor.constraint(equalTo: searchContainer.topAnchor),
	            searchEdgeOverlay.bottomAnchor.constraint(equalTo: searchContainer.bottomAnchor),

	            searchContentView.leadingAnchor.constraint(equalTo: searchContainer.leadingAnchor, constant: searchContentInsetX),
	            searchContentView.trailingAnchor.constraint(equalTo: searchContainer.trailingAnchor, constant: -searchContentInsetX),
	            searchContentView.topAnchor.constraint(equalTo: searchContainer.topAnchor, constant: searchContentInsetY),
	            searchContentView.bottomAnchor.constraint(equalTo: searchContainer.bottomAnchor, constant: -searchContentInsetY),

            toolbarControls.leadingAnchor.constraint(equalTo: headerControlsContainer.leadingAnchor),
            toolbarControls.trailingAnchor.constraint(equalTo: headerControlsContainer.trailingAnchor),
            toolbarControls.topAnchor.constraint(equalTo: headerControlsContainer.topAnchor),
            toolbarControls.bottomAnchor.constraint(equalTo: headerControlsContainer.bottomAnchor),

            searchField.centerYAnchor.constraint(equalTo: searchContentView.centerYAnchor),
            searchField.leadingAnchor.constraint(equalTo: searchContentView.leadingAnchor),
            searchField.trailingAnchor.constraint(equalTo: searchContentView.trailingAnchor),
            searchField.heightAnchor.constraint(equalToConstant: 28),
            searchMinWidth,

            splitView.topAnchor.constraint(equalTo: root.topAnchor,
                                           constant: searchContainerTopInset + searchContainerHeight + searchContainerGap),
            splitView.leadingAnchor.constraint(equalTo: root.leadingAnchor, constant: WINDOW_BEZEL_INSET),
            splitView.trailingAnchor.constraint(equalTo: root.trailingAnchor, constant: -WINDOW_BEZEL_INSET),
            splitView.bottomAnchor.constraint(equalTo: root.bottomAnchor, constant: -WINDOW_BEZEL_INSET),
        ])

        windowResizeObserver = NotificationCenter.default.addObserver(
            forName: NSWindow.didResizeNotification,
            object: window,
            queue: .main
        ) { [weak self] _ in
            PerfLogger.measure("window.did_resize") {
                guard let self else { return }
                let live = self.window?.inLiveResize == true
                let immediateResize = !live
                self.window?.acceptsMouseMovedEvents = true
                self.installHoverTooltipMonitor()
                if let window = self.window {
                    let contentSize = window.contentRect(forFrameRect: window.frame).size
                    self.lastWindowResizeContentSize = contentSize
                    let contentWidth = contentSize.width
                    self.noteWindowResizeEvent(live: live,
                                               contentWidth: contentWidth,
                                               reason: live ? "window_resize_live" : "window_resize")
                    self.autoCollapseSidePanelsIfNeeded(proposedContentWidth: contentWidth,
                                                        reason: live ? "window_resize_live" : "window_resize")
                }
                self.applyResizeGeometryOnly(live: live, immediateResize: immediateResize)
            }
        }

        windowLiveResizeStartObserver = NotificationCenter.default.addObserver(
            forName: NSWindow.willStartLiveResizeNotification,
            object: window,
            queue: .main
        ) { [weak self] _ in
            PerfLogger.measure("window.live_resize_start") {
                guard let self else { return }
                self.beginWindowResizeSessionIfNeeded(live: true, reason: "live_resize_start")
            }
        }

        windowMoveObserver = NotificationCenter.default.addObserver(
            forName: NSWindow.didMoveNotification,
            object: window,
            queue: .main
        ) { [weak self] _ in
            self?.handleWindowDidMove()
        }

        windowScreenObserver = NotificationCenter.default.addObserver(
            forName: NSWindow.didChangeScreenNotification,
            object: window,
            queue: .main
        ) { [weak self] _ in
            self?.updateLeftCardBackgroundFrame()
            self?.updateRightCardBackgroundFrame()
            self?.updateWindowBackgroundBackingScale()
            self?.invalidateSidebarHardMinWidthCache()
        }

        splitWillResizeObserver = NotificationCenter.default.addObserver(
            forName: NSSplitView.willResizeSubviewsNotification,
            object: splitView,
            queue: .main
        ) { [weak self] _ in
            PerfLogger.measure("split.will_resize") {
                guard let self else { return }
                // Detect native split-view dragging (when the user drags the divider itself).
                // Our custom `SplitDividerHandleView` sets `dividerDragActive` explicitly, but
                // AppKit-driven divider drags otherwise look like ordinary resize notifications.
                if !self.dividerDragActive,
                   !self.sidebarTransitionInProgress,
                   (NSEvent.pressedMouseButtons & 1) != 0,
                   let window = self.window,
                   let dividerRect = self.dividerRectInWindow(),
                   dividerRect.contains(window.mouseLocationOutsideOfEventStream) {
                    self.cancelSplitDividerSpringAnimation()
                    self.dividerDragActive = true
                    self.systemDividerDragStartX = window.mouseLocationOutsideOfEventStream.x
                    self.systemDividerDragStartLeftWidth = self.leftContainer.frame.width
                    self.systemDividerDragPendingSplitModeExit = self.rightPanelSplitModeActive
                    self.logDividerState("drag_begin_system")
                    layoutLog("drag_begin_system left=\(Int(self.leftContainer.frame.width)) right=\(Int(self.rightSplitContainer.frame.width))")
                    self.updateLayoutDebugOverlay(reason: "drag_begin_system")
                }

                if self.uiDebugEnabled, self.dividerDragActive {
                    self.logDividerState("drag_will_resize")
                }
                if debugLayoutEnabled {
                    self.updateLayoutDebugOverlay(reason: self.dividerDragActive ? "drag_will_resize" : "split_will_resize")
                }
            }
        }

        splitResizeObserver = NotificationCenter.default.addObserver(
            forName: NSSplitView.didResizeSubviewsNotification,
            object: splitView,
            queue: .main
        ) { [weak self] _ in
            PerfLogger.measure("split.did_resize") {
                if let self, !self.resizeSessionActive {
                    self.updateNarrowWindowModeIfNeeded(reason: "split_resize")
                }
                if let self,
                   !self.resizeSessionActive,
                   self.window?.inLiveResize != true,
                   !self.dividerDragActive,
                   !self.sidebarTransitionInProgress,
                   !self.rightAuxTransitionInProgress,
                   let window = self.window {
                    let contentSize = window.contentRect(forFrameRect: window.frame).size
                    if self.shouldStartWindowResizeSession(for: contentSize) {
                        self.noteWindowResizeEvent(live: false,
                                                   contentWidth: contentSize.width,
                                                   reason: "split_resize")
                    }
                }
                // During live divider drags, do the minimum work possible.
                // Constraint/layout churn here can fight AppKit’s interactive divider updates and
                // make dragging feel “stuck” (especially with nested split views + glass cards).
                if let self {
                    // Apply toolbar scaling for divider changes as well.
                    if !self.resizeSessionActive {
                        self.updateToolbarScaleForWindowSize(reason: self.dividerDragActive ? "split_divider_drag" : "split_resize")
                    }
                }
                if let self, self.dividerDragActive {
                    self.updateSplitDividerHandleFrame()
                    self.updateRightSplitDividerHandleFrame()
                    self.rightSplitContainer.needsLayout = true
                    self.rightSplitView.needsLayout = true
                    PerfLogger.measure("autolayout.rightSplitContainer.outer_drag") {
                        AnimationGuard.measure("autolayout.rightSplitContainer.outer_drag") {
                            self.rightSplitContainer.layoutSubtreeIfNeeded()
                        }
                    }
                    ResizeLatencyProbe.shared.markDragUpdate(width: self.leftContainer.frame.width, source: "split_resize")
                    self.noteResizeDragEvent(source: "split_resize")
                    ResizePerfTrace.shared.noteConstraintAdjust(name: "splitView.didResize")
                    self.layoutLeftContainerSubviews(duringDividerDrag: true)
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    self.logDividerState("drag_update")

                    // Avoid a visual snap on mere mouse-down: only exit split-mode
                    // once the user has actually moved the pointer.
                    if self.systemDividerDragPendingSplitModeExit,
                       let window = self.window {
                        let dx = window.mouseLocationOutsideOfEventStream.x - self.systemDividerDragStartX
                        let dLeft = self.leftContainer.frame.width - self.systemDividerDragStartLeftWidth
                        if abs(dx) >= 2 || abs(dLeft) >= 1 {
                            self.systemDividerDragPendingSplitModeExit = false
                            if self.rightPanelSplitModeActive {
                                layoutLog("drag_exit_right_split_mode dx=\(Int(dx)) dLeft=\(Int(dLeft))")
                                self.setRightPanelSplitMode(false, animated: false)
                                self.updateLayoutDebugOverlay(reason: "drag_exit_right_split_mode")
                            }
                        }
                    }

                    // End native drag when the mouse is released.
                    if (NSEvent.pressedMouseButtons & 1) == 0 {
                        self.dividerDragActive = false
                        self.systemDividerDragPendingSplitModeExit = false
                        self.logDividerState("drag_end_system")
                        layoutLog("drag_end_system left=\(Int(self.leftContainer.frame.width)) right=\(Int(self.rightSplitContainer.frame.width))")
                        self.schedulePanelSettle()

                        // If the user dragged the (previously hidden) sidebar open while Chat is hidden,
                        // treat that as an explicit unhide intent before clamping. Otherwise the clamp
                        // path would force the sidebar back to 0 (snap-back).
                        if !self.sidebarVisible,
                           !self.rightAuxPanelVisible {
                            let w = self.leftContainer.frame.width
                            if w.isFinite, w > 12 {
                                self.sidebarVisible = true
                                self.lastUserActivatedPanel = .leftContainer
                                self.lastSidebarWidth = w
                                self.persistSidebarVisibility(true)
                                self.persistSidebarWidth(w)
                                self.updateSidebarToggleIcon()
                                self.leftContainer.setAccessibilityHidden(false)
                                self.uiLog("sidebar_unhide_via_divider_drag width=\(Int(w))")
                            }
                        }

                        self.enforceSidebarWidthBounds(reason: "drag_end")
                        self.scheduleDividerDragReflow()
                        self.debugDumpViewHierarchy(reason: "divider_drag_end")
                        self.debugProbeDividerHitTest(reason: "divider_drag_end")
                        self.updateLayoutDebugOverlay(reason: "drag_end_system")
                    }
                    return
                }

                if let self, self.sidebarTransitionInProgress || self.rightAuxTransitionInProgress {
                    if self.sidebarTransitionInProgress {
                        self.layoutLeftContainerSubviews(duringDividerDrag: true)
                    }
                    if self.rightAuxTransitionInProgress {
                        self.layoutRightAuxPanelSubviews()
                    }
                    if !self.sidebarTransitionInProgress {
                        self.layoutViewerAnchoredHeaderControls()
                    }
                    self.updateSplitDividerHandleFrame()
                    self.updateRightSplitDividerHandleFrame()
                    if self.sidebarTransitionInProgress {
                        self.applySidebarTogglePDFSnapshotDuringResize()
                    }
                    if debugLayoutEnabled {
                        self.updateLayoutDebugOverlay(reason: "split_resize_transition")
                    }
                    return
                }

                if let self, (self.window?.inLiveResize == true || self.resizeSessionActive) {
                    self.layoutLeftContainerSubviews(duringDividerDrag: true)
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    if self.rightAuxPanelVisible {
                        self.layoutViewerAnchoredHeaderControls()
                    }
                    self.updateToolbarScaleForWindowSize(reason: "split_resize_live")
                    self.updateSplitDividerHandleFrame()
                    self.updateRightSplitDividerHandleFrame()
                    if debugLayoutEnabled && !self.resizeSessionActive {
                        self.updateLayoutDebugOverlay(reason: "split_resize_live")
                    }
                    if self.rightAuxPanelVisible && !self.resizeSessionActive {
                        self.scheduleRightAuxResizeSync(reason: "split_resize_live")
                    }
                    return
                }

                if let self, self.suppressSplitResizeHeavyWork {
                    self.layoutLeftContainerSubviews(duringDividerDrag: true)
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    if self.rightAuxPanelVisible {
                        self.layoutViewerAnchoredHeaderControls(ensureLayout: false)
                    }
                    self.updateToolbarScaleForWindowSize(reason: "split_resize_suppressed")
                    self.updateSplitDividerHandleFrame()
                    self.updateRightSplitDividerHandleFrame()
                    self.applySidebarTogglePDFSnapshotDuringResize()
                    if debugLayoutEnabled {
                        self.updateLayoutDebugOverlay(reason: "split_resize_suppressed")
                    }
                    if !self.sidebarTransitionInProgress,
                       CACurrentMediaTime() >= self.suppressSplitResizeHeavyWorkUntil {
                        self.suppressSplitResizeHeavyWork = false
                    }
                    return
                }

                if let self, self.skipNextSplitResizeHeavyWork {
                    self.layoutLeftContainerSubviews(duringDividerDrag: true)
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    if self.rightAuxPanelVisible {
                        self.layoutViewerAnchoredHeaderControls(ensureLayout: false)
                    }
                    self.updateToolbarScaleForWindowSize(reason: "split_resize_skip_next")
                    self.updateSplitDividerHandleFrame()
                    self.updateRightSplitDividerHandleFrame()
                    self.applySidebarTogglePDFSnapshotDuringResize()
                    if debugLayoutEnabled {
                        self.updateLayoutDebugOverlay(reason: "split_resize_skip_next")
                    }
                    self.skipNextSplitResizeHeavyWork = false
                    return
                }

                if let self, (CACurrentMediaTime() - self.lastSidebarToggleTimestamp) < 0.60 {
                    self.layoutLeftContainerSubviews(duringDividerDrag: true)
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    if self.rightAuxPanelVisible {
                        self.layoutViewerAnchoredHeaderControls(ensureLayout: false)
                    }
                    self.updateToolbarScaleForWindowSize(reason: "split_resize_recent_toggle")
                    self.updateSplitDividerHandleFrame()
                    self.updateRightSplitDividerHandleFrame()
                    self.applySidebarTogglePDFSnapshotDuringResize()
                    if debugLayoutEnabled {
                        self.updateLayoutDebugOverlay(reason: "split_resize_recent_toggle")
                    }
                    return
                }

                if let self {
                    self.layoutLeftContainerSubviews(duringDividerDrag: true)
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    if self.rightAuxPanelVisible {
                        self.layoutViewerAnchoredHeaderControls(ensureLayout: false)
                    }
                    self.updateToolbarScaleForWindowSize(reason: "split_resize_programmatic")
                    self.updateSplitDividerHandleFrame()
                    self.updateRightSplitDividerHandleFrame()
                    self.applySidebarTogglePDFSnapshotDuringResize()
                    if debugLayoutEnabled {
                        self.updateLayoutDebugOverlay(reason: "split_resize_programmatic")
                    }
                    self.scheduleProgrammaticSplitResizeMaintenance(reason: "split_resize_programmatic")
                }
            }
        }

            rightSplitWillResizeObserver = NotificationCenter.default.addObserver(
                forName: NSSplitView.willResizeSubviewsNotification,
                object: rightSplitView,
                queue: .main
            ) { [weak self] _ in
                PerfLogger.measure("right_split.will_resize") {
                    guard let self else { return }
                    if self.uiDebugEnabled {
                        self.uiLog("right_divider_will_resize")
                    }
                    if !self.rightSplitDividerDragActive,
                       !self.rightAuxTransitionInProgress,
                       (NSEvent.pressedMouseButtons & 1) != 0,
                       let window = self.window,
                       let dividerRect = self.rightSplitDividerRectInWindow(),
                       dividerRect.contains(window.mouseLocationOutsideOfEventStream) {
                        self.rightSplitDividerDragActive = true
                        self.rightSplitDividerDragFromSystem = true
                        self.updateRightAuxRasterizationState(reason: "right_divider_drag_begin_system")
                        self.updatePDFResizeFreezeState(reason: "right_divider_drag_begin_system")
                        ResizeLatencyProbe.shared.beginDrag(reason: "right_divider_system")
                        ResizePerfTrace.shared.beginSession(reason: "right_divider_system")
                    }
                    // The system warning "NSLayoutConstraintNumberExceedsLimit" often means AppKit
                    // has clamped a constraint constant. Sample constraint constants right here while
                    // the layout engine is active so we can attribute the offending constraint.
                    self.launchAuditConstraintConstants(reason: "right_divider_will_resize", threshold: 10_000)
                }
            }

            rightSplitResizeObserver = NotificationCenter.default.addObserver(
                forName: NSSplitView.didResizeSubviewsNotification,
                object: rightSplitView,
                queue: .main
            ) { [weak self] _ in
                PerfLogger.measure("right_split.did_resize") {
                    guard let self else { return }
                if self.rightSplitDividerDragActive {
                    ResizeLatencyProbe.shared.markDragUpdate(width: self.rightAuxPanelWidth(), source: "right_split_resize")
                    self.noteResizeDragEvent(source: "right_split_resize")
                    ResizePerfTrace.shared.noteConstraintAdjust(name: "rightSplitView.didResize")
                    // Mirror the left-divider path: keep drag updates lightweight.
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    self.layoutViewerAnchoredHeaderControls(ensureLayout: false)
                    self.updateRightSplitDividerHandleFrame()
                    if self.rightSplitDividerDragFromSystem, (NSEvent.pressedMouseButtons & 1) == 0 {
                        self.rightSplitDividerDragActive = false
                        self.rightSplitDividerDragFromSystem = false
                        self.updateRightAuxRasterizationState(reason: "right_divider_drag_end_system")
                        ResizeLatencyProbe.shared.endDrag(reason: "right_divider_system")
                        ResizePerfTrace.shared.endSession(reason: "right_divider_system")
                        self.finishPDFInteractiveResize(reason: "right_divider_drag_end_system", applyPendingScale: true)
                        self.updatePDFResizeFreezeState(reason: "right_divider_drag_end_system")
                        if self.rightAuxPanelVisible {
                            let w = self.rightAuxPanelWidth()
                            if w.isFinite, w > 0 {
                                self.lastRightAuxPanelWidth = w
                                self.persistRightAuxWidth(w)
                            }
                        }
                        self.scheduleRightAuxResizeSync(reason: "right_divider_drag_end_system", delay: 0.0)
                        self.schedulePanelSettle()
                    }
                    return
                }
                if self.rightAuxTransitionInProgress {
                    // Keep the PDF viewer/layout in lockstep with the divider animation.
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    self.layoutViewerAnchoredHeaderControls(ensureLayout: false)
                    self.updateRightSplitDividerHandleFrame()
                    return
                }
                if !self.resizeSessionActive,
                   self.window?.inLiveResize != true,
                   !self.dividerDragActive,
                   !self.rightAuxTransitionInProgress,
                   let window = self.window {
                    let contentSize = window.contentRect(forFrameRect: window.frame).size
                    if self.shouldStartWindowResizeSession(for: contentSize) {
                        self.noteWindowResizeEvent(live: false,
                                                   contentWidth: contentSize.width,
                                                   reason: "right_split_resize")
                    }
                }
                if self.window?.inLiveResize == true || self.resizeSessionActive {
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    self.layoutViewerAnchoredHeaderControls()
                    self.updateToolbarScaleForWindowSize(reason: "right_split_resize_live")
                    self.updateRightSplitDividerHandleFrame()
                    if self.rightAuxPanelVisible && !self.resizeSessionActive {
                        self.scheduleRightAuxResizeSync(reason: "right_split_resize_live")
                    }
                    return
                }
                if !self.resizeSessionActive {
                    self.updateNarrowWindowModeIfNeeded(reason: "right_split_resize")
                }
                self.updateToolbarScaleForWindowSize(reason: "right_split_resize")
                    self.scheduleRootGlassTintApply(reason: "right_split_resize", delay: 0.12)
                    self.layoutRightPanelSubviews()
                    self.layoutViewerAnchoredHeaderControls()
                    self.updateWindowMinSizeForToolbarGapIfNeeded(reason: "right_split_resize")
                    self.updateRightSplitDividerHandleFrame()
                    self.enforceRightAuxMinWidthIfNeeded(reason: "right_split_resize")
                    self.enforceRightAuxTargetWidthIfNeeded(reason: "right_split_resize")
                    if self.rightAuxPanelVisible {
                        self.scheduleRightAuxResizeSync(reason: "right_split_resize")
                    }

                    if self.panelDebugAssertionsEnabled {
                        if self.isNarrowWindowModeCached {
                            assert(!(self.sidebarVisible && self.rightAuxPanelVisible), "Invariant: narrow mode must not show both leftContainer and annotations")
                        }
                        // No min/max sizing invariants enforced.
                    }
                }
            }

        windowFocusObservers.append(
            NotificationCenter.default.addObserver(
                forName: NSWindow.didBecomeKeyNotification,
                object: window,
                queue: .main
            ) { [weak self] _ in
                if let self, !self.didCaptureMinWidthScreenRatio, let window = self.window {
                    let contentWidth = window.contentRect(forFrameRect: window.frame).width
                    if let screen = window.screen ?? NSScreen.main,
                       contentWidth.isFinite, contentWidth > 1,
                       screen.frame.width.isFinite, screen.frame.width > 1 {
                        let ratio = contentWidth / screen.frame.width
                        let clamped = max(0.1, min(self.maxWindowMinWidthScreenRatio, ratio))
                        if let existing = self.defaultWindowMinWidthScreenRatio {
                            if clamped < existing {
                                self.defaultWindowMinWidthScreenRatio = clamped
                            }
                        } else {
                            self.defaultWindowMinWidthScreenRatio = clamped
                        }
                        self.didCaptureMinWidthScreenRatio = true
                        self.updateWindowMinSizeForToolbarGapIfNeeded(reason: "min_width_ratio_capture")
                    }
                }
                self?.updateLeftPanelDepth(animated: true, reason: .focus)
                self?.refreshVisibleRowDepth(animated: true)
                self?.updateVisibleRowSelectionStyling()
                self?.updateCardEdgeGlowIntensity()
                self?.updateToolbarEmphasis()
                self?.refreshMenuTextColors()
            }
        )

        windowFocusObservers.append(
            NotificationCenter.default.addObserver(
                forName: NSWindow.didResignKeyNotification,
                object: window,
                queue: .main
            ) { [weak self] _ in
                self?.updateLeftPanelDepth(animated: true, reason: .focus)
                self?.refreshVisibleRowDepth(animated: true)
                self?.updateVisibleRowSelectionStyling()
                self?.updateCardEdgeGlowIntensity()
                self?.updateToolbarEmphasis()
                self?.refreshMenuTextColors()
            }
        )

        windowLiveResizeEndObserver = NotificationCenter.default.addObserver(
            forName: NSWindow.didEndLiveResizeNotification,
            object: window,
            queue: .main
        ) { [weak self] _ in
            PerfLogger.measure("window.live_resize_end") {
                guard let self else { return }
                self.finishWindowResizeSession(reason: "live_resize_end")
            }
        }

        func applyInitialLayoutWhenReady(attempt: Int) {
            if self.didApplyInitialSidebarLayout { return }
            self.window?.contentView?.layoutSubtreeIfNeeded()
            self.splitView.layoutSubtreeIfNeeded()
            self.rightSplitView.layoutSubtreeIfNeeded()
            // Avoid applying split positions before AppKit has produced real frames.
            // When done too early, the right panel can end up effectively 0-sized until a later interaction.
            let boundsReady = self.splitView.bounds.width > 80
                && self.splitView.bounds.height > 80
                && self.rightSplitView.bounds.width > 40
                && self.rightSplitView.bounds.height > 40
            if !boundsReady {
                let delay: TimeInterval = attempt < 12 ? 0.04 : 0.08
                DispatchQueue.main.asyncAfter(deadline: .now() + delay) { [weak self] in
                    guard let self else { return }
                    applyInitialLayoutWhenReady(attempt: attempt + 1)
                }
                return
            }

            let total = self.splitView.bounds.width
            let divider = self.splitView.dividerThickness
            let maxLeft = self.cappedSidebarMaxWidth(forPotential: total - divider - self.minOuterRightContainerWidth())

            // Always launch with the left panel visible.
            // Use the default launch width (clamped by the sidebar hard minimum).
            self.sidebarVisible = true
            let bootstrapLeft = self.desiredLaunchSidebarWidth(maxLeft: maxLeft)
            self.splitView.setPosition(bootstrapLeft, ofDividerAt: 0)
            self.splitView.adjustSubviews()

            self.layoutLeftContainerSubviews()
            self.layoutRightPanelSubviews()
            self.updateSplitDividerHandleFrame()

            // Ensure the Annotations (right aux) panel truly starts hidden on first launch:
            // keep it collapsed to ~0 width (not just transparent).
            self.rightAuxPanelVisible = false
            self.rightAuxContainer.alphaValue = 0
            self.ensureRightAuxCollapsedIfHidden()
            // One extra tick helps when nested split bounds finalize slightly later.
            DispatchQueue.main.async { [weak self] in
                self?.ensureRightAuxCollapsedIfHidden()
            }
            self.reflowLeft()

            let contentFitLeft = self.desiredLaunchSidebarWidth(maxLeft: maxLeft)
            if abs(contentFitLeft - self.leftContainer.frame.width) >= 0.5 {
                self.splitView.setPosition(contentFitLeft, ofDividerAt: 0)
                self.splitView.adjustSubviews()
                self.layoutLeftContainerSubviews()
                self.layoutRightPanelSubviews()
                self.updateSplitDividerHandleFrame()
                self.reflowLeft()
            }
            if self.initialSidebarWidthForSession <= 0 {
                self.initialSidebarWidthForSession = self.leftContainer.frame.width
            }
            self.updateLeftPanelDepth(animated: false)
            self.refreshVisibleRowDepth(animated: false, preset: .crisp)
            self.updateSearchCapsuleGeometry()
            self.updateSearchDepth(animated: false)
            self.updateCardEdgeGlowIntensity()
            self.layoutToolbarControls()
            self.updateToolbarScaleForWindowSize(reason: "initial", immediate: true)
	        self.updateWindowMinSizeForToolbarGapIfNeeded(reason: "initial")
                self.enforceSidebarWidthBounds(reason: "initial")
                self.didApplyInitialSidebarLayout = true
            self.updateSidebarStateFromSplit()
            self.updateNavigationButtons()
            if ProcessInfo.processInfo.environment["ARXIV_ANNOTATIONS_PANEL_OPEN"] == "1" {
                self.setRightAuxPanelVisible(true, animated: false)
            }
            self.updateLayoutDebugOverlay(reason: "initial")
            self.debugDumpViewHierarchy(reason: "initial")
            self.debugProbeDividerHitTest(reason: "initial")
            self.debugProbeToolbarHitTests(reason: "initial")
            self.debugProbeViewerHitTest(reason: "initial")
            self.launchAuditConstraintConstants(reason: "initial", threshold: 10_000)

            DispatchQueue.main.async { [weak self] in
                guard let self else { return }
                self.splitView.layoutSubtreeIfNeeded()
                self.layoutLeftContainerSubviews()
                self.layoutRightPanelSubviews()
                self.layoutToolbarControls()
                self.layoutViewerAnchoredHeaderControls()
                self.updateWindowMinSizeForToolbarGapIfNeeded(reason: "initial_post")
                self.enforceSidebarWidthBounds(reason: "initial_post")
                self.updateSplitDividerHandleFrame()
                self.updateRightSplitDividerHandleFrame()
                self.updateSidebarStateFromSplit()
                self.reflowLeft()
            }
        }

        DispatchQueue.main.async {
            applyInitialLayoutWhenReady(attempt: 0)
        }

        // Optional: smoke-test the Chat panel mount/unmount on launch.
        // Enable with `ARXIV_CHAT_SMOKE=1`.
        if ProcessInfo.processInfo.environment["ARXIV_CHAT_SMOKE"] == "1" {
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.6) { [weak self] in
                self?.setRightAuxPanelVisible(true, animated: false)
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 1.1) { [weak self] in
                self?.setRightAuxPanelVisible(false, animated: false)
            }
        }

        // Optional: rapid toggle stress (layout stability + no perceived lag under repeated clicks).
        // Enable with `ARXIV_CHAT_STRESS=1`.
        runChatRapidToggleStressIfEnabled()

        setupKeyHandling()
        setupPDFWheelRouting()
        setupSelectionClearMonitor()
        setupDividerDragEndMonitor()
        launchLog("setupUI end")
    }

    private func setupPDFWheelRouting() {
        guard pdfWheelMonitor == nil else { return }
        pdfWheelMonitor = NSEvent.addLocalMonitorForEvents(matching: .scrollWheel) { [weak self] event in
            guard let self else { return event }
            guard self.window?.isKeyWindow == true else { return event }
            guard self.isShowingPDF, self.pdfView.isHidden == false else { return event }
            guard event.window === self.window else { return event }

            // Avoid intercepting modifier-driven scroll gestures (e.g. Cmd-scroll zoom).
            if event.modifierFlags.contains(.command) { return event }

            let p = self.pdfView.convert(event.locationInWindow, from: nil)
            guard self.pdfView.bounds.contains(p) else { return event }

            self.noteSidebarTogglePDFUserScroll()
            if self.pdfView.routeScrollWheel(event) {
                return nil
            }
            return event
        }
    }

	    private func setupLeftPanelChrome() {
	        // Match the AI shortcut popup liquid-glass material for the main left panel.
	        let card = makeShortcutResultGlassBase()
	        leftContainer = card
            // The outer split view uses `addArrangedSubview`, so its panes must participate in Auto Layout.
            // Keeping autoresizing-mask translation enabled can cause AppKit to synthesize placeholder
            // constraints that fight divider dragging (observed as “stuck” drags).
            leftContainer.translatesAutoresizingMaskIntoConstraints = false
            let contentHost = NSView(frame: .zero)
            contentHost.translatesAutoresizingMaskIntoConstraints = true
            contentHost.autoresizingMask = [.width, .height]
            leftContentContainer = contentHost
	        embedContentView(contentHost, into: leftContainer)
            leftContentView.translatesAutoresizingMaskIntoConstraints = true
            leftContentView.autoresizingMask = [.width, .height]
            leftContentView.frame = contentHost.bounds
            contentHost.addSubview(leftContentView)
            clearGlassChrome(for: leftContainer)
	    }

    private func runChatRapidToggleStressIfEnabled() {
        guard ProcessInfo.processInfo.environment["ARXIV_CHAT_STRESS"] == "1" else { return }

        let env = ProcessInfo.processInfo.environment
        let cycles = max(1, Int(env["ARXIV_CHAT_STRESS_CYCLES"] ?? "14") ?? 14)
        let interval = max(0.02, Double(env["ARXIV_CHAT_STRESS_INTERVAL"] ?? "0.06") ?? 0.06)
        let startDelay = max(0.2, Double(env["ARXIV_CHAT_STRESS_DELAY"] ?? "0.9") ?? 0.9)
        let animated = (env["ARXIV_CHAT_STRESS_ANIMATED"] ?? "1") != "0"

        chatStressToken &+= 1
        let token = chatStressToken
        uiLog("chat_stress_start cycles=\(cycles) interval=\(String(format: "%.3f", interval)) delay=\(String(format: "%.2f", startDelay)) animated=\(animated)")

        DispatchQueue.main.asyncAfter(deadline: .now() + startDelay) { [weak self] in
            guard let self, token == self.chatStressToken else { return }

            func assertInvariant(_ label: String) {
                // 1) Visible flag implies aux view is fully opaque.
                if self.rightAuxPanelVisible && self.rightAuxContainer.alphaValue < 0.95 {
                    self.uiLog("chat_stress_invariant_fail \(label) visible=true alpha=\(String(format: "%.2f", self.rightAuxContainer.alphaValue))")
                }
                // 2) Not visible implies we keep it collapsed and fully transparent.
                if !self.rightAuxPanelVisible && self.rightAuxContainer.alphaValue > 0.05 {
                    self.uiLog("chat_stress_invariant_fail \(label) visible=false alpha=\(String(format: "%.2f", self.rightAuxContainer.alphaValue))")
                }
                if !self.rightAuxPanelVisible {
                    let auxW = Int(self.rightAuxPanelWidth())
                    if auxW > 2 {
                        self.uiLog("chat_stress_invariant_warn \(label) auxWidth=\(auxW) expected~0")
                    }
                }
            }

            var i = 0
            func step() {
                guard token == self.chatStressToken else { return }
                if i >= cycles {
                    assertInvariant("done")
                    self.launchAuditConstraintConstants(reason: "chat_stress_done", threshold: 10_000)
                    self.uiLog("chat_stress_done")
                    return
                }

                let opening = (i % 2 == 0)
                ChatLatencyProbe.shared.markButtonAction(opening: opening)
                self.setRightAuxPanelVisible(opening, animated: animated)
                assertInvariant("step_\(i)")
                i += 1
                DispatchQueue.main.asyncAfter(deadline: .now() + interval) {
                    step()
                }
            }

            step()
        }
    }

    private func recordRightPanelWidthIfNeeded() {
        guard !rightPanelSplitModeActive, sidebarVisible else { return }
        let width = rightContainer.frame.width
        if width > 0 { lastRightPanelWidth = width }
    }

    private func targetRightPanelWidthForSplit() -> CGFloat {
        let total = rightCompositeContainer.bounds.width
        let fallback = max(0, total > 1 ? total * 0.6 : 0)
        let stored = lastRightPanelWidth > 0 ? lastRightPanelWidth : fallback
        let maxPrimary = max(0, total - 1)
        return max(0, min(stored, maxPrimary))
    }

    private func clampRightPanelWidthForSplit() {
        guard rightPanelSplitModeActive,
              let constraint = rightPrimaryWidthConstraint,
              constraint.isActive else { return }
        let maxPrimary = max(0, rightCompositeContainer.bounds.width - 1)
        if constraint.constant > maxPrimary {
            constraint.constant = maxPrimary
            rightCompositeContainer.layoutSubtreeIfNeeded()
        }
    }

    private func setRightPanelSplitMode(_ active: Bool, animated: Bool, preset: SpringPreset = .soft, deferHeavyLayout: Bool = false) {
        let guardMeasure = AnimationGuard.beginMeasurement("right_splitmode_toggle")
        defer { AnimationGuard.endMeasurement(guardMeasure, details: "active=\(active) animated=\(animated) defer=\(deferHeavyLayout)") }
        guard let secondary = rightSecondaryContainer,
              rightPanelSplitModeActive != active else { return }

        reportStateTransition("right_panel_split_mode", details: ["active": "\(active)", "animated": "\(animated)"])
        layoutLog("right_splitmode_toggle active=\(active) before primaryW=\(Int(rightContainer.frame.width)) secondaryW=\(Int(secondary.frame.width)) secondaryHidden=\(secondary.isHidden)")

        rightPanelSplitModeActive = active
        let reduce = shouldReduceMotion || !animated

        if active {
            recordRightPanelWidthIfNeeded()
            secondary.isHidden = false
            rightPrimaryTrailingConstraint?.isActive = false
            rightPrimaryWidthConstraint?.constant = targetRightPanelWidthForSplit()
            rightPrimaryWidthConstraint?.isActive = true
            rightSecondaryWidthConstraint?.isActive = false
            rightSecondaryLeadingConstraint?.isActive = true
            if deferHeavyLayout {
                AnimationGuard.deferWork(label: "right_splitmode_layout") { [weak self] in
                    self?.rightCompositeContainer.layoutSubtreeIfNeeded()
                }
            } else {
                AnimationGuard.measure("autolayout.right_splitmode") {
                    rightCompositeContainer.layoutSubtreeIfNeeded()
                }
            }

            secondary.invalidateGlass(reason: "right_secondary_show")
            if let layer = secondary.layer {
                if reduce {
                    CATransaction.begin()
                    CATransaction.setDisableActions(true)
                    layer.opacity = 1
                    layer.transform = CATransform3DIdentity
                    CATransaction.commit()
                } else {
                    CATransaction.begin()
                    CATransaction.setDisableActions(true)
                    layer.opacity = 0
                    layer.transform = CATransform3DMakeScale(0.98, 0.98, 1.0)
                    CATransaction.commit()
                    animateLayer(layer, keyPath: "opacity", to: 1, preset: preset, reduceMotion: false, basicDuration: 0.22)
                    animateLayer(layer, keyPath: "transform", to: CATransform3DIdentity, preset: preset, reduceMotion: false, basicDuration: 0.26)
                }
            }
        } else {
            rightPrimaryTrailingConstraint?.isActive = true
            rightPrimaryWidthConstraint?.isActive = false
            rightSecondaryLeadingConstraint?.isActive = false
            rightSecondaryWidthConstraint?.isActive = true
            if deferHeavyLayout {
                AnimationGuard.deferWork(label: "right_splitmode_layout") { [weak self] in
                    self?.rightCompositeContainer.layoutSubtreeIfNeeded()
                }
            } else {
                AnimationGuard.measure("autolayout.right_splitmode") {
                    rightCompositeContainer.layoutSubtreeIfNeeded()
                }
            }

            guard let layer = secondary.layer else {
                secondary.isHidden = true
                return
            }
            if reduce {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                layer.opacity = 1
                layer.transform = CATransform3DIdentity
                CATransaction.commit()
                secondary.isHidden = true
            } else {
                animateLayer(layer, keyPath: "opacity", to: 0, preset: preset, reduceMotion: false, basicDuration: 0.18)
                let shrink = CATransform3DMakeScale(0.98, 0.98, 1.0)
                animateLayer(layer, keyPath: "transform", to: shrink, preset: preset, reduceMotion: false, basicDuration: 0.22)
                let duration = springSpec(for: preset).settleCap
                DispatchQueue.main.asyncAfter(deadline: .now() + duration) {
                    secondary.isHidden = true
                    CATransaction.begin()
                    CATransaction.setDisableActions(true)
                    layer.opacity = 1
                    layer.transform = CATransform3DIdentity
                    CATransaction.commit()
                }
            }
        }
        let liveLayout = sidebarTransitionInProgress || deferHeavyLayout || rightAuxTransitionInProgress
        if deferHeavyLayout {
            AnimationGuard.deferWork(label: "right_splitmode_post_layout") { [weak self] in
                self?.layoutRightPanelSubviews(duringLiveResize: liveLayout)
            }
        } else {
            layoutRightPanelSubviews(duringLiveResize: liveLayout)
        }

        layoutLog("right_splitmode_done active=\(rightPanelSplitModeActive) after primaryW=\(Int(rightContainer.frame.width)) secondaryW=\(Int(secondary.frame.width)) secondaryHidden=\(secondary.isHidden)")
    }

    // MARK: Split view sizing

    enum ToolbarGapClampMath {
        // Computes the pill width from `layoutRightPanelPillControl` given a candidate right-card width.
        static func pillWidth(forRightCardWidth w: CGFloat, baseHeight: CGFloat) -> CGFloat? {
            let inset: CGFloat = 12
            let availableWidth = max(0, w - (2 * inset))
            guard availableWidth > 24 else { return nil }

            let scale = max(0.86, min(1.15, w / 720))
            let height = baseHeight * scale
            let minWidth = height * 4.4
            let maxWidth = height * 8.0
            let targetWidth = min(w * 0.6, maxWidth)
            let width = min(availableWidth, max(minWidth, targetWidth))
            return (width.isFinite && width > 0) ? width : nil
        }

        // Computes edge-to-edge gap (in points) between the pill and the left edge of the right cluster
        // (Zotero button). `pillCenterOffsetFromCardMidX` is measured from the currently rendered frames.
        static func pillToRightClusterGap(forRightCardWidth w: CGFloat,
                                         baseHeight: CGFloat,
                                         buttonWidth: CGFloat,
                                         edgeInset: CGFloat,
                                         pillCenterOffsetFromCardMidX: CGFloat) -> CGFloat {
            guard let pillW = pillWidth(forRightCardWidth: w, baseHeight: baseHeight) else {
                return -CGFloat.greatestFiniteMagnitude
            }
            let pillMaxX = (w / 2) + pillCenterOffsetFromCardMidX + (pillW / 2)
            let zoteroMinX = w - (2 * buttonWidth) - (2 * edgeInset)
            return zoteroMinX - pillMaxX
        }

        // Computes edge-to-edge gap (in points) between the right edge of the left cluster
        // (Settings button) and the pill.
        static func leftClusterToPillGap(forRightCardWidth w: CGFloat,
                                         baseHeight: CGFloat,
                                         leftClusterMaxXFromCardMinX: CGFloat,
                                         pillCenterOffsetFromCardMidX: CGFloat) -> CGFloat {
            guard let pillW = pillWidth(forRightCardWidth: w, baseHeight: baseHeight) else {
                return -CGFloat.greatestFiniteMagnitude
            }
            let pillMinX = (w / 2) + pillCenterOffsetFromCardMidX - (pillW / 2)
            return pillMinX - leftClusterMaxXFromCardMinX
        }

        static func minRightCardWidthForGap(minGap: CGFloat,
                                            baseHeight: CGFloat,
                                            buttonWidth: CGFloat,
                                            edgeInset: CGFloat,
                                            leftClusterMaxXFromCardMinX: CGFloat,
                                            pillCenterOffsetFromCardMidX: CGFloat) -> CGFloat {
            let requiredForButtons = (4 * buttonWidth) + (4 * edgeInset)
            // Start from the strictest obvious lower bound.
            var lo = max(1, requiredForButtons)
            var hi = max(lo + 1, 720)

            func satisfies(_ w: CGFloat) -> Bool {
                if w < requiredForButtons { return false }
                let gapRight = pillToRightClusterGap(forRightCardWidth: w,
                                                     baseHeight: baseHeight,
                                                     buttonWidth: buttonWidth,
                                                     edgeInset: edgeInset,
                                                     pillCenterOffsetFromCardMidX: pillCenterOffsetFromCardMidX)
                if gapRight < minGap { return false }

                let gapLeft = leftClusterToPillGap(forRightCardWidth: w,
                                                  baseHeight: baseHeight,
                                                  leftClusterMaxXFromCardMinX: leftClusterMaxXFromCardMinX,
                                                  pillCenterOffsetFromCardMidX: pillCenterOffsetFromCardMidX)
                return gapLeft >= minGap
            }

            // Ensure `hi` is a satisfying bound.
            var guardIters = 0
            while !satisfies(hi) && guardIters < 24 {
                hi = min(5200, hi * 1.18 + 24)
                guardIters += 1
            }
            if !satisfies(hi) {
                return hi
            }

            // Binary search for the minimum satisfying width.
            for _ in 0..<36 {
                let mid = (lo + hi) / 2
                if satisfies(mid) {
                    hi = mid
                } else {
                    lo = mid
                }
            }
            return hi
        }
    }

    private func recomputeToolbarGapMinOuterRightWidthIfNeeded(reason: String) {
        guard !rightAuxPanelVisible else {
            toolbarGapCachedParams = nil
            toolbarGapCachedMinOuterRightWidth = 0
            return
        }
        if window?.inLiveResize == true,
           toolbarGapCachedMinOuterRightWidth.isFinite,
           toolbarGapCachedMinOuterRightWidth > 0 {
            return
        }
        guard let root = headerControlsContainer.superview else { return }

        let rightFrameInRoot = rightPanelPrimaryFrame(in: root)
        guard rightFrameInRoot.width.isFinite, rightFrameInRoot.width > 1 else { return }

        let minScale = toolbarControlScaleBase * toolbarProximityMinScale
        let baseHeight = max(toolbarMinHitSize, 32 * minScale)
        let buttonWidth: CGFloat = max(toolbarMinHitSize, 30 * minScale)
        let edgeInset: CGFloat = 6
        let insetDelta = (rightSplitContainer.frame.width.isFinite && rightFrameInRoot.width.isFinite)
            ? max(0, rightSplitContainer.frame.width - rightFrameInRoot.width)
            : 0
        let pillOffset = desiredPillCenterX(in: root, rightFrameInRoot: rightFrameInRoot) - rightFrameInRoot.midX

        // Compute the right edge of the left cluster (Settings button) relative to the card,
        // using the minimum toolbar scale to keep the clamp responsive under tight widths.
        let navFrameInRoot = navControlContainer.convert(navControlContainer.bounds, to: root)
        let toolbarMaxX = (navFrameInRoot.width > 1 && navFrameInRoot.maxX.isFinite)
            ? navFrameInRoot.maxX
            : headerControlsContainer.frame.maxX
        let minLeftX = toolbarMaxX + minToolbarEdgeButtonGap
        let leftX = max(rightFrameInRoot.minX + edgeInset, minLeftX)
        let settingsMaxX = leftX + (2 * buttonWidth) + edgeInset
        let leftClusterMaxXFromCardMinX = max(0, settingsMaxX - rightFrameInRoot.minX)

        let nextParams = (minGap: minToolbarGap,
                  baseHeight: baseHeight,
                  buttonWidth: buttonWidth,
                  edgeInset: edgeInset,
                  leftClusterMaxX: leftClusterMaxXFromCardMinX,
                  pillOffset: pillOffset,
                  insetDelta: insetDelta)

        if let last = toolbarGapCachedParams {
            let eps: CGFloat = 0.25
            if abs(last.minGap - nextParams.minGap) < eps,
               abs(last.baseHeight - nextParams.baseHeight) < eps,
               abs(last.buttonWidth - nextParams.buttonWidth) < eps,
               abs(last.edgeInset - nextParams.edgeInset) < eps,
               abs(last.leftClusterMaxX - nextParams.leftClusterMaxX) < 1.0,
               abs(last.pillOffset - nextParams.pillOffset) < eps,
               abs(last.insetDelta - nextParams.insetDelta) < 1.0,
               toolbarGapCachedMinOuterRightWidth.isFinite,
               toolbarGapCachedMinOuterRightWidth > 0 {
                return
            }
        }

        let minRightCardW = ToolbarGapClampMath.minRightCardWidthForGap(
            minGap: minToolbarGap,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            leftClusterMaxXFromCardMinX: leftClusterMaxXFromCardMinX,
            pillCenterOffsetFromCardMidX: pillOffset
        )
        let minOuterRightW = max(0, minRightCardW + insetDelta)
        toolbarGapCachedParams = nextParams
        toolbarGapCachedMinOuterRightWidth = minOuterRightW

        if toolbarGapDebugEnabled {
            let gapNow = ToolbarGapClampMath.pillToRightClusterGap(
                forRightCardWidth: rightFrameInRoot.width,
                baseHeight: baseHeight,
                buttonWidth: buttonWidth,
                edgeInset: edgeInset,
                pillCenterOffsetFromCardMidX: pillOffset
            )
            let leftGapNow = ToolbarGapClampMath.leftClusterToPillGap(
                forRightCardWidth: rightFrameInRoot.width,
                baseHeight: baseHeight,
                leftClusterMaxXFromCardMinX: leftClusterMaxXFromCardMinX,
                pillCenterOffsetFromCardMidX: pillOffset
            )
            toolbarGapLog(String(format: "cache_update reason=%@ minOuterRightW=%.1f (cardMin=%.1f insetDelta=%.1f) cardW=%.1f gapNow=%.1f minGap=%.1f offset=%.1f",
                                reason, minOuterRightW, minRightCardW, insetDelta, rightFrameInRoot.width, min(gapNow, leftGapNow), minToolbarGap, pillOffset))
        }
    }

    private func minRightCompositeWidthForToolbarGap() -> CGFloat {
        guard let root = headerControlsContainer.superview else { return 0 }
        let rightFrameInRoot = rightPanelPrimaryFrame(in: root)
        guard rightFrameInRoot.width.isFinite, rightFrameInRoot.width > 1 else { return 0 }

        let minScale = toolbarControlScaleBase * toolbarProximityMinScale
        let baseHeight = max(toolbarMinHitSize, 32 * minScale)
        let buttonWidth: CGFloat = max(toolbarMinHitSize, 30 * minScale)
        let edgeInset: CGFloat = 6

        let navFrameInRoot = navControlContainer.convert(navControlContainer.bounds, to: root)
        let toolbarMaxX = (navFrameInRoot.width > 1 && navFrameInRoot.maxX.isFinite)
            ? navFrameInRoot.maxX
            : headerControlsContainer.frame.maxX
        let minLeftX = toolbarMaxX + minToolbarEdgeButtonGap
        let leftX = max(rightFrameInRoot.minX + edgeInset, minLeftX)
        let settingsMaxX = leftX + (2 * buttonWidth) + edgeInset
        let leftClusterMaxXFromCardMinX = max(0, settingsMaxX - rightFrameInRoot.minX)

        let pillOffset = desiredPillCenterX(in: root, rightFrameInRoot: rightFrameInRoot) - rightFrameInRoot.midX

        return ToolbarGapClampMath.minRightCardWidthForGap(
            minGap: minToolbarGap,
            baseHeight: baseHeight,
            buttonWidth: buttonWidth,
            edgeInset: edgeInset,
            leftClusterMaxXFromCardMinX: leftClusterMaxXFromCardMinX,
            pillCenterOffsetFromCardMidX: pillOffset
        )
    }

    private func minOuterRightContainerWidth() -> CGFloat {
        if rightAuxPanelVisible {
            return max(0, minRightCompositeWidthForToolbarGap())
        }

        recomputeToolbarGapMinOuterRightWidthIfNeeded(reason: "min_outer_right")
        let minRight = max(0, toolbarGapCachedMinOuterRightWidth)
        let total = splitView.bounds.width
        let divider = splitView.dividerThickness
        let available = max(0, total - divider)
        if initialSidebarWidthForSession > 0 {
            let maxLeft = available - minRight
            if maxLeft < initialSidebarWidthForSession {
                let allowedMinRight = max(0, available - initialSidebarWidthForSession)
                return min(minRight, allowedMinRight)
            }
            return minRight
        }

        // Initial launch: keep enough space for the sidebar hard minimum even before we capture
        // the session's launch width.
        let minLeft = sidebarHardMinWidth()
        if available - minRight < minLeft {
            let allowedMinRight = max(0, available - minLeft)
            return min(minRight, allowedMinRight)
        }
        return minRight
    }

    private func minOuterRightContainerWidthFast() -> CGFloat {
        // Fast path: avoid recomputing toolbar gap metrics on the toggle input path.
        let minRight = max(0, toolbarGapCachedMinOuterRightWidth)
        let total = splitView.bounds.width
        let divider = splitView.dividerThickness
        let available = max(0, total - divider)
        if initialSidebarWidthForSession > 0 {
            let maxLeft = available - minRight
            if maxLeft < initialSidebarWidthForSession {
                let allowedMinRight = max(0, available - initialSidebarWidthForSession)
                return min(minRight, allowedMinRight)
            }
            return minRight
        }

        let minLeft = sidebarHardMinWidthFast()
        if available - minRight < minLeft {
            let allowedMinRight = max(0, available - minLeft)
            return min(minRight, allowedMinRight)
        }
        return minRight
    }

    private func defaultMinContentWidthFromScreenRatio(for window: NSWindow?) -> CGFloat? {
        guard let screen = (window?.screen ?? NSScreen.main) else { return nil }
        let screenWidth = screen.frame.width
        guard screenWidth.isFinite, screenWidth > 1 else { return nil }
        var ratio = defaultWindowMinWidthScreenRatio
        if ratio == nil, let contentSize = defaultWindowContentSize, contentSize.width.isFinite, contentSize.width > 1 {
            let computed = contentSize.width / screenWidth
            ratio = max(0.1, min(maxWindowMinWidthScreenRatio, computed))
            defaultWindowMinWidthScreenRatio = ratio
        }
        guard let finalRatio = ratio, finalRatio.isFinite, finalRatio > 0 else { return nil }
        return screenWidth * finalRatio
    }

    private func collapsedMinContentWidth(for window: NSWindow?) -> CGFloat {
        guard let window else { return 0 }
        guard let screen = window.screen ?? NSScreen.main else { return 0 }
        let screenWidth = screen.frame.width
        guard screenWidth.isFinite, screenWidth > 1 else { return 0 }
        let targetFrameWidth = screenWidth * 0.5
        let currentContentRect = window.contentRect(forFrameRect: window.frame)
        let decorationDeltaW = max(0, window.frame.width - currentContentRect.width)
        let targetContentWidth = max(0, targetFrameWidth - decorationDeltaW)
        return targetContentWidth
    }

    private func panelDrivenMinContentWidth() -> CGFloat {
        let divider = splitView.dividerThickness
        let useFast = window?.inLiveResize == true
            || resizeSessionActive
            || suppressSplitResizeHeavyWork
            || AnimationGuard.shouldDeferHeavyWork
        let minLeft: CGFloat = sidebarVisible ? (useFast ? sidebarHardMinWidthFast() : sidebarHardMinWidth()) : 0
        let minRight: CGFloat = useFast ? minOuterRightContainerWidthFast() : minOuterRightContainerWidth()
        let minSplitWidth = max(0, minLeft + divider + minRight)
        return minSplitWidth + (2 * WINDOW_BEZEL_INSET)
    }

    @discardableResult
    private func autoCollapseSidePanelsIfNeeded(proposedContentWidth: CGFloat, reason: String) -> Bool {
        return PerfLogger.measure("resize.auto_collapse") { () -> Bool in
            guard (sidebarVisible || rightAuxPanelVisible) else { return false }
            let shouldAnimate = !(window?.inLiveResize == true || resizeSessionActive)
            let panelMinRaw = panelDrivenMinContentWidth()
            let panelMin = (panelMinRaw.isFinite && panelMinRaw > 0) ? panelMinRaw : 0
            let defaultWidthMin = defaultMinContentWidthFromScreenRatio(for: window)
                ?? ((defaultWindowContentSize?.width ?? 0) * 0.5)
            // NOTE: Historically we hard-clamped window resizing to this minimum, which blocked
            // macOS snapping at 50% when panels were open. We now treat it as a collapse trigger.
            let currentMin: CGFloat = (panelMin.isFinite && panelMin > 1) ? panelMin : defaultWidthMin
            guard currentMin.isFinite, currentMin > 1 else { return false }
            if proposedContentWidth + 0.5 >= currentMin { return false }

            layoutLog("auto_collapse_panels reason=\(reason) proposedContent=\(Int(proposedContentWidth)) minContent=\(Int(currentMin))")
            if rightAuxPanelVisible {
                setRightAuxPanelVisible(false, animated: shouldAnimate, deferHeavyLayout: true)
            }
            if sidebarVisible {
                setSidebarVisible(false, animated: shouldAnimate, deferHeavyLayout: true)
            }
            updateWindowMinSizeForToolbarGapIfNeeded(reason: "auto_collapse")
            return true
        }
    }

    private func updateWindowMinSizeForToolbarGapIfNeeded(reason: String) {
        guard let window else { return }
        if baseWindowContentMinSize == nil {
            baseWindowContentMinSize = window.contentMinSize
        }
        let base = baseWindowContentMinSize ?? .zero

        var next = base
        var minWidthFromDefaults: CGFloat?
        if let defaultSize = defaultWindowContentSize {
            let minFromScreen = defaultMinContentWidthFromScreenRatio(for: window)
            minWidthFromDefaults = minFromScreen ?? (defaultSize.width * 0.5)
            next.height = max(next.height, defaultSize.height * 0.75)
        }

        // Do not enforce panel-driven minimums via `contentMinSize` (that blocks snapping).
        // Always allow the 50% screen-width minimum; panels collapse dynamically as needed.
        let collapsedMin = collapsedMinContentWidth(for: window)
        if collapsedMin.isFinite, collapsedMin > 1 {
            next.width = max(0, collapsedMin)
        } else if let minWidth = minWidthFromDefaults {
            next.width = max(next.width, minWidth)
        }

        if abs(window.contentMinSize.width - next.width) >= 0.5 || abs(window.contentMinSize.height - next.height) >= 0.5 {
            window.contentMinSize = next
            if toolbarGapDebugEnabled {
                toolbarGapLog("contentMinSize_update reason=\(reason) chatHidden=\(!rightAuxPanelVisible) minW=\(Int(next.width))")
            }
        }
    }

    // Resize performance fix: snap/tiling resizes previously ran full layout+model work on every tick,
    // causing stutter. We now treat resize as a geometry-only session and defer heavy work to settle.
    private func beginWindowResizeSessionIfNeeded(live: Bool, reason: String) {
        if resizeSessionActive { return }
        resizeSessionActive = true
        resizeSessionToken &+= 1
        resizeSessionLastEventNs = monotonicNowNs()
        resizeSessionWorkItem?.cancel()
        resizeSessionWorkItem = nil

        // Only freeze the window background during true live-resize drags.
        // Snap/tiling resizes should stay fully live to avoid flash/flicker.
        windowBackgroundFrozenByLiveResize = live
        windowBackgroundFrozenBySnap = !live
        updateWindowBackgroundFreezeState(reason: "resize_session_start")
        updateLeftPanelFreezeState(reason: "resize_session_start")
        updateRightAuxRasterizationState(reason: "resize_session_start")
        updateLeftTableHorizontalScrollerState(reason: "resize_session_start")
        updatePDFResizeFreezeState(reason: "resize_session_start")
        updateWindowMinSizeForToolbarGapIfNeeded(reason: "resize_session_start")

        ResizeLatencyProbe.shared.beginWindowResize(reason: live ? "live" : "snap")
    }

    private func noteWindowResizeEvent(live: Bool, contentWidth: CGFloat, reason: String) {
        beginWindowResizeSessionIfNeeded(live: live, reason: reason)
        resizeSessionLastEventNs = monotonicNowNs()
        ResizeLatencyProbe.shared.markWindowResizeEvent(width: contentWidth,
                                                        source: live ? "live" : "snap")
        if !live {
            scheduleWindowResizeSettle(reason: "resize_settle")
        }
    }

    private func shouldStartWindowResizeSession(for contentSize: NSSize) -> Bool {
        guard contentSize.width.isFinite, contentSize.height.isFinite else { return false }
        if lastWindowResizeContentSize.width <= 1 || lastWindowResizeContentSize.height <= 1 {
            lastWindowResizeContentSize = contentSize
            return false
        }
        let dw = abs(contentSize.width - lastWindowResizeContentSize.width)
        let dh = abs(contentSize.height - lastWindowResizeContentSize.height)
        guard dw >= 0.5 || dh >= 0.5 else { return false }
        lastWindowResizeContentSize = contentSize
        return true
    }

    private func scheduleWindowResizeSettle(reason: String) {
        resizeSessionWorkItem?.cancel()
        let token = resizeSessionToken
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            guard self.resizeSessionActive, self.resizeSessionToken == token else { return }
            self.finishWindowResizeSession(reason: reason)
        }
        resizeSessionWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + resizeSessionSettleDelay, execute: work)
    }

    private func finishWindowResizeSession(reason: String) {
        guard resizeSessionActive else { return }
        resizeSessionActive = false
        resizeSessionWorkItem?.cancel()
        resizeSessionWorkItem = nil

        applyDeferredResizeWork(reason: reason)

        // Unfreeze after deferred work so the snapshot stays stable through the settle.
        windowBackgroundFrozenByLiveResize = false
        windowBackgroundFrozenBySnap = false
        updateWindowBackgroundFreezeState(reason: "resize_session_end")
        updateLeftPanelFreezeState(reason: "resize_session_end")
        updateRightAuxRasterizationState(reason: "resize_session_end")
        updateLeftTableHorizontalScrollerState(reason: "resize_session_end")
        finishPDFInteractiveResize(reason: "resize_session_end", applyPendingScale: true)
        updatePDFResizeFreezeState(reason: "resize_session_end")
        ResizeLatencyProbe.shared.endWindowResize(reason: reason)
    }

    private func applyResizeGeometryOnly(live: Bool, immediateResize: Bool) {
        // Geometry-only updates during resize to keep motion smooth at frame rate.
        PerfLogger.measure("window.resize_geometry") {
            let geometryLive = live || resizeSessionActive
            layoutLeftContainerSubviews(duringDividerDrag: geometryLive)
            layoutRightPanelSubviews(duringLiveResize: geometryLive)
            if rightAuxPanelVisible {
                layoutViewerAnchoredHeaderControls()
            }
            updateToolbarScaleForWindowSize(reason: live ? "window_resize_live" : "window_resize",
                                             immediate: immediateResize)
            layoutShortcutResultPanel()
            updateSplitDividerHandleFrame()
            updateRightSplitDividerHandleFrame()
        }
    }

    private func applyDeferredResizeWork(reason: String) {
        // Heavy work (reflow, HTML rebuilds, annotation/table updates) is deferred to avoid frame drops.
        PerfLogger.measure("window.resize_deferred") {
            installTitlebarTintBackground()
            scheduleRootGlassTintApply(reason: "resize_settle", delay: 0.0)

            updateNarrowWindowModeIfNeeded(reason: "resize_settle")
            layoutLeftContainerSubviews()
            layoutRightPanelSubviews()
            if rightAuxPanelVisible {
                layoutViewerAnchoredHeaderControls()
            }
            updateToolbarScaleForWindowSize(reason: "resize_settle")
            layoutShortcutResultPanel()
            updateSplitDividerHandleFrame()
            updateRightSplitDividerHandleFrame()

            updateWindowMinSizeForToolbarGapIfNeeded(reason: "resize_settle")
            enforceSidebarWidthBounds(reason: "resize_settle")
            if rightAuxPanelVisible {
                scheduleRightAuxResizeSync(reason: "resize_settle")
            }

            if sidebarVisible || leftContainer.frame.width > 12 {
                reflowLeft()
                refreshVisibleRowDepth(animated: true)
                updateSearchCapsuleGeometry()
                updateSearchDepth(animated: true)
            }
            nudgePanelForResize(immediate: true)
            layoutToolbarControls()
            rightPanelPillControl.refreshForegroundColors()
            updateHoverTooltipAppearance()
            refreshHoverTooltipLayoutIfNeeded()
            updateLayoutDebugOverlay(reason: reason)
        }
    }

    private func isSidebarEffectivelyCollapsed() -> Bool {
        !sidebarVisible || leftContainer.frame.width <= 12
    }

    private func rightAuxMaxWidthAllowable(innerTotalWidth: CGFloat? = nil) -> CGFloat {
        let total = innerTotalWidth ?? rightSplitView.bounds.width
        let divider = rightSplitView.dividerThickness
        guard total.isFinite, total > 0, divider.isFinite else { return 0 }

        let available = max(0, total - divider)
        let minPrimary = minRightCompositeWidthForToolbarGap()
        // Clamp the aux panel so the primary viewer keeps the toolbar's minimum spacing,
        // while never exceeding 50% of the window's available width.
        let maxFromViewer = max(0, available - minPrimary)
        let windowAvailable = splitView.bounds.width
        let windowCap = (windowAvailable.isFinite && windowAvailable > 0)
            ? (windowAvailable * 0.5)
            : maxFromViewer
        return min(maxFromViewer, windowCap)
    }

    private func rightAuxMinWidthAllowable(innerTotalWidth: CGFloat? = nil) -> CGFloat {
        let total = innerTotalWidth ?? rightSplitView.bounds.width
        let divider = rightSplitView.dividerThickness
        guard total.isFinite, total > 0, divider.isFinite else { return 0 }

        // Match the sidebar's hard minimum width definition (Author & Year header centering).
        // Clamp to what is physically possible for the current inner split width.
        let available = max(0, total - divider)
        return min(sidebarHardMinWidth(), available)
    }

    private func balancedLeftWidthForThreePanelEquality() -> CGFloat {
        // When Chat is visible and the sidebar is visible, enforce a three-way balance:
        // left = viewer = chat. With an outer divider and an inner divider, this implies:
        // (outerTotal - outerDivider - innerDivider) = 3 * L.
        let outerTotal = splitView.bounds.width
        let outerDivider = splitView.dividerThickness
        let innerDivider = rightSplitView.dividerThickness
        guard outerTotal.isFinite, outerTotal > 0, outerDivider.isFinite, innerDivider.isFinite else { return 0 }
        let available = max(0, outerTotal - outerDivider - innerDivider)
        let scale = currentBackingScale()
        return ceilToDevicePixels(available / 3, scale: scale)
    }

    private func cappedSidebarMaxWidth(forPotential potential: CGFloat) -> CGFloat {
        guard potential.isFinite else { return 0 }
        _ = maxSidebarWidthFraction
        let total = splitView.bounds.width
        let divider = splitView.dividerThickness
        let available = max(0, total - divider)
        if available > 0 {
            return max(0, min(potential, available * 0.5))
        }
        return max(0, potential)
    }

    private func clampSidebarWidth(_ proposedPosition: CGFloat) -> CGFloat {
        let total = splitView.bounds.width
        let divider = splitView.dividerThickness
        let useFastMin = sidebarTransitionInProgress || suppressSplitResizeHeavyWork || AnimationGuard.shouldDeferHeavyWork
        let minRight = useFastMin ? minOuterRightContainerWidthFast() : minOuterRightContainerWidth()
        let maxLeftPotential = total - divider - minRight
        let maxLeft = cappedSidebarMaxWidth(forPotential: maxLeftPotential)

        if toolbarGapDebugEnabled, !rightAuxPanelVisible, proposedPosition > maxLeft + 0.5 {
            toolbarGapLog("divider_clamp proposed=\(Int(proposedPosition)) maxLeft=\(Int(maxLeft)) total=\(Int(total)) minRight=\(Int(minRight))")
        }
        if !sidebarVisible {
            return max(0, min(proposedPosition, maxLeft))
        }

        let minLeft = useFastMin ? sidebarHardMinWidthFast() : desiredMinSidebarWidthForCurrentPage(maxLeft: maxLeft)
        if allowSidebarCollapse {
            // Still permit a fully-collapsed sidebar when explicitly hidden, but when visible
            // the divider must not cross the absolute minimum.
            return min(maxLeft, max(minLeft, proposedPosition))
        }
        return min(maxLeft, max(minLeft, proposedPosition))
    }

    func splitView(_ splitView: NSSplitView,
                   constrainSplitPosition proposedPosition: CGFloat,
                   ofSubviewAt dividerIndex: Int) -> CGFloat {
        if splitView === self.splitView {
            let clamped = clampSidebarWidth(proposedPosition)
            // Record last user-driven sidebar width while dragging.
            if sidebarVisible, clamped > 12 {
                lastSidebarWidth = clamped
            }
            return clamped
        }
        if splitView === rightSplitView {
            let clamped = clampRightAuxDividerPosition(proposedPosition)
            // Record last user-driven chat width only while the user is actively dragging
            // the right divider handle. Do not treat programmatic layout passes (e.g. open/close
            // animations, window resizes, split-view relayout) as updates to the remembered width.
            if rightAuxPanelVisible, rightSplitDividerDragActive {
                let total = rightSplitView.bounds.width
                let divider = rightSplitView.dividerThickness
                let available = max(0, total - divider)
                let auxW = max(0, available - clamped)
                if auxW.isFinite, auxW > 0 {
                    lastRightAuxPanelWidth = auxW
                }
            }
            return clamped
        }
        return proposedPosition
    }

    func splitView(_ splitView: NSSplitView,
                   constrainMaxCoordinate proposedMax: CGFloat,
                   ofSubviewAt dividerIndex: Int) -> CGFloat {
        // `constrainSplitPosition` is used primarily for user-driven divider drags.
        // During window resizes / AppKit layout passes, the split view can temporarily
        // try to squeeze the right pane to an infeasible width (observed as right≈20px).
        // Constrain the divider coordinate here so the right viewer stays open.
        if splitView === self.splitView, dividerIndex == 0 {
            let total = splitView.bounds.width
            let divider = splitView.dividerThickness
            let useFastMin = sidebarTransitionInProgress || suppressSplitResizeHeavyWork || AnimationGuard.shouldDeferHeavyWork
            let minRight = useFastMin ? minOuterRightContainerWidthFast() : minOuterRightContainerWidth()
            let maxLeft = cappedSidebarMaxWidth(forPotential: total - divider - minRight)
            return min(proposedMax, maxLeft)
        }
        if splitView === rightSplitView, dividerIndex == 0 {
            return min(proposedMax, clampRightAuxDividerPosition(proposedMax))
        }
        return proposedMax
    }

    func splitView(_ splitView: NSSplitView,
                   constrainMinCoordinate proposedMin: CGFloat,
                   ofSubviewAt dividerIndex: Int) -> CGFloat {
        if splitView === self.splitView, dividerIndex == 0 {
            let total = splitView.bounds.width
            let divider = splitView.dividerThickness
            let useFastMin = sidebarTransitionInProgress || suppressSplitResizeHeavyWork || AnimationGuard.shouldDeferHeavyWork
            let minRight = useFastMin ? minOuterRightContainerWidthFast() : minOuterRightContainerWidth()
            let maxLeft = cappedSidebarMaxWidth(forPotential: total - divider - minRight)
            if !sidebarVisible {
                return max(0, min(proposedMin, maxLeft))
            }
            let minLeft = useFastMin ? sidebarHardMinWidthFast() : desiredMinSidebarWidthForCurrentPage(maxLeft: maxLeft)
            return min(maxLeft, max(minLeft, proposedMin))
        }
        if splitView === rightSplitView, dividerIndex == 0 {
            return max(0, clampRightAuxDividerPosition(proposedMin))
        }
        return proposedMin
    }

    func splitView(_ splitView: NSSplitView, canCollapseSubview subview: NSView) -> Bool {
        if splitView === self.splitView {
            // Needed so AppKit permits a fully collapsed sidebar width.
            return subview === leftContainer
        }
        if splitView === rightSplitView {
            return subview === rightAuxContainer
        }
        return false
    }

    func windowWillResize(_ sender: NSWindow, to frameSize: NSSize) -> NSSize {
        PerfLogger.measure("window.will_resize") {
            // Keep `contentMinSize` in sync (AppKit consults it during live resize).
            updateWindowMinSizeForToolbarGapIfNeeded(reason: "window_will_resize")

            let proposedContentWidth = sender.contentRect(forFrameRect: NSRect(origin: .zero, size: frameSize)).width
            let proposedContentHeight = sender.contentRect(forFrameRect: NSRect(origin: .zero, size: frameSize)).height

            _ = autoCollapseSidePanelsIfNeeded(proposedContentWidth: proposedContentWidth,
                                               reason: "window_will_resize")

            let defaultWidthMin = defaultMinContentWidthFromScreenRatio(for: sender)
                ?? ((defaultWindowContentSize?.width ?? 0) * 0.5)
            let collapsedMinWidth = collapsedMinContentWidth(for: sender)
            let collapsedEffective = (collapsedMinWidth.isFinite && collapsedMinWidth > 1)
                ? collapsedMinWidth
                : defaultWidthMin
            // Previously we clamped to the open-panels minimum here, which prevented snapping.
            // Now we always clamp to the 50% width minimum and collapse panels dynamically.
            let desiredContentMinWidth = max(0, collapsedEffective)
            let desiredContentMinHeight = max(baseWindowContentMinSize?.height ?? 0,
                                              (defaultWindowContentSize?.height ?? 0) * 0.75)
            if proposedContentWidth + 0.5 >= desiredContentMinWidth,
               proposedContentHeight + 0.5 >= desiredContentMinHeight {
                return frameSize
            }

            let currentFrame = sender.frame
            let currentContentRect = sender.contentRect(forFrameRect: currentFrame)
            let decorationDeltaW = max(0, currentFrame.width - currentContentRect.width)
            let decorationDeltaH = max(0, currentFrame.height - currentContentRect.height)
            let requiredFrameWidth = desiredContentMinWidth + decorationDeltaW
            let requiredFrameHeight = desiredContentMinHeight + decorationDeltaH
            if toolbarGapDebugEnabled {
                toolbarGapLog("window_will_resize_clamp proposedContent=\(Int(proposedContentWidth)) minContent=\(Int(desiredContentMinWidth)) -> frameW>=\(Int(requiredFrameWidth))")
            }
            return NSSize(width: max(frameSize.width, requiredFrameWidth),
                          height: max(frameSize.height, requiredFrameHeight))
        }
    }

    private enum PanelMotionReason { case focus, resize, settle }
    private enum SidebarTransitionStyle { case standard, pill }

    private func updateLeftPanelDepth(animated: Bool,
                                      reason: PanelMotionReason = .focus,
                                      gestureVelocity: CGFloat = 0.0) {
        _ = animated
        _ = reason
        _ = gestureVelocity
        // GlassCardView has no emphasis state.
    }

    private func nudgePanelForResize(immediate: Bool = false) {
        updateLeftPanelDepth(animated: true, reason: .resize)
        let settleDelay: TimeInterval = immediate ? 0.0 : 0.16
        schedulePanelSettle(delay: settleDelay)
    }

    private func schedulePanelSettle(velocity: CGFloat = 0.0, delay: TimeInterval = 0.16) {
        dividerSettleWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            self?.updateLeftPanelDepth(animated: true, reason: .settle, gestureVelocity: velocity)
            self?.refreshVisibleRowDepth(animated: true, preset: .microBounce)
        }
        dividerSettleWorkItem = work
        if delay <= 0 {
            DispatchQueue.main.async(execute: work)
        } else {
            DispatchQueue.main.asyncAfter(deadline: .now() + delay, execute: work)
        }
    }

    private func scheduleProgrammaticSplitResizeMaintenance(reason: String) {
        programmaticSplitResizeWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            guard !self.sidebarTransitionInProgress,
                  !self.rightAuxTransitionInProgress,
                  !self.dividerDragActive,
                  !self.rightSplitDividerDragActive,
                  self.window?.inLiveResize != true,
                  !self.resizeSessionActive else { return }
            if (CACurrentMediaTime() - self.lastSidebarToggleTimestamp) < 0.8 { return }

            self.scheduleRootGlassTintApply(reason: "split_resize_settle", delay: 0.0)
            self.layoutLeftContainerSubviews()
            self.layoutRightPanelSubviews()
            if self.rightAuxPanelVisible {
                self.layoutViewerAnchoredHeaderControls()
            }
            self.updateToolbarScaleForWindowSize(reason: "split_resize_settle")
            self.updateSplitDividerHandleFrame()
            self.updateRightSplitDividerHandleFrame()
            self.enforceSidebarWidthBounds(reason: "split_resize_settle")
            if self.sidebarVisible || self.leftContainer.frame.width > 12 {
                self.reflowLeft()
                self.updateSearchCapsuleGeometry()
                self.updateSearchDepth(animated: true)
            }
            self.updateSidebarStateFromSplit()
            self.nudgePanelForResize(immediate: true)
            if self.rightAuxPanelVisible {
                self.scheduleRightAuxResizeSync(reason: "split_resize_settle")
            }
            if debugLayoutEnabled {
                self.updateLayoutDebugOverlay(reason: reason)
            }
        }
        programmaticSplitResizeWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.35, execute: work)
    }

    private func captureSidebarTogglePDFSnapshot(token: UInt64) {
        sidebarTogglePDFSnapshotClearWorkItem?.cancel()
        sidebarTogglePDFSnapshotClearWorkItem = nil
        removeSidebarTogglePDFScrollObserver()
        guard isShowingPDF, pdfView.document != nil else {
            sidebarTogglePDFSnapshot = nil
            sidebarTogglePDFSnapshotToken = token
            return
        }
        sidebarTogglePDFSnapshot = capturePDFScrollSnapshot(reason: "sidebar_toggle")
        sidebarTogglePDFSnapshotToken = token
        if sidebarTogglePDFSnapshot != nil {
            installSidebarTogglePDFScrollObserver(token: token)
        }
    }

    private func installSidebarTogglePDFScrollObserver(token: UInt64) {
        removeSidebarTogglePDFScrollObserver()
        guard isShowingPDF, pdfView.document != nil, let scrollView = pdfPrimaryScrollView() else { return }
        let clip = scrollView.contentView
        clip.postsBoundsChangedNotifications = true
        sidebarTogglePDFScrollObserver = NotificationCenter.default.addObserver(
            forName: NSView.boundsDidChangeNotification,
            object: clip,
            queue: .main
        ) { [weak self] _ in
            guard let self else { return }
            guard self.sidebarTogglePDFSnapshotToken == token else { return }
            guard self.sidebarTransitionInProgress
                || self.sidebarToggleDeferredWorkItem != nil
                || self.sidebarTogglePDFSnapshotClearWorkItem != nil else { return }
            guard self.isShowingPDF, self.pdfView.document != nil else { return }
            if self.sidebarTogglePDFUserScrollActive {
                self.sidebarTogglePDFSnapshot = self.capturePDFScrollSnapshot(reason: "sidebar_toggle_scroll")
                return
            }
            if self.sidebarTransitionInProgress { return }
            guard !self.sidebarTogglePDFRestoringScroll else { return }
            if self.sidebarTogglePDFSnapshot == nil {
                self.sidebarTogglePDFSnapshot = self.capturePDFScrollSnapshot(reason: "sidebar_toggle_scroll_lock")
            }
            guard let snapshot = self.sidebarTogglePDFSnapshot else { return }
            self.sidebarTogglePDFRestoringScroll = true
            self.restorePDFScrollSnapshot(snapshot, reason: "sidebar_toggle_scroll_lock", preferClipOrigin: true)
            self.sidebarTogglePDFRestoringScroll = false
        }

        let center = NotificationCenter.default
        let willStart = center.addObserver(
            forName: NSScrollView.willStartLiveScrollNotification,
            object: scrollView,
            queue: .main
        ) { [weak self] _ in
            self?.noteSidebarTogglePDFUserScroll()
        }
        let didLive = center.addObserver(
            forName: NSScrollView.didLiveScrollNotification,
            object: scrollView,
            queue: .main
        ) { [weak self] _ in
            self?.noteSidebarTogglePDFUserScroll()
        }
        let didEnd = center.addObserver(
            forName: NSScrollView.didEndLiveScrollNotification,
            object: scrollView,
            queue: .main
        ) { [weak self] _ in
            self?.sidebarTogglePDFUserScrollActive = false
            self?.sidebarTogglePDFUserScrollResetWorkItem?.cancel()
            self?.sidebarTogglePDFUserScrollResetWorkItem = nil
        }
        sidebarTogglePDFUserScrollObservers = [willStart, didLive, didEnd]
    }

    private func removeSidebarTogglePDFScrollObserver() {
        if let observer = sidebarTogglePDFScrollObserver {
            NotificationCenter.default.removeObserver(observer)
            sidebarTogglePDFScrollObserver = nil
        }
        if !sidebarTogglePDFUserScrollObservers.isEmpty {
            for obs in sidebarTogglePDFUserScrollObservers {
                NotificationCenter.default.removeObserver(obs)
            }
            sidebarTogglePDFUserScrollObservers.removeAll()
        }
        sidebarTogglePDFUserScrollActive = false
        sidebarTogglePDFUserScrollResetWorkItem?.cancel()
        sidebarTogglePDFUserScrollResetWorkItem = nil
    }

    private func noteSidebarTogglePDFUserScroll() {
        guard sidebarTransitionInProgress
            || sidebarToggleDeferredWorkItem != nil
            || sidebarTogglePDFSnapshotClearWorkItem != nil else { return }
        sidebarTogglePDFLastUserScrollTimestamp = CACurrentMediaTime()
        sidebarTogglePDFUserScrollActive = true
        sidebarTogglePDFUserScrollResetWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            let now = CACurrentMediaTime()
            if now - self.sidebarTogglePDFLastUserScrollTimestamp >= 0.18 {
                self.sidebarTogglePDFUserScrollActive = false
            }
        }
        sidebarTogglePDFUserScrollResetWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.2, execute: work)
    }

    private func applySidebarTogglePDFSnapshotIfNeeded(token: UInt64, preferClipOrigin: Bool) {
        guard sidebarTogglePDFSnapshotToken == token else { return }
        guard let snapshot = sidebarTogglePDFSnapshot else { return }
        if isShowingPDF, !preferClipOrigin {
            if rightPanelContentHost.needsLayout {
                rightPanelContentHost.layoutSubtreeIfNeeded()
            }
            if pdfView.needsLayout {
                pdfView.layoutSubtreeIfNeeded()
            }
        }
        restorePDFScrollSnapshot(snapshot,
                                 reason: preferClipOrigin ? "sidebar_toggle_apply_clip" : "sidebar_toggle_apply",
                                 preferClipOrigin: preferClipOrigin,
                                 anchorFallbackToClipOrigin: !preferClipOrigin)
    }

    private func restoreSidebarTogglePDFSnapshotIfNeeded(token: UInt64) {
        guard sidebarTogglePDFSnapshotToken == token else { return }
        guard sidebarTogglePDFSnapshot != nil else {
            removeSidebarTogglePDFScrollObserver()
            sidebarTogglePDFSnapshotClearWorkItem?.cancel()
            sidebarTogglePDFSnapshotClearWorkItem = nil
            sidebarTogglePDFScrollLockTimer?.invalidate()
            sidebarTogglePDFScrollLockTimer = nil
            return
        }
        applySidebarTogglePDFSnapshotIfNeeded(token: token, preferClipOrigin: sidebarTogglePreferClipOrigin)
        sidebarTogglePDFSnapshot = nil
        sidebarTogglePDFSnapshotClearWorkItem?.cancel()
        sidebarTogglePDFSnapshotClearWorkItem = nil
        sidebarTogglePDFScrollLockTimer?.invalidate()
        sidebarTogglePDFScrollLockTimer = nil
        removeSidebarTogglePDFScrollObserver()
    }

    private func scheduleSidebarTogglePDFSnapshotClear(token: UInt64, delay: TimeInterval = 0.6) {
        sidebarTogglePDFSnapshotClearWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            guard self.sidebarTogglePDFSnapshotToken == token else { return }
            self.restoreSidebarTogglePDFSnapshotIfNeeded(token: token)
        }
        sidebarTogglePDFSnapshotClearWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + delay, execute: work)
        startSidebarTogglePDFScrollLock(token: token, duration: delay)
    }

    private func applySidebarTogglePDFSnapshotDuringResize() {
        applySidebarTogglePDFSnapshotIfNeeded(token: sidebarToggleToken, preferClipOrigin: true)
    }

    private func startSidebarTogglePDFScrollLock(token: UInt64, duration: TimeInterval) {
        sidebarTogglePDFScrollLockTimer?.invalidate()
        let startTime = CACurrentMediaTime()
        let interval = displayRefreshInterval(for: window)
        let timer = Timer(timeInterval: interval, repeats: true) { [weak self] timer in
            guard let self else {
                timer.invalidate()
                return
            }
            guard self.sidebarTogglePDFSnapshotToken == token else {
                timer.invalidate()
                return
            }
            if (CACurrentMediaTime() - startTime) >= duration {
                timer.invalidate()
                if self.sidebarTogglePDFScrollLockTimer === timer {
                    self.sidebarTogglePDFScrollLockTimer = nil
                }
                return
            }
            guard self.sidebarTransitionInProgress
                || self.sidebarToggleDeferredWorkItem != nil
                || self.sidebarTogglePDFSnapshotClearWorkItem != nil else { return }
            guard !self.sidebarTogglePDFUserScrollActive else { return }
            self.applySidebarTogglePDFSnapshotIfNeeded(token: token, preferClipOrigin: true)
        }
        sidebarTogglePDFScrollLockTimer = timer
        RunLoop.main.add(timer, forMode: .common)
    }

    private func beginSplitResizeSuppression(token: UInt64) {
        suppressSplitResizeHeavyWork = true
        suppressSplitResizeHeavyWorkToken = token
        suppressSplitResizeHeavyWorkUntil = CACurrentMediaTime() + 0.30
        skipNextSplitResizeHeavyWork = false
    }

    private func endSplitResizeSuppression(token: UInt64) {
        guard suppressSplitResizeHeavyWorkToken == token else { return }
        let now = CACurrentMediaTime()
        suppressSplitResizeHeavyWorkUntil = max(suppressSplitResizeHeavyWorkUntil, now + 0.20)
        skipNextSplitResizeHeavyWork = true
        let deadline = suppressSplitResizeHeavyWorkUntil
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.25) { [weak self] in
            guard let self else { return }
            guard self.suppressSplitResizeHeavyWorkToken == token else { return }
            guard !self.sidebarTransitionInProgress else { return }
            if CACurrentMediaTime() >= deadline {
                self.suppressSplitResizeHeavyWork = false
                self.skipNextSplitResizeHeavyWork = false
            }
        }
    }

    private func scheduleSidebarTogglePostWork(visible: Bool, token: UInt64) {
        sidebarToggleDeferredWorkItem?.cancel()
        var work: DispatchWorkItem?
        work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            guard self.sidebarToggleToken == token else { return }
            self.layoutLeftContainerSubviews(duringDividerDrag: true)
            self.layoutRightPanelSubviews(duringLiveResize: true)
            self.updatePageStepperState(triggerLayout: false)
            self.updateRightSplitDividerHandleFrame()
            self.updateToolbarScaleForWindowSize(reason: "sidebar_toggle_settle")
            if !self.isShowingPDF { self.updateDetails() }
            self.refreshLeftLayoutAfterSidebarToggle(visible: visible, layoutAlreadyApplied: true)
            self.applySidebarTogglePDFSnapshotIfNeeded(token: token, preferClipOrigin: !visible)
            self.scheduleSidebarTogglePDFSnapshotClear(token: token)
            self.endSplitResizeSuppression(token: token)
            if let work, self.sidebarToggleDeferredWorkItem === work {
                self.sidebarToggleDeferredWorkItem = nil
            }
        }
        sidebarToggleDeferredWorkItem = work
        if let work {
            DispatchQueue.main.async(execute: work)
        }
    }

    private func scheduleDividerDragReflow() {
        dividerDragReflowWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            guard !self.dividerDragActive else { return }
            let sidebarShown = self.sidebarVisible || self.leftContainer.frame.width > 12
            guard sidebarShown else { return }
            self.reflowLeft()
        }
        dividerDragReflowWorkItem = work
        DispatchQueue.main.async(execute: work)
    }

    private func scheduleRightAuxResizeSync(reason: String, delay: TimeInterval = 0.0) {
        guard rightAuxPanelVisible else { return }
        rightAuxResizeSyncWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            guard self.rightAuxPanelVisible else { return }
            guard !self.rightAuxTransitionInProgress else { return }
            guard !self.rightSplitDividerDragActive else { return }
            guard !self.rightAuxResizeSyncInProgress else { return }

            self.rightAuxResizeSyncInProgress = true
            defer { self.rightAuxResizeSyncInProgress = false }

            PerfLogger.measure("autolayout.window.content_view") {
                self.window?.contentView?.layoutSubtreeIfNeeded()
            }
            PerfLogger.measure("autolayout.splitView.right_aux_sync") {
                self.splitView.layoutSubtreeIfNeeded()
            }
            PerfLogger.measure("autolayout.rightSplitView.right_aux_sync") {
                self.rightSplitView.layoutSubtreeIfNeeded()
            }
            self.enforceRightAuxMinWidthIfNeeded(reason: reason)
            self.enforceRightAuxTargetWidthIfNeeded(reason: reason)
            self.layoutRightPanelSubviews()
            self.layoutViewerAnchoredHeaderControls()
            self.updateToolbarScaleForWindowSize(reason: reason)
            self.updateRightSplitDividerHandleFrame()
        }
        rightAuxResizeSyncWorkItem = work
        if delay > 0 {
            DispatchQueue.main.asyncAfter(deadline: .now() + delay, execute: work)
        } else {
            DispatchQueue.main.async(execute: work)
        }
    }

    private func refreshVisibleRowDepth(animated: Bool, preset: SpringPreset = .crisp) {
        let visible = tableView.rows(in: tableView.visibleRect)
        guard visible.length > 0 else { return }

        for row in visible.location..<(visible.location + visible.length) {
            guard let rowView = tableView.rowView(atRow: row, makeIfNecessary: false) as? ElasticRowView else { continue }
            rowView.isHeaderRow = (row == 0)
            rowView.rowIndex = row
            rowView.reduceMotionProvider = { [weak self] in self?.shouldReduceMotion ?? false }
            rowView.isActiveWindowProvider = { [weak self] in self?.isWindowActiveForAppearance() ?? true }
            rowView.refreshDepth(animated: animated, preset: preset)
        }
    }

    private func setupPinnedHeader() {
        leftHeaderBar.wantsLayer = true
        leftHeaderBar.layer?.backgroundColor = NSColor.clear.cgColor
        leftHeaderBar.autoresizingMask = []
        leftHeaderEdgeOverlay.translatesAutoresizingMaskIntoConstraints = true
        leftHeaderEdgeOverlay.wantsLayer = true
        leftHeaderEdgeOverlay.layer?.masksToBounds = false
        if let layer = leftHeaderEdgeOverlay.layer {
            leftHeaderEdgeOrnaments.attach(to: layer)
        }
        if leftHeaderGlassBackground == nil {
            let bg = makeGlassEffectView(
                passthrough: true,
                cornerRadius: 0,
                tintColor: leftPanelGlassTintColor(),
                style: .regular,
                fallbackMaterial: .hudWindow,
                fallbackBlending: .behindWindow,
                fallbackState: .active,
                emphasized: false
            )
            clearGlassBorder(for: bg)
            clearGlassShadow(for: bg)
            bg.translatesAutoresizingMaskIntoConstraints = true
            bg.autoresizingMask = [.width, .height]
            leftHeaderBar.addSubview(bg, positioned: .below, relativeTo: leftHeaderEdgeOverlay)
            leftHeaderGlassBackground = bg
        }
        leftHeaderBar.addSubview(leftHeaderEdgeOverlay)
        leftHeaderBar.addSubview(leftHeaderLabel)
        leftHeaderEdgeOverlay.isHidden = true

        leftHeaderLabel.translatesAutoresizingMaskIntoConstraints = true
        leftHeaderLabel.autoresizingMask = []
        leftHeaderLabel.font = NSFont.systemFont(ofSize: 12, weight: .semibold)
        leftHeaderLabel.textColor = leftHeaderTextColor()
        leftHeaderLabel.alignment = .left
        leftHeaderLabel.backgroundColor = .clear
        leftHeaderLabel.lineBreakMode = .byTruncatingTail

        leftHeaderRule.wantsLayer = true
        leftHeaderRule.layer?.backgroundColor = resolvedSystemColor(.separatorColor).cgColor
        leftHeaderRule.autoresizingMask = []

        updateLeftHeaderText()
        leftHeaderBar.isHidden = true
        leftHeaderRule.isHidden = true

        searchBackgroundFrameObserver = NotificationCenter.default.addObserver(
            forName: NSView.frameDidChangeNotification,
            object: searchBackground,
            queue: .main
        ) { [weak self] _ in
            self?.updateSearchCapsuleGeometry()
        }
        installSearchTracking()
    }

	    private func updateSearchCapsuleGeometry() {
	        guard let layer = searchBackground.layer else { return }
	        let b = searchBackground.bounds
	        guard b.width > 1, b.height > 1 else { return }

	        let radius = b.height / 2
	        let maskPath = CGPath(roundedRect: b,
	                              cornerWidth: radius,
	                              cornerHeight: radius,
	                              transform: nil)

	        let lineWidth: CGFloat = max(1, SPOTLIGHT_SEARCH_OUTLINE_WIDTH)
	        let inset = lineWidth / 2
	        let outlineRect = b.insetBy(dx: inset, dy: inset)
	        let outlineRadius = max(0, outlineRect.height / 2)
	        let outlinePath = CGPath(roundedRect: outlineRect,
	                                 cornerWidth: outlineRadius,
	                                 cornerHeight: outlineRadius,
	                                 transform: nil)
	        let innerRect = b.insetBy(dx: inset + 1.0, dy: inset + 1.0)
	        let innerRadius = max(0, innerRect.height / 2)
	        let innerPath = CGPath(roundedRect: innerRect,
	                               cornerWidth: innerRadius,
	                               cornerHeight: innerRadius,
	                               transform: nil)

	        let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
	        let edgePx = 1.0 / scale
	        let maxInset = max(0.0, radius - 0.5)
	        let edgeInset = min(edgePx, maxInset)
	        let edgeInnerInset = min(edgePx * 2.0, maxInset)
	        let outerInnerRect = b.insetBy(dx: edgeInset, dy: edgeInset)
	        let innerInnerRect = b.insetBy(dx: edgeInnerInset, dy: edgeInnerInset)
	        let outerInnerPath = CGPath(roundedRect: outerInnerRect,
	                                    cornerWidth: max(0, radius - edgeInset),
	                                    cornerHeight: max(0, radius - edgeInset),
	                                    transform: nil)
	        let innerInnerPath = CGPath(roundedRect: innerInnerRect,
	                                    cornerWidth: max(0, radius - edgeInnerInset),
	                                    cornerHeight: max(0, radius - edgeInnerInset),
	                                    transform: nil)
	        let outerBandPath = MaterialEdgeStack.ringPath(outer: maskPath, inner: outerInnerPath)
	        let innerBandPath = MaterialEdgeStack.ringPath(outer: outerInnerPath, inner: innerInnerPath)

	        CATransaction.begin()
	        CATransaction.setDisableActions(true)
	        layer.masksToBounds = true
	        layer.cornerRadius = radius
	        if let glass = searchBackground as? NSGlassEffectView {
	            glass.cornerRadius = radius
	        }
	        searchOutlineLayer.lineWidth = lineWidth
	        searchOutlineLayer.path = outlinePath
	        searchInnerOutlineLayer.lineWidth = lineWidth
	        searchInnerOutlineLayer.path = innerPath
	        searchMaskLayer.path = maskPath
	        searchCenterGlowLayer.frame = b
	        searchCenterGlowLayer.locations = [0.0, 1.0]
	        searchHighlightLayer.frame = b
	        searchHighlightLayer.locations = [0.0, 0.55, 1.0]
	        searchFalloffLayer.frame = b
	        searchFalloffLayer.locations = [0.0, 1.0]
	        if let ornamentLayer = searchEdgeOverlay.layer {
	            searchEdgeOrnaments.setContentsScale(scale)
	            searchEdgeOrnaments.setFrames(bounds: ornamentLayer.bounds)
	            searchEdgeOrnaments.maskLayer.path = maskPath
	            searchEdgeOrnaments.outerBandLayer.path = outerBandPath
	            searchEdgeOrnaments.innerBandLayer.path = innerBandPath
	        }
	        if let containerLayer = searchContainer.layer {
	            containerLayer.shadowPath = maskPath
	        }
	        CATransaction.commit()

	        updateEmbeddedSearchAppearance(animated: false)
	        layoutSuggestionsDropdown()
	    }

    private func updateLeftHeaderEdgeGeometry() {
        guard !leftHeaderBar.isHidden else { return }
        guard let layer = leftHeaderBar.layer else { return }
        let b = leftHeaderBar.bounds
        guard b.width > 1, b.height > 1 else { return }

        let radius = b.height / 2
        let maskPath = CGPath(roundedRect: b,
                              cornerWidth: radius,
                              cornerHeight: radius,
                              transform: nil)

        let scale = max(1.0, window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
        let edgePx = 1.0 / scale
        let maxInset = max(0.0, radius - 0.5)
        let edgeInset = min(edgePx, maxInset)
        let edgeInnerInset = min(edgePx * 2.0, maxInset)
        let outerInnerRect = b.insetBy(dx: edgeInset, dy: edgeInset)
        let innerInnerRect = b.insetBy(dx: edgeInnerInset, dy: edgeInnerInset)
        let outerInnerPath = CGPath(roundedRect: outerInnerRect,
                                    cornerWidth: max(0, radius - edgeInset),
                                    cornerHeight: max(0, radius - edgeInset),
                                    transform: nil)
        let innerInnerPath = CGPath(roundedRect: innerInnerRect,
                                    cornerWidth: max(0, radius - edgeInnerInset),
                                    cornerHeight: max(0, radius - edgeInnerInset),
                                    transform: nil)
        let outerBandPath = MaterialEdgeStack.ringPath(outer: maskPath, inner: outerInnerPath)
        let innerBandPath = MaterialEdgeStack.ringPath(outer: outerInnerPath, inner: innerInnerPath)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer.masksToBounds = true
        layer.cornerRadius = radius
        if #available(macOS 10.13, *) {
            layer.cornerCurve = .continuous
        }
        if let bg = leftHeaderGlassBackground {
            bg.frame = b
            if let bgLayer = bg.layer {
                bgLayer.cornerRadius = radius
                bgLayer.masksToBounds = true
                if #available(macOS 10.13, *) {
                    bgLayer.cornerCurve = .continuous
                }
            }
            if let glass = bg as? NSGlassEffectView {
                glass.cornerRadius = radius
            }
        }

        guard !leftHeaderEdgeOverlay.isHidden else {
            CATransaction.commit()
            return
        }

        leftHeaderEdgeOverlay.frame = b
        if let ornamentLayer = leftHeaderEdgeOverlay.layer {
            leftHeaderEdgeOrnaments.setContentsScale(scale)
            leftHeaderEdgeOrnaments.setFrames(bounds: ornamentLayer.bounds)
            leftHeaderEdgeOrnaments.maskLayer.path = maskPath
            leftHeaderEdgeOrnaments.outerBandLayer.path = outerBandPath
            leftHeaderEdgeOrnaments.innerBandLayer.path = innerBandPath
            let bands = ToolbarOutlineTokens.edgeBands(for: .normal)
            leftHeaderEdgeOrnaments.applyEdgeStyle(outerBand: bands.outer, innerRim: bands.inner)
        }
        CATransaction.commit()
    }

    private func updatePDFFindCapsuleGeometry() {
        guard let layer = pdfFindBackgroundView.layer else { return }
        let b = pdfFindBackgroundView.bounds
        guard b.width > 1, b.height > 1 else { return }

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        let radius = b.height / 2
        if let card = pdfFindBackgroundView as? GlassCardView {
            card.cornerRadius = radius
        } else {
            layer.masksToBounds = true
            layer.cornerRadius = radius
            if let glass = pdfFindBackgroundView as? NSGlassEffectView {
                glass.cornerRadius = radius
            }
        }
        if pdfFindOutlineLayer.superlayer != nil {
            let lineWidth: CGFloat = max(1, SPOTLIGHT_SEARCH_OUTLINE_WIDTH)
            let inset = lineWidth / 2
            let rect = b.insetBy(dx: inset, dy: inset)
            let outlineRadius = rect.height / 2
            let path = CGPath(roundedRect: rect,
                              cornerWidth: outlineRadius,
                              cornerHeight: outlineRadius,
                              transform: nil)
            pdfFindOutlineLayer.lineWidth = lineWidth
            pdfFindOutlineLayer.strokeColor = spotlightSearchOutlineColor().cgColor
            pdfFindOutlineLayer.path = path
            pdfFindHighlightLayer.frame = b
            pdfFindHighlightLayer.colors = spotlightSearchHighlightColors()
            pdfFindHighlightLayer.locations = [0.0, 0.55, 1.0]
            pdfFindFalloffLayer.frame = b
            pdfFindFalloffLayer.colors = spotlightSearchFalloffColors()
            pdfFindFalloffLayer.locations = [0.0, 1.0]
        }
        CATransaction.commit()
    }

    private func installSearchTracking() {
        if let tracking = searchTracking {
            searchField.removeTrackingArea(tracking)
        }
        let opts: NSTrackingArea.Options = [.mouseEnteredAndExited, .activeAlways, .inVisibleRect]
        let area = NSTrackingArea(rect: searchField.bounds, options: opts, owner: self, userInfo: nil)
        searchField.addTrackingArea(area)
        searchTracking = area
    }

    private func installPDFFindTracking() {
        if let tracking = pdfFindTracking {
            pdfFindField.removeTrackingArea(tracking)
        }
        let opts: NSTrackingArea.Options = [.mouseEnteredAndExited, .activeAlways, .inVisibleRect]
        let area = NSTrackingArea(rect: pdfFindField.bounds, options: opts, owner: self, userInfo: nil)
        pdfFindField.addTrackingArea(area)
        pdfFindTracking = area
    }

    override func mouseEntered(with event: NSEvent) {
        if event.trackingArea == searchTracking {
            searchHover = true
            updateSearchDepth(animated: true)
        } else if event.trackingArea == rightAuxAskTracking {
            rightAuxAskHover = true
            updateRightAuxAskDepth(animated: true)
        } else if event.trackingArea == pdfFindTracking {
            pdfFindHover = true
            updatePDFFindDepth(animated: true)
        }
        super.mouseEntered(with: event)
    }

    override func mouseExited(with event: NSEvent) {
        if event.trackingArea == searchTracking {
            searchHover = false
            updateSearchDepth(animated: true)
        } else if event.trackingArea == rightAuxAskTracking {
            rightAuxAskHover = false
            updateRightAuxAskDepth(animated: true)
        } else if event.trackingArea == pdfFindTracking {
            pdfFindHover = false
            updatePDFFindDepth(animated: true)
        }
        super.mouseExited(with: event)
    }

    private func updateSearchDepth(animated: Bool) {
        updateEmbeddedSearchAppearance(animated: animated)
        updateSearchHoverMotion(animated: animated)
        enforceActiveVisualEffectState(searchBackground)
    }

    private func updateSearchContainerAnchor() {
        guard let layer = searchContainer.layer else { return }
        let anchor = CGPoint(x: 0.5, y: 0.5)
        let position = CGPoint(x: searchContainer.frame.midX, y: searchContainer.frame.midY)

        guard layer.anchorPoint != anchor || layer.position != position else { return }
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer.anchorPoint = anchor
        layer.position = position
        CATransaction.commit()
    }

    private func cornerInset(at distance: CGFloat, radius: CGFloat) -> CGFloat {
        guard radius > 0, distance < radius else { return 0 }
        let clamped = max(0, min(distance, radius))
        let under = max(0, (radius * radius) - (clamped * clamped))
        return radius - sqrt(under)
    }

    private func maxSearchHoverScale(lift: CGFloat) -> CGFloat {
        guard let root = searchContainer.superview else { return 1.0 }
        let searchFrame = searchContainer.frame
        guard searchFrame.width > 1 else { return 1.0 }

        let leftFrame = leftContainer.convert(leftContainer.bounds, to: root)
        let leftInset = max(0, searchFrame.minX - leftFrame.minX)
        let rightInset = max(0, leftFrame.maxX - searchFrame.maxX)
        let minInset = min(leftInset, rightInset)

        let radius = leftCardCornerRadius()
        let topInsetRaw = max(0, leftFrame.maxY - searchFrame.maxY)
        let bottomInsetRaw = max(0, searchFrame.minY - leftFrame.minY)
        let topInset = max(0, topInsetRaw + min(lift, 0))
        let bottomInset = bottomInsetRaw
        let cornerInset = max(cornerInset(at: topInset, radius: radius),
                              cornerInset(at: bottomInset, radius: radius))
        let safeInset = max(0, minInset - cornerInset)

        return max(1.0, 1.0 + (2.0 * safeInset / searchFrame.width))
    }

    private func updateSearchHoverMotion(animated: Bool) {
        guard let layer = searchContainer.layer else { return }
        let reduceMotion = shouldReduceMotion || !animated
        let isActive = searchHover && searchField.isEnabled

        updateSearchContainerAnchor()
        let baseScale: CGFloat = isActive ? 1.02 : 1.0
        let lift: CGFloat = isActive ? -0.8 : 0.0
        let scale: CGFloat = isActive ? min(baseScale, maxSearchHoverScale(lift: lift)) : 1.0
        var transform = CATransform3DIdentity
        transform = CATransform3DTranslate(transform, 0, lift, 0)
        transform = CATransform3DScale(transform, scale, scale, 1.0)

        let glowColor = (NSColor.white.usingColorSpace(.deviceRGB) ?? NSColor.white)
        let targetShadowOpacity: Float = isActive ? 0.22 : 0.0
        let targetShadowRadius: CGFloat = isActive ? 6 : 0
        let targetShadowOffset = CGSize(width: 0, height: isActive ? -1.0 : 0)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer.shadowColor = glowColor.cgColor
        CATransaction.commit()

        if reduceMotion {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.transform = transform
            layer.shadowOpacity = targetShadowOpacity
            layer.shadowRadius = targetShadowRadius
            layer.shadowOffset = targetShadowOffset
            CATransaction.commit()
        } else {
            animateLayer(layer, keyPath: "transform", to: transform, preset: .microBounce, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOpacity", to: targetShadowOpacity, preset: .microBounce, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowRadius", to: targetShadowRadius, preset: .microBounce, reduceMotion: false, basicDuration: 0.14)
            animateLayer(layer, keyPath: "shadowOffset", to: targetShadowOffset, preset: .microBounce, reduceMotion: false, basicDuration: 0.14)
        }
    }

    private func updatePDFFindDepth(animated: Bool) {
        if let layer = pdfFindBackgroundView.layer,
           layer.animation(forKey: "pdfFindTransform") != nil {
            return
        }
        applySearchBarDepth(to: pdfFindBackgroundView, focused: pdfFindFocused, hovered: pdfFindHover, animated: animated)
        enforceActiveVisualEffectState(pdfFindBackgroundView)
    }

    private func pdfFindTransform(scaleX: CGFloat, scaleY: CGFloat, yOffset: CGFloat) -> CATransform3D {
        var transform = CATransform3DIdentity
        transform = CATransform3DScale(transform, scaleX, scaleY, 1.0)
        transform = CATransform3DTranslate(transform, 0, yOffset, 0)
        return transform
    }

    private func pdfFindHiddenTransform() -> CATransform3D {
        pdfFindTransform(
            scaleX: PDF_FIND_DISMISS_END_SCALE_X,
            scaleY: PDF_FIND_DISMISS_END_SCALE_Y,
            yOffset: PDF_FIND_DISMISS_END_Y_OFFSET
        )
    }

    private func currentLayerTransform(_ layer: CALayer) -> CATransform3D {
        layer.presentation()?.transform ?? layer.transform
    }

    private func currentLayerOpacity(_ layer: CALayer) -> Float {
        layer.presentation()?.opacity ?? layer.opacity
    }

    private func currentLayerShadowOpacity(_ layer: CALayer) -> Float {
        layer.presentation()?.shadowOpacity ?? layer.shadowOpacity
    }

    private func currentLayerShadowRadius(_ layer: CALayer) -> CGFloat {
        if let value = layer.presentation()?.value(forKeyPath: "shadowRadius") as? NSNumber {
            return CGFloat(truncating: value)
        }
        return layer.shadowRadius
    }

    private func currentLayerShadowOffset(_ layer: CALayer) -> CGSize {
        if let value = layer.presentation()?.value(forKeyPath: "shadowOffset") as? NSValue {
            return value.sizeValue
        }
        return layer.shadowOffset
    }

    private func addKeyframeAnimation(_ layer: CALayer,
                                      keyPath: String,
                                      values: [Any],
                                      keyTimes: [NSNumber],
                                      duration: CFTimeInterval,
                                      timingFunctions: [CAMediaTimingFunction],
                                      key: String) {
        let animation = CAKeyframeAnimation(keyPath: keyPath)
        animation.values = values
        animation.keyTimes = keyTimes
        animation.timingFunctions = timingFunctions
        animation.duration = duration
        animation.isRemovedOnCompletion = true
        layer.add(animation, forKey: key)
    }

    private func setPDFFindHUDVisible(_ visible: Bool, animated: Bool) {
        pdfFindVisibilityWorkItem?.cancel()
        pdfFindDepthWorkItem?.cancel()
        if !visible {
            stopPDFFindLiveGlass(reason: "hide")
        }
        guard let backgroundLayer = pdfFindBackgroundView.layer else {
            pdfFindHUD.isHidden = !visible
            return
        }
        let contentLayer = pdfFindContentView.layer

        let theme = currentSearchBarTheme()
        let reduce = shouldReduceMotion || !animated
        let targetTransform = CATransform3DIdentity
        let targetShadowOpacity = theme.shadowOpacity
        let targetShadowRadius = theme.shadowRadius
        let targetShadowOffset = theme.shadowOffset

        let liveTransform = currentLayerTransform(backgroundLayer)
        let liveOpacity = currentLayerOpacity(backgroundLayer)
        let liveShadowOpacity = currentLayerShadowOpacity(backgroundLayer)
        let liveShadowRadius = currentLayerShadowRadius(backgroundLayer)
        let liveShadowOffset = currentLayerShadowOffset(backgroundLayer)

        backgroundLayer.removeAnimation(forKey: "pdfFindTransform")
        backgroundLayer.removeAnimation(forKey: "pdfFindOpacity")
        backgroundLayer.removeAnimation(forKey: "pdfFindShadowOpacity")
        backgroundLayer.removeAnimation(forKey: "pdfFindShadowRadius")
        backgroundLayer.removeAnimation(forKey: "pdfFindShadowOffset")
        contentLayer?.removeAnimation(forKey: "pdfFindContentTransform")
        contentLayer?.removeAnimation(forKey: "pdfFindContentOpacity")

        if visible {
            let wasHidden = pdfFindHUD.isHidden
            if wasHidden {
                pdfFindHUD.isHidden = false
                layoutPDFFindHUDSubviews()
                if let card = pdfFindBackgroundView as? GlassCardView {
                    card.invalidateGlass(reason: "pdf_find_show")
                }
                pdfFindPrevButton.invalidateLiquidGlass(reason: "pdf_find_show")
                pdfFindNextButton.invalidateLiquidGlass(reason: "pdf_find_show")
            }

            let startTransform = wasHidden
                ? pdfFindTransform(
                    scaleX: PDF_FIND_APPEAR_START_SCALE_X,
                    scaleY: PDF_FIND_APPEAR_START_SCALE_Y,
                    yOffset: PDF_FIND_APPEAR_START_Y_OFFSET
                )
                : liveTransform
            let startOpacity: Float = wasHidden ? 0 : liveOpacity
            let startShadowOpacity: Float = wasHidden ? 0 : liveShadowOpacity
            let startShadowRadius: CGFloat = wasHidden ? 0 : liveShadowRadius

            if let contentLayer, wasHidden {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                contentLayer.opacity = 0
                contentLayer.transform = startTransform
                CATransaction.commit()
            }

            if reduce {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                backgroundLayer.transform = startTransform
                backgroundLayer.opacity = startOpacity
                backgroundLayer.shadowOpacity = startShadowOpacity
                backgroundLayer.shadowRadius = startShadowRadius
                backgroundLayer.shadowOffset = targetShadowOffset
                CATransaction.commit()

                animateLayer(backgroundLayer, keyPath: "transform", to: targetTransform, preset: .crisp, reduceMotion: true, basicDuration: 0.2)
                animateLayer(backgroundLayer, keyPath: "opacity", to: 1, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                animateLayer(backgroundLayer, keyPath: "shadowOpacity", to: targetShadowOpacity, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                animateLayer(backgroundLayer, keyPath: "shadowRadius", to: targetShadowRadius, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                if let contentLayer {
                    CATransaction.begin()
                    CATransaction.setDisableActions(true)
                    contentLayer.transform = startTransform
                    contentLayer.opacity = startOpacity
                    CATransaction.commit()
                    animateLayer(contentLayer, keyPath: "transform", to: targetTransform, preset: .crisp, reduceMotion: true, basicDuration: 0.2)
                    animateLayer(contentLayer, keyPath: "opacity", to: 1, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                }
                return
            }

            CATransaction.begin()
            CATransaction.setDisableActions(true)
            backgroundLayer.transform = targetTransform
            backgroundLayer.opacity = 1
            backgroundLayer.shadowOpacity = targetShadowOpacity
            backgroundLayer.shadowRadius = targetShadowRadius
            backgroundLayer.shadowOffset = targetShadowOffset
            CATransaction.commit()

            let overshootTransform = pdfFindTransform(
                scaleX: PDF_FIND_APPEAR_OVERSHOOT_SCALE_X,
                scaleY: PDF_FIND_APPEAR_OVERSHOOT_SCALE_Y,
                yOffset: PDF_FIND_APPEAR_OVERSHOOT_Y_OFFSET
            )
            let transformValues: [Any] = [
                NSValue(caTransform3D: startTransform),
                NSValue(caTransform3D: overshootTransform),
                NSValue(caTransform3D: targetTransform)
            ]
            let transformTimes: [NSNumber] = [
                0,
                NSNumber(value: Double(PDF_FIND_APPEAR_OVERSHOOT_TIME)),
                1
            ]
            addKeyframeAnimation(
                backgroundLayer,
                keyPath: "transform",
                values: transformValues,
                keyTimes: transformTimes,
                duration: PDF_FIND_APPEAR_DURATION,
                timingFunctions: [
                    CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                    CAMediaTimingFunction(controlPoints: 0.2, 0.8, 0.2, 1.0)
                ],
                key: "pdfFindTransform"
            )

            let opacityValues: [NSNumber] = [
                NSNumber(value: Double(startOpacity)),
                1,
                1
            ]
            let opacityTimes: [NSNumber] = [
                0,
                NSNumber(value: Double(PDF_FIND_OPACITY_RAMP_TIME)),
                1
            ]
            addKeyframeAnimation(
                backgroundLayer,
                keyPath: "opacity",
                values: opacityValues,
                keyTimes: opacityTimes,
                duration: PDF_FIND_APPEAR_DURATION,
                timingFunctions: [
                    CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                    CAMediaTimingFunction(controlPoints: 0.2, 0.8, 0.2, 1.0)
                ],
                key: "pdfFindOpacity"
            )

            let shadowOpacityValues: [NSNumber] = [
                NSNumber(value: Double(startShadowOpacity)),
                NSNumber(value: Double(targetShadowOpacity)),
                NSNumber(value: Double(targetShadowOpacity))
            ]
            addKeyframeAnimation(
                backgroundLayer,
                keyPath: "shadowOpacity",
                values: shadowOpacityValues,
                keyTimes: opacityTimes,
                duration: PDF_FIND_APPEAR_DURATION,
                timingFunctions: [
                    CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                    CAMediaTimingFunction(controlPoints: 0.2, 0.8, 0.2, 1.0)
                ],
                key: "pdfFindShadowOpacity"
            )

            let shadowRadiusValues: [NSNumber] = [
                NSNumber(value: Double(startShadowRadius)),
                NSNumber(value: Double(targetShadowRadius)),
                NSNumber(value: Double(targetShadowRadius))
            ]
            addKeyframeAnimation(
                backgroundLayer,
                keyPath: "shadowRadius",
                values: shadowRadiusValues,
                keyTimes: opacityTimes,
                duration: PDF_FIND_APPEAR_DURATION,
                timingFunctions: [
                    CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                    CAMediaTimingFunction(controlPoints: 0.2, 0.8, 0.2, 1.0)
                ],
                key: "pdfFindShadowRadius"
            )

            if let contentLayer {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                contentLayer.transform = targetTransform
                contentLayer.opacity = 1
                CATransaction.commit()

                let contentTransformValues: [Any] = [
                    NSValue(caTransform3D: startTransform),
                    NSValue(caTransform3D: overshootTransform),
                    NSValue(caTransform3D: targetTransform)
                ]
                addKeyframeAnimation(
                    contentLayer,
                    keyPath: "transform",
                    values: contentTransformValues,
                    keyTimes: transformTimes,
                    duration: PDF_FIND_APPEAR_DURATION,
                    timingFunctions: [
                        CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                        CAMediaTimingFunction(controlPoints: 0.2, 0.8, 0.2, 1.0)
                    ],
                    key: "pdfFindContentTransform"
                )

                let contentOpacityValues: [NSNumber] = [
                    NSNumber(value: Double(startOpacity)),
                    1,
                    1
                ]
                addKeyframeAnimation(
                    contentLayer,
                    keyPath: "opacity",
                    values: contentOpacityValues,
                    keyTimes: opacityTimes,
                    duration: PDF_FIND_APPEAR_DURATION,
                    timingFunctions: [
                        CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                        CAMediaTimingFunction(controlPoints: 0.2, 0.8, 0.2, 1.0)
                    ],
                    key: "pdfFindContentOpacity"
                )
            }

            let depthWorkItem = DispatchWorkItem { [weak self] in
                self?.updatePDFFindDepth(animated: true)
            }
            pdfFindDepthWorkItem = depthWorkItem
            DispatchQueue.main.asyncAfter(deadline: .now() + PDF_FIND_APPEAR_DURATION, execute: depthWorkItem)
        } else {
            guard !pdfFindHUD.isHidden else { return }

            let currentTransform = liveTransform
            let currentOpacity = liveOpacity
            let currentShadowOpacity = liveShadowOpacity
            let currentShadowRadius = liveShadowRadius
            let endTransform = pdfFindHiddenTransform()

            if reduce {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                backgroundLayer.transform = currentTransform
                backgroundLayer.opacity = currentOpacity
                backgroundLayer.shadowOpacity = currentShadowOpacity
                backgroundLayer.shadowRadius = currentShadowRadius
                backgroundLayer.shadowOffset = liveShadowOffset
                CATransaction.commit()

                animateLayer(backgroundLayer, keyPath: "transform", to: endTransform, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                animateLayer(backgroundLayer, keyPath: "opacity", to: 0, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                animateLayer(backgroundLayer, keyPath: "shadowOpacity", to: 0, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                animateLayer(backgroundLayer, keyPath: "shadowRadius", to: 0, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                if let contentLayer {
                    CATransaction.begin()
                    CATransaction.setDisableActions(true)
                    contentLayer.transform = currentTransform
                    contentLayer.opacity = currentOpacity
                    CATransaction.commit()
                    animateLayer(contentLayer, keyPath: "transform", to: endTransform, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                    animateLayer(contentLayer, keyPath: "opacity", to: 0, preset: .crisp, reduceMotion: true, basicDuration: 0.16)
                }
                let workItem = DispatchWorkItem { [weak self] in
                    self?.pdfFindHUD.isHidden = true
                }
                pdfFindVisibilityWorkItem = workItem
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.18, execute: workItem)
                return
            }

            CATransaction.begin()
            CATransaction.setDisableActions(true)
            backgroundLayer.transform = endTransform
            backgroundLayer.opacity = 0
            backgroundLayer.shadowOpacity = 0
            backgroundLayer.shadowRadius = 0
            backgroundLayer.shadowOffset = .zero
            CATransaction.commit()

            let tensionTransform = pdfFindTransform(
                scaleX: PDF_FIND_DISMISS_TENSION_SCALE_X,
                scaleY: PDF_FIND_DISMISS_TENSION_SCALE_Y,
                yOffset: PDF_FIND_DISMISS_TENSION_Y_OFFSET
            )
            let overshootTransform = pdfFindTransform(
                scaleX: PDF_FIND_DISMISS_OVERSHOOT_SCALE_X,
                scaleY: PDF_FIND_DISMISS_OVERSHOOT_SCALE_Y,
                yOffset: PDF_FIND_DISMISS_OVERSHOOT_Y_OFFSET
            )

            let transformValues: [Any]
            let transformTimes: [NSNumber]
            let transformTiming: [CAMediaTimingFunction]

            if currentOpacity < 0.4 {
                transformValues = [
                    NSValue(caTransform3D: currentTransform),
                    NSValue(caTransform3D: endTransform)
                ]
                transformTimes = [0, 1]
                transformTiming = [
                    CAMediaTimingFunction(controlPoints: 0.3, 0.1, 0.2, 1.0)
                ]
            } else {
                transformValues = [
                    NSValue(caTransform3D: currentTransform),
                    NSValue(caTransform3D: tensionTransform),
                    NSValue(caTransform3D: overshootTransform),
                    NSValue(caTransform3D: endTransform)
                ]
                transformTimes = [
                    0,
                    NSNumber(value: Double(PDF_FIND_DISMISS_TENSION_TIME)),
                    NSNumber(value: Double(PDF_FIND_DISMISS_OVERSHOOT_TIME)),
                    1
                ]
                transformTiming = [
                    CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                    CAMediaTimingFunction(controlPoints: 0.2, 0.1, 0.2, 1.0),
                    CAMediaTimingFunction(controlPoints: 0.2, 0.6, 0.2, 1.0)
                ]
            }

            addKeyframeAnimation(
                backgroundLayer,
                keyPath: "transform",
                values: transformValues,
                keyTimes: transformTimes,
                duration: PDF_FIND_DISMISS_DURATION,
                timingFunctions: transformTiming,
                key: "pdfFindTransform"
            )

            let opacityValues: [NSNumber] = [
                NSNumber(value: Double(currentOpacity)),
                0.5,
                0
            ]
            let opacityTimes: [NSNumber] = [
                0,
                NSNumber(value: Double(PDF_FIND_DISMISS_TENSION_TIME)),
                1
            ]
            addKeyframeAnimation(
                backgroundLayer,
                keyPath: "opacity",
                values: opacityValues,
                keyTimes: opacityTimes,
                duration: PDF_FIND_DISMISS_DURATION,
                timingFunctions: [
                    CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                    CAMediaTimingFunction(controlPoints: 0.2, 0.1, 0.2, 1.0)
                ],
                key: "pdfFindOpacity"
            )

            let shadowOpacityValues: [NSNumber] = [
                NSNumber(value: Double(currentShadowOpacity)),
                0,
                0
            ]
            addKeyframeAnimation(
                backgroundLayer,
                keyPath: "shadowOpacity",
                values: shadowOpacityValues,
                keyTimes: opacityTimes,
                duration: PDF_FIND_DISMISS_DURATION,
                timingFunctions: [
                    CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                    CAMediaTimingFunction(controlPoints: 0.2, 0.1, 0.2, 1.0)
                ],
                key: "pdfFindShadowOpacity"
            )

            let shadowRadiusValues: [NSNumber] = [
                NSNumber(value: Double(currentShadowRadius)),
                0,
                0
            ]
            addKeyframeAnimation(
                backgroundLayer,
                keyPath: "shadowRadius",
                values: shadowRadiusValues,
                keyTimes: opacityTimes,
                duration: PDF_FIND_DISMISS_DURATION,
                timingFunctions: [
                    CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                    CAMediaTimingFunction(controlPoints: 0.2, 0.1, 0.2, 1.0)
                ],
                key: "pdfFindShadowRadius"
            )

            if let contentLayer {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                contentLayer.opacity = 0
                CATransaction.commit()
                addKeyframeAnimation(
                    contentLayer,
                    keyPath: "transform",
                    values: transformValues,
                    keyTimes: transformTimes,
                    duration: PDF_FIND_DISMISS_DURATION,
                    timingFunctions: transformTiming,
                    key: "pdfFindContentTransform"
                )
                addKeyframeAnimation(
                    contentLayer,
                    keyPath: "opacity",
                    values: opacityValues,
                    keyTimes: opacityTimes,
                    duration: PDF_FIND_DISMISS_DURATION,
                    timingFunctions: [
                        CAMediaTimingFunction(controlPoints: 0.2, 0.9, 0.2, 1.0),
                        CAMediaTimingFunction(controlPoints: 0.2, 0.1, 0.2, 1.0)
                    ],
                    key: "pdfFindContentOpacity"
                )
            }

            let workItem = DispatchWorkItem { [weak self] in
                guard let self else { return }
                self.pdfFindHUD.isHidden = true
                if let layer = self.pdfFindBackgroundView.layer {
                    CATransaction.begin()
                    CATransaction.setDisableActions(true)
                    layer.transform = targetTransform
                    layer.opacity = 1
                    layer.shadowOpacity = targetShadowOpacity
                    layer.shadowRadius = targetShadowRadius
                    layer.shadowOffset = targetShadowOffset
                    CATransaction.commit()
                }
            }
            pdfFindVisibilityWorkItem = workItem
            DispatchQueue.main.asyncAfter(deadline: .now() + PDF_FIND_DISMISS_DURATION, execute: workItem)
        }
    }

    private func layoutSearchContainer(ensureLayout: Bool = true) {
        guard let root = searchContainer.superview else { return }
        if ensureLayout {
            root.layoutSubtreeIfNeeded()
            splitView.layoutSubtreeIfNeeded()
        }

        let sidebarShown = !isSidebarEffectivelyCollapsed()
        searchContainer.isHidden = !sidebarShown
        if !sidebarShown {
            if suggestionsVisible || !suggestionsContainer.isHidden {
                setSuggestionsVisible(false, animated: false)
            }
            layoutHeaderControls(ensureLayout: ensureLayout)
            return
        }

        let leftFrameInRoot = leftContainer.convert(leftContainer.bounds, to: root)

        // Inset the search glass so the leftContainer reads as a bezel behind it.
        let insetX: CGFloat = PANEL_INSET
        let contentWidth = max(0, leftFrameInRoot.width - (2 * insetX))
        let x = leftFrameInRoot.minX + insetX
        let y = leftFrameInRoot.maxY - PANEL_INSET - searchContainerHeight
        searchContainer.frame = NSRect(x: x, y: y, width: contentWidth, height: searchContainerHeight)
        if ensureLayout {
            searchContainer.layoutSubtreeIfNeeded()
        }
        updateSearchContainerAnchor()
        updateSearchContainerClip()
        if ensureLayout {
            updateSearchCapsuleGeometry()
            if !suggestionsContainer.isHidden && !suggestions.isEmpty {
                layoutSuggestionsDropdown()
            }
        }
        layoutHeaderControls(ensureLayout: ensureLayout)
    }

    private func updateSearchContainerClip() {
        guard let root = searchContainer.superview,
              let layer = searchContainer.layer else { return }

        let leftFrameInRoot = leftContainer.convert(leftContainer.bounds, to: root)
        let searchFrameInRoot = searchContainer.frame
        let clipInRoot = searchFrameInRoot.intersection(leftFrameInRoot)
        let clipInSearch: NSRect
        if clipInRoot.isNull || clipInRoot.isEmpty {
            clipInSearch = .zero
        } else {
            clipInSearch = searchContainer.convert(clipInRoot, from: root)
        }

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        searchContainerClipLayer.frame = searchContainer.bounds
        searchContainerClipLayer.path = CGPath(rect: clipInSearch, transform: nil)
        layer.mask = searchContainerClipLayer
        CATransaction.commit()
    }

    private func layoutHeaderControls(ensureLayout: Bool = true) {
        guard let root = headerControlsContainer.superview else { return }
        if ensureLayout {
            root.layoutSubtreeIfNeeded()
        }

        var size = toolbarControls.fittingSize
        if !size.width.isFinite || size.width <= 0 {
            size.width = max(0, root.bounds.width - WINDOW_BEZEL_INSET * 2)
        } else {
            let availableWidth = max(0, root.bounds.width - WINDOW_BEZEL_INSET * 2)
            if availableWidth > 0 {
                size.width = min(size.width, availableWidth)
            }
        }
        let x = root.bounds.minX + WINDOW_BEZEL_INSET
        var frame = NSRect(x: x,
                           y: root.bounds.maxY - headerControlsTopInset - size.height,
                           width: size.width,
                           height: size.height)
        frame = pixelAlignedRect(frame, in: root)

        let freezeVertical = dividerDragActive
        if freezeVertical {
            if cachedHeaderControlsFrameValid, cachedHeaderControlsFrame.height > 0 {
                frame.origin.y = cachedHeaderControlsFrame.origin.y
                frame.size.height = cachedHeaderControlsFrame.size.height
            } else {
                cachedHeaderControlsFrame = frame
                cachedHeaderControlsFrameValid = true
            }
        } else {
            cachedHeaderControlsFrame = frame
            cachedHeaderControlsFrameValid = true
        }

        headerControlsContainer.frame = frame
        if ensureLayout {
            headerControlsContainer.layoutSubtreeIfNeeded()
        }
        layoutRightPanelPillControl(in: root)
        if !menuContainer.isHidden {
            layoutMenuPanel()
        }
    }

    private func layoutRightPanelPillControl(in root: NSView) {
        let rightFrameInRoot = rightPanelPrimaryFrame(in: root)
        let inset: CGFloat = 12
        let availableWidth = max(0, rightFrameInRoot.width - (2 * inset))
        guard availableWidth > 24 else {
            rightPanelPillControl.isHidden = true
            if !appleIntelligenceToast.isHidden {
                layoutAppleIntelligenceToast()
            }
            return
        }

        rightPanelPillControl.isHidden = false
        let baseHeight = toolbarControlHeight > 0 ? toolbarControlHeight : (32 * toolbarControlScaleCurrent)
        let baseScaleCap: CGFloat = 1.15
        let baseScale = max(0.86, min(baseScaleCap, rightFrameInRoot.width / 720))
        let panelScale = panelClosedPillScale()
        rightPanelPillControl.setCollapsedCapsuleHeightScale(1.0 / max(1.0, panelScale))
        rightPanelPillControl.setEdgeThicknessScale(panelScale)
        let scale = baseScale * panelScale
        let height = baseHeight * scale
        let minWidth = height * 4.4
        let maxWidth = height * 8.0
        let targetWidth = min(rightFrameInRoot.width * 0.6, maxWidth)
        let width = min(availableWidth, max(minWidth, targetWidth))
        // Keep the pill horizontally centered on the viewer (PDF or HTML). When the sidebar
        // is collapsed, center on the full window instead.
        let centerX = desiredPillCenterX(in: root, rightFrameInRoot: rightFrameInRoot)
        let x = centerX - (width / 2)
        let y = headerControlsContainer.frame.midY - (height / 2)
        var alignedFrame = pixelAlignedRect(NSRect(x: x, y: y, width: width, height: height), in: root)

        // Keep the pill from covering header controls (especially the sidebar button) in narrow layouts.
        let headerFrame = headerControlsContainer.frame.insetBy(dx: -8, dy: -4)
        if alignedFrame.intersects(headerFrame) {
            let clearance: CGFloat = 8
            let safeLeft = headerFrame.maxX + clearance
            let safeRight = rightFrameInRoot.maxX - inset
            let maxPillWidth = max(0, safeRight - safeLeft)
            guard maxPillWidth >= minWidth else {
                rightPanelPillControl.isHidden = true
                return
            }
            alignedFrame.size.width = min(alignedFrame.size.width, maxPillWidth)
            alignedFrame.origin.x = min(max(alignedFrame.origin.x, safeLeft),
                                        safeRight - alignedFrame.size.width)
            alignedFrame = pixelAlignedRect(alignedFrame, in: root)
        }

        rightPanelPillControl.frame = alignedFrame
        rightPanelPillControl.needsLayout = true
        // Important: if the pill moves under a stationary cursor (e.g. after opening the
        // Annotations panel), AppKit won't send a new mouseEntered. Re-sync hover now.
        rightPanelPillControl.syncHoverFromCurrentMouseLocation(animated: !disablePillToolbarAnimations)
        if !appleIntelligenceToast.isHidden {
            layoutAppleIntelligenceToast()
        }
        layoutRightPanelEdgeButtons(in: root)
        refreshHoverTooltipLayoutIfNeeded()
    }

    private func layoutRightPanelEdgeButtons(in root: NSView) {
        guard let leftGlass = rightPanelLeftEdgeButtonBackground,
              let zoteroGlass = rightPanelZoteroEdgeButtonBackground,
              let rightGlass = rightPanelRightEdgeButtonBackground,
              let settingsGlass = rightPanelSettingsEdgeButtonBackground else {
            return
        }
        defer { updateRightPanelPillCircleInsets() }

        func setEdgeButtonsHidden(_ hidden: Bool) {
            leftGlass.isHidden = hidden
            zoteroGlass.isHidden = hidden
            rightGlass.isHidden = hidden
            settingsGlass.isHidden = hidden
            rightPanelLeftEdgeButton.isHidden = hidden
            rightPanelZoteroEdgeButton.isHidden = hidden
            rightPanelRightEdgeButton.isHidden = hidden
            rightPanelSettingsEdgeButton.isHidden = hidden
        }

        let rightFrameInRoot = rightPanelPrimaryFrame(in: root)
        guard rightFrameInRoot.width.isFinite, rightFrameInRoot.height.isFinite, rightFrameInRoot.width > 1 else {
            rightPanelEdgeButtonsVisibilityInitialized = false
            setEdgeButtonsHidden(true)
            return
        }

        let buttonHeight = toolbarControlHeight > 0 ? toolbarControlHeight : (32 * toolbarControlScaleCurrent)
        let buttonWidth: CGFloat = max(toolbarMinHitSize, 30 * toolbarControlScaleCurrent)
        let horizontalInset: CGFloat = 6
        // Two-button cluster on the left (Share + Settings) and two-button cluster on the right (Zotero + panel toggle).
        let requiredWidth = (4 * buttonWidth) + (4 * horizontalInset)

        let navFrameInRoot = navControlContainer.convert(navControlContainer.bounds, to: root)
        let computedToolbarMaxX = (navFrameInRoot.width > 1 && navFrameInRoot.maxX.isFinite)
            ? navFrameInRoot.maxX
            : headerControlsContainer.frame.maxX
        let freezeLayout = dividerDragActive
            || rightSplitDividerDragActive
            || sidebarTransitionInProgress
            || rightAuxTransitionInProgress
        let toolbarMaxX: CGFloat
        if freezeLayout {
            if !rightPanelEdgeButtonsToolbarMaxXCacheValid {
                rightPanelEdgeButtonsToolbarMaxXCache = computedToolbarMaxX
                rightPanelEdgeButtonsToolbarMaxXCacheValid = true
            }
            toolbarMaxX = rightPanelEdgeButtonsToolbarMaxXCache
        } else {
            toolbarMaxX = computedToolbarMaxX
            rightPanelEdgeButtonsToolbarMaxXCache = toolbarMaxX
            rightPanelEdgeButtonsToolbarMaxXCacheValid = true
        }

        let centerY = headerControlsContainer.frame.midY
        let buttonY = centerY - (buttonHeight / 2)
        // Keep the leftmost right-panel edge button to the right of the back/forward cluster.
        let minLeftX = toolbarMaxX + minToolbarEdgeButtonGap
        let leftX = max(rightFrameInRoot.minX + horizontalInset, minLeftX)
        let middleX = leftX + buttonWidth + horizontalInset
        let rightX = rightFrameInRoot.maxX - horizontalInset - buttonWidth
        let zoteroX = rightX - buttonWidth - horizontalInset

        let widthDelta = rightFrameInRoot.width - requiredWidth
        let overlapGap = (zoteroX - horizontalInset) - middleX

        let freezeVisibility = freezeLayout || (window?.inLiveResize == true)
        let shouldRecomputeVisibility = !freezeVisibility || !rightPanelEdgeButtonsVisibilityInitialized
        if shouldRecomputeVisibility {
            if !rightPanelEdgeButtonsVisibilityInitialized {
                rightPanelEdgeButtonsVisibleCache = (widthDelta >= 0 && overlapGap >= 0)
                rightPanelEdgeButtonsVisibilityInitialized = true
            } else if rightPanelEdgeButtonsVisibleCache {
                if widthDelta < -rightPanelEdgeButtonsVisibilityHysteresis
                    || overlapGap < -rightPanelEdgeButtonsOverlapHysteresis {
                    rightPanelEdgeButtonsVisibleCache = false
                }
            } else {
                if widthDelta > rightPanelEdgeButtonsVisibilityHysteresis
                    && overlapGap > rightPanelEdgeButtonsOverlapHysteresis {
                    rightPanelEdgeButtonsVisibleCache = true
                }
            }
        }

        guard rightPanelEdgeButtonsVisibleCache else {
            setEdgeButtonsHidden(true)
            return
        }

        // Keep the panel toggle on the far right; keep Share on the left edge, with Settings immediately to its right.
        // NOTE: Existing naming is historical: `rightPanelRightEdgeButton` is the Share button.
        let shareFrame = pixelAlignedRect(NSRect(x: leftX, y: buttonY, width: buttonWidth, height: buttonHeight), in: root)
        let settingsFrame = pixelAlignedRect(NSRect(x: middleX, y: buttonY, width: buttonWidth, height: buttonHeight), in: root)
        let zoteroFrame = pixelAlignedRect(NSRect(x: zoteroX, y: buttonY, width: buttonWidth, height: buttonHeight), in: root)
        let toggleFrame = pixelAlignedRect(NSRect(x: rightX, y: buttonY, width: buttonWidth, height: buttonHeight), in: root)

        leftGlass.frame = toggleFrame
        zoteroGlass.frame = zoteroFrame
        rightGlass.frame = shareFrame
        settingsGlass.frame = settingsFrame
        rightPanelLeftEdgeButton.frame = toggleFrame
        rightPanelZoteroEdgeButton.frame = zoteroFrame
        rightPanelRightEdgeButton.frame = shareFrame
        rightPanelSettingsEdgeButton.frame = settingsFrame
        setEdgeButtonsHidden(false)

        let cornerRadius = shareFrame.height / 2
        leftGlass.wantsLayer = true
        zoteroGlass.wantsLayer = true
        rightGlass.wantsLayer = true
        settingsGlass.wantsLayer = true
        leftGlass.layer?.cornerRadius = cornerRadius
        zoteroGlass.layer?.cornerRadius = cornerRadius
        rightGlass.layer?.cornerRadius = cornerRadius
        settingsGlass.layer?.cornerRadius = cornerRadius
        if #available(macOS 10.13, *) {
            leftGlass.layer?.cornerCurve = .continuous
            zoteroGlass.layer?.cornerCurve = .continuous
            rightGlass.layer?.cornerCurve = .continuous
            settingsGlass.layer?.cornerCurve = .continuous
        }

        if #available(macOS 26.0, *) {
            (leftGlass as? NSGlassEffectView)?.cornerRadius = cornerRadius
            (zoteroGlass as? NSGlassEffectView)?.cornerRadius = cornerRadius
            (rightGlass as? NSGlassEffectView)?.cornerRadius = cornerRadius
            (settingsGlass as? NSGlassEffectView)?.cornerRadius = cornerRadius
        }
        rightPanelLeftEdgeButton.setCornerRadius(cornerRadius)
        rightPanelZoteroEdgeButton.setCornerRadius(cornerRadius)
        rightPanelRightEdgeButton.setCornerRadius(cornerRadius)
        rightPanelSettingsEdgeButton.setCornerRadius(cornerRadius)

        // Match the pill outline token for the edge buttons.
        updateToolbarEdgeButtonBorders()
        rightPanelLeftEdgeButton.needsLayout = true
        rightPanelZoteroEdgeButton.needsLayout = true
        rightPanelRightEdgeButton.needsLayout = true
        rightPanelSettingsEdgeButton.needsLayout = true
    }

    private func updateRightPanelPillCircleInsets() {
        guard rightPanelPillControl.isHidden == false else {
            rightPanelPillControl.setExpandedCircleInsets(left: 0, right: 0)
            return
        }

        let pillFrame = rightPanelPillControl.frame
        guard pillFrame.width.isFinite, pillFrame.width > 1 else {
            rightPanelPillControl.setExpandedCircleInsets(left: 0, right: 0)
            return
        }

        let baseGap = minToolbarGap
        let scale = currentBackingScale()
        let buttonHeight = toolbarControlHeight > 0 ? toolbarControlHeight : (32 * toolbarControlScaleCurrent)
        let buttonWidth: CGFloat = max(toolbarMinHitSize, 30 * toolbarControlScaleCurrent)
        let effectiveMinGap = max(baseGap, ceilToDevicePixels(buttonWidth * 0.38, scale: scale))

        let leftVisible = rightPanelSettingsEdgeButton.isHidden == false
        let rightVisible = rightPanelZoteroEdgeButton.isHidden == false
        guard leftVisible || rightVisible else {
            rightPanelPillControl.setExpandedCircleInsets(left: 0, right: 0)
            return
        }

        let baseMask = rightPanelPillControl.expandedMaskBounds(forLeftInset: 0, rightInset: 0)
        let baseLeftEdge = pillFrame.minX + baseMask.minX
        let baseRightEdge = pillFrame.minX + baseMask.maxX

        let naturalLeftGap = leftVisible ? (baseLeftEdge - rightPanelSettingsEdgeButton.frame.maxX) : CGFloat.greatestFiniteMagnitude
        let naturalRightGap = rightVisible ? (rightPanelZoteroEdgeButton.frame.minX - baseRightEdge) : CGFloat.greatestFiniteMagnitude

        var desiredGap = effectiveMinGap
        if leftVisible { desiredGap = max(desiredGap, naturalLeftGap) }
        if rightVisible { desiredGap = max(desiredGap, naturalRightGap) }

        let desiredLeftGap = leftVisible ? desiredGap : effectiveMinGap
        let desiredRightGap = rightVisible ? desiredGap : effectiveMinGap

        var insetLeftNeeded: CGFloat = 0
        if leftVisible {
            let targetLeftEdgeLocal = (rightPanelSettingsEdgeButton.frame.maxX + desiredLeftGap) - pillFrame.minX
            let needed = max(0, targetLeftEdgeLocal - baseMask.minX)
            insetLeftNeeded = ceilToDevicePixels(needed, scale: scale)
        }

        var insetRightNeeded: CGFloat = 0
        if rightVisible {
            let targetRightEdgeLocal = (rightPanelZoteroEdgeButton.frame.minX - desiredRightGap) - pillFrame.minX
            let needed = max(0, baseMask.maxX - targetRightEdgeLocal)
            insetRightNeeded = ceilToDevicePixels(needed, scale: scale)
        }

        // Keep the circular buttons centered on the pill by enforcing symmetric insets.
        // Clamp to a minimum circle size so we avoid overly tiny buttons in tight layouts.
        let maxInset = max(0, (rightPanelPillControl.bounds.width / 2) - 1)
        let symmetricInset = min(maxInset, max(insetLeftNeeded, insetRightNeeded))
        let minCircleDiameter = max(22, buttonHeight)
        let maxInsetForMinSize = rightPanelPillControl.maxSymmetricInset(forMinimumCircleDiameter: minCircleDiameter)
        let clampedInset = min(symmetricInset, maxInsetForMinSize)

        rightPanelPillControl.setExpandedCircleInsets(left: clampedInset, right: clampedInset)
    }

    private func desiredPillCenterX(in root: NSView, rightFrameInRoot: NSRect) -> CGFloat {
        if isShowingPDF, pdfView.isHidden == false, pdfView.window === root.window {
            let f = pdfView.convert(pdfView.bounds, to: root)
            if f.isEmpty == false { return f.midX }
        }
        if detailsWebView.isHidden == false, detailsWebView.window === root.window {
            let f = detailsWebView.convert(detailsWebView.bounds, to: root)
            if f.isEmpty == false { return f.midX }
        }
        return rightFrameInRoot.midX
    }

    // Panel-visibility-only progress used to scale the pill container for circle size.
    private func panelClosedPillScaleProgress() -> CGFloat {
        let panelsClosed = (!sidebarVisible && !rightAuxPanelVisible)
        if !sidebarTransitionInProgress && !rightAuxTransitionInProgress {
            return panelsClosed ? 1.0 : 0.0
        }

        func collapseProgress(currentWidth: CGFloat, referenceWidth: CGFloat, track: Bool) -> CGFloat {
            guard track else { return 0 }
            let ref = max(1, referenceWidth)
            let clamped = max(0, min(ref, currentWidth))
            return 1.0 - (clamped / ref)
        }

        let leftTrack = !sidebarVisible || sidebarTransitionInProgress
        let leftProgress = collapseProgress(currentWidth: leftContainer.frame.width,
                                            referenceWidth: lastSidebarWidth,
                                            track: leftTrack)

        let rightReference = max(1, max(lastRightAuxPanelWidth, rightAuxMinWidthAllowable()))
        let rightTrack = !rightAuxPanelVisible || rightAuxTransitionInProgress
        let rightProgress = collapseProgress(currentWidth: rightAuxContainer.frame.width,
                                             referenceWidth: rightReference,
                                             track: rightTrack)

        let progress = min(leftProgress, rightProgress)
        return smoothstep01(progress)
    }

    private func panelClosedPillScale() -> CGFloat {
        1.0 + ((panelClosedPillScaleMax - 1.0) * panelClosedPillScaleProgress())
    }

    func layoutViewerAnchoredHeaderControls(ensureLayout: Bool = true) {
        PerfLogger.begin("layout.header_controls")
        defer { PerfLogger.end("layout.header_controls") }
        let perfStart = perfDebugEnabled ? monotonicNowNs() : 0
        defer {
            if perfDebugEnabled {
                ResizeLatencyProbe.shared.markLayoutPass(name: "header_anchor_layout", durationNs: monotonicNowNs() &- perfStart)
            }
        }
        guard let root = headerControlsContainer.superview else { return }
        if ensureLayout {
            PerfLogger.measure("autolayout.header_controls.root") {
                root.layoutSubtreeIfNeeded()
            }
        }
        layoutRightPanelPillControl(in: root)
    }

    private func suggestionTitleMaxWidth() -> CGFloat {
        guard !suggestions.isEmpty else { return 0 }
        let titleAttrs: [NSAttributedString.Key: Any] = [.font: suggestionTitleFont]
        var maxWidth: CGFloat = 0
        for suggestion in suggestions {
            let titleWidth = (suggestion.title as NSString).size(withAttributes: titleAttrs).width
            if titleWidth > maxWidth { maxWidth = titleWidth }
        }
        // Include hover scale so padding stays symmetric when text bounces.
        let hoverScale = max(1.0, ROW_TEXT_HOVER_SCALE)
        return ceil(maxWidth * hoverScale)
    }

    private func pixelAlignedRect(_ rect: NSRect, in view: NSView) -> NSRect {
        let scale = max(1.0, view.window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0)
        let minX = round(rect.minX * scale) / scale
        let minY = round(rect.minY * scale) / scale
        let maxX = round(rect.maxX * scale) / scale
        let maxY = round(rect.maxY * scale) / scale
        return NSRect(x: minX, y: minY, width: max(0, maxX - minX), height: max(0, maxY - minY))
    }

    private func layoutSuggestionsDropdown(ensureLayout: Bool = true) {
        guard let root = searchContainer.superview else { return }
        if ensureLayout {
            root.layoutSubtreeIfNeeded()
        }

        let anchorFrame = searchContainer.convert(searchContainer.bounds, to: root)

        // Size the dropdown by the longest visible title string (plus padding/insets),
        // and keep it independent of the left panel width.
        let titleWidth = suggestionTitleMaxWidth()
        let innerWidth = titleWidth + (suggestionTextInsetX * 2)
        let insetWidth = suggestionsScroll.contentInsets.left + suggestionsScroll.contentInsets.right
        var width = max(anchorFrame.width, innerWidth + insetWidth)

        // Clamp within the root bounds so it never renders off-screen.
        let screenMargin: CGFloat = 6
        let maxWidth = max(1, root.bounds.width - (screenMargin * 2))
        width = min(width, maxWidth)

        // Left-align to the search bar, then clamp so the entire dropdown stays visible.
        var x = anchorFrame.minX
        x = max(root.bounds.minX + screenMargin, min(x, root.bounds.maxX - screenMargin - width))
        let maxRows = min(8, suggestions.count)
        let contentHeight = CGFloat(maxRows) * suggestionRowHeight + suggestionsScroll.contentInsets.top + suggestionsScroll.contentInsets.bottom
        let height = max(0, contentHeight)
        let y = anchorFrame.minY - 6 - height

        let alignedFrame = pixelAlignedRect(NSRect(x: x, y: y, width: width, height: height), in: root)
        suggestionsContainer.frame = alignedFrame
        suggestionsBackground.frame = suggestionsContainer.bounds
        suggestionsScroll.frame = suggestionsContainer.bounds
        suggestionsTable.frame = suggestionsScroll.bounds
        if let col = suggestionsTable.tableColumns.first {
            col.width = max(1, suggestionsScroll.contentSize.width)
        }

        if let layer = suggestionsContainer.layer {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.anchorPoint = CGPoint(x: 0.5, y: 1.0)
            layer.position = CGPoint(x: suggestionsContainer.frame.midX, y: suggestionsContainer.frame.maxY)
            CATransaction.commit()
        }
        updateSuggestionsShadow()
    }

    private func menuAnchorFrameInRoot(for anchor: NSView, root: NSView) -> NSRect {
        guard let anchorWindow = anchor.window,
              let rootWindow = root.window,
              anchorWindow === rootWindow else {
            return anchor.convert(anchor.bounds, to: root)
        }

        let frameInWindow = anchor.convert(anchor.bounds, to: nil)
        return root.convert(frameInWindow, from: nil)
    }

    private func menuAlignedX(anchorFrame: NSRect, width: CGFloat, rootBounds: NSRect) -> CGFloat {
        let targetX = anchorFrame.minX + menuAnchorInsetX
        let minX = rootBounds.minX + PANEL_INSET
        let maxX = max(minX, rootBounds.maxX - width - PANEL_INSET)
        return min(maxX, max(minX, targetX))
    }

    private func layoutMenuPanel() {
        guard let root = menuContainer.superview,
              let anchor = menuAnchorView else { return }
        root.layoutSubtreeIfNeeded()

        let anchorFrame = menuAnchorFrameInRoot(for: anchor, root: root)
        let maxWidth = max(1, root.bounds.width - (2 * PANEL_INSET))
        let width = min(menuPreferredWidth(for: menuItems, anchorWidth: anchorFrame.width), maxWidth)
        let rowsHeight = menuItems.enumerated().reduce(CGFloat(0)) { partial, entry in
            let rowHeight = tableView(menuTable, heightOfRow: entry.offset)
            return partial + rowHeight
        }
        let height = max(1, rowsHeight + menuContentInsets.top + menuContentInsets.bottom)
        let x = menuAlignedX(anchorFrame: anchorFrame, width: width, rootBounds: root.bounds)

        let minY = PANEL_INSET
        let maxY = max(minY, root.bounds.height - height - PANEL_INSET)
        let belowY = anchorFrame.minY - menuVerticalGap - height
        let aboveY = anchorFrame.maxY + menuVerticalGap
        let fitsBelow = belowY >= minY
        let fitsAbove = aboveY <= maxY
        let y: CGFloat
        if fitsBelow || !fitsAbove {
            menuOpensUpward = false
            y = max(minY, min(maxY, belowY))
        } else {
            menuOpensUpward = true
            y = max(minY, min(maxY, aboveY))
        }

        menuContainer.frame = NSRect(x: x, y: y, width: width, height: height)
        menuBackground.frame = menuContainer.bounds
        menuScroll.frame = menuContainer.bounds
        let menuContentWidth = max(1, menuScroll.bounds.width - menuContentInsets.left - menuContentInsets.right)
        let tableOriginY = menuTable.isFlipped ? menuContentInsets.top : menuContentInsets.bottom
        menuTable.frame = NSRect(x: menuContentInsets.left,
                                 y: tableOriginY,
                                 width: menuContentWidth,
                                 height: rowsHeight)
        if let col = menuTable.tableColumns.first {
            col.width = max(1, menuContentWidth)
        }

        if let layer = menuContainer.layer {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.anchorPoint = CGPoint(x: 0.5, y: menuOpensUpward ? 0.0 : 1.0)
            layer.position = CGPoint(x: menuContainer.frame.midX,
                                     y: menuOpensUpward ? menuContainer.frame.minY : menuContainer.frame.maxY)
            CATransaction.commit()
        }

        menuShield.frame = root.bounds
        updateMenuShadow()
    }

    private func updateDropdownShadow(for container: NSView, offset overrideOffset: CGSize? = nil) {
        guard let layer = container.layer else { return }
        let dark = window?.effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        let active = isWindowActiveForAppearance()
        let opacity: Float = dark ? (active ? 0.34 : 0.24) : (active ? 0.24 : 0.18)
        let radius: CGFloat = dark ? 18 : 16
        let offset = overrideOffset ?? CGSize(width: 0, height: -3)
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer.cornerRadius = menuCornerRadius
        layer.masksToBounds = false
        layer.shadowColor = NSColor.black.cgColor
        layer.shadowOpacity = opacity
        layer.shadowRadius = radius
        layer.shadowOffset = offset
        layer.shadowPath = CGPath(roundedRect: container.bounds,
                                  cornerWidth: menuCornerRadius,
                                  cornerHeight: menuCornerRadius,
                                  transform: nil)
        CATransaction.commit()
    }

    private func updateMenuShadow() {
        updateDropdownShadow(for: menuContainer)
    }

    private func updateSuggestionsShadow() {
        updateDropdownShadow(for: suggestionsContainer, offset: .zero)
    }

    private func setSuggestionsVisible(_ visible: Bool, animated: Bool) {
        let wasVisible = suggestionsVisible
        suggestionsVisibilityWorkItem?.cancel()
        suggestionsVisible = visible
        updateSearchDepth(animated: animated)

        guard let layer = suggestionsContainer.layer else {
            suggestionsContainer.isHidden = !visible
            return
        }

        if visible {
            // Always keep the dropdown on top if it overlaps other controls.
            if let root = suggestionsContainer.superview {
                root.addSubview(suggestionsContainer, positioned: .above, relativeTo: nil)
            }
            suggestionsContainer.layer?.zPosition = 10_000
            if wasVisible, !suggestionsContainer.isHidden {
                layoutSuggestionsDropdown()
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                layer.opacity = 1
                layer.transform = CATransform3DIdentity
                CATransaction.commit()
                updateSuggestionsShadow()
                return
            }
            suggestionsContainer.isHidden = false
            layoutSuggestionsDropdown()
            if let card = suggestionsBackground as? GlassCardView {
                card.invalidateGlass(reason: "suggestions_show")
            }
            let startTransform = CATransform3DTranslate(CATransform3DMakeScale(0.98, 0.98, 1.0), 0, -6, 0)
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.opacity = 0
            layer.transform = startTransform
            CATransaction.commit()
            animateLayer(layer, keyPath: "opacity", to: 1, preset: .crisp, reduceMotion: shouldReduceMotion || !animated, basicDuration: 0.16)
            animateLayer(layer, keyPath: "transform", to: CATransform3DIdentity, preset: .crisp, reduceMotion: shouldReduceMotion || !animated, basicDuration: 0.18)
        } else {
            if !wasVisible, suggestionsContainer.isHidden {
                return
            }
            suggestionsTable.deselectAll(nil)
            clearSuggestionHover(animated: false)
            refreshSuggestionTextColors()
            let endTransform = CATransform3DTranslate(CATransform3DMakeScale(0.98, 0.98, 1.0), 0, -6, 0)
            animateLayer(layer, keyPath: "opacity", to: 0, preset: .crisp, reduceMotion: shouldReduceMotion || !animated, basicDuration: 0.14)
            animateLayer(layer, keyPath: "transform", to: endTransform, preset: .crisp, reduceMotion: shouldReduceMotion || !animated, basicDuration: 0.16)
            let work = DispatchWorkItem { [weak self] in
                self?.suggestionsContainer.isHidden = true
            }
            suggestionsVisibilityWorkItem = work
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.16, execute: work)
        }
    }

    private func setMenuVisible(_ visible: Bool, animated: Bool) {
        menuVisibilityWorkItem?.cancel()
        menuShield.isHidden = !visible
        guard let layer = menuContainer.layer else {
            menuContainer.isHidden = !visible
            return
        }

        if visible {
            menuContainer.isHidden = false
            layoutMenuPanel()
            if let card = menuBackground as? GlassCardView {
                card.invalidateGlass(reason: "menu_show")
            }
            let yOffset: CGFloat = menuOpensUpward ? -6 : 6
            let startTransform = CATransform3DTranslate(CATransform3DMakeScale(0.98, 0.98, 1.0), 0, yOffset, 0)
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.opacity = 0
            layer.transform = startTransform
            CATransaction.commit()
            animateLayer(layer, keyPath: "opacity", to: 1, preset: .crisp, reduceMotion: shouldReduceMotion || !animated, basicDuration: 0.16)
            animateLayer(layer, keyPath: "transform", to: CATransform3DIdentity, preset: .microBounce, reduceMotion: shouldReduceMotion || !animated, basicDuration: 0.18)
        } else {
            hoveredMenuRow = nil
            let yOffset: CGFloat = menuOpensUpward ? -6 : 6
            let endTransform = CATransform3DTranslate(CATransform3DMakeScale(0.98, 0.98, 1.0), 0, yOffset, 0)
            animateLayer(layer, keyPath: "opacity", to: 0, preset: .crisp, reduceMotion: shouldReduceMotion || !animated, basicDuration: 0.14)
            animateLayer(layer, keyPath: "transform", to: endTransform, preset: .microBounce, reduceMotion: shouldReduceMotion || !animated, basicDuration: 0.16)
            let work = DispatchWorkItem { [weak self] in
                self?.menuContainer.isHidden = true
                self?.menuSelectionHandler = nil
                self?.menuAnchorView = nil
            }
            menuVisibilityWorkItem = work
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.16, execute: work)
        }
    }

    func layoutToolbarControls() {
        PerfLogger.begin("toolbar.layout_controls")
        defer { PerfLogger.end("toolbar.layout_controls") }
        applyLeftToolbarClusterAutoScaleIfNeeded()

        if ToolbarAutoScale.isEnabled {
            let btnSize = max(0, sidebarToggleWidthConstraint?.constant ?? (24 * leftToolbarControlScaleBase))
            let buttonRadius = max(0, btnSize / 2)
            sidebarToggleButton.setCornerRadius(buttonRadius, maskedCorners: [.layerMinXMinYCorner, .layerMinXMaxYCorner])
            sidebarMenuButton.setCornerRadius(buttonRadius, maskedCorners: [.layerMaxXMinYCorner, .layerMaxXMaxYCorner])
            backButton.setCornerRadius(buttonRadius, maskedCorners: [.layerMinXMinYCorner, .layerMinXMaxYCorner])
            forwardButton.setCornerRadius(buttonRadius, maskedCorners: [.layerMaxXMinYCorner, .layerMaxXMaxYCorner])

            let controlRadius: CGFloat = lockLeftToolbarClusterMetrics
                ? max(10, (32 * leftToolbarControlScaleBase) / 2)
                : (toolbarScaleLastApplied?.cornerRadius ?? max(10, navControlContainer.bounds.height / 2))
            sidebarControlBackground.wantsLayer = true
            sidebarControlBackground.layer?.cornerRadius = controlRadius
            if #available(macOS 10.13, *) {
                sidebarControlBackground.layer?.cornerCurve = .continuous
            }
            navControlBackground.wantsLayer = true
            navControlBackground.layer?.cornerRadius = controlRadius
            if #available(macOS 10.13, *) {
                navControlBackground.layer?.cornerCurve = .continuous
            }
        } else {
            // Respect resize-driven coupled corner radius when available.
            let radius: CGFloat = lockLeftToolbarClusterMetrics
                ? max(10, (32 * leftToolbarControlScaleBase) / 2)
                : (toolbarScaleLastApplied?.cornerRadius ?? max(10, sidebarControlContainer.bounds.height / 2))
            sidebarControlBackground.wantsLayer = true
            sidebarControlBackground.layer?.cornerRadius = radius
            if #available(macOS 10.13, *) {
                sidebarControlBackground.layer?.cornerCurve = .continuous
            }
            navControlBackground.wantsLayer = true
            navControlBackground.layer?.cornerRadius = radius
            if #available(macOS 10.13, *) {
                navControlBackground.layer?.cornerCurve = .continuous
            }
            sidebarToggleButton.setCornerRadius(radius, maskedCorners: [.layerMinXMinYCorner, .layerMinXMaxYCorner])
            sidebarMenuButton.setCornerRadius(radius, maskedCorners: [.layerMaxXMinYCorner, .layerMaxXMaxYCorner])
            backButton.setCornerRadius(radius, maskedCorners: [.layerMinXMinYCorner, .layerMinXMaxYCorner])
            forwardButton.setCornerRadius(radius, maskedCorners: [.layerMaxXMinYCorner, .layerMaxXMaxYCorner])
        }
        let edgeRadius: CGFloat
        if let metrics = toolbarScaleLastApplied {
            edgeRadius = max(0, metrics.controlHeight / 2)
        } else {
            edgeRadius = max(0, rightPanelLeftEdgeButton.bounds.height / 2)
        }
        if edgeRadius > 0 {
            rightPanelLeftEdgeButton.setCornerRadius(edgeRadius)
            rightPanelRightEdgeButton.setCornerRadius(edgeRadius)
            rightPanelLeftEdgeButtonBackground?.wantsLayer = true
            rightPanelRightEdgeButtonBackground?.wantsLayer = true
            rightPanelLeftEdgeButtonBackground?.layer?.cornerRadius = edgeRadius
            rightPanelRightEdgeButtonBackground?.layer?.cornerRadius = edgeRadius
            if #available(macOS 10.13, *) {
                rightPanelLeftEdgeButtonBackground?.layer?.cornerCurve = .continuous
                rightPanelRightEdgeButtonBackground?.layer?.cornerCurve = .continuous
            }
        }
    }

    private func applyLeftToolbarClusterAutoScaleIfNeeded() {
        guard !lockLeftToolbarClusterMetrics else { return }
        guard ToolbarAutoScale.isEnabled else { return }
        guard leftToolbarCluster.arrangedSubviews.count >= 2 else { return }
        let leftWidth = leftContainer.frame.width
        if !sidebarVisible || leftWidth <= 12 {
            if let last = leftToolbarAutoScaleLastApplied, last.buttonSize >= toolbarMinHitSize {
                applyLeftToolbarClusterAutoScale(result: last, force: false)
                return
            }
            let baseBtn = max(toolbarMinHitSize, 24 * leftToolbarControlScaleCurrent)
            let baseSymbolPt = max(11, 13 * leftToolbarControlScaleCurrent)
            let fallback = LeftToolbarClusterAutoScaleResult(
                spacing: toolbarBaseSpacing,
                navButtonWidth: baseBtn,
                buttonSize: baseBtn,
                symbolPointSize: baseSymbolPt
            )
            applyLeftToolbarClusterAutoScale(result: fallback, force: false)
            return
        }

        let availableWidth = max(0, leftWidth - leftToolbarAutoScaleSidePadding)
        let result = computeLeftToolbarClusterAutoScale(availableWidth: availableWidth)
        applyLeftToolbarClusterAutoScale(result: result, force: false)
    }

    private func smoothstep01(_ t: CGFloat) -> CGFloat {
        let x = max(0, min(1, t))
        return x * x * (3 - 2 * x)
    }

    private func computeLeftToolbarClusterAutoScale(availableWidth: CGFloat) -> LeftToolbarClusterAutoScaleResult {
        let w = max(0, availableWidth)
        let baseSpacing = toolbarBaseSpacing
        let minSpacing = toolbarMinSpacing

        let baseBtn: CGFloat = max(toolbarMinHitSize, 24 * leftToolbarControlScaleCurrent)
        let minBtn: CGFloat = toolbarMinHitSize

        let baseSymbolPt: CGFloat = max(11, 13 * leftToolbarControlScaleCurrent)
        let minSymbolPt: CGFloat = max(9, 11 * leftToolbarControlScaleCurrent)

        let fixedWidth = (2 * navDividerWidth) + (4 * navInset)

        func totalWidth(btn: CGFloat, spacing: CGFloat) -> CGFloat {
            (4 * btn) + fixedWidth + spacing
        }

        let wBase = totalWidth(btn: baseBtn, spacing: baseSpacing)
        if w >= wBase {
            return LeftToolbarClusterAutoScaleResult(spacing: baseSpacing, navButtonWidth: baseBtn, buttonSize: baseBtn, symbolPointSize: baseSymbolPt)
        }

        // Phase 1: reduce spacing from base -> min.
        let wMinSpacing = totalWidth(btn: baseBtn, spacing: minSpacing)
        if w >= wMinSpacing {
            let t = (w - wMinSpacing) / max(0.0001, (wBase - wMinSpacing))
            let eased = smoothstep01(t)
            let candidate = minSpacing + (baseSpacing - minSpacing) * eased

            let spacingMaxFit = max(0, w - (fixedWidth + (4 * baseBtn)))
            let spacing = max(0, min(candidate, spacingMaxFit))
            return LeftToolbarClusterAutoScaleResult(spacing: spacing, navButtonWidth: baseBtn, buttonSize: baseBtn, symbolPointSize: baseSymbolPt)
        }

        // Phase 2: spacing at min; reduce button size from base -> min.
        var spacing = minSpacing
        if w < (fixedWidth + spacing) {
            spacing = max(0, w - fixedWidth)
            return LeftToolbarClusterAutoScaleResult(spacing: spacing, navButtonWidth: 0, buttonSize: 0, symbolPointSize: 0)
        }

        let btnNeeded = max(0, (w - fixedWidth - spacing) / 4)
        let btn: CGFloat
        let symbolPt: CGFloat

        if btnNeeded >= baseBtn {
            btn = baseBtn
            symbolPt = baseSymbolPt
        } else if btnNeeded >= minBtn {
            let t = (btnNeeded - minBtn) / max(0.0001, (baseBtn - minBtn))
            let eased = smoothstep01(t)
            let btnCandidate = minBtn + (baseBtn - minBtn) * eased
            let symCandidate = minSymbolPt + (baseSymbolPt - minSymbolPt) * eased

            let btnClamped = min(btnCandidate, btnNeeded)
            let symClamped = (btnCandidate > 0) ? (symCandidate * (btnClamped / btnCandidate)) : symCandidate
            btn = btnClamped
            symbolPt = symClamped
        } else {
            // Final guard clamp for *all* widths.
            btn = btnNeeded
            let scale = (minBtn > 0) ? (btn / minBtn) : 0
            symbolPt = max(0, minSymbolPt * scale)
        }

        // Final guard clamp (per spec).
        let btnClamped = min(btn, btnNeeded)
        let symClamped = (btn > 0) ? (symbolPt * (btnClamped / btn)) : symbolPt

        return LeftToolbarClusterAutoScaleResult(
            spacing: spacing,
            navButtonWidth: btnClamped,
            buttonSize: btnClamped,
            symbolPointSize: symClamped
        )
    }

    private func applyLeftToolbarClusterAutoScale(result: LeftToolbarClusterAutoScaleResult, force: Bool) {
        if !force, let last = leftToolbarAutoScaleLastApplied {
            if abs(last.spacing - result.spacing) < leftToolbarAutoScaleEpsilon,
               abs(last.navButtonWidth - result.navButtonWidth) < leftToolbarAutoScaleEpsilon,
               abs(last.buttonSize - result.buttonSize) < leftToolbarAutoScaleEpsilon,
               abs(last.symbolPointSize - result.symbolPointSize) < leftToolbarAutoScaleEpsilon {
                return
            }
        }

        leftToolbarCluster.spacing = result.spacing

        sidebarToggleWidthConstraint?.constant = result.buttonSize
        sidebarToggleHeightConstraint?.constant = result.buttonSize
        sidebarMenuWidthConstraint?.constant = result.buttonSize
        sidebarMenuHeightConstraint?.constant = result.buttonSize
        let navWidth = (2 * result.navButtonWidth) + navDividerWidth + (2 * navInset)
        sidebarWidthConstraint?.constant = navWidth
        navWidthConstraint?.constant = navWidth
        if toolbarControlHeight > 0 {
            let leftHeight = max(toolbarMinHitSize, toolbarControlHeight * leftToolbarClusterScale)
            sidebarHeightConstraint?.constant = leftHeight
            navHeightConstraint?.constant = leftHeight
        }
        backWidthConstraint?.constant = result.buttonSize
        backHeightConstraint?.constant = result.buttonSize
        forwardWidthConstraint?.constant = result.buttonSize
        forwardHeightConstraint?.constant = result.buttonSize

        // Symbol sizes scale with the same eased factor as control size.
        let symbolConfig = toolbarSymbolConfig(pointSize: result.symbolPointSize)
        updateSidebarToggleIcon(symbolConfig: symbolConfig)
        sidebarMenuButton.image = NSImage(systemSymbolName: "chevron.down", accessibilityDescription: nil)?.withSymbolConfiguration(symbolConfig)
        backButton.image = NSImage(systemSymbolName: "chevron.left", accessibilityDescription: nil)?.withSymbolConfiguration(symbolConfig)
        forwardButton.image = NSImage(systemSymbolName: "chevron.right", accessibilityDescription: nil)?.withSymbolConfiguration(symbolConfig)

        leftToolbarAutoScaleLastApplied = result
    }

