    private func setupHoverTooltipBubble(in root: NSView) {
        guard hoverTooltipBubble == nil else { return }
        let bubble = NSView(frame: .zero)
        bubble.translatesAutoresizingMaskIntoConstraints = true
        bubble.wantsLayer = true
        bubble.layer?.zPosition = 20_000
        bubble.isHidden = true

        hoverTooltipLabel.font = NSFont.systemFont(ofSize: 12.5, weight: .medium)
        hoverTooltipLabel.alignment = .center
        hoverTooltipLabel.lineBreakMode = .byTruncatingTail
        hoverTooltipLabel.isSelectable = false
        hoverTooltipLabel.isEditable = false
        hoverTooltipLabel.isBordered = false
        hoverTooltipLabel.drawsBackground = false

        bubble.addSubview(hoverTooltipLabel)
        root.addSubview(bubble, positioned: .above, relativeTo: suggestionsContainer)
        hoverTooltipBubble = bubble
        updateHoverTooltipAppearance()
