    private func installHoverTooltipMonitor() {
        guard hoverTooltipMoveMonitor == nil else { return }
        window?.acceptsMouseMovedEvents = true
        hoverTooltipMoveMonitor = NSEvent.addLocalMonitorForEvents(matching: [.mouseMoved, .leftMouseDown, .rightMouseDown]) { [weak self] event in
            guard let self else { return event }
            guard event.window === self.window else { return event }
            switch event.type {
            case .mouseMoved:
                self.updateHoverTooltip(at: event.locationInWindow)
            case .leftMouseDown, .rightMouseDown:
                self.hideHoverTooltip()
            default:
                break
            }
            return event
        }
    }

    private func registerCustomTooltips(in root: NSView) {
        func walk(_ view: NSView) {
            if let button = view as? NSButton {
                if let tip = button.toolTip, !tip.isEmpty {
                    if (button.accessibilityLabel() ?? "").isEmpty {
                        button.setAccessibilityLabel(tip)
                    }
                    button.toolTip = nil
                }
            }
            for sub in view.subviews {
                walk(sub)
            }
        }
        walk(root)
    }

    private func hoverTooltipBaseBackground(for anchor: NSView?) -> NSColor {
        let base = windowBackgroundSolidColor()
        guard let anchor else { return base }
        if anchor === rightPanelPillControl || anchor.isDescendant(of: rightPanelPillControl) {
            return effectiveBackgroundColor(base: base, tint: toolbarGlassTintColor())
        }
        if anchor.isDescendant(of: headerControlsContainer) {
            return effectiveBackgroundColor(base: base, tint: toolbarGlassTintColor())
        }
        if anchor.isDescendant(of: leftContainer) || anchor.isDescendant(of: leftHeaderBar) {
            return effectiveBackgroundColor(base: base, tint: leftPanelGlassTintColor())
        }
        if anchor.isDescendant(of: rightAuxContainer) || anchor.isDescendant(of: rightAuxContentView) {
            return effectiveBackgroundColor(base: base, tint: rightAuxFixedGlassTintColor())
        }
        if anchor.isDescendant(of: rightContainer) || anchor.isDescendant(of: rightPanelContentHost) {
            return effectiveBackgroundColor(base: base, tint: panelClearGlassTintColor())
        }
        return base
    }

    private func hoverTooltipBackgroundForBubble(_ bubble: NSView, anchor: NSView?) -> NSColor {
        guard let root = bubble.superview else { return hoverTooltipBaseBackground(for: anchor) }
        guard bubble.frame.width > 1, bubble.frame.height > 1 else { return hoverTooltipBaseBackground(for: anchor) }
        let point = NSPoint(x: bubble.frame.midX, y: bubble.frame.midY)
        let wasHidden = bubble.isHidden
        bubble.isHidden = true
        let hit = root.hitTest(point)
        bubble.isHidden = wasHidden
        return hoverTooltipBaseBackground(for: hit ?? anchor)
    }

    private func updateHoverTooltipAppearance(anchor: NSView? = nil) {
        guard let bubble = hoverTooltipBubble else { return }
        let bubbleBase = hoverTooltipBackgroundForBubble(bubble, anchor: anchor)
        applyStandardHoverTooltipStyle(to: bubble, label: hoverTooltipLabel, base: bubbleBase)
    }

    private func refreshHoverTooltipLayoutIfNeeded() {
        guard let bubble = hoverTooltipBubble,
              let root = window?.contentView else { return }
        if let anchor = hoverTooltipAnchor, !hoverTooltipText.isEmpty {
            guard anchor.window === window,
                  anchor.isHidden == false,
                  anchor.superview != nil else {
                hideHoverTooltip()
                return
            }
            showHoverTooltip(hoverTooltipText, anchor: anchor, in: root, bubble: bubble)
            return
        }
        let point = window?.mouseLocationOutsideOfEventStream ?? .zero
        if root.bounds.contains(point) {
            updateHoverTooltip(at: point)
        } else {
            hideHoverTooltip()
        }
    }

    private func updateHoverTooltip(at pointInWindow: NSPoint) {
        guard let root = window?.contentView,
              let bubble = hoverTooltipBubble else { return }
        let hit = root.hitTest(pointInWindow)
        guard let anchor = tooltipAnchorCandidate(from: hit, root: root, pointInWindow: pointInWindow) else {
            hideHoverTooltip()
            return
        }
        let text = tooltipText(for: anchor)
        guard !text.isEmpty else {
            hideHoverTooltip()
            return
        }
        showHoverTooltip(text, anchor: anchor, in: root, bubble: bubble)
    }

    private func tooltipAnchorCandidate(from hit: NSView?, root: NSView, pointInWindow: NSPoint) -> NSView? {
        if let pill = rightPanelPillControl as NSView? {
            let pillFrameInRoot = pill.convert(pill.bounds, to: root)
            let hitPill = pillFrameInRoot.contains(pointInWindow)
                || hit == nil
                || hit === pill
                || (hit?.isDescendant(of: pill) ?? false)
            if hitPill {
                let pointInPill = pill.convert(pointInWindow, from: nil)
                if pill.bounds.contains(pointInPill) {
                    guard rightPanelPillControl.isExpandedForInteraction() else {
                        return nil
                    }
                    let count = AppSettings.AppleIntelligence.defaultButtons.count
                    for index in 0..<count {
                        guard let button = rightPanelPillControl.circleButton(at: index) else { continue }
                        if button.isHidden { continue }
                        if button.alphaValue < 0.05 { continue }
                        if button.frame.contains(pointInPill) {
                            return button
                        }
                    }
                }
                if hit == nil { return nil }
            }
        }

        var current = hit
        while let view = current, view !== root {
            if view === pdfView || view.isDescendant(of: pdfView) {
                return nil
            }
            if view === detailsWebView || view.isDescendant(of: detailsWebView) {
                return nil
            }
            if view is NSButton {
                return view
            }
            current = view.superview
        }
        return nil
    }

    private func tooltipText(for view: NSView) -> String {
        if let button = view as? NSButton,
           rightPanelPillControl.isExpandedForInteraction(),
           let label = rightPanelPillControl.circleButtonLabel(for: button) {
            return label
        }
        if view === rightPanelSettingsEdgeButton {
            return "Settings"
        }
        if let label = view.accessibilityLabel(), !label.isEmpty {
            return label
        }
        if let tip = view.toolTip, !tip.isEmpty {
            return tip
        }
        if let button = view as? NSButton, !button.title.isEmpty {
            return button.title
        }
        return ""
    }

    private func showHoverTooltip(_ text: String, anchor: NSView, in root: NSView, bubble: NSView) {
        if hoverTooltipAnchor !== anchor || hoverTooltipText != text {
            hoverTooltipAnchor = anchor
            hoverTooltipText = text
            hoverTooltipLabel.stringValue = text
        }

        let labelSize = hoverTooltipLabel.fittingSize
        let paddingX: CGFloat = 10
        let paddingY: CGFloat = 6
        let bubbleWidth = labelSize.width + (paddingX * 2)
        let bubbleHeight = labelSize.height + (paddingY * 2)

        let anchorFrame = anchor.convert(anchor.bounds, to: root)
        let edgeInset: CGFloat = 6
        let minX = root.bounds.minX + edgeInset
        let maxX = root.bounds.maxX - edgeInset - bubbleWidth
        var x = anchorFrame.midX - (bubbleWidth / 2)
        x = min(maxX, max(minX, x))

        let minY = root.bounds.minY + edgeInset
        let maxY = root.bounds.maxY - edgeInset - bubbleHeight
        var y = anchorFrame.minY - bubbleHeight - 8
        if y < minY {
            y = anchorFrame.maxY + 8
        }
        if y > maxY {
            y = maxY
        }
        if y < minY {
            y = minY
        }

        bubble.frame = NSRect(x: x, y: y, width: bubbleWidth, height: bubbleHeight)
        hoverTooltipLabel.frame = NSRect(x: paddingX,
                                         y: paddingY,
                                         width: bubbleWidth - (paddingX * 2),
                                         height: bubbleHeight - (paddingY * 2))
        updateHoverTooltipAppearance(anchor: anchor)
        bubble.isHidden = false
    }

    private func showHoverTooltip(_ text: String, anchor: NSView) {
        guard let root = window?.contentView,
              let bubble = hoverTooltipBubble else { return }
        showHoverTooltip(text, anchor: anchor, in: root, bubble: bubble)
    }

    private func hideHoverTooltip() {
        hoverTooltipAnchor = nil
        hoverTooltipText = ""
        hoverTooltipBubble?.isHidden = true
    }

    @objc private func dismissShortcutResultPanel(_ sender: Any?) {
        hideShortcutResultPanel()
    }

    private func layoutShortcutResultPanel() {
        guard let panel = shortcutResultPanel,
              let contentView = panel.contentView else { return }

        let bounds = contentView.bounds
        if let glassBase = shortcutResultGlassBase, glassBase.frame != bounds {
            glassBase.frame = bounds
        }
        shortcutResultContentHost.frame = bounds

        let contentInset: CGFloat = 20
        let buttonHeight: CGFloat = 36
        let buttonSpacing: CGFloat = 12
        let availableWidth = max(0, bounds.width - (contentInset * 2))
        let doneFitting = max(1, shortcutResultDoneButton.fittingSize.width)
        let addFitting = max(1, shortcutResultAddToAnnotationsButton.fittingSize.width)
        var doneWidth = max(90, doneFitting + 24)
        var addWidth = max(160, addFitting + 24)
        let totalWidth = doneWidth + buttonSpacing + addWidth
        if totalWidth > availableWidth, totalWidth > 0 {
            let scale = availableWidth / totalWidth
            doneWidth = floor(doneWidth * scale)
            addWidth = floor(addWidth * scale)
        }
        let startX = (bounds.width - (doneWidth + buttonSpacing + addWidth)) / 2
        let buttonsY = contentInset
        shortcutResultDoneButton.frame = NSRect(x: startX,
                                                y: buttonsY,
                                                width: doneWidth,
                                                height: buttonHeight)
        shortcutResultAddToAnnotationsButton.frame = NSRect(x: startX + doneWidth + buttonSpacing,
                                                            y: buttonsY,
                                                            width: addWidth,
                                                            height: buttonHeight)

        let scrollTopInset: CGFloat = contentInset
        let scrollBottom = (buttonsY + buttonHeight) + 12
        let scrollHeight = max(160, bounds.height - scrollTopInset - scrollBottom - 10)
        let scrollFrame = NSRect(x: contentInset,
                                 y: scrollBottom,
                                 width: bounds.width - (contentInset * 2),
                                 height: scrollHeight)
        shortcutResultScroll.frame = scrollFrame
        shortcutResultTextView.frame = NSRect(origin: .zero, size: scrollFrame.size)

        let labelSize = shortcutResultLoadingLabel.fittingSize
        let spinnerSize = shortcutResultSpinner.fittingSize
        let chipPaddingX: CGFloat = 16
        let chipPaddingY: CGFloat = 10
        let chipHeight = max(spinnerSize.height, labelSize.height) + (chipPaddingY * 2)
        let chipWidth = spinnerSize.width + 10 + labelSize.width + (chipPaddingX * 2)
        let chipX = max(contentInset, (bounds.width - chipWidth) / 2)
        let chipY = max(contentInset, (bounds.height - chipHeight) / 2)
        shortcutResultLoadingView.frame = NSRect(x: chipX, y: chipY, width: chipWidth, height: chipHeight)
        shortcutResultSpinner.frame = NSRect(x: chipPaddingX,
                                             y: (chipHeight - spinnerSize.height) / 2,
                                             width: spinnerSize.width,
                                             height: spinnerSize.height)
        shortcutResultLoadingLabel.frame = NSRect(x: chipPaddingX + spinnerSize.width + 10,
                                                  y: (chipHeight - labelSize.height) / 2,
                                                  width: labelSize.width,
                                                  height: labelSize.height)
    }

    private func setShortcutResultLoading(_ isLoading: Bool, label: String?) {
        shortcutResultLoadingVisible = isLoading
        if let label, !label.isEmpty {
            shortcutResultLoadingLabel.stringValue = label
        } else {
            shortcutResultLoadingLabel.stringValue = "Running..."
        }
        shortcutResultLoadingView.isHidden = !isLoading
        shortcutResultScroll.isHidden = isLoading
        shortcutResultDoneButton.isHidden = isLoading
        shortcutResultAddToAnnotationsButton.isHidden = isLoading
        if isLoading {
            shortcutResultSpinner.startAnimation(nil)
        } else {
            shortcutResultSpinner.stopAnimation(nil)
        }
    }

    private func presentShortcutResultPanel() {
        guard let panel = shortcutResultPanel else { return }
        if panel.parent == nil, let hostWindow = window {
            hostWindow.addChildWindow(panel, ordered: .above)
        }
        if !panel.isVisible, let hostWindow = window {
            let preferred = preferredShortcutResultPanelFrame(hostWindow: hostWindow)
            let visibleFrame = (hostWindow.screen ?? NSScreen.main)?.visibleFrame ?? preferred
            if panel.screen != hostWindow.screen || !visibleFrame.intersects(panel.frame) {
                panel.setFrame(preferred, display: true)
            }
        }
        layoutShortcutResultPanel()
        panel.makeKeyAndOrderFront(nil)
    }

    private func shortcutLoadingMessage(for label: String) -> String {
        let trimmed = label.trimmingCharacters(in: .whitespacesAndNewlines)
        let key = trimmed.lowercased()
        switch key {
        case "contribution", "contributions", "key contribution", "key contributions":
            return "Summarizing the Key Contributions..."
        case "method", "methods", "methodology":
            return "Extracting Core Methods..."
        case "equation", "equations":
            return "Analyzing Key Equations..."
        case "constraint", "constraints":
            return "Identifying Constraints..."
        case "strength", "strengths":
            return "Assessing Strengths and Weaknesses..."
        case "related work", "related", "related-work", "related research":
            return "Connecting Related Work..."
        default:
            if trimmed.isEmpty {
                return "Working..."
            }
            return "Working on \(trimmed)..."
        }
    }

    private func showShortcutRunningPanel(title: String?) {
        setShortcutResultLoading(true, label: title)
        presentShortcutResultPanel()
    }

    private func showShortcutResultPanel(output: String) {
        setShortcutResultLoading(false, label: nil)
        let formatted = formatShortcutOutput(output)
        shortcutResultTextView.textStorage?.setAttributedString(formatted)
        shortcutResultTextView.assignInlineMathHosts()
        shortcutResultTextView.scrollRangeToVisible(NSRange(location: 0, length: 0))
        shortcutResultVisible = true
        presentShortcutResultPanel()
        shortcutResultPanel?.makeFirstResponder(shortcutResultTextView)
    }

    private func shortcutResultAnnotationContent() -> AnnotationCommentContent? {
        guard let storage = shortcutResultTextView.textStorage else { return nil }
        let plain = inlineMathRawString(from: storage)
        let baseFont = shortcutResultTextView.font ?? NSFont.systemFont(ofSize: 14, weight: .regular)
        let baseColor = shortcutResultTextView.textColor ?? resolvedSystemColor(.labelColor)
        let payload = annotationRichTextPayload(from: storage, baseFont: baseFont, baseColor: baseColor)
        return AnnotationCommentContent(plainText: plain, richTextPayload: payload)
    }

    @objc private func addShortcutResultToAnnotations(_ sender: Any?) {
        guard isShowingPDF, pdfView.isHidden == false, pdfView.document != nil else {
            showAppleIntelligenceToast("Open a PDF to add annotations.")
            return
        }
        guard let content = shortcutResultAnnotationContent(), !content.isEmpty else {
            showAppleIntelligenceToast("Nothing to add.")
            return
        }
        guard annotationController?.addShortcutResultAnnotation(content: content) != nil else {
            showAppleIntelligenceToast("Unable to add annotation.")
            return
        }
        showAppleIntelligenceToast("Added to Annotations.", duration: 1.0)
    }

    private func hideShortcutResultPanel() {
        shortcutResultVisible = false
        setShortcutResultLoading(false, label: nil)
        guard let panel = shortcutResultPanel else { return }
        if let parent = panel.parent {
            parent.removeChildWindow(panel)
        }
        panel.orderOut(nil)
    }

    private func preferredShortcutResultPanelFrame(hostWindow: NSWindow) -> NSRect {
        func viewRectInScreen(_ view: NSView) -> NSRect? {
            guard view.window === hostWindow else { return nil }
            let frameInWindow = view.convert(view.bounds, to: nil)
            return hostWindow.convertToScreen(frameInWindow)
        }

        func anchorRectInScreen() -> NSRect? {
            if rightAuxPanelVisible,
               rightAuxContainer.superview != nil,
               rightAuxContainer.bounds.width > 12,
               let rect = viewRectInScreen(rightAuxContainer) {
                return rect
            }
            let leftShown = sidebarVisible || leftContainer.frame.width > 12
            if leftShown,
               leftContainer.superview != nil,
               leftContainer.bounds.width > 12,
               let rect = viewRectInScreen(leftContainer) {
                return rect
            }
            return nil
        }

        let hostFrame = hostWindow.frame
        let width = hostFrame.width * 0.5
        let targetHeight = max(460, hostFrame.height * 0.78)
        let height = min(targetHeight, hostFrame.height * 0.9)

        let rawFrame: NSRect
        if let anchor = anchorRectInScreen() {
            let originX = anchor.midX - (width / 2)
            let originY = anchor.midY - (height / 2)
            rawFrame = NSRect(x: originX, y: originY, width: width, height: height)
        } else {
            let margin: CGFloat = 16
            let contentRect = hostWindow.contentView.flatMap { viewRectInScreen($0) } ?? hostFrame
            let originX = contentRect.maxX - width - margin
            let originY = contentRect.midY - (height / 2)
            rawFrame = NSRect(x: originX, y: originY, width: width, height: height)
        }

        guard let screen = hostWindow.screen ?? NSScreen.main else { return rawFrame }
        let visible = screen.visibleFrame.insetBy(dx: 12, dy: 12)
        let clampedX = min(max(rawFrame.minX, visible.minX), visible.maxX - rawFrame.width)
        let clampedY = min(max(rawFrame.minY, visible.minY), visible.maxY - rawFrame.height)
        return NSRect(x: clampedX, y: clampedY, width: rawFrame.width, height: rawFrame.height)
    }


    private func normalizeShortcutOutput(_ text: String) -> String {
        var value = text.replacingOccurrences(of: "\r\n", with: "\n")
        value = value.replacingOccurrences(of: "\r", with: "\n")
        let keys = ["Title:", "Label:", "Prompt:", "URL:"]
        for key in keys {
            value = value.replacingOccurrences(of: " \(key)", with: "\n\(key)")
        }
        return value.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func formatShortcutOutput(_ text: String) -> NSAttributedString {
        let clean = normalizeShortcutOutput(text)
        let palette = shortcutResultTextPalette()
        let baseFont = NSFont.systemFont(ofSize: 14, weight: .regular)
        let heading1 = NSFont.systemFont(ofSize: 18, weight: .semibold)
        let heading2 = NSFont.systemFont(ofSize: 16, weight: .semibold)
        let heading3 = NSFont.systemFont(ofSize: 15, weight: .semibold)
        let mono = NSFont.monospacedSystemFont(ofSize: 13, weight: .regular)

        let baseStyle = NSMutableParagraphStyle()
        baseStyle.lineSpacing = 3
        baseStyle.paragraphSpacing = 8
        baseStyle.lineBreakMode = .byWordWrapping

        let bulletStyle = NSMutableParagraphStyle()
        bulletStyle.lineSpacing = 2
        bulletStyle.paragraphSpacing = 6
        bulletStyle.firstLineHeadIndent = 0
        bulletStyle.headIndent = 16
        bulletStyle.lineBreakMode = .byWordWrapping

        let headingStyle = NSMutableParagraphStyle()
        headingStyle.lineSpacing = 3
        headingStyle.paragraphSpacing = 8
        headingStyle.paragraphSpacingBefore = 6
        headingStyle.lineBreakMode = .byWordWrapping

        let result = NSMutableAttributedString()
        let lines = clean.split(separator: "\n", omittingEmptySubsequences: false)
        var inCodeBlock = false
        let keyPrefixes = ["Title:", "Label:", "Prompt:", "URL:"]

        for rawLine in lines {
            let line = String(rawLine)
            let trimmed = line.trimmingCharacters(in: .whitespaces)
            if trimmed.hasPrefix("```") {
                inCodeBlock.toggle()
                continue
            }

            if inCodeBlock {
                let attrs: [NSAttributedString.Key: Any] = [
                    .font: mono,
                    .foregroundColor: palette.primary,
                    .paragraphStyle: baseStyle
                ]
                result.append(NSAttributedString(string: line + "\n", attributes: attrs))
                continue
            }

            if trimmed.hasPrefix("### ") || trimmed.hasPrefix("## ") || trimmed.hasPrefix("# ") {
                let level: Int
                if trimmed.hasPrefix("### ") { level = 3 }
                else if trimmed.hasPrefix("## ") { level = 2 }
                else { level = 1 }
                let content = trimmed.replacingOccurrences(of: String(repeating: "#", count: level) + " ", with: "")
                let font = (level == 1) ? heading1 : (level == 2 ? heading2 : heading3)
                let attrs: [NSAttributedString.Key: Any] = [
                    .font: font,
                    .foregroundColor: palette.primary,
                    .paragraphStyle: headingStyle
                ]
                result.append(NSAttributedString(string: content + "\n", attributes: attrs))
                continue
            }

            if trimmed.hasPrefix("- ") || trimmed.hasPrefix("* ") || trimmed.hasPrefix("• ") {
                let content = trimmed.dropFirst(2)
                let attrs: [NSAttributedString.Key: Any] = [
                    .font: baseFont,
                    .foregroundColor: palette.primary,
                    .paragraphStyle: bulletStyle
                ]
                result.append(NSAttributedString(string: "• \(content)\n", attributes: attrs))
                continue
            }

            if let key = keyPrefixes.first(where: { trimmed.hasPrefix($0) }) {
                let rest = trimmed.dropFirst(key.count).trimmingCharacters(in: .whitespaces)
                let keyAttrs: [NSAttributedString.Key: Any] = [
                    .font: NSFont.systemFont(ofSize: 14, weight: .semibold),
                    .foregroundColor: palette.primary,
                    .paragraphStyle: baseStyle
                ]
                let restAttrs: [NSAttributedString.Key: Any] = [
                    .font: baseFont,
                    .foregroundColor: palette.primary,
                    .paragraphStyle: baseStyle
                ]
                result.append(NSAttributedString(string: key + " ", attributes: keyAttrs))
                result.append(NSAttributedString(string: rest + "\n", attributes: restAttrs))
                continue
            }

            let attrs: [NSAttributedString.Key: Any] = [
                .font: baseFont,
                .foregroundColor: palette.primary,
                .paragraphStyle: baseStyle
            ]
            result.append(NSAttributedString(string: line + "\n", attributes: attrs))
        }

        return inlineMathAttributedString(from: result,
                                          baseFont: baseFont,
                                          textColor: palette.primary,
                                          allowBare: true)
    }

    private func layoutAppleIntelligenceToast() {
        guard let root = appleIntelligenceToast.superview else { return }
        let text = appleIntelligenceToast.stringValue
        guard !text.isEmpty else { return }
        let size = appleIntelligenceToast.fittingSize
        let paddingX: CGFloat = 12
        let paddingY: CGFloat = 6
        let width = max(120, size.width + (2 * paddingX))
        let height = max(20, size.height + (2 * paddingY))
        let pillFrame = rightPanelPillControl.frame
        let x = min(max(8, pillFrame.midX - (width / 2)), max(8, root.bounds.maxX - width - 8))
        let y = min(max(8, pillFrame.maxY + 6), max(8, root.bounds.maxY - height - 8))
        appleIntelligenceToast.frame = NSRect(x: x, y: y, width: width, height: height)
    }

    private func showAppleIntelligenceToast(_ message: String, duration: TimeInterval = 1.2) {
        appleIntelligenceToastWorkItem?.cancel()
        appleIntelligenceToast.stringValue = message
        appleIntelligenceToast.isHidden = false
        layoutAppleIntelligenceToast()
        NSAnimationContext.runAnimationGroup { context in
            context.duration = 0.15
            appleIntelligenceToast.animator().alphaValue = 1.0
        }
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            NSAnimationContext.runAnimationGroup { context in
                context.duration = 0.2
                self.appleIntelligenceToast.animator().alphaValue = 0.0
            } completionHandler: {
                self.appleIntelligenceToast.isHidden = true
            }
        }
        appleIntelligenceToastWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + duration, execute: work)
    }

    private func positionAppleIntelligenceTextView(near anchorView: NSView) {
        guard let root = anchorView.superview else { return }
        let anchorFrameInRoot = anchorView.convert(anchorView.bounds, to: root)
        let clampX = min(max(2, anchorFrameInRoot.minX), max(2, root.bounds.maxX - 2))
        let clampY = min(max(2, anchorFrameInRoot.minY), max(2, root.bounds.maxY - 2))
        appleIntelligenceTextView.frame = NSRect(x: clampX, y: clampY, width: 1, height: 1)
    }

    private func updateAppleIntelligencePillTooltips() {
        let settings = AppSettingsStore.shared.current.appleIntelligence
        let count = AppSettings.AppleIntelligence.defaultButtons.count
        var labels: [String] = []
        labels.reserveCapacity(count)
        for index in 0..<count {
            labels.append(settings.resolvedButton(at: index).label)
        }
        rightPanelPillControl.updateCircleButtonTooltips(labels)
    }

    private func installPillClickFallbackMonitor() {
        guard pillClickMonitor == nil else { return }
        pillClickMonitor = NSEvent.addLocalMonitorForEvents(matching: [.leftMouseUp]) { [weak self] event in
            guard let self else { return event }
            guard event.window === self.window else { return event }

            let pill = self.rightPanelPillControl
            let pointInPill = pill.convert(event.locationInWindow, from: nil)
            guard pill.bounds.contains(pointInPill) else { return event }

            AppleIntelligenceLog.info("fallback_monitor hit expanded=\(pill.isExpandedForInteraction()) loc=\(Int(pointInPill.x)),\(Int(pointInPill.y))")
            self.showAppleIntelligenceToast("AI monitor hit", duration: 0.6)
            if pill.isExpandedForInteraction() {
                for index in 0..<AppSettings.AppleIntelligence.defaultButtons.count {
                    guard let button = pill.circleButton(at: index) else { continue }
                    if button.frame.contains(pointInPill) {
                        self.runAppleIntelligencePrompt(index: index, anchor: button)
                        return event
                    }
                }
            } else {
                self.runAppleIntelligencePrompt(index: 0, anchor: pill)
            }
            return event
        }
    }

    private func runAppleIntelligencePrompt(index: Int, anchor: NSView?) {
        let now = ProcessInfo.processInfo.systemUptime
        if let last = lastAppleIntelligenceTrigger,
           last.index == index,
           (now - last.time) < 0.25 {
            return
        }
        lastAppleIntelligenceTrigger = (now, index)

        let settings = AppSettingsStore.shared.current.appleIntelligence
        let button = settings.resolvedButton(at: index)
        let prompt = button.prompt
        let label = button.label
        let useShortcuts = settings.useShortcuts
        let shortcutName = button.shortcutName.trimmingCharacters(in: .whitespacesAndNewlines)
        let shouldUseShortcut = useShortcuts || !shortcutName.isEmpty

        AppleIntelligenceLog.info("click index=\(index) label=\(label)")
        let isPDFContext = isShowingPDF && pdfView.isHidden == false
        if shouldUseShortcut {
            guard !shortcutName.isEmpty else {
                showAppleIntelligenceToast("AI: no Shortcut set")
                presentNonBlockingAlert(message: "No Shortcut set",
                                        informative: "Set a Shortcut name for this button in Settings → Apple Intelligence.")
                return
            }
            routePDFToShortcut(name: shortcutName,
                               runningLabel: label,
                               inputText: nil,
                               onStart: { [weak self] in
                                   self?.showAppleIntelligenceToast("AI: running Shortcut…", duration: 1.0)
                               },
                               onResult: { [weak self] result in
                                   self?.handleShortcutResult(result)
                               },
                               onRoutingError: { [weak self] error in
                                   self?.showAppleIntelligenceToast("AI: no PDF input")
                                   self?.presentShortcutRoutingError(error)
                               })
            return
        }
        if AppleIntelligenceLog.isEnabled {
            showAppleIntelligenceToast("AI click \(index + 1)")
        } else {
            let source = isPDFContext ? "PDF" : "HTML"
            showAppleIntelligenceToast("AI: reading \(source)...")
        }
        showAppleIntelligenceLoading(after: 0.2)
        fetchActiveDocumentText { [weak self] text in
            guard let self else { return }
            self.hideAppleIntelligenceLoading()
            guard let text, !text.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
                AppleIntelligenceLog.info("no_document_text")
                self.hideShortcutResultPanel()
                self.showAppleIntelligenceToast("AI: no document text")
                self.presentNonBlockingAlert(message: "No document text", informative: "Open an HTML or PDF paper to ask Apple Intelligence.")
                return
            }
            let context = self.truncateAppleIntelligenceContext(text)
            let request = AppleIntelligenceRequest(label: label, prompt: prompt, documentText: context)
            if let handler = AppleIntelligenceHooks.present, handler(request) {
                return
            }
            if Thread.isMainThread {
                self.presentAppleIntelligence(request, anchor: anchor)
            } else {
                DispatchQueue.main.async { [weak self] in
                    self?.presentAppleIntelligence(request, anchor: anchor)
                }
            }
        }
    }

    private func showAppleIntelligenceLoading(after delay: TimeInterval) {
        appleIntelligenceLoadingWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            guard self.loadingOverlay.isHidden else {
                self.appleIntelligenceLoadingVisible = false
                return
            }
            self.appleIntelligenceLoadingVisible = true
            self.showLoading("Preparing Apple Intelligence…")
        }
        appleIntelligenceLoadingWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + delay, execute: work)
    }

    private func hideAppleIntelligenceLoading() {
        appleIntelligenceLoadingWorkItem?.cancel()
        appleIntelligenceLoadingWorkItem = nil
        if appleIntelligenceLoadingVisible {
            appleIntelligenceLoadingVisible = false
            hideLoading()
        }
    }

    private func handleShortcutResult(_ result: ShortcutCLIRunner.Result) {
        let output = result.output.trimmingCharacters(in: .whitespacesAndNewlines)
        if !output.isEmpty {
            showShortcutResultPanel(output: output)
            return
        }
        if !result.isSuccess {
            var message = result.error.isEmpty ? "Shortcut failed." : result.error
            // Surface the most common misconfiguration explicitly: Shortcut not set to accept PDF input.
            if message.lowercased().contains("input") || message.lowercased().contains("pdf") {
                message += "\n\nEnsure the Shortcut is configured to receive PDFs."
            }
            hideShortcutResultPanel()
            presentNonBlockingAlert(message: "Shortcut failed", informative: message)
            return
        }
        hideShortcutResultPanel()
        showAppleIntelligenceToast("Shortcut finished", duration: 0.8)
    }


    private func fetchActiveDocumentText(completion: @escaping (String?) -> Void) {
        if let override = AppleIntelligenceHooks.contextOverride?() {
            completion(override)
            return
        }
        if !Thread.isMainThread {
            DispatchQueue.main.async { [weak self] in
                self?.fetchActiveDocumentText(completion: completion)
            }
            return
        }

        let isPDFContext = isShowingPDF && pdfView.isHidden == false
        if isPDFContext {
            guard let doc = pdfView.document else {
                completion(nil)
                return
            }
            AppleIntelligenceLog.info("fetch_pdf pages=\(doc.pageCount)")
            if let data = doc.dataRepresentation() {
                appleIntelligenceContextQueue.async { [weak self] in
                    let snapshot = PDFDocument(data: data)
                    let text = self?.extractPDFDocumentText(snapshot)
                    DispatchQueue.main.async {
                        completion(text)
                    }
                }
            } else {
                AppleIntelligenceLog.info("fetch_pdf_data_unavailable")
                let text = extractPDFDocumentText(doc)
                completion(text)
            }
            return
        }

        AppleIntelligenceLog.info("fetch_html")
        let js = "(() => { const root = document.body || document.documentElement; return root ? root.innerText : ''; })()"
        var completed = false
        let timeout = DispatchWorkItem { [weak self] in
            guard let self else { return }
            guard !completed else { return }
            completed = true
            AppleIntelligenceLog.info("fetch_html_timeout")
            self.showAppleIntelligenceToast("AI: HTML timeout")
            completion(nil)
        }
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5, execute: timeout)
        detailsWebView.evaluateJavaScript(js) { result, error in
            guard !completed else { return }
            completed = true
            timeout.cancel()
            if let error {
                AppleIntelligenceLog.info("fetch_html_error=\(String(describing: error))")
            }
            var text = result as? String
            if let trimmed = text?.trimmingCharacters(in: .whitespacesAndNewlines), trimmed.isEmpty {
                text = nil
            }
            completion(text)
        }
    }

    private func extractPDFDocumentText(_ document: PDFDocument?) -> String? {
        guard let document else { return nil }
        if let text = document.string,
           !text.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return text
        }
        var parts: [String] = []
        parts.reserveCapacity(document.pageCount)
        for index in 0..<document.pageCount {
            if let pageText = document.page(at: index)?.string,
               !pageText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                parts.append(pageText)
            }
        }
        let merged = parts.joined(separator: "\n\n")
        let trimmed = merged.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? nil : merged
    }

    private func truncateAppleIntelligenceContext(_ text: String) -> String {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmed.count > appleIntelligenceMaxContextCharacters else { return trimmed }
        let prefix = trimmed.prefix(appleIntelligenceMaxContextCharacters)
        return "\(prefix)\n\n[Context truncated to \(appleIntelligenceMaxContextCharacters) characters.]"
    }

    struct ShortcutDocumentInput {
        let fileURL: URL
        let cleanupAfterRun: Bool
        let sourceDescription: String
    }

    enum ShortcutPDFRoutingError: Error, LocalizedError {
        case noDocument
        case documentNotReady
        case stagingDirectoryUnavailable
        case sourceFileUnreadable
        case copyFailed
        case writeFailed
        case dataUnavailable
        case invalidPDFFile

        var isRetryable: Bool {
            switch self {
            case .noDocument, .documentNotReady, .dataUnavailable, .writeFailed:
                return true
            default:
                return false
            }
        }

        var errorDescription: String? {
            switch self {
            case .noDocument:
                return "No PDF document is loaded."
            case .documentNotReady:
                return "PDF document is still loading."
            case .stagingDirectoryUnavailable:
                return "Could not create a staging directory for Shortcuts input."
            case .sourceFileUnreadable:
                return "PDF source file is not readable."
            case .copyFailed:
                return "Failed to copy PDF into the Shortcuts staging folder."
            case .writeFailed:
                return "Failed to export PDF for Shortcuts."
            case .dataUnavailable:
                return "PDF data is unavailable."
            case .invalidPDFFile:
                return "Prepared file is not a valid PDF."
            }
        }

        var alertTitle: String {
            switch self {
            case .noDocument:
                return "No PDF available"
            case .documentNotReady:
                return "PDF still loading"
            case .stagingDirectoryUnavailable, .copyFailed, .writeFailed, .dataUnavailable:
                return "Could not prepare PDF"
            case .sourceFileUnreadable:
                return "PDF file not readable"
            case .invalidPDFFile:
                return "Invalid PDF file"
            }
        }

        var alertInfo: String {
            switch self {
            case .noDocument:
                return "Open a PDF in the viewer before running this Shortcut."
            case .documentNotReady:
                return "Wait for the PDF to finish loading and try again."
            case .stagingDirectoryUnavailable:
                return "The Shortcuts input folder could not be created."
            case .sourceFileUnreadable:
                return "The current PDF file could not be accessed."
            case .copyFailed:
                return "The app couldn't copy the current PDF into a safe location."
            case .writeFailed:
                return "The app couldn't export the current PDF for Shortcuts."
            case .dataUnavailable:
                return "The PDF data wasn't ready. Try again in a moment."
            case .invalidPDFFile:
                return "The prepared file doesn't look like a valid PDF."
            }
        }
    }

    func resolvePDFOnlyShortcutInput() -> Result<ShortcutDocumentInput, ShortcutPDFRoutingError> {
        return resolvePDFShortcutInput()
    }

    // Shortcut routing reliability notes:
    // - Previously we relied on `documentURL` directly when it looked like a file. That URL can point to
    //   transient/sandboxed locations or files still being written, which caused intermittent "no input" runs.
    // - We now always stage a verified PDF copy into a dedicated session directory, validate readability + header,
    //   surface CLI launch/input errors, and retry briefly if the PDF is still loading.
    // - This makes routing deterministic across sources, filenames, and rapid PDF switches.
    private func resolvePDFShortcutInput() -> Result<ShortcutDocumentInput, ShortcutPDFRoutingError> {
        guard let doc = pdfView.document else { return .failure(.noDocument) }
        guard doc.pageCount > 0 else { return .failure(.documentNotReady) }
        guard let stagingDir = shortcutStagingDirectory() else { return .failure(.stagingDirectoryUnavailable) }

        let stagingURL = makeShortcutStagingURL(in: stagingDir)

        var sawInvalidPDF = false

        if let sourceURL = doc.documentURL, sourceURL.isFileURL {
            if shortcutInputFileIsValid(sourceURL) {
                if copyShortcutSourcePDF(from: sourceURL, to: stagingURL) {
                    if shortcutInputFileIsValid(stagingURL) {
                        ShortcutRunnerLog.info("shortcut_input source=file copy=1 url=\(stagingURL.path)")
                        return .success(ShortcutDocumentInput(fileURL: stagingURL,
                                                              cleanupAfterRun: true,
                                                              sourceDescription: "file"))
                    }
                    sawInvalidPDF = true
                    try? FileManager.default.removeItem(at: stagingURL)
                }
            } else {
                ShortcutRunnerLog.error("shortcut_input source_unreadable url=\(sourceURL.path)")
            }
        }

        if doc.write(to: stagingURL), shortcutInputFileIsValid(stagingURL) {
            ShortcutRunnerLog.info("shortcut_input source=pdfkit_write url=\(stagingURL.path)")
            return .success(ShortcutDocumentInput(fileURL: stagingURL,
                                                  cleanupAfterRun: true,
                                                  sourceDescription: "pdfkit"))
        }
        if FileManager.default.fileExists(atPath: stagingURL.path) {
            sawInvalidPDF = true
        }

        try? FileManager.default.removeItem(at: stagingURL)
        let data = doc.dataRepresentation()
        if let data {
            do {
                try data.write(to: stagingURL, options: [.atomic])
                if shortcutInputFileIsValid(stagingURL) {
                    ShortcutRunnerLog.info("shortcut_input source=data_rep url=\(stagingURL.path)")
                    return .success(ShortcutDocumentInput(fileURL: stagingURL,
                                                          cleanupAfterRun: true,
                                                          sourceDescription: "data"))
                }
                sawInvalidPDF = true
            } catch {
                ShortcutRunnerLog.error("shortcut_input data_write_failed error=\(String(describing: error))")
            }
        } else {
            ShortcutRunnerLog.error("shortcut_input data_unavailable")
        }

        try? FileManager.default.removeItem(at: stagingURL)
        if sawInvalidPDF {
            return .failure(.invalidPDFFile)
        }
        return .failure(data == nil ? .dataUnavailable : .writeFailed)
    }

    private func shortcutStagingDirectory() -> URL? {
        let dir = pdfCache.sessionDirectory.appendingPathComponent("shortcuts", isDirectory: true)
        do {
            try FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true, attributes: nil)
            return dir
        } catch {
            ShortcutRunnerLog.error("shortcut_stage_dir_failed error=\(String(describing: error))")
            return nil
        }
    }

    private func makeShortcutStagingURL(in dir: URL) -> URL {
        dir.appendingPathComponent("shortcut-input-\(UUID().uuidString)").appendingPathExtension("pdf")
    }

    private func copyShortcutSourcePDF(from sourceURL: URL, to destURL: URL) -> Bool {
        let fm = FileManager.default
        var didStartAccess = false
        if sourceURL.startAccessingSecurityScopedResource() {
            didStartAccess = true
        }
        defer {
            if didStartAccess {
                sourceURL.stopAccessingSecurityScopedResource()
            }
        }
        do {
            if fm.fileExists(atPath: destURL.path) {
                try fm.removeItem(at: destURL)
            }
            try fm.copyItem(at: sourceURL, to: destURL)
            return true
        } catch {
            ShortcutRunnerLog.error("shortcut_input_copy_failed error=\(String(describing: error))")
            return false
        }
    }

    private func shortcutInputFileIsValid(_ url: URL) -> Bool {
        guard url.isFileURL else { return false }
        var isDir: ObjCBool = false
        let exists = FileManager.default.fileExists(atPath: url.path, isDirectory: &isDir)
        guard exists, !isDir.boolValue else { return false }
        guard FileManager.default.isReadableFile(atPath: url.path) else { return false }
        if let fileSize = (try? url.resourceValues(forKeys: [.fileSizeKey]))?.fileSize {
            guard fileSize > 0 else { return false }
        }
        return shortcutInputFileLooksLikePDF(url)
    }

    private func shortcutInputFileLooksLikePDF(_ url: URL) -> Bool {
        guard let handle = try? FileHandle(forReadingFrom: url) else { return false }
        defer { try? handle.close() }
        let data = try? handle.read(upToCount: 5)
        guard let data, data.count >= 4 else { return false }
        let header = String(data: data.prefix(4), encoding: .ascii)
        return header == "%PDF"
    }

    private func presentShortcutRoutingError(_ error: ShortcutPDFRoutingError) {
        reportError("shortcut_route_failed", documentID: reportingDocumentID(), details: ["error": error.localizedDescription])
        presentNonBlockingAlert(message: error.alertTitle, informative: error.alertInfo)
    }

    func routePDFToShortcut(name: String,
                                        runningLabel: String?,
                                        inputText: String?,
                                        onStart: (() -> Void)? = nil,
                                        onResult: @escaping (ShortcutCLIRunner.Result) -> Void,
                                        onRoutingError: ((ShortcutPDFRoutingError) -> Void)? = nil,
                                        attempt: Int = 0) {
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            ShortcutRunnerLog.error("shortcut_missing_name")
            presentNonBlockingAlert(message: "No Shortcut set",
                                    informative: "Set a Shortcut name before running it.")
            return
        }

        let resolution = resolvePDFOnlyShortcutInput()
        switch resolution {
        case .success(let shortcutInput):
            if let label = runningLabel {
                showShortcutRunningPanel(title: shortcutLoadingMessage(for: label))
            }
            onStart?()
            reportDocumentIO("shortcut_route",
                             documentID: reportingDocumentID(),
                             details: ["shortcut": reportingHash(trimmed),
                                       "has_input_text": "\(inputText != nil)",
                                       "input_file": shortcutInput.fileURL.lastPathComponent])
            ShortcutCLIRunner.shared.runShortcut(nameOrIdentifier: trimmed,
                                                 inputText: inputText,
                                                 inputFileURL: shortcutInput.fileURL,
                                                 cleanupInputFile: shortcutInput.cleanupAfterRun) { result in
                onResult(result)
            }
        case .failure(let error):
            if error.isRetryable && attempt < 2 {
                let nextAttempt = attempt + 1
                ShortcutRunnerLog.info("shortcut_input_retry attempt=\(nextAttempt) reason=\(error.localizedDescription)")
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.18) { [weak self] in
                    self?.routePDFToShortcut(name: trimmed,
                                             runningLabel: runningLabel,
                                             inputText: inputText,
                                             onStart: onStart,
                                             onResult: onResult,
                                             onRoutingError: onRoutingError,
                                             attempt: nextAttempt)
                }
                return
            }
            if let handler = onRoutingError {
                handler(error)
            } else {
                presentShortcutRoutingError(error)
            }
        }
    }

    private func writeTemporaryPDFForShortcut(from document: PDFDocument) -> URL? {
        let dir = FileManager.default.temporaryDirectory
        let url = dir.appendingPathComponent("arxiv_shortcut_\(UUID().uuidString).pdf")
        if document.write(to: url), shortcutInputFileIsValid(url) {
            return url
        }
        try? FileManager.default.removeItem(at: url)
        if let data = document.dataRepresentation() {
            do {
                try data.write(to: url, options: [.atomic])
            } catch {
                return nil
            }
        }
        return shortcutInputFileIsValid(url) ? url : nil
    }

    private func presentAppleIntelligence(_ request: AppleIntelligenceRequest, anchor: NSView?) {
        if #available(macOS 15.2, *) {
            guard NSWritingToolsCoordinator.isWritingToolsAvailable else {
                presentNonBlockingAlert(message: "Apple Intelligence unavailable",
                                        informative: "Writing Tools is not available on this Mac.")
                return
            }
        }

        if let session = appleIntelligenceSession {
            session.popover.close()
            appleIntelligenceSession = nil
        }

        guard let window else { return }
        NSApp.activate(ignoringOtherApps: true)
        var anchorView = anchor ?? rightPanelPillControl
        if anchorView.window == nil {
            anchorView = window.contentView ?? rightPanelPillControl
        }
        positionAppleIntelligenceTextView(near: anchorView)

        appleIntelligenceTextView.string = request.documentText
        let fullRange = NSRange(location: 0, length: (appleIntelligenceTextView.string as NSString).length)
        appleIntelligenceTextView.setSelectedRange(fullRange)
        applyWritingToolsPromptToTextView(request.prompt)
        if let container = appleIntelligenceTextView.textContainer {
            appleIntelligenceTextView.layoutManager?.ensureLayout(for: container)
        }
        if window.makeFirstResponder(appleIntelligenceTextView) == false {
            AppleIntelligenceLog.info("first_responder_failed")
            showAppleIntelligenceToast("AI: focus failed")
            presentNonBlockingAlert(message: "Apple Intelligence unavailable",
                                    informative: "Could not focus the Writing Tools text view. Please try again.")
            return
        }
        AppleIntelligenceLog.info("present_start prompt_len=\(request.prompt.count) text_len=\(request.documentText.count)")
        showAppleIntelligenceToast("AI: presenting…")
        let anchorRect = anchorView.bounds
        var popover: NSPopover?
        let disablePrivateUI = ProcessInfo.processInfo.environment["ARXIV_AI_PRIVATE_UI"] == "0"
        if !disablePrivateUI,
           anchorView.window != nil,
           loadWritingToolsFrameworks(),
           let config = makeWritingToolsConfiguration(prompt: request.prompt,
                                                      contextText: request.documentText,
                                                      selectedRange: fullRange,
                                                      anchorView: anchorView,
                                                      anchorRect: anchorRect),
           let vcClass = NSClassFromString("WTWritingToolsViewController") as? NSViewController.Type {
            let vc = vcClass.init(nibName: nil, bundle: nil)
            let vcObject = vc as NSObject
            _ = setValueIfPossible(vcObject, key: "configuration", value: config)
            _ = setValueIfPossible(vcObject, key: "writingToolsConfiguration", value: config)

            let nextPopover = NSPopover()
            nextPopover.behavior = .transient
            nextPopover.animates = true
            nextPopover.delegate = self
            nextPopover.contentViewController = vc

            let safeAnchorRect: NSRect = {
                let rect = anchorRect
                if rect.width.isFinite, rect.height.isFinite, rect.width > 0, rect.height > 0 {
                    return rect
                }
                let fallback = anchorView.bounds
                if fallback.width.isFinite, fallback.height.isFinite, fallback.width > 0, fallback.height > 0 {
                    return fallback
                }
                return NSRect(x: 0, y: 0, width: 1, height: 1)
            }()

            nextPopover.show(relativeTo: safeAnchorRect, of: anchorView, preferredEdge: .maxY)
            popover = nextPopover
            appleIntelligenceSession = AppleIntelligenceSession(popover: nextPopover, viewController: vc)
        } else if disablePrivateUI {
            AppleIntelligenceLog.info("private_ui_disabled")
        } else {
            AppleIntelligenceLog.info("wt_ui_unavailable")
        }

        if popover == nil {
            if !presentAppleIntelligenceViaTextView(prompt: request.prompt) {
                AppleIntelligenceLog.info("public_show_failed")
                showAppleIntelligenceToast("AI: failed")
                presentNonBlockingAlert(message: "Apple Intelligence unavailable",
                                        informative: "Writing Tools did not respond on this Mac.")
                return
            }
        }

        window.makeKeyAndOrderFront(nil)
        if let popover {
            scheduleAppleIntelligenceVisibilityCheck(request: request, popover: popover)
        }
    }

    @discardableResult
    private func applyWritingToolsPromptToTextView(_ prompt: String) -> Bool {
        let promptKeys = [
            "writingToolsPrompt",
            "writingToolsUserPrompt",
            "writingToolsQuestion",
            "writingToolsQuery",
            "writingToolsInstruction",
            "userPrompt",
            "prompt"
        ]
        var applied = false
        for key in promptKeys {
            if setValueIfPossible(appleIntelligenceTextView, key: key, value: prompt) {
                applied = true
            }
        }
        AppleIntelligenceLog.info("prompt_applied=\(applied)")
        return applied
    }

    private func presentAppleIntelligenceViaTextView(prompt: String) -> Bool {
        applyWritingToolsPromptToTextView(prompt)
        let selectors: [(String, Any?)] = [
            ("showWritingToolsWithPrompt:", prompt),
            ("showWritingToolsForPrompt:", prompt),
            ("showWritingToolsWithInstruction:", prompt)
        ]
        for (selectorName, arg) in selectors {
            let selector = NSSelectorFromString(selectorName)
            if appleIntelligenceTextView.responds(to: selector) {
                _ = appleIntelligenceTextView.perform(selector, with: arg)
                AppleIntelligenceLog.info("public_show selector=\(selectorName)")
                return true
            }
        }
        let didShow = fallbackShowWritingTools()
        if didShow {
            AppleIntelligenceLog.info("public_show fallback")
        }
        return didShow
    }

    private func loadWritingToolsFrameworks() -> Bool {
        if NSClassFromString("WTWritingToolsViewController") != nil {
            return true
        }
        let bundles = [
            "/System/Library/PrivateFrameworks/WritingTools.framework",
            "/System/Library/PrivateFrameworks/WritingToolsUI.framework"
        ]
        for path in bundles {
            if let bundle = Bundle(path: path), !bundle.isLoaded {
                _ = bundle.load()
            }
        }
        return NSClassFromString("WTWritingToolsViewController") != nil
    }

    private func makeWritingToolsConfiguration(prompt: String,
                                               contextText: String,
                                               selectedRange: NSRange,
                                               anchorView: NSView,
                                               anchorRect: NSRect) -> NSObject? {
        guard let configClass = NSClassFromString("WTWritingToolsConfiguration") as? NSObject.Type else { return nil }
        let config = configClass.init()

        applyWritingToolsConfiguration(config,
                                       prompt: prompt,
                                       contextText: contextText,
                                       selectedRange: selectedRange,
                                       anchorView: anchorView,
                                       anchorRect: anchorRect)

        return config
    }

    private func applyWritingToolsConfiguration(_ config: NSObject,
                                               prompt: String,
                                               contextText: String,
                                               selectedRange: NSRange,
                                               anchorView: NSView,
                                               anchorRect: NSRect) {
        let attributed = NSAttributedString(string: contextText)
        let rangeValue = NSValue(range: selectedRange)
        let rangeArray = [rangeValue]

        let promptKeys = ["prompt", "userPrompt", "instruction", "query", "question", "request", "askPrompt", "inputPrompt"]
        for key in promptKeys {
            _ = setValueIfPossible(config, key: key, value: prompt)
        }

        let toolKeys: [(String, NSNumber)] = [
            ("requestedTool", NSNumber(value: 0)),
            ("requestedToolType", NSNumber(value: 0)),
            ("tool", NSNumber(value: 0)),
            ("toolType", NSNumber(value: 0)),
            ("operation", NSNumber(value: 0)),
            ("operationType", NSNumber(value: 0))
        ]
        for (key, value) in toolKeys {
            _ = setValueIfPossible(config, key: key, value: value)
        }

        let viewKeys = ["textView", "sourceTextView", "documentView", "inputView"]
        for key in viewKeys {
            _ = setValueIfPossible(config, key: key, value: appleIntelligenceTextView)
        }

        let textKeys = ["text", "documentText", "contextText", "sourceText", "inputText", "selectedText"]
        for key in textKeys {
            _ = setValueIfPossible(config, key: key, value: contextText)
        }

        let attributedKeys = ["attributedString", "attributedText", "contextAttributedString", "sourceAttributedString"]
        for key in attributedKeys {
            _ = setValueIfPossible(config, key: key, value: attributed)
        }

        let rangeKeys = ["selectedRange", "selectionRange", "selectedTextRange"]
        for key in rangeKeys {
            _ = setValueIfPossible(config, key: key, value: rangeValue)
        }
        let rangesKeys = ["selectedRanges", "selectionRanges"]
        for key in rangesKeys {
            _ = setValueIfPossible(config, key: key, value: rangeArray)
        }

        _ = setValueIfPossible(config, key: "positioningView", value: anchorView)
        _ = setValueIfPossible(config, key: "positioningRect", value: NSValue(rect: anchorRect))
    }

    private func scheduleAppleIntelligenceVisibilityCheck(request: AppleIntelligenceRequest, popover: NSPopover) {
        appleIntelligenceAttemptID += 1
        let attempt = appleIntelligenceAttemptID
        appleIntelligenceFallbackAttempted = false

        DispatchQueue.main.asyncAfter(deadline: .now() + 0.35) { [weak self] in
            guard let self else { return }
            guard attempt == self.appleIntelligenceAttemptID else { return }
            if self.isWritingToolsVisible(popover: popover) { return }
            if !self.appleIntelligenceFallbackAttempted {
                AppleIntelligenceLog.info("popover_not_visible fallback=1")
                self.showAppleIntelligenceToast("AI: fallback…")
                self.appleIntelligenceFallbackAttempted = true
                self.fallbackShowWritingTools()
                self.scheduleAppleIntelligenceFallbackCheck(request: request, popover: popover, attempt: attempt)
                return
            }
            AppleIntelligenceLog.info("popover_not_visible giving_up")
            self.showAppleIntelligenceToast("AI: failed")
            self.presentNonBlockingAlert(message: "Apple Intelligence didn’t appear",
                                         informative: "Writing Tools did not present. Ensure Apple Intelligence is enabled for this Mac and try again.")
        }
    }

    private func scheduleAppleIntelligenceFallbackCheck(request: AppleIntelligenceRequest, popover: NSPopover, attempt: Int) {
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.35) { [weak self] in
            guard let self else { return }
            guard attempt == self.appleIntelligenceAttemptID else { return }
            if self.isWritingToolsVisible(popover: popover) { return }
            AppleIntelligenceLog.info("fallback_not_visible")
            self.showAppleIntelligenceToast("AI: failed")
            self.presentNonBlockingAlert(message: "Apple Intelligence didn’t appear",
                                         informative: "Writing Tools did not present. Ensure Apple Intelligence is enabled for this Mac and try again.")
        }
    }

    private func isWritingToolsVisible(popover: NSPopover?) -> Bool {
        if popover?.isShown == true { return true }
        if #available(macOS 15.0, *) {
            if appleIntelligenceTextView.isWritingToolsActive { return true }
        }
        return false
    }

    @discardableResult
    private func fallbackShowWritingTools() -> Bool {
        guard let window else { return false }
        NSApp.activate(ignoringOtherApps: true)
        window.makeFirstResponder(appleIntelligenceTextView)
        let selector = #selector(NSResponder.showWritingTools(_:))
        if NSApp.sendAction(selector, to: nil, from: appleIntelligenceTextView) {
            return true
        }
        if appleIntelligenceTextView.responds(to: selector) {
            _ = appleIntelligenceTextView.perform(selector, with: nil)
            return true
        }
        return false
    }

    @discardableResult
    private func setValueIfPossible(_ object: NSObject, key: String, value: Any) -> Bool {
        guard let first = key.unicodeScalars.first else { return false }
        let firstString = String(first).uppercased()
        let rest = String(key.dropFirst())
        let selector = NSSelectorFromString("set\(firstString)\(rest):")
        guard object.responds(to: selector) else { return false }
        object.setValue(value, forKey: key)
        return true
    }

    private func selectedPaperURLStringIfAvailable() -> String? {
        guard let idx = selectedFilteredIndex(), idx >= 0, idx < filtered.count else { return nil }
        let paper = filtered[idx]
        let canonical = ArxivShareURL.canonicalAbsURL(from: paper.url)
        let urlString = (canonical?.absoluteString ?? paper.url).trimmingCharacters(in: .whitespacesAndNewlines)
        return urlString.isEmpty ? nil : urlString
    }

    func currentDisplayedArxivURLString() -> String? {
        if isShowingPDF, let doc = pdfView.document {
            if let url = ArxivShareURL.canonicalAbsURL(from: doc.documentURL) {
                return url.absoluteString
            }
            if let urlString = doc.documentURL?.absoluteString,
               let id = ArxivShareURL.extractArxivIdentifier(from: urlString),
               let absURL = URL(string: "https://arxiv.org/abs/\(id)") {
                return absURL.absoluteString
            }
            if let text = doc.page(at: 0)?.string,
               let id = ArxivShareURL.extractArxivIdentifier(from: text),
               let absURL = URL(string: "https://arxiv.org/abs/\(id)") {
                return absURL.absoluteString
            }
        }
        return selectedPaperURLStringIfAvailable()
    }

    private func currentDisplayedMailSubject() -> String {
        if let idx = selectedFilteredIndex(), idx >= 0, idx < filtered.count {
            let safeTitle = decodeTeXAccents(filtered[idx].title).trimmingCharacters(in: .whitespacesAndNewlines)
            if !safeTitle.isEmpty { return safeTitle }
        }
        if isShowingPDF, let title = pdfDocumentTitle(pdfView.document), !title.isEmpty {
            return title
        }
        return "arXiv paper"
    }

    private func resolvedRecipientEmail() -> String {
        let fromScript = (recipientEmailFromAppleScript ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        if !fromScript.isEmpty { return fromScript }
        let fallback = AppSettingsStore.shared.current.sharingExport.email.defaultToAddress
            .trimmingCharacters(in: .whitespacesAndNewlines)
        return fallback
    }

    private func emailTemplateContext(title: String, url: String) -> EmailTemplateContext {
        let name = (recipientNameFromAppleScript ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let email = resolvedRecipientEmail()
        return EmailTemplateContext(
            title: title,
            url: url,
            recipientName: name,
            recipientEmail: email,
            appName: APP_EFFECTIVE_NAME
        )
    }

    private func resolvedEmailSubject(fallback: String, context: EmailTemplateContext) -> String {
        let template = AppSettingsStore.shared.current.sharingExport.email.defaultSubjectTemplate
        let trimmedTemplate = template.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedTemplate.isEmpty else { return fallback }
        let rendered = renderEmailTemplate(template, context: context)
        return rendered.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? fallback : rendered
    }

    private func resolvedEmailBody(fallback: String, context: EmailTemplateContext) -> String {
        let template = AppSettingsStore.shared.current.sharingExport.email.defaultBodyTemplate
        let trimmedTemplate = template.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedTemplate.isEmpty else { return fallback }
        let rendered = renderEmailTemplate(template, context: context)
        return rendered.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? fallback : rendered
    }

    private func effectiveEmailAppBundleID() -> String? {
        let settings = AppSettingsStore.shared.current.sharingExport.email
        let explicit = settings.defaultEmailAppBundleID.trimmingCharacters(in: .whitespacesAndNewlines)
        if !explicit.isEmpty { return explicit }
        return systemDefaultMailtoBundleID()
    }

    private func defaultEmailToAddress() -> String? {
        let raw = AppSettingsStore.shared.current.sharingExport.email.defaultToAddress
            .trimmingCharacters(in: .whitespacesAndNewlines)
        return raw.isEmpty ? nil : raw
    }

    private func defaultEmailFromAddress() -> String? {
        let raw = AppSettingsStore.shared.current.sharingExport.email.defaultFromAddress
            .trimmingCharacters(in: .whitespacesAndNewlines)
        return raw.isEmpty ? nil : raw
    }

    private func resolvedEmailToAddress() -> String? {
        let fromScript = (recipientEmailFromAppleScript ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        if fromScript.contains("@") { return fromScript }
        if let fallback = defaultEmailToAddress(), fallback.contains("@") { return fallback }
        return nil
    }

    private func composeEmailWithMailApp(subject: String,
                                         body: String,
                                         toAddress: String?,
                                         fromAddress: String?,
                                         attachments: [URL] = []) {
        let shareT0 = monotonicNow()
        let mailWasRunning = (mailAppRunning() != nil)
        let frontmostBefore = NSWorkspace.shared.frontmostApplication?.bundleIdentifier ?? "(none)"
        MailShareDiagnostics.log("share_click t=\(String(format: "%.3f", shareT0)) mailRunning=\(mailWasRunning) frontmost=\(frontmostBefore)")

        let fromTrimmed = (fromAddress ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let wantsAttachments = !attachments.isEmpty
        if wantsAttachments || MailShareDiagnostics.forceAppleScript || !fromTrimmed.isEmpty {
            if MailShareDiagnostics.forceAppleScript {
                MailShareDiagnostics.log("share_force_applescript=1")
            }
            let label = wantsAttachments
                ? "compose_with_attachments"
                : (fromTrimmed.isEmpty ? "compose_fallback_forced" : "compose_with_sender")
            runAppleScriptAsync(
                mailComposeAppleScript(subject: subject,
                                       body: body,
                                       toAddress: toAddress,
                                       fromAddress: fromTrimmed,
                                       attachments: attachments),
                label: label
            )
            return
        }

        if #available(macOS 10.15, *) {
            // Prelaunch Mail without stealing focus.
            ensureMailLaunchedForShare(activates: false, completion: nil)
        }

        var attemptedService = false
        func attemptSharingServiceCompose() {
            guard let service = NSSharingService(named: .composeEmail) else { return }
            attemptedService = true
            service.subject = subject
            if let toAddress {
                service.recipients = [toAddress]
            }
            MailShareDiagnostics.log("share_compose_request via=NSSharingService")
            service.perform(withItems: [body])
        }

        attemptSharingServiceCompose()
        // One-shot: bring Mail forward and minimize viewer windows exactly once.
        runAppleScriptAsync(mailActivateAndMinimizeViewerOnceAppleScript(subject: subject), label: "activate_and_minimize_once")

        // Deterministic fallback (no repeated activate/minimize loops, to avoid visible flicker).
        let initialTimeout: TimeInterval = mailWasRunning ? 0.25 : 0.55
        DispatchQueue.main.asyncAfter(deadline: .now() + initialTimeout) {
            let frontmost1 = NSWorkspace.shared.frontmostApplication?.bundleIdentifier
            MailShareDiagnostics.log("share_check_1 frontmost=\(frontmost1 ?? "(none)") attemptedService=\(attemptedService)")

            if frontmost1 == "com.apple.mail" { return }

            MailShareDiagnostics.log("share_fallback_applescript")
            runAppleScriptAsync(
                mailComposeAppleScript(subject: subject,
                                       body: body,
                                       toAddress: toAddress,
                                       fromAddress: nil,
                                       attachments: []),
                label: "compose_fallback"
            )
        }
    }

    private func composeEmail(subject: String,
                              body: String,
                              toAddress: String?,
                              attachments: [URL] = []) {
        let bundleID = effectiveEmailAppBundleID()
        let isMail = (bundleID ?? "") == "com.apple.mail"
        if isMail {
            composeEmailWithMailApp(subject: subject,
                                    body: body,
                                    toAddress: toAddress,
                                    fromAddress: defaultEmailFromAddress(),
                                    attachments: attachments)
            return
        }
        guard let url = buildMailtoURL(toAddress: toAddress, subject: subject, body: body) else {
            reportError("mailto_build_failed")
            NSSound.beep()
            return
        }
        openMailtoURL(url, bundleID: bundleID)
    }

    // Isolated action handler used by the left-most pill circle.
    private func runUserShortcutFromToolbar() {
        let settings = AppSettingsStore.shared.current
        let name = settings.shortcuts.shortcutName.trimmingCharacters(in: .whitespacesAndNewlines)

        // Pill requirement: fail gracefully, never block UI/animations.
        // Missing/renamed/unavailable shortcuts are handled via CLI exit status logging.
        guard !name.isEmpty else {
            ShortcutRunnerLog.error("pill_shortcut_missing_name")
            return
        }

        let inputText: String? = {
            guard settings.shortcuts.inputTextMode else { return nil }
            return currentDisplayedArxivURLString()
        }()

        // Prefer the Apple-supported Shortcuts CLI (only path that supports file input).
        routePDFToShortcut(name: name,
                           runningLabel: nil,
                           inputText: inputText,
                           onResult: { [weak self] result in
                               guard let self else { return }
                               if !result.isSuccess {
                                   let message = result.error.isEmpty ? "Shortcut failed." : result.error
                                   self.presentNonBlockingAlert(message: "Shortcut failed", informative: message)
                               }
                           })
    }

    private func isNarrowWindowMode(windowWidth: CGFloat) -> Bool {
        guard windowWidth.isFinite else { return false }
        return windowWidth <= (NOMINAL_FULL_WINDOW_WIDTH * 0.50)
    }

    private func updateNarrowWindowModeIfNeeded(reason: String) {
        guard let window else { return }
        let w = window.frame.width
        let next = isNarrowWindowMode(windowWidth: w)
        if next == isNarrowWindowModeCached { return }

        layoutLog("narrow_mode_transition from=\(isNarrowWindowModeCached) to=\(next) windowW=\(Int(w)) threshold=\(Int(NOMINAL_FULL_WINDOW_WIDTH * 0.50)) reason=\(reason)")

        if next {
            // Capture pre-narrow state so we can restore on exit.
            preNarrowSidebarVisible = sidebarVisible
            preNarrowChatVisible = rightAuxPanelVisible
            preNarrowSidebarWidth = leftContainer.frame.width
            preNarrowChatWidth = rightAuxPanelWidth()

            // If both side panels are visible, hide the non-last-activated one.
            if sidebarVisible && rightAuxPanelVisible {
                let keep: LastUserActivatedPanel = (lastUserActivatedPanel == .leftContainer || lastUserActivatedPanel == .annotations)
                    ? lastUserActivatedPanel
                    : .leftContainer
                if keep == .leftContainer {
                    layoutLog("narrow_mode_enter_hide target=annotations basis=\(lastUserActivatedPanel.rawValue) fallback=hide_annotations")
                    // Critical invariant: in narrow mode, never allow a rendered state with both visible.
                    // Collapse the hidden panel immediately, then allow subsequent animations.
                    setRightAuxPanelVisible(false, animated: false)
                } else {
                    layoutLog("narrow_mode_enter_hide target=leftContainer basis=\(lastUserActivatedPanel.rawValue)")
                    setSidebarVisible(false, animated: false)
                }
            }
        } else {
            // Restore pre-narrow visibility, respecting global mutual exclusivity.
            if preNarrowSidebarVisible && preNarrowChatVisible {
                let keep: LastUserActivatedPanel = (lastUserActivatedPanel == .leftContainer || lastUserActivatedPanel == .annotations)
                    ? lastUserActivatedPanel
                    : .leftContainer
                if keep == .leftContainer {
                    if rightAuxPanelVisible { setRightAuxPanelVisible(false, animated: true) }
                    if !sidebarVisible { setSidebarVisible(true, animated: true) }
                } else {
                    if sidebarVisible { setSidebarVisible(false, animated: true) }
                    if !rightAuxPanelVisible { setRightAuxPanelVisible(true, animated: true) }
                }
            } else {
                if preNarrowSidebarVisible != sidebarVisible {
                    setSidebarVisible(preNarrowSidebarVisible, animated: true)
                }
                if preNarrowChatVisible != rightAuxPanelVisible {
                    setRightAuxPanelVisible(preNarrowChatVisible, animated: true)
                }
            }

            // Restore widths proportionally relative to last-known sizes.
            // Sidebar width is persisted through `lastSidebarWidth`; chat through `lastRightAuxPanelWidth`.
            if preNarrowSidebarWidth.isFinite, preNarrowSidebarWidth > 1 {
                lastSidebarWidth = preNarrowSidebarWidth
            }
            if preNarrowChatWidth.isFinite, preNarrowChatWidth > 1 {
                lastRightAuxPanelWidth = preNarrowChatWidth
            }
            enforceSidebarWidthBounds(reason: "narrow_exit")
            if rightAuxPanelVisible {
                let total = rightSplitView.bounds.width
                let divider = rightSplitView.dividerThickness
                let targetAux = rightAuxTargetWidth()
                let targetPos = clampRightAuxDividerPosition(max(0, total - divider - targetAux))
                animateRightSplitDivider(to: targetPos, preset: AnimationConstants.panelSpringPreset, animated: true, completion: nil)
            }
        }

        isNarrowWindowModeCached = next

        if panelDebugAssertionsEnabled {
            // In narrow mode, never allow both side panels simultaneously.
            if isNarrowWindowModeCached {
            assert(!(sidebarVisible && rightAuxPanelVisible), "Invariant: narrow mode must not show both leftContainer and annotations")
            }
        }
    }

    @objc private func toggleSidebar() {
        AnimationGuard.performAnimated("sidebar_toggle") { [weak self] in
            guard let self else { return }
            AnimationGuard.trace("sidebar_button_press", details: "visible=\(self.sidebarVisible)")
            let beforeLeft = Int(self.leftContainer.frame.width)
            let beforeRight = Int(self.rightSplitContainer.frame.width)
            SidebarLatencyProbe.shared.markButtonAction(opening: !self.sidebarVisible)
            reportUIEvent("button_press", details: ["button": "sidebar_toggle", "visible_before": "\(self.sidebarVisible)"])
            uiLog("sidebar_button_click visible=\(self.sidebarVisible)")
            layoutLog("sidebar_toggle_enter visible=\(self.sidebarVisible) left=\(beforeLeft) right=\(beforeRight)")
            // User-initiated activation updates ordering.
            self.lastUserActivatedPanel = .leftContainer
            if self.isNarrowWindowModeCached {
                // Narrow mode: keep mutual exclusivity, but still behave as a *toggle*.
                // - If sidebar is visible, hide it.
                // - If sidebar is hidden, show it (and collapse chat first).
            if self.sidebarVisible {
                self.setSidebarVisible(false, animated: true, deferHeavyLayout: true)
            } else {
                // Collapse chat immediately so we never render both side panels at once.
                self.kickstartRightAuxMotion(opening: false, recordStart: false)
                AnimationGuard.deferWork(label: "sidebar_toggle_hide_right_aux") { [weak self] in
                    self?.setRightAuxPanelVisible(false, animated: false, deferHeavyLayout: true)
                }
                self.setSidebarVisible(true, animated: true, deferHeavyLayout: true)
            }
            } else {
                self.setSidebarVisible(!self.sidebarVisible, animated: true, deferHeavyLayout: true)
            }
            DispatchQueue.main.async { [weak self] in
                guard let self else { return }
                layoutLog("sidebar_toggle_exit visible=\(self.sidebarVisible) left=\(Int(self.leftContainer.frame.width)) right=\(Int(self.rightSplitContainer.frame.width))")
                self.updateLayoutDebugOverlay(reason: "sidebar_toggle")
            }
        }
    }

    @objc private func toggleRightPanel() {
        AnimationGuard.performAnimated("right_aux_toggle") { [weak self] in
            guard let self else { return }
            let opening = !self.rightAuxPanelVisible
            AnimationGuard.trace("right_aux_button_press", details: "visible=\(self.rightAuxPanelVisible)")
            ChatLatencyProbe.shared.markButtonAction(opening: opening)
            reportUIEvent("button_press", details: ["button": "annotations_toggle", "visible_before": "\(self.rightAuxPanelVisible)"])
            // User-initiated activation updates ordering.
            self.lastUserActivatedPanel = .annotations
            if self.isNarrowWindowModeCached {
                // Narrow mode: keep mutual exclusivity, but still behave as a *toggle*.
                // - If chat is visible, hide it.
                // - If chat is hidden, show it (and collapse sidebar first).
            if self.rightAuxPanelVisible {
                self.setRightAuxPanelVisible(false, animated: true, deferHeavyLayout: true)
            } else {
                // Collapse sidebar immediately so we never render both side panels at once.
                self.sidebarAnimator.kickstartImmediateMotion(show: false, recordStart: false)
                AnimationGuard.deferWork(label: "right_aux_toggle_hide_sidebar") { [weak self] in
                    self?.setSidebarVisible(false, animated: false, deferHeavyLayout: true)
                }
                self.setRightAuxPanelVisible(true, animated: true, deferHeavyLayout: true)
            }
            } else {
                self.setRightAuxPanelVisible(opening, animated: true, deferHeavyLayout: true)
            }
        }
    }

    // MARK: - Zotero Save

    private func applyZoteroButtonAppearance(state: ZoteroButtonState) {
        zoteroButtonState = state
        let tooltip = (state == .save) ? "Save to Zotero" : "Remove from Zotero"
        rightPanelZoteroEdgeButton.setAccessibilityLabel(tooltip)
        rightPanelZoteroEdgeButton.toolTip = nil
        let isCheckmarkActive = (zoteroCheckmarkVisibleUntil?.timeIntervalSinceNow ?? -1) > 0
        if isCheckmarkActive {
            rightPanelZoteroEdgeButton.image = nil
        } else {
            rightPanelZoteroEdgeButton.image = zoteroToolbarImage(pointSize: 13 * toolbarControlScaleCurrent, state: state)
        }
        rightPanelZoteroEdgeButton.updateTint()
        DispatchQueue.main.async { [weak self] in
            self?.rightPanelZoteroEdgeButton.invalidateLiquidGlass(reason: "zotero_state")
        }
    }

    private func startZoteroActiveIndicator() {
        guard let hostLayer = rightPanelZoteroEdgeButton.layer else { return }
        let buttonBounds = rightPanelZoteroEdgeButton.bounds
        guard buttonBounds.width > 0 && buttonBounds.height > 0 else { return }

        let indicatorLayer: CALayer
        if let existing = zoteroActiveIndicatorLayer {
            indicatorLayer = existing
        } else {
            let layer = CALayer()
            layer.opacity = 0
            layer.zPosition = 18
            hostLayer.addSublayer(layer)
            zoteroActiveIndicatorLayer = layer
            indicatorLayer = layer
        }

        let minDim = min(buttonBounds.width, buttonBounds.height)
        let dotSize = max(3.0, minDim * 0.12)
        let radius = max(1.0, minDim / 2.0)
        let center = CGPoint(x: buttonBounds.midX, y: buttonBounds.midY)
        let steps = 60
        let startAngle = -CGFloat.pi / 2
        var points: [CGPoint] = []
        points.reserveCapacity(steps + 1)
        for i in 0...steps {
            let t = CGFloat(i) / CGFloat(steps)
            let angle = startAngle - (2 * CGFloat.pi * t)
            points.append(CGPoint(x: center.x + cos(angle) * radius,
                                  y: center.y + sin(angle) * radius))
        }

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        indicatorLayer.bounds = CGRect(x: 0, y: 0, width: dotSize, height: dotSize)
        indicatorLayer.position = points.first ?? center
        indicatorLayer.cornerRadius = dotSize / 2
        let indicatorColor = ForegroundResolver.color(base: windowBackgroundSolidColor(),
                                                      tint: toolbarGlassTintColor(),
                                                      role: .icon)
        indicatorLayer.backgroundColor = indicatorColor.cgColor
        indicatorLayer.shadowColor = indicatorColor.cgColor
        indicatorLayer.shadowOpacity = 0.9
        indicatorLayer.shadowRadius = dotSize * 1.6
        indicatorLayer.shadowOffset = .zero
        indicatorLayer.opacity = 1
        CATransaction.commit()

        indicatorLayer.removeAnimation(forKey: "zoteroActiveOrbit")
        let orbit = CAKeyframeAnimation(keyPath: "position")
        orbit.values = points
        orbit.duration = 1.1
        orbit.repeatCount = .infinity
        orbit.calculationMode = .linear
        orbit.timingFunction = CAMediaTimingFunction(name: .linear)
        orbit.isRemovedOnCompletion = false
        indicatorLayer.add(orbit, forKey: "zoteroActiveOrbit")
    }

    private func stopZoteroActiveIndicator() {
        guard let layer = zoteroActiveIndicatorLayer else { return }
        layer.removeAnimation(forKey: "zoteroActiveOrbit")
        let reduce = shouldReduceMotion
        animateLayer(layer, keyPath: "opacity", to: 0, preset: .crisp, reduceMotion: reduce, basicDuration: 0.12)
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.12) { [weak self] in
            guard let self else { return }
            self.zoteroActiveIndicatorLayer?.removeFromSuperlayer()
            self.zoteroActiveIndicatorLayer = nil
        }
    }

    @discardableResult
    private func showZoteroSuccessCheckmark() -> TimeInterval {
        let button = rightPanelZoteroEdgeButton
        guard let hostLayer = button.layer else { return 0 }

        zoteroSuccessCheckmarkWorkItem?.cancel()
        stopZoteroActiveIndicator()
        zoteroCheckmarkToken += 1
        let token = zoteroCheckmarkToken
        let visibleUntil = Date().addingTimeInterval(zoteroCheckmarkHoldSeconds + zoteroCheckmarkFadeSeconds)
        zoteroCheckmarkVisibleUntil = visibleUntil
        applyZoteroButtonAppearance(state: zoteroButtonState)

        let checkLayer: CALayer
        if let existing = zoteroSuccessCheckmarkLayer {
            checkLayer = existing
        } else {
            let layer = CALayer()
            layer.opacity = 0
            layer.zPosition = 20
            hostLayer.addSublayer(layer)
            zoteroSuccessCheckmarkLayer = layer
            checkLayer = layer
        }

        let pointSize = max(12, 13 * toolbarControlScaleCurrent)
        let config = NSImage.SymbolConfiguration(pointSize: pointSize, weight: .semibold)
        let base = NSImage(systemSymbolName: "checkmark", accessibilityDescription: nil)
        let image = base?.withSymbolConfiguration(config) ?? base
        let checkTint = ForegroundResolver.color(base: windowBackgroundSolidColor(),
                                                 tint: toolbarGlassTintColor(),
                                                 role: .icon)
        if let image, let cgImage = tintedImage(image, color: checkTint).cgImage(forProposedRect: nil, context: nil, hints: nil) {
            checkLayer.contents = cgImage
        }
        let scale = button.window?.backingScaleFactor ?? NSScreen.main?.backingScaleFactor ?? 2.0
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        checkLayer.contentsScale = scale
        checkLayer.frame = button.bounds
        checkLayer.contentsGravity = .center
        checkLayer.opacity = 0
        checkLayer.transform = CATransform3DMakeScale(0.6, 0.6, 1.0)
        CATransaction.commit()

        let reduce = shouldReduceMotion
        animateLayer(checkLayer, keyPath: "opacity", to: 1, preset: .crisp, reduceMotion: reduce, basicDuration: 0.14)
        animateLayer(checkLayer, keyPath: "transform", to: CATransform3DIdentity, preset: .microBounce, reduceMotion: reduce, basicDuration: 0.18)

        let work = DispatchWorkItem { [weak self] in
            guard let self, let layer = self.zoteroSuccessCheckmarkLayer, token == self.zoteroCheckmarkToken else { return }
            let endTransform = CATransform3DMakeScale(0.7, 0.7, 1.0)
            animateLayer(layer, keyPath: "opacity", to: 0, preset: .crisp, reduceMotion: self.shouldReduceMotion, basicDuration: 0.16)
            animateLayer(layer, keyPath: "transform", to: endTransform, preset: .crisp, reduceMotion: self.shouldReduceMotion, basicDuration: 0.16)
        }
        let restoreWork = DispatchWorkItem { [weak self] in
            guard let self, token == self.zoteroCheckmarkToken else { return }
            self.zoteroCheckmarkVisibleUntil = nil
            self.refreshZoteroButtonState(reason: "checkmark_end")
        }
        zoteroSuccessCheckmarkWorkItem = restoreWork
        DispatchQueue.main.asyncAfter(deadline: .now() + zoteroCheckmarkHoldSeconds, execute: work)
        DispatchQueue.main.asyncAfter(deadline: .now() + zoteroCheckmarkHoldSeconds + zoteroCheckmarkFadeSeconds, execute: restoreWork)
        return zoteroCheckmarkHoldSeconds + zoteroCheckmarkFadeSeconds
    }

    private func scheduleZoteroButtonStateOverride(_ state: ZoteroButtonState,
                                                   stableID: String?,
                                                   duration: TimeInterval) {
        zoteroStateOverrideWorkItem?.cancel()
        zoteroStateOverride = (state, Date().addingTimeInterval(duration), stableID)
        applyZoteroButtonAppearance(state: state)
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            self.zoteroStateOverride = nil
            self.refreshZoteroButtonState(reason: "override_expired")
        }
        zoteroStateOverrideWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + duration, execute: work)
    }

    private func refreshZoteroButtonState(reason: String) {
        let descriptor = currentZoteroPublicationDescriptor()
        let stableID = descriptor?.stableID
        if let override = zoteroStateOverride,
           override.expiresAt > Date(),
           override.stableID == stableID {
            applyZoteroButtonAppearance(state: override.state)
            return
        } else if zoteroStateOverride != nil {
            zoteroStateOverride = nil
        }
        let record = stableID.flatMap { ZoteroSavedItemStore.shared.record(for: $0) }
        let library = zoteroLibrarySelection(for: record)
        let shouldRemove = (record != nil && library != nil)
        applyZoteroButtonAppearance(state: shouldRemove ? .remove : .save)
        layoutLog("zotero_state reason=\(reason) stable=\(stableID ?? "nil") remove=\(shouldRemove)")
    }

    private func setZoteroActionInFlight(_ inFlight: Bool) {
        zoteroActionInFlight = inFlight
        if inFlight {
            startZoteroActiveIndicator()
        } else {
            stopZoteroActiveIndicator()
        }
        rightPanelZoteroEdgeButton.isEnabled = !inFlight
        rightPanelZoteroEdgeButton.updateTint()
    }

    private func currentZoteroPublicationDescriptor() -> ZoteroPublicationDescriptor? {
        let idx = selectedFilteredIndex()
        let paper = idx.flatMap { idx in
            (idx >= 0 && idx < filtered.count) ? filtered[idx] : nil
        }
        let pdfDoc = pdfView.document

        let title = paper?.title ?? pdfDocumentTitle(pdfDoc)
        let authors = paper.map { parseAuthorList(from: $0.authors) } ?? pdfDocumentAuthors(pdfDoc)
        let year = paper.map { extractYear(from: $0.dateLine) }

        let arxivIDValue: String? = {
            if let url = pdfDoc?.documentURL, let id = arxivIDFromPDFURL(url) { return id }
            if let p = paper, let id = arxivID(fromAbsURL: p.url) { return id }
            if let p = paper, let id = ArxivShareURL.extractArxivIdentifier(from: p.url) { return id }
            if let url = pdfDoc?.documentURL?.absoluteString, let id = ArxivShareURL.extractArxivIdentifier(from: url) { return id }
            if let text = pdfDoc?.page(at: 0)?.string,
               let id = ArxivShareURL.extractArxivIdentifier(from: text) { return id }
            return nil
        }()

        let doi: String? = {
            if let p = paper, let d = extractDOI(from: p.comments) { return d }
            if let p = paper, let d = extractDOI(from: p.abstractText) { return d }
            if let d = extractDOI(from: pdfDoc) { return d }
            return nil
        }()

        let arxivURL = arxivIDValue.flatMap { URL(string: "https://arxiv.org/abs/\($0)")?.absoluteString }
            ?? paper.flatMap { ArxivShareURL.canonicalAbsURL(from: $0.url)?.absoluteString }

        let stableID: String = {
            if let id = arxivIDValue, !id.isEmpty { return "arxiv:\(id.lowercased())" }
            if let d = doi, !d.isEmpty { return "doi:\(normalizeDOI(d).lowercased())" }
            if let url = pdfDoc?.documentURL?.absoluteString, !url.isEmpty { return "url:\(url)" }
            if let t = title?.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines),
               !t.isEmpty {
                return "title:\(t.lowercased())"
            }
            return "unknown"
        }()

        return ZoteroPublicationDescriptor(
            stableID: stableID,
            arxivID: arxivIDValue,
            doi: doi,
            title: title,
            authors: authors,
            year: year,
            abstractText: paper?.abstractText,
            arxivURL: arxivURL,
            pdfDocument: pdfDoc
        )
    }

    private func zoteroLibrarySelection(for record: ZoteroSavedItemRecord?) -> ZoteroLibrary? {
        if let record {
            return ZoteroLibrary(type: record.libraryType, id: record.libraryID, name: record.libraryID)
        }
        let settings = AppSettingsStore.shared.current
        var libraryID = settings.zotero.libraryID
        if settings.zotero.libraryType == .user && libraryID.isEmpty {
            libraryID = settings.zotero.userID
        }
        guard !libraryID.isEmpty else { return nil }
        let name = settings.zotero.libraryName.isEmpty
            ? (settings.zotero.libraryType == .user ? "Personal Library" : "Group \(libraryID)")
            : settings.zotero.libraryName
        return ZoteroLibrary(type: settings.zotero.libraryType, id: libraryID, name: name)
    }

    @objc private func saveCurrentPaperToZotero() {
        guard !zoteroActionInFlight else { return }
        guard let descriptor = currentZoteroPublicationDescriptor() else {
            NSSound.beep()
            return
        }
        let record = ZoteroSavedItemStore.shared.record(for: descriptor.stableID)
        let shouldRemove = record != nil
        reportDocumentIO("zotero_save_request",
                         documentID: reportingDocumentID(),
                         details: ["action": shouldRemove ? "remove" : "save"])
        if shouldRemove, let record {
            removeZoteroItem(descriptor: descriptor, record: record)
        } else {
            saveZoteroItem(descriptor: descriptor)
        }
    }

    private func handleZoteroActionError(_ error: Error, fallbackTitle: String) {
        if (error as? ZoteroActionError) == .cancelled {
            return
        }
        presentNonBlockingAlert(message: fallbackTitle, informative: error.localizedDescription)
    }

    private func saveZoteroItem(descriptor: ZoteroPublicationDescriptor) {
        setZoteroActionInFlight(true)
        ensureZoteroAuthenticated { [weak self] authResult in
            guard let self else { return }
            switch authResult {
            case .failure(let error):
                DispatchQueue.main.async {
                    self.setZoteroActionInFlight(false)
                    self.handleZoteroActionError(error, fallbackTitle: "Zotero Save Failed")
                }
            case .success(let session):
                guard self.isZoteroAuthGateTokenCurrent(session.gateToken) else {
                    DispatchQueue.main.async { self.setZoteroActionInFlight(false) }
                    return
                }
                self.ensureZoteroLibrarySelection(apiKey: session.apiKey, keyInfo: session.info, gateToken: session.gateToken) { [weak self] libResult in
                    guard let self else { return }
                    switch libResult {
                    case .failure(let error):
                        DispatchQueue.main.async {
                            self.setZoteroActionInFlight(false)
                            self.handleZoteroActionError(error, fallbackTitle: "Zotero Save Failed")
                        }
                    case .success(let library):
                        self.promptForZoteroCollection(apiKey: session.apiKey, library: library, gateToken: session.gateToken) { [weak self] collectionResult in
                            guard let self else { return }
                            switch collectionResult {
                            case .failure(let error):
                                DispatchQueue.main.async {
                                    self.setZoteroActionInFlight(false)
                                    self.handleZoteroActionError(error, fallbackTitle: "Zotero Save Failed")
                                }
                            case .success(let collection):
                                ZoteroMetadataResolver.resolveMetadata(for: descriptor) { [weak self] metadataResult in
                                    guard let self else { return }
                                    switch metadataResult {
                                    case .failure(let error):
                                        DispatchQueue.main.async {
                                            self.setZoteroActionInFlight(false)
                                            self.handleZoteroActionError(error, fallbackTitle: "Zotero Save Failed")
                                        }
                                    case .success(let metadata):
                                        self.findExistingZoteroItem(apiKey: session.apiKey,
                                                                    library: library,
                                                                    descriptor: descriptor) { [weak self] findResult in
                                            guard let self else { return }
                                            switch findResult {
                                            case .failure(let error):
                                                DispatchQueue.main.async {
                                                    self.setZoteroActionInFlight(false)
                                                    self.handleZoteroActionError(error, fallbackTitle: "Zotero Save Failed")
                                                }
                                            case .success(let existingItem):
                                                if let existingItem {
                                                    self.updateExistingZoteroItem(apiKey: session.apiKey,
                                                                                  library: library,
                                                                                  item: existingItem,
                                                                                  metadata: metadata,
                                                                                  collection: collection) { [weak self] updateResult in
                                                        guard let self else { return }
                                                        switch updateResult {
                                                        case .failure(let error):
                                                            DispatchQueue.main.async {
                                                                self.setZoteroActionInFlight(false)
                                                                self.handleZoteroActionError(error, fallbackTitle: "Zotero Save Failed")
                                                            }
                                                        case .success(let itemKey):
                                                            self.attachPDFToZoteroItem(apiKey: session.apiKey,
                                                                                       keyInfo: session.info,
                                                                                       library: library,
                                                                                       parentKey: itemKey,
                                                                                       descriptor: descriptor) { [weak self] attachResult in
                                                                guard let self else { return }
                                                                DispatchQueue.main.async {
                                                                    self.setZoteroActionInFlight(false)
                                                                    switch attachResult {
                                                                    case .success:
                                                                        ZoteroSavedItemStore.shared.upsert(
                                                                            ZoteroSavedItemRecord(
                                                                                stableID: descriptor.stableID,
                                                                                libraryType: library.type,
                                                                                libraryID: library.id,
                                                                                itemKey: itemKey
                                                                            )
                                                                        )
                                                                        let anim = self.showZoteroSuccessCheckmark()
                                                                        let delay = anim + self.zoteroPostCheckmarkDelaySeconds
                                                                        self.scheduleZoteroButtonStateOverride(.save,
                                                                                                               stableID: descriptor.stableID,
                                                                                                               duration: delay)
                                                                    case .failure(let error):
                                                                        self.handleZoteroActionError(error, fallbackTitle: "Zotero Save Failed")
                                                                    }
                                                                }
                                                            }
                                                        }
                                                    }
                                                } else {
                                                    let itemData = self.buildZoteroItemData(metadata: metadata, collection: collection)
                                                    ZoteroAPIClient.createItem(apiKey: session.apiKey, library: library, itemData: itemData) { [weak self] createResult in
                                                        guard let self else { return }
                                                        switch createResult {
                                                        case .failure(let error):
                                                            DispatchQueue.main.async {
                                                                self.setZoteroActionInFlight(false)
                                                                self.handleZoteroActionError(error, fallbackTitle: "Zotero Save Failed")
                                                            }
                                                        case .success(let itemKey):
                                                            self.attachPDFToZoteroItem(apiKey: session.apiKey,
                                                                                       keyInfo: session.info,
                                                                                       library: library,
                                                                                       parentKey: itemKey,
                                                                                       descriptor: descriptor) { [weak self] attachResult in
                                                                guard let self else { return }
                                                                DispatchQueue.main.async {
                                                                    self.setZoteroActionInFlight(false)
                                                                    switch attachResult {
                                                                    case .success:
                                                                        ZoteroSavedItemStore.shared.upsert(
                                                                            ZoteroSavedItemRecord(
                                                                                stableID: descriptor.stableID,
                                                                                libraryType: library.type,
                                                                                libraryID: library.id,
                                                                                itemKey: itemKey
                                                                            )
                                                                        )
                                                                        let anim = self.showZoteroSuccessCheckmark()
                                                                        let delay = anim + self.zoteroPostCheckmarkDelaySeconds
                                                                        self.scheduleZoteroButtonStateOverride(.save,
                                                                                                               stableID: descriptor.stableID,
                                                                                                               duration: delay)
                                                                    case .failure(let error):
                                                                        self.handleZoteroActionError(error, fallbackTitle: "Zotero Save Failed")
                                                                    }
                                                                }
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    private func removeZoteroItem(descriptor: ZoteroPublicationDescriptor, record: ZoteroSavedItemRecord) {
        setZoteroActionInFlight(true)
        ensureZoteroAuthenticated { [weak self] authResult in
            guard let self else { return }
            switch authResult {
            case .failure(let error):
                DispatchQueue.main.async {
                    self.setZoteroActionInFlight(false)
                    self.handleZoteroActionError(error, fallbackTitle: "Zotero Remove Failed")
                }
            case .success(let session):
                guard self.isZoteroAuthGateTokenCurrent(session.gateToken) else {
                    DispatchQueue.main.async { self.setZoteroActionInFlight(false) }
                    return
                }
                let library = ZoteroLibrary(type: record.libraryType, id: record.libraryID, name: record.libraryID)
                ZoteroAPIClient.fetchItem(apiKey: session.apiKey, library: library, itemKey: record.itemKey) { [weak self] itemResult in
                    guard let self else { return }
                    switch itemResult {
                    case .failure(let error):
                        if let apiError = error as? ZoteroAPIError, apiError.statusCode == 404 {
                            DispatchQueue.main.async {
                                ZoteroSavedItemStore.shared.remove(stableID: record.stableID)
                                self.refreshZoteroButtonState(reason: "remove_missing")
                                self.setZoteroActionInFlight(false)
                                self.saveZoteroItem(descriptor: descriptor)
                            }
                        } else {
                            DispatchQueue.main.async {
                                self.setZoteroActionInFlight(false)
                                self.handleZoteroActionError(error, fallbackTitle: "Zotero Remove Failed")
                            }
                        }
                    case .success:
                        self.deleteZoteroItemWithChildren(apiKey: session.apiKey,
                                                          library: library,
                                                          record: record)
                    }
                }
            }
        }
    }

    private func deleteZoteroItemWithChildren(apiKey: String,
                                              library: ZoteroLibrary,
                                              record: ZoteroSavedItemRecord) {
        ZoteroAPIClient.fetchItemChildren(apiKey: apiKey, library: library, parentKey: record.itemKey) { [weak self] childResult in
            guard let self else { return }
            let deleteParent = { [weak self] in
                guard let self else { return }
                ZoteroAPIClient.deleteItem(apiKey: apiKey,
                                           library: library,
                                           itemKey: record.itemKey,
                                           version: nil) { [weak self] deleteResult in
                    guard let self else { return }
                    DispatchQueue.main.async {
                        self.setZoteroActionInFlight(false)
                        switch deleteResult {
                        case .success:
                            ZoteroSavedItemStore.shared.remove(stableID: record.stableID)
                            let anim = self.showZoteroSuccessCheckmark()
                            let delay = anim + self.zoteroPostCheckmarkDelaySeconds
                            self.scheduleZoteroButtonStateOverride(.remove,
                                                                   stableID: record.stableID,
                                                                   duration: delay)
                        case .failure(let error):
                            if let apiError = error as? ZoteroAPIError, apiError.statusCode == 404 {
                                ZoteroSavedItemStore.shared.remove(stableID: record.stableID)
                                let anim = self.showZoteroSuccessCheckmark()
                                let delay = anim + self.zoteroPostCheckmarkDelaySeconds
                                self.scheduleZoteroButtonStateOverride(.remove,
                                                                       stableID: record.stableID,
                                                                       duration: delay)
                            } else {
                                self.handleZoteroActionError(error, fallbackTitle: "Zotero Remove Failed")
                            }
                        }
                    }
                }
            }

            switch childResult {
            case .failure:
                deleteParent()
            case .success(let children):
                let attachments = children.map { (key: $0.key, version: $0.version) }
                guard !attachments.isEmpty else {
                    deleteParent()
                    return
                }
                let group = DispatchGroup()
                var deleteError: Error?
                for attachment in attachments {
                    group.enter()
                    ZoteroAPIClient.deleteItem(apiKey: apiKey,
                                               library: library,
                                               itemKey: attachment.key,
                                               version: attachment.version) { result in
                        if case .failure(let error) = result {
                            if let apiError = error as? ZoteroAPIError, apiError.statusCode == 404 {
                                // Ignore missing attachments.
                            } else {
                                deleteError = error
                            }
                        }
                        group.leave()
                    }
                }
                group.notify(queue: .global(qos: .userInitiated)) {
                    if let error = deleteError {
                        DispatchQueue.main.async {
                            self.setZoteroActionInFlight(false)
                            self.handleZoteroActionError(error, fallbackTitle: "Zotero Remove Failed")
                        }
                        return
                    }
                    deleteParent()
                }
            }
        }
    }

    private func ensureZoteroAuthenticated(completion: @escaping (Result<ZoteroAuthSession, Error>) -> Void) {
        zoteroAuthGateToken += 1
        let gateToken = zoteroAuthGateToken

        func completeIfCurrent(_ result: Result<ZoteroAuthSession, Error>) {
            guard isZoteroAuthGateTokenCurrent(gateToken) else { return }
            completion(result)
        }

        let rawKey = resolvedZoteroAPIKey()?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !rawKey.isEmpty {
            let fingerprint = zoteroAPIKeyFingerprint(rawKey)
            if let verified = zoteroVerifiedKeyFingerprint,
               verified == fingerprint,
               let info = zoteroVerifiedKeyInfo {
                let requestKey = zoteroVerifiedRequestKey ?? zoteroRequestAPIKey(from: rawKey, context: "auth_verified")
                completeIfCurrent(.success(ZoteroAuthSession(apiKey: requestKey, info: info, gateToken: gateToken)))
                return
            }

            let settings = AppSettingsStore.shared.current
            let hint = settings.zotero.userID.isEmpty ? nil : settings.zotero.userID
            fetchZoteroKeyInfoWithFallback(rawKey: rawKey, userIDHint: hint, context: "auth_cached") { [weak self] result in
                guard let self else { return }
                guard self.isZoteroAuthGateTokenCurrent(gateToken) else { return }
                switch result {
                case .success(let auth):
                    self.applyZoteroAuthSuccess(apiKey: rawKey, info: auth.info)
                    self.markZoteroVerifiedSession(rawKey: rawKey, requestKey: auth.apiKey, info: auth.info)
                    completeIfCurrent(.success(ZoteroAuthSession(apiKey: auth.apiKey, info: auth.info, gateToken: gateToken)))
                case .failure(let error):
                    if self.isZoteroInvalidKeyError(error) {
                        self.clearZoteroVerifiedSession()
                        DispatchQueue.main.async {
                            self.promptForZoteroAuthentication(requiredBy: nil, gateToken: gateToken, completion: completion)
                        }
                        return
                    }
                    DispatchQueue.main.async {
                        self.presentZoteroNetworkErrorAlert()
                        completeIfCurrent(.failure(ZoteroActionError.cancelled))
                    }
                }
            }
            return
        }

        DispatchQueue.main.async { [weak self] in
            guard let self else {
                completion(.failure(ZoteroActionError.cancelled))
                return
            }
            self.promptForZoteroAuthentication(requiredBy: nil, gateToken: gateToken, completion: completion)
        }
    }

    private func applyZoteroAuthSuccess(apiKey: String, info: ZoteroKeyInfo) {
        persistZoteroAPIKey(apiKey)
        AppSettingsStore.shared.update { s in
            s.zotero.userID = info.userID
            s.zotero.username = info.username
            if s.zotero.libraryType == .user && s.zotero.libraryID.isEmpty {
                s.zotero.libraryID = info.userID
                s.zotero.libraryName = info.username.isEmpty ? "Personal Library" : info.username
            }
        }
    }

    private func markZoteroVerifiedSession(rawKey: String, requestKey: String, info: ZoteroKeyInfo) {
        zoteroVerifiedKeyFingerprint = zoteroAPIKeyFingerprint(rawKey)
        zoteroVerifiedKeyInfo = info
        zoteroVerifiedRequestKey = requestKey
    }

    private func clearZoteroVerifiedSession() {
        zoteroVerifiedKeyFingerprint = nil
        zoteroVerifiedKeyInfo = nil
        zoteroVerifiedRequestKey = nil
    }

    private func isZoteroAuthGateTokenCurrent(_ token: Int) -> Bool {
        token == zoteroAuthGateToken
    }

    private func isZoteroInvalidKeyError(_ error: Error) -> Bool {
        guard let apiError = error as? ZoteroAPIError else { return false }
        if apiError.statusCode == 403 { return true }
        return apiError.message.localizedCaseInsensitiveContains("invalid key")
    }

    private func presentZoteroAuthSuccessAlert(completion: @escaping () -> Void) {
        guard let window else {
            completion()
            return
        }
        let alert = NSAlert()
        alert.messageText = "Zotero Connected"
        alert.informativeText = "Your Zotero API key was verified successfully.\nYou can now save items to Zotero."
        alert.addButton(withTitle: "OK")
        alert.beginSheetModal(for: window) { _ in
            completion()
        }
    }

    private func presentZoteroInvalidKeyAlert(onRetry: @escaping () -> Void,
                                              onCancel: @escaping () -> Void) {
        guard let window else {
            onCancel()
            return
        }
        let alert = NSAlert()
        alert.messageText = "Zotero Connection Failed"
        alert.informativeText = "Zotero API error (403): Invalid API key.\n\nPlease check the key and try again."
        alert.addButton(withTitle: "Retry")
        alert.addButton(withTitle: "Cancel")
        alert.beginSheetModal(for: window) { response in
            if response == .alertFirstButtonReturn {
                onRetry()
            } else {
                onCancel()
            }
        }
    }

    private func presentZoteroNetworkErrorAlert() {
        guard let window else { return }
        let alert = NSAlert()
        alert.messageText = "Zotero Connection Failed"
        alert.informativeText = "Unable to connect to Zotero.\nPlease check your network connection and try again."
        alert.addButton(withTitle: "OK")
        alert.beginSheetModal(for: window, completionHandler: nil)
    }

    private func promptForZoteroAuthentication(requiredBy _: Error?,
                                               gateToken: Int,
                                               completion: @escaping (Result<ZoteroAuthSession, Error>) -> Void) {
        guard let window else {
            completion(.failure(ZoteroActionError.cancelled))
            return
        }
        if zoteroAuthAlert != nil {
            completion(.failure(ZoteroActionError.cancelled))
            return
        }

        let alert = NSAlert()
        alert.messageText = "Zotero API Key Required"
        alert.informativeText = """
Paste your Zotero API key to continue.
You can create a key at zotero.org/settings/keys.
"""

        let placeholderButton = alert.addButton(withTitle: " ")
        placeholderButton.isHidden = true
        placeholderButton.isEnabled = false
        placeholderButton.keyEquivalent = ""

        let accessoryWidth: CGFloat = 420
        let accessoryHeight: CGFloat = 66
        let accessory = NSView(frame: NSRect(x: 0, y: 0, width: accessoryWidth, height: accessoryHeight))

        let apiField = NSTextField(frame: NSRect(x: 0, y: accessoryHeight - 26, width: accessoryWidth, height: 22))
        apiField.isEditable = true
        apiField.isSelectable = true
        apiField.isEnabled = true
        apiField.usesSingleLineMode = true
        apiField.cell?.isScrollable = true
        apiField.isAutomaticTextCompletionEnabled = false
        apiField.focusRingType = .default
        apiField.target = self
        apiField.action = #selector(onZoteroAuthConnect(_:))
        apiField.stringValue = resolvedZoteroAPIKey() ?? ""
        accessory.addSubview(apiField)

        let buttonWidth: CGFloat = 96
        let buttonHeight: CGFloat = 28
        let buttonSpacing: CGFloat = 8
        let buttonY: CGFloat = 0
        let connectButton = NSButton(title: "Connect", target: self, action: #selector(onZoteroAuthConnect(_:)))
        connectButton.bezelStyle = .rounded
        connectButton.keyEquivalent = "\r"
        connectButton.frame = NSRect(x: accessoryWidth - buttonWidth,
                                     y: buttonY,
                                     width: buttonWidth,
                                     height: buttonHeight)
        accessory.addSubview(connectButton)

        let cancelButton = NSButton(title: "Cancel", target: self, action: #selector(onZoteroAuthCancel(_:)))
        cancelButton.bezelStyle = .rounded
        cancelButton.keyEquivalent = "\u{1b}"
        cancelButton.frame = NSRect(x: accessoryWidth - (buttonWidth * 2) - buttonSpacing,
                                    y: buttonY,
                                    width: buttonWidth,
                                    height: buttonHeight)
        accessory.addSubview(cancelButton)

        alert.accessoryView = accessory
        let alertWindow = alert.window
        alertWindow.initialFirstResponder = apiField

        zoteroAuthAlert = alert
        zoteroAuthCompletion = completion
        zoteroAuthKeyField = apiField
        zoteroAuthConnectButton = connectButton
        zoteroAuthCancelButton = cancelButton
        zoteroAuthDidFinish = false
        zoteroAuthIsAuthenticating = false
        zoteroAuthPromptGateToken = gateToken
        zoteroAuthDelayCompletion = false

        alert.beginSheetModal(for: window) { [weak self] _ in
            guard let self else { return }
            if self.zoteroAuthDidFinish {
                if !self.zoteroAuthDelayCompletion {
                    self.cleanupZoteroAuthPrompt()
                }
                return
            }
            self.cleanupZoteroAuthPrompt()
            completion(.failure(ZoteroActionError.cancelled))
        }
        DispatchQueue.main.async {
            alertWindow.makeFirstResponder(apiField)
            apiField.selectText(nil)
        }
    }

    private func finishZoteroAuthPrompt(_ result: Result<ZoteroAuthSession, Error>, force: Bool = false) {
        if zoteroAuthDidFinish && !force { return }
        zoteroAuthDidFinish = true
        let completion = zoteroAuthCompletion
        if let alert = zoteroAuthAlert, let parent = alert.window.sheetParent {
            parent.endSheet(alert.window)
        } else {
            zoteroAuthAlert?.window.close()
        }
        if let completion {
            DispatchQueue.main.async {
                completion(result)
            }
        }
        zoteroAuthDelayCompletion = false
        cleanupZoteroAuthPrompt()
    }

    private func cleanupZoteroAuthPrompt() {
        zoteroAuthAlert = nil
        zoteroAuthCompletion = nil
        zoteroAuthKeyField = nil
        zoteroAuthConnectButton = nil
        zoteroAuthCancelButton = nil
        zoteroAuthDidFinish = false
        zoteroAuthIsAuthenticating = false
        zoteroAuthPromptGateToken = 0
        zoteroAuthDelayCompletion = false
    }

    private func setZoteroAuthPromptBusy(_ busy: Bool) {
        zoteroAuthIsAuthenticating = busy
        zoteroAuthConnectButton?.isEnabled = !busy
        zoteroAuthCancelButton?.isEnabled = !busy
        zoteroAuthKeyField?.isEnabled = !busy
    }

    @objc private func onZoteroAuthConnect(_ sender: Any?) {
        guard !zoteroAuthIsAuthenticating else { return }
        guard let apiField = zoteroAuthKeyField else { return }
        let rawInput = apiField.stringValue
        let trimmedKey = rawInput.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmedKey.isEmpty {
            NSSound.beep()
            apiField.window?.makeFirstResponder(apiField)
            return
        }
        logZoteroAPIKeyDiagnostics(context: "auth_prompt_submit", key: rawInput)
        setZoteroAuthPromptBusy(true)
        persistZoteroAPIKey(trimmedKey)
        fetchZoteroKeyInfoWithFallback(rawKey: trimmedKey, userIDHint: nil, context: "auth_prompt") { [weak self] result in
            DispatchQueue.main.async {
                guard let self else { return }
                guard self.zoteroAuthAlert != nil else { return }
                guard self.isZoteroAuthGateTokenCurrent(self.zoteroAuthPromptGateToken) else { return }
                self.setZoteroAuthPromptBusy(false)
                switch result {
                case .success(let auth):
                    self.applyZoteroAuthSuccess(apiKey: trimmedKey, info: auth.info)
                    self.markZoteroVerifiedSession(rawKey: trimmedKey, requestKey: auth.apiKey, info: auth.info)
                    let session = ZoteroAuthSession(apiKey: auth.apiKey, info: auth.info, gateToken: self.zoteroAuthPromptGateToken)
                    self.zoteroAuthDidFinish = true
                    self.zoteroAuthDelayCompletion = true
                    if let alert = self.zoteroAuthAlert, let parent = alert.window.sheetParent {
                        parent.endSheet(alert.window)
                    } else {
                        self.zoteroAuthAlert?.window.close()
                    }
                    self.presentZoteroAuthSuccessAlert {
                        self.finishZoteroAuthPrompt(.success(session), force: true)
                    }
                case .failure(let error):
                    if self.isZoteroInvalidKeyError(error) {
                        self.clearZoteroVerifiedSession()
                        self.presentZoteroInvalidKeyAlert(onRetry: {
                            apiField.window?.makeFirstResponder(apiField)
                            apiField.selectText(nil)
                        }, onCancel: {
                            self.finishZoteroAuthPrompt(.failure(ZoteroActionError.cancelled), force: true)
                        })
                    } else {
                        self.presentZoteroNetworkErrorAlert()
                        apiField.window?.makeFirstResponder(apiField)
                        apiField.selectText(nil)
                    }
                }
            }
        }
    }

    @objc private func onZoteroAuthCancel(_ sender: Any?) {
        finishZoteroAuthPrompt(.failure(ZoteroActionError.cancelled), force: true)
    }

    private func openZoteroSettingsTab() {
        SettingsWindowController.shared.openSettings(nil)
        guard let tabVC = SettingsWindowController.shared.window?.contentViewController as? NSTabViewController else {
            return
        }
        if let idx = tabVC.tabViewItems.firstIndex(where: { $0.label == "Zotero" }) {
            tabVC.selectedTabViewItemIndex = idx
        }
    }

    private func ensureZoteroLibrarySelection(apiKey: String,
                                              keyInfo: ZoteroKeyInfo,
                                              gateToken: Int,
                                              completion: @escaping (Result<ZoteroLibrary, Error>) -> Void) {
        guard isZoteroAuthGateTokenCurrent(gateToken) else {
            completion(.failure(ZoteroActionError.cancelled))
            return
        }
        if let library = zoteroLibrarySelection(for: nil) {
            completion(.success(library))
            return
        }
        promptForZoteroLibrarySelection(apiKey: apiKey, keyInfo: keyInfo, gateToken: gateToken, completion: completion)
    }

    private func promptForZoteroLibrarySelection(apiKey: String,
                                                 keyInfo: ZoteroKeyInfo,
                                                 gateToken: Int,
                                                 completion: @escaping (Result<ZoteroLibrary, Error>) -> Void) {
        ZoteroAPIClient.fetchLibraries(apiKey: apiKey, userID: keyInfo.userID, username: keyInfo.username) { result in
            DispatchQueue.main.async { [weak self] in
                guard let self else { return }
                guard self.isZoteroAuthGateTokenCurrent(gateToken) else {
                    completion(.failure(ZoteroActionError.cancelled))
                    return
                }
                switch result {
                case .failure(let error):
                    completion(.failure(error))
                case .success(let libraries):
                    guard !libraries.isEmpty else {
                        completion(.failure(ZoteroAPIError(message: "No Zotero libraries available.", statusCode: nil)))
                        return
                    }
                    if libraries.count == 1, let library = libraries.first {
                        AppSettingsStore.shared.update { s in
                            s.zotero.libraryType = library.type
                            s.zotero.libraryID = library.id
                            s.zotero.libraryName = library.name
                        }
                        completion(.success(library))
                        return
                    }

                    guard let window else {
                        completion(.failure(ZoteroActionError.cancelled))
                        return
                    }

                    let alert = NSAlert()
                    alert.messageText = "Choose Zotero Library"
                    alert.informativeText = """
Pick the library where items should be saved.
Personal Library is your own Zotero library. Group libraries are shared.
This choice is remembered and can be changed later in Settings.
Click Continue to confirm or Cancel to stop saving.
"""
                    alert.addButton(withTitle: "Continue")
                    alert.addButton(withTitle: "Cancel")

                    let popupWidth: CGFloat = 360
                    let popupHeight: CGFloat = 26
                    let labelHeight: CGFloat = 16
                    let verticalGap: CGFloat = 6

                    let popup = NSPopUpButton(frame: NSRect(x: 0, y: 0, width: popupWidth, height: popupHeight), pullsDown: false)
                    for library in libraries {
                        popup.addItem(withTitle: library.name)
                        popup.lastItem?.representedObject = library
                    }
                    popup.focusRingType = .default

                    let label = NSTextField(labelWithString: "Library")
                    label.font = NSFont.systemFont(ofSize: 12.5, weight: .regular)
                    label.frame = NSRect(x: 0, y: popupHeight + verticalGap, width: popupWidth, height: labelHeight)

                    let containerHeight = labelHeight + verticalGap + popupHeight
                    let container = NSView(frame: NSRect(x: 0, y: 0, width: popupWidth, height: containerHeight))
                    container.addSubview(label)
                    container.addSubview(popup)

                    alert.accessoryView = container
                    let alertWindow = alert.window
                    alertWindow.initialFirstResponder = popup

                    if popup.selectedItem == nil {
                        popup.selectItem(at: 0)
                    }

                    alert.beginSheetModal(for: window) { response in
                        guard self.isZoteroAuthGateTokenCurrent(gateToken) else {
                            completion(.failure(ZoteroActionError.cancelled))
                            return
                        }
                        guard response == .alertFirstButtonReturn else {
                            completion(.failure(ZoteroActionError.cancelled))
                            return
                        }
                        if let library = popup.selectedItem?.representedObject as? ZoteroLibrary {
                            AppSettingsStore.shared.update { s in
                                s.zotero.libraryType = library.type
                                s.zotero.libraryID = library.id
                                s.zotero.libraryName = library.name
                            }
                            completion(.success(library))
                        } else {
                            completion(.failure(ZoteroAPIError(message: "No library selected.", statusCode: nil)))
                        }
                    }
                    DispatchQueue.main.async {
                        alertWindow.makeFirstResponder(popup)
                    }
                }
            }
        }
    }

    private func promptForZoteroCollection(apiKey: String,
                                           library: ZoteroLibrary,
                                           gateToken: Int,
                                           completion: @escaping (Result<ZoteroCollection?, Error>) -> Void) {
        guard isZoteroAuthGateTokenCurrent(gateToken) else {
            completion(.failure(ZoteroActionError.cancelled))
            return
        }
        ZoteroAPIClient.fetchCollections(apiKey: apiKey, library: library) { result in
            DispatchQueue.main.async { [weak self] in
                guard let self else { return }
                guard self.isZoteroAuthGateTokenCurrent(gateToken) else {
                    completion(.failure(ZoteroActionError.cancelled))
                    return
                }
                switch result {
                case .failure(let error):
                    completion(.failure(error))
                case .success(let collections):
                    guard !collections.isEmpty else {
                        completion(.success(nil))
                        return
                    }
                    let zoteroSettings = AppSettingsStore.shared.current.zotero
                    if !zoteroSettings.promptForCollectionsOnSave {
                        let defaultKey = zoteroSettings.defaultCollectionKey.trimmingCharacters(in: .whitespacesAndNewlines)
                        if defaultKey.isEmpty {
                            completion(.success(nil))
                            return
                        }
                        if let match = collections.first(where: { $0.key == defaultKey }) {
                            AppSettingsStore.shared.update { s in
                                s.zotero.lastCollectionKey = match.key
                            }
                            completion(.success(match))
                            return
                        }
                    }
                    if collections.count == 1, let collection = collections.first {
                        AppSettingsStore.shared.update { s in
                            s.zotero.lastCollectionKey = collection.key
                        }
                        completion(.success(collection))
                        return
                    }

                    guard let window else {
                        completion(.failure(ZoteroActionError.cancelled))
                        return
                    }

                    let display = collectionDisplayNames(for: collections)
                    guard !display.isEmpty else {
                        completion(.failure(ZoteroAPIError(message: "No Zotero collections were returned for \(library.name). Make sure your API key has read access to this library and that it contains collections.", statusCode: nil)))
                        return
                    }
                    let alert = NSAlert()
                    alert.messageText = "Choose Zotero Collection"
                    alert.informativeText = """
Choose the collection (folder) where this item should be saved.

Your default collection is preselected when set; otherwise your last used collection is preselected.

Click Continue to save to the selected collection or Cancel to stop saving.
"""
                    alert.addButton(withTitle: "Continue")
                    alert.addButton(withTitle: "Cancel")

                    let popupWidth: CGFloat = 360
                    let popupHeight: CGFloat = 26
                    let labelHeight: CGFloat = 16
                    let verticalGap: CGFloat = 6

                    let popup = NSPopUpButton(frame: NSRect(x: 0, y: 0, width: popupWidth, height: popupHeight), pullsDown: false)
                    for entry in display {
                        popup.addItem(withTitle: entry.displayName)
                        popup.lastItem?.representedObject = entry.collection
                    }
                    popup.focusRingType = .default

                    let label = NSTextField(labelWithString: "Collection")
                    label.font = NSFont.systemFont(ofSize: 12.5, weight: .regular)
                    label.frame = NSRect(x: 0, y: popupHeight + verticalGap, width: popupWidth, height: labelHeight)

                    let containerHeight = labelHeight + verticalGap + popupHeight
                    let container = NSView(frame: NSRect(x: 0, y: 0, width: popupWidth, height: containerHeight))
                    container.addSubview(label)
                    container.addSubview(popup)

                    alert.accessoryView = container
                    let alertWindow = alert.window
                    alertWindow.initialFirstResponder = popup

                    let preferredKey = zoteroSettings.defaultCollectionKey.isEmpty
                        ? zoteroSettings.lastCollectionKey
                        : zoteroSettings.defaultCollectionKey
                    if let idx = display.firstIndex(where: { $0.collection.key == preferredKey }) {
                        popup.selectItem(at: idx)
                    } else if popup.selectedItem == nil {
                        popup.selectItem(at: 0)
                    }

                    alert.beginSheetModal(for: window) { response in
                        guard self.isZoteroAuthGateTokenCurrent(gateToken) else {
                            completion(.failure(ZoteroActionError.cancelled))
                            return
                        }
                        guard response == .alertFirstButtonReturn else {
                            completion(.failure(ZoteroActionError.cancelled))
                            return
                        }
                        if let collection = popup.selectedItem?.representedObject as? ZoteroCollection {
                            AppSettingsStore.shared.update { s in
                                s.zotero.lastCollectionKey = collection.key
                            }
                            completion(.success(collection))
                        } else {
                            completion(.failure(ZoteroAPIError(message: "No collection selected.", statusCode: nil)))
                        }
                    }
                    DispatchQueue.main.async {
                        alertWindow.makeFirstResponder(popup)
                    }
                }
            }
        }
    }

    private func collectionDisplayNames(for collections: [ZoteroCollection]) -> [(collection: ZoteroCollection, displayName: String)] {
        var map: [String: ZoteroCollection] = [:]
        for collection in collections {
            map[collection.key] = collection
        }
        func buildName(_ collection: ZoteroCollection) -> String {
            var names: [String] = [collection.name]
            var parentKey = collection.parentKey
            var visited: Set<String> = []
            while let key = parentKey, let parent = map[key], !visited.contains(key) {
                visited.insert(key)
                names.insert(parent.name, at: 0)
                parentKey = parent.parentKey
            }
            return names.joined(separator: " / ")
        }
        var out: [(collection: ZoteroCollection, displayName: String)] = []
        for collection in collections {
            out.append((collection, buildName(collection)))
        }
        return out.sorted(by: {
            $0.displayName.localizedCaseInsensitiveCompare($1.displayName) == .orderedAscending
        })
    }

    private func findExistingZoteroItem(apiKey: String,
                                        library: ZoteroLibrary,
                                        descriptor: ZoteroPublicationDescriptor,
                                        completion: @escaping (Result<ZoteroItem?, Error>) -> Void) {
        if let record = ZoteroSavedItemStore.shared.record(for: descriptor.stableID),
           record.libraryType == library.type,
           record.libraryID == library.id {
            ZoteroAPIClient.fetchItem(apiKey: apiKey, library: library, itemKey: record.itemKey) { [weak self] result in
                guard let self else { return }
                switch result {
                case .success(let item):
                    completion(.success(item))
                case .failure(let error):
                    if let apiError = error as? ZoteroAPIError, apiError.statusCode == 404 {
                        ZoteroSavedItemStore.shared.remove(stableID: descriptor.stableID)
                        self.searchZoteroItem(apiKey: apiKey, library: library, descriptor: descriptor, completion: completion)
                    } else {
                        completion(.failure(error))
                    }
                }
            }
            return
        }
        searchZoteroItem(apiKey: apiKey, library: library, descriptor: descriptor, completion: completion)
    }

    private func searchZoteroItem(apiKey: String,
                                  library: ZoteroLibrary,
                                  descriptor: ZoteroPublicationDescriptor,
                                  completion: @escaping (Result<ZoteroItem?, Error>) -> Void) {
        let query = descriptor.doi ?? descriptor.arxivID ?? descriptor.title ?? ""
        if query.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            completion(.success(nil))
            return
        }
        ZoteroAPIClient.searchItems(apiKey: apiKey, library: library, query: query) { [weak self] result in
            guard let self else { return }
            switch result {
            case .failure(let error):
                completion(.failure(error))
            case .success(let items):
                let match = items.first { self.zoteroItemMatchesDescriptor($0, descriptor: descriptor) }
                completion(.success(match))
            }
        }
    }

    private func zoteroItemMatchesDescriptor(_ item: ZoteroItem, descriptor: ZoteroPublicationDescriptor) -> Bool {
        if let doi = descriptor.doi, !doi.isEmpty {
            let target = normalizeDOI(doi).lowercased()
            if let itemDOI = item.data["DOI"] as? String,
               normalizeDOI(itemDOI).lowercased() == target {
                return true
            }
        }
        if let arxivID = descriptor.arxivID?.lowercased() {
            if let archiveLocation = item.data["archiveLocation"] as? String,
               archiveLocation.lowercased() == arxivID {
                return true
            }
            if let url = item.data["url"] as? String,
               url.lowercased().contains(arxivID) {
                return true
            }
            if let extra = item.data["extra"] as? String,
               extra.lowercased().contains(arxivID) {
                return true
            }
        }
        if let title = descriptor.title?.trimmingCharacters(in: .whitespacesAndNewlines),
           let itemTitle = item.data["title"] as? String,
           !title.isEmpty,
           itemTitle.trimmingCharacters(in: .whitespacesAndNewlines).caseInsensitiveCompare(title) == .orderedSame {
            return true
        }
        return false
    }

    private func buildZoteroItemData(metadata: ZoteroResolvedMetadata,
                                     collection: ZoteroCollection?) -> [String: Any] {
        let doiURL = metadata.doi.map { "https://doi.org/\(normalizeDOI($0))" }
        var data: [String: Any] = [
            "itemType": metadata.itemType,
            "title": metadata.title,
            "creators": metadata.creators,
            "url": metadata.arxivURL ?? doiURL ?? ""
        ]
        if !metadata.date.isEmpty {
            data["date"] = metadata.date
        }
        if let abstract = metadata.abstractText, !abstract.isEmpty {
            data["abstractNote"] = abstract
        }
        if let doi = metadata.doi, !doi.isEmpty {
            data["DOI"] = normalizeDOI(doi)
        }
        if metadata.itemType == "preprint" {
            data["archive"] = "arXiv"
            if let arxivID = metadata.arxivID {
                data["archiveLocation"] = arxivID
            }
        }
        if let journal = metadata.journal, !journal.isEmpty {
            data["publicationTitle"] = journal
        }
        if let collection {
            data["collections"] = [collection.key]
        }
        return data
    }

    private func updateExistingZoteroItem(apiKey: String,
                                          library: ZoteroLibrary,
                                          item: ZoteroItem,
                                          metadata: ZoteroResolvedMetadata,
                                          collection: ZoteroCollection?,
                                          completion: @escaping (Result<String, Error>) -> Void) {
        var updated = item.data
        updated["itemType"] = metadata.itemType
        if !metadata.title.isEmpty && metadata.title != "Untitled" {
            updated["title"] = metadata.title
        }
        if !metadata.creators.isEmpty {
            updated["creators"] = metadata.creators
        }
        if !metadata.date.isEmpty {
            updated["date"] = metadata.date
        }
        if let doi = metadata.doi, !doi.isEmpty {
            updated["DOI"] = normalizeDOI(doi)
        }
        if let url = metadata.arxivURL, !url.isEmpty {
            updated["url"] = url
        } else if let doi = metadata.doi, !doi.isEmpty {
            updated["url"] = "https://doi.org/\(normalizeDOI(doi))"
        }
        if let abstract = metadata.abstractText, !abstract.isEmpty {
            updated["abstractNote"] = abstract
        }
        if metadata.itemType == "preprint" {
            updated["archive"] = "arXiv"
            if let arxivID = metadata.arxivID {
                updated["archiveLocation"] = arxivID
            }
        }
        if let journal = metadata.journal, !journal.isEmpty {
            updated["publicationTitle"] = journal
        }
        if let collection {
            var collections = updated["collections"] as? [String] ?? []
            if !collections.contains(collection.key) {
                collections.append(collection.key)
                updated["collections"] = collections
            }
        }
        ZoteroAPIClient.updateItem(apiKey: apiKey, library: library, item: item, updateData: updated) { result in
            switch result {
            case .success:
                completion(.success(item.key))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }

    private func attachPDFToZoteroItem(apiKey: String,
                                       keyInfo: ZoteroKeyInfo,
                                       library: ZoteroLibrary,
                                       parentKey: String,
                                       descriptor: ZoteroPublicationDescriptor,
                                       completion: @escaping (Result<Void, Error>) -> Void) {
        if let canUpload = keyInfo.fileAccess(for: library), !canUpload {
            DispatchQueue.main.async { [weak self] in
                self?.presentNonBlockingAlert(message: "Zotero PDF Upload Skipped",
                                              informative: "Your Zotero API key doesn't allow file access for this library. Enable \"Allow file access\" for the key (and group file access if saving to a group library) in Zotero settings to upload PDFs.")
            }
            completion(.success(()))
            return
        }
        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            guard let fileURL = self.exportAnnotatedPDFURL() else {
                completion(.failure(ZoteroAPIError(message: "No PDF available to upload.", statusCode: nil)))
                return
            }
            DispatchQueue.global(qos: .userInitiated).async {
                guard let data = try? Data(contentsOf: fileURL) else {
                    completion(.failure(ZoteroAPIError(message: "Failed to read PDF data.", statusCode: nil)))
                    return
                }
                let filename = fileURL.lastPathComponent.isEmpty ? "paper.pdf" : fileURL.lastPathComponent
                let md5 = md5Hex(data)

                let handleUploadError: (Error) -> Void = { [weak self] error in
                    if let apiError = error as? ZoteroAPIError, apiError.statusCode == 403 {
                        DispatchQueue.main.async {
                            self?.presentNonBlockingAlert(message: "Zotero PDF Upload Skipped",
                                                          informative: "Zotero rejected the PDF upload (403). Your API key likely lacks file access for this library. Enable \"Allow file access\" for the key (and group file access if saving to a group library) in Zotero settings to upload PDFs.")
                        }
                        completion(.success(()))
                        return
                    }
                    completion(.failure(error))
                }

                ZoteroAPIClient.fetchItemChildren(apiKey: apiKey, library: library, parentKey: parentKey) { result in
                    switch result {
                    case .failure(let error):
                        completion(.failure(error))
                    case .success(let children):
                        if let attachment = self.firstPDFAttachment(in: children) {
                            ZoteroAPIClient.uploadAttachment(apiKey: apiKey,
                                                             library: library,
                                                             attachmentKey: attachment.key,
                                                             filename: filename,
                                                             contentType: "application/pdf",
                                                             md5: md5,
                                                             data: data,
                                                             completion: { uploadResult in
                                                                switch uploadResult {
                                                                case .success:
                                                                    completion(.success(()))
                                                                case .failure(let error):
                                                                    handleUploadError(error)
                                                                }
                                                             })
                        } else {
                            let title = descriptor.title ?? "PDF"
                            ZoteroAPIClient.createAttachmentItem(apiKey: apiKey,
                                                                 library: library,
                                                                 parentKey: parentKey,
                                                                 title: title,
                                                                 filename: filename,
                                                                 contentType: "application/pdf") { createResult in
                                switch createResult {
                                case .failure(let error):
                                    completion(.failure(error))
                                case .success(let attachmentKey):
                                    ZoteroAPIClient.uploadAttachment(apiKey: apiKey,
                                                                     library: library,
                                                                     attachmentKey: attachmentKey,
                                                                     filename: filename,
                                                                     contentType: "application/pdf",
                                                                     md5: md5,
                                                                     data: data,
                                                                     completion: { uploadResult in
                                                                        switch uploadResult {
                                                                        case .success:
                                                                            completion(.success(()))
                                                                        case .failure(let error):
                                                                            handleUploadError(error)
                                                                        }
                                                                     })
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    private func firstPDFAttachment(in items: [ZoteroItem]) -> ZoteroItem? {
        for item in items {
            let contentType = (item.data["contentType"] as? String) ?? (item.data["mimeType"] as? String) ?? ""
            let filename = (item.data["filename"] as? String) ?? ""
            if contentType.lowercased() == "application/pdf" || filename.lowercased().hasSuffix(".pdf") {
                return item
            }
        }
        return nil
    }

    private func exportAnnotatedPDFURL() -> URL? {
        if let annotated = annotationController?.exportAnnotatedPDF() {
            return annotated
        }
        return pdfView.document?.documentURL
    }

    private func zoteroToolbarImage(pointSize: CGFloat, state: ZoteroButtonState) -> NSImage? {
        let ps = max(9, pointSize)
        let config = NSImage.SymbolConfiguration(pointSize: ps, weight: .semibold)
        let names: [String]
        switch state {
        case .save:
            names = ["tray.and.arrow.down", "square.and.arrow.down", "arrow.down.doc"]
        case .remove:
            names = ["trash", "trash.circle", "xmark.circle"]
        }
        for name in names {
            if let image = NSImage(systemSymbolName: name, accessibilityDescription: nil) {
                return image.withSymbolConfiguration(config)
            }
        }
        return nil
    }

    @objc private func sendCurrentViewerLinkByEmail() {
        reportUIEvent("button_press", details: ["button": "send_viewer_link"])
        guard let urlString = currentDisplayedArxivURLString()?.trimmingCharacters(in: .whitespacesAndNewlines),
              !urlString.isEmpty else {
            NSSound.beep()
            return
        }

        let fallbackSubject = currentDisplayedMailSubject()
        let context = emailTemplateContext(title: fallbackSubject, url: urlString)
        let subject = resolvedEmailSubject(fallback: fallbackSubject, context: context)
        let body = resolvedEmailBody(fallback: urlString, context: context)
        let toAddress = resolvedEmailToAddress()
        reportDocumentIO("email_compose",
                         documentID: reportingDocumentID(),
                         details: ["mode": "viewer_link"])
        composeEmail(subject: subject, body: body, toAddress: toAddress)
    }

    @objc private func shareCurrentPaperByEmail() {
        reportUIEvent("button_press", details: ["button": "share"])
        guard let idx = selectedFilteredIndex(), idx >= 0, idx < filtered.count else {
            NSSound.beep()
            return
        }

        let paper = filtered[idx]
        let canonical = ArxivShareURL.canonicalAbsURL(from: paper.url)
        let urlString = (canonical?.absoluteString ?? paper.url).trimmingCharacters(in: .whitespacesAndNewlines)

        guard !urlString.isEmpty else {
            NSSound.beep()
            return
        }

        let safeTitle = decodeTeXAccents(paper.title).trimmingCharacters(in: .whitespacesAndNewlines)
        let fallbackSubject = safeTitle.isEmpty ? "arXiv paper" : safeTitle
        let context = emailTemplateContext(title: fallbackSubject, url: urlString)
        let subject = resolvedEmailSubject(fallback: fallbackSubject, context: context)
        let fallbackBody = mailShareBody(recipientName: recipientNameFromAppleScript, arxivAbsURL: urlString)
        let body = resolvedEmailBody(fallback: fallbackBody, context: context)
        let toAddress = resolvedEmailToAddress()
        reportDocumentIO("email_compose",
                         documentID: reportingHash(urlString),
                         details: ["mode": "paper_share"])
        composeEmail(subject: subject, body: body, toAddress: toAddress)
    }

    private func updateRightAuxToggleButtonAppearance() {
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        defer { CATransaction.commit() }
        // Existing toolbar convention: subtle accent glow when a toggle is active.
        if rightAuxPanelVisible {
            rightPanelLeftEdgeButton.restingGlowColor = primaryAccentFillColor().withAlphaComponent(0.55)
        } else {
            rightPanelLeftEdgeButton.restingGlowColor = nil
        }
        rightPanelLeftEdgeButton.updateTint()
        // Avoid doing potentially expensive glass invalidation synchronously on the input path.
        DispatchQueue.main.async { [weak self] in
            self?.rightPanelLeftEdgeButton.invalidateLiquidGlass(reason: "right_aux_toggle")
        }
    }

    private func notePanelToggleForFlickerSuppression() {
        let now = CACurrentMediaTime()
        panelToggleFlickerSuppressionUntil = max(panelToggleFlickerSuppressionUntil, now + 0.35)
    }

    private func clampRightAuxDividerPosition(_ proposedPosition: CGFloat) -> CGFloat {
        // Divider between [rightCompositeContainer] and [rightAuxContainer].
        // When the chat panel is visible, enforce a minimum width equal to the sidebar's
        // Author&Year centering minimum. Otherwise allow full collapse.
        let total = rightSplitView.bounds.width
        let divider = rightSplitView.dividerThickness
        let available = max(0, total - divider)

        if !rightAuxPanelVisible {
            // Chat hidden: allow the divider to move anywhere within non-negative bounds.
            return max(0, min(proposedPosition, available))
        }

        let minAux = rightAuxMinWidthAllowable(innerTotalWidth: total)
        let maxAux = rightAuxMaxWidthAllowable(innerTotalWidth: total)
        let minAuxEffective = min(minAux, maxAux)
        let minPrimary = max(0, available - maxAux)
        let maxPrimary = max(0, available - minAuxEffective)
        return max(minPrimary, min(proposedPosition, maxPrimary))
    }

    private func rightAuxPanelWidth() -> CGFloat {
        guard rightAuxPanelVisible, rightSplitView.subviews.count >= 2 else { return 0 }
        let total = rightSplitView.bounds.width
        let divider = rightSplitView.dividerThickness
        let primary = rightCompositeContainer.frame.width
        return max(0, total - divider - primary)
    }

    private func rightAuxTargetWidth() -> CGFloat {
        let total = rightSplitView.bounds.width
        let divider = rightSplitView.dividerThickness
        guard total.isFinite, total > 0, divider.isFinite else { return 0 }

        let available = max(0, total - divider)
        let minAux = rightAuxPanelVisible ? rightAuxMinWidthAllowable(innerTotalWidth: total) : 0
        let maxAux = rightAuxMaxWidthAllowable(innerTotalWidth: total)
        let minAuxEffective = min(minAux, maxAux)
        // Open to the last-known width when possible; otherwise fall back to the absolute minimum.
        let stored = lastRightAuxPanelWidth > 0 ? lastRightAuxPanelWidth : minAuxEffective
        let desired = max(minAuxEffective, stored)
        return max(0, min(desired, min(available, maxAux)))
    }

    private func enforceRightAuxMinWidthIfNeeded(reason: String) {
        guard rightAuxPanelVisible else { return }
        guard !rightAuxTransitionInProgress else { return }
        let total = rightSplitView.bounds.width
        let divider = rightSplitView.dividerThickness
        guard total.isFinite, total > 0, divider.isFinite else { return }

        let available = max(0, total - divider)
        let minAux = rightAuxMinWidthAllowable(innerTotalWidth: total)
        let maxAux = rightAuxMaxWidthAllowable(innerTotalWidth: total)
        let minAuxEffective = min(minAux, maxAux)
        guard minAuxEffective > 0, available > 0 else { return }

        let currentAux = rightAuxPanelWidth()
        if currentAux + 0.5 < minAuxEffective {
            let targetPrimary = max(0, available - minAuxEffective)
            let clamped = clampRightAuxDividerPosition(targetPrimary)
            rightSplitView.setPosition(clamped, ofDividerAt: 0)
            rightSplitView.adjustSubviews()
            updateRightSplitDividerHandleFrame()
            layoutLog("right_aux_enforce_min reason=\(reason) auxW=\(Int(currentAux))->\(Int(rightAuxPanelWidth())) min=\(Int(minAuxEffective))")
        }
    }

    private func enforceRightAuxTargetWidthIfNeeded(reason: String) {
        guard rightAuxPanelVisible else { return }
        guard !rightAuxTransitionInProgress else { return }
        guard !rightSplitDividerDragActive else { return }
        // Avoid fighting the spring animation; it will land on its target.
        guard rightSplitDividerSpringTimer == nil else { return }

        let total = rightSplitView.bounds.width
        let divider = rightSplitView.dividerThickness
        guard total.isFinite, total > 0, divider.isFinite else { return }

        let targetAux = rightAuxTargetWidth()
        let available = max(0, total - divider)
        guard available > 0 else { return }

        let currentAux = rightAuxPanelWidth()
        if abs(currentAux - targetAux) >= 0.75 {
            let targetPrimary = max(0, available - targetAux)
            let clamped = clampRightAuxDividerPosition(targetPrimary)
            rightSplitView.setPosition(clamped, ofDividerAt: 0)
            rightSplitView.adjustSubviews()
            updateRightSplitDividerHandleFrame()
            layoutLog("right_aux_enforce_target reason=\(reason) auxW=\(Int(currentAux))->\(Int(rightAuxPanelWidth())) target=\(Int(targetAux))")
        }
    }

    private func ensureRightAuxCollapsedIfHidden() {
        guard !rightAuxPanelVisible, rightSplitView.subviews.count >= 2 else { return }
        let total = rightSplitView.bounds.width
        guard total > 2 else { return }
        let divider = rightSplitView.dividerThickness
        let collapsedPos = max(0, total - divider)
        rightSplitView.setPosition(collapsedPos, ofDividerAt: 0)
        rightSplitView.adjustSubviews()
    }

    private func kickstartRightAuxMotion(opening: Bool, recordStart: Bool = true) {
        if shouldReduceMotion { return }
        let direction: CGFloat = opening ? -1 : 1
        let nudge: CGFloat = 6
        rightContainer.wantsLayer = true
        if opening, rightAuxContainer.alphaValue < 0.01 {
            rightAuxContainer.alphaValue = 1
        }
        if let layer = rightContainer.layer {
            let anim = CABasicAnimation(keyPath: "transform.translation.x")
            anim.fromValue = 0
            anim.toValue = direction * nudge
            anim.duration = 0.06
            anim.timingFunction = CAMediaTimingFunction(name: .easeOut)
            anim.isAdditive = true
            anim.isRemovedOnCompletion = true
            layer.add(anim, forKey: "right_aux_kickstart")
        }
        if recordStart {
            AnimationGuard.recordKickstart("right_aux_toggle")
        }
    }

    private func setRightAuxPanelVisible(_ visible: Bool,
                                         animated: Bool,
                                         deferHeavyLayout: Bool = false) {
        applyRightAuxPanelVisible(visible, animated: animated, deferHeavyLayout: deferHeavyLayout)
    }

    private func applyRightAuxPanelVisible(_ visible: Bool,
                                           animated: Bool,
                                           deferHeavyLayout: Bool) {
        PerfLogger.begin("panel.right_aux_toggle")
        defer { PerfLogger.end("panel.right_aux_toggle") }
        let guardMeasure = AnimationGuard.beginMeasurement("right_aux.set_visible")
        defer { AnimationGuard.endMeasurement(guardMeasure, details: "visible=\(visible) animated=\(animated) defer=\(deferHeavyLayout)") }
        AnimationGuard.trace("right_aux_set_visible_entry", details: "visible=\(visible) animated=\(animated) defer=\(deferHeavyLayout)")
        lastRightAuxToggleTimestamp = CACurrentMediaTime()
        notePanelToggleForFlickerSuppression()
        guard visible != rightAuxPanelVisible else {
            updateRightAuxToggleButtonAppearance()
            return
        }
        reportStateTransition("annotations_panel_visibility", details: ["visible": "\(visible)", "animated": "\(animated)"])

        // Ensure we never carry over any in-flight spring/timer updates while toggling.
        // Also disable implicit layer actions so the split/handle/button updates apply immediately.
        cancelRightSplitDividerSpringAnimation()
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        defer { CATransaction.commit() }

        layoutLog("right_aux_toggle visible=\(visible) animated=\(animated) before outerLeft=\(Int(leftContainer.frame.width)) outerRight=\(Int(rightSplitContainer.frame.width)) innerTotal=\(Int(rightSplitView.bounds.width)) innerPrimary=\(Int(rightCompositeContainer.frame.width)) auxMounted=\(rightAuxContainer.superview != nil)")

        let reduce = shouldReduceMotion || !animated
        let showPreset: SpringPreset = .hoverBounce
        let hidePreset: SpringPreset = .panelTransition
        let auxContainer = rightAuxContainer
        rightAuxTransitionInProgress = true
        annotationsPanelController?.setRowHeightUpdatesSuppressed(true)

        func resetRightAuxTransform() {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            auxContainer.layer?.transform = CATransform3DIdentity
            CATransaction.commit()
        }

        if visible {
            // Mutual exclusivity: opening chat always hides the sidebar.
            if sidebarVisible {
                // Collapse the sidebar, but avoid blocking animation start.
                sidebarAnimator.kickstartImmediateMotion(show: false, recordStart: false)
                if deferHeavyLayout {
                    AnimationGuard.deferWork(label: "right_aux_hide_sidebar") { [weak self] in
                        self?.setSidebarVisible(false, animated: false, deferHeavyLayout: true)
                    }
                } else {
                    setSidebarVisible(false, animated: false, deferHeavyLayout: true)
                }
            }

            let outerTotal = splitView.bounds.width
            let outerDivider = splitView.dividerThickness

            rightAuxPanelVisible = true
	        if !deferHeavyLayout {
                updateWindowMinSizeForToolbarGapIfNeeded(reason: "right_aux_open")
            }
            rightAuxContainer.alphaValue = 1
            resetRightAuxTransform()
            updateRightAuxToggleButtonAppearance()

            if deferHeavyLayout && !reduce {
                kickstartRightAuxMotion(opening: true)
            }
            applyRightAuxOpenLayout(outerTotal: outerTotal,
                                    outerDivider: outerDivider,
                                    reduce: reduce,
                                    showPreset: showPreset,
                                    deferHeavyLayout: deferHeavyLayout)
            return
        }

        // Closing: animate collapsed, then hide so it consumes zero width and intercepts no events.
	    // Capture width before collapse so reopening restores it.
	    let preCloseWidth = rightAuxPanelWidth()
	    if preCloseWidth.isFinite, preCloseWidth > 0 {
            // Persist the user's chosen width (reopen will clamp to current min/max).
            lastRightAuxPanelWidth = preCloseWidth
            persistRightAuxWidth(preCloseWidth)
        }
        rightAuxPanelVisible = false
	    if !deferHeavyLayout {
            updateWindowMinSizeForToolbarGapIfNeeded(reason: "right_aux_close")
        }
        if reduce {
            rightAuxContainer.alphaValue = 0
        } else {
            rightAuxContainer.alphaValue = 1
        }
        resetRightAuxTransform()
        updateRightAuxToggleButtonAppearance()

        let total = rightSplitView.bounds.width
        let divider = rightSplitView.dividerThickness
        let collapsedPos = max(0, total - divider)
        animateRightSplitDivider(to: collapsedPos, preset: hidePreset, animated: !reduce, deferHeavyLayout: deferHeavyLayout) { [weak self] in
            guard let self else { return }
            self.rightAuxContainer.alphaValue = 0
            // Do the heavier follow-up work on the next tick so the collapse can present immediately.
            AnimationGuard.deferWork(label: "right_aux_close_post") { [weak self] in
                guard let self else { return }
                self.layoutLeftContainerSubviews()
                self.layoutRightPanelSubviews()
	            self.layoutViewerAnchoredHeaderControls()
                self.updateSplitDividerHandleFrame()
                self.updateRightSplitDividerHandleFrame()
                if deferHeavyLayout {
                    self.updateWindowMinSizeForToolbarGapIfNeeded(reason: "right_aux_close_deferred")
                    self.enforceSidebarWidthBounds(reason: "right_aux_close_deferred")
                }
                self.updateToolbarScaleForWindowSize(reason: "right_aux_toggle")
                self.rightAuxTransitionInProgress = false
                self.annotationsPanelController?.setRowHeightUpdatesSuppressed(false)
                layoutLog("right_aux_close_done innerPrimary=\(Int(self.rightCompositeContainer.frame.width)) auxAlpha=\(String(format: "%.2f", self.rightAuxContainer.alphaValue))")
            }
        }
    }

    private func applyRightAuxOpenLayout(outerTotal: CGFloat,
                                         outerDivider: CGFloat,
                                         reduce: Bool,
                                         showPreset: SpringPreset,
                                         deferHeavyLayout: Bool) {
        // Ensure the outer split view leaves enough space for the viewer + third panel.
        // Keep synchronous work minimal so the animation can be committed immediately.
        let minRight = deferHeavyLayout ? minOuterRightContainerWidthFast() : minOuterRightContainerWidth()
        let maxLeft = cappedSidebarMaxWidth(forPotential: outerTotal - outerDivider - minRight)
        if leftContainer.frame.width > maxLeft, !deferHeavyLayout {
            splitView.setPosition(maxLeft, ofDividerAt: 0)
            splitView.adjustSubviews()
            updateSplitDividerHandleFrame()
        }

        let total = rightSplitView.bounds.width
        let divider = rightSplitView.dividerThickness

        // First toggle after launch: open chat at twice the sidebar's initial visible width
        // (the Author&Year centering minimum). Seed `lastRightAuxPanelWidth` to this target
        // so resize observers enforcing `rightAuxTargetWidth()` do not momentarily snap to
        // the old minimum-width fallback.
        let available = max(0, total - divider)
        let maxAux = rightAuxMaxWidthAllowable(innerTotalWidth: total)
        let minAux = rightAuxMinWidthAllowable(innerTotalWidth: total)
        let minAuxEffective = min(minAux, maxAux)
        let firstOpenAux = min(available, maxAux, minAuxEffective * 2)
        if !didOpenRightAuxInThisSession {
            lastRightAuxPanelWidth = firstOpenAux
        }
        let targetAux = (!didOpenRightAuxInThisSession)
            ? firstOpenAux
            : rightAuxTargetWidth()
        didOpenRightAuxInThisSession = true
        let targetPos = clampRightAuxDividerPosition(max(0, total - divider - targetAux))
        animateRightSplitDivider(to: targetPos, preset: showPreset, animated: !reduce, deferHeavyLayout: deferHeavyLayout) { [weak self] in
            guard let self else { return }
            self.lastRightAuxPanelWidth = self.rightAuxPanelWidth()
            if self.lastRightAuxPanelWidth.isFinite, self.lastRightAuxPanelWidth > 0 {
                self.persistRightAuxWidth(self.lastRightAuxPanelWidth)
            }
            // Do the heavier follow-up work on the next tick so the divider move can present immediately.
            AnimationGuard.deferWork(label: "right_aux_open_post") { [weak self] in
                guard let self else { return }
                self.enforceRightAuxTargetWidthIfNeeded(reason: "open_fixup")
                self.layoutLeftContainerSubviews()
                self.layoutRightPanelSubviews()
                self.layoutViewerAnchoredHeaderControls()
                self.updateSplitDividerHandleFrame()
                self.updateRightSplitDividerHandleFrame()
                if deferHeavyLayout {
                    self.updateWindowMinSizeForToolbarGapIfNeeded(reason: "right_aux_open_deferred")
                    self.enforceSidebarWidthBounds(reason: "right_aux_open_deferred")
                }
                self.updateToolbarScaleForWindowSize(reason: "right_aux_toggle")
                self.rightAuxTransitionInProgress = false
                if self.rightAuxPanelVisible {
                    self.annotationsPanelController?.setRowHeightUpdatesSuppressed(false)
                    self.annotationsPanelController?.forceRowHeightRefresh()
                }
                layoutLog("right_aux_open_done innerPrimary=\(Int(self.rightCompositeContainer.frame.width)) auxW=\(Int(self.rightAuxPanelWidth()))")
            }
        }
    }

    private func cancelRightSplitDividerSpringAnimation() {
        rightSplitDividerSpringToken &+= 1
        rightSplitDividerSpringTimer?.invalidate()
        rightSplitDividerSpringTimer = nil
        rightSplitDividerSpringLayer.removeAllAnimations()
    }

    private func animateRightSplitDivider(to targetPosition: CGFloat,
                                         preset: SpringPreset,
                                         animated: Bool,
                                         deferHeavyLayout: Bool = false,
                                         completion: (() -> Void)? = nil) {
        cancelRightSplitDividerSpringAnimation()
        ensureDividerSpringDriverLayersAttached()
        let reduce = shouldReduceMotion || !animated
        if reduce {
            rightSplitView.setPosition(targetPosition, ofDividerAt: 0)
            rightSplitView.adjustSubviews()
            ChatLatencyProbe.shared.markAnimationCommitted()
            updateRightSplitDividerHandleFrame()
            if !deferHeavyLayout {
                rightAuxContainer.layoutSubtreeIfNeeded()
                rightAuxContentView.layoutSubtreeIfNeeded()
                layoutRightPanelSubviews(duringLiveResize: true)
                layoutViewerAnchoredHeaderControls()
            }
            AnimationGuard.markAnimationStart("right_aux_toggle")
            completion?()
            return
        }

        let from = rightCompositeContainer.frame.width
        // Immediate response: nudge divider toward target in the same runloop tick.
        let delta = targetPosition - from
        if abs(delta) > 0.5, !deferHeavyLayout {
            let nudgeMagnitude = max(2.0, min(18.0, abs(delta) * 0.08))
            let nudgedFrom = from + (delta >= 0 ? nudgeMagnitude : -nudgeMagnitude)
            rightSplitView.setPosition(nudgedFrom, ofDividerAt: 0)
            rightSplitView.adjustSubviews()
            updateRightSplitDividerHandleFrame()
            rightAuxContainer.layoutSubtreeIfNeeded()
            rightAuxContentView.layoutSubtreeIfNeeded()
            layoutRightPanelSubviews(duringLiveResize: true)
            layoutViewerAnchoredHeaderControls()
        }

        let fromAfterNudge = rightCompositeContainer.frame.width
        let spec = springSpec(for: preset)
        let spring = CASpringAnimation(keyPath: "position.x")
        spring.mass = spec.mass
        spring.stiffness = spec.stiffness
        spring.damping = spec.damping
        spring.initialVelocity = spec.initialVelocity
        spring.fromValue = fromAfterNudge
        spring.toValue = targetPosition
        spring.duration = min(spring.settlingDuration, spec.settleCap)
        spring.isRemovedOnCompletion = true

        rightSplitDividerSpringLayer.position = CGPoint(x: targetPosition, y: 0)
        rightSplitDividerSpringLayer.add(spring, forKey: "right_divider_spring")
        AnimationGuard.markAnimationStart("right_aux_toggle")
        ChatLatencyProbe.shared.markAnimationCommitted()

        let duration = spring.duration
        let startTime = CACurrentMediaTime()
        rightSplitDividerSpringToken &+= 1
        let token = rightSplitDividerSpringToken

        let timer = Timer(timeInterval: displayRefreshInterval(for: window),
                           repeats: true) { [weak self] timer in
            guard let self, token == self.rightSplitDividerSpringToken else {
                timer.invalidate()
                return
            }
            let now = CACurrentMediaTime()
            if now - startTime >= duration {
                timer.invalidate()
                self.rightSplitView.setPosition(targetPosition, ofDividerAt: 0)
                self.rightSplitView.adjustSubviews()
                self.updateRightSplitDividerHandleFrame()
                if !deferHeavyLayout {
                    self.rightAuxContainer.layoutSubtreeIfNeeded()
                    self.rightAuxContentView.layoutSubtreeIfNeeded()
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    self.layoutViewerAnchoredHeaderControls()
                }
                completion?()
                return
            }
            if let presentation = self.rightSplitDividerSpringLayer.presentation() {
                self.rightSplitView.setPosition(presentation.position.x, ofDividerAt: 0)
                self.rightSplitView.adjustSubviews()
                self.updateRightSplitDividerHandleFrame()
                if !deferHeavyLayout {
                    self.rightAuxContainer.layoutSubtreeIfNeeded()
                    self.rightAuxContentView.layoutSubtreeIfNeeded()
                    self.layoutRightPanelSubviews(duringLiveResize: true)
                    self.layoutViewerAnchoredHeaderControls()
                }
            }
        }
        rightSplitDividerSpringTimer = timer
        RunLoop.main.add(timer, forMode: .common)
    }

    @objc private func showSidebarMenu() {
        reportUIEvent("button_press", details: ["button": "sidebar_menu"])
        presentPageMenu(anchor: sidebarMenuButton)
    }

    @objc private func showPageMenu() {
        reportUIEvent("button_press", details: ["button": "page_menu"])
        presentPageMenu(anchor: pageMenuButton)
    }

    private func presentPageMenu(anchor: NSView) {
        let items = buildPageMenuItems()
        let activeIndex = max(0, min(currentPageIndex, max(0, paginator.pageCount - 1)))
        let selectedRow = menuRowIndex(forPageIndex: activeIndex, in: items)
        presentMenu(items: items, anchor: anchor, selectedRow: selectedRow) { [weak self] item in
            guard let self else { return }
            if let action = item.action, case .page(let pageIndex) = action {
                self.selectPage(pageIndex)
            }
        }
    }

    private func presentAnnotationMenu(for item: PDFAnnotationListItem, anchor: NSView) {
        let palette = annotationPaletteEntries()
        let targetStyle = annotationController?.annotationToggleTargetStyle(for: item) ?? .underline
        let toggleTitle = annotationController?.annotationToggleTitle(for: item) ?? "Convert to Underline"

        var items: [MenuItem] = []
        items.append(MenuItem(kind: .summary,
                              title: "Add to Note",
                              isEnabled: true,
                              isChecked: false,
                              action: .annotationEditText,
                              swatchColor: nil))
        items.append(MenuItem(kind: .action,
                              title: toggleTitle,
                              isEnabled: true,
                              isChecked: false,
                              action: .annotationConvertStyle(targetStyle),
                              swatchColor: nil))
        items.append(MenuItem(kind: .separator,
                              title: "",
                              isEnabled: false,
                              isChecked: false,
                              action: nil,
                              swatchColor: nil))
        for (index, entry) in palette.enumerated() {
            items.append(MenuItem(kind: .action,
                                  title: entry.name,
                                  isEnabled: true,
                                  isChecked: false,
                                  action: .annotationColor(index),
                                  swatchColor: entry.color))
        }
        items.append(MenuItem(kind: .separator,
                              title: "",
                              isEnabled: false,
                              isChecked: false,
                              action: nil,
                              swatchColor: nil))
        items.append(MenuItem(kind: .action,
                              title: "Edit Page Number",
                              isEnabled: true,
                              isChecked: false,
                              action: .annotationEditPage,
                              swatchColor: nil))
        items.append(MenuItem(kind: .separator,
                              title: "",
                              isEnabled: false,
                              isChecked: false,
                              action: nil,
                              swatchColor: nil))
        items.append(MenuItem(kind: .action,
                              title: "Delete",
                              isEnabled: true,
                              isChecked: false,
                              action: .annotationDelete,
                              swatchColor: nil))

        presentMenu(items: items, anchor: anchor, selectedRow: nil) { [weak self] menuItem in
            guard let self, let action = menuItem.action else { return }
            switch action {
            case .annotationColor(let index):
                guard index >= 0, index < palette.count else { return }
                let entry = palette[index]
                if let annotation = self.annotationController?.primaryAnnotation(for: item) {
                    let currentStyle = annotationMarkupStyle(for: annotation)
                    self.annotationController?.updateAnnotationAppearance(for: annotation,
                                                                          color: entry.color,
                                                                          style: currentStyle,
                                                                          source: "menu_color")
                } else {
                    annotationActionLog("menu_color_skipped reason=no_annotation item=\(item.stableID)")
                }
            case .annotationEditText:
                DispatchQueue.main.async { [weak self] in
                    self?.annotationsPanelController?.beginEditingComment(for: item)
                }
            case .annotationConvertStyle(let style):
                self.annotationController?.performAnnotationCommand(.convertStyle(style), for: item, source: "menu")
            case .annotationEditPage:
                self.promptEditAnnotationPageNumber(for: item)
            case .annotationDelete:
                self.annotationController?.performAnnotationCommand(.delete, for: item, source: "menu")
            case .page:
                break
            }
        }
    }

    private func promptEditAnnotationPageNumber(for item: PDFAnnotationListItem) {
        guard let window = self.window else { return }
        let alert = NSAlert()
        alert.messageText = "Edit Page Number"
        alert.informativeText = "Enter a page label for this annotation."

        let input = NSTextField(string: annotationPageLabelValue(from: item))
        input.placeholderString = "Page label"
        input.frame = NSRect(x: 0, y: 0, width: 240, height: 24)
        alert.accessoryView = input

        alert.addButton(withTitle: "OK")
        alert.addButton(withTitle: "Cancel")

        alert.beginSheetModal(for: window) { [weak self] response in
            guard response == .alertFirstButtonReturn else { return }
            self?.annotationController?.updateAnnotationGroupPageLabel(for: item, label: input.stringValue)
        }
    }

    private func annotationPageLabelValue(from item: PDFAnnotationListItem) -> String {
        let prefix = "Page "
        if item.pageLabel.hasPrefix(prefix) {
            return String(item.pageLabel.dropFirst(prefix.count))
        }
        return item.pageLabel
    }

    @objc private func stepToPreviousPage() {
        selectPage(currentPageIndex - 1)
    }

    @objc private func stepToNextPage() {
        selectPage(currentPageIndex + 1)
    }

    private func buildPageMenuItems() -> [MenuItem] {
        let count = max(0, paginator.pageCount)
        let activeIndex = max(0, min(currentPageIndex, max(0, count - 1)))

        guard count > 0 else { return [] }

        var items: [MenuItem] = []
        for i in 0..<count {
            let checked = (i == activeIndex)
            items.append(MenuItem(kind: .page,
                                  title: "Page \(i + 1)",
                                  isEnabled: true,
                                  isChecked: checked,
                                  action: .page(i),
                                  swatchColor: nil))
        }
        return items
    }

    private func menuRowIndex(forPageIndex index: Int, in items: [MenuItem]) -> Int? {
        items.firstIndex {
            guard $0.kind == .page, let action = $0.action else { return false }
            if case .page(let pageIndex) = action {
                return pageIndex == index
            }
            return false
        }
    }

    private func presentMenu(items: [MenuItem],
                             anchor: NSView,
                             selectedRow: Int?,
                             handler: @escaping (MenuItem) -> Void) {
        if !menuContainer.isHidden, menuAnchorView === anchor {
            setMenuVisible(false, animated: true)
            return
        }
        hoveredMenuRow = nil
        menuItems = items
        menuAnchorView = anchor
        menuSelectionHandler = handler
        menuTable.reloadData()
        if let selectedRow, selectedRow >= 0, selectedRow < items.count {
            menuTable.selectRowIndexes(IndexSet(integer: selectedRow), byExtendingSelection: false)
        } else {
            menuTable.deselectAll(nil)
        }
        layoutMenuPanel()
        setMenuVisible(true, animated: true)
    }

    @objc private func menuRowClicked() {
        let row = menuTable.clickedRow
        performMenuSelection(at: row)
    }

    private func performMenuSelection(at row: Int) {
        guard row >= 0, row < menuItems.count else { return }
        guard menuItems[row].isSelectable else { return }
        let item = menuItems[row]
        reportUIEvent("menu_selection", details: ["title": item.title,
                                                 "kind": "\(item.kind)",
                                                 "action": item.action.map { String(describing: $0) } ?? "none"])
        menuSelectionHandler?(item)
        setMenuVisible(false, animated: true)
    }

    private func moveMenuSelection(_ delta: Int) {
        let selectable = menuItems.enumerated().compactMap { $0.element.isSelectable ? $0.offset : nil }
        guard !selectable.isEmpty else { return }
        let currentRow = menuTable.selectedRow
        if let idx = selectable.firstIndex(of: currentRow) {
            let nextIndex = max(0, min(selectable.count - 1, idx + delta))
            let row = selectable[nextIndex]
            menuTable.selectRowIndexes(IndexSet(integer: row), byExtendingSelection: false)
            menuTable.scrollRowToVisible(row)
            return
        }

        let row = (delta >= 0) ? selectable.first! : selectable.last!
        menuTable.selectRowIndexes(IndexSet(integer: row), byExtendingSelection: false)
        menuTable.scrollRowToVisible(row)
    }

    private func activateMenuSelection() {
        performMenuSelection(at: menuTable.selectedRow)
    }

    private func selectPage(_ index: Int) {
        let clamped = max(0, min(index, max(0, paginator.pageCount - 1)))
        guard clamped != currentPageIndex else { return }
        currentPageIndex = clamped
        refreshSidebarPageContentWidthCache(reason: "page_select")
        updatePageControlTitle()
        updatePageStepperState()
        setHoveredTableRow(nil, animated: false)
        tableView.reloadData()
        DispatchQueue.main.async { [weak self] in
            self?.enforceSidebarWidthBounds(reason: "page_select")
        }
        let targetIndex = paginator.range(forPage: currentPageIndex).lowerBound
        if targetIndex >= 0, targetIndex < filtered.count {
            selectFilteredIndex(targetIndex, scroll: true, reason: "page-select")
        }
    }

    @objc private func suggestionClicked() {
        let row = suggestionsTable.clickedRow
        guard row >= 0, row < suggestions.count else { return }
        acceptSuggestion(at: row)
    }

    private func acceptSuggestion(at index: Int) {
        guard index >= 0, index < suggestions.count else { return }
        let suggestion = suggestions[index]
        if let filteredIndex = filteredIndex(for: suggestion.paperKey) {
            selectFilteredIndex(filteredIndex, scroll: true, reason: "suggestion")
        }
        setSuggestionsVisible(false, animated: true)
    }

    private func moveSuggestionSelection(_ delta: Int) {
        guard !suggestions.isEmpty else { return }
        let current = suggestionsTable.selectedRow
        let next: Int
        if current < 0 {
            next = delta > 0 ? 0 : (suggestions.count - 1)
        } else {
            next = max(0, min(suggestions.count - 1, current + delta))
        }
        suggestionsTable.selectRowIndexes(IndexSet(integer: next), byExtendingSelection: false)
        suggestionsTable.scrollRowToVisible(next)
        suggestionSelectionIndex = next
        refreshSuggestionTextColors()
    }

    private func acceptSuggestionSelection() {
        let row = suggestionsTable.selectedRow >= 0 ? suggestionsTable.selectedRow : 0
        acceptSuggestion(at: row)
    }

