    func cancelSplitDividerSpringAnimation() {
        splitDividerSpringToken &+= 1
        splitDividerSpringTimer?.invalidate()
        splitDividerSpringTimer = nil
        splitDividerSpringLayer.removeAllAnimations()
    }

    // Divider motion is driven by sampling a CALayer's presentation state.
    // That only advances reliably if the layer is attached to a live render tree.
    // If it's detached, `presentation()` can be nil and the divider/handle can appear
    // to move late (often snapping only at the end).
    private func ensureDividerSpringDriverLayersAttached() {
        guard let root = window?.contentView else { return }

        // Ensure we have a host layer to attach to.
        if root.layer == nil {
            root.wantsLayer = true
        }
        guard let host = root.layer else { return }

        if splitDividerSpringLayer.superlayer !== host {
            splitDividerSpringLayer.removeFromSuperlayer()
            splitDividerSpringLayer.bounds = CGRect(x: 0, y: 0, width: 1, height: 1)
            splitDividerSpringLayer.position = CGPoint(x: leftContainer.frame.width, y: 0)
            splitDividerSpringLayer.backgroundColor = NSColor.clear.cgColor
            splitDividerSpringLayer.opacity = 0
            host.addSublayer(splitDividerSpringLayer)
        }

        if rightSplitDividerSpringLayer.superlayer !== host {
            rightSplitDividerSpringLayer.removeFromSuperlayer()
            rightSplitDividerSpringLayer.bounds = CGRect(x: 0, y: 0, width: 1, height: 1)
            rightSplitDividerSpringLayer.position = CGPoint(x: rightCompositeContainer.frame.width, y: 0)
            rightSplitDividerSpringLayer.backgroundColor = NSColor.clear.cgColor
            rightSplitDividerSpringLayer.opacity = 0
            host.addSublayer(rightSplitDividerSpringLayer)
        }
    }

    func animateSplitViewDivider(to targetWidth: CGFloat,
                                            preset: SpringPreset,
                                            deferHeavyLayout: Bool = false,
                                            completion: (() -> Void)? = nil) {
        cancelSplitDividerSpringAnimation()
        ensureDividerSpringDriverLayersAttached()
        let reduce = shouldReduceMotion
        if reduce {
            splitView.setPosition(targetWidth, ofDividerAt: 0)
            splitView.adjustSubviews()
            updateSplitDividerHandleFrame()
            updateRightSplitDividerHandleFrame()
            if !deferHeavyLayout {
                leftContainer.layoutSubtreeIfNeeded()
                leftContentView.layoutSubtreeIfNeeded()
                layoutLeftContainerSubviews(duringDividerDrag: true)
            }
            AnimationGuard.markAnimationStart("sidebar_toggle")
            SidebarLatencyProbe.shared.markAnimationCommitted()
            completion?()
            return
        }

        let fromWidth = leftContainer.frame.width
        // Immediate response: nudge divider toward target in the same runloop tick.
        let delta = targetWidth - fromWidth
        if abs(delta) > 0.5, !deferHeavyLayout {
            let nudgeMagnitude = max(2.0, min(18.0, abs(delta) * 0.08))
            let nudgedFrom = fromWidth + (delta >= 0 ? nudgeMagnitude : -nudgeMagnitude)
            splitView.setPosition(nudgedFrom, ofDividerAt: 0)
            splitView.adjustSubviews()
            updateSplitDividerHandleFrame()
            updateRightSplitDividerHandleFrame()
            leftContainer.layoutSubtreeIfNeeded()
            leftContentView.layoutSubtreeIfNeeded()
            layoutLeftContainerSubviews(duringDividerDrag: true)
        }
        let fromAfterNudge = leftContainer.frame.width
        let spec = springSpec(for: preset)
        let spring = CASpringAnimation(keyPath: "position.x")
        spring.mass = spec.mass
        spring.stiffness = spec.stiffness
        spring.damping = spec.damping
        spring.initialVelocity = spec.initialVelocity
        spring.fromValue = fromAfterNudge
        spring.toValue = targetWidth
        spring.duration = min(spring.settlingDuration, spec.settleCap)
        spring.isRemovedOnCompletion = true

        splitDividerSpringLayer.position = CGPoint(x: targetWidth, y: 0)
        splitDividerSpringLayer.add(spring, forKey: "divider_spring")
        AnimationGuard.markAnimationStart("sidebar_toggle")
        SidebarLatencyProbe.shared.markAnimationCommitted()

        let duration = spring.duration
        let startTime = CACurrentMediaTime()
        splitDividerSpringToken &+= 1
        let token = splitDividerSpringToken

        let timer = Timer(timeInterval: displayRefreshInterval(for: window),
                           repeats: true) { [weak self] timer in
            guard let self, token == self.splitDividerSpringToken else {
                timer.invalidate()
                return
            }
            let now = CACurrentMediaTime()
            if now - startTime >= duration {
                timer.invalidate()
                self.splitView.setPosition(targetWidth, ofDividerAt: 0)
                self.splitView.adjustSubviews()
                self.updateSplitDividerHandleFrame()
                self.updateRightSplitDividerHandleFrame()
                if !deferHeavyLayout {
                    self.leftContainer.layoutSubtreeIfNeeded()
                    self.leftContentView.layoutSubtreeIfNeeded()
                    self.layoutLeftContainerSubviews(duringDividerDrag: true)
                }
                completion?()
                return
            }
            if let presentation = self.splitDividerSpringLayer.presentation() {
                self.splitView.setPosition(presentation.position.x, ofDividerAt: 0)
                self.splitView.adjustSubviews()
                self.updateSplitDividerHandleFrame()
                self.updateRightSplitDividerHandleFrame()
                if !deferHeavyLayout {
                    self.leftContainer.layoutSubtreeIfNeeded()
                    self.leftContentView.layoutSubtreeIfNeeded()
                    self.layoutLeftContainerSubviews(duringDividerDrag: true)
                }
            }
        }
        splitDividerSpringTimer = timer
        RunLoop.main.add(timer, forMode: .common)
    }

    private func setSidebarVisible(_ visible: Bool,
                                   animated: Bool,
                                   style: SidebarTransitionStyle = .standard,
                                   deferHeavyLayout: Bool = false) {
        PerfLogger.begin("panel.sidebar_toggle")
        defer { PerfLogger.end("panel.sidebar_toggle") }
        let guardMeasure = AnimationGuard.beginMeasurement("sidebar.set_visible")
        defer { AnimationGuard.endMeasurement(guardMeasure, details: "visible=\(visible) animated=\(animated) defer=\(deferHeavyLayout)") }
        AnimationGuard.trace("sidebar_set_visible_entry", details: "visible=\(visible) animated=\(animated) defer=\(deferHeavyLayout)")
        lastSidebarToggleTimestamp = CACurrentMediaTime()
        notePanelToggleForFlickerSuppression()
        programmaticSplitResizeWorkItem?.cancel()
        programmaticSplitResizeWorkItem = nil
        let wasVisible = sidebarVisible
        sidebarAnimator.cancelPendingCleanup()
        sidebarToggleDeferredWorkItem?.cancel()
        sidebarToggleDeferredWorkItem = nil
        sidebarToggleToken &+= 1
        let toggleToken = sidebarToggleToken
        sidebarTogglePreferClipOrigin = !visible
        captureSidebarTogglePDFSnapshot(token: toggleToken)
        let shouldDeferWork = deferHeavyLayout && animated && !shouldReduceMotion
        reportStateTransition("sidebar_visibility", details: ["visible": "\(visible)", "animated": "\(animated)", "style": "\(style)"])

        // Capture the current width before closing so reopen restores the last resized size.
        if !visible, wasVisible {
            let preCloseWidth = leftContainer.frame.width
            if preCloseWidth.isFinite, preCloseWidth > 12 {
                lastSidebarWidth = preCloseWidth
                if shouldDeferWork {
                    AnimationGuard.deferWork(label: "sidebar_persist_width_close") { [weak self] in
                        guard let self, self.sidebarVisible == visible else { return }
                        self.persistSidebarWidth(preCloseWidth)
                    }
                } else {
                    persistSidebarWidth(preCloseWidth)
                }
            }
        }

        // Mutual exclusivity: showing sidebar always hides chat.
        if visible, rightAuxPanelVisible {
            kickstartRightAuxMotion(opening: false, recordStart: false)
            if deferHeavyLayout {
                AnimationGuard.deferWork(label: "sidebar_toggle_hide_right_aux") { [weak self] in
                    self?.setRightAuxPanelVisible(false, animated: animated, deferHeavyLayout: true)
                }
            } else {
                setRightAuxPanelVisible(false, animated: animated, deferHeavyLayout: true)
            }
        }

        if !visible, style == .pill, sidebarVisible {
            let width = rightContainer.frame.width
            if width > 0 { lastRightPanelWidth = width }
        }
        sidebarVisible = visible
        if shouldDeferWork {
            AnimationGuard.deferWork(label: "sidebar_persist_visibility") { [weak self] in
                guard let self, self.sidebarVisible == visible else { return }
                self.persistSidebarVisibility(visible)
            }
        } else {
            persistSidebarVisibility(visible)
        }
        updateSidebarToggleIcon()
        uiLog("sidebar_toggle visible=\(visible) animated=\(animated)")
        if visible {
            let currentWidth = leftContainer.frame.width
            if currentWidth > 12 {
                lastSidebarWidth = currentWidth
                if shouldDeferWork {
                    AnimationGuard.deferWork(label: "sidebar_persist_width_open") { [weak self] in
                        guard let self, self.sidebarVisible == visible else { return }
                        self.persistSidebarWidth(currentWidth)
                    }
                } else {
                    persistSidebarWidth(currentWidth)
                }
            }
        }
        let shouldAnimateNow = animated && !shouldReduceMotion
        if deferHeavyLayout && shouldAnimateNow {
            sidebarAnimator.kickstartImmediateMotion(show: visible)
        }
        applySidebarVisibilityLayout(visible: visible,
                                     animated: animated,
                                     style: style,
                                     wasVisible: wasVisible,
                                     deferHeavyLayout: deferHeavyLayout,
                                     toggleToken: toggleToken)
    }

    private func applySidebarVisibilityLayout(visible: Bool,
                                              animated: Bool,
                                              style: SidebarTransitionStyle,
                                              wasVisible: Bool,
                                              deferHeavyLayout: Bool,
                                              toggleToken: UInt64) {
        let guardMeasure = AnimationGuard.beginMeasurement("sidebar.toggle_layout")
        defer { AnimationGuard.endMeasurement(guardMeasure, details: "visible=\(visible) animated=\(animated) defer=\(deferHeavyLayout)") }
        let total = splitView.bounds.width
        let divider = splitView.dividerThickness
        let minRight = deferHeavyLayout ? minOuterRightContainerWidthFast() : minOuterRightContainerWidth()
        let maxLeft = cappedSidebarMaxWidth(forPotential: total - divider - minRight)
        if visible, !wasVisible {
            // Toggle-open sizing: use last remembered width, clamped to the absolute minimum.
            let minLeft = deferHeavyLayout ? sidebarHardMinWidthFast() : desiredMinSidebarWidthForCurrentPage(maxLeft: maxLeft)
            if lastSidebarWidth <= 12 {
                lastSidebarWidth = minLeft
            } else {
                lastSidebarWidth = max(lastSidebarWidth, minLeft)
            }
        }
        let targetWidth: CGFloat = visible ? max(0, min(lastSidebarWidth, maxLeft)) : 0
        let reduce = shouldReduceMotion
        let shouldAnimate = animated && !reduce
        let shouldDeferWork = deferHeavyLayout && shouldAnimate
        if visible {
            if shouldDeferWork {
                AnimationGuard.deferWork(label: "sidebar_persist_width_target") { [weak self] in
                    guard let self, self.sidebarVisible == visible else { return }
                    self.persistSidebarWidth(targetWidth)
                }
                AnimationGuard.deferWork(label: "sidebar_page_stepper") { [weak self] in
                    self?.updatePageStepperState(triggerLayout: false)
                }
            } else {
                persistSidebarWidth(targetWidth)
                updatePageStepperState(triggerLayout: false)
            }
        }

        if !visible {
            allowSidebarCollapse = true
        }

        sidebarTransitionInProgress = true
        beginSplitResizeSuppression(token: toggleToken)

        cancelSplitDividerSpringAnimation()

        if visible {
            if rightPanelSplitModeActive {
                setRightPanelSplitMode(false, animated: shouldAnimate, preset: .soft, deferHeavyLayout: deferHeavyLayout)
            }
        } else {
            if style == .pill {
                setRightPanelSplitMode(true, animated: shouldAnimate, preset: .soft, deferHeavyLayout: deferHeavyLayout)
            } else if rightPanelSplitModeActive {
                setRightPanelSplitMode(false, animated: false, deferHeavyLayout: deferHeavyLayout)
            }
        }

        guard shouldAnimate else {
            splitView.setPosition(targetWidth, ofDividerAt: 0)
            splitView.adjustSubviews()
            AnimationGuard.markAnimationStart("sidebar_toggle_immediate")
            if !visible { allowSidebarCollapse = false }
            sidebarTransitionInProgress = false
            leftContainer.setAccessibilityHidden(!visible)
            updateSplitDividerHandleFrame()
            if deferHeavyLayout {
                layoutLeftContainerSubviews(duringDividerDrag: true)
                layoutRightPanelSubviews(duringLiveResize: true)
                updatePageStepperState(triggerLayout: false)
                updateRightSplitDividerHandleFrame()
                updateToolbarScaleForWindowSize(reason: "sidebar_toggle")
                scheduleSidebarTogglePostWork(visible: visible, token: toggleToken)
                return
            }
            layoutLeftContainerSubviews(duringDividerDrag: true)
            layoutRightPanelSubviews(duringLiveResize: true)
            updatePageStepperState(triggerLayout: false)
            updateRightSplitDividerHandleFrame()
            updateToolbarScaleForWindowSize(reason: "sidebar_toggle")
            refreshLeftLayoutAfterSidebarToggle(visible: visible, layoutAlreadyApplied: true)
            applySidebarTogglePDFSnapshotIfNeeded(token: toggleToken, preferClipOrigin: !visible)
            scheduleSidebarTogglePDFSnapshotClear(token: toggleToken)
            endSplitResizeSuppression(token: toggleToken)
            return
        }

        // Smooth slide with coordinated divider handling (via SidebarAnimator).
        sidebarAnimator.prepare(leftTargetWidth: targetWidth,
                               leftOpeningFromCollapsed: (!wasVisible && visible))

        sidebarAnimator.animateLeft(show: visible,
                                    animated: true,
                                    deferHeavyLayout: deferHeavyLayout,
                                    completion: { [weak self] in
            guard let self else { return }
            guard self.sidebarToggleToken == toggleToken else { return }
            if !visible { self.allowSidebarCollapse = false }
            self.sidebarTransitionInProgress = false
            self.leftContainer.setAccessibilityHidden(!visible)
            self.updateSplitDividerHandleFrame()
            if deferHeavyLayout {
                self.layoutLeftContainerSubviews(duringDividerDrag: true)
                self.layoutRightPanelSubviews(duringLiveResize: true)
                self.updatePageStepperState(triggerLayout: false)
                self.updateRightSplitDividerHandleFrame()
                self.updateToolbarScaleForWindowSize(reason: "sidebar_toggle")
                self.scheduleSidebarTogglePostWork(visible: visible, token: toggleToken)
            } else {
                self.layoutLeftContainerSubviews(duringDividerDrag: true)
                self.layoutRightPanelSubviews(duringLiveResize: true)
                self.updatePageStepperState(triggerLayout: false)
                self.updateRightSplitDividerHandleFrame()
                self.updateToolbarScaleForWindowSize(reason: "sidebar_toggle")
                self.refreshLeftLayoutAfterSidebarToggle(visible: visible, layoutAlreadyApplied: true)
                self.applySidebarTogglePDFSnapshotIfNeeded(token: toggleToken, preferClipOrigin: !visible)
                self.scheduleSidebarTogglePDFSnapshotClear(token: toggleToken)
                self.endSplitResizeSuppression(token: toggleToken)
            }
        },
                                    cleanup: { [weak self] in
            guard let self else { return }
            guard self.sidebarToggleToken == toggleToken else { return }
            self.applySidebarTogglePDFSnapshotIfNeeded(token: toggleToken, preferClipOrigin: !visible)
            self.scheduleSidebarTogglePDFSnapshotClear(token: toggleToken)
        })
    }

    private func updateSidebarStateFromSplit() {
        guard didApplyInitialSidebarLayout else { return }
        guard !sidebarTransitionInProgress else { return }
        let width = leftContainer.frame.width
        if width > 12 {
            sidebarVisible = true
            lastSidebarWidth = width
            persistSidebarWidth(width)
        } else {
            sidebarVisible = false
        }
        uiLog("sidebar_split_state width=\(Int(width)) visible=\(sidebarVisible)")
        persistSidebarVisibility(sidebarVisible)
        updateSidebarToggleIcon()
    }

    @objc private func navigateBack() {
        guard let target = nextHistoryIndex(from: selectionHistoryIndex, delta: -1) else {
            uiLog("history_nav back unavailable index=\(selectionHistoryIndex)")
            return
        }
        applyHistoryEntry(at: target, reason: "back")
    }

    @objc private func navigateForward() {
        guard let target = nextHistoryIndex(from: selectionHistoryIndex, delta: 1) else {
            uiLog("history_nav forward unavailable index=\(selectionHistoryIndex)")
            return
        }
        applyHistoryEntry(at: target, reason: "forward")
    }

    private func navigateToAnnotation(_ item: PDFAnnotationListItem) {
        guard let _ = pdfView.document else { return }
        if !isShowingPDF {
            showPDFPanel(animated: true)
        }
        let page = item.page
        let bounds = item.anchorBounds
        if rectIsUsable(bounds) {
            let destination = PDFDestination(page: page, at: NSPoint(x: bounds.minX, y: bounds.maxY))
            pdfView.go(to: destination)
        } else {
            pdfView.go(to: page)
        }
    }

    private func navigateAnnotations(delta: Int) {
        guard let controller = annotationsPanelController,
              let item = controller.selectAdjacentItem(delta: delta) else { return }
        navigateToAnnotation(item)
        annotationController?.openAnnotationGroup(for: item)
    }

	    func controlTextDidBeginEditing(_ obj: Notification) {
	        if obj.object as? NSSearchField === searchField {
	            searchFocused = true
                uiLog("search_focus begin")
	            suppressRowAnimations = true
	            refreshVisibleRowDepth(animated: false)
            updateSearchDepth(animated: true)
            updateSuggestions(for: normalizedSearchQuery(searchField.stringValue))
            if let editor = window?.fieldEditor(false, for: searchField) as? NSTextView {
                    let text = ToolbarForegroundTheme.shared.palette.primary
                editor.textColor = text
                editor.insertionPointColor = text
                var attrs = editor.typingAttributes
                attrs[.font] = currentSearchBarTheme().font
	                attrs[.foregroundColor] = text
	                attrs[.kern] = -0.15
	                editor.typingAttributes = attrs
	                logSearchDebug("fieldEditor active textColor=\(String(describing: editor.textColor)) alpha=\(editor.alphaValue)")
	            } else {
	                logSearchDebug("fieldEditor missing")
	            }
	        } else if obj.object as? NSSearchField === rightAuxAskField {
            rightAuxAskFocused = true
            updateRightAuxAskDepth(animated: true)
            if let editor = window?.fieldEditor(false, for: rightAuxAskField) as? NSTextView {
                let text = ToolbarForegroundTheme.shared.palette.primary
                editor.textColor = text
                editor.insertionPointColor = text
                var attrs = editor.typingAttributes
                attrs[.font] = leftRowTitleFont
                attrs[.foregroundColor] = text
                attrs[.kern] = -0.15
                editor.typingAttributes = attrs
            }
	        } else if obj.object as? NSSearchField === pdfFindField {
            pdfFindFocused = true
            updatePDFFindDepth(animated: true)
            updatePDFFindClearButtonLayout()
        }
    }

	    func controlTextDidEndEditing(_ obj: Notification) {
        if obj.object as? NSSearchField === searchField {
            searchFocused = false
            uiLog("search_focus end")
            suppressRowAnimations = false
            refreshVisibleRowDepth(animated: false)
            updateSearchDepth(animated: true)
            setSuggestionsVisible(false, animated: true)
            if searchAppliedToken == searchToken, searchAppliedToken > 0 {
                scheduleSearchFinalize(token: searchAppliedToken,
                                       reason: "search_end_editing",
                                       delayOverride: 0.0)
            }
        } else if obj.object as? NSSearchField === rightAuxAskField {
            rightAuxAskFocused = false
            updateRightAuxAskDepth(animated: true)
        } else if obj.object as? NSSearchField === pdfFindField {
            pdfFindFocused = false
            updatePDFFindDepth(animated: true)
            updatePDFFindClearButtonLayout()
        }
    }

    func controlTextDidChange(_ obj: Notification) {
        if obj.object as? NSSearchField === searchField {
            let raw = searchField.stringValue
            let isEmpty = raw.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            if isEmpty != searchFieldLastEmpty {
                updateSearchFieldIconColorForCurrentState()
            }
            SearchLatencyProbe.shared.markKeypress(source: "search_field", query: raw, window: window)
            SearchPerfLog.measure("search.textDidChange") {
                scheduleSearchUpdate(for: raw, reason: "typing", immediate: false)
            }
        } else if obj.object as? NSSearchField === rightAuxAskField {
            updateRightAuxAskDepth(animated: true)
        } else if obj.object as? NSSearchField === pdfFindField {
            pdfFindQueryDidChange()
        }
    }

    private func updateLeftTableHorizontalScrollerState(reason: String, suppress: Bool? = nil) {
        let shouldSuppress = suppress ?? (dividerDragActive || (window?.inLiveResize == true))
        if leftTableHorizontalScrollerSuppressed == shouldSuppress { return }
        leftTableHorizontalScrollerSuppressed = shouldSuppress

        let shouldShow = leftTableAllowsHorizontalScroller && !shouldSuppress
        tableScroll.hasHorizontalScroller = shouldShow
        tableScroll.horizontalScrollElasticity = shouldShow ? leftTableHorizontalElasticityDefault : .none
        if let scroller = tableScroll.horizontalScroller {
            scroller.alphaValue = shouldShow ? 1.0 : 0.0
        }
    }

            private func layoutLeftContainerSubviews(duringDividerDrag: Bool = false) {
            let guardMeasure = AnimationGuard.beginMeasurement("layout.left_container")
            defer { AnimationGuard.endMeasurement(guardMeasure) }
            PerfLogger.begin("layout.left_container")
            defer { PerfLogger.end("layout.left_container") }
            let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
            defer {
                if resizePerfEnabled {
                    let duration = monotonicNowNs() &- perfStart
                    ResizeLatencyProbe.shared.markLayoutPass(name: "left_layout", durationNs: duration)
                    ResizePerfTrace.shared.noteLayoutPass(name: "left", durationNs: duration)
                }
            }
            noteResizeLayoutEvent(name: "left_layout")
            defer { updateLeftCardBackgroundFrame() }
            let refreshFreeze = duringDividerDrag || (window?.inLiveResize == true)
            updateLeftTableHorizontalScrollerState(reason: "left_layout", suppress: refreshFreeze)
            if refreshFreeze {
                updateLeftPanelFreezeState(reason: "left_panel_resize")
            }
            // Keep the panel “bezel” stable under window resize and split-view drags.
            // This method lays out subviews using explicit frames, so we must ensure the
            // container bounds we read are current before computing insets.
            if !duringDividerDrag {
                PerfLogger.measure("autolayout.splitView.left") {
                    AnimationGuard.measure("autolayout.splitView.left") {
                        splitView.layoutSubtreeIfNeeded()
                    }
                }
                PerfLogger.measure("autolayout.leftContainer") {
                    AnimationGuard.measure("autolayout.leftContainer") {
                        leftContainer.layoutSubtreeIfNeeded()
                    }
                }
                PerfLogger.measure("autolayout.leftContentView") {
                    AnimationGuard.measure("autolayout.leftContentView") {
                        leftContentView.layoutSubtreeIfNeeded()
                    }
                }
            }
            updatePageStepperState(triggerLayout: false)
            // Apple-like inset padding inside bordered left panel (rows go full width).
            let bounds = leftContentView.bounds
	        let topInset = PANEL_INSET + searchContainerHeight + searchContainerGap
            // Give the leftContainer a visible “bezel”: inset the content glass (table + search).
            let rowInsetX: CGFloat = PANEL_INSET
            let w = max(1, bounds.width - (2 * rowInsetX))
	        let h = max(bounds.height - PANEL_INSET - topInset, 0)
	        let ib = NSRect(
	            x: bounds.minX + rowInsetX,
	            y: bounds.minY + PANEL_INSET,
	            width: w,
	            height: h
	        )

	        // If header bar is hidden, let the table fill the space and clear caches.
	        if leftHeaderBar.isHidden {
	            headerFramesFrozen = false
	            cachedHeaderBarFrame = .zero
	            cachedHeaderLabelFrame = .zero
	            cachedHeaderRuleFrame = .zero
                let showPageStepper = !pageStepperContainer.isHidden
                let reservedStepperHeight = showPageStepper ? (pageStepperHeight + pageStepperBottomInset) : 0
                tableScroll.frame = NSRect(x: ib.minX, y: ib.minY, width: w, height: h)
                updateTableBottomInset(showPageStepper: showPageStepper)
                if showPageStepper {
                    layoutPageStepper(in: ib, tableFrame: tableScroll.frame, reservedHeight: reservedStepperHeight)
                } else {
                    pageStepperContainer.frame = .zero
                }
                layoutSearchContainer(ensureLayout: !duringDividerDrag)
	            layoutLeftTableUnderlay(approximate: duringDividerDrag)
	            return
	        }

        // Compute header frames only when we have meaningful dimensions; freeze once computed.
        if !headerFramesFrozen || cachedHeaderBarFrame.width <= 0 || cachedHeaderBarFrame.height <= 0 {
            if w > 80 && h > 60 {
                let headerH: CGFloat = 26
                let ruleH: CGFloat = 1

	                let headerY = ib.maxY - headerH
	                cachedHeaderBarFrame = NSRect(x: ib.minX, y: headerY, width: w, height: headerH)
                    cachedHeaderLabelFrame = NSRect(x: leftRowTextInset, y: 3, width: w - (2 * leftRowTextInset), height: headerH - 6)
	                cachedHeaderRuleFrame = NSRect(x: ib.minX, y: headerY - ruleH, width: w, height: ruleH)
	                headerFramesFrozen = true
	            }
	        }

        // Use cached frames if available; otherwise fallback to current geometry.
        if cachedHeaderBarFrame.width > 0 && cachedHeaderBarFrame.height > 0 {
            leftHeaderBar.frame = cachedHeaderBarFrame
            leftHeaderLabel.frame = cachedHeaderLabelFrame
            leftHeaderRule.frame = cachedHeaderRuleFrame
        } else {
            let headerH: CGFloat = 26
	            let ruleH: CGFloat = 1
	            let headerY = ib.maxY - headerH
	            leftHeaderBar.frame = NSRect(x: ib.minX, y: headerY, width: w, height: headerH)
                leftHeaderLabel.frame = NSRect(x: leftRowTextInset, y: 3, width: w - (2 * leftRowTextInset), height: headerH - 6)
	            leftHeaderRule.frame = NSRect(x: ib.minX, y: headerY - ruleH, width: w, height: ruleH)
	        }

                updateLeftHeaderText()
                updateLeftHeaderEdgeGeometry()

                let headerH = leftHeaderBar.frame.height
                let ruleH = leftHeaderRule.frame.height
                let showPageStepper = !pageStepperContainer.isHidden
                let reservedStepperHeight = showPageStepper ? (pageStepperHeight + pageStepperBottomInset) : 0
                let tableHeight = max(0, h - headerH - ruleH)
                tableScroll.frame = NSRect(x: ib.minX, y: ib.minY, width: w, height: tableHeight)
                updateTableBottomInset(showPageStepper: showPageStepper)
                if showPageStepper {
                    layoutPageStepper(in: ib, tableFrame: tableScroll.frame, reservedHeight: reservedStepperHeight)
                } else {
                    pageStepperContainer.frame = .zero
                }
                layoutSearchContainer(ensureLayout: !duringDividerDrag)
		        layoutLeftTableUnderlay(approximate: duringDividerDrag)
		    }

    private func layoutPageStepper(in insetBounds: NSRect, tableFrame: NSRect, reservedHeight: CGFloat) {
        guard !pageStepperContainer.isHidden, reservedHeight > 0 else { return }

        let buttonSize = pageStepperButtonSize
        let height = pageStepperHeight
        let width = (2 * buttonSize) + pageStepperButtonSpacing + (2 * pageStepperHorizontalPadding)

        // Anchor the stepper to the bottom of the left card instead of near the header.
        let y = insetBounds.minY + pageStepperBottomInset
        let x = insetBounds.midX - (width / 2)
        let frame = NSRect(x: round(x), y: round(y), width: width, height: height)

        pageStepperContainer.frame = frame
        pageStepperBackground.frame = pageStepperContainer.bounds
        if let layer = pageStepperBackground.layer {
            let radius = height / 2
            layer.cornerRadius = radius
            if #available(macOS 10.13, *) {
                layer.cornerCurve = .continuous
            }
        }

        let buttonY = round((height - buttonSize) / 2)
        pagePrevButton.frame = NSRect(
            x: pageStepperHorizontalPadding,
            y: buttonY,
            width: buttonSize,
            height: buttonSize
        )
        pageNextButton.frame = NSRect(
            x: frame.width - pageStepperHorizontalPadding - buttonSize,
            y: buttonY,
            width: buttonSize,
            height: buttonSize
        )
    }

    private func updateTableBottomInset(showPageStepper: Bool) {
        let bottomInset = PANEL_INSET + (showPageStepper ? (pageStepperHeight + pageStepperBottomInset) : 0)
        tableScroll.contentInsets = NSEdgeInsets(top: PANEL_INSET, left: 0, bottom: bottomInset, right: 0)
    }

    private func leftListContentContract(in bounds: NSRect) -> (CGFloat, CGFloat) {
        guard let root = searchContainer.superview else { return (0, max(1, bounds.width)) }
        let contentFrameInRoot = leftContentView.convert(leftContentView.bounds, to: root)
        let contractXInRoot = contentFrameInRoot.minX + PANEL_INSET
        let contractWInRoot = max(contentFrameInRoot.width - (2 * PANEL_INSET), 0)

        let leftX = leftContentView.convert(NSPoint(x: contractXInRoot, y: 0), from: root).x
        let rightX = leftContentView.convert(NSPoint(x: contractXInRoot + contractWInRoot, y: 0), from: root).x

        let x = max(0, min(bounds.width, leftX))
        let r = max(x, min(bounds.width, rightX))
        return (x, max(1, r - x))
    }

	    private func setupLeftTableUnderlay() {
	        guard leftTableUnderlayView == nil else { return }
        let underlay = makeGlassEffectView(
            passthrough: true,
            cornerRadius: 14,
            tintColor: leftTableUnderlayTintColor(),
            style: .regular,
            fallbackMaterial: .sidebar,
            fallbackBlending: .withinWindow,
            fallbackState: .active,
            emphasized: true
        )
	        underlay.translatesAutoresizingMaskIntoConstraints = true
	        underlay.wantsLayer = true
	        underlay.layer?.masksToBounds = true
	        if #available(macOS 10.13, *) {
	            underlay.layer?.cornerCurve = .continuous
	        }

            clearGlassChrome(for: underlay)

	        leftContentView.addSubview(underlay, positioned: .below, relativeTo: tableScroll)
	        leftTableUnderlayView = underlay
        layoutLeftTableUnderlay(approximate: false)
	    }

			    private func layoutLeftTableUnderlay(approximate: Bool = false) {
			        guard let underlay = leftTableUnderlayView else { return }
        var frame = tableScroll.frame
        let contentHeight: CGFloat
        if approximate {
            let docHeight = tableView.frame.height
            let fallback = tableScroll.documentView?.bounds.height ?? docHeight
            if cachedLeftTableContentHeight >= 0 {
                contentHeight = cachedLeftTableContentHeight
            } else {
                contentHeight = max(0, fallback.isFinite ? fallback : 0)
            }
        } else {
            contentHeight = leftTableContentHeight()
            cachedLeftTableContentHeight = contentHeight
        }
        let rowCount = tableView.numberOfRows
        let minContentHeight = rowCount > 0 ? headerRowHeight : 0
        let effectiveContentHeight = max(contentHeight, minContentHeight)
        let desiredHeight = min(
            frame.height,
            tableScroll.contentInsets.top + effectiveContentHeight + leftTableUnderlayBottomPadding
        )
        let availableHeight = max(0, frame.height)
        let resolvedHeight: CGFloat
        if !desiredHeight.isFinite {
            resolvedHeight = availableHeight
        } else if availableHeight >= 1 {
            resolvedHeight = max(1, desiredHeight)
        } else {
            resolvedHeight = availableHeight
        }

        let bottomExtension: CGFloat = 6
        var extendedHeight = resolvedHeight + bottomExtension
        if extendedHeight > frame.height {
            extendedHeight = frame.height
        }
        frame.origin.y = frame.maxY - extendedHeight
        frame.size.height = extendedHeight
        underlay.frame = frame
			        if underlay.isHidden { underlay.isHidden = false }
			        if underlay.alphaValue < 1.0 { underlay.alphaValue = 1.0 }
			        let radius: CGFloat = 14
			        underlay.layer?.cornerRadius = radius
            if #available(macOS 26.0, *), let glass = underlay as? NSGlassEffectView {
                glass.cornerRadius = radius
                glass.tintColor = leftTableUnderlayTintColor()
            }
            // Keep the left panel underlay surface clean to avoid inset outlines.
			    }

		private func leftTableContentHeight() -> CGFloat {
            let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
            defer {
                if resizePerfEnabled {
                    ResizePerfTrace.shared.recordWork(name: "table.measure.height", durationNs: monotonicNowNs() &- perfStart)
                }
            }
			let rows = tableView.numberOfRows
			guard rows > 0 else { return 0 }
			var height: CGFloat = 0
			for row in 0..<rows {
				height += tableView(tableView, heightOfRow: row)
			}
			return height
		}

    private func setupTable() {
        let col = NSTableColumn(identifier: .init("left"))
        col.title = ""
        col.resizingMask = []
        tableView.addTableColumn(col)
        tableView.headerView = nil

        tableView.dataSource = self
        tableView.delegate = self

        if #available(macOS 11.0, *) {
            tableView.style = .fullWidth
        }
        tableView.usesAlternatingRowBackgroundColors = false
        tableView.focusRingType = .none
        tableView.allowsEmptySelection = true
        tableView.allowsMultipleSelection = false
        tableView.selectionHighlightStyle = .none
        tableView.backgroundColor = .clear

        tableView.target = self
        tableView.action = #selector(singleClick)
        tableView.doubleAction = #selector(doubleClick)

        tableView.usesAutomaticRowHeights = false
        tableView.intercellSpacing = NSSize(width: 0, height: 0)
        // Disable automatic column sizing; width is driven by layout.
        tableView.columnAutoresizingStyle = .noColumnAutoresizing

        tableScroll.drawsBackground = false
        tableScroll.backgroundColor = .clear
        tableScroll.hasHorizontalScroller = leftTableAllowsHorizontalScroller
        tableScroll.horizontalScrollElasticity = leftTableHorizontalElasticityDefault
        tableScroll.verticalScrollElasticity = .none
        tableScroll.usesPredominantAxisScrolling = false
        // Keep the row “glass tabs” aligned to the same right edge as the search bar by avoiding
        // any reserved scroller gutter in the left panel.
        tableScroll.hasVerticalScroller = false
        tableScroll.autohidesScrollers = false
        tableScroll.scrollerStyle = .overlay
        tableScroll.usesPredominantAxisScrolling = true
        tableScroll.automaticallyAdjustsContentInsets = false
        // Horizontal extent is controlled by layoutLeftContainerSubviews() to respect the panel inset.
        tableScroll.contentInsets = NSEdgeInsets(top: PANEL_INSET, left: 0, bottom: PANEL_INSET, right: 0)

        tableScroll.documentView = tableView
        tableScroll.contentView.postsBoundsChangedNotifications = true

        rowMenu.delegate = self
        tableView.menu = rowMenu
    }

    private func configurePageStepperGlyphButton(_ button: GlassToolbarButton) {
        // Glyph-only feedback: no box, no halo, no shadow; tint changes only.
        button.idleHoverOpacity = 0.0
        button.hoverFillOpacity = 0.0
        button.pressedFillOpacity = 0.0
        button.restingGlowOpacity = 0.0
        button.hoverShadowOpacity = 0.0
        button.pressedShadowOpacity = 0.0
        button.restingShadowRadius = 0.0
        button.hoverShadowRadius = 0.0
        button.pressedShadowRadius = 0.0
        button.restingShadowOffset = .zero
        button.hoverShadowOffset = .zero
        button.pressedShadowOffset = .zero
        button.hoverScale = 1.0
        button.activeScale = 1.0
        button.hoverLift = 0.0
        button.activeLift = 0.0
        button.showsHaloRing = false
        button.showsRestingGlow = false
        button.restingGlowColor = nil
        button.glyphHoverAlpha = 0.9
        button.glyphPressedAlpha = 0.75
        button.usesGlyphOnlyFeedback = true
        button.layer?.backgroundColor = NSColor.clear.cgColor
        button.layer?.borderWidth = 0
        button.layer?.shadowOpacity = 0
        button.focusRingType = .none
    }

    private func setupPageStepper() {
        pageStepperContainer.translatesAutoresizingMaskIntoConstraints = true
        pageStepperContainer.wantsLayer = false
        pageStepperContainer.isHidden = true

        // Keep the pager fully transparent—only the chevron icons should be visible.
        let background = makeGlassEffectView(
            passthrough: true,
            cornerRadius: pageStepperHeight / 2,
            tintColor: .clear,
            style: .regular,
            fallbackMaterial: .sidebar,
            fallbackBlending: .withinWindow,
            fallbackState: .active,
            emphasized: false
        )
        background.isHidden = true
        background.alphaValue = 0
        background.translatesAutoresizingMaskIntoConstraints = true
        background.wantsLayer = true
        background.layer?.masksToBounds = true
        pageStepperBackground = background
        pageStepperContainer.addSubview(background)

        let symbolConfig = NSImage.SymbolConfiguration(pointSize: 13 * toolbarControlScaleBase, weight: .regular)
        pagePrevButton.image = NSImage(systemSymbolName: "chevron.left", accessibilityDescription: nil)?.withSymbolConfiguration(symbolConfig)
        pageNextButton.image = NSImage(systemSymbolName: "chevron.right", accessibilityDescription: nil)?.withSymbolConfiguration(symbolConfig)
        pagePrevButton.target = self
        pageNextButton.target = self
        pagePrevButton.action = #selector(stepToPreviousPage)
        pageNextButton.action = #selector(stepToNextPage)
        pagePrevButton.setAccessibilityLabel("Previous Page")
        pageNextButton.setAccessibilityLabel("Next Page")
        pagePrevButton.toolTip = nil
        pageNextButton.toolTip = nil
        pagePrevButton.debugIdentifier = "toolbar.pageStepper.prev"
        pageNextButton.debugIdentifier = "toolbar.pageStepper.next"
        configurePageStepperGlyphButton(pagePrevButton)
        configurePageStepperGlyphButton(pageNextButton)
        updatePageStepperAppearance()

        pagePrevButton.translatesAutoresizingMaskIntoConstraints = true
        pageNextButton.translatesAutoresizingMaskIntoConstraints = true
        pageStepperContainer.addSubview(pagePrevButton)
        pageStepperContainer.addSubview(pageNextButton)
    }

	    private func setupRightPanelChrome() {
	        rightContainer = makePrimaryGlassPanelChrome()
	        embedContentView(rightContentView, into: rightContainer)
