    private func setupRightAuxAnnotationsPanel() {
        let controller = PDFAnnotationsPanelController()
        controller.onSelectItem = { [weak self] item in
            guard let self else { return }
            self.navigateToAnnotation(item)
            DispatchQueue.main.async { [weak self] in
                self?.annotationController?.openAnnotationGroup(for: item)
            }
        }
        controller.onRequestMenu = { [weak self] item, anchor in
            self?.presentAnnotationMenu(for: item, anchor: anchor)
        }
        controller.onCommitCommentEdit = { [weak self] item, content in
            self?.annotationController?.updateAnnotationGroupComment(for: item, content: content)
        }
        controller.onDeleteItem = { [weak self] item in
            self?.annotationController?.performAnnotationCommand(.delete, for: item, source: "list_delete")
        }
        controller.alignmentReferenceView = rightAuxHeaderRule
        controller.isResizingProvider = { [weak self] in
            guard let self else { return false }
            return self.rightSplitDividerDragActive || self.window?.inLiveResize == true
        }
        controller.setRowHeightUpdatesSuppressed(true)
        annotationsViewModel.onItemsChanged = { [weak controller, weak self] items in
            controller?.applyItems(items)
            if AnimationGuard.shouldDeferHeavyWork {
                AnimationGuard.deferWork(label: "annotations.sync_current") { [weak self] in
                    self?.annotationController?.syncCurrentListItem(with: items)
                }
            } else {
                self?.annotationController?.syncCurrentListItem(with: items)
            }
        }
        controller.install(in: rightAuxContentView)
        annotationsPanelController = controller
    }

    private func installAnnotationsPanelObservers() {
        let center = NotificationCenter.default
        annotationsPanelObservers.append(center.addObserver(forName: .arxivPDFAnnotationsDidChange, object: nil, queue: nil) { [weak self] note in
            guard let self else { return }
            let update = {
                if let doc = note.object as? PDFDocument,
                   doc !== self.pdfView.document {
                    return
                }
                if let info = note.userInfo,
                   let rawKind = info[annotationChangeKindKey] as? String,
                   let kind = AnnotationChangeKind(rawValue: rawKind),
                   let groupID = info[annotationChangeGroupIDKey] as? String {
                    let pageIndex = info[annotationChangePageIndexKey] as? Int
                    switch kind {
                    case .comment:
                        let comment = info[annotationChangeCommentKey] as? String
                        let payload = info[annotationChangeCommentPayloadKey] as? String
                        let color = info[annotationChangeColorKey] as? NSColor
                        if self.annotationsViewModel.applyInlineUpdate(groupID: groupID,
                                                                       pageIndex: pageIndex,
                                                                       commentText: comment,
                                                                       commentPayload: payload,
                                                                       color: color) {
                            return
                        }
                    case .pageLabel:
                        let label = info[annotationChangePageLabelKey] as? String
                        if self.annotationsViewModel.applyInlineUpdate(groupID: groupID,
                                                                       pageIndex: pageIndex,
                                                                       pageLabel: label) {
                            return
                        }
                    case .color:
                        let color = info[annotationChangeColorKey] as? NSColor
                        if self.annotationsViewModel.applyInlineUpdate(groupID: groupID,
                                                                       pageIndex: pageIndex,
                                                                       color: color) {
                            return
                        }
                    }
                }
                self.refreshAnnotationsPanel(reason: "annotations_changed")
            }
            if Thread.isMainThread {
                update()
            } else {
                DispatchQueue.main.async {
                    update()
                }
            }
        })
        annotationsPanelObservers.append(center.addObserver(forName: .PDFViewDocumentChanged, object: pdfView, queue: nil) { [weak self] _ in
            guard let self else { return }
            if Thread.isMainThread {
                self.invalidatePDFResizeFreezeSnapshot(reason: "pdf_document_changed")
                self.refreshAnnotationsPanel(reason: "pdf_document_changed")
            } else {
                DispatchQueue.main.async {
                    self.invalidatePDFResizeFreezeSnapshot(reason: "pdf_document_changed")
                    self.refreshAnnotationsPanel(reason: "pdf_document_changed")
                }
            }
        })
    }

    private func refreshAnnotationsPanel(reason: String) {
        if AnimationGuard.shouldDeferHeavyWork {
            pendingAnnotationsRefreshReason = reason
            if pendingAnnotationsRefreshWorkItem == nil {
                let work = DispatchWorkItem { [weak self] in
                    guard let self else { return }
                    let nextReason = self.pendingAnnotationsRefreshReason ?? "deferred"
                    self.pendingAnnotationsRefreshReason = nil
                    self.pendingAnnotationsRefreshWorkItem = nil
                    self.refreshAnnotationsPanelNow(reason: nextReason)
                }
                pendingAnnotationsRefreshWorkItem = work
                AnimationGuard.deferWork(label: "annotations.refresh.deferred") {
                    work.perform()
                }
            }
            return
        }
        if pendingAnnotationsRefreshWorkItem != nil {
            pendingAnnotationsRefreshWorkItem?.cancel()
            pendingAnnotationsRefreshWorkItem = nil
            pendingAnnotationsRefreshReason = nil
        }
        refreshAnnotationsPanelNow(reason: reason)
    }

    private func refreshAnnotationsPanelNow(reason: String) {
        let guardMeasure = AnimationGuard.beginMeasurement("annotations.panel.refresh")
        defer { AnimationGuard.endMeasurement(guardMeasure, details: "reason=\(reason)") }
        PerfLogger.begin("annotations.panel.refresh")
        defer { PerfLogger.end("annotations.panel.refresh") }
        let doc = isShowingPDF ? pdfView.document : nil
        let message = (doc == nil) ? "No PDF selected." : "No annotations yet."
        annotationsPanelController?.setEmptyMessage(message)
        PerfLogger.measure("annotations.model.reload") {
            AnimationGuard.measure("annotations.model.reload") {
                annotationsViewModel.reload(document: doc, displayBox: pdfView.displayBox)
            }
        }
        reportEvent(severity: .info,
                    category: .annotationOps,
                    event: "annotation_panel_refresh",
                    documentID: doc.flatMap { AstroStack.reportingDocumentID(for: $0) },
                    details: ["reason": reason])
    }

