        NSLayoutConstraint.activate([
            // Host fills the right content view inset by the panel padding.
            rightPanelContentHost.leadingAnchor.constraint(equalTo: rightContentView.leadingAnchor, constant: PANEL_INSET),
            rightPanelContentHost.trailingAnchor.constraint(equalTo: rightContentView.trailingAnchor, constant: -PANEL_INSET),
            rightPanelContentHost.topAnchor.constraint(equalTo: rightContentView.topAnchor, constant: PANEL_INSET),
            rightPanelContentHost.bottomAnchor.constraint(equalTo: rightContentView.bottomAnchor, constant: -PANEL_INSET),

            // Content fills the host.
            detailsWebView.leadingAnchor.constraint(equalTo: rightPanelContentHost.leadingAnchor),
            detailsWebView.trailingAnchor.constraint(equalTo: rightPanelContentHost.trailingAnchor),
            detailsWebView.topAnchor.constraint(equalTo: rightPanelContentHost.topAnchor),
            detailsWebView.bottomAnchor.constraint(equalTo: rightPanelContentHost.bottomAnchor),

            pdfView.leadingAnchor.constraint(equalTo: rightPanelContentHost.leadingAnchor),
            pdfView.trailingAnchor.constraint(equalTo: rightPanelContentHost.trailingAnchor),
            pdfView.topAnchor.constraint(equalTo: rightPanelContentHost.topAnchor),
            pdfView.bottomAnchor.constraint(equalTo: rightPanelContentHost.bottomAnchor),

            rightPanelTransitionBlurView.leadingAnchor.constraint(equalTo: rightPanelContentHost.leadingAnchor),
            rightPanelTransitionBlurView.trailingAnchor.constraint(equalTo: rightPanelContentHost.trailingAnchor),
            rightPanelTransitionBlurView.topAnchor.constraint(equalTo: rightPanelContentHost.topAnchor),
            rightPanelTransitionBlurView.bottomAnchor.constraint(equalTo: rightPanelContentHost.bottomAnchor),
        ])

        installRightPanelScrollRestrictions()

        enforceWhitePDFBackground()

        loadHTMLWithLocalAccess(buildDetailsStatusHTML("", paperIndex: nil, paperTotal: nil, leftHeaderText: nil, centerHeaderText: nil))
    }

    private func installRightPanelScrollRestrictions() {
        // Details panel: allow vertical scrolling, suppress all horizontal panning/elasticity.
        for sv in descendantScrollViews(in: detailsWebView) {
            ensureHorizontalLock(for: sv, lockedX: 0, clampVertical: true)
            sv.verticalScrollElasticity = .none // no rubber-banding on HTML pane
        }
        detailsWebView.lockedX = 0

        // PDF pane: do not constrain scrolling (allow both horizontal + vertical).
        releasePDFScrollRestrictions()

        installPDFScrollDebuggingIfNeeded()
        installPDFFindBackgroundRefreshObserver()
    }

    private func releasePDFScrollRestrictions() {
        for sv in descendantScrollViews(in: pdfView) {
            // Remove any previously-installed horizontal locks so scroll wheel gestures and
            // trackpad panning work normally in both axes.
            rightHorizontalScrollLocks[ObjectIdentifier(sv)] = nil

            // Restore default scroll behavior.
            sv.hasVerticalScroller = true
            sv.hasHorizontalScroller = true
            sv.verticalScrollElasticity = .automatic
            sv.horizontalScrollElasticity = .automatic
            sv.usesPredominantAxisScrolling = true

            if let clip = sv.contentView as? HorizontalLockingClipView {
                clip.locksHorizontal = false
                clip.clampsVertical = false
            }
        }
    }

    private func installPDFScrollDebuggingIfNeeded() {
        guard PDFScrollDebugState.shared.enabled else { return }
        guard let scrollView = pdfPrimaryScrollView() else { return }
        if let overlay = pdfScrollDebugOverlay, overlay.matches(scrollView: scrollView) {
            return
        }
        pdfScrollDebugOverlay = PDFScrollDebugOverlay(hostView: rightContentView, scrollView: scrollView)
    }

    private func installPDFFindBackgroundRefreshObserver() {
        guard let scrollView = pdfPrimaryScrollView() else { return }
        let clip = scrollView.contentView
        if pdfFindScrollObservedClipView === clip { return }
        let center = NotificationCenter.default
        if let observer = pdfFindScrollObserver {
            center.removeObserver(observer)
            pdfFindScrollObserver = nil
        }
        pdfFindScrollObservedClipView = clip
        clip.postsBoundsChangedNotifications = true
        pdfFindScrollObserver = center.addObserver(forName: NSView.boundsDidChangeNotification,
                                                   object: clip,
                                                   queue: .main) { [weak self] _ in
            self?.schedulePDFFindBackgroundRefresh(reason: "scroll")
        }
    }

    private func schedulePDFFindBackgroundRefresh(reason: String) {
        _ = reason
        guard !pdfFindHUD.isHidden else {
            stopPDFFindLiveGlass(reason: "hidden")
            return
        }
        if pdfFindLiveGlassEnabled {
            renderPDFFindGlassFrame(reason: "pdf_find_scroll")
            startPDFFindLiveGlassIfNeeded()
            schedulePDFFindLiveGlassStop()
            return
        }
        let now = CACurrentMediaTime()
        let minInterval = 1.0 / 60.0
        let shouldRenderNow = (now - pdfFindLastBackgroundRefresh) >= minInterval
        if shouldRenderNow {
            pdfFindLastBackgroundRefresh = now
        }

        if shouldRenderNow {
            renderPDFFindGlassFrame(reason: "pdf_find_scroll")
        }

        // Trailing refresh: ensures the HUD catches the final PDF frame after scrolling stops.
        pdfFindBackgroundRefreshWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            self.renderPDFFindGlassFrame(reason: "pdf_find_scroll")
        }
        pdfFindBackgroundRefreshWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.045, execute: work)
    }

    private var pdfFindLiveGlassEnabled: Bool {
        // Default on; set ARXIV_PDF_FIND_LIVE_GLASS=0 to disable.
        ProcessInfo.processInfo.environment["ARXIV_PDF_FIND_LIVE_GLASS"] != "0"
    }

    private func pdfFindLiveGlassTargetFPS() -> Double {
        if #available(macOS 10.15, *) {
            if let screen = pdfFindHUD.window?.screen ?? NSScreen.main {
                let fps = screen.maximumFramesPerSecond
                if fps > 0 { return Double(fps) }
            }
        }
        return 60.0
    }

    private func renderPDFFindGlassFrame(reason: String) {
        _ = reason
        if let card = pdfFindBackgroundView as? GlassCardView {
            card.renderImmediately(reason: "pdf_find_live")
        } else {
            pdfFindBackgroundView.needsDisplay = true
            pdfFindBackgroundView.layer?.setNeedsDisplay()
        }
        if let prev = pdfFindPrevGlassBackground {
            prev.renderImmediately(reason: "pdf_find_live")
        } else {
            pdfFindPrevButton.invalidateLiquidGlass(reason: "pdf_find_live")
        }
        if let next = pdfFindNextGlassBackground {
            next.renderImmediately(reason: "pdf_find_live")
        } else {
            pdfFindNextButton.invalidateLiquidGlass(reason: "pdf_find_live")
        }
    }

    private func startPDFFindLiveGlassIfNeeded() {
        guard pdfFindLiveGlassTimer == nil else { return }
        let fps = pdfFindLiveGlassTargetFPS()
        let interval = max(1.0 / fps, 1.0 / 120.0)
        let timer = Timer(timeInterval: interval, repeats: true) { [weak self] _ in
            guard let self else { return }
            guard !self.pdfFindHUD.isHidden else {
                self.stopPDFFindLiveGlass(reason: "hidden")
                return
            }
            self.renderPDFFindGlassFrame(reason: "pdf_find_live_tick")
        }
        timer.tolerance = 0
        pdfFindLiveGlassTimer = timer
        RunLoop.main.add(timer, forMode: .common)
    }

    private func schedulePDFFindLiveGlassStop() {
        pdfFindLiveGlassStopWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            self.stopPDFFindLiveGlass(reason: "idle")
            self.renderPDFFindGlassFrame(reason: "pdf_find_live_end")
        }
        pdfFindLiveGlassStopWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.12, execute: work)
    }

    private func stopPDFFindLiveGlass(reason: String) {
        _ = reason
        pdfFindLiveGlassStopWorkItem?.cancel()
        pdfFindLiveGlassStopWorkItem = nil
        pdfFindLiveGlassTimer?.invalidate()
        pdfFindLiveGlassTimer = nil
    }

    private func layoutPDFScrollDebugOverlay() {
        guard let overlay = pdfScrollDebugOverlay else { return }
        overlay.setHidden(!isShowingPDF)
        overlay.layout(in: rightContentView.bounds)
    }

    private func ensureHorizontalLock(
        for scrollView: NSScrollView,
        lockedX: CGFloat,
        clampVertical: Bool = false,
        swapClipView: Bool = true
    ) {
        let id = ObjectIdentifier(scrollView)
        if let lock = rightHorizontalScrollLocks[id] {
            lock.updateLockedX(lockedX)
            return
        }
        rightHorizontalScrollLocks[id] = HorizontalScrollLock(scrollView: scrollView, lockedX: lockedX, clampVertical: clampVertical, swapClipView: swapClipView)
    }

    private func descendantScrollViews(in root: NSView) -> [NSScrollView] {
        var out: [NSScrollView] = []
        func walk(_ view: NSView) {
            if let sv = view as? NSScrollView { out.append(sv) }
            for sub in view.subviews { walk(sub) }
        }
        walk(root)
        return out
    }

    private func layoutRightPanelSubviews(duringLiveResize: Bool = false) {
        let guardMeasure = AnimationGuard.beginMeasurement("layout.right_container")
        defer { AnimationGuard.endMeasurement(guardMeasure) }
        PerfLogger.begin("layout.right_container")
        defer { PerfLogger.end("layout.right_container") }
        let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
        defer {
            if resizePerfEnabled {
                let duration = monotonicNowNs() &- perfStart
                ResizeLatencyProbe.shared.markLayoutPass(name: "right_layout", durationNs: duration)
                ResizePerfTrace.shared.noteLayoutPass(name: "right", durationNs: duration)
            }
        }
        noteResizeLayoutEvent(name: "right_layout")
        let transitionLive = sidebarTransitionInProgress || rightAuxTransitionInProgress
        let live = duringLiveResize || window?.inLiveResize == true || transitionLive
        if !live {
            defer { updateRightCardBackgroundFrame() }
        }
        // Apple-like inset padding inside bordered right panel
        let ib = rightContentView.bounds.insetBy(dx: PANEL_INSET, dy: PANEL_INSET)

        rightPDFBackgroundView.frame = rightContentView.bounds
        if let layer = rightPDFBackgroundView.layer {
            layer.cornerRadius = rightCardCornerRadius()
            layer.masksToBounds = true
            if #available(macOS 10.13, *) {
                layer.cornerCurve = rightContainer.layer?.cornerCurve ?? .continuous
            }
        }
        if !live {
            AnimationGuard.measure("pdf.refresh_background") {
                refreshPDFBackgroundImage()
            }
            AnimationGuard.measure("pdf.refresh_embedded") {
                refreshEmbeddedPDFImage()
            }
        }
        // Constrained: rightPanelContentHost fills rightContentView with PANEL_INSET.
        if let hostLayer = rightPanelContentHost.layer {
            // Transition safety: clip transforms to the right panel content bounds.
            // Divider safety: this is confined to the content host; split-view layout is untouched.
            hostLayer.cornerRadius = rightCardCornerRadius()
            hostLayer.masksToBounds = true
            if #available(macOS 10.13, *) {
                hostLayer.cornerCurve = rightContainer.layer?.cornerCurve ?? .continuous
            }
        }

        if let blurLayer = rightPanelTransitionBlurView.layer {
            blurLayer.cornerRadius = rightCardCornerRadius()
            blurLayer.masksToBounds = true
            if #available(macOS 10.13, *) {
                blurLayer.cornerCurve = rightContainer.layer?.cornerCurve ?? .continuous
            }
        }
            _ = ib // now constraint-driven
	        applyDetailsWebViewRoundedClipping()
        if live {
            if !(sidebarTransitionInProgress
                 || sidebarToggleDeferredWorkItem != nil
                 || sidebarTogglePDFSnapshotClearWorkItem != nil) {
                let forceInteractive = dividerDragActive || rightSplitDividerDragActive || rightAuxTransitionInProgress
                updateViewerForInteractiveResize(force: forceInteractive)
            }
        }

        if sidebarTransitionInProgress
            || sidebarToggleDeferredWorkItem != nil
            || sidebarTogglePDFSnapshotClearWorkItem != nil {
            applySidebarTogglePDFSnapshotDuringResize()
        }

        layoutLoadingOverlaySubviews()
        layoutPDFFindHUDSubviews()

        if isShowingPDF {
            if !live {
                enforceWhitePDFBackground()
                let now = CACurrentMediaTime()
                let recentToggle = (now - lastSidebarToggleTimestamp) < 0.6
                    || (now - lastRightAuxToggleTimestamp) < 0.6
                    || now < panelToggleFlickerSuppressionUntil
                if !recentToggle {
                    AnimationGuard.measure("pdf.apply_zoom_preset") {
                        applyPDFZoomPresetIfNeeded()
                    }
                } else if pdfInteractivePendingScale == nil && pdfInteractiveResizeWorkItem == nil {
                    // No pending interactive scale updates; allow a tiny settle once the toggle
                    // window elapses without forcing a synchronous relayout now.
                    let settleDelay: TimeInterval = 0.12
                    DispatchQueue.main.asyncAfter(deadline: .now() + settleDelay) { [weak self] in
                        guard let self else { return }
                        let now = CACurrentMediaTime()
                        let stillRecent = (now - self.lastSidebarToggleTimestamp) < 0.6
                            || (now - self.lastRightAuxToggleTimestamp) < 0.6
                            || now < self.panelToggleFlickerSuppressionUntil
                        guard !stillRecent else { return }
                        self.applyPDFZoomPresetIfNeeded(minimumDelta: 0.0005)
                    }
                }
            }
        }
        if !live {
            layoutPDFScrollDebugOverlay()
            recordRightPanelWidthIfNeeded()
            clampRightPanelWidthForSplit()
        }
        // Use lightweight list layout while the right divider is actively dragged or animating.
        let interactiveAuxLayout = rightSplitDividerDragActive || rightAuxTransitionInProgress
        layoutRightAuxPanelSubviews(interactive: interactiveAuxLayout)
    }

    private func layoutRightAuxPanelSubviews(interactive: Bool = false) {
        let guardMeasure = AnimationGuard.beginMeasurement("layout.right_aux")
        defer { AnimationGuard.endMeasurement(guardMeasure) }
        PerfLogger.begin("layout.right_aux")
        defer { PerfLogger.end("layout.right_aux") }
        let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
        defer {
            if resizePerfEnabled {
                let duration = monotonicNowNs() &- perfStart
                ResizeLatencyProbe.shared.markLayoutPass(name: "right_aux_layout", durationNs: duration)
                ResizePerfTrace.shared.noteLayoutPass(name: "right_aux", durationNs: duration)
            }
        }
        noteResizeLayoutEvent(name: "right_aux_layout")
        updateRightAuxRasterizationState(reason: "right_aux_layout")
        guard rightAuxContainer.superview != nil else { return }
        if rightAuxPanelVisible, !rightAuxTransitionInProgress, rightAuxContainer.alphaValue < 0.98 {
            rightAuxContainer.alphaValue = 1
        }
        let b = rightAuxContentView.bounds
        guard b.width > 1, b.height > 1 else { return }

        let insetX: CGFloat = PANEL_INSET
        let insetY: CGFloat = PANEL_INSET
        let width = max(0, b.width - (2 * insetX))

        // Header at top: "Annotations" + underline.
        let headerLabelH: CGFloat = 16
        let headerGapBelowLabel: CGFloat = 6
        let headerRuleH: CGFloat = 1
        let headerLabelY = max(insetY, b.height - insetY - headerLabelH)
        rightAuxHeaderLabel.frame = NSRect(x: insetX,
                                           y: headerLabelY,
                                           width: width,
                                           height: headerLabelH)
        let ruleY = max(insetY, headerLabelY - headerGapBelowLabel - headerRuleH)
        rightAuxHeaderRule.frame = NSRect(x: insetX,
                                          y: ruleY,
                                          width: width,
                                          height: headerRuleH)

        rightAuxAskContainer.isHidden = true
        rightAuxAskSeparatorView.isHidden = true

        let listGapBelowHeader: CGFloat = 10
        let listTop = max(insetY, ruleY - listGapBelowHeader)
        let listHeight = max(0, listTop - insetY)
        let listFrame = NSRect(x: insetX, y: insetY, width: width, height: listHeight)
        // During right-divider drags, keep annotation list layout lightweight; full pass runs after drag end.
        let annotationsLayoutStart = resizePerfEnabled ? monotonicNowNs() : 0
        PerfLogger.measure("annotations.panel.layout_invoke") {
            let mode: PDFAnnotationsPanelController.LayoutMode = interactive ? .interactive : .full
            AnimationGuard.measure("annotations.panel.layout") {
                annotationsPanelController?.layout(in: listFrame, mode: mode)
            }
        }
        if resizePerfEnabled {
            let key = interactive ? "annotations.layout.interactive" : "annotations.layout.full"
            ResizePerfTrace.shared.recordWork(name: key, durationNs: monotonicNowNs() &- annotationsLayoutStart)
        }
    }

    private func updateRightAuxAskCapsuleGeometry() {
        guard let layer = rightAuxAskBackground.layer else { return }
        let b = rightAuxAskBackground.bounds
        guard b.width > 1, b.height > 1 else { return }

        let lineWidth: CGFloat = max(1, SPOTLIGHT_SEARCH_OUTLINE_WIDTH)
        let inset = lineWidth / 2
        let rect = b.insetBy(dx: inset, dy: inset)
        let radius = rect.height / 2
        let path = CGPath(roundedRect: rect, cornerWidth: radius, cornerHeight: radius, transform: nil)
        let innerRect = b.insetBy(dx: inset + 1.0, dy: inset + 1.0)
        let innerRadius = max(0, innerRect.height / 2)
        let innerPath = CGPath(roundedRect: innerRect, cornerWidth: innerRadius, cornerHeight: innerRadius, transform: nil)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer.masksToBounds = true
        layer.cornerRadius = radius
        layer.shadowPath = path
        if let glass = rightAuxAskBackground as? NSGlassEffectView {
            glass.cornerRadius = radius
        }
        rightAuxAskOutlineLayer.lineWidth = lineWidth
        rightAuxAskOutlineLayer.path = path
        rightAuxAskInnerOutlineLayer.lineWidth = lineWidth
        rightAuxAskInnerOutlineLayer.path = innerPath
        rightAuxAskMaskLayer.path = path
        rightAuxAskCenterGlowLayer.frame = b
        rightAuxAskCenterGlowLayer.locations = [0.0, 1.0]
        rightAuxAskHighlightLayer.frame = b
        rightAuxAskHighlightLayer.locations = [0.0, 1.0]
        rightAuxAskFalloffLayer.frame = b
        rightAuxAskFalloffLayer.locations = [0.0, 1.0]
        if let containerLayer = rightAuxAskContainer.layer {
            containerLayer.shadowPath = path
        }
        CATransaction.commit()

        updateRightAuxAskDepth(animated: false)
    }

    // MARK: Loading overlay (CENTERED)

    private func setupLoadingOverlay() {
        loadingOverlay = makeGlassEffectView(
            passthrough: false,
            cornerRadius: PANEL_CORNER_RADIUS,
            tintColor: nil,
            style: .regular,
            fallbackMaterial: .hudWindow,
            fallbackBlending: .withinWindow,
            fallbackState: .active,
            emphasized: true
        )
        loadingOverlay.translatesAutoresizingMaskIntoConstraints = false
        loadingOverlay.wantsLayer = true
        loadingOverlay.layer?.cornerRadius = PANEL_CORNER_RADIUS
        loadingOverlay.layer?.masksToBounds = true
        loadingOverlay.isHidden = true

        loadingSpinner.style = .spinning
        loadingSpinner.isIndeterminate = true
        loadingSpinner.controlSize = .regular

        loadingLabel.font = NSFont.systemFont(ofSize: 13)
        loadingLabel.textColor = resolvedForegroundColor(base: windowBackgroundSolidColor(),
                                                         tint: panelClearGlassTintColor(),
                                                         role: .primaryText)
        loadingLabel.alignment = .center

        rightContentView.addSubview(loadingOverlay)
        NSLayoutConstraint.activate([
            loadingOverlay.leadingAnchor.constraint(equalTo: rightContentView.leadingAnchor, constant: PANEL_INSET),
            loadingOverlay.trailingAnchor.constraint(equalTo: rightContentView.trailingAnchor, constant: -PANEL_INSET),
            loadingOverlay.topAnchor.constraint(equalTo: rightContentView.topAnchor, constant: PANEL_INSET),
            loadingOverlay.bottomAnchor.constraint(equalTo: rightContentView.bottomAnchor, constant: -PANEL_INSET),
        ])
        loadingOverlay.addSubview(loadingSpinner)
        loadingOverlay.addSubview(loadingLabel)
        updateLoadingOverlayAppearance()
    }

	    private func installCacheLifecycleObservers() {
	        appTerminationObserver = NotificationCenter.default.addObserver(
	            forName: NSApplication.willTerminateNotification,
	            object: nil,
	            queue: .main
	        ) { [weak self] _ in
	            guard let self else { return }
	            if self.pdfCacheCleanupState == .cleaned { return }
                guard let cache = self.pdfCacheStorage else {
                    self.pdfCacheCleanupState = .cleaned
                    return
                }
	            self.pdfCacheCleanupState = .cleaning
	            NSLog("[PDFEager] cleanup_start reason=will_terminate dir=\(cache.sessionDirectory.path)")
	            cache.cleanupOnExit()
	            self.pdfCacheCleanupState = .cleaned
	        }
	    }

    private func installSettingsObservers() {
        settingsChangeObserver = NotificationCenter.default.addObserver(
            forName: .astroStackSettingsDidChange,
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.applySettingsChange(reason: "settings_change")
        }
    }

    private func applySettingsChange(reason: String) {
        if !Thread.isMainThread {
            DispatchQueue.main.async { [weak self] in
                self?.applySettingsChange(reason: reason)
            }
            return
        }
        if isApplyingSettingsChange {
            pendingSettingsChange = true
            return
        }
        isApplyingSettingsChange = true
        defer {
            isApplyingSettingsChange = false
            if pendingSettingsChange {
                pendingSettingsChange = false
                applySettingsChange(reason: "coalesced")
            }
        }
        _ = reason
        updateAppleIntelligencePillTooltips()

        let appearance = AppSettingsStore.shared.current.appearance
        let appearanceOverrideChanged = lastAppliedAppearanceSettings?.appearanceOverride != appearance.appearanceOverride
        if appearanceOverrideChanged {
            AppSettingsBootstrap.applyAppAppearanceOverrideIfNeeded(NSApp)
            pendingAppearanceWork.needsWindowAppearance = true
        }

        let liquidGlassChanged = lastAppliedAppearanceSettings?.liquidGlassEnabled != appearance.liquidGlassEnabled
        if liquidGlassChanged {
            pendingAppearanceWork.needsWindowAppearance = true
        }

        let fontChanged = lastAppliedAppearanceSettings?.fonts != appearance.fonts
        if fontChanged {
            pendingAppearanceWork.needsFontApply = true
        }

        let htmlChanged = lastAppliedAppearanceSettings?.htmlImages != appearance.htmlImages
            || lastAppliedAppearanceSettings?.fonts.htmlFontName != appearance.fonts.htmlFontName
            || lastAppliedAppearanceSettings?.fonts.htmlFontSize != appearance.fonts.htmlFontSize

        let shouldUpdateRootGlass = appearanceOverrideChanged
            || lastAppliedAppearanceSettings?.accentMode != appearance.accentMode
            || lastAppliedAppearanceSettings?.customAccentHex != appearance.customAccentHex
            || lastAppliedAppearanceSettings?.liquidGlassTintStrength != appearance.liquidGlassTintStrength
            || lastAppliedAppearanceSettings?.liquidGlassEnabled != appearance.liquidGlassEnabled
            || lastAppliedAppearanceSettings?.windowTintEnabled != appearance.windowTintEnabled
            || lastAppliedAppearanceSettings?.glassTintSourceEnabled != appearance.glassTintSourceEnabled
            || lastAppliedAppearanceSettings?.glassTintSource != appearance.glassTintSource
            || lastAppliedAppearanceSettings?.customGlassTintEnabled != appearance.customGlassTintEnabled
            || lastAppliedAppearanceSettings?.customGlassTintHex != appearance.customGlassTintHex
            || lastAppliedAppearanceSettings?.glassStyleEnabled != appearance.glassStyleEnabled
            || lastAppliedAppearanceSettings?.glassStyle != appearance.glassStyle
            || lastAppliedAppearanceSettings?.leftPanelGlassEnabled != appearance.leftPanelGlassEnabled
            || lastAppliedAppearanceSettings?.leftPanelTintHex != appearance.leftPanelTintHex
            || lastAppliedAppearanceSettings?.leftPanelTintAlpha != appearance.leftPanelTintAlpha
            || lastAppliedAppearanceSettings?.leftTablePanelBackgroundMode != appearance.leftTablePanelBackgroundMode
            || lastAppliedAppearanceSettings?.leftTablePanelBackgroundHex != appearance.leftTablePanelBackgroundHex
            || lastAppliedAppearanceSettings?.rightAuxGlassEnabled != appearance.rightAuxGlassEnabled
            || lastAppliedAppearanceSettings?.rightAuxTintHex != appearance.rightAuxTintHex
            || lastAppliedAppearanceSettings?.rightAuxTintAlpha != appearance.rightAuxTintAlpha
            || lastAppliedAppearanceSettings?.annotationListGlassEnabled != appearance.annotationListGlassEnabled
            || lastAppliedAppearanceSettings?.annotationListTintHex != appearance.annotationListTintHex
            || lastAppliedAppearanceSettings?.annotationListTintStrength != appearance.annotationListTintStrength
        if shouldUpdateRootGlass {
            scheduleRootGlassTintApply(reason: "settings", delay: 0.0)
        }

        let annotationListTintChanged = lastAppliedAppearanceSettings?.annotationListGlassEnabled != appearance.annotationListGlassEnabled
            || lastAppliedAppearanceSettings?.annotationListTintHex != appearance.annotationListTintHex
            || lastAppliedAppearanceSettings?.annotationListTintStrength != appearance.annotationListTintStrength
        if annotationListTintChanged {
            pendingAppearanceWork.needsAnnotationsRefresh = true
        }

        let annotationComposerTintChanged = lastAppliedAppearanceSettings?.annotationComposerTintHex != appearance.annotationComposerTintHex
            || lastAppliedAppearanceSettings?.annotationComposerTintStrength != appearance.annotationComposerTintStrength
            || lastAppliedAppearanceSettings?.accentMode != appearance.accentMode
            || lastAppliedAppearanceSettings?.customAccentHex != appearance.customAccentHex
            || lastAppliedAppearanceSettings?.liquidGlassTintStrength != appearance.liquidGlassTintStrength
        if annotationComposerTintChanged {
            pendingAppearanceWork.needsAnnotationComposerRefresh = true
        }

        if htmlChanged, !isShowingPDF, !shouldUpdateRootGlass {
            pendingAppearanceWork.needsDetailsUpdate = true
        }

        let needsHoverTooltipRefresh = !shouldUpdateRootGlass
            && (appearanceOverrideChanged
                || liquidGlassChanged
                || fontChanged
                || htmlChanged
                || annotationListTintChanged
                || annotationComposerTintChanged)
        if needsHoverTooltipRefresh {
            pendingAppearanceWork.needsHoverTooltipRefresh = true
        }

        if pendingAppearanceWork.needsWindowAppearance
            || pendingAppearanceWork.needsFontApply
            || pendingAppearanceWork.needsDetailsUpdate
            || pendingAppearanceWork.needsAnnotationsRefresh
            || pendingAppearanceWork.needsAnnotationComposerRefresh
            || pendingAppearanceWork.needsHoverTooltipRefresh {
            scheduleAppearanceDeferredWork(reason: reason)
        }

        lastAppliedAppearanceSettings = appearance
    }

    private func scheduleAppearanceDeferredWork(reason: String, delay: TimeInterval = 0.12) {
        _ = reason
        appearanceDeferredWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            let pending = self.pendingAppearanceWork
            self.pendingAppearanceWork = PendingAppearanceWork()
            self.appearanceDeferredWorkItem = nil
            self.applyDeferredAppearanceWork(pending)
        }
        appearanceDeferredWorkItem = work
        if delay <= 0 {
            DispatchQueue.main.async(execute: work)
        } else {
            DispatchQueue.main.asyncAfter(deadline: .now() + delay, execute: work)
        }
    }

    private func applyDeferredAppearanceWork(_ pending: PendingAppearanceWork) {
        let appearance = AppSettingsStore.shared.current.appearance
        if pending.needsWindowAppearance {
            configureWindowAppearance()
            if let content = window?.contentView {
                setupWindowBackgroundMaterial(in: content)
            }
            if !appearance.liquidGlassEnabled {
                rightPanelTransitionBlurView.layer?.removeAllAnimations()
                rightPanelTransitionBlurView.layer?.opacity = 0
                rightPanelTransitionBlurView.isHidden = true
            }
        }
        if pending.needsFontApply {
            applyUIFontSettings()
        }
        if pending.needsDetailsUpdate, !isShowingPDF {
            updateDetails()
        }
        if pending.needsAnnotationsRefresh {
            refreshAnnotationsPanel(reason: "appearance")
        }
        if pending.needsAnnotationComposerRefresh {
            annotationController?.refreshComposerAppearance()
        }
        if pending.needsHoverTooltipRefresh {
            updateHoverTooltipAppearance()
        }
    }

    private func applyUIFontSettings() {
        let base = resolvedUIFontFromSettings(defaultSize: 12.75, weight: .regular)
        let emphasis = fontByApplyingTrait(base, trait: .boldFontMask)

        leftRowTitleFont = base
        leftRowSecondaryFont = base
        leftRowSecondaryEmphasisFont = emphasis

        leftHeaderLabel.font = resolvedUIFontFromSettings(defaultSize: 12, weight: .semibold)
        rightAuxHeaderLabel.font = resolvedUIFontFromSettings(defaultSize: 12, weight: .semibold)

        cachedMaxLeftTextWidth = 0
        cachedMaxKeywordTextWidth = 0
        cachedRowNumberDigits = 1
        headerFramesFrozen = false
        invalidateSidebarPageContentWidthCache()

        if tableView.superview != nil {
	        setHoveredTableRow(nil, animated: false)
            tableView.reloadData()
        }
        layoutLeftContainerSubviews()
        refreshAnnotationsPanel(reason: "font_change")
    }

    private func layoutLoadingOverlaySubviews() {
        let b = loadingOverlay.bounds
        guard b.width > 10, b.height > 10 else { return }

        let spinnerSize: CGFloat = 18
        let labelH: CGFloat = 18
        let gap: CGFloat = 10

        let groupH = spinnerSize + gap + labelH
        let startY = (b.height - groupH) / 2

        loadingSpinner.frame = NSRect(
            x: (b.width - spinnerSize) / 2,
            y: startY + labelH + gap,
            width: spinnerSize,
            height: spinnerSize
        )
        loadingLabel.frame = NSRect(
            x: 24,
            y: startY,
            width: b.width - 48,
            height: labelH
        )
    }

    private func showLoading(_ msg: String) {
        loadingLabel.stringValue = msg
        loadingOverlay.isHidden = false
        loadingSpinner.startAnimation(nil)
        DispatchQueue.main.async { self.layoutRightPanelSubviews() }
    }

    private func hideLoading() {
        loadingSpinner.stopAnimation(nil)
        loadingOverlay.isHidden = true
    }

	    // MARK: PDF Cache + Prefetch

    private func debugPDFOverrideURL() -> URL? {
        let raw = (ProcessInfo.processInfo.environment["ARXIV_DEBUG_PDF_URL_OVERRIDE"] ?? "")
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !raw.isEmpty else { return nil }
        guard let url = URL(string: raw) else {
            NSLog("[PDFEager] debug_override_pdf_url_invalid=\(raw)")
            return nil
        }
        if !didLogDebugPDFOverride {
            didLogDebugPDFOverride = true
            NSLog("[PDFEager] debug_override_pdf_url=\(raw)")
        }
        return url
    }

    private func pdfURL(for paper: Paper) -> URL? {
        // If ARXIV_SAMPLE_PDF=1, always load a local sample PDF for debugging.
        if ProcessInfo.processInfo.environment["ARXIV_SAMPLE_PDF"] == "1" {
            if let url = ensureSamplePDFOnDisk() {
                return url
            }
        }
        if let override = debugPDFOverrideURL() { return override }
        guard let pdfURLStr = arxivPDFFromAbs(url: paper.url),
              let pdfURL = URL(string: pdfURLStr) else {
            return nil
        }
        return normalizedPDFURL(pdfURL)
    }

    private func pdfMetadata(for paper: Paper, url: URL) -> PDFCacheManager.Metadata {
        let stableID = arxivID(fromAbsURL: paper.url)
        return PDFCacheManager.Metadata(url: url, paperIndex: paper.index, stableID: stableID)
    }

    private func pdfMetadata(with url: URL) -> PDFCacheManager.Metadata {
        let stableID = arxivIDFromPDFURL(url)
        return PDFCacheManager.Metadata(url: url, paperIndex: nil, stableID: stableID)
    }

    private func prefetchRequest(for paper: Paper) -> PDFCacheManager.PrefetchRequest? {
        guard let url = pdfURL(for: paper) else { return nil }
        return PDFCacheManager.PrefetchRequest(
            url: url,
            metadata: pdfMetadata(for: paper, url: url)
        )
    }

    private func arxivIDFromPDFURL(_ url: URL) -> String? {
        if url.path == "/tmp/sample.pdf" {
            return "sample"
        }
        guard let host = url.host?.lowercased(), host.hasSuffix("arxiv.org") else { return nil }
        guard url.path.lowercased().hasPrefix("/pdf/") else { return nil }
        var identifier = url.path.dropFirst("/pdf/".count)
        if identifier.lowercased().hasSuffix(".pdf") {
            identifier = identifier.dropLast(4)
        }
        return identifier.trimmingCharacters(in: CharacterSet(charactersIn: "/"))
    }

    private func normalizedPDFURL(_ url: URL) -> URL {
        guard !url.isFileURL else { return url }
	        guard var comps = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return url }
	        comps.fragment = nil
	        comps.query = nil
	        if (comps.scheme ?? "").lowercased() == "http" {
	            comps.scheme = "https"
	        }
	        if let host = comps.host?.lowercased(), host.hasSuffix("arxiv.org"), comps.path.hasPrefix("/pdf/") {
	            if !comps.path.lowercased().hasSuffix(".pdf") {
	                comps.path += ".pdf"
	            }
	        }
	        return comps.url ?? url
	    }

    private func prefetchAllPapers(reason: String) {
        // Enqueue synchronously so any immediate user action can subscribe to pending downloads
        // (without triggering on-demand network requests).
        let requests = allItems.compactMap { prefetchRequest(for: $0) }
        NSLog("[PDFEager] eager_enqueue_all count=\(requests.count) reason=\(reason)")
        pdfCache.prefetch(requests, priority: 3, reason: reason)
    }

    private func prunePDFCache(for papers: [Paper]) {
        let urls = papers.compactMap { paper -> URL? in
            let abs = ArxivShareURL.canonicalAbsURL(from: paper.url)?.absoluteString ?? paper.url
            guard let pdfString = arxivPDFFromAbs(url: abs) else { return nil }
            return URL(string: pdfString)
        }
        pdfCache.prune(keepingURLs: urls)
    }

    private func prefetchNeighborPDFs(around index: Int, radius: Int = 2, reason: String) {
        guard index >= 0, index < filtered.count else { return }
        let start = max(0, index - radius)
        let end = min(filtered.count - 1, index + radius)
        guard start <= end else { return }

        var requests: [PDFCacheManager.PrefetchRequest] = []
        for i in start...end where i != index {
            if let req = prefetchRequest(for: filtered[i]) {
                requests.append(req)
            }
        }
        guard !requests.isEmpty else { return }
        pdfCache.prefetch(requests, priority: 2, reason: reason)
    }

	    private func applyPDFDocument(_ doc: PDFDocument,
	                                  token: Int,
	                                  source: String,
	                                  startTime: CFTimeInterval,
	                                  cacheKey: String) {
	        guard pdfLoadToken == token else { return }

        // Save current PDF position before switching
        if let currentDoc = pdfView.document, let currentPage = pdfView.currentPage, let scrollView = pdfView.primaryScrollView() {
            let pageIndex = currentDoc.index(for: currentPage)
            let scrollY = scrollView.contentView.bounds.origin.y
            let scale = pdfView.scaleFactor
            let saveStableID = arxivIDFromPDFURL(currentDoc.documentURL ?? URL(fileURLWithPath: "")) ?? (currentDoc.documentURL == nil ? "sample" : nil)
            if let saveStableID {
                pdfPositions[saveStableID] = (pageIndex, scrollY, scale)
            }
        }

        // Deterministic PDFView reset (single persistent PDFView):
        // Clear selection/state, then swap documents atomically without blanking the view.
        pdfView.highlightedSelections = nil
        pdfView.clearSelection()
        resetPDFFindResults(clearHighlights: false)
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        pdfView.document = doc
	        CATransaction.commit()
	        pdfView.displayBox = .mediaBox

        // Restore position or go to top
        var shouldForceTop = false
        if let stableID = arxivIDFromPDFURL(doc.documentURL ?? URL(fileURLWithPath: "")),
           let position = pdfPositions[stableID],
           let page = doc.page(at: position.pageIndex) {
            pdfView.autoScales = false
            pdfZoomPreset = .free
            applyPDFScale(position.scale)
            pdfView.go(to: page)
            if let scrollView = pdfView.primaryScrollView() {
                var origin = scrollView.contentView.bounds.origin
                origin.y = position.scrollY
                scrollView.contentView.setBoundsOrigin(origin)
            }
        } else {
            // New PDF: reset to page width and scroll to top
            pdfView.autoScales = false
            pdfZoomPreset = .pageWidth
            pdfView.goToFirstPage(nil)
            if let scrollView = pdfView.primaryScrollView() {
                scrollView.contentView.setBoundsOrigin(.zero)
            }
            shouldForceTop = true
        }
        applyPDFZoomPresetIfNeeded()
        if shouldForceTop {
            scrollPDFToDocumentTop()
        }

        DispatchQueue.main.async {
            self.applyPDFZoomPresetIfNeeded()
            if shouldForceTop {
                self.scrollPDFToDocumentTop()
            }
        }
	        installRightPanelScrollRestrictions()
	        enforceWhitePDFBackground()
        annotationController?.refreshIcons()
        refreshAnnotationsPanel(reason: "pdf_apply")
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.05) {
            self.installRightPanelScrollRestrictions()
            self.enforceWhitePDFBackground()
            self.annotationController?.refreshIcons()
            self.applyPDFZoomPresetIfNeeded()
            if shouldForceTop {
                self.scrollPDFToDocumentTop()
            }
        }
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
            self.enforceWhitePDFBackground()
            self.annotationController?.refreshIcons()
            self.applyPDFZoomPresetIfNeeded()
            if shouldForceTop {
                self.scrollPDFToDocumentTop()
            }
        }
        hideLoading()
        refreshZoteroButtonState(reason: "pdf_apply")

        let elapsedMs = Int((monotonicNow() - startTime) * 1000.0)
        let keyLabel = cacheKey.isEmpty ? "none" : String(cacheKey.prefix(8))
        perfLog("pdf_open_ms=\(elapsedMs) source=\(source) key=\(keyLabel)")
        let docID = AstroStack.reportingDocumentID(for: doc)
        reportDocumentIO("pdf_load_complete",
                         documentID: docID,
                         details: ["source": source, "ms": "\(elapsedMs)", "cacheKey": keyLabel])
        if elapsedMs >= ReportingLogConfig.slowOperationThresholdMs {
            reportPerformance("pdf_open_slow", details: ["ms": "\(elapsedMs)", "source": source])
        }

        // Optional: inject a test highlight annotation to ensure something is visibly
        // present for debug captures. Gate with ARXIV_INJECT_TEST_HIGHLIGHT=1.
        if ProcessInfo.processInfo.environment["ARXIV_INJECT_TEST_HIGHLIGHT"] == "1" {
            if let doc = self.pdfView.document, let page = doc.page(at: 0) {
                let crop = page.bounds(for: self.pdfView.displayBox)
                // place a short line near the top of the page
                let testRect = NSRect(x: 72, y: crop.maxY - 80, width: min(300, crop.width - 144), height: 18)
                let ann = PDFAnnotation(bounds: testRect, forType: PDFAnnotationSubtype.highlight, withProperties: nil)
                ann.color = NSColor.systemYellow
                page.addAnnotation(ann)
                print("[DBG_INJECT] added highlight page=0 bounds=\(NSStringFromRect(testRect))")
                // If the debug hide flag is set, force a refresh so the hide-path
                // runs before we capture the snapshot.
                if ProcessInfo.processInfo.environment["ARXIV_DEBUG_HIDE_PDF_ANNOTATIONS"] == "1" {
                    annotationController?.refreshIcons()
                }
                // Optional: persist immediately to exercise the save path (set to 1 to enable)
                if ProcessInfo.processInfo.environment["ARXIV_INJECT_AND_PERSIST"] == "1" {
                    if let doc = page.document {
                        print("[DBG_INJECT] persisting after injection page=0 (manual write)")
                        if let caches = FileManager.default.urls(for: .cachesDirectory, in: .userDomainMask).first {
                            let tmpURL = caches.appendingPathComponent("debug-inject-\(UUID().uuidString).pdf")
                            if doc.write(to: tmpURL) {
                                print("[DBG_INJECT] document.write succeeded tmp=\(tmpURL.path)")
                            } else {
                                print("[DBG_INJECT] document.write failed tmp=\(tmpURL.path)")
                            }
                        }
                        self.pdfView.go(to: page)
                        annotationController?.refreshIcons()
                    }
                }
            }
        }

        // If requested, capture an in-process snapshot of the host (no screen-record
        // permission required) and write it to /tmp so automated tests can inspect the
        // visible overlays / highlight fills.
        if ProcessInfo.processInfo.environment["ARXIV_CAPTURE_HOST_SNAPSHOT"] == "1" {
            let path = "/tmp/arxiv_snapshot_\(Int(Date().timeIntervalSince1970)).png"
            annotationController?.debugSaveHostSnapshot(to: path)
        }
    }

private func pdfGlassBackgroundImageURL() -> URL? {
    if let configured = PDF_GLASS_BACKGROUND_IMAGE_PATH,
       !configured.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
        return URL(fileURLWithPath: (configured as NSString).expandingTildeInPath)
    }

    guard let raw = ProcessInfo.processInfo.environment["ARXIV_PDF_GLASS_BACKGROUND_IMAGE"],
          !raw.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
        return nil
    }
    let expanded = (raw as NSString).expandingTildeInPath
    return URL(fileURLWithPath: expanded)
}

    private func refreshPDFBackgroundImage() {
        PerfLogger.begin("pdf.background_image.refresh")
        defer { PerfLogger.end("pdf.background_image.refresh") }
        let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
        defer {
            if resizePerfEnabled {
                ResizePerfTrace.shared.recordWork(name: "pdf.background_image.refresh", durationNs: monotonicNowNs() &- perfStart)
            }
        }
        guard let url = pdfGlassBackgroundImageURL() else {
            pdfBackgroundImageView?.removeFromSuperview()
            pdfBackgroundImageView = nil
            return
        }
        var data: Data?
        PerfLogger.measure("io.pdf_background.read") {
            data = try? Data(contentsOf: url)
        }
        guard let data, let image = NSImage(data: data) else {
            return
        }

        let imageView: NSImageView
        if let existing = pdfBackgroundImageView {
            imageView = existing
        } else {
            imageView = NSImageView(frame: rightPDFBackgroundView.bounds)
            imageView.wantsLayer = true
            imageView.layer?.backgroundColor = NSColor.clear.cgColor
            imageView.imageScaling = .scaleAxesIndependently
            imageView.autoresizingMask = [.width, .height]
            rightPDFBackgroundView.addSubview(imageView, positioned: .below, relativeTo: nil)
            pdfBackgroundImageView = imageView
        }

        imageView.image = image
        let hostBounds = rightPDFBackgroundView.bounds
        let targetWidth = hostBounds.width * 0.6
        let targetHeight = hostBounds.height * 0.6
        let scale = min(1.0, min(targetWidth / max(1, image.size.width),
                                  targetHeight / max(1, image.size.height)))
        let drawSize = CGSize(width: image.size.width * scale,
                              height: image.size.height * scale)
        imageView.frame = CGRect(
            x: (hostBounds.width - drawSize.width) / 2,
            y: (hostBounds.height - drawSize.height) / 2,
            width: drawSize.width,
            height: drawSize.height
        )

        let baseBackground: NSColor = {
            if let cg = rightPDFBackgroundView.layer?.backgroundColor,
               let color = NSColor(cgColor: cg) {
                return color
            }
            if let cg = rightContainer.layer?.backgroundColor,
               let color = NSColor(cgColor: cg) {
                return color
            }
            return windowBackgroundSolidColor()
        }()
        let baseLum = relativeLuminance(baseBackground)
        let avgColor = averageColor(from: image, sampleSize: 24)
        let avgLum = avgColor.map(relativeLuminance) ?? baseLum
        let contrast = avgColor.map { contrastRatio($0, baseBackground) } ?? 3.0
        let lumDelta = abs(baseLum - avgLum)
        let minRatio: CGFloat = 1.8
        let contrastDeficit = max(0.0, min(1.0, (minRatio - contrast) / (minRatio - 1.0)))
        let needsPlate = contrast < minRatio || lumDelta < 0.18
        let isLightBackground = baseLum > 0.6
        let plateBase: CGFloat = isLightBackground ? 0.06 : 0.08
        let plateBoost: CGFloat = isLightBackground ? 0.08 : 0.10
        let plateAlpha: CGFloat = needsPlate ? (plateBase + (plateBoost * contrastDeficit)) : 0.0
        let plateColor = (isLightBackground ? NSColor.black : NSColor.white).withAlphaComponent(plateAlpha)
        let shadowColor = (isLightBackground ? NSColor.black : NSColor.white).withAlphaComponent(needsPlate ? 0.32 : 0.18)
        let shadowOpacity: Float = needsPlate
            ? (isLightBackground ? 0.26 : 0.20)
            : (isLightBackground ? 0.18 : 0.12)
        let shadowRadius: CGFloat = needsPlate
            ? (isLightBackground ? 18 : 12)
            : (isLightBackground ? 14 : 10)
        let shadowOffset = CGSize(width: 0, height: -2)
        let cornerRadius = max(8, min(22, min(drawSize.width, drawSize.height) * 0.08))
        if let layer = imageView.layer {
            layer.masksToBounds = false
            layer.backgroundColor = plateColor.cgColor
            layer.cornerRadius = cornerRadius
            layer.shadowColor = shadowColor.cgColor
            layer.shadowOpacity = shadowOpacity
            layer.shadowRadius = shadowRadius
            layer.shadowOffset = shadowOffset
            layer.shadowPath = CGPath(roundedRect: imageView.bounds,
                                      cornerWidth: cornerRadius,
                                      cornerHeight: cornerRadius,
                                      transform: nil)
        }
    }

    private func refreshEmbeddedPDFImage() {
        PerfLogger.begin("pdf.embedded_image.refresh")
        defer { PerfLogger.end("pdf.embedded_image.refresh") }
        let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
        defer {
            if resizePerfEnabled {
                ResizePerfTrace.shared.recordWork(name: "pdf.embedded_image.refresh", durationNs: monotonicNowNs() &- perfStart)
            }
        }
        guard let url = pdfGlassBackgroundImageURL() else {
            if let existing = pdfEmbeddedImageAnnotation {
                existing.page?.removeAnnotation(existing)
            }
            pdfEmbeddedImageAnnotation = nil
            return
        }
        var data: Data?
        PerfLogger.measure("io.pdf_embedded.read") {
            data = try? Data(contentsOf: url)
        }
        guard let data,
              let image = NSImage(data: data),
              let doc = pdfView.document,
              let page = doc.page(at: 0) else {
            if let existing = pdfEmbeddedImageAnnotation {
                existing.page?.removeAnnotation(existing)
            }
            pdfEmbeddedImageAnnotation = nil
            return
        }

        if let existing = pdfEmbeddedImageAnnotation {
            existing.page?.removeAnnotation(existing)
        }

        let pageBounds = page.bounds(for: pdfView.displayBox)
        let maxWidth = pageBounds.width * 0.45
        let width = min(maxWidth, image.size.width)
        let scale = width / max(1, image.size.width)
        let height = image.size.height * scale
        let rect = CGRect(
            x: (pageBounds.width - width) / 2,
            y: (pageBounds.height - height) / 2,
            width: width,
            height: height
        )
        let annotation = PDFAnnotation(bounds: rect, forType: .stamp, withProperties: nil)
        let imageKey = PDFAnnotationKey(rawValue: "Image")
        annotation.setValue(image, forAnnotationKey: imageKey)
        annotation.isReadOnly = true
        annotation.shouldPrint = true
        page.addAnnotation(annotation)
        pdfEmbeddedImageAnnotation = annotation
    }

    private func logListRenderIfNeeded() {
        guard let start = listRenderStartTime, listRenderLogged == false else { return }
        listRenderLogged = true
        let elapsedMs = Int((monotonicNow() - start) * 1000.0)
        perfLog("list_first_render_ms=\(elapsedMs) rows=\(filtered.count)")
        if elapsedMs >= ReportingLogConfig.slowOperationThresholdMs {
            reportPerformance("list_first_render_slow", details: ["ms": "\(elapsedMs)", "rows": "\(filtered.count)"])
        }
    }

    // MARK: PDF Find HUD (Cmd-F)

    private func setupPDFFindHUD() {
        let searchTheme = currentSearchBarTheme()
        let findTint = pdfFindGlassTintColor()
        let buttonTint = findTint
        pdfFindHUD = NSView(frame: .zero)
        pdfFindHUD.translatesAutoresizingMaskIntoConstraints = true
        pdfFindHUD.isHidden = true

        if let card = makePDFFindGlassCard(tint: findTint, refractionOnly: false) as? GlassCardView {
            pdfFindBackgroundView = card
            card.cornerRadius = 12
            card.layer?.shadowOpacity = 0
            card.layer?.shadowRadius = 0
            card.layer?.shadowOffset = .zero
            card.layer?.masksToBounds = true
        } else {
            pdfFindBackgroundView = makePDFFindGlassCard(tint: findTint, refractionOnly: false)
            pdfFindBackgroundView.layer?.cornerRadius = 12
            pdfFindBackgroundView.layer?.shadowOpacity = 0
            pdfFindBackgroundView.layer?.shadowRadius = 0
            pdfFindBackgroundView.layer?.shadowOffset = .zero
            pdfFindBackgroundView.layer?.masksToBounds = true
        }
        applySearchBarTheme(to: pdfFindBackgroundView, tintOverride: findTint)

        pdfFindContentView.translatesAutoresizingMaskIntoConstraints = true
        pdfFindContentView.wantsLayer = true
        pdfFindContentView.layer?.opacity = 0

        pdfFindOutlineLayer.fillColor = NSColor.clear.cgColor
        pdfFindOutlineLayer.lineJoin = .round
        pdfFindOutlineLayer.lineCap = .round
        pdfFindOutlineLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
        pdfFindHighlightLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
        pdfFindFalloffLayer.contentsScale = NSScreen.main?.backingScaleFactor ?? 2.0
        pdfFindHighlightLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        pdfFindHighlightLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
        pdfFindFalloffLayer.startPoint = CGPoint(x: 0.5, y: 1.0)
        pdfFindFalloffLayer.endPoint = CGPoint(x: 0.5, y: 0.0)
        pdfFindFalloffLayer.opacity = 0.75
        pdfFindField.target = self
        pdfFindField.action = #selector(pdfFindSubmitted)
        pdfFindField.delegate = self
        if let cell = pdfFindField.cell as? NSSearchFieldCell {
            cell.cancelButtonCell = nil
        }

        // Small clear (x) button that follows the end of the typed text.
        pdfFindClearButton.translatesAutoresizingMaskIntoConstraints = true
        pdfFindClearButton.isBordered = false
        pdfFindClearButton.bezelStyle = .regularSquare
        pdfFindClearButton.title = ""
        pdfFindClearButton.target = self
        pdfFindClearButton.action = #selector(pdfFindClearPressed)
        pdfFindClearButton.imagePosition = .imageOnly
        pdfFindClearButton.setAccessibilityLabel("Clear")
        pdfFindClearButton.toolTip = nil
        pdfFindClearButton.isHidden = true

        pdfFindCountLabel.font = NSFont.monospacedDigitSystemFont(ofSize: searchTheme.secondaryFont.pointSize,
                                                                  weight: .regular)
        pdfFindCountLabel.alignment = .center
        pdfFindCountLabel.usesSingleLineMode = true
        pdfFindCountLabel.lineBreakMode = .byClipping

        let pdfFindPrevGlass = makePDFFindGlassCard(tint: buttonTint)
        let pdfFindNextGlass = makePDFFindGlassCard(tint: buttonTint)
        pdfFindPrevGlassBackground = pdfFindPrevGlass
        pdfFindNextGlassBackground = pdfFindNextGlass

        let symbolConfig = toolbarSymbolConfig()
        pdfFindPrevButton.image = NSImage(systemSymbolName: "chevron.left", accessibilityDescription: nil)?
            .withSymbolConfiguration(symbolConfig)
        pdfFindNextButton.image = NSImage(systemSymbolName: "chevron.right", accessibilityDescription: nil)?
            .withSymbolConfiguration(symbolConfig)
        pdfFindPrevButton.target = self
        pdfFindNextButton.target = self
        pdfFindPrevButton.action = #selector(pdfFindPreviousMatch)
        pdfFindNextButton.action = #selector(pdfFindNextMatch)
        pdfFindPrevButton.setAccessibilityLabel("Previous Match")
        pdfFindNextButton.setAccessibilityLabel("Next Match")
        pdfFindPrevButton.toolTip = nil
        pdfFindNextButton.toolTip = nil
        pdfFindPrevButton.attachLiquidGlassBackground(pdfFindPrevGlass)
        pdfFindNextButton.attachLiquidGlassBackground(pdfFindNextGlass)

        pdfFindHUD.addSubview(pdfFindBackgroundView)
        pdfFindHUD.addSubview(pdfFindContentView)
        pdfFindContentView.addSubview(pdfFindField)
        pdfFindContentView.addSubview(pdfFindClearButton)
        pdfFindContentView.addSubview(pdfFindCountLabel)
        pdfFindContentView.addSubview(pdfFindPrevGlass)
        pdfFindContentView.addSubview(pdfFindNextGlass)
        pdfFindContentView.addSubview(pdfFindPrevButton)
        pdfFindContentView.addSubview(pdfFindNextButton)
        rightContentView.addSubview(pdfFindHUD)
        updatePDFFindAppearance()
        installPDFFindTracking()
        updatePDFFindControls()
    }

    private func layoutPDFFindHUDSubviews() {
        guard !pdfFindHUD.isHidden else { return }
        let ib = rightContentView.bounds.insetBy(dx: PANEL_INSET, dy: PANEL_INSET)

        let hudW: CGFloat = min(420, ib.width - 24)
        let hudH: CGFloat = 46
        let x = ib.minX + (ib.width - hudW) / 2
        let y = ib.maxY - hudH - 14

        pdfFindHUD.frame = NSRect(x: x, y: y, width: hudW, height: hudH)
        pdfFindBackgroundView.frame = pdfFindHUD.bounds
        pdfFindContentView.frame = pdfFindHUD.bounds
        let fieldHeight: CGFloat = 26
        let contentInsetX: CGFloat = 12
        let contentInsetRight: CGFloat = 12
        let fieldToControlsGap: CGFloat = 8
        let controlGap: CGFloat = 6
        let arrowButtonSize: CGFloat = 20
        let countWidth: CGFloat = 72
        let labelHeight = max(14, pdfFindCountLabel.intrinsicContentSize.height)
        let fieldY = round((hudH - fieldHeight) / 2)
        let labelY = round((hudH - labelHeight) / 2)
        let buttonY = round((hudH - arrowButtonSize) / 2)

        let rightControlsWidth = (2 * arrowButtonSize) + countWidth + (2 * controlGap)
        let availableFieldWidth = hudW - contentInsetX - contentInsetRight - rightControlsWidth - fieldToControlsGap
        let fieldWidth = max(0, availableFieldWidth)
        let controlsX = hudW - contentInsetRight - rightControlsWidth

        pdfFindField.frame = NSRect(x: contentInsetX, y: fieldY, width: fieldWidth, height: fieldHeight)
        pdfFindPrevButton.frame = NSRect(x: controlsX,
                                         y: buttonY,
                                         width: arrowButtonSize,
                                         height: arrowButtonSize)
        pdfFindCountLabel.frame = NSRect(x: controlsX + arrowButtonSize + controlGap,
                                         y: labelY,
                                         width: countWidth,
                                         height: labelHeight)
        pdfFindNextButton.frame = NSRect(x: controlsX + arrowButtonSize + controlGap + countWidth + controlGap,
                                         y: buttonY,
                                         width: arrowButtonSize,
                                         height: arrowButtonSize)
        pdfFindPrevButton.setCornerRadius(arrowButtonSize / 2)
        pdfFindNextButton.setCornerRadius(arrowButtonSize / 2)
        pdfFindPrevButton.needsLayout = true
        pdfFindNextButton.needsLayout = true

        updatePDFFindClearButtonLayout()

        let radius = hudH / 2
        if let card = pdfFindBackgroundView as? GlassCardView {
            card.cornerRadius = radius
        } else if let glass = pdfFindBackgroundView as? NSGlassEffectView {
            glass.cornerRadius = radius
        }
        if let layer = pdfFindBackgroundView.layer {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.cornerRadius = radius
            layer.masksToBounds = true
            layer.anchorPoint = CGPoint(x: 0.5, y: 0.5)
            layer.position = CGPoint(x: layer.bounds.midX, y: layer.bounds.midY)
            CATransaction.commit()
        }
        if let layer = pdfFindContentView.layer {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.anchorPoint = CGPoint(x: 0.5, y: 0.5)
            layer.position = CGPoint(x: layer.bounds.midX, y: layer.bounds.midY)
            CATransaction.commit()
        }

        installPDFFindTracking()
        updatePDFFindCapsuleGeometry()
        updatePDFFindDepth(animated: false)
    }

    @objc private func pdfFindClearPressed() {
        pdfFindField.stringValue = ""
        resetPDFFindResults(clearHighlights: true)
        updatePDFFindClearButtonLayout()
        window?.makeFirstResponder(pdfFindField)
    }

    private func updatePDFFindClearButtonLayout() {
        guard pdfFindHUD.isHidden == false else {
            pdfFindClearButton.isHidden = true
            return
        }

        let q = pdfFindField.stringValue
        let hasText = !q.isEmpty
        pdfFindClearButton.isHidden = !hasText
        guard hasText else { return }

        let buttonSize: CGFloat = 14
        let padAfterText: CGFloat = 4
        let insetX: CGFloat = 6
        let fieldFrame = pdfFindField.frame
        let minX = fieldFrame.minX + insetX
        let maxX = fieldFrame.maxX - insetX - buttonSize

        var endX: CGFloat?
        if let w = window,
           let editor = w.fieldEditor(false, for: pdfFindField) as? NSTextView,
           w.firstResponder === editor {
            let end = (editor.string as NSString).length
            editor.scrollRangeToVisible(NSRange(location: end, length: 0))
            let rectOnScreen = editor.firstRect(forCharacterRange: NSRange(location: end, length: 0), actualRange: nil)
            let rectInWindow = w.convertFromScreen(NSRect(origin: rectOnScreen.origin, size: rectOnScreen.size))
            let rectInContent = pdfFindContentView.convert(rectInWindow, from: nil)
            endX = rectInContent.minX
        }

        if endX == nil {
            let font = pdfFindField.font ?? currentSearchBarTheme().font
            let attr = NSAttributedString(string: q, attributes: [.font: font])
            let textW = attributedSingleLineTypographicWidth(attr)
            if let cell = pdfFindField.cell as? NSSearchFieldCell {
                let textRect = cell.searchTextRect(forBounds: pdfFindField.bounds)
                endX = fieldFrame.minX + textRect.minX + textW
            } else {
                endX = fieldFrame.minX + insetX + textW
            }
        }

        let rawX = (endX ?? minX) + padAfterText
        let clampedX = max(minX, min(maxX, rawX))
        let y = round(fieldFrame.midY - buttonSize / 2)
        pdfFindClearButton.frame = NSRect(x: clampedX, y: y, width: buttonSize, height: buttonSize)
    }

    private func showPDFFindHUD() {
        guard isShowingPDF else { return }
        pdfFindHover = false
        pdfFindFocused = false
        setPDFFindHUDVisible(true, animated: true)
        resetPDFFindResults(clearHighlights: true)
        window?.makeFirstResponder(pdfFindField)
    }

    private func hidePDFFindHUD() {
        resetPDFFindResults(clearHighlights: true)
        pdfFindHover = false
        pdfFindFocused = false
        updatePDFFindDepth(animated: false)
        setPDFFindHUDVisible(false, animated: true)
    }

    @objc private func pdfFindSubmitted() {
        let mods = NSEvent.modifierFlags.intersection(.deviceIndependentFlagsMask)
        let backwards = mods.contains(.shift)
        let q = normalizedPDFFindQuery(pdfFindField.stringValue)
        guard !q.isEmpty else { return }
        navigatePDFFind(delta: backwards ? -1 : 1, query: q, beepOnEmpty: true)
    }

    @objc private func pdfFindPreviousMatch() {
        navigatePDFFind(delta: -1, query: pdfFindField.stringValue, beepOnEmpty: true)
    }

    @objc private func pdfFindNextMatch() {
        navigatePDFFind(delta: 1, query: pdfFindField.stringValue, beepOnEmpty: true)
    }

    private func normalizedPDFFindQuery(_ query: String) -> String {
        query.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func pdfFindQueryDidChange() {
        let q = normalizedPDFFindQuery(pdfFindField.stringValue)
        guard !q.isEmpty else {
            resetPDFFindResults(clearHighlights: true)
            updatePDFFindClearButtonLayout()
            return
        }
        rebuildPDFFindResults(for: q)
        updatePDFFindClearButtonLayout()
    }

    private func resetPDFFindResults(clearHighlights: Bool) {
        pdfFindResults = []
        pdfFindIndex = -1
        pdfFindQuery = ""
        if clearHighlights {
            pdfView.highlightedSelections = nil
            pdfView.clearSelection()
        }
        updatePDFFindControls()
    }

    private func updatePDFFindControls() {
        let total = pdfFindResults.count
        let current = (total > 0 && pdfFindIndex >= 0) ? (min(pdfFindIndex, total - 1) + 1) : 0
        pdfFindCountLabel.stringValue = "\(current)/\(total)"

        let prevEnabled = total > 0 && pdfFindIndex > 0
        let nextEnabled = total > 0 && pdfFindIndex >= 0 && pdfFindIndex < total - 1
        pdfFindPrevButton.isEnabled = prevEnabled
        pdfFindNextButton.isEnabled = nextEnabled
        pdfFindPrevButton.alphaValue = prevEnabled ? 1.0 : 0.45
        pdfFindNextButton.alphaValue = nextEnabled ? 1.0 : 0.45
    }

    private func rebuildPDFFindResults(for query: String) {
        guard let doc = pdfView.document else {
            pdfFindQuery = query
            pdfFindResults = []
            pdfFindIndex = -1
            pdfView.highlightedSelections = nil
            pdfView.clearSelection()
            updatePDFFindControls()
            return
        }
        pdfFindQuery = query
        pdfFindResults = doc.findString(query, withOptions: [.caseInsensitive])
        if pdfFindResults.isEmpty {
            pdfFindIndex = -1
            pdfView.highlightedSelections = nil
            pdfView.clearSelection()
            updatePDFFindControls()
            return
        }
        pdfFindIndex = 0
        goToPDFFindMatch(at: pdfFindIndex)
        updatePDFFindControls()
    }

    private func navigatePDFFind(delta: Int, query: String, beepOnEmpty: Bool) {
        let normalized = normalizedPDFFindQuery(query)
        guard !normalized.isEmpty else {
            resetPDFFindResults(clearHighlights: true)
            return
        }

        let needsRebuild = normalized != pdfFindQuery || pdfFindResults.isEmpty
        if needsRebuild {
            rebuildPDFFindResults(for: normalized)
        }

        if pdfFindResults.isEmpty {
            if beepOnEmpty { NSSound.beep() }
            updatePDFFindControls()
            return
        }

        if needsRebuild {
            return
        }

        if pdfFindIndex < 0 {
            pdfFindIndex = 0
        }

        let target = max(0, min(pdfFindResults.count - 1, pdfFindIndex + delta))
        guard target != pdfFindIndex else {
            updatePDFFindControls()
            return
        }

        pdfFindIndex = target
        goToPDFFindMatch(at: pdfFindIndex)
        updatePDFFindControls()
    }

    private func goToPDFFindMatch(at index: Int) {
        guard index >= 0, index < pdfFindResults.count else { return }
        let selection = pdfFindResults[index]
        pdfView.setCurrentSelection(selection, animate: false)
        pdfView.highlightedSelections = [selection]

        guard let page = selection.pages.first as? PDFPage,
              let scrollView = descendantScrollViews(in: pdfView).first,
              let docView = scrollView.documentView else {
            pdfView.scrollSelectionToVisible(nil)
            return
        }

        // Convert PDF page coordinates -> PDFView -> documentView so scroll positions
        // are computed in the same space as the clip view bounds, then clamp to doc limits.
        let matchRectInView = pdfView.convert(selection.bounds(for: page), from: page)
        let matchRectInDoc = pdfView.convert(matchRectInView, to: docView)
        let viewportHeight = scrollView.contentView.bounds.height
        let minY = docView.bounds.minY
        let maxY = max(minY, docView.bounds.maxY - viewportHeight)
        let targetY = max(minY, min(maxY, matchRectInDoc.midY - viewportHeight / 2))

        let clipView = scrollView.contentView
        clipView.setBoundsOrigin(NSPoint(x: clipView.bounds.origin.x, y: targetY))
        scrollView.reflectScrolledClipView(clipView)
    }

    // MARK: Click handling

    private func setupSelectionClearMonitor() {
        guard selectionClearMonitor == nil else { return }
        selectionClearMonitor = NSEvent.addLocalMonitorForEvents(matching: [.leftMouseDown, .rightMouseDown]) { [weak self] event in
            guard let self else { return event }
            self.clearListSelectionIfNeeded(for: event)
            return event
        }
    }

    private func setupDividerDragEndMonitor() {
        guard dividerDragEndMonitor == nil else { return }
        dividerDragEndMonitor = NSEvent.addLocalMonitorForEvents(matching: .leftMouseUp) { [weak self] event in
            guard let self else { return event }
            // Native split-view divider drags can end without another didResize notification.
            // If we don't clear this flag, later drags/resizes can appear “stuck”.
            if self.dividerDragActive {
                self.dividerDragActive = false
                self.systemDividerDragPendingSplitModeExit = false
                self.logDividerState("drag_end_mouse_up")
                self.schedulePanelSettle()

                // If the user dragged the (previously hidden) sidebar open while Chat is hidden,
                // treat that as an explicit unhide intent before clamping.
                if !self.sidebarVisible,
                   !self.rightAuxPanelVisible {
                    let w = self.leftContainer.frame.width
                    if w.isFinite, w > 12 {
                        self.sidebarVisible = true
                        self.lastUserActivatedPanel = .leftContainer
                        self.lastSidebarWidth = w
                        self.persistSidebarVisibility(true)
                        self.persistSidebarWidth(w)
                        self.updateSidebarToggleIcon()
                        self.leftContainer.setAccessibilityHidden(false)
                        uiLog("sidebar_unhide_via_divider_drag width=\(Int(w))")
                    }
                }

                self.enforceSidebarWidthBounds(reason: "drag_end_mouse_up")
                self.scheduleDividerDragReflow()
                if self.rightAuxPanelVisible {
                    let w = self.rightAuxPanelWidth()
                    if w.isFinite, w > 0 {
                        self.lastRightAuxPanelWidth = w
                        self.persistRightAuxWidth(w)
                    }
                }
                if debugLayoutEnabled {
                    self.updateLayoutDebugOverlay(reason: "drag_end_mouse_up")
                }
            }
            return event
        }
    }

    private func clearListSelectionIfNeeded(for event: NSEvent) {
        guard let window, window.isKeyWindow else { return }
        let pointInTable = tableView.convert(event.locationInWindow, from: nil)
        // Only clear selection when the user clicks empty space *within* the table.
        // Clicking elsewhere (e.g. the PDF viewer) should not clear the current paper selection.
        guard tableView.bounds.contains(pointInTable) else { return }
        let row = tableView.row(at: pointInTable)
        guard row < 0 else { return }
        if tableView.selectedRow >= 0 {
            tableView.deselectAll(nil)
        }
    }

    // MARK: Key handling (Enter / Cmd-F / Esc / Cmd-Shift-E)

    private func currentViewerPaperRowForToggle() -> Int? {
        if let idx = selectedFilteredIndex() {
            return idx
        }
        guard selectionHistoryIndex >= 0, selectionHistoryIndex < selectionHistory.count else {
            return nil
        }
        let key = selectionHistory[selectionHistoryIndex].key
        return filteredIndex(for: key)
    }

    private func setupKeyHandling() {
        keyMonitor = NSEvent.addLocalMonitorForEvents(matching: .keyDown) { [weak self] e in
            guard let self, self.window?.isKeyWindow == true else { return e }

            if ReportingLogger.shared.isActive, e.keyCode == 53 {
                self.exitReportingMode(cancelled: true, reason: "escape_key")
                return nil
            }

            if self.window?.attachedSheet != nil {
                return e
            }

            if let keyWindow = NSApp.keyWindow, keyWindow !== self.window {
                return e
            }

            if let editor = NSApp.keyWindow?.firstResponder as? NSTextView {
                if editor.isFieldEditor {
                    let isSearchEditor = (self.searchField.currentEditor() === editor)
                        || (self.rightAuxAskField.currentEditor() === editor)
                        || (self.pdfFindField.currentEditor() === editor)
                    if !isSearchEditor {
                        return e
                    }
                } else if editor.isEditable {
                    // Allow inline-math and annotation editors to consume shortcuts (e.g. Cmd-Shift-E).
                    return e
                }
            }

            if self.annotationController?.isComposerVisible == true {
                return e
            }

            if let eventWindow = e.window, eventWindow !== self.window {
                return e
            }

            let mods = e.modifierFlags.intersection(.deviceIndependentFlagsMask)
            let key = (e.charactersIgnoringModifiers ?? "").lowercased()

            if e.keyCode == 53 {
                if !self.menuContainer.isHidden {
                    self.setMenuVisible(false, animated: true)
                    return nil
                }
                if self.suggestionsVisible {
                    self.setSuggestionsVisible(false, animated: true)
                    return nil
                }
            }

            if !self.menuContainer.isHidden {
                switch e.keyCode {
                case 125: // down
                    self.moveMenuSelection(1)
                    return nil
                case 126: // up
                    self.moveMenuSelection(-1)
                    return nil
                case 36, 76: // Return / Enter
                    self.activateMenuSelection()
                    return nil
                default:
                    break
                }
            }

            if self.searchFocused {
                if self.suggestionsVisible {
                    switch e.keyCode {
                    case 125: // down
                        self.moveSuggestionSelection(1)
                        return nil
                    case 126: // up
                        self.moveSuggestionSelection(-1)
                        return nil
                    case 36, 76: // Return / Enter
                        self.acceptSuggestionSelection()
                        return nil
                    case 53: // Esc handled above
                        return nil
                    default:
                        break
                    }
                } else {
                    // Allow text navigation when suggestions are not visible.
                    if e.keyCode == 125 || e.keyCode == 126 {
                        return e
                    }
                    if e.keyCode == 36 || e.keyCode == 76 {
                        return e
                    }
                }
            }

            // When the PDF pane is visible and PDFKit (or our PDFView) is the active responder,
            // do NOT steal navigation keys; they should scroll the PDF.
            if self.isShowingPDF {
                if let responderView = self.window?.firstResponder as? NSView,
                   responderView.isDescendant(of: self.pdfView) {
                    switch e.keyCode {
                    case 125, 126, 116, 121, 49, 115, 119: // ↓ ↑ PageUp PageDown Space Home End
                        return e
                    default:
                        break
                    }
                }
            }

            // Key routing note:
            // We capture ↑/↓ at the app level so list navigation keeps working even when PDFKit's view hierarchy
            // is the first responder (PDFView/scroll views tend to consume arrow-key events).

	            // Cmd-Shift-E exits for Shortcuts continuation
	            if mods.contains([.command, .shift]) && key == "e" {
	                self.window?.close()
	                return nil
	            }

            // Esc: only act when PDF or its find HUD is active; otherwise swallow to avoid cancel/close.
            if e.keyCode == 53 {
                if !self.pdfFindHUD.isHidden {
                    self.hidePDFFindHUD()
                    return nil
                }
                if self.isShowingPDF {
                    self.showDetailsPanel()
                    return nil
                }
                return nil
            }

            // Cmd-F: open PDF find when PDF is showing
            if mods.contains(.command) && key == "f" {
                if self.isShowingPDF {
                    self.reportUIEvent("keyboard_shortcut", details: ["action": "pdf_find", "keys": "cmd+f"])
                    self.showPDFFindHUD()
                    return nil
                }
                return e
            }

            if mods.contains(.command) && (key == "=" || key == "+") {
                if self.isShowingPDF {
                    self.reportUIEvent("keyboard_shortcut", details: ["action": "pdf_zoom_in", "keys": "cmd++"])
                    self.zoomPDFStep(increase: true, event: e)
                    return nil
                }
                return e
            }

            if mods.contains(.command) && (key == "-" || key == "_") {
                if self.isShowingPDF {
                    self.reportUIEvent("keyboard_shortcut", details: ["action": "pdf_zoom_out", "keys": "cmd+-"])
                    self.zoomPDFStep(increase: false, event: e)
                    return nil
                }
                return e
            }

            if mods.contains(.command) && key == "0" {
                if self.isShowingPDF {
                    self.reportUIEvent("keyboard_shortcut", details: ["action": "pdf_zoom_reset", "keys": "cmd+0"])
                    self.zoomPDFReset(event: e)
                    return nil
                }
                return e
            }

            // Enter/Return opens PDF in right panel
            switch e.keyCode {
            case 125: // down
                if let idx = self.selectedFilteredIndex() {
                    self.select(idx + 1)
                } else if !self.filtered.isEmpty {
                    self.select(0)
                }
                return nil
            case 126: // up
                if let idx = self.selectedFilteredIndex() {
                    self.select(idx - 1)
                }
                return nil
            case 36, 76: // Return / Enter
                // When both left + chat panels are hidden, the table selection can be nil even
                // though we're still viewing a concrete paper. Fall back to the current history entry
                // so Enter toggles to PDF exactly like the normal (sidebar-visible) case.
                let isViewerOnly = (!self.sidebarVisible && !self.rightAuxPanelVisible)
                let targetRow: Int?
                if isViewerOnly {
                    targetRow = self.currentViewerPaperRowForToggle()
                } else {
                    targetRow = self.selectedFilteredIndex()
                }

                if let dataRow = targetRow {
                    self.reportUIEvent("keyboard_shortcut", details: ["action": "open_pdf", "keys": "enter"])
                    // Enter-key PDF switching uses the same canonical presenter as details-panel PDF link clicks.
                    self.openPDFInRightPanel(forRow: dataRow, trigger: isViewerOnly ? "keyboard-enter-viewer-only" : "keyboard-enter")
                }
                return nil
            default:
                return e
            }
        }
    }

    // MARK: Reporting Mode

    func enterReportingMode(source: String) {
        guard reportingModeActive == false else { return }
        let bugID = Int(Date().timeIntervalSince1970 * 1000)
        reportingBugID = bugID
        reportingModeActive = true
        ReportingLogger.shared.beginSession(bugID: bugID)
        reportingOverlayLabel.stringValue = "Reporting Mode - Bug #\(bugID)"
        if reportingEscMonitor == nil {
            reportingEscMonitor = NSEvent.addLocalMonitorForEvents(matching: .keyDown) { [weak self] event in
                guard let self else { return event }
                if ReportingLogger.shared.isActive, event.keyCode == 53 {
                    self.exitReportingMode(cancelled: true, reason: "escape_key")
                    return nil
                }
                return event
            }
        }
        reportUIEvent("report_bugs", details: ["source": source])
        reportStateTransition("reporting_mode_enter", details: ["source": source])
        setReportingOverlayVisible(true)
        showReportingInstructions()
    }

    @objc private func reportingDonePressed(_ sender: Any?) {
        reportUIEvent("button_press", details: ["button": "report_done"])
        exitReportingMode(cancelled: false, reason: "done_button")
    }

    @objc private func reportingCancelPressed(_ sender: Any?) {
        reportUIEvent("button_press", details: ["button": "report_cancel"])
        exitReportingMode(cancelled: true, reason: "cancel_button")
    }

    private func exitReportingMode(cancelled: Bool, reason: String) {
        guard reportingModeActive else { return }
        reportStateTransition("reporting_mode_exit", details: ["reason": cancelled ? "cancel" : "done", "trigger": reason])
        let report = ReportingLogger.shared.endSession(discard: cancelled)
        reportingModeActive = false
        reportingBugID = nil
        if let monitor = reportingEscMonitor {
            NSEvent.removeMonitor(monitor)
            reportingEscMonitor = nil
        }
        setReportingOverlayVisible(false)
        reportingOverlayLabel.stringValue = "Reporting Mode"
        if cancelled { return }
        guard let report else { return }
        composeBugReportEmail(report: report)
    }

    private func showReportingInstructions() {
        let alert = NSAlert()
        alert.messageText = "Reporting Mode"
        alert.informativeText = """
Reproduce the bug by repeating the exact steps that caused it.
Perform those steps sequentially, as they originally occurred.
"""
        alert.addButton(withTitle: "OK")
        if let w = window {
            alert.beginSheetModal(for: w, completionHandler: nil)
        } else {
            _ = alert.runModal()
        }
    }

    private func setReportingOverlayVisible(_ visible: Bool) {
        reportingOverlay.isHidden = !visible
    }

    private func buildBugReportEmailBody(report: ReportingLogReport) -> String {
        let formatter = ISO8601DateFormatter()
        formatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        let dateText = formatter.string(from: Date())
        let infoLogs = report.infoWarnErrorEntries
        let logsText = infoLogs.isEmpty ? "[]" : report.jsonString(for: infoLogs)
        let debugNote = report.debugEntries.isEmpty
            ? "Debug logs: none."
            : "Debug logs: attached as a separate file (if supported by your email app)."
        return """
AstroStack Bug Report
Bug ID: \(report.bugID)
Date: \(dateText)
\(debugNote)

Please describe what happened:

Steps to reproduce:
1.
2.

--- Logs (INFO/WARN/ERROR) ---
\(logsText)
"""
    }

    private func composeBugReportEmail(report: ReportingLogReport) {
        let subject = "AstroStack Bug #\(report.bugID)"
        let body = buildBugReportEmailBody(report: report)
        var attachments: [URL] = []
        if !report.debugEntries.isEmpty {
            let debugJSON = report.jsonString(for: report.debugEntries)
            if let url = writeBugReportAttachment(prefix: "astrostack-debug-\(report.bugID)", json: debugJSON) {
                attachments.append(url)
            }
        }
        composeEmail(subject: subject,
                     body: body,
                     toAddress: ReportingLogConfig.defaultRecipient,
                     attachments: attachments)
    }

    private func writeBugReportAttachment(prefix: String, json: String) -> URL? {
        let fileName = "\(prefix).json"
        let url = FileManager.default.temporaryDirectory.appendingPathComponent(fileName)
        do {
            try json.write(to: url, atomically: true, encoding: .utf8)
            return url
        } catch {
            reportError("report_attachment_write_failed", details: ["file": fileName])
            return nil
        }
    }

    private func reportingViewName() -> String {
        isShowingPDF ? "pdf" : "details"
    }

    private func reportingDocumentID() -> String? {
        if isShowingPDF, let doc = pdfView.document {
            return AstroStack.reportingDocumentID(for: doc)
        }
        if let idx = selectedFilteredIndex(), idx >= 0, idx < filtered.count {
            return reportingHash(filtered[idx].url)
        }
        return nil
    }

    private func reportingAnnotationID(_ annotation: PDFAnnotation, pageIndex: Int?) -> String {
        let safePage = max(0, pageIndex ?? annotation.page.flatMap { $0.document?.index(for: $0) } ?? 0)
        return reportingHash(annotationStableKey(annotation, pageIndex: safePage))
    }

    private func reportEvent(severity: ReportingLogSeverity,
                             category: ReportingLogCategory,
                             event: String,
                             view: String? = nil,
                             documentID: String? = nil,
                             annotationID: String? = nil,
                             details: [String: String] = [:]) {
        guard ReportingLogger.shared.isActive else { return }
        let context = ReportingLogContext(
            view: view ?? reportingViewName(),
            documentID: documentID ?? reportingDocumentID(),
            annotationID: annotationID,
            details: details
        )
        ReportingLogger.shared.log(severity: severity,
                                   category: category,
                                   event: event,
                                   context: context)
    }

    private func reportUIEvent(_ event: String, details: [String: String] = [:]) {
        reportEvent(severity: .info, category: .uiEvents, event: event, details: details)
    }

    private func reportStateTransition(_ event: String, details: [String: String] = [:]) {
        reportEvent(severity: .info, category: .stateTransitions, event: event, details: details)
    }

    private func reportAnnotationOp(_ event: String,
                                    annotation: PDFAnnotation,
                                    pageIndex: Int?,
                                    details: [String: String] = [:]) {
        let annotationID = reportingAnnotationID(annotation, pageIndex: pageIndex)
        reportEvent(severity: .info,
                    category: .annotationOps,
                    event: event,
                    annotationID: annotationID,
                    details: details)
    }

    private func reportDocumentIO(_ event: String,
                                  documentID: String?,
                                  severity: ReportingLogSeverity = .info,
                                  details: [String: String] = [:]) {
        reportEvent(severity: severity,
                    category: .documentIO,
                    event: event,
                    documentID: documentID,
                    details: details)
    }

    private func reportError(_ event: String,
                             documentID: String? = nil,
                             details: [String: String] = [:]) {
        reportEvent(severity: .error,
                    category: .errors,
                    event: event,
                    documentID: documentID,
                    details: details)
    }

    private func reportPerformance(_ event: String, details: [String: String] = [:]) {
        reportEvent(severity: .warn, category: .performance, event: event, details: details)
    }

    private func select(_ globalIndex: Int) {
        guard !filtered.isEmpty else { return }
        let clamped = max(0, min(globalIndex, filtered.count - 1))
        selectFilteredIndex(clamped, scroll: true, reason: "keyboard-updown")
    }

    // MARK: Context menu (right-click)

    func menuNeedsUpdate(_ menu: NSMenu) {
        guard menu === rowMenu else { return }
        menu.removeAllItems()

        let clickedRow = tableView.clickedRow
        guard let dataRow = globalIndex(forTableRow: clickedRow),
              dataRow >= 0, dataRow < filtered.count else {
            let item = menu.addItem(withTitle: "No row", action: nil, keyEquivalent: "")
            item.isEnabled = false
            configureContextMenuItemViews(menu)
            return
        }

        if tableView.selectedRow != clickedRow {
            tableView.selectRowIndexes(IndexSet(integer: clickedRow), byExtendingSelection: false)
            if !isShowingPDF { updateDetails() }
        }

        menu.addItem(withTitle: "Open arXiv (abs)", action: #selector(ctxOpenAbs(_:)), keyEquivalent: "")
        menu.addItem(withTitle: "Open PDF", action: #selector(ctxOpenPDF(_:)), keyEquivalent: "")
        menu.addItem(NSMenuItem.separator())
        menu.addItem(withTitle: "Copy citation", action: #selector(ctxCopyCitation(_:)), keyEquivalent: "")
        menu.addItem(withTitle: "Copy BibTeX link", action: #selector(ctxCopyBibtexLink(_:)), keyEquivalent: "")
        menu.addItem(NSMenuItem.separator())
        menu.addItem(withTitle: "Copy Title", action: #selector(ctxCopyTitle(_:)), keyEquivalent: "")
        menu.addItem(withTitle: "Copy Authors", action: #selector(ctxCopyAuthors(_:)), keyEquivalent: "")

        for item in menu.items { item.target = self }
        configureContextMenuItemViews(menu)
    }

    func menu(_ menu: NSMenu, willHighlight item: NSMenuItem?) {
        guard menu === rowMenu else { return }
        for menuItem in menu.items {
            guard let view = menuItem.view as? ContextMenuItemView else { continue }
            view.setMenuHighlighted(menuItem == item, animated: true)
        }
    }

    func menuDidClose(_ menu: NSMenu) {
        guard menu === rowMenu else { return }
        for menuItem in menu.items {
            guard let view = menuItem.view as? ContextMenuItemView else { continue }
            view.setMenuHighlighted(false, animated: false)
        }
    }

    private func configureContextMenuItemViews(_ menu: NSMenu) {
        let font = NSFont.menuFont(ofSize: 0)
        let textWidths = menu.items
            .filter { !$0.isSeparatorItem }
            .map { ($0.title as NSString).size(withAttributes: [.font: font]).width }
        let maxTextWidth = textWidths.max() ?? 0
        let itemWidth = max(ContextMenuItemView.minWidth,
                            ceil(maxTextWidth + ContextMenuItemView.contentInsets.left + ContextMenuItemView.contentInsets.right))
        let rowHeight = ContextMenuItemView.rowHeight(for: font)

        for item in menu.items where !item.isSeparatorItem {
            let view = ContextMenuItemView(
                frame: NSRect(x: 0, y: 0, width: itemWidth, height: rowHeight),
                title: item.title,
                font: font
            )
            view.menuItem = item
            view.reduceMotionProvider = { [weak self] in self?.shouldReduceMotion ?? false }
            item.view = view
        }
    }

    private func paste(_ s: String) {
        let pb = NSPasteboard.general
        pb.clearContents()
        pb.setString(s, forType: .string)
    }

    private func currentRowPaperFromMenu() -> (row: Int, paper: Paper)? {
        let rRaw = tableView.clickedRow >= 0 ? tableView.clickedRow : tableView.selectedRow
        guard let r = globalIndex(forTableRow: rRaw) else { return nil }
        guard r >= 0, r < filtered.count else { return nil }
        return (r, filtered[r])
    }

    @objc private func ctxOpenAbs(_ sender: Any?) {
        guard let (_, p) = currentRowPaperFromMenu() else { return }
        let abs = stripLeadingLabel(p.url, label: "URL").trimmingCharacters(in: .whitespacesAndNewlines)
        guard let u = URL(string: abs), !abs.isEmpty else { return }
        NSWorkspace.shared.open(u)
    }

    @objc private func ctxOpenPDF(_ sender: Any?) {
        guard let (r, _) = currentRowPaperFromMenu() else { return }
        openPDFInRightPanel(forRow: r, trigger: "context-menu")
    }

    @objc private func ctxCopyTitle(_ sender: Any?) {
        guard let (_, p) = currentRowPaperFromMenu() else { return }
        paste(decodeTeXAccents(p.title))
    }

    @objc private func ctxCopyAuthors(_ sender: Any?) {
        guard let (_, p) = currentRowPaperFromMenu() else { return }
        paste(decodeTeXAccents(stripLeadingLabel(p.authors, label: "Authors")))
    }

    @objc private func ctxCopyBibtexLink(_ sender: Any?) {
        guard let (_, p) = currentRowPaperFromMenu() else { return }
        guard let id = arxivID(fromAbsURL: p.url), !id.isEmpty else { return }
        paste("https://arxiv.org/bibtex/\(id)")
    }

    @objc private func ctxCopyCitation(_ sender: Any?) {
        guard let (_, p) = currentRowPaperFromMenu() else { return }

        let year = extractYear(from: p.dateLine)
        let id = arxivID(fromAbsURL: p.url) ?? ""
        let abs = stripLeadingLabel(p.url, label: "URL").trimmingCharacters(in: .whitespacesAndNewlines)

        let authorShort = decodeTeXAccents(leftAuthorYearText(paper: p))
        let title = decodeTeXAccents(p.title)

        var parts: [String] = []
        parts.append(authorShort)
        parts.append("“\(title)”")
        if !id.isEmpty { parts.append("arXiv:\(id)") }
        else if !abs.isEmpty { parts.append(abs) }
        if !year.isEmpty, !authorShort.contains(year) { parts.append("(\(year))") }

        paste(parts.joined(separator: ". "))
    }

    // MARK: Click actions

    @objc private func singleClick() {
        uiLog("row_click single selectedRow=\(tableView.selectedRow) clickedRow=\(tableView.clickedRow)")
        if tableView.selectedRow == 0 {
            select(0)
            return
        }
    }

    @objc private func doubleClick() {
        uiLog("row_click double selectedRow=\(tableView.selectedRow) clickedRow=\(tableView.clickedRow)")
        let row = tableView.clickedRow
        guard row > 0 else { return }
        if let idx = globalIndex(forTableRow: row) {
            openAbs(idx)
        }
    }

    private func openAbs(_ row: Int) {
        guard row >= 0, row < filtered.count else { return }
        let p = filtered[row]
        let abs = stripLeadingLabel(p.url, label: "URL").trimmingCharacters(in: .whitespacesAndNewlines)
        guard !abs.isEmpty, let u = URL(string: abs) else { return }
        NSWorkspace.shared.open(u)
    }

    // MARK: Details HTML load

	    private func loadHTMLWithLocalAccess(_ html: String) {
            PerfLogger.begin("details.load_html")
            defer { PerfLogger.end("details.load_html") }
	        if let u = lastTempHTMLURL { try? FileManager.default.removeItem(at: u) }

        let dir = FileManager.default.temporaryDirectory
        let file = dir.appendingPathComponent("arxiv_picker_\(UUID().uuidString).html")

            guard let data = html.data(using: .utf8) else {
                lastTempHTMLURL = nil
                detailsWebView.loadHTMLString(html, baseURL: nil)
                DispatchQueue.main.async { [weak self] in
                    self?.installRightPanelScrollRestrictions()
                    self?.applyDetailsWebViewRoundedClipping()
                }
                return
            }
	        do {
	            try PerfLogger.measure("io.details_html.write") {
                    try data.write(to: file, options: [.atomic])
                }
	        } catch {
                lastTempHTMLURL = nil
                detailsWebView.loadHTMLString(html, baseURL: nil)
                DispatchQueue.main.async { [weak self] in
                    self?.installRightPanelScrollRestrictions()
                    self?.applyDetailsWebViewRoundedClipping()
                }
                return
            }

            lastTempHTMLURL = file
	        detailsWebView.loadFileURL(file, allowingReadAccessTo: URL(fileURLWithPath: "/"))
	        DispatchQueue.main.async { [weak self] in
	            self?.installRightPanelScrollRestrictions()
	            self?.applyDetailsWebViewRoundedClipping()
	        }
	    }

	    private func applyDetailsWebViewRoundedClipping() {
	        // Persistent rounded clipping for WKWebView requires applying the same mask to the
	        // actual scrolling/clipping surfaces (webView, scrollView, and the clip view).
	        let radius = rightCardCornerRadius()

	        func apply(_ view: NSView?) {
	            guard let view else { return }
	            view.wantsLayer = true
	            view.layer?.masksToBounds = true
	            view.layer?.cornerRadius = radius
	            if #available(macOS 10.13, *) {
	                view.layer?.cornerCurve = .continuous
	            }
	        }

	        apply(detailsWebView)

	        guard let scroll = descendantScrollViews(in: detailsWebView).first else { return }
	        scroll.drawsBackground = false
	        scroll.backgroundColor = NSColor.clear
	        scroll.horizontalScrollElasticity = .none
	        scroll.verticalScrollElasticity = .none
	        scroll.hasHorizontalScroller = false

	        scroll.contentView.drawsBackground = false
	        scroll.contentView.backgroundColor = NSColor.clear

	        apply(scroll)
	        apply(scroll.contentView) // critical: NSClipView (or HorizontalLockClipView) is the clip surface
	        apply(scroll.documentView)
	    }

	    private func updateDetails() {
            let guardMeasure = AnimationGuard.beginMeasurement("details.update")
            defer { AnimationGuard.endMeasurement(guardMeasure) }
            PerfLogger.begin("details.update")
            defer { PerfLogger.end("details.update") }
	        guard let idx = selectedFilteredIndex() else { return }
	        guard idx >= 0, idx < filtered.count else { return }
	        let p = filtered[idx]

        var terms = keywordsFromAppleScript
        let q = searchField.stringValue.trimmingCharacters(in: .whitespacesAndNewlines)
        if !q.isEmpty { terms.append(q) }
        let present = keywordsPresent(in: p, keywords: terms)

        // Keyword highlighting must derive from the same RootGlassTint pipeline as the first glass card.
        let highlight = cssRGBA(rootGlassTheme().keywordHighlight)
        let palette = rightCardTextPalette()

            let html = PerfLogger.measure("details.build_html") {
                AnimationGuard.measure("details.build_html") {
                    buildDetailsHTML(paper: p,
                                     keywordsForHighlight: present,
                                     highlightCSS: highlight,
                                     textPalette: palette,
                                     paperIndex: idx + 1,
                                     paperTotal: filtered.count)
                }
            }
	        loadHTMLWithLocalAccess(html)
	    }

    // MARK: Details PDF link routing

    func webView(_ webView: WKWebView,
                 decidePolicyFor navigationAction: WKNavigationAction,
                 decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard navigationAction.navigationType == .linkActivated,
              let url = navigationAction.request.url else {
            decisionHandler(.allow)
            return
        }

	        // Route PDF link clicks through the canonical PDF presentation pipeline (same as Enter-key flow).
	        if urlLooksLikePDF(url) {
	            presentPDF(remoteURL: url, trigger: "details-link", animateViewMode: true)
	            decisionHandler(.cancel)
	            return
	        }

	        // For all non-PDF links (including the clickable title), open in the system default browser
	        // instead of navigating inside the embedded details view.
	        if let scheme = url.scheme?.lowercased(), scheme == "http" || scheme == "https" {
	            NSWorkspace.shared.open(url)
	            decisionHandler(.cancel)
	            return
	        }

	        decisionHandler(.allow)
	    }

    private func urlLooksLikePDF(_ url: URL) -> Bool {
        let path = url.path.lowercased()
        return path.hasSuffix(".pdf") || path.contains("/pdf/")
    }

private func buildDetailsStatusHTML(_ message: String, paperIndex: Int? = nil, paperTotal: Int? = nil, leftHeaderText: String? = nil, centerHeaderText: String? = nil) -> String {
		        let detailsLightBG = DETAILS_PANEL_LIGHT_BG
		        let detailsDarkBG = DETAILS_PANEL_DARK_BG
		        let lightPalette = adaptiveTextPalette(baseColor: detailsLightBG, linkHex: RIGHT_LINK_COLOR_HEX)
		        let darkPalette = adaptiveTextPalette(baseColor: detailsDarkBG, linkHex: RIGHT_LINK_COLOR_HEX)
                func cssFontFamily(_ name: String) -> String {
                    name.replacingOccurrences(of: "'", with: "\\'")
                }
                let fontOverride = resolvedHTMLFontOverride()
                let bodyFontCSS: String
                if let override = fontOverride {
                    let family = cssFontFamily(override.familyName)
                    let sizePx = max(10.0, override.font.pointSize)
                    bodyFontCSS = "font-family: '\(family)', -apple-system, BlinkMacSystemFont, \"SF Pro Text\", \"Helvetica Neue\", Helvetica, Arial, sans-serif; font-size: \(String(format: "%.0f", sizePx))px;"
                } else {
                    bodyFontCSS = "font-family: -apple-system, BlinkMacSystemFont, \"SF Pro Text\", \"Helvetica Neue\", Helvetica, Arial, sans-serif;"
                }
		        let leftText = (leftHeaderText ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
		        let centerText = (centerHeaderText ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
		        let countText: String = {
		            guard let idx = paperIndex, let total = paperTotal else { return "" }
		            let t = max(0, total)
		            let i = (t == 0) ? 0 : max(1, min(t, idx))
		            return "Paper \(i)/\(t)"
		        }()
	        return """
<!doctype html>
<html>
<head>
  <meta charset="utf-8"/>
  <meta name="viewport" content="width=device-width, initial-scale=1"/>
  <style>
    :root {
      --bg: \(cssRGBA(detailsLightBG));
      --text-primary: \(cssRGBA(lightPalette.primary));
      --text-secondary: \(cssRGBA(lightPalette.secondary));
      --text-muted: \(cssRGBA(lightPalette.muted));
      --text-link: \(cssRGBA(lightPalette.link));
      --rule: \(cssRGBA(lightPalette.rule));
      --code-fg: \(cssRGBA(lightPalette.codeText));
      --code-bg: \(cssRGBA(lightPalette.codeBackground));
    }

    @media (prefers-color-scheme: dark) {
      :root {
        --bg: \(cssRGBA(detailsDarkBG));
        --text-primary: \(cssRGBA(darkPalette.primary));
        --text-secondary: \(cssRGBA(darkPalette.secondary));
        --text-muted: \(cssRGBA(darkPalette.muted));
        --text-link: \(cssRGBA(darkPalette.link));
        --rule: \(cssRGBA(darkPalette.rule));
        --code-fg: \(cssRGBA(darkPalette.codeText));
        --code-bg: \(cssRGBA(darkPalette.codeBackground));
      }
    }

		    html, body { height: 100%; background: var(--bg); overflow-x: hidden; overscroll-behavior: none; overscroll-behavior-y: none; }
		    body {
		      margin: 0;
		      color: var(--text-secondary);
		      \(bodyFontCSS)
		      line-height: 1.35;
		    }

		    .page-shell {
		      min-height: 100vh;
		      background: var(--bg);
		      border-radius: \(PANEL_CORNER_RADIUS)px;
		      overflow: hidden;
		      position: relative;
		      padding: 18px 18px 18px 18px;
		      box-sizing: border-box;
		    }
		    a { color: var(--text-link); text-decoration: underline; }

	    /* Static page header: stays at the top of the document and scrolls away (not fixed/sticky). */
	    .page-header {
	      display: grid;
	      grid-template-columns: minmax(0, 1fr) minmax(0, 2fr) minmax(0, 1fr);
	      align-items: start;
	      column-gap: 12px;
	      margin: 0 0 12px 0;
	    }

	    .chrome-left,
	    .chrome-center,
	    .chrome-right {
	      font-size: 11px;
	      font-weight: 500;
	      letter-spacing: 0.1px;
	      color: var(--text-muted);
	      opacity: 0.95;
	      user-select: none;
	      pointer-events: none;
	      font-variant-numeric: tabular-nums;
	      min-width: 0;
	    }

	    .chrome-left {
	      text-align: left;
	      white-space: nowrap;
	      overflow: hidden;
	      text-overflow: ellipsis;
	    }

	    .chrome-center {
	      text-align: center;
	      white-space: normal;
	      overflow-wrap: anywhere;
	      word-break: break-word;
	      line-height: 1.25;
	    }

	    .chrome-right {
	      text-align: right;
	      white-space: nowrap;
	      overflow: hidden;
	      text-overflow: ellipsis;
	    }
		  </style>
		</head>
			<body>
			  <div class="page-shell">
			  <div class="page-header">
			    <div class="chrome-left">\(htmlEscape(leftText))</div>
			    <div class="chrome-center">\(htmlEscape(centerText))</div>
			    <div class="chrome-right">\(htmlEscape(countText))</div>
			  </div>
			  <div class="status">\(htmlEscape(message))</div>
			  </div>
			</body>
			</html>
"""
			    }

    // MARK: PDF view

    private func showDetailsPanel(animated: Bool = true, updateContent: Bool = true) {
        reportStateTransition("view_mode_change", details: ["view": "details", "animated": "\(animated)"])
	        hidePDFFindHUD()
	        isShowingPDF = false
	        pdfLoadToken &+= 1 // invalidate any in-flight PDF load completions
	        hideLoading()
        removePDFResizeFreezeIfNeeded(reason: "show_details")
	        transitionRightPanel(toPDF: false, animated: animated)

        applyRightPanelBaseColor()
        rightPanelPillControl.refreshForegroundColors()
        
        if updateContent {
            updateDetails()
        }
        updateCurrentHistoryViewMode(false, reason: "show_details")
        updateNavigationButtons()
        refreshAnnotationsPanel(reason: "show_details")
    }

    private func showPDFPanel(animated: Bool = true) {
        reportStateTransition("view_mode_change", details: ["view": "pdf", "animated": "\(animated)"])
        isShowingPDF = true
        transitionRightPanel(toPDF: true, animated: animated)
        enforceWhitePDFBackground()
        applyRightPanelBaseColor()
        rightPanelPillControl.refreshForegroundColors()
        updateCurrentHistoryViewMode(true, reason: "show_pdf")
        updateNavigationButtons()
        refreshAnnotationsPanel(reason: "show_pdf")

        // Make keyboard scrolling work immediately when the PDF becomes visible.
        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            guard self.window?.isKeyWindow == true else { return }
            if self.pdfFindHUD.isHidden {
                // Preserve text input focus while the user is actively searching.
                if self.searchFocused || self.searchField.currentEditor() != nil {
                    return
                }
                self.window?.makeFirstResponder(self.pdfView)
            }
        }
    }

    private func setRightPanelHitTesting(_ view: NSView, enabled: Bool) {
        (view as? HitTestControlling)?.allowsHitTesting = enabled
    }

    private func describeRightPanelState(_ state: RightPanelTransitionState) -> String {
        switch state {
        case .idle(let mode):
            return "idle(\(mode.rawValue))"
        case .transition(let from, let to):
            return "transition(\(from.rawValue)->\(to.rawValue))"
        }
    }

    private func animateOpacity(_ layer: CALayer?,
                                from: Float,
                                to: Float,
                                duration: CFTimeInterval,
                                timing: CAMediaTimingFunctionName = .easeOut,
                                key: String) {
        guard let layer else { return }
        layer.removeAnimation(forKey: key)
        let animation = CABasicAnimation(keyPath: "opacity")
        animation.fromValue = from
        animation.toValue = to
        animation.duration = duration
        animation.timingFunction = CAMediaTimingFunction(name: timing)
        layer.add(animation, forKey: key)
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        layer.opacity = to
        CATransaction.commit()
    }

    private func snapRightPanel(to targetMode: RightPanelViewMode,
                                showView: NSView,
                                hideView: NSView,
                                reason: String) {
        viewModeTransitionToken &+= 1
        viewModeTransitionWorkItem?.cancel()
        pendingRightPanelTransitionTarget = nil
        rightPanelTransitionState = .idle(targetMode)

        // Avoid layer-backed PDFView animations; PDFKit can flicker during resize when layer-backed.
        let showIsPDF = (showView === pdfView)
        let hideIsPDF = (hideView === pdfView)
        if !showIsPDF { showView.wantsLayer = true }
        if !hideIsPDF { hideView.wantsLayer = true }
        showView.layer?.removeAllAnimations()
        hideView.layer?.removeAllAnimations()

        rightPanelTransitionBlurView.layer?.removeAllAnimations()
        rightPanelTransitionBlurView.isHidden = true
        if let blurLayer = rightPanelTransitionBlurView.layer {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            blurLayer.opacity = 0
            CATransaction.commit()
        }

        if let backgroundLayer = rightPDFBackgroundView.layer {
            backgroundLayer.removeAllAnimations()
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            backgroundLayer.opacity = targetMode == .pdf ? 1 : 0
            CATransaction.commit()
        }
        rightPDFBackgroundView.isHidden = targetMode != .pdf

        showView.isHidden = false
        hideView.isHidden = true
        showView.alphaValue = 1.0
        hideView.alphaValue = 1.0
        rightPanelContentHost.addSubview(showView, positioned: .above, relativeTo: hideView)
        setRightPanelHitTesting(showView, enabled: true)
        setRightPanelHitTesting(hideView, enabled: false)

        if let layer = showView.layer, !showIsPDF {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.opacity = 1
            layer.transform = CATransform3DIdentity
            CATransaction.commit()
        }
        if let layer = hideView.layer, !hideIsPDF {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.opacity = 1
            layer.transform = CATransform3DIdentity
            CATransaction.commit()
        }

        viewModeLog("transition_snap reason=\(reason) state=\(describeRightPanelState(rightPanelTransitionState))")
    }

    private func transitionRightPanel(toPDF: Bool, animated: Bool) {
        let targetMode: RightPanelViewMode = toPDF ? .pdf : .details
        let showView = toPDF ? pdfView : detailsWebView
        let hideView = toPDF ? detailsWebView : pdfView

        guard animated, !shouldReduceMotion else {
            let reason = animated ? "reduce_motion" : "no_animation"
            snapRightPanel(to: targetMode, showView: showView, hideView: hideView, reason: reason)
            return
        }

        if case .transition = rightPanelTransitionState {
            if case .transition(_, let to) = rightPanelTransitionState, to == targetMode {
                viewModeLog("transition_inflight target=\(targetMode.rawValue) state=\(describeRightPanelState(rightPanelTransitionState))")
                return
            }
            pendingRightPanelTransitionTarget = targetMode
            viewModeLog("transition_queued target=\(targetMode.rawValue) state=\(describeRightPanelState(rightPanelTransitionState))")
            return
        }

        let fromMode: RightPanelViewMode
        switch rightPanelTransitionState {
        case .idle(let mode):
            fromMode = mode
        case .transition(let from, _):
            fromMode = from
        }

        if fromMode == targetMode {
            snapRightPanel(to: targetMode, showView: showView, hideView: hideView, reason: "already_visible")
            return
        }

        rightPanelTransitionState = .transition(from: fromMode, to: targetMode)
        pendingRightPanelTransitionTarget = nil

        viewModeTransitionToken &+= 1
        let token = viewModeTransitionToken
        viewModeTransitionWorkItem?.cancel()

        let showIsPDF = (showView === pdfView)
        let hideIsPDF = (hideView === pdfView)
        if !showIsPDF { showView.wantsLayer = true }
        if !hideIsPDF { hideView.wantsLayer = true }
        showView.layer?.removeAllAnimations()
        hideView.layer?.removeAllAnimations()

        if let blurLayer = rightPanelTransitionBlurView.layer {
            blurLayer.removeAllAnimations()
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            blurLayer.opacity = 0
            CATransaction.commit()
        }
        rightPanelTransitionBlurView.isHidden = true

        let startTime = monotonicNow()
        let fastCycle = (startTime - lastViewModeSwitchTime) < rightPanelTransition.fastCycleThreshold
        lastViewModeSwitchTime = startTime
        let duration = rightPanelTransition.duration(forFastCycle: fastCycle)
        let transitionScale = rightPanelTransition.scale(forFastCycle: fastCycle)
        let offsetX = rightPanelTransition.translationX(forFastCycle: fastCycle)
        let direction: CGFloat = toPDF ? 1 : -1
        let incomingX = direction * offsetX
        let outgoingX = -direction * offsetX
        let springPreset = rightPanelTransition.springPreset(forFastCycle: fastCycle)

        let startHostSize = rightPanelContentHost.bounds.size
        let startContainerSize = rightContainer.bounds.size
        viewModeLog("transition_start t=\(String(format: "%.4f", startTime)) from=\(fromMode.rawValue) to=\(targetMode.rawValue) duration=\(String(format: "%.2f", duration)) fast=\(fastCycle) host=\(Int(startHostSize.width))x\(Int(startHostSize.height)) container=\(Int(startContainerSize.width))x\(Int(startContainerSize.height)) state=\(describeRightPanelState(rightPanelTransitionState))")

        showView.isHidden = false
        hideView.isHidden = false
        rightPanelContentHost.addSubview(showView, positioned: .above, relativeTo: hideView)

        setRightPanelHitTesting(hideView, enabled: false)
        setRightPanelHitTesting(showView, enabled: false)

        let incomingEnableDelay = duration * rightPanelTransition.incomingHitTestEnableFraction
        DispatchQueue.main.asyncAfter(deadline: .now() + incomingEnableDelay) { [weak self] in
            guard let self, self.viewModeTransitionToken == token else { return }
            self.setRightPanelHitTesting(showView, enabled: true)
        }

        if let backgroundLayer = rightPDFBackgroundView.layer {
            rightPDFBackgroundView.isHidden = false
            backgroundLayer.removeAllAnimations()
            let startOpacity: Float = toPDF ? 0 : 1
            let endOpacity: Float = toPDF ? 1 : 0
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            backgroundLayer.opacity = startOpacity
            CATransaction.commit()
            animateOpacity(backgroundLayer,
                           from: startOpacity,
                           to: endOpacity,
                           duration: duration * 0.75,
                           timing: .easeOut,
                           key: "right_panel_bg")
        }

        if rightPanelTransition.blurEnabled, liquidGlassEnabled, let blurLayer = rightPanelTransitionBlurView.layer {
            rightPanelTransitionBlurView.isHidden = false
            rightPanelContentHost.addSubview(rightPanelTransitionBlurView, positioned: .above, relativeTo: showView)
            let maxOpacity = Float(rightPanelTransition.blurMaxOpacity)
            let blurDuration = max(0.08, duration * rightPanelTransition.blurFadeFraction)
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            blurLayer.opacity = maxOpacity
            CATransaction.commit()
            animateOpacity(blurLayer,
                           from: maxOpacity,
                           to: 0,
                           duration: blurDuration,
                           timing: .easeOut,
                           key: "right_panel_blur")
        }

        var showStart = CATransform3DIdentity
        showStart = CATransform3DTranslate(showStart, incomingX, 0, 0)
        showStart = CATransform3DScale(showStart, transitionScale, transitionScale, 1.0)
        var hideEnd = CATransform3DIdentity
        hideEnd = CATransform3DTranslate(hideEnd, outgoingX, 0, 0)
        hideEnd = CATransform3DScale(hideEnd, transitionScale, transitionScale, 1.0)

        if let layer = showView.layer, !showIsPDF {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.opacity = 0
            layer.transform = showStart
            CATransaction.commit()
            // Opacity should be a clean crossfade (no spring wobble).
            animateOpacity(layer, from: 0, to: 1, duration: duration, timing: .easeOut, key: "right_panel_in_opacity")
            animateLayer(layer, keyPath: "transform", to: CATransform3DIdentity, preset: springPreset, reduceMotion: false, basicDuration: duration)
        }
        if let layer = hideView.layer, !hideIsPDF {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            layer.opacity = 1
            layer.transform = CATransform3DIdentity
            CATransaction.commit()
            animateOpacity(layer, from: 1, to: 0, duration: duration, timing: .easeIn, key: "right_panel_out_opacity")
            animateLayer(layer, keyPath: "transform", to: hideEnd, preset: springPreset, reduceMotion: false, basicDuration: duration)
        }

        let work = DispatchWorkItem { [weak self] in
            guard let self, self.viewModeTransitionToken == token else { return }
            hideView.isHidden = true
            self.setRightPanelHitTesting(hideView, enabled: false)
            self.setRightPanelHitTesting(showView, enabled: true)
            if let layer = hideView.layer, !hideIsPDF {
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                layer.opacity = 1
                layer.transform = CATransform3DIdentity
                CATransaction.commit()
            }
            if targetMode == .details {
                if let backgroundLayer = self.rightPDFBackgroundView.layer {
                    CATransaction.begin()
                    CATransaction.setDisableActions(true)
                    backgroundLayer.opacity = 0
                    CATransaction.commit()
                }
                self.rightPDFBackgroundView.isHidden = true
            }

            self.rightPanelTransitionBlurView.isHidden = true
            if let blurLayer = self.rightPanelTransitionBlurView.layer {
                blurLayer.removeAllAnimations()
                CATransaction.begin()
                CATransaction.setDisableActions(true)
                blurLayer.opacity = 0
                CATransaction.commit()
            }

            self.rightPanelTransitionState = .idle(targetMode)
            let endHostSize = self.rightPanelContentHost.bounds.size
            let endContainerSize = self.rightContainer.bounds.size
            if abs(endHostSize.width - startHostSize.width) > 0.5 ||
                abs(endHostSize.height - startHostSize.height) > 0.5 ||
                abs(endContainerSize.width - startContainerSize.width) > 0.5 ||
                abs(endContainerSize.height - startContainerSize.height) > 0.5 {
                self.viewModeLog("transition_resize host=\(Int(startHostSize.width))x\(Int(startHostSize.height))->\(Int(endHostSize.width))x\(Int(endHostSize.height)) container=\(Int(startContainerSize.width))x\(Int(startContainerSize.height))->\(Int(endContainerSize.width))x\(Int(endContainerSize.height))")
            }
            let endTime = monotonicNow()
            let elapsedMs = Int((endTime - startTime) * 1000.0)
            self.viewModeLog("transition_end t=\(String(format: "%.4f", endTime)) to=\(targetMode.rawValue) elapsed_ms=\(elapsedMs) state=\(self.describeRightPanelState(self.rightPanelTransitionState))")

            if let pending = self.pendingRightPanelTransitionTarget, pending != targetMode {
                self.pendingRightPanelTransitionTarget = nil
                self.transitionRightPanel(toPDF: pending == .pdf, animated: true)
            } else {
                self.pendingRightPanelTransitionTarget = nil
            }
        }
        viewModeTransitionWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + duration, execute: work)
    }

    private func runRightPanelTransitionStressTestIfRequested() {
        guard ProcessInfo.processInfo.environment["ARXIV_VIEWMODE_STRESS"] == "1" else { return }
        let requested = Int(ProcessInfo.processInfo.environment["ARXIV_VIEWMODE_STRESS_COUNT"] ?? "")
        let totalSwitches = max(20, min(30, requested ?? 24))
        let interval = max(rightPanelTransition.normalDuration, rightPanelTransition.fastDuration) + 0.06
        let initialDelay: CFTimeInterval = 0.8

        var remaining = totalSwitches
        var showNextPDF = !isShowingPDF
        NSLog("[ViewModeStress] start switches=\(totalSwitches) interval=\(interval)")

        func step() {
            guard remaining > 0 else {
                NSLog("[ViewModeStress] complete switches=\(totalSwitches)")
                return
            }
            if showNextPDF {
                showPDFPanel(animated: true)
            } else {
                showDetailsPanel(animated: true, updateContent: false)
            }
            showNextPDF.toggle()
            remaining -= 1
            DispatchQueue.main.asyncAfter(deadline: .now() + interval, execute: step)
        }

        DispatchQueue.main.asyncAfter(deadline: .now() + initialDelay, execute: step)
    }

    // MARK: PDF Zoom

    private func pdfPrimaryScrollView() -> NSScrollView? {
        let scrollViews = descendantScrollViews(in: pdfView)
        if scrollViews.count == 1 {
            return scrollViews[0]
        }
        return scrollViews.first(where: { $0.documentView != nil }) ?? scrollViews.first
    }

    private struct PDFScrollSnapshot {
        let documentID: ObjectIdentifier
        let clipOrigin: NSPoint
        let anchorPageIndex: Int?
        let anchorPointOnPage: NSPoint?
        let anchorOffsetInClip: NSPoint?
    }

    private func capturePDFScrollSnapshot(reason: String) -> PDFScrollSnapshot? {
        _ = reason
        guard let doc = pdfView.document,
              let scrollView = pdfPrimaryScrollView() else { return nil }
        let clip = scrollView.contentView
        let clipOrigin = clip.bounds.origin

        var anchorPageIndex: Int?
        var anchorPointOnPage: NSPoint?
        var anchorOffsetInClip: NSPoint?

        let visibleRect = pdfVisibleRectInView()
        let anchorInView = NSPoint(x: visibleRect.midX, y: visibleRect.midY)
        if let page = pdfView.page(for: anchorInView, nearest: true) {
            let pageIndex = doc.index(for: page)
            if pageIndex != NSNotFound {
                anchorPageIndex = pageIndex
                anchorPointOnPage = pdfView.convert(anchorInView, to: page)
                if let docView = scrollView.documentView {
                    let anchorInDoc = pdfView.convert(anchorInView, to: docView)
                    anchorOffsetInClip = NSPoint(x: anchorInDoc.x - clipOrigin.x,
                                                 y: anchorInDoc.y - clipOrigin.y)
                }
            }
        }

        return PDFScrollSnapshot(documentID: ObjectIdentifier(doc),
                                 clipOrigin: clipOrigin,
                                 anchorPageIndex: anchorPageIndex,
                                 anchorPointOnPage: anchorPointOnPage,
                                 anchorOffsetInClip: anchorOffsetInClip)
    }

    private func restorePDFScrollSnapshot(_ snapshot: PDFScrollSnapshot?,
                                          reason: String,
                                          preferClipOrigin: Bool = false,
                                          anchorFallbackToClipOrigin: Bool = false) {
        _ = reason
        guard let snapshot,
              let doc = pdfView.document,
              ObjectIdentifier(doc) == snapshot.documentID,
              let scrollView = pdfPrimaryScrollView() else { return }
        let clip = scrollView.contentView

        var targetOrigin: NSPoint?
        if !preferClipOrigin,
           let pageIndex = snapshot.anchorPageIndex,
           let anchorPointOnPage = snapshot.anchorPointOnPage,
           let offset = snapshot.anchorOffsetInClip,
           let page = doc.page(at: pageIndex),
           let docView = scrollView.documentView {
            let anchorInView = pdfView.convert(anchorPointOnPage, from: page)
            let anchorInDoc = pdfView.convert(anchorInView, to: docView)
            var origin = NSPoint(x: anchorInDoc.x - offset.x, y: anchorInDoc.y - offset.y)
            origin = clip.constrainBoundsRect(NSRect(origin: origin, size: clip.bounds.size)).origin
            if anchorFallbackToClipOrigin {
                let dy = abs(origin.y - snapshot.clipOrigin.y)
                let dx = abs(origin.x - snapshot.clipOrigin.x)
                let maxDelta = max(80, clip.bounds.height * 0.5)
                if dy > maxDelta || dx > max(40, clip.bounds.width * 0.5) {
                    var fallback = snapshot.clipOrigin
                    fallback = clip.constrainBoundsRect(NSRect(origin: fallback, size: clip.bounds.size)).origin
                    targetOrigin = fallback
                } else {
                    targetOrigin = origin
                }
            } else {
                targetOrigin = origin
            }
        } else {
            var origin = snapshot.clipOrigin
            origin = clip.constrainBoundsRect(NSRect(origin: origin, size: clip.bounds.size)).origin
            targetOrigin = origin
        }

        guard let origin = targetOrigin else { return }
        if abs(origin.x - clip.bounds.origin.x) > 0.01 || abs(origin.y - clip.bounds.origin.y) > 0.01 {
            clip.setBoundsOrigin(origin)
            scrollView.reflectScrolledClipView(clip)
        }
    }

    private func applyPDFScalePreservingScroll(_ scale: CGFloat, reason: String) {
        PerfLogger.begin("pdf.scale_preserve_scroll")
        defer { PerfLogger.end("pdf.scale_preserve_scroll") }
        let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
        defer {
            if resizePerfEnabled {
                ResizePerfTrace.shared.recordWork(name: "pdf.scale_preserve_scroll", durationNs: monotonicNowNs() &- perfStart)
            }
        }
        let snapshot: PDFScrollSnapshot? = {
            if let toggleSnapshot = sidebarTogglePDFSnapshot,
               sidebarTogglePDFSnapshotToken == sidebarToggleToken {
                return toggleSnapshot
            }
            return capturePDFScrollSnapshot(reason: reason)
        }()
        applyPDFScale(scale)
        let scaleLayoutStart = resizePerfEnabled ? monotonicNowNs() : 0
        if pdfView.needsLayout {
            PerfLogger.measure("autolayout.pdfView.scale") {
                pdfView.layoutSubtreeIfNeeded()
            }
            if resizePerfEnabled {
                ResizePerfTrace.shared.noteAutoLayout(name: "pdfView.scale", durationNs: monotonicNowNs() &- scaleLayoutStart)
            }
        }
        restorePDFScrollSnapshot(snapshot, reason: reason)
    }

    private func scheduleInteractivePDFScale(_ scale: CGFloat, reason: String) {
        pdfInteractivePendingScale = scale
        if pdfResizeFreezeActive {
            return
        }
        guard pdfInteractiveResizeWorkItem == nil else { return }
        // Root cause: applying PDF scale on every layout tick triggers PDFKit retile/flicker
        // during divider drags. Coalesce to a steady cadence to keep resizing smooth.
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            self.pdfInteractiveResizeWorkItem = nil
            guard let target = self.pdfInteractivePendingScale else { return }
            self.pdfInteractivePendingScale = nil
            self.applyPDFScalePreservingScroll(target, reason: reason)
        }
        pdfInteractiveResizeWorkItem = work
        DispatchQueue.main.asyncAfter(deadline: .now() + pdfInteractiveUpdateInterval, execute: work)
    }

    private func flushInteractivePDFScale(reason: String) {
        pdfInteractiveResizeWorkItem?.cancel()
        pdfInteractiveResizeWorkItem = nil
        guard let target = pdfInteractivePendingScale else { return }
        pdfInteractivePendingScale = nil
        applyPDFScalePreservingScroll(target, reason: reason)
    }

    private func finishPDFInteractiveResize(reason: String, applyPendingScale: Bool) {
        if applyPendingScale {
            flushInteractivePDFScale(reason: reason)
        } else {
            pdfInteractiveResizeWorkItem?.cancel()
            pdfInteractiveResizeWorkItem = nil
            pdfInteractivePendingScale = nil
        }
        annotationController?.flushPendingOverlayRefresh(reason: reason)
        DispatchQueue.main.async { [weak self] in
            self?.updatePDFResizeFreezeState(reason: reason)
        }
    }

    private func pdfVisibleRectInView() -> NSRect {
        if let scrollView = pdfPrimaryScrollView() {
            let clip = scrollView.contentView
            return pdfView.convert(clip.bounds, from: clip)
        }
        return pdfView.bounds
    }

    private func updateViewerForInteractiveResize(force: Bool = false) {
        PerfLogger.begin("pdf.interactive_resize.update_viewer")
        defer { PerfLogger.end("pdf.interactive_resize.update_viewer") }
        let perfStart = resizePerfEnabled ? monotonicNowNs() : 0
        defer {
            if resizePerfEnabled {
                ResizePerfTrace.shared.recordWork(name: "pdf.interactive_resize.update_viewer", durationNs: monotonicNowNs() &- perfStart)
            }
        }
        let hostSize = rightPanelContentHost.bounds.size
        guard hostSize.width > 1, hostSize.height > 1 else { return }
        let deltaW = abs(hostSize.width - pdfInteractiveLastHostSize.width)
        let deltaH = abs(hostSize.height - pdfInteractiveLastHostSize.height)
        let now = monotonicNow()
        let timeOk = (now - pdfInteractiveLastUpdate) >= pdfInteractiveUpdateInterval
        guard force || deltaW > pdfInteractiveSizeDeltaThreshold || deltaH > pdfInteractiveSizeDeltaThreshold || timeOk else {
            return
        }
        pdfInteractiveLastHostSize = hostSize
        pdfInteractiveLastUpdate = now

        if rightPanelContentHost.needsLayout {
            let hostLayoutStart = resizePerfEnabled ? monotonicNowNs() : 0
            PerfLogger.measure("autolayout.rightPanelContentHost") {
                rightPanelContentHost.layoutSubtreeIfNeeded()
            }
            if resizePerfEnabled {
                ResizePerfTrace.shared.noteAutoLayout(name: "rightPanelContentHost", durationNs: monotonicNowNs() &- hostLayoutStart)
            }
        }
        if isShowingPDF {
            if pdfView.needsLayout {
                let pdfLayoutStart = resizePerfEnabled ? monotonicNowNs() : 0
                PerfLogger.measure("autolayout.pdfView") {
                    pdfView.layoutSubtreeIfNeeded()
                }
                if resizePerfEnabled {
                    ResizePerfTrace.shared.noteAutoLayout(name: "pdfView", durationNs: monotonicNowNs() &- pdfLayoutStart)
                }
            }
            if pdfZoomPreset != .free, pdfView.document != nil {
                let visibleRect = pdfVisibleRectInView()
                let targetPage = pdfZoomTargetPage(for: pdfView.currentPage)
                if let target = pdfZoomScale(for: pdfZoomPreset, page: targetPage, visibleRect: visibleRect),
                   target.isFinite, target > 0 {
                    scheduleInteractivePDFScale(target, reason: "interactive_resize")
                }
            }
        } else {
            if detailsWebView.needsLayout {
                let detailsLayoutStart = resizePerfEnabled ? monotonicNowNs() : 0
                PerfLogger.measure("autolayout.detailsWebView") {
                    detailsWebView.layoutSubtreeIfNeeded()
                }
                if resizePerfEnabled {
                    ResizePerfTrace.shared.noteAutoLayout(name: "detailsWebView", durationNs: monotonicNowNs() &- detailsLayoutStart)
                }
            }
        }
    }

    private func scrollPDFToDocumentTop() {
        guard pdfView.document != nil else { return }
        if pdfView.needsLayout {
            pdfView.layoutSubtreeIfNeeded()
        }
        pdfView.goToFirstPage(nil)
        guard let scrollView = pdfPrimaryScrollView(),
              let docView = scrollView.documentView else { return }
        let clip = scrollView.contentView
        var origin = clip.bounds.origin
        if docView.isFlipped {
            origin.y = docView.bounds.minY
        } else {
            origin.y = docView.bounds.maxY - clip.bounds.height
        }
        origin = clip.constrainBoundsRect(NSRect(origin: origin, size: clip.bounds.size)).origin
        clip.setBoundsOrigin(origin)
        scrollView.reflectScrolledClipView(clip)
    }

    private func pdfZoomTargetPage(for page: PDFPage?) -> PDFPage? {
        if let page { return page }
        if let current = pdfView.currentPage { return current }
        return pdfView.document?.page(at: 0)
    }

    private func pdfZoomScaleForPageWidth(page: PDFPage?, visibleRect: NSRect) -> CGFloat? {
        guard let page = pdfZoomTargetPage(for: page) else { return nil }
        let bounds = page.bounds(for: pdfView.displayBox)
        guard bounds.width.isFinite, bounds.width > 0 else { return nil }
        guard visibleRect.width.isFinite, visibleRect.width > 0 else { return nil }
        return visibleRect.width / bounds.width
    }

    private func pdfZoomScaleForPageHeight(page: PDFPage?, visibleRect: NSRect) -> CGFloat? {
        guard let page = pdfZoomTargetPage(for: page) else { return nil }
        let bounds = page.bounds(for: pdfView.displayBox)
        guard bounds.height.isFinite, bounds.height > 0 else { return nil }
        guard visibleRect.height.isFinite, visibleRect.height > 0 else { return nil }
        return visibleRect.height / bounds.height
    }

    private func pdfZoomScale(for preset: PDFZoomPreset, page: PDFPage?, visibleRect: NSRect) -> CGFloat? {
        switch preset {
        case .pageWidth:
            return pdfZoomScaleForPageWidth(page: page, visibleRect: visibleRect)
        case .pageHeight:
            return pdfZoomScaleForPageHeight(page: page, visibleRect: visibleRect)
        case .auto:
            guard let w = pdfZoomScaleForPageWidth(page: page, visibleRect: visibleRect),
                  let h = pdfZoomScaleForPageHeight(page: page, visibleRect: visibleRect) else { return nil }
            return min(w, h)
        case .free:
            return nil
        }
    }

    private func clampPDFScale(_ scale: CGFloat) -> CGFloat {
        var clamped = scale
        let minScale = pdfView.minScaleFactor
        let maxScale = pdfView.maxScaleFactor
        if minScale > 0 { clamped = max(clamped, minScale) }
        if maxScale > 0 { clamped = min(clamped, maxScale) }
        return clamped
    }

    private func applyPDFScale(_ scale: CGFloat) {
        guard pdfView.document != nil else { return }
        guard scale.isFinite, scale > 0 else { return }
        let clamped = clampPDFScale(scale)
        let currentScale = pdfView.scaleFactor
        guard abs(clamped - currentScale) > 0.0001 else { return }

        pdfView.autoScales = false
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        pdfView.scaleFactor = clamped
        CATransaction.commit()
    }

    private func applyPDFZoomPreset(_ preset: PDFZoomPreset) {
        guard isShowingPDF, pdfView.document != nil else { return }
        pdfView.layoutSubtreeIfNeeded()
        let visibleRect = pdfVisibleRectInView()
        let targetPage = pdfZoomTargetPage(for: pdfView.currentPage)
        let target = pdfZoomScale(for: preset, page: targetPage, visibleRect: visibleRect)
        guard let target, target.isFinite, target > 0 else { return }
        applyPDFScale(target)
        pdfZoomPreset = preset
    }

    private func zoomPDFReset(event: NSEvent?) {
        applyPDFZoomPreset(.pageWidth)
    }

    private func zoomPDFAuto(event: NSEvent?) {
        applyPDFZoomPreset(.auto)
    }

    private func zoomPDFPageWidth(event: NSEvent?) {
        applyPDFZoomPreset(.pageWidth)
    }

    private func zoomPDFPageHeight(event: NSEvent?) {
        applyPDFZoomPreset(.pageHeight)
    }

    private func zoomPDFStep(increase: Bool, event: NSEvent?) {
        guard isShowingPDF, pdfView.document != nil else { return }
        let current = pdfView.scaleFactor
        guard current.isFinite, current > 0 else { return }
        let factor = pdfZoomStepFactor
        let target = increase ? (current * factor) : (current / factor)
        pdfZoomPreset = .free
        applyPDFScale(target)
    }

    private func applyPDFZoomPresetIfNeeded(minimumDelta: CGFloat = 0.0001) {
        guard isShowingPDF, pdfView.document != nil else { return }
        guard pdfZoomPreset != .free else { return }
        pdfView.layoutSubtreeIfNeeded()
        let visibleRect = pdfVisibleRectInView()
        let targetPage = pdfZoomTargetPage(for: pdfView.currentPage)
        let target = pdfZoomScale(for: pdfZoomPreset, page: targetPage, visibleRect: visibleRect)
        guard let target, target.isFinite, target > 0 else { return }
        let currentScale = pdfView.scaleFactor
        guard abs(target - currentScale) >= minimumDelta else { return }
        applyPDFScalePreservingScroll(target, reason: "zoom_preset_layout")
    }

    private func pdfZoomMenuState() -> PDFZoomMenuState {
        guard isShowingPDF, pdfView.document != nil else {
            return PDFZoomMenuState(
                canZoomIn: false,
                canZoomOut: false,
                canZoomReset: false,
                zoomAutoEnabled: false,
                zoomPageWidthEnabled: false,
                zoomPageHeightEnabled: false
            )
        }

        let current = pdfView.scaleFactor
        let eps: CGFloat = 0.0001
        let minScale = pdfView.minScaleFactor
        let maxScale = pdfView.maxScaleFactor
        let canZoomOut = minScale <= 0 ? true : (current - minScale > eps)
        let canZoomIn = maxScale <= 0 ? true : (maxScale - current > eps)
        let preset = pdfZoomPreset

        return PDFZoomMenuState(
            canZoomIn: canZoomIn,
            canZoomOut: canZoomOut,
            canZoomReset: preset != .pageWidth,
            zoomAutoEnabled: preset == .auto,
            zoomPageWidthEnabled: preset == .pageWidth,
            zoomPageHeightEnabled: preset == .pageHeight
        )
    }

    // Canonical PDF presentation pipeline (used by Enter-key flow and by PDF link clicks in the details panel).
    private func presentPDF(remoteURL: URL, trigger: String, animateViewMode: Bool = false) {
	        let normalizedURL = normalizedPDFURL(remoteURL)
        let requestedDocID = AstroStack.reportingDocumentID(for: normalizedURL)
        reportDocumentIO("pdf_load_request",
                         documentID: requestedDocID,
                         details: ["trigger": trigger])
        let metadata = metadataForCurrentSelection(for: normalizedURL)
        pdfCache.registerMetadata(metadata, for: normalizedURL)
        let demandRequest = PDFCacheManager.PrefetchRequest(url: normalizedURL, metadata: metadata)
        pdfCache.prefetch([demandRequest], priority: 1, reason: "present/on-demand")
	        pdfLoadToken &+= 1
	        let token = pdfLoadToken
	        let startTime = monotonicNow()
	        let cacheKey = pdfCache.cacheKey(for: normalizedURL)
	        let state = pdfCache.debugStateDescription(for: normalizedURL)
	        NSLog("[PDFEager] pdf_present_request trigger=\(trigger) key=\(cacheKey.prefix(8)) state=\(state)")

	        if isShowingPDF {
	            showPDFPanel(animated: false)
	        }
	        hidePDFFindHUD()
	        hideLoading()

	        let handlePrepared: (PDFCacheManager.PreparedPDF, String) -> Void = { [weak self] prepared, source in
	            self?.renderPreparedPDF(
	                prepared,
	                remoteURL: normalizedURL,
	                token: token,
	                startTime: startTime,
	                source: source,
	                cacheKey: cacheKey,
	                animateViewMode: animateViewMode
	            )
	        }

	        if let prepared = pdfCache.preparedPDFIfReady(for: normalizedURL) {
	            handlePrepared(prepared, "local-ready")
	            return
	        }

	        pdfCache.whenPreparedPDF(for: normalizedURL) { [weak self] result in
	            guard let self, self.pdfLoadToken == token else { return }
            switch result {
            case .success(let prepared):
                handlePrepared(prepared, "local-wait")
            case .failure(let error):
                NSLog("[PDFEager] pdf_present_failed trigger=\(trigger) key=\(cacheKey.prefix(8)) error=\(error)")
                self.reportError("pdf_present_failed", documentID: requestedDocID, details: ["trigger": trigger, "error": "\(error)"])
                self.pdfCache.trackLifecycleStage(.failed,
                                                  for: normalizedURL,
                                                  message: "presentError \(error)")
                self.showDetailsStatus(message: "PDF is still preparing or failed to download.")
            }
        }
	    }

	    private func renderPreparedPDF(_ prepared: PDFCacheManager.PreparedPDF,
	                                   remoteURL: URL,
	                                   token: Int,
	                                   startTime: CFTimeInterval,
	                                   source: String,
	                                   cacheKey: String,
	                                   animateViewMode: Bool) {
	        pdfCache.trackLifecycleStage(.renderQueued,
	                                     for: remoteURL,
	                                     fileURL: prepared.fileURL,
	                                     fileSize: prepared.byteCount,
	                                     lastModified: prepared.lastModified,
	                                     message: source)

	        pendingRenderWork?.cancel()
	        var workItem: DispatchWorkItem!
	        workItem = DispatchWorkItem { [weak self] in
	            guard let self else { return }
	            guard workItem?.isCancelled == false else { return }
	            guard self.pdfLoadToken == token else { return }
	            let cacheKeyObj = cacheKey as NSString
	            var document: PDFDocument?

	            if let cached = self.pdfDocumentCache.object(forKey: cacheKeyObj) {
	                document = cached
	                self.pdfCache.trackLifecycleStage(.validated,
	                                                  for: remoteURL,
	                                                  fileURL: prepared.fileURL,
	                                                  fileSize: prepared.byteCount,
	                                                  lastModified: prepared.lastModified,
	                                                  message: "cache-hit pageCount=\(cached.pageCount)")
	            } else {
	                autoreleasepool {
	                    let candidate = PDFDocument(url: prepared.fileURL)
	                    if let candidate = candidate, candidate.pageCount > 0 {
	                        self.pdfDocumentCache.setObject(candidate, forKey: cacheKeyObj)
	                        self.pdfCache.trackLifecycleStage(.validated,
	                                                          for: remoteURL,
	                                                          fileURL: prepared.fileURL,
	                                                          fileSize: prepared.byteCount,
	                                                          lastModified: prepared.lastModified,
	                                                          message: "pageCount=\(candidate.pageCount)")
	                    }
	                    document = candidate
	                }
	            }

            guard let validated = document, validated.pageCount > 0 else {
                let reason = document == nil ? "pdfkit_init_failed" : "empty-page-count"
                self.pdfCache.trackLifecycleStage(.failed,
                                                  for: remoteURL,
                                                  fileURL: prepared.fileURL,
                                                  fileSize: prepared.byteCount,
                                                  lastModified: prepared.lastModified,
                                                  message: reason)
                let docID = AstroStack.reportingDocumentID(for: remoteURL)
                self.reportError("pdf_render_failed", documentID: docID, details: ["reason": reason])
                DispatchQueue.main.async {
                    self.pendingRenderWork = nil
                    self.presentPDFRenderFailure(message: "PDF could not be rendered (\(reason)).")
                }
                return
            }

	            DispatchQueue.main.async {
	                guard self.pdfLoadToken == token else { return }
	                self.pendingRenderWork = nil
	                let shouldAnimate = animateViewMode && !self.isShowingPDF
	                self.showPDFPanel(animated: shouldAnimate)
	                self.applyPDFDocument(
	                    validated,
	                    token: token,
	                    source: source,
	                    startTime: startTime,
	                    cacheKey: cacheKey
	                )
	                self.pdfCache.trackLifecycleStage(.rendered,
	                                                  for: remoteURL,
	                                                  fileURL: prepared.fileURL,
	                                                  fileSize: prepared.byteCount,
	                                                  lastModified: prepared.lastModified,
	                                                  message: "source=\(source)")
	            }
	        }

	        pendingRenderWork = workItem
	        pdfRenderQueue.async(execute: workItem)
	    }

	    private func metadataForCurrentSelection(for url: URL) -> PDFCacheManager.Metadata {
	        if let idx = selectedFilteredIndex() {
	            return pdfMetadata(for: filtered[idx], url: url)
	        }
	        return pdfMetadata(with: url)
	    }

	    private func headerValues(for filteredIndex: Int) -> (date: String?, authors: String?)? {
	        guard filteredIndex >= 0, filteredIndex < filtered.count else { return nil }
	        let paper = filtered[filteredIndex]
	        let rawAuthors = stripLeadingLabel(paper.authors, label: "Authors")
	        let authorText = decodeTeXAccents(rawAuthors)
	            .replacingOccurrences(of: "\n", with: " ")
	            .components(separatedBy: .whitespacesAndNewlines)
	            .filter { !$0.isEmpty }
	            .joined(separator: " ")
	        let dateText = dateOnlyDisplayString(from: paper.dateLine)
	        return (dateText, authorText)
	    }

	    private func showDetailsStatus(message: String) {
	        guard !isShowingPDF else { return }
	        let idx = selectedFilteredIndex()
	        let total = filtered.count
	        let headers = idx.flatMap { headerValues(for: $0) }
	        loadHTMLWithLocalAccess(
	            buildDetailsStatusHTML(
	                message,
	                paperIndex: idx.map { $0 + 1 },
	                paperTotal: total,
	                leftHeaderText: headers?.date,
	                centerHeaderText: headers?.authors
	            )
	        )
	    }

	    private func presentPDFRenderFailure(message: String) {
	        showDetailsStatus(message: message)
	    }

    private func openPDFInRightPanel(forRow row: Int, trigger: String) {
        guard row >= 0, row < filtered.count else { return }
        let p = filtered[row]
        guard let pdfURL = pdfURL(for: p) else {
            openAbs(row)
            return
        }
        presentPDF(remoteURL: pdfURL, trigger: trigger, animateViewMode: true)
    }

    // MARK: Search (left)

    private func normalizedSearchQuery(_ raw: String) -> String {
        raw.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private func tokenizedPrefixMatch(query: String, text: String) -> Bool {
        guard !query.isEmpty else { return true }
        let tokens = text.lowercased().split { ch in
            !(ch.isLetter || ch.isNumber)
        }
        return tokens.contains { $0.hasPrefix(query) }
    }

    private func paperMatchesPrefix(_ paper: Paper,
                                    query: String,
                                    keywords: [String]? = nil) -> Bool {
        let authorYear = decodeTeXAccents(leftAuthorYearText(paper: paper))
        let title = decodeTeXAccents(paper.title)
        let cats = decodeTeXAccents(stripLeadingLabel(paper.categories, label: "Categories"))
        let abs = decodeTeXAccents(paper.abstractText)
        var parts = [authorYear, title, cats, abs]
        let keywordList = keywords ?? keywordsFromAppleScript
        if !keywordList.isEmpty {
            let present = keywordsPresent(in: paper, keywords: keywordList)
            if !present.isEmpty { parts.append(present.joined(separator: " ")) }
        }
        let corpus = parts.joined(separator: " ").lowercased()
        let q = query.lowercased()
        return corpus.contains(q)
    }

    @objc private func searchChanged() {
        let raw = searchField.stringValue
        logSearchDebug("searchChanged value=\(raw) textColor=\(String(describing: searchField.textColor))")
        SearchPerfLog.measure("search.action") {
            scheduleSearchUpdate(for: raw, reason: "action", immediate: true)
        }
    }

    private func scheduleSearchUpdate(for raw: String, reason: String, immediate: Bool) {
        let q = normalizedSearchQuery(raw)
        let priorSelectedKey: PaperKey? = {
            let row = tableView.selectedRow
            guard let idx = globalIndex(forTableRow: row), idx >= 0, idx < filtered.count else { return nil }
            return filtered[idx].key
        }()

        let itemsSnapshot = allItems
        let keywordsSnapshot = keywordsFromAppleScript

        searchToken &+= 1
        let token = searchToken
        searchDebounceWorkItem?.cancel()

        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            self.performSearch(token: token,
                               query: q,
                               priorSelectedKey: priorSelectedKey,
                               items: itemsSnapshot,
                               keywords: keywordsSnapshot,
                               reason: reason)
        }
        searchDebounceWorkItem = work
        let delay = immediate ? 0.0 : searchDebounceInterval
        if delay <= 0 {
            searchWorkerQueue.async(execute: work)
        } else {
            searchWorkerQueue.asyncAfter(deadline: .now() + delay, execute: work)
        }
    }

    private func performSearch(token: UInt64,
                               query: String,
                               priorSelectedKey: PaperKey?,
                               items: [Paper],
                               keywords: [String],
                               reason: String) {
        let startNs = monotonicNowNs()
        let filteredResults: [Paper] = SearchPerfLog.measure("search.filter") {
            guard !query.isEmpty else { return items }
            return items.filter { paperMatchesPrefix($0, query: query, keywords: keywords) }
        }

        let rawSuggestions: [SearchSuggestion]
        if query.isEmpty {
            rawSuggestions = []
        } else {
            rawSuggestions = SearchPerfLog.measure("search.suggest") {
                searchIndex.suggest(query: query, maxResults: 8)
            }
        }

        let filteredSuggestions: [SearchSuggestion] = SearchPerfLog.measure("search.suggest.filter") {
            guard !rawSuggestions.isEmpty else { return [] }
            let allowed = Set(filteredResults.map { $0.key })
            return rawSuggestions.filter { allowed.contains($0.paperKey) }
        }

        SearchPerfLog.logDuration("search.background.total", durationNs: monotonicNowNs() &- startNs)

        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            guard self.searchToken == token else { return }
            self.applySearchResults(token: token,
                                    query: query,
                                    filteredResults: filteredResults,
                                    suggestions: filteredSuggestions,
                                    priorSelectedKey: priorSelectedKey,
                                    reason: reason)
        }
    }

    private func resolvedSearchSelectionIndex(priorSelectedKey: PaperKey?,
                                              in results: [Paper]) -> Int? {
        guard !results.isEmpty else { return nil }
        if let key = priorSelectedKey,
           let idx = results.firstIndex(where: { $0.key == key }) {
            return idx
        }
        return 0
    }

    private func applySearchResults(token: UInt64,
                                    query: String,
                                    filteredResults: [Paper],
                                    suggestions: [SearchSuggestion],
                                    priorSelectedKey: PaperKey?,
                                    reason: String) {
        SearchPerfLog.measure("search.applyResults") {
            searchAppliedToken = token
            publicationStore.setFiltered(filteredResults)
            updateLeftHeaderText()

            SearchPerfLog.measure("search.pagination.fast") {
                recomputePaginationFast(preserveSelection: false, reason: "search-fast")
            }

            let targetIndex = resolvedSearchSelectionIndex(priorSelectedKey: priorSelectedKey,
                                                           in: filteredResults)
            if let idx = targetIndex,
               let page = paginator.pageIndex(containingGlobalFilteredIndex: idx),
               page != currentPageIndex {
                currentPageIndex = page
                updatePageControlTitle()
                updatePageStepperState()
            }

            SearchPerfLog.measure("search.table.noteRows") {
                tableView.noteNumberOfRowsChanged()
            }
            let visible = tableView.rows(in: tableView.visibleRect)
            if visible.length > 0 {
                let rowRange = visible.location..<(visible.location + visible.length)
                SearchPerfLog.measure("search.table.reloadVisible") {
                    tableView.reloadData(forRowIndexes: IndexSet(integersIn: rowRange),
                                         columnIndexes: IndexSet(integer: 0))
                }
            } else {
                SearchPerfLog.measure("search.table.reloadHeader") {
                    tableView.reloadData(forRowIndexes: IndexSet(integer: 0),
                                         columnIndexes: IndexSet(integer: 0))
                }
            }
            layoutLeftTableUnderlay(approximate: true)
            setHoveredTableRow(nil, animated: false)

            if let idx = targetIndex {
                SearchPerfLog.measure("search.select.fast") {
                    selectFilteredIndex(idx, scroll: false, reason: "search-fast-\(reason)", updatePanels: false)
                }
            } else {
                tableView.deselectAll(nil)
            }
            updateNavigationButtons()

            updateSuggestions(for: query, results: suggestions)
            scheduleSearchFinalize(token: token, reason: reason)
        }
    }

    private func scheduleSearchFinalize(token: UInt64, reason: String, delayOverride: TimeInterval? = nil) {
        searchHeavyReflowWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            guard self.searchToken == token, self.searchAppliedToken == token else { return }
            self.finalizeSearchUpdate(reason: reason)
        }
        searchHeavyReflowWorkItem = work
        let delay = delayOverride ?? searchHeavyReflowDelay
        DispatchQueue.main.asyncAfter(deadline: .now() + max(0, delay), execute: work)
    }

    private func finalizeSearchUpdate(reason: String) {
        SearchPerfLog.measure("search.finalize.reflow") {
            reflowLeft()
        }
        if filtered.isEmpty {
            SearchPerfLog.measure("search.finalize.empty") {
                loadHTMLWithLocalAccess(buildDetailsStatusHTML("No matches.",
                                                               paperIndex: nil,
                                                               paperTotal: 0,
                                                               leftHeaderText: nil,
                                                               centerHeaderText: nil))
                // If we were showing a PDF, force the right panel back to the details view so the
                // search result state is visible even when no results or no PDF.
                if isShowingPDF {
                    showDetailsPanel(animated: false, updateContent: false)
                }
                updateNavigationButtons()
            }
            return
        }
        if selectedFilteredIndex() == nil {
            SearchPerfLog.measure("search.finalize.selection") {
                ensureDefaultSelectionIfNeeded(reason: "search-final-\(reason)")
            }
        }
    }

    private func updateSuggestions(for query: String, results: [SearchSuggestion]? = nil) {
        let q = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !q.isEmpty else {
            clearSuggestionHover(animated: false)
            suggestions = []
            suggestionsTable.reloadData()
            suggestionSelectionIndex = -1
            setSuggestionsVisible(false, animated: true)
            return
        }

        let resolvedResults: [SearchSuggestion] = SearchPerfLog.measure("search.suggestions.resolve") {
            let base = results ?? searchIndex.suggest(query: q, maxResults: 8)
            return base.filter { filteredIndex(for: $0.paperKey) != nil }
        }

        let previousSuggestions = suggestions
        let previousCount = suggestions.count
        let suggestionsChanged = resolvedResults != previousSuggestions
        suggestions = resolvedResults
        suggestionsTable.deselectAll(nil)
        suggestionSelectionIndex = -1
        if suggestionsChanged {
            clearSuggestionHover(animated: false)
        }
        if suggestions.count != previousCount {
            SearchPerfLog.measure("search.suggestions.reload") {
                suggestionsTable.reloadData()
            }
        }
        SearchPerfLog.measure("search.suggestions.layout") {
            layoutSuggestionsDropdown()
        }
        if suggestions.isEmpty {
            setSuggestionsVisible(false, animated: true)
        } else {
            setSuggestionsVisible(true, animated: true)
        }
        syncSuggestionHoverFromMouse(animated: false)
        refreshSuggestionTextColors()
    }

    // MARK: Pagination + selection mapping

    private func availableListHeight() -> CGFloat {
        max(1, tableScroll.bounds.height)
    }

    private func rowHeightForFilteredIndex(_ index: Int) -> CGFloat {
        guard index >= 0, index < filtered.count else { return minRowHeight }
        let wrapW = leftWrapWidth()

        let leftW = max(1, min(keywordColumnTabX, wrapW))
        let gap = keywordSeparatorGap
        let rightW = max(1, wrapW - (leftW + gap))

        let pstyle = NSMutableParagraphStyle()
        pstyle.lineBreakMode = .byWordWrapping

        let colors = leftRowTextColors(isSelected: false, isActive: true)
        let paper = filtered[index]

        let leftAttr = leftAttributedAuthorText(
            for: paper,
            rowNumber: index + 1,
            paragraphStyle: pstyle,
            titleFont: leftRowTitleFont,
            secondaryFont: leftRowSecondaryFont,
            titleColor: colors.title,
            secondaryColor: colors.secondary
        )
        let leftBounding = leftAttr.boundingRect(
            with: NSSize(width: leftW, height: .greatestFiniteMagnitude),
            options: [.usesLineFragmentOrigin, .usesFontLeading]
        )

        let rightAttr = leftAttributedKeywordsText(
            for: paper,
            paragraphStyle: pstyle,
            secondaryFont: leftRowSecondaryFont,
            secondaryEmphasisFont: leftRowSecondaryEmphasisFont,
            secondaryColor: colors.secondary
        )
        let rightBounding = (rightAttr?.boundingRect(
            with: NSSize(width: rightW, height: .greatestFiniteMagnitude),
            options: [.usesLineFragmentOrigin, .usesFontLeading]
        )) ?? .zero

        let h = ceil(max(leftBounding.height, rightBounding.height)) + leftCellVerticalInsetY
        return max(minRowHeight, h)
    }

    private func recomputePagination(preserveSelection: Bool, reason: String) {
        let priorSelectedIndex = preserveSelection ? selectedFilteredIndex() : nil
        let availableHeight = availableListHeight()
        let inset = max(0, tableScroll.contentInsets.top)

        paginator.recompute(
            itemCount: filtered.count,
            availableHeight: availableHeight,
            minTopBottomInset: inset,
            headerRowHeight: headerRowHeight,
            rowHeightForFilteredIndex: { [weak self] idx in
                self?.rowHeightForFilteredIndex(idx) ?? self?.minRowHeight ?? 24
            }
        )

        if let idx = priorSelectedIndex,
           let page = paginator.pageIndex(containingGlobalFilteredIndex: idx) {
            // Keep the user on the closest equivalent page after resizing or filtering.
            currentPageIndex = page
        } else {
            currentPageIndex = max(0, min(currentPageIndex, max(0, paginator.pageCount - 1)))
        }

        updatePageControlVisibility()
        updatePageControlTitle()
        updatePageStepperState()

        if let idx = priorSelectedIndex {
            selectFilteredIndex(idx, scroll: false, reason: "pagination-preserve-\(reason)")
        }
    }

    private func recomputePaginationFast(preserveSelection: Bool, reason: String) {
        let priorSelectedIndex = preserveSelection ? selectedFilteredIndex() : nil
        let availableHeight = availableListHeight()
        let inset = max(0, tableScroll.contentInsets.top)

        paginator.recompute(
            itemCount: filtered.count,
            availableHeight: availableHeight,
            minTopBottomInset: inset,
            headerRowHeight: headerRowHeight,
            rowHeightForFilteredIndex: { [weak self] _ in self?.minRowHeight ?? 24 }
        )

        if let idx = priorSelectedIndex,
           let page = paginator.pageIndex(containingGlobalFilteredIndex: idx) {
            currentPageIndex = page
        } else {
            currentPageIndex = max(0, min(currentPageIndex, max(0, paginator.pageCount - 1)))
        }

        updatePageControlVisibility()
        updatePageControlTitle()
        updatePageStepperState()
    }

    private func globalIndex(forTableRow row: Int) -> Int? {
        // Table row (current page slice) → global filtered index mapping.
        guard row > 0 else { return nil } // row 0 is header
        let range = paginator.range(forPage: currentPageIndex)
        let dataRow = row - 1
        let idx = range.lowerBound + dataRow
        guard idx >= range.lowerBound, idx < range.upperBound else { return nil }
        return idx
    }

    private func tableRow(forGlobalFilteredIndex idx: Int) -> Int? {
        let range = paginator.range(forPage: currentPageIndex)
        guard range.contains(idx) else { return nil }
        return (idx - range.lowerBound) + 1
    }

    private func selectedFilteredIndex() -> Int? {
        globalIndex(forTableRow: tableView.selectedRow)
    }

    private func ensureDefaultSelectionIfNeeded(reason: String) {
        guard selectedFilteredIndex() == nil else { return }
        guard !filtered.isEmpty else { return }
        selectFilteredIndex(0, scroll: true, reason: reason)
    }

    private func selectFilteredIndex(_ idx: Int,
                                     scroll: Bool,
                                     reason: String,
                                     updatePanels: Bool = true) {
        guard idx >= 0, idx < filtered.count else { return }

        // Search → page navigation: move to the owning page before selecting the row.
        if let page = paginator.pageIndex(containingGlobalFilteredIndex: idx),
           page != currentPageIndex {
            currentPageIndex = page
            refreshSidebarPageContentWidthCache(reason: "page_change_select")
            updatePageControlTitle()
            updatePageStepperState()
            setHoveredTableRow(nil, animated: false)
            tableView.reloadData()
            DispatchQueue.main.async { [weak self] in
                self?.enforceSidebarWidthBounds(reason: "page_change_select")
            }
        }

        guard let row = tableRow(forGlobalFilteredIndex: idx) else { return }
        let priorRow = tableView.selectedRow
        if priorRow != row {
            selectionChangeFromCode = true
            tableView.selectRowIndexes(IndexSet(integer: row), byExtendingSelection: false)
            selectionChangeFromCode = false
        }
        if scroll { tableView.scrollRowToVisible(row) }
        if updatePanels {
            let applyPanels: () -> Void = { [self] in
                if self.isShowingPDF {
                    if let url = self.pdfURL(for: self.filtered[idx]) {
                        self.presentPDF(remoteURL: url, trigger: "select-\(reason)")
                        self.prefetchNeighborPDFs(around: idx, reason: "select-\(reason)")
                    } else {
                        // If there is no PDF for this selection, switch to the HTML/details view so the search still works.
                        self.showDetailsPanel(animated: true, updateContent: true)
                    }
                } else {
                    self.updateDetails()
                }
            }
            if searchLatencyDebugEnabled, reason.contains("search") {
                SearchPerfLog.measure("search.updatePanels") {
                    applyPanels()
                }
            } else {
                applyPanels()
            }
        }
        updateNavigationButtons()
        refreshZoteroButtonState(reason: "select-\(reason)")
    }

    private func filteredIndex(for key: PaperKey) -> Int? {
        filtered.firstIndex { $0.key == key }
    }

    private func updatePageControlVisibility() {
        // Hide the page navigation control so the publications table no longer exposes pagination UI.
        pageControlContainer.isHidden = true
        layoutHeaderControls()
    }

    private func updatePageControlTitle() {
        let page = max(0, min(currentPageIndex, max(0, paginator.pageCount - 1)))
        let title = "Page \(page + 1)"
        if pageMenuButton.title != title {
            pageMenuButton.title = title
            pageMenuButton.updateTint()
        }
    }

    private var pageStepperRelayoutInProgress = false
    private func updatePageStepperState(triggerLayout: Bool = true) {
        let pageCount = paginator.pageCount
        // Always show when the sidebar is visible; gate enablement (not visibility) on page count.
        let sidebarShown = sidebarVisible || leftContainer.frame.width > 2
        let shouldShow = sidebarShown
        let wasHidden = pageStepperContainer.isHidden
        pageStepperContainer.isHidden = !shouldShow

        let canStepBack = (pageCount > 1) && currentPageIndex > 0
        let canStepForward = (pageCount > 1) && currentPageIndex < max(0, pageCount - 1)
        pagePrevButton.isEnabled = canStepBack
        pageNextButton.isEnabled = canStepForward
        pagePrevButton.updateTint()
        pageNextButton.updateTint()

        if triggerLayout, wasHidden != pageStepperContainer.isHidden, !pageStepperRelayoutInProgress {
            pageStepperRelayoutInProgress = true
            layoutLeftContainerSubviews()
            pageStepperRelayoutInProgress = false
        }
    }

    // MARK: Left layout

        private func leftPreferredColumnWidth() -> CGFloat {
            // Ensure the column can grow beyond the viewport so users can pan horizontally,
            // but only as far as there is real text content (longest row).
            if cachedMaxLeftTextWidth <= 0 {
                rebuildLeftRowContentMetrics()
            }

            let visible = max(220, tableScroll.contentSize.width)
            let contentFit = max(220, sidebarHardMinWidth() - (2 * PANEL_INSET))

            // Content extent: leading inset + left column + gap + keyword text + trailing inset.
            // Use the same gutter constant as recomputeKeywordTabX() so both calculations agree.
            let gutter: CGFloat = 10
            let leftColumn = max(180, cachedMaxLeftTextWidth + gutter)
            let contentExtent = leftRowTextInset + leftColumn + keywordSeparatorGap + cachedMaxKeywordTextWidth + leftRowTextInset

            return max(visible, contentFit, max(220, contentExtent))
        }

        private func leftPreferredColumnWidthFast() -> CGFloat {
            let visible = max(220, tableScroll.contentSize.width)
            let contentFit = max(220, sidebarHardMinWidth() - (2 * PANEL_INSET))
            guard cachedMaxLeftTextWidth > 0, cachedMaxKeywordTextWidth > 0 else {
                return max(visible, contentFit)
            }

            let gutter: CGFloat = 10
            let leftColumn = max(180, cachedMaxLeftTextWidth + gutter)
            let contentExtent = leftRowTextInset + leftColumn + keywordSeparatorGap + cachedMaxKeywordTextWidth + leftRowTextInset
            return max(visible, contentFit, max(220, contentExtent))
        }

        private func recomputeKeywordTabXFast() {
            guard cachedMaxLeftTextWidth > 0 else { return }
            let colW = max(220, (tableView.tableColumns.first?.width ?? tableView.bounds.width))
            let available = max(160, colW - (2 * leftRowTextInset))

            let gutter: CGFloat = 10
            var tabX = cachedMaxLeftTextWidth + gutter

            let keywordHeaderMin = ("Keyword(s)" as NSString).size(withAttributes: [.font: leftRowSecondaryFont]).width
            let minRight: CGFloat = max(70, keywordHeaderMin + 10)
            let maxTab = max(120, available - minRight)
            tabX = min(tabX, maxTab)
            tabX = max(tabX, 180)

            keywordColumnTabX = tabX
        }

        private func updateVisibleLeftRowLayoutsForCurrentColumn() {
            let visible = tableView.rows(in: tableView.visibleRect)
            guard visible.length > 0 else { return }
            let leading = leftRowTextInset
            let trailing = leftRowTextInset
            let top = leftCellInsetY
            let bottom = leftCellBottomInsetY
            let leftColumnWidth = keywordColumnTabX
            let gap = keywordSeparatorGap
            let minRight = leftKeywordMinColumnWidth()

            for row in visible.location..<(visible.location + visible.length) {
                guard let rowView = tableView.rowView(atRow: row, makeIfNecessary: false),
                      let cell = rowView.view(atColumn: 0) as? LeftTwoColumnCellView else { continue }
                cell.updateLayout(leadingInset: leading,
                                  trailingInset: trailing,
                                  topInset: top,
                                  bottomInset: bottom,
                                  leftColumnWidth: leftColumnWidth,
                                  gap: gap,
                                  minRightWidth: minRight)
                cell.layoutSubtreeIfNeeded()
            }
        }

        private func refreshLeftLayoutAfterSidebarToggle(visible: Bool, layoutAlreadyApplied: Bool = false) {
            guard visible else { return }
            let guardMeasure = AnimationGuard.beginMeasurement("list.reflow_left.toggle")
            defer { AnimationGuard.endMeasurement(guardMeasure) }
            PerfLogger.begin("list.reflow_left.toggle")
            defer { PerfLogger.end("list.reflow_left.toggle") }

            if !layoutAlreadyApplied {
                layoutLeftContainerSubviews(duringDividerDrag: true)
            }
            if let col = tableView.tableColumns.first {
                let preferred = leftPreferredColumnWidthFast()
                if abs(col.width - preferred) > 0.5 {
                    col.width = preferred
                }
            }
            recomputeKeywordTabXFast()
            updateLeftHeaderText()
            updateVisibleLeftRowLayoutsForCurrentColumn()
            layoutLeftTableUnderlay(approximate: true)
        }

        private func reflowLeft() {
            let guardMeasure = AnimationGuard.beginMeasurement("list.reflow_left")
            defer { AnimationGuard.endMeasurement(guardMeasure) }
            PerfLogger.begin("list.reflow_left")
            defer { PerfLogger.end("list.reflow_left") }
            // Ensure split view sizing is fresh before measuring column widths.
            layoutLeftContainerSubviews()
            PerfLogger.measure("autolayout.leftContainer.reflow") {
                leftContainer.layoutSubtreeIfNeeded()
            }
            PerfLogger.measure("autolayout.tableScroll.reflow") {
                tableScroll.layoutSubtreeIfNeeded()
            }
            rebuildLeftRowContentMetrics()
            if let col = tableView.tableColumns.first {
                col.width = leftPreferredColumnWidth()
            }

            recomputeKeywordTabX()
            updateLeftHeaderText()

            PerfLogger.measure("list.pagination.recompute") {
	        recomputePagination(preserveSelection: true, reason: "reflow")
            }
	        let visibleRows = max(0, paginator.range(forPage: currentPageIndex).count)
            PerfLogger.measure("tableView.note_height_rows") {
	        tableView.noteHeightOfRows(withIndexesChanged: IndexSet(integersIn: 0...max(0, visibleRows)))
            }
            setHoveredTableRow(nil, animated: false)
            PerfLogger.measure("tableView.reloadData") {
	        tableView.reloadData()
            }
            PerfLogger.measure("autolayout.tableView.reflow") {
	        tableView.layoutSubtreeIfNeeded()
            }
            PerfLogger.measure("autolayout.tableScroll.post_reflow") {
	        tableScroll.layoutSubtreeIfNeeded()
            }
	        layoutLeftTableUnderlay()

        tableView.menu = rowMenu

            // Keep the sidebar minimum width aligned to the current page's keyword extent.
            // (When the sidebar is hidden, this is intentionally a no-op.)
            refreshSidebarPageContentWidthCache(reason: "reflow")
            enforceSidebarWidthBounds(reason: "reflow")
	    }

    private func launchPageRangeForSidebarSizing() -> Range<Int> {
        // Prefer the current page range once pagination is available.
        if paginator.pageCount > 0 {
            let r = paginator.range(forPage: currentPageIndex)
            if !r.isEmpty { return r }
        }

        // Fallback: early launch before pagination is computed.
        if filtered.isEmpty { return 0..<0 }
        return 0..<min(filtered.count, 24)
    }

    private func measureSingleLineWidth(_ s: NSAttributedString) -> CGFloat {
        let rect = s.boundingRect(
            with: NSSize(width: CGFloat.greatestFiniteMagnitude, height: CGFloat.greatestFiniteMagnitude),
            options: [.usesLineFragmentOrigin, .usesFontLeading]
        )
        return ceil(max(0, rect.width))
    }

    private func rebuildLeftRowContentMetrics() {
        let guardMeasure = AnimationGuard.beginMeasurement("list.rebuild_row_metrics")
        defer { AnimationGuard.endMeasurement(guardMeasure) }
        PerfLogger.begin("list.rebuild_row_metrics")
        defer { PerfLogger.end("list.rebuild_row_metrics") }
        // Measure the actual rendered text extents so horizontal scrolling can be clamped
        // to real content (prevents "infinite" panning into empty space).
        let total = max(1, filtered.count)
        cachedRowNumberDigits = String(total).count

        let pstyle = NSMutableParagraphStyle()
        pstyle.lineBreakMode = .byClipping
        let colors = leftRowTextColors(isSelected: false, isActive: true)

        var maxLeftWidth: CGFloat = 0
        var maxKeywordWidth: CGFloat = 0

        for (i, paper) in filtered.enumerated() {
            let leftAttr = leftAttributedAuthorText(
                for: paper,
                rowNumber: i + 1,
                paragraphStyle: pstyle,
                titleFont: leftRowTitleFont,
                secondaryFont: leftRowSecondaryFont,
                titleColor: colors.title,
                secondaryColor: colors.secondary
            )
            maxLeftWidth = max(maxLeftWidth, measureSingleLineWidth(leftAttr))

            if let kwAttr = leftAttributedKeywordsText(
                for: paper,
                paragraphStyle: pstyle,
                secondaryFont: leftRowSecondaryFont,
                secondaryEmphasisFont: leftRowSecondaryEmphasisFont,
                secondaryColor: colors.secondary
            ) {
                maxKeywordWidth = max(maxKeywordWidth, measureSingleLineWidth(kwAttr))
            }
        }

        cachedMaxLeftTextWidth = maxLeftWidth
        cachedMaxKeywordTextWidth = maxKeywordWidth
    }

    private func maxAuthorYearWidthForLaunchRows(_ range: Range<Int>) -> CGFloat {
        guard !range.isEmpty else { return 0 }
        let pstyle = NSMutableParagraphStyle()
        pstyle.lineBreakMode = .byClipping
        let colors = leftRowTextColors(isSelected: false, isActive: true)

        var maxWidth: CGFloat = 0
        for idx in range {
            guard idx >= 0, idx < filtered.count else { continue }
            let attr = leftAttributedAuthorText(
                for: filtered[idx],
                rowNumber: idx + 1,
                paragraphStyle: pstyle,
                titleFont: leftRowTitleFont,
                secondaryFont: leftRowSecondaryFont,
                titleColor: colors.title,
                secondaryColor: colors.secondary
            )
            let w = measureSingleLineWidth(attr)
            if w > maxWidth { maxWidth = w }
        }

        return maxWidth
    }

    private func maxTwoKeywordWidthForLaunchRows(_ range: Range<Int>) -> CGFloat {
        guard !range.isEmpty else { return 0 }
        guard !keywordsFromAppleScript.isEmpty else { return 0 }

        let pstyle = NSMutableParagraphStyle()
        pstyle.lineBreakMode = .byClipping
        let colors = leftRowTextColors(isSelected: false, isActive: true)

        var maxWidth: CGFloat = 0
        for idx in range {
            guard idx >= 0, idx < filtered.count else { continue }
            let present = dedupePluralKeywordsForDisplay(
                keywordsPresent(in: filtered[idx], keywords: keywordsFromAppleScript)
            )
            let two = Array(present.prefix(2))
            guard !two.isEmpty else { continue }

            let result = NSMutableAttributedString(
                string: "",
                attributes: [
                    .font: leftRowSecondaryFont,
                    .paragraphStyle: pstyle,
                    .foregroundColor: colors.secondary
                ]
            )

            for (i, kw) in two.enumerated() {
                if i > 0 {
                    result.append(NSAttributedString(
                        string: ", ",
                        attributes: [
                            .font: leftRowSecondaryFont,
                            .paragraphStyle: pstyle,
                            .foregroundColor: colors.secondary
                        ]
                    ))
                }
                result.append(NSAttributedString(
                    string: kw,
                    attributes: [
                        .font: leftRowSecondaryEmphasisFont,
                        .paragraphStyle: pstyle,
                        .foregroundColor: colors.secondary
                    ]
                ))
            }

            let w = measureSingleLineWidth(result)
            if w > maxWidth { maxWidth = w }
        }

        return maxWidth
    }

    private func maxKeywordWidthForRange(_ range: Range<Int>) -> CGFloat {
        guard !range.isEmpty else { return 0 }
        guard !keywordsFromAppleScript.isEmpty else { return 0 }

        let pstyle = NSMutableParagraphStyle()
        pstyle.lineBreakMode = .byClipping
        let colors = leftRowTextColors(isSelected: false, isActive: true)

        var maxWidth: CGFloat = 0
        for idx in range {
            guard idx >= 0, idx < filtered.count else { continue }
            guard let kwAttr = leftAttributedKeywordsText(
                for: filtered[idx],
                paragraphStyle: pstyle,
                secondaryFont: leftRowSecondaryFont,
                secondaryEmphasisFont: leftRowSecondaryEmphasisFont,
                secondaryColor: colors.secondary
            ) else { continue }
            let w = measureSingleLineWidth(kwAttr)
            if w > maxWidth { maxWidth = w }
        }

        return maxWidth
    }

    private func desiredLaunchSidebarWidth(maxLeft: CGFloat) -> CGFloat {
        // Launch sizing: honor the last remembered width (or the default) while respecting
        // the hard minimum needed to center "Author & Year".
        let minLeft = sidebarHardMinWidth()
        let fallback = max(minLeft, Self.defaultSidebarWidth)
        let stored = (lastSidebarWidth.isFinite && lastSidebarWidth > 12) ? lastSidebarWidth : fallback
        return min(maxLeft, max(minLeft, stored))
    }

    private func rebuildLeftColumnMetrics() {
        rebuildLeftRowContentMetrics()
    }

    private func stableRowNumberDigits() -> Int {
        if cachedRowNumberDigits > 0 { return cachedRowNumberDigits }
        return max(1, String(max(1, allItems.count)).count)
    }

    private func leftWrapWidth() -> CGFloat {
        let colW = max(220, (tableView.tableColumns.first?.width ?? tableView.bounds.width))
        return max(120, colW - (2 * leftRowTextInset) - 2)
    }

    private func recomputeKeywordTabX() {
        let colW = max(220, (tableView.tableColumns.first?.width ?? tableView.bounds.width))
        let available = max(160, colW - (2 * leftRowTextInset))

        if cachedMaxLeftTextWidth <= 0 {
            rebuildLeftColumnMetrics()
        }

        let gutter: CGFloat = 10
        var tabX = cachedMaxLeftTextWidth + gutter

        // Keep some room for the keyword column, but don't reserve so much that
        // author/year wraps unnecessarily (keywords can wrap too).
        let keywordHeaderMin = ("Keyword(s)" as NSString).size(withAttributes: [.font: leftRowSecondaryFont]).width
        let minRight: CGFloat = max(70, keywordHeaderMin + 10)
        let maxTab = max(120, available - minRight)
        tabX = min(tabX, maxTab)
        tabX = max(tabX, 180)

        keywordColumnTabX = tabX
    }

    private func leftKeywordMinColumnWidth() -> CGFloat {
        let pstyle = NSMutableParagraphStyle()
        pstyle.lineBreakMode = .byClipping
        let attrs = leftAuthorYearHeaderAttributes(paragraphStyle: pstyle)
        let headerW = ("Keyword(s)" as NSString).size(withAttributes: attrs).width
        return max(70, headerW + 10)
    }

    private func applyTwoColumnTabStops(to pstyle: NSMutableParagraphStyle) {
        let tabX = keywordColumnTabX
        let t1 = NSTextTab(textAlignment: .left, location: tabX, options: [:])
        let t2 = NSTextTab(textAlignment: .left, location: tabX + keywordSeparatorGap, options: [:])
        pstyle.tabStops = [t1, t2]
        pstyle.defaultTabInterval = tabX + keywordSeparatorGap
    }

    private func updateLeftHeaderText() {
        let pstyle = NSMutableParagraphStyle()
        pstyle.lineBreakMode = .byClipping
        let labelWidth = leftHeaderLabel.bounds.width > 1
            ? leftHeaderLabel.bounds.width
            : leftHeaderBar.bounds.width
        if labelWidth > 1 {
            let minRight = leftKeywordMinColumnWidth()
            let maxTab = max(1, labelWidth - minRight)
            let tabX = max(1, min(keywordColumnTabX, maxTab))
            let t1 = NSTextTab(textAlignment: .left, location: tabX, options: [:])
            let t2 = NSTextTab(textAlignment: .left, location: tabX + keywordSeparatorGap, options: [:])
            pstyle.tabStops = [t1, t2]
            pstyle.defaultTabInterval = tabX + keywordSeparatorGap
        } else {
            applyTwoColumnTabStops(to: pstyle)
        }

        // Use two tab characters so the keyword column always lands on the
        // second tab stop (tabX + gap) for consistent spacing/alignment.
        let headerString = "Author & Year\t\tKeyword(s)"
        let attr = NSAttributedString(
            string: headerString,
            attributes: [
                .font: resolvedUIFontFromSettings(defaultSize: 12, weight: .semibold),
                .foregroundColor: leftHeaderTextColor(),
                .paragraphStyle: pstyle
            ]
        )
        leftHeaderLabel.attributedStringValue = attr
    }

    private final class LeftTwoColumnCellView: NSTableCellView {
        let leftField = NSTextField(labelWithString: "")
        let rightField = NSTextField(labelWithString: "")

        private var leftLeading: NSLayoutConstraint!
        private var leftTop: NSLayoutConstraint!
        private var leftBottomMax: NSLayoutConstraint!
        private var leftWidth: NSLayoutConstraint!

        private var rightLeading: NSLayoutConstraint!
        private var rightTop: NSLayoutConstraint!
        private var rightBottomMax: NSLayoutConstraint!
        private var rightTrailing: NSLayoutConstraint!

        private var lastLeadingInset: CGFloat = 0
        private var lastTrailingInset: CGFloat = 0
        private var lastLeftColumnWidth: CGFloat = 200
        private var lastGap: CGFloat = 0
        private var lastMinRightWidth: CGFloat = 70
        private var resolvedLeftColumnWidth: CGFloat = 200

        override init(frame frameRect: NSRect) {
            super.init(frame: frameRect)

            leftField.translatesAutoresizingMaskIntoConstraints = false
            leftField.backgroundColor = .clear
            leftField.maximumNumberOfLines = 1
            leftField.usesSingleLineMode = true
            leftField.cell?.wraps = false
            leftField.cell?.isScrollable = false
            leftField.lineBreakMode = .byTruncatingTail
            leftField.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)

            rightField.translatesAutoresizingMaskIntoConstraints = false
            rightField.backgroundColor = .clear
            rightField.maximumNumberOfLines = 1
            rightField.usesSingleLineMode = true
            rightField.cell?.wraps = false
            rightField.cell?.isScrollable = false
            rightField.lineBreakMode = .byTruncatingTail
            rightField.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)

            addSubview(leftField)
            addSubview(rightField)

            leftLeading = leftField.leadingAnchor.constraint(equalTo: leadingAnchor)
            leftTop = leftField.topAnchor.constraint(equalTo: topAnchor)
            leftBottomMax = leftField.bottomAnchor.constraint(lessThanOrEqualTo: bottomAnchor)
            leftWidth = leftField.widthAnchor.constraint(equalToConstant: 200)

            rightLeading = rightField.leadingAnchor.constraint(equalTo: leadingAnchor)
            rightTop = rightField.topAnchor.constraint(equalTo: topAnchor)
            rightBottomMax = rightField.bottomAnchor.constraint(lessThanOrEqualTo: bottomAnchor)
            rightTrailing = rightField.trailingAnchor.constraint(equalTo: trailingAnchor)

            NSLayoutConstraint.activate([
                leftLeading,
                leftTop,
                leftBottomMax,
                leftWidth,
                rightLeading,
                rightTop,
                rightBottomMax,
                rightTrailing
            ])

            textField = leftField
            rightField.tag = 2
        }

        required init?(coder: NSCoder) {
            fatalError("init(coder:) has not been implemented")
        }

        override func layout() {
            super.layout()
            // Critical: when cells are created/reused, `updateLayout(...)` may be called
            // before the table has assigned a final width. If we freeze the preferredMaxLayoutWidth
            // at that moment (often ~0), the keyword column can remain effectively invisible until
            // some unrelated relayout (e.g., hiding/showing the sidebar) happens.
            // Re-apply using the current bounds so the keywords appear immediately.
            applyColumnConstraintClamp()
            applyPreferredMaxLayoutWidths()
        }

        private func applyPreferredMaxLayoutWidths() {
            let leadingInset = lastLeadingInset
            let trailingInset = lastTrailingInset
            let leftColumnWidth = max(1, resolvedLeftColumnWidth)
            let gap = lastGap

            leftField.preferredMaxLayoutWidth = max(1, leftColumnWidth)
            let rightW = max(1, bounds.width - (leadingInset + leftColumnWidth + gap) - trailingInset)
            rightField.preferredMaxLayoutWidth = rightW
        }

        private func applyColumnConstraintClamp() {
            let available = max(1, bounds.width - lastLeadingInset - lastTrailingInset)
            let minRight = max(1, lastMinRightWidth)
            let maxLeft = max(1, available - lastGap - minRight)
            let clampedLeft = min(maxLeft, max(1, lastLeftColumnWidth))
            resolvedLeftColumnWidth = clampedLeft
            if abs(leftWidth.constant - clampedLeft) > 0.25 {
                leftWidth.constant = clampedLeft
            }
            let rightLead = lastLeadingInset + clampedLeft + lastGap
            if abs(rightLeading.constant - rightLead) > 0.25 {
                rightLeading.constant = rightLead
            }
        }

        func updateLayout(leadingInset: CGFloat,
                          trailingInset: CGFloat,
                          topInset: CGFloat,
                          bottomInset: CGFloat,
                          leftColumnWidth: CGFloat,
                          gap: CGFloat,
                          minRightWidth: CGFloat) {
            lastLeadingInset = leadingInset
            lastTrailingInset = trailingInset
            lastLeftColumnWidth = leftColumnWidth
            lastGap = gap
            lastMinRightWidth = minRightWidth

            leftLeading.constant = leadingInset
            leftTop.constant = topInset
            leftBottomMax.constant = -bottomInset
            applyColumnConstraintClamp()

            rightLeading.constant = leadingInset + resolvedLeftColumnWidth + gap
            rightTop.constant = topInset
            rightBottomMax.constant = -bottomInset
            rightTrailing.constant = -trailingInset

            applyPreferredMaxLayoutWidths()
        }
    }

    // MARK: Table
    func numberOfRows(in tableView: NSTableView) -> Int {
        if tableView === suggestionsTable {
            return suggestions.count
        }
        if tableView === menuTable {
            return menuItems.count
        }
        return paginator.range(forPage: currentPageIndex).count + 1 // +1 for header row
    }

    func tableView(_ tableView: NSTableView, shouldSelectRow row: Int) -> Bool {
        if tableView === suggestionsTable {
            return row >= 0
        }
        if tableView === menuTable {
            guard row >= 0, row < menuItems.count else { return false }
            return menuItems[row].isSelectable
        }
        return row > 0 // prevent selecting header row
    }

    func tableView(_ tableView: NSTableView, rowViewForRow row: Int) -> NSTableRowView? {
        if tableView === suggestionsTable {
            let view = GlassMenuRowView()
            view.rowInsets = NSEdgeInsets(top: 6, left: 10, bottom: 6, right: 10)
            view.isActiveWindowProvider = { [weak self] in self?.isWindowActiveForAppearance() ?? true }
            view.accentBaseColorProvider = { [weak self] in self?.panelClearGlassTintColor() ?? resolvedSystemColor(.textBackgroundColor) }
            return view
        }
        if tableView === menuTable {
            guard row >= 0, row < menuItems.count else { return nil }
            let item = menuItems[row]
            if item.kind == .separator {
                return NSTableRowView()
            }
            let view = GlassMenuRowView()
            view.rowInsets = menuRowInsets
            view.isActiveWindowProvider = { [weak self] in self?.isWindowActiveForAppearance() ?? true }
            view.accentBaseColorProvider = { [weak self] in self?.panelClearGlassTintColor() ?? resolvedSystemColor(.textBackgroundColor) }
            view.outlineOnly = true
            view.isInteractive = item.isSelectable
            return view
        }
        let view = ElasticRowView()
        view.isHeaderRow = (row == 0)
        view.rowIndex = row
        view.reduceMotionProvider = { [weak self] in self?.shouldReduceMotion ?? false }
        view.isActiveWindowProvider = { [weak self] in self?.isWindowActiveForAppearance() ?? true }
        view.animationEnabledProvider = { [weak self] in !(self?.suppressRowAnimations ?? false) }
        view.accentBaseColorProvider = { [weak self] in self?.leftTableUnderlayTintColor() ?? resolvedSystemColor(.textBackgroundColor) }
        view.horizontalAlignmentReferenceView = searchBackground
        view.hoverChanged = { [weak self] rowIndex, isHovered in
            self?.handleRowHover(rowIndex, isHovered: isHovered)
        }
        return view
    }

    func tableView(_ tableView: NSTableView, heightOfRow row: Int) -> CGFloat {
        if tableView === suggestionsTable {
            return suggestionRowHeight
        }
        if tableView === menuTable {
            guard row >= 0, row < menuItems.count else { return menuRowHeight }
            switch menuItems[row].kind {
            case .summary:
                return menuSummaryRowHeight
            case .separator:
                return menuSeparatorHeight
            case .page, .action:
                return menuRowHeight
            }
        }
        if row == 0 { return headerRowHeight }
        // Publication rows are single-line (truncated), so row heights are fixed.
        return minRowHeight
    }

    func tableView(_ tableView: NSTableView, viewFor tableColumn: NSTableColumn?, row: Int) -> NSView? {
        if tableView === suggestionsTable {
            guard row >= 0, row < suggestions.count else { return nil }
            let cellId = NSUserInterfaceItemIdentifier("suggestionCell")
            if let existing = tableView.makeView(withIdentifier: cellId, owner: self) as? NSTableCellView {
                configureSuggestionCell(existing, row: row)
                return existing
            }
            let cellView = NSTableCellView(frame: .zero)
            cellView.identifier = cellId

            let titleField = NSTextField(labelWithString: "")
            titleField.translatesAutoresizingMaskIntoConstraints = false
            titleField.font = suggestionTitleFont
            titleField.lineBreakMode = .byTruncatingTail
            titleField.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)

            let subtitleField = NSTextField(labelWithString: "")
            subtitleField.translatesAutoresizingMaskIntoConstraints = false
            subtitleField.font = suggestionSubtitleFont
            subtitleField.lineBreakMode = .byTruncatingTail
            subtitleField.textColor = resolvedSystemColor(.secondaryLabelColor)
            subtitleField.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)

            cellView.addSubview(titleField)
            cellView.addSubview(subtitleField)
            cellView.textField = titleField
            subtitleField.tag = 2

            NSLayoutConstraint.activate([
                titleField.leadingAnchor.constraint(equalTo: cellView.leadingAnchor, constant: suggestionTextInsetX),
                titleField.trailingAnchor.constraint(equalTo: cellView.trailingAnchor, constant: -suggestionTextInsetX),
                titleField.topAnchor.constraint(equalTo: cellView.topAnchor, constant: 6),
                subtitleField.leadingAnchor.constraint(equalTo: cellView.leadingAnchor, constant: suggestionTextInsetX),
                subtitleField.trailingAnchor.constraint(equalTo: cellView.trailingAnchor, constant: -suggestionTextInsetX),
                subtitleField.topAnchor.constraint(equalTo: titleField.bottomAnchor, constant: 2),
                subtitleField.bottomAnchor.constraint(equalTo: cellView.bottomAnchor, constant: -6)
            ])
            configureSuggestionCell(cellView, row: row)
            return cellView
        }

        if tableView === menuTable {
            guard row >= 0, row < menuItems.count else { return nil }
            let item = menuItems[row]
            if item.kind == .separator {
                let sepId = NSUserInterfaceItemIdentifier("menuSeparator")
                if let existing = tableView.makeView(withIdentifier: sepId, owner: self) as? MenuSeparatorView {
                    configureMenuSeparator(existing)
                    return existing
                }
                let view = MenuSeparatorView(frame: .zero)
                view.identifier = sepId
                configureMenuSeparator(view)
                return view
            }

            let cellId = NSUserInterfaceItemIdentifier("menuCell")
            if let existing = tableView.makeView(withIdentifier: cellId, owner: self) as? NSTableCellView {
                configureMenuCell(existing, row: row)
                return existing
            }
            let cellView = NSTableCellView(frame: .zero)
            cellView.identifier = cellId

            let check = NSImageView(frame: .zero)
            check.translatesAutoresizingMaskIntoConstraints = false
            check.imageScaling = .scaleProportionallyDown
            check.setContentCompressionResistancePriority(.required, for: .horizontal)
            cellView.addSubview(check)
            cellView.imageView = check

            let tf = NSTextField(labelWithString: "")
            tf.translatesAutoresizingMaskIntoConstraints = false
            tf.lineBreakMode = .byTruncatingTail
            tf.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)
            cellView.addSubview(tf)
            cellView.textField = tf

            NSLayoutConstraint.activate([
                check.leadingAnchor.constraint(equalTo: cellView.leadingAnchor, constant: menuCheckmarkLeading),
                check.centerYAnchor.constraint(equalTo: cellView.centerYAnchor),
                check.widthAnchor.constraint(equalToConstant: menuCheckmarkSize),
                check.heightAnchor.constraint(equalToConstant: menuCheckmarkSize),

                tf.leadingAnchor.constraint(equalTo: cellView.leadingAnchor, constant: menuTextLeading),
                tf.trailingAnchor.constraint(equalTo: cellView.trailingAnchor, constant: -menuTextTrailing),
                tf.centerYAnchor.constraint(equalTo: cellView.centerYAnchor)
            ])
            configureMenuCell(cellView, row: row)
            return cellView
        }

        guard row >= 0, row <= paginator.range(forPage: currentPageIndex).count else { return nil }

        let cellId = NSUserInterfaceItemIdentifier("leftCell")

        if let existing = tableView.makeView(withIdentifier: cellId, owner: self) as? LeftTwoColumnCellView {
            let selected = tableView.selectedRowIndexes.contains(row)
            let active = isWindowActiveForAppearance()
            existing.updateLayout(
                leadingInset: leftRowTextInset,
                trailingInset: leftRowTextInset,
                topInset: leftCellInsetY,
                bottomInset: leftCellBottomInsetY,
                leftColumnWidth: keywordColumnTabX,
                gap: keywordSeparatorGap,
                minRightWidth: leftKeywordMinColumnWidth()
            )
            configureLeftCell(existing, row: row, isSelected: selected, isActive: active)
            return existing
        }

        let cellView = LeftTwoColumnCellView(frame: .zero)
        cellView.identifier = cellId
        let selected = tableView.selectedRowIndexes.contains(row)
        let active = isWindowActiveForAppearance()
        cellView.updateLayout(
            leadingInset: leftRowTextInset,
            trailingInset: leftRowTextInset,
            topInset: leftCellInsetY,
            bottomInset: leftCellBottomInsetY,
            leftColumnWidth: keywordColumnTabX,
            gap: keywordSeparatorGap,
            minRightWidth: leftKeywordMinColumnWidth()
        )
        configureLeftCell(cellView, row: row, isSelected: selected, isActive: active)
        return cellView
    }

    func tableView(_ tableView: NSTableView, didAdd rowView: NSTableRowView, forRow row: Int) {
        if tableView === suggestionsTable {
            configureSuggestionRowView(rowView, row: row)
            return
        }
        if tableView === menuTable {
            configureMenuRowView(rowView, row: row)
            return
        }
        guard row >= 0, row <= paginator.range(forPage: currentPageIndex).count else { return }
        if row == 1 { logListRenderIfNeeded() }
        if let elastic = rowView as? ElasticRowView {
            elastic.isHeaderRow = (row == 0)
            elastic.rowIndex = row
            elastic.reduceMotionProvider = { [weak self] in self?.shouldReduceMotion ?? false }
            elastic.isActiveWindowProvider = { [weak self] in self?.isWindowActiveForAppearance() ?? true }
            elastic.refreshDepth(animated: false, preset: .crisp)
            elastic.setHoverState(row == hoveredTableRow, animated: false, notify: false)
        }
        guard let cell = rowView.view(atColumn: 0) as? LeftTwoColumnCellView else { return }
        cell.updateLayout(
            leadingInset: leftRowTextInset,
            trailingInset: leftRowTextInset,
            topInset: leftCellInsetY,
            bottomInset: leftCellBottomInsetY,
            leftColumnWidth: keywordColumnTabX,
            gap: keywordSeparatorGap,
            minRightWidth: leftKeywordMinColumnWidth()
        )
        cell.layoutSubtreeIfNeeded()
        let selected = rowView.isSelected
        let active = isWindowActiveForAppearance()
        configureLeftCell(cell, row: row, isSelected: selected, isActive: active)
    }

    func tableViewSelectionDidChange(_ notification: Notification) {
        if let table = notification.object as? NSTableView, table === suggestionsTable {
            suggestionSelectionIndex = table.selectedRow
            refreshSuggestionTextColors()
            return
        }
        if let table = notification.object as? NSTableView, table === menuTable {
            refreshMenuTextBounce(animated: true)
            return
        }
        updateVisibleRowSelectionStyling()
        var fellBackToDetails = false
        if let idx = selectedFilteredIndex(), idx >= 0, idx < filtered.count {
            let key = filtered[idx].key
            uiLog("row_selection_change row=\(tableView.selectedRow) dataRow=\(idx)")
            recordSelectionHistory(for: key, viewMode: isShowingPDF, reason: "table-selection")
            if isShowingPDF && !selectionChangeFromCode {
                if let url = pdfURL(for: filtered[idx]) {
                    presentPDF(remoteURL: url, trigger: "table-selection")
                    prefetchNeighborPDFs(around: idx, reason: "table-selection")
                } else {
                    // Items without PDFs should still react to selection while the PDF view is showing.
                    showDetailsPanel(animated: true, updateContent: true)
                    fellBackToDetails = true
                }
            }
        } else {
            uiLog("row_selection_change row=\(tableView.selectedRow) dataRow=nil")
        }
        if !isShowingPDF && !selectionChangeFromCode && !fellBackToDetails { updateDetails() }
        updateNavigationButtons()
    }

    private func updateVisibleRowSelectionStyling() {
        let visible = tableView.rows(in: tableView.visibleRect)
        guard visible.length > 0 else { return }
        let active = isWindowActiveForAppearance()

        for row in visible.location..<(visible.location + visible.length) {
            guard let rowView = tableView.rowView(atRow: row, makeIfNecessary: false),
                let cell = rowView.view(atColumn: 0) as? LeftTwoColumnCellView else { continue }
            let selected = rowView.isSelected
            configureLeftCell(cell, row: row, isSelected: selected, isActive: active)
        }
    }

    private func applySuggestionTextBounce(row: Int, hovered: Bool, animated: Bool) {
        guard row >= 0, row < suggestions.count else { return }
        guard let cell = suggestionsTable.view(atColumn: 0, row: row, makeIfNecessary: false) as? NSTableCellView else { return }
        let reduce = shouldReduceMotion
        applyHoverBounce(to: cell.textField, hovered: hovered, animated: animated, reduceMotion: reduce)
        if let subtitle = cell.viewWithTag(2) as? NSTextField {
            applyHoverBounce(to: subtitle, hovered: hovered, animated: animated, reduceMotion: reduce)
        }
    }

    private func handleSuggestionHover(_ row: Int, isHovered: Bool) {
        guard row >= 0, row < suggestions.count else { return }
        if isHovered {
            hoveredSuggestionRow = row
        } else if hoveredSuggestionRow == row {
            hoveredSuggestionRow = nil
        }
        applySuggestionTextBounce(row: row, hovered: isHovered, animated: true)
    }

    private func applyMenuTextBounce(row: Int, hovered: Bool, animated: Bool) {
        guard row >= 0, row < menuItems.count else { return }
        if menuItems[row].kind == .separator { return }
        guard let cell = menuTable.view(atColumn: 0, row: row, makeIfNecessary: false) as? NSTableCellView else { return }
        applyHoverBounce(to: cell.textField,
                         hovered: hovered,
                         animated: animated,
                         reduceMotion: shouldReduceMotion)
    }

    private func handleMenuHover(_ row: Int, isHovered: Bool) {
        guard row >= 0, row < menuItems.count else { return }
        if menuItems[row].kind == .separator { return }
        if isHovered {
            hoveredMenuRow = row
        } else if hoveredMenuRow == row {
            hoveredMenuRow = nil
        }
        applyMenuTextBounce(row: row, hovered: isHovered, animated: true)
    }

    private func applyTableRowHoverState(for row: Int,
                                         hovered: Bool,
                                         animated: Bool,
                                         notify: Bool) {
        guard row > 0 else { return }
        if let rowView = tableView.rowView(atRow: row, makeIfNecessary: false) as? ElasticRowView {
            rowView.setHoverState(hovered, animated: animated, notify: notify)
        }
        if let cell = tableView.view(atColumn: 0, row: row, makeIfNecessary: false) as? LeftTwoColumnCellView {
            applyHoverBounce(to: cell.leftField,
                             hovered: hovered,
                             animated: animated,
                             reduceMotion: shouldReduceMotion)
            applyHoverBounce(to: cell.rightField,
                             hovered: hovered,
                             animated: animated,
                             reduceMotion: shouldReduceMotion)
        }
        guard let dataRow = globalIndex(forTableRow: row) else { return }
        if hovered {
            hoveredDataRow = dataRow
        } else if hoveredDataRow == dataRow {
            hoveredDataRow = nil
        }
    }

    private func setHoveredTableRow(_ row: Int?, animated: Bool) {
        let normalized = (row ?? -1) > 0 ? row : nil
        guard normalized != hoveredTableRow else { return }
        let previous = hoveredTableRow
        hoveredTableRow = normalized

        if let previous {
            applyTableRowHoverState(for: previous, hovered: false, animated: animated, notify: false)
        }
        if let normalized {
            applyTableRowHoverState(for: normalized, hovered: true, animated: animated, notify: false)
        } else {
            hoveredDataRow = nil
        }
    }

    private func handleRowHover(_ row: Int, isHovered: Bool) {
        guard row > 0 else { return }
        guard let dataRow = globalIndex(forTableRow: row) else { return }
        guard dataRow >= 0, dataRow < filtered.count else { return }
        uiLog("row_hover tableRow=\(row) dataRow=\(dataRow) hover=\(isHovered)")
        if isHovered {
            setHoveredTableRow(row, animated: true)
        } else if hoveredTableRow == row {
            setHoveredTableRow(nil, animated: true)
        } else {
            applyTableRowHoverState(for: row, hovered: false, animated: true, notify: false)
        }
    }

    private func leftAttributedAuthorText(for paper: Paper,
                                         rowNumber: Int,
                                         paragraphStyle: NSParagraphStyle,
                                         titleFont: NSFont,
                                         secondaryFont: NSFont,
                                         titleColor: NSColor,
                                         secondaryColor: NSColor) -> NSAttributedString {
        let base = decodeTeXAccents(leftAuthorYearText(paper: paper))

        // Left-align row text: no digit-padding for the row-number prefix.
        let prefix = "\(rowNumber). "

        let result = NSMutableAttributedString(
            string: prefix,
            attributes: [
                .font: secondaryFont,
                .paragraphStyle: paragraphStyle,
                .foregroundColor: secondaryColor
            ]
        )

        result.append(NSAttributedString(
            string: base,
            attributes: [
                .font: titleFont,
                .paragraphStyle: paragraphStyle,
                .foregroundColor: titleColor
            ]
        ))
        return result
    }

    private func leftAttributedKeywordsText(for paper: Paper,
                                           paragraphStyle: NSParagraphStyle,
                                           secondaryFont: NSFont,
                                           secondaryEmphasisFont: NSFont,
                                           secondaryColor: NSColor) -> NSAttributedString? {
        let present = dedupePluralKeywordsForDisplay(
            keywordsPresent(in: paper, keywords: keywordsFromAppleScript)
        )
        guard !present.isEmpty else { return nil }

        let result = NSMutableAttributedString(
            string: "",
            attributes: [
                .font: secondaryFont,
                .paragraphStyle: paragraphStyle,
                .foregroundColor: secondaryColor
            ]
        )

        for (i, kw) in present.enumerated() {
            if i > 0 {
                result.append(NSAttributedString(
                    string: ", ",
                    attributes: [
                        .font: secondaryFont,
                        .paragraphStyle: paragraphStyle,
                        .foregroundColor: secondaryColor
                    ]
                ))
            }
            result.append(NSAttributedString(
                string: kw,
                attributes: [
                    .font: secondaryEmphasisFont,
                    .paragraphStyle: paragraphStyle,
                    .foregroundColor: secondaryColor
                ]
            ))
        }
        return result
    }

    private func leftHeaderTextColor() -> NSColor {
        let color = resolvedForegroundColor(base: windowBackgroundSolidColor(),
                                            tint: leftPanelGlassTintColor(),
                                            role: .primaryText)
        let active = isWindowActiveForAppearance()
        return active ? color : color.withAlphaComponent(max(0.6, color.alphaComponent * 0.85))
    }

    private func rightAuxHeaderTextColor() -> NSColor {
        toolbarSeparatorForegroundColor()
    }

    private func leftRowTextColors(isSelected: Bool, isActive: Bool) -> (title: NSColor, secondary: NSColor) {
        leftTablePanelTextColors(isSelected: isSelected, isActive: isActive)
    }

    // Keep dropdown text (suggestions/menus) in the same contrast resolver as the search bar.
    private func dropdownTextPalette(for background: NSView?,
                                     context: String) -> (primary: NSColor, secondary: NSColor, tertiary: NSColor, effective: NSColor) {
        let base: NSColor = {
            guard let view = background else { return windowBackgroundSolidColor() }
            if view === searchBackground || view.isDescendant(of: leftContainer) {
                return leftPanelEffectiveBackgroundColor()
            }
            if view === rightAuxAskBackground || view.isDescendant(of: rightAuxContainer) {
                return rightAuxEffectiveBackgroundColor()
            }
            return windowBackgroundSolidColor()
        }()
        let tint = embeddedSearchResolvedTint(for: background) ?? panelClearGlassTintColor()
        let effective = embeddedSearchEffectiveBackground(for: background,
                                                          baseOverride: base,
                                                          tintOverride: tint)
        let primary = embeddedSearchForegroundColor(for: background,
                                                    baseOverride: base,
                                                    tintOverride: tint,
                                                    role: .primaryText,
                                                    minContrast: 4.5,
                                                    context: "\(context).primary")
        let secondary = embeddedSearchForegroundColor(for: background,
                                                      baseOverride: base,
                                                      tintOverride: tint,
                                                      role: .secondaryText,
                                                      context: "\(context).secondary")
        let tertiary = embeddedSearchForegroundColor(for: background,
                                                     baseOverride: base,
                                                     tintOverride: tint,
                                                     role: .tertiaryText,
                                                     context: "\(context).tertiary")
        return (primary, secondary, tertiary, effective)
    }

    private func suggestionTextPalette(isSelected: Bool, isActive: Bool) -> (title: NSColor, subtitle: NSColor) {
        let palette = dropdownTextPalette(for: suggestionsBackground, context: "search.suggestions")
        var title = palette.primary
        var subtitle = palette.secondary
        if !isActive {
            title = title.withAlphaComponent(max(0.6, title.alphaComponent * 0.85))
            subtitle = subtitle.withAlphaComponent(max(0.5, subtitle.alphaComponent * 0.85))
        } else if isSelected {
            title = title.withAlphaComponent(min(1.0, title.alphaComponent * 1.02))
            subtitle = subtitle.withAlphaComponent(min(1.0, subtitle.alphaComponent * 1.02))
        }
        let backgrounds = [palette.effective]
        title = ensureMinimumContrast(title, backgrounds: backgrounds, target: foregroundTarget(for: .primaryText, minContrast: 4.5))
        subtitle = ensureMinimumContrast(subtitle, backgrounds: backgrounds, target: foregroundTarget(for: .secondaryText, minContrast: nil))
        return (title, subtitle)
    }

    private func menuTextPalette() -> (primary: NSColor, secondary: NSColor, tertiary: NSColor, effective: NSColor) {
        dropdownTextPalette(for: menuBackground, context: "menu")
    }

	    private func configureLeftCell(_ cell: LeftTwoColumnCellView, row: Int, isSelected: Bool, isActive: Bool) {
	        let pstyle = NSMutableParagraphStyle()
            pstyle.lineBreakMode = (row == 0) ? .byClipping : .byTruncatingTail

	        if row == 0 {
                let headerAttrs = leftAuthorYearHeaderAttributes(paragraphStyle: pstyle)
	            cell.leftField.attributedStringValue = NSAttributedString(string: "Author & Year", attributes: headerAttrs)
	            cell.rightField.attributedStringValue = NSAttributedString(string: "Keyword(s)", attributes: headerAttrs)
	            applyHoverBounce(to: cell.leftField, hovered: false, animated: false, reduceMotion: shouldReduceMotion)
	            applyHoverBounce(to: cell.rightField, hovered: false, animated: false, reduceMotion: shouldReduceMotion)
	            return
	        }

        guard let dataRow = globalIndex(forTableRow: row) else { return }
        let colors = leftRowTextColors(isSelected: isSelected, isActive: isActive)
        let paper = filtered[dataRow]

        cell.leftField.attributedStringValue = leftAttributedAuthorText(
            for: paper,
            rowNumber: dataRow + 1,
            paragraphStyle: pstyle,
            titleFont: leftRowTitleFont,
            secondaryFont: leftRowSecondaryFont,
            titleColor: colors.title,
            secondaryColor: colors.secondary
        )

        if let kwAttr = leftAttributedKeywordsText(
            for: paper,
            paragraphStyle: pstyle,
            secondaryFont: leftRowSecondaryFont,
            secondaryEmphasisFont: leftRowSecondaryEmphasisFont,
            secondaryColor: colors.secondary
        ) {
            cell.rightField.attributedStringValue = kwAttr
        } else {
            cell.rightField.stringValue = ""
        }

        let hovered = (dataRow == hoveredDataRow)
        applyHoverBounce(to: cell.leftField, hovered: hovered, animated: false, reduceMotion: shouldReduceMotion)
        applyHoverBounce(to: cell.rightField, hovered: hovered, animated: false, reduceMotion: shouldReduceMotion)
    }

    private func configureSuggestionCell(_ cell: NSTableCellView, row: Int) {
        guard row >= 0, row < suggestions.count else { return }
        let suggestion = suggestions[row]
        let selected = suggestionsTable.selectedRow == row
        let active = isWindowActiveForAppearance()
        let palette = suggestionTextPalette(isSelected: selected, isActive: active)
        let titleColor = palette.title
        let subtitleColor = palette.subtitle

        cell.textField?.stringValue = suggestion.title
        cell.textField?.textColor = titleColor
        let hovered = hoveredSuggestionRow == row
        let reduce = shouldReduceMotion
        applyHoverBounce(to: cell.textField, hovered: hovered, animated: false, reduceMotion: reduce)
        if let subtitle = cell.viewWithTag(2) as? NSTextField {
            subtitle.stringValue = suggestion.subtitle
            subtitle.textColor = subtitleColor
            applyHoverBounce(to: subtitle, hovered: hovered, animated: false, reduceMotion: reduce)
        }
    }

    private func menuTextColor(for item: MenuItem, isActive: Bool) -> NSColor {
        let palette = menuTextPalette()
        let primary = palette.primary
        let secondary = palette.secondary
        let tertiary = palette.tertiary

        if item.kind == .summary {
            if item.isEnabled {
                return isActive ? primary : primary.withAlphaComponent(max(0.6, primary.alphaComponent * 0.85))
            }
            return isActive ? secondary : secondary.withAlphaComponent(max(0.5, secondary.alphaComponent * 0.85))
        }
        if !item.isEnabled {
            return tertiary
        }
        return isActive ? primary : primary.withAlphaComponent(max(0.6, primary.alphaComponent * 0.85))
    }

    private func menuSwatchImage(for color: NSColor) -> NSImage {
        let appearanceKey = AppearanceManager.shared.snapshot().nsAppearanceName.rawValue
        let key = "\(appearanceKey)|\(hexFromColor(color, includeAlpha: true))"
        if let cached = menuSwatchCache[key] {
            return cached
        }

        let size = CGSize(width: menuCheckmarkSize, height: menuCheckmarkSize)
        let image = NSImage(size: size)
        image.isTemplate = false
        image.lockFocus()

        let rect = NSRect(origin: .zero, size: size).insetBy(dx: 0.5, dy: 0.5)
        let radius = max(2, menuCheckmarkSize * 0.25)
        let path = NSBezierPath(roundedRect: rect, xRadius: radius, yRadius: radius)
        let fill = (color.usingColorSpace(.deviceRGB) ?? color).withAlphaComponent(1.0)
        fill.setFill()
        path.fill()
        resolvedSystemColor(.separatorColor).withAlphaComponent(0.5).setStroke()
        path.lineWidth = 1
        path.stroke()

        image.unlockFocus()
        menuSwatchCache[key] = image
        return image
    }

    private func configureMenuCell(_ cell: NSTableCellView, row: Int) {
        guard row >= 0, row < menuItems.count else { return }
        let item = menuItems[row]
        let active = isWindowActiveForAppearance()
        let textColor = menuTextColor(for: item, isActive: active)

        cell.textField?.stringValue = item.title
        cell.textField?.font = (item.kind == .summary) ? menuSummaryFont : menuFont
        cell.textField?.textColor = textColor

        if let check = cell.imageView {
            if let swatchColor = item.swatchColor {
                check.image = menuSwatchImage(for: swatchColor)
                check.contentTintColor = nil
                check.isHidden = false
                check.alphaValue = 1.0
            } else {
                check.image = menuCheckmarkImage
                check.contentTintColor = textColor
                check.isHidden = !item.isChecked
                check.alphaValue = item.isChecked ? (item.kind == .summary ? 0.72 : 0.90) : 0.0
            }
        }

        let selected = menuTable.selectedRowIndexes.contains(row)
        let hovered = hoveredMenuRow == row
        applyHoverBounce(to: cell.textField,
                         hovered: selected || hovered,
                         animated: false,
                         reduceMotion: shouldReduceMotion)
    }

    private func menuSeparatorColor() -> NSColor {
        let dark = window?.effectiveAppearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        let alpha: CGFloat = dark ? 0.28 : 0.20
        return resolvedSystemColor(.separatorColor).withAlphaComponent(alpha)
    }

    private func configureMenuSeparator(_ view: MenuSeparatorView) {
        view.lineInsets = NSEdgeInsets(top: 0, left: menuTextLeading, bottom: 0, right: menuTextTrailing)
        view.colorProvider = { [weak self] in
            self?.menuSeparatorColor() ?? resolvedSystemColor(.separatorColor).withAlphaComponent(0.2)
        }
    }

    private func menuPreferredWidth(for items: [MenuItem], anchorWidth: CGFloat) -> CGFloat {
        var maxTextWidth: CGFloat = 0
        for item in items where item.kind != .separator {
            let font = (item.kind == .summary) ? menuSummaryFont : menuFont
            let w = (item.title as NSString).size(withAttributes: [.font: font]).width
            if w > maxTextWidth { maxTextWidth = w }
        }
        let horizontalInset = menuContentInsets.left + menuContentInsets.right
        let contentWidth = menuTextLeading + maxTextWidth + menuTextTrailing + horizontalInset
        let base = max(menuMinWidth, anchorWidth + 40 + horizontalInset)
        return max(base, ceil(contentWidth))
    }

    private func configureSuggestionRowView(_ rowView: NSTableRowView, row: Int) {
        if let glass = rowView as? GlassMenuRowView {
            glass.isActiveWindowProvider = { [weak self] in self?.isWindowActiveForAppearance() ?? true }
            glass.rowIndex = row
            glass.hoverChanged = { [weak self] rowIndex, isHovered in
                self?.handleSuggestionHover(rowIndex, isHovered: isHovered)
            }
            let shouldHover = (hoveredSuggestionRow == row)
            glass.setHoverState(shouldHover, animated: false, notify: false)
        }
        if let cell = rowView.view(atColumn: 0) as? NSTableCellView {
            configureSuggestionCell(cell, row: row)
        }
    }

    private func configureMenuRowView(_ rowView: NSTableRowView, row: Int) {
        if let glass = rowView as? GlassMenuRowView {
            glass.isActiveWindowProvider = { [weak self] in self?.isWindowActiveForAppearance() ?? true }
            glass.outlineOnly = true
            glass.rowIndex = row
            glass.hoverChanged = { [weak self] rowIndex, isHovered in
                self?.handleMenuHover(rowIndex, isHovered: isHovered)
            }
            if row >= 0, row < menuItems.count {
                glass.isInteractive = menuItems[row].isSelectable
            }
            let shouldHover = (hoveredMenuRow == row)
            glass.setHoverState(shouldHover, animated: false, notify: false)
        }
        if let cell = rowView.view(atColumn: 0) as? NSTableCellView,
           cell.textField != nil {
            configureMenuCell(cell, row: row)
        }
    }

    private func clearSuggestionHover(animated: Bool) {
        hoveredSuggestionRow = nil
        let visible = suggestionsTable.rows(in: suggestionsTable.visibleRect)
        guard visible.length > 0 else { return }
        for row in visible.location..<(visible.location + visible.length) {
            guard let rowView = suggestionsTable.rowView(atRow: row, makeIfNecessary: false) as? GlassMenuRowView else { continue }
            rowView.setHoverState(false, animated: animated, notify: false)
        }
    }

    private func refreshSuggestionTextColors() {
        let visible = suggestionsTable.rows(in: suggestionsTable.visibleRect)
        guard visible.length > 0 else { return }
        for row in visible.location..<(visible.location + visible.length) {
            if let cell = suggestionsTable.view(atColumn: 0, row: row, makeIfNecessary: false) as? NSTableCellView {
                configureSuggestionCell(cell, row: row)
            }
        }
    }

    private func syncSuggestionHoverFromMouse(animated: Bool) {
        guard suggestionsVisible, let window = suggestionsTable.window else {
            hoveredSuggestionRow = nil
            return
        }
        let mouseInWindow = window.mouseLocationOutsideOfEventStream
        let mouseInTable = suggestionsTable.convert(mouseInWindow, from: nil)
        let row = suggestionsTable.row(at: mouseInTable)
        let hoverRow = (row >= 0 && row < suggestions.count) ? row : nil
        hoveredSuggestionRow = hoverRow

        let visible = suggestionsTable.rows(in: suggestionsTable.visibleRect)
        guard visible.length > 0 else { return }
        for r in visible.location..<(visible.location + visible.length) {
            guard let rowView = suggestionsTable.rowView(atRow: r, makeIfNecessary: true) as? GlassMenuRowView else { continue }
            rowView.setHoverState(r == row, animated: animated, notify: false)
        }
    }

    private func refreshMenuTextColors() {
        guard !menuContainer.isHidden else { return }
        let visible = menuTable.rows(in: menuTable.visibleRect)
        guard visible.length > 0 else { return }
        for row in visible.location..<(visible.location + visible.length) {
            guard row >= 0, row < menuItems.count else { continue }
            if menuItems[row].kind == .separator { continue }
            if let cell = menuTable.view(atColumn: 0, row: row, makeIfNecessary: false) as? NSTableCellView {
                configureMenuCell(cell, row: row)
            }
        }
    }

    private func refreshMenuTextBounce(animated: Bool) {
        let visible = menuTable.rows(in: menuTable.visibleRect)
        guard visible.length > 0 else { return }
        for row in visible.location..<(visible.location + visible.length) {
            guard row >= 0, row < menuItems.count else { continue }
            if menuItems[row].kind == .separator { continue }
            if let cell = menuTable.view(atColumn: 0, row: row, makeIfNecessary: false) as? NSTableCellView {
                let selected = menuTable.selectedRowIndexes.contains(row)
                let hovered = hoveredMenuRow == row
                applyHoverBounce(to: cell.textField,
                                 hovered: selected || hovered,
                                 animated: animated,
                                 reduceMotion: shouldReduceMotion)
            }
        }
    }

    private func applyPayload(_ payload: Payload) {
        listRenderStartTime = monotonicNow()
        listRenderLogged = false
        currentPageIndex = 0
        publicationStore.setAll(payload.papers)
        publicationStore.setFiltered(payload.papers)
        self.keywordsFromAppleScript = payload.keywords
        invalidateSidebarPageContentWidthCache()
        self.recipientNameFromAppleScript = payload.recipientName
        self.recipientEmailFromAppleScript = payload.recipientEmail
        searchIndex.rebuild(from: payload.papers)
        let abstracts = payload.papers.map { $0.abstractText }
        #if DEBUG
        let topicInference = updateAutoHTMLThemeSelection(from: abstracts)
        logTopicInference(topicInference)
        #else
        _ = updateAutoHTMLThemeSelection(from: abstracts)
        #endif
        selectionHistory.removeAll()
        selectionHistoryIndex = -1
        updateNavigationButtons()

        let earlyHotCount = min(12, filtered.count)
        if earlyHotCount > 0 {
            let earlyRequests = filtered.prefix(earlyHotCount).compactMap { prefetchRequest(for: $0) }
            pdfCache.prefetch(earlyRequests, priority: 2, reason: "payload-load/early-top")
        }
        prefetchAllPapers(reason: "payload-load/all")
        prunePDFCache(for: payload.papers)

        rebuildLeftColumnMetrics()

        // Preserve initial-launch sizing behavior, but once rows exist, size the sidebar to the
        // publications table's max internal scroll width.
        didAdoptTableDrivenSidebarWidth = !payload.papers.isEmpty

        hideLoading()

        layoutLeftContainerSubviews()
        layoutRightPanelSubviews()
        reflowLeft()

        // IMPORTANT: When launched in wait-for-file mode, the payload can arrive before
        // the split view / table have fully finalized their first layout pass. In that state,
        // the keyword column can be computed with a near-zero width and remain visually empty
        // until a later user interaction forces another layout (e.g. toggling the sidebar).
        // Schedule a one-shot post-layout reflow to make keyword rendering deterministic.
        payloadPostLayoutReflowWorkItem?.cancel()
        let work = DispatchWorkItem { [weak self] in
            guard let self else { return }
            self.layoutLeftContainerSubviews()
            self.reflowLeft()
        }
        payloadPostLayoutReflowWorkItem = work
        DispatchQueue.main.async(execute: work)
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.08) { [weak self] in
            guard let self else { return }
            // A second tick helps when split-view frames settle one runloop later.
            self.layoutLeftContainerSubviews()
            self.reflowLeft()
        }

        if !filtered.isEmpty {
            selectFilteredIndex(0, scroll: true, reason: "payload-first")
            updateDetails()
        }
    }
}




// MARK: - Zotero Integration (auth + API)

private func resolvedZoteroAPIKey() -> String? {
    if let cached = ZOTERO_API_KEY_CACHE, !cached.isEmpty {
        logZoteroAPIKeyDiagnostics(context: "cache", key: cached)
        return cached
    }
    if let key = ZoteroKeychain.readAPIKey(), !key.isEmpty {
        logZoteroAPIKeyDiagnostics(context: "keychain", key: key)
        return key
    }
    return nil
}

private func cacheZoteroAPIKey(_ key: String?) {
    guard let key, !key.isEmpty else {
        ZOTERO_API_KEY_CACHE = nil
        return
    }
    ZOTERO_API_KEY_CACHE = key
}

private func persistZoteroAPIKey(_ key: String) {
    let trimmed = key.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty else { return }
    _ = ZoteroKeychain.saveAPIKey(trimmed)
    cacheZoteroAPIKey(trimmed)
}

private struct ZoteroAPIKeyDiagnostics {
    let characterCount: Int
    let scalarCount: Int
    let utf8Count: Int
    let leadingWhitespace: Bool
    let trailingWhitespace: Bool
    let whitespaceCount: Int
    let newlineCount: Int
    let controlCount: Int
    let zeroWidthCount: Int
    let nonASCII: [String]
    let confusables: [String]
    let fingerprint: String
}

private struct ZoteroAPIKeyCandidate {
    let key: String
    let mode: ZoteroAPIKeyRequestMode
}

private func zoteroAPIKeyNeedsNormalization(_ diagnostics: ZoteroAPIKeyDiagnostics) -> Bool {
    if !diagnostics.nonASCII.isEmpty { return true }
    if diagnostics.whitespaceCount > 0 { return true }
    if diagnostics.controlCount > 0 { return true }
    if diagnostics.zeroWidthCount > 0 { return true }
    return false
}

private enum ZoteroAPIKeyRequestMode: String {
    case raw = "raw"
    case normalizedExplicit = "normalized_explicit"
    case normalizedAuto = "normalized_auto"
}

private func zoteroAPIKeyRequestMode(for diagnostics: ZoteroAPIKeyDiagnostics) -> ZoteroAPIKeyRequestMode {
    let settings = AppSettingsStore.shared.current
    if settings.zotero.useNormalizedKeyForRequests {
        return .normalizedExplicit
    }
    return zoteroAPIKeyNeedsNormalization(diagnostics) ? .normalizedAuto : .raw
}

private let zoteroAPIKeyConfusableScalars: Set<UnicodeScalar> = [
    "\u{0410}", "\u{0430}", // Cyrillic A/a
    "\u{0412}", "\u{0432}", // Cyrillic Ve
    "\u{0415}", "\u{0435}", // Cyrillic Ie
    "\u{041A}", "\u{043A}", // Cyrillic Ka
    "\u{041C}", "\u{043C}", // Cyrillic Em
    "\u{041D}", "\u{043D}", // Cyrillic En
    "\u{041E}", "\u{043E}", // Cyrillic O
    "\u{0420}", "\u{0440}", // Cyrillic Er
    "\u{0421}", "\u{0441}", // Cyrillic Es
    "\u{0422}", "\u{0442}", // Cyrillic Te
    "\u{0425}", "\u{0445}", // Cyrillic Ha
    "\u{0423}", "\u{0443}"  // Cyrillic U
]

private let zoteroAPIKeyZeroWidthScalars: Set<UnicodeScalar> = [
    "\u{200B}", // zero width space
    "\u{200C}", // zero width non-joiner
    "\u{200D}", // zero width joiner
    "\u{2060}", // word joiner
    "\u{FEFF}"  // zero width no-break space / BOM
]

private let zoteroAPIKeyConfusableMap: [UnicodeScalar: String] = [
    "\u{0410}": "A", "\u{0430}": "a", // Cyrillic A/a
    "\u{0412}": "B", "\u{0432}": "b", // Cyrillic Ve
    "\u{0415}": "E", "\u{0435}": "e", // Cyrillic Ie
    "\u{041A}": "K", "\u{043A}": "k", // Cyrillic Ka
    "\u{041C}": "M", "\u{043C}": "m", // Cyrillic Em
    "\u{041D}": "H", "\u{043D}": "h", // Cyrillic En
    "\u{041E}": "O", "\u{043E}": "o", // Cyrillic O
    "\u{0420}": "P", "\u{0440}": "p", // Cyrillic Er
    "\u{0421}": "C", "\u{0441}": "c", // Cyrillic Es
    "\u{0422}": "T", "\u{0442}": "t", // Cyrillic Te
    "\u{0425}": "X", "\u{0445}": "x", // Cyrillic Ha
    "\u{0423}": "Y", "\u{0443}": "y"  // Cyrillic U
]

private func zoteroAPIKeyFingerprint(_ key: String) -> String {
    let digest = SHA256.hash(data: Data(key.utf8))
    let hex = digest.map { String(format: "%02x", $0) }.joined()
    return String(hex.prefix(12))
}

private func zoteroMaskedKey(_ key: String) -> String {
    let chars = Array(key)
    guard chars.count > 6 else { return key }
    let prefix = String(chars.prefix(3))
    let suffix = String(chars.suffix(3))
    return "\(prefix)...\(suffix)"
}

private func makeZoteroAPIKeyDiagnostics(_ key: String) -> ZoteroAPIKeyDiagnostics {
    let scalars = Array(key.unicodeScalars)
    var whitespaceCount = 0
    var newlineCount = 0
    var controlCount = 0
    var zeroWidthCount = 0
    var nonASCII: [String] = []
    var confusables: [String] = []

    for (idx, scalar) in scalars.enumerated() {
        if CharacterSet.whitespacesAndNewlines.contains(scalar) {
            whitespaceCount += 1
        }
        if scalar == "\n" || scalar == "\r" {
            newlineCount += 1
        }
        if scalar.value < 0x20 || scalar.value == 0x7F {
            controlCount += 1
        }
        if zoteroAPIKeyZeroWidthScalars.contains(scalar) {
            zeroWidthCount += 1
        }
        if scalar.value > 0x7F {
            nonASCII.append(String(format: "U+%04X@%d", scalar.value, idx))
        }
        if zoteroAPIKeyConfusableScalars.contains(scalar) {
            confusables.append(String(format: "U+%04X@%d", scalar.value, idx))
        }
    }

    let leadingWhitespace = scalars.first.map { CharacterSet.whitespacesAndNewlines.contains($0) } ?? false
    let trailingWhitespace = scalars.last.map { CharacterSet.whitespacesAndNewlines.contains($0) } ?? false

    return ZoteroAPIKeyDiagnostics(
        characterCount: key.count,
        scalarCount: scalars.count,
        utf8Count: key.utf8.count,
        leadingWhitespace: leadingWhitespace,
        trailingWhitespace: trailingWhitespace,
        whitespaceCount: whitespaceCount,
        newlineCount: newlineCount,
        controlCount: controlCount,
        zeroWidthCount: zeroWidthCount,
        nonASCII: nonASCII,
        confusables: confusables,
        fingerprint: zoteroAPIKeyFingerprint(key)
    )
}

private struct ZoteroAPIKeyNormalizationResult {
    let key: String
    let changes: [String]
}

private func normalizeZoteroAPIKeyForRequest(_ raw: String) -> ZoteroAPIKeyNormalizationResult {
    var changes: [String] = []
    var removedWhitespace = 0
    var removedControl = 0
    var removedZeroWidth = 0

    var strippedScalars: [UnicodeScalar] = []
    strippedScalars.reserveCapacity(raw.unicodeScalars.count)
    for scalar in raw.unicodeScalars {
        if CharacterSet.whitespacesAndNewlines.contains(scalar) {
            removedWhitespace += 1
            continue
        }
        if scalar.value < 0x20 || scalar.value == 0x7F {
            removedControl += 1
            continue
        }
        if zoteroAPIKeyZeroWidthScalars.contains(scalar) {
            removedZeroWidth += 1
            continue
        }
        strippedScalars.append(scalar)
    }

    if removedWhitespace > 0 { changes.append("removed_whitespace=\(removedWhitespace)") }
    if removedControl > 0 { changes.append("removed_control=\(removedControl)") }
    if removedZeroWidth > 0 { changes.append("removed_zero_width=\(removedZeroWidth)") }

    var mappedConfusables = 0
    var normalized = ""
    normalized.reserveCapacity(strippedScalars.count)
    for scalar in strippedScalars {
        if let mapped = zoteroAPIKeyConfusableMap[scalar] {
            normalized.append(mapped)
            mappedConfusables += 1
        } else {
            normalized.append(String(scalar))
        }
    }
    if mappedConfusables > 0 { changes.append("mapped_confusables=\(mappedConfusables)") }

    return ZoteroAPIKeyNormalizationResult(key: normalized, changes: changes)
}

private func zoteroRequestAPIKey(from raw: String, context: String? = nil) -> String {
    let diagnostics = makeZoteroAPIKeyDiagnostics(raw)
    let mode = zoteroAPIKeyRequestMode(for: diagnostics)
    guard mode != .raw else { return raw }
    let result = normalizeZoteroAPIKeyForRequest(raw)
    if ZoteroKeyDiagnosticsLog.isEnabled, result.key != raw {
        let ctx = context ?? "request"
        logZoteroAPIKeyDiagnostics(context: "\(ctx)_raw", key: raw)
        logZoteroAPIKeyDiagnostics(context: "\(ctx)_normalized", key: result.key)
        ZoteroKeyDiagnosticsLog.info("zotero_key[\(ctx)_mode] \(mode.rawValue)")
        if !result.changes.isEmpty {
            ZoteroKeyDiagnosticsLog.info("zotero_key[\(ctx)_changes] \(result.changes.joined(separator: ","))")
        }
    }
    return result.key
}

private func zoteroRequestKeyCandidates(for raw: String) -> [ZoteroAPIKeyCandidate] {
    let diagnostics = makeZoteroAPIKeyDiagnostics(raw)
    let mode = zoteroAPIKeyRequestMode(for: diagnostics)
    let normalized = normalizeZoteroAPIKeyForRequest(raw).key
    if normalized == raw {
        return [ZoteroAPIKeyCandidate(key: raw, mode: .raw)]
    }

    var candidates: [ZoteroAPIKeyCandidate] = []
    let appendUnique: (ZoteroAPIKeyCandidate) -> Void = { candidate in
        guard candidates.contains(where: { $0.key == candidate.key }) == false else { return }
        candidates.append(candidate)
    }

    switch mode {
    case .normalizedExplicit:
        appendUnique(ZoteroAPIKeyCandidate(key: normalized, mode: .normalizedExplicit))
        appendUnique(ZoteroAPIKeyCandidate(key: raw, mode: .raw))
    case .normalizedAuto:
        appendUnique(ZoteroAPIKeyCandidate(key: raw, mode: .raw))
        appendUnique(ZoteroAPIKeyCandidate(key: normalized, mode: .normalizedAuto))
    case .raw:
        appendUnique(ZoteroAPIKeyCandidate(key: raw, mode: .raw))
    }
    return candidates
}

private func zoteroShouldRetryWithAlternateKey(_ error: Error) -> Bool {
    guard let apiError = error as? ZoteroAPIError else { return false }
    if apiError.statusCode == 401 || apiError.statusCode == 403 {
        return true
    }
    return apiError.message.localizedCaseInsensitiveContains("invalid key")
}

private func fetchZoteroKeyInfoWithFallback(rawKey: String,
                                            userIDHint: String?,
                                            context: String,
                                            completion: @escaping (Result<(apiKey: String, info: ZoteroKeyInfo, mode: ZoteroAPIKeyRequestMode), Error>) -> Void) {
    let candidates = zoteroRequestKeyCandidates(for: rawKey)
    guard candidates.isEmpty == false else {
        completion(.failure(ZoteroAPIError(message: "Missing API key.", statusCode: nil)))
        return
    }

    func attempt(_ index: Int) {
        let candidate = candidates[index]
        logZoteroAPIKeyDiagnostics(context: "\(context)_try_\(candidate.mode.rawValue)", key: candidate.key)
        ZoteroAPIClient.fetchKeyInfo(apiKey: candidate.key, userIDHint: userIDHint) { result in
            switch result {
            case .success(let info):
                completion(.success((apiKey: candidate.key, info: info, mode: candidate.mode)))
            case .failure(let error):
                if index + 1 < candidates.count, zoteroShouldRetryWithAlternateKey(error) {
                    attempt(index + 1)
                } else {
                    completion(.failure(error))
                }
            }
        }
    }

    attempt(0)
}

private func resolvedZoteroAPIKeyForRequest(context: String? = nil) -> String? {
    guard let raw = resolvedZoteroAPIKey() else { return nil }
    return zoteroRequestAPIKey(from: raw, context: context)
}

private func zoteroAPIKeyDiagnosticsSummary(_ diag: ZoteroAPIKeyDiagnostics) -> String {
    let nonASCII = diag.nonASCII.isEmpty ? "none" : diag.nonASCII.joined(separator: ", ")
    let confusables = diag.confusables.isEmpty ? "none" : diag.confusables.joined(separator: ", ")
    let normalizationPref = AppSettingsStore.shared.current.zotero.useNormalizedKeyForRequests ? "enabled" : "disabled"
    let mode = zoteroAPIKeyRequestMode(for: diag).rawValue
    return """
length(chars)=\(diag.characterCount) scalars=\(diag.scalarCount) utf8_bytes=\(diag.utf8Count)
leading_ws=\(diag.leadingWhitespace) trailing_ws=\(diag.trailingWhitespace)
whitespace=\(diag.whitespaceCount) newlines=\(diag.newlineCount) control=\(diag.controlCount) zero_width=\(diag.zeroWidthCount)
non_ascii=[\(nonASCII)]
confusables=[\(confusables)]
fingerprint=\(diag.fingerprint)
request_normalization_pref=\(normalizationPref)
request_key_mode=\(mode)
"""
}

private func zoteroAPIKeyVisualized(_ key: String) -> String {
    var out = ""
    out.reserveCapacity(key.count)
    for scalar in key.unicodeScalars {
        switch scalar {
        case " ":
            out.append("<SP>")
        case "\t":
            out.append("<TAB>")
        case "\n":
            out.append("<LF>")
        case "\r":
            out.append("<CR>")
        default:
            if zoteroAPIKeyZeroWidthScalars.contains(scalar) {
                out.append(String(format: "<ZW U+%04X>", scalar.value))
            } else if scalar.value < 0x20 || scalar.value == 0x7F {
                out.append(String(format: "<CTRL U+%04X>", scalar.value))
            } else if scalar.value > 0x7F {
                out.append(String(format: "<U+%04X>", scalar.value))
            } else {
                out.append(String(scalar))
            }
        }
    }
    return out
}

private enum ZoteroKeyDiagnosticsLog {
    static var isEnabled: Bool {
        ProcessInfo.processInfo.environment["ARXIV_ZOTERO_KEY_DEBUG"] == "1"
    }

    private static let log = OSLog(subsystem: APP_LOG_SUBSYSTEM, category: "zotero.key")

    static func info(_ message: String) {
        guard isEnabled else { return }
        os_log("%{public}@", log: log, type: .info, message)
    }
}

private func logZoteroAPIKeyDiagnostics(context: String, key: String) {
    guard ZoteroKeyDiagnosticsLog.isEnabled else { return }
    let diag = makeZoteroAPIKeyDiagnostics(key)
    let nonASCII = diag.nonASCII.isEmpty ? "none" : diag.nonASCII.joined(separator: ",")
    let confusables = diag.confusables.isEmpty ? "none" : diag.confusables.joined(separator: ",")
    let msg = "zotero_key[\(context)] len=\(diag.characterCount) scalars=\(diag.scalarCount) utf8=\(diag.utf8Count) leading_ws=\(diag.leadingWhitespace) trailing_ws=\(diag.trailingWhitespace) whitespace=\(diag.whitespaceCount) newlines=\(diag.newlineCount) control=\(diag.controlCount) zero_width=\(diag.zeroWidthCount) non_ascii=\(nonASCII) confusables=\(confusables) fp=\(diag.fingerprint)"
    ZoteroKeyDiagnosticsLog.info(msg)
}

private struct ZoteroKeyInfo: Equatable {
    let userID: String
    let username: String
    let userFilesAccess: Bool?
    let groupFilesAccess: [String: Bool]
}

private struct ZoteroAuthSession {
    let apiKey: String
    let info: ZoteroKeyInfo
    let gateToken: Int
}

private struct ZoteroLibrary: Equatable {
    let type: AppSettings.Zotero.LibraryType
    let id: String
    let name: String
}

private extension ZoteroKeyInfo {
    func fileAccess(for library: ZoteroLibrary) -> Bool? {
        switch library.type {
        case .user:
            return userFilesAccess
        case .group:
            return groupFilesAccess[library.id]
        }
    }
}

private struct ZoteroCollection: Equatable {
    let key: String
    let name: String
    let parentKey: String?
}

private struct ZoteroItem {
    let key: String
    let version: Int?
    let data: [String: Any]
}

private struct ZoteroSavedItemRecord: Codable, Equatable {
    let stableID: String
    let libraryType: AppSettings.Zotero.LibraryType
    let libraryID: String
    let itemKey: String
}

private final class ZoteroSavedItemStore {
    static let shared = ZoteroSavedItemStore()

    private struct Persistence {
        static let defaultsKey = "astroStack.zotero.savedItems.v1"
    }

    private let lock = NSLock()
    private var cache: [String: ZoteroSavedItemRecord] = [:]
    private var loaded = false

    private init() {}

    func record(for stableID: String) -> ZoteroSavedItemRecord? {
        lock.lock()
        defer { lock.unlock() }
        ensureLoadedLocked()
        return cache[stableID]
    }

    func upsert(_ record: ZoteroSavedItemRecord) {
        lock.lock()
        ensureLoadedLocked()
        cache[record.stableID] = record
        persistLocked()
        lock.unlock()
    }

    func remove(stableID: String) {
        lock.lock()
        ensureLoadedLocked()
        cache.removeValue(forKey: stableID)
        persistLocked()
        lock.unlock()
    }

    private func ensureLoadedLocked() {
        guard !loaded else { return }
        defer { loaded = true }
        guard let data = UserDefaults.standard.data(forKey: Persistence.defaultsKey) else { return }
        guard let decoded = try? JSONDecoder().decode([String: ZoteroSavedItemRecord].self, from: data) else { return }
        cache = decoded
    }

    private func persistLocked() {
        do {
            let data = try JSONEncoder().encode(cache)
            UserDefaults.standard.set(data, forKey: Persistence.defaultsKey)
        } catch {
            // Non-fatal; keep in-memory copy.
        }
    }
}

private enum ZoteroKeychain {
    private static let service = "AstroStack.Zotero"
    private static let account = "apiKey"

    static func readAPIKey() -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: kCFBooleanTrue as Any,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess, let data = item as? Data else { return nil }
        let key = String(data: data, encoding: .utf8)
        if let key {
            logZoteroAPIKeyDiagnostics(context: "keychain_read", key: key)
        }
        return key
    }

    @discardableResult
    static func saveAPIKey(_ key: String) -> Bool {
        _ = deleteAPIKey()
        logZoteroAPIKeyDiagnostics(context: "keychain_save", key: key)
        guard let data = key.data(using: .utf8) else { return false }
        let attrs: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlock
        ]
        let status = SecItemAdd(attrs as CFDictionary, nil)
        return status == errSecSuccess
    }

    @discardableResult
    static func deleteAPIKey() -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess || status == errSecItemNotFound
    }
}

private struct ZoteroAPIError: LocalizedError {
    let message: String
    let statusCode: Int?

    var errorDescription: String? { message }
}

private enum ZoteroActionError: LocalizedError {
    case cancelled

    var errorDescription: String? { "Cancelled" }
}

private enum ZoteroAPIClient {
    private static let apiVersion = "3"
    private static let baseURL = URL(string: "https://api.zotero.org/")!
    private static let session: URLSession = {
        let config = URLSessionConfiguration.ephemeral
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        return URLSession(configuration: config)
    }()

    private static func makeURL(path: String, queryItems: [URLQueryItem]? = nil) -> URL? {
        guard var comps = URLComponents(url: baseURL.appendingPathComponent(path), resolvingAgainstBaseURL: false) else {
            return nil
        }
        comps.queryItems = queryItems
        return comps.url
    }

    private static func request(_ method: String,
                                url: URL,
                                apiKey: String?,
                                body: Data? = nil,
                                contentType: String? = nil,
                                extraHeaders: [String: String] = [:],
                                completion: @escaping (Result<(Data, HTTPURLResponse), Error>) -> Void) {
        let candidates = apiKey.map { zoteroRequestKeyCandidates(for: $0) } ?? []
        let keyCandidates = candidates.isEmpty ? [ZoteroAPIKeyCandidate(key: "", mode: .raw)] : candidates

        func attempt(_ index: Int) {
            var request = URLRequest(url: url)
            request.httpMethod = method
            request.httpBody = body
            request.setValue("AstroStack", forHTTPHeaderField: "User-Agent")
            request.setValue(apiVersion, forHTTPHeaderField: "Zotero-API-Version")
            if let apiKey {
                let candidate = keyCandidates[index]
                logZoteroAPIKeyDiagnostics(context: "http_request", key: candidate.key)
                request.setValue(candidate.key, forHTTPHeaderField: "Zotero-API-Key")
            }
            if let contentType {
                request.setValue(contentType, forHTTPHeaderField: "Content-Type")
            }
            for (k, v) in extraHeaders {
                request.setValue(v, forHTTPHeaderField: k)
            }

            let task = session.dataTask(with: request) { data, response, error in
                if let error {
                    completion(.failure(error))
                    return
                }
                guard let http = response as? HTTPURLResponse else {
                    completion(.failure(ZoteroAPIError(message: "Invalid Zotero response.", statusCode: nil)))
                    return
                }
                let payload = data ?? Data()
                guard (200...299).contains(http.statusCode) else {
                    let msg = errorMessage(from: payload, status: http.statusCode)
                    let apiError = ZoteroAPIError(message: msg, statusCode: http.statusCode)
                    if index + 1 < keyCandidates.count, zoteroShouldRetryWithAlternateKey(apiError) {
                        attempt(index + 1)
                        return
                    }
                    completion(.failure(apiError))
                    return
                }
                completion(.success((payload, http)))
            }
            task.resume()
        }

        attempt(0)
    }

    private static func errorMessage(from data: Data, status: Int) -> String {
        let text = String(data: data, encoding: .utf8)?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if text.isEmpty {
            return "Zotero API request failed with status \(status)."
        }
        return "Zotero API error (\(status)): \(text)"
    }

    private static func parseJSON(_ data: Data) -> Any? {
        (try? JSONSerialization.jsonObject(with: data)) ?? nil
    }

    private static func parseFileAccess(_ obj: [String: Any]) -> (userFiles: Bool?, groupFiles: [String: Bool]) {
        let access = obj["access"] as? [String: Any]
        let userAccess = access?["user"] as? [String: Any]
        let userFiles = userAccess?["files"] as? Bool
        var groupFiles: [String: Bool] = [:]
        if let groups = access?["groups"] as? [String: Any] {
            for (groupID, value) in groups {
                if let dict = value as? [String: Any], let files = dict["files"] as? Bool {
                    groupFiles[groupID] = files
                } else if let files = value as? Bool {
                    groupFiles[groupID] = files
                }
            }
        }
        return (userFiles, groupFiles)
    }

    private static func libraryPath(_ library: ZoteroLibrary) -> String {
        switch library.type {
        case .user:
            return "users/\(library.id)"
        case .group:
            return "groups/\(library.id)"
        }
    }

    static func fetchKeyInfo(apiKey: String,
                             userIDHint: String?,
                             completion: @escaping (Result<ZoteroKeyInfo, Error>) -> Void) {
        guard let url = makeURL(path: "keys/current") else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero key URL.", statusCode: nil)))
            return
        }
        request("GET", url: url, apiKey: apiKey) { result in
            switch result {
            case .success(let (data, _)):
                guard let obj = parseJSON(data) as? [String: Any] else {
                    completion(.failure(ZoteroAPIError(message: "Unexpected Zotero key response.", statusCode: nil)))
                    return
                }
                let access = obj["access"] as? [String: Any]
                let userAccess = access?["user"] as? [String: Any]
                let groupAccess = access?["groups"] as? [String: Any]
                let libraryAccess = userAccess?["library"] as? Bool ?? true
                let writeAccess = userAccess?["write"] as? Bool ?? true
                let hasGroupAccess = (groupAccess?.isEmpty == false)
                if !((libraryAccess && writeAccess) || hasGroupAccess) {
                    completion(.failure(ZoteroAPIError(message: "API key does not allow write access to the Zotero library.", statusCode: nil)))
                    return
                }
                let userID = (obj["userID"] as? NSNumber)?.stringValue
                    ?? (obj["userID"] as? String)
                    ?? userIDHint
                    ?? ""
                let username = (obj["username"] as? String) ?? ""
                if userID.isEmpty {
                    completion(.failure(ZoteroAPIError(message: "Could not determine Zotero user ID. Please enter it manually.", statusCode: nil)))
                    return
                }
                let fileAccess = parseFileAccess(obj)
                completion(.success(ZoteroKeyInfo(userID: userID,
                                                  username: username,
                                                  userFilesAccess: fileAccess.userFiles,
                                                  groupFilesAccess: fileAccess.groupFiles)))
            case .failure(let error):
                fetchKeyInfoFromKeyEndpoint(apiKey: apiKey, userIDHint: userIDHint) { fallback in
                    switch fallback {
                    case .success(let info):
                        completion(.success(info))
                    case .failure:
                        completion(.failure(error))
                    }
                }
            }
        }
    }

    private static func fetchKeyInfoFromKeyEndpoint(apiKey: String,
                                                    userIDHint: String?,
                                                    completion: @escaping (Result<ZoteroKeyInfo, Error>) -> Void) {
        let encoded = apiKey.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? apiKey
        guard let url = makeURL(path: "keys/\(encoded)") else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero key lookup URL.", statusCode: nil)))
            return
        }
        request("GET", url: url, apiKey: nil) { result in
            switch result {
            case .success(let (data, _)):
                guard let obj = parseJSON(data) as? [String: Any] else {
                    completion(.failure(ZoteroAPIError(message: "Unexpected Zotero key response.", statusCode: nil)))
                    return
                }
                let userID = (obj["userID"] as? NSNumber)?.stringValue
                    ?? (obj["userID"] as? String)
                    ?? userIDHint
                    ?? ""
                let username = (obj["username"] as? String) ?? ""
                if userID.isEmpty {
                    completion(.failure(ZoteroAPIError(message: "Could not determine Zotero user ID. Please enter it manually.", statusCode: nil)))
                    return
                }
                let fileAccess = parseFileAccess(obj)
                completion(.success(ZoteroKeyInfo(userID: userID,
                                                  username: username,
                                                  userFilesAccess: fileAccess.userFiles,
                                                  groupFilesAccess: fileAccess.groupFiles)))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }

    static func fetchLibraries(apiKey: String,
                               userID: String,
                               username: String,
                               completion: @escaping (Result<[ZoteroLibrary], Error>) -> Void) {
        guard !userID.isEmpty else {
            completion(.failure(ZoteroAPIError(message: "Zotero user ID missing.", statusCode: nil)))
            return
        }
        let personalName = username.isEmpty ? "Personal Library" : username
        var libraries = [ZoteroLibrary(type: .user, id: userID, name: personalName)]

        guard let url = makeURL(path: "users/\(userID)/groups") else {
            completion(.success(libraries))
            return
        }
        request("GET", url: url, apiKey: apiKey) { result in
            switch result {
            case .success(let (data, _)):
                if let arr = parseJSON(data) as? [[String: Any]] {
                    for item in arr {
                        let id = (item["id"] as? NSNumber)?.stringValue ?? (item["id"] as? String) ?? ""
                        guard !id.isEmpty else { continue }
                        let dataDict = item["data"] as? [String: Any]
                        let name = (dataDict?["name"] as? String)?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "Group \(id)"
                        libraries.append(ZoteroLibrary(type: .group, id: id, name: name))
                    }
                }
                completion(.success(libraries))
            case .failure:
                completion(.success(libraries))
            }
        }
    }

    static func fetchCollections(apiKey: String,
                                 library: ZoteroLibrary,
                                 completion: @escaping (Result<[ZoteroCollection], Error>) -> Void) {
        let path = "\(libraryPath(library))/collections"
        let limit = 200
        var allCollections: [ZoteroCollection] = []

        func fetchPage(start: Int) {
            let query = [
                URLQueryItem(name: "format", value: "json"),
                URLQueryItem(name: "limit", value: String(limit)),
                URLQueryItem(name: "start", value: String(start))
            ]
            guard let url = makeURL(path: path, queryItems: query) else {
                completion(.failure(ZoteroAPIError(message: "Invalid Zotero collections URL.", statusCode: nil)))
                return
            }
            request("GET", url: url, apiKey: apiKey) { result in
                switch result {
                case .failure(let error):
                    completion(.failure(error))
                case .success(let (data, _)):
                    var page: [ZoteroCollection] = []
                    if let arr = parseJSON(data) as? [[String: Any]] {
                        for item in arr {
                            guard let key = item["key"] as? String else { continue }
                            let dataDict = item["data"] as? [String: Any]
                            let rawName = (dataDict?["name"] as? String) ?? ""
                            let trimmedName = rawName.trimmingCharacters(in: .whitespacesAndNewlines)
                            let name = trimmedName.isEmpty ? "Collection \(key)" : trimmedName
                            let parent = dataDict?["parentCollection"] as? String
                            page.append(ZoteroCollection(key: key, name: name, parentKey: parent))
                        }
                    }
                    allCollections.append(contentsOf: page)
                    if page.count == limit {
                        fetchPage(start: start + limit)
                    } else {
                        completion(.success(allCollections))
                    }
                }
            }
        }

        fetchPage(start: 0)
    }

    static func fetchItem(apiKey: String,
                          library: ZoteroLibrary,
                          itemKey: String,
                          completion: @escaping (Result<ZoteroItem, Error>) -> Void) {
        let path = "\(libraryPath(library))/items/\(itemKey)"
        let query = [URLQueryItem(name: "format", value: "json")]
        guard let url = makeURL(path: path, queryItems: query) else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero item URL.", statusCode: nil)))
            return
        }
        request("GET", url: url, apiKey: apiKey) { result in
            switch result {
            case .success(let (data, response)):
                guard let obj = parseJSON(data) as? [String: Any] else {
                    completion(.failure(ZoteroAPIError(message: "Unexpected Zotero item response.", statusCode: nil)))
                    return
                }
                guard let item = parseItem(obj, response: response) else {
                    completion(.failure(ZoteroAPIError(message: "Failed to parse Zotero item.", statusCode: nil)))
                    return
                }
                completion(.success(item))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }

    static func searchItems(apiKey: String,
                            library: ZoteroLibrary,
                            query: String,
                            completion: @escaping (Result<[ZoteroItem], Error>) -> Void) {
        let path = "\(libraryPath(library))/items"
        let queryItems = [
            URLQueryItem(name: "format", value: "json"),
            URLQueryItem(name: "itemType", value: "-attachment"),
            URLQueryItem(name: "qmode", value: "everything"),
            URLQueryItem(name: "q", value: query)
        ]
        guard let url = makeURL(path: path, queryItems: queryItems) else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero search URL.", statusCode: nil)))
            return
        }
        request("GET", url: url, apiKey: apiKey) { result in
            switch result {
            case .success(let (data, response)):
                var items: [ZoteroItem] = []
                if let arr = parseJSON(data) as? [[String: Any]] {
                    for obj in arr {
                        if let item = parseItem(obj, response: response) {
                            items.append(item)
                        }
                    }
                }
                completion(.success(items))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }

    static func createItem(apiKey: String,
                           library: ZoteroLibrary,
                           itemData: [String: Any],
                           completion: @escaping (Result<String, Error>) -> Void) {
        let path = "\(libraryPath(library))/items"
        guard let url = makeURL(path: path) else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero create URL.", statusCode: nil)))
            return
        }
        guard let body = try? JSONSerialization.data(withJSONObject: [itemData]) else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero item payload.", statusCode: nil)))
            return
        }
        request("POST", url: url, apiKey: apiKey, body: body, contentType: "application/json") { result in
            switch result {
            case .success(let (data, _)):
                guard let obj = parseJSON(data) as? [String: Any],
                      let success = obj["success"] as? [String: Any],
                      let key = success["0"] as? String else {
                    completion(.failure(ZoteroAPIError(message: "Zotero did not return an item key.", statusCode: nil)))
                    return
                }
                completion(.success(key))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }

    static func updateItem(apiKey: String,
                           library: ZoteroLibrary,
                           item: ZoteroItem,
                           updateData: [String: Any],
                           completion: @escaping (Result<Void, Error>) -> Void) {
        let path = "\(libraryPath(library))/items/\(item.key)"
        guard let url = makeURL(path: path) else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero update URL.", statusCode: nil)))
            return
        }
        var payload = updateData
        payload["key"] = item.key
        if let version = item.version {
            payload["version"] = version
        }
        guard let body = try? JSONSerialization.data(withJSONObject: payload) else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero update payload.", statusCode: nil)))
            return
        }
        var headers: [String: String] = [:]
        if let version = item.version {
            headers["If-Unmodified-Since-Version"] = String(version)
        }
        request("PUT", url: url, apiKey: apiKey, body: body, contentType: "application/json", extraHeaders: headers) { result in
            switch result {
            case .success:
                completion(.success(()))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }

    static func deleteItem(apiKey: String,
                           library: ZoteroLibrary,
                           itemKey: String,
                           version: Int? = nil,
                           completion: @escaping (Result<Void, Error>) -> Void) {
        if let version {
            deleteItemWithVersion(apiKey: apiKey,
                                  library: library,
                                  itemKey: itemKey,
                                  version: version,
                                  allowRetry: true,
                                  completion: completion)
            return
        }
        fetchItem(apiKey: apiKey, library: library, itemKey: itemKey) { result in
            switch result {
            case .failure(let error):
                completion(.failure(error))
            case .success(let item):
                guard let version = item.version else {
                    completion(.failure(ZoteroAPIError(message: "Missing Zotero item version for delete.", statusCode: nil)))
                    return
                }
                deleteItemWithVersion(apiKey: apiKey,
                                      library: library,
                                      itemKey: itemKey,
                                      version: version,
                                      allowRetry: true,
                                      completion: completion)
            }
        }
    }

    private static func deleteItemWithVersion(apiKey: String,
                                              library: ZoteroLibrary,
                                              itemKey: String,
                                              version: Int,
                                              allowRetry: Bool,
                                              completion: @escaping (Result<Void, Error>) -> Void) {
        let path = "\(libraryPath(library))/items/\(itemKey)"
        guard let url = makeURL(path: path) else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero delete URL.", statusCode: nil)))
            return
        }
        let headers = ["If-Unmodified-Since-Version": String(version)]
        request("DELETE", url: url, apiKey: apiKey, extraHeaders: headers) { result in
            switch result {
            case .success:
                completion(.success(()))
            case .failure(let error):
                if allowRetry,
                   let apiError = error as? ZoteroAPIError,
                   apiError.statusCode == 412 {
                    fetchItem(apiKey: apiKey, library: library, itemKey: itemKey) { fetchResult in
                        switch fetchResult {
                        case .success(let item):
                            guard let newVersion = item.version, newVersion != version else {
                                completion(.failure(error))
                                return
                            }
                            deleteItemWithVersion(apiKey: apiKey,
                                                  library: library,
                                                  itemKey: itemKey,
                                                  version: newVersion,
                                                  allowRetry: false,
                                                  completion: completion)
                        case .failure:
                            completion(.failure(error))
                        }
                    }
                } else {
                    completion(.failure(error))
                }
            }
        }
    }

    static func fetchItemChildren(apiKey: String,
                                  library: ZoteroLibrary,
                                  parentKey: String,
                                  completion: @escaping (Result<[ZoteroItem], Error>) -> Void) {
        let path = "\(libraryPath(library))/items/\(parentKey)/children"
        let query = [
            URLQueryItem(name: "format", value: "json"),
            URLQueryItem(name: "itemType", value: "attachment")
        ]
        guard let url = makeURL(path: path, queryItems: query) else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero children URL.", statusCode: nil)))
            return
        }
        request("GET", url: url, apiKey: apiKey) { result in
            switch result {
            case .success(let (data, response)):
                var items: [ZoteroItem] = []
                if let arr = parseJSON(data) as? [[String: Any]] {
                    for obj in arr {
                        if let item = parseItem(obj, response: response) {
                            items.append(item)
                        }
                    }
                }
                completion(.success(items))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }

    static func createAttachmentItem(apiKey: String,
                                     library: ZoteroLibrary,
                                     parentKey: String,
                                     title: String,
                                     filename: String,
                                     contentType: String,
                                     completion: @escaping (Result<String, Error>) -> Void) {
        let item: [String: Any] = [
            "itemType": "attachment",
            "linkMode": "imported_file",
            "title": title,
            "parentItem": parentKey,
            "contentType": contentType,
            "filename": filename,
            "accessDate": "CURRENT_TIMESTAMP"
        ]
        createItem(apiKey: apiKey, library: library, itemData: item, completion: completion)
    }

    static func uploadAttachment(apiKey: String,
                                 library: ZoteroLibrary,
                                 attachmentKey: String,
                                 filename: String,
                                 contentType: String,
                                 md5: String,
                                 data: Data,
                                 completion: @escaping (Result<Void, Error>) -> Void) {
        let path = "\(libraryPath(library))/items/\(attachmentKey)/file"
        guard let url = makeURL(path: path) else {
            completion(.failure(ZoteroAPIError(message: "Invalid Zotero attachment URL.", statusCode: nil)))
            return
        }
        let mtime = Int(Date().timeIntervalSince1970 * 1000)
        let meta = [
            "md5": md5,
            "filename": filename,
            "filesize": String(data.count),
            "mtime": String(mtime),
            "contentType": contentType
        ]
        let formBody = meta.map { "\($0.key)=\($0.value.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? "")" }
            .joined(separator: "&")
        let formData = formBody.data(using: .utf8) ?? Data()

        request("POST",
                url: url,
                apiKey: apiKey,
                body: formData,
                contentType: "application/x-www-form-urlencoded",
                extraHeaders: ["If-None-Match": "*"]) { result in
            switch result {
            case .success(let (responseData, _)):
                guard let obj = parseJSON(responseData) as? [String: Any] else {
                    completion(.failure(ZoteroAPIError(message: "Unexpected Zotero upload response.", statusCode: nil)))
                    return
                }
                if let exists = obj["exists"] as? Bool, exists {
                    completion(.success(()))
                    return
                }
                if let exists = obj["exists"] as? Int, exists == 1 {
                    completion(.success(()))
                    return
                }
                guard let uploadURLString = obj["url"] as? String,
                      let uploadURL = URL(string: uploadURLString),
                      let prefix = obj["prefix"] as? String,
                      let suffix = obj["suffix"] as? String,
                      let uploadKey = obj["uploadKey"] as? String,
                      let uploadContentType = obj["contentType"] as? String else {
                    completion(.failure(ZoteroAPIError(message: "Invalid Zotero upload metadata.", statusCode: nil)))
                    return
                }

                var uploadData = Data()
                uploadData.append(prefix.data(using: .utf8) ?? Data())
                uploadData.append(data)
                uploadData.append(suffix.data(using: .utf8) ?? Data())

                request("POST",
                        url: uploadURL,
                        apiKey: apiKey,
                        body: uploadData,
                        contentType: uploadContentType) { uploadResult in
                    switch uploadResult {
                    case .success:
                        let finalizeBody = "upload=\(uploadKey)"
                        let finalizeData = finalizeBody.data(using: .utf8) ?? Data()
                        request("POST",
                                url: url,
                                apiKey: apiKey,
                                body: finalizeData,
                                contentType: "application/x-www-form-urlencoded",
                                extraHeaders: ["If-None-Match": "*"]) { finalizeResult in
                            switch finalizeResult {
                            case .success:
                                completion(.success(()))
                            case .failure(let error):
                                completion(.failure(error))
                            }
                        }
                    case .failure(let error):
                        completion(.failure(error))
                    }
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }

    private static func parseItem(_ obj: [String: Any], response: HTTPURLResponse) -> ZoteroItem? {
        guard let key = obj["key"] as? String else { return nil }
        let data = obj["data"] as? [String: Any] ?? [:]
        let versionHeader = response.value(forHTTPHeaderField: "Last-Modified-Version")
        let version = versionHeader.flatMap { Int($0) } ?? obj["version"] as? Int
        return ZoteroItem(key: key, version: version, data: data)
    }
}

private struct ZoteroPublicationDescriptor {
    let stableID: String
    let arxivID: String?
    let doi: String?
    let title: String?
    let authors: [String]
    let year: String?
    let abstractText: String?
    let arxivURL: String?
    let pdfDocument: PDFDocument?
}

private struct ZoteroResolvedMetadata {
    let itemType: String
    let title: String
    let creators: [[String: String]]
    let date: String
    let doi: String?
    let arxivID: String?
    let arxivURL: String?
    let journal: String?
    let abstractText: String?
}

private struct ZoteroArxivMeta {
    let title: String
    let authors: [String]
    let summary: String
    let published: String
    let doi: String?
    let journalRef: String?
    let absURL: String?
}

private struct ZoteroDOIMeta {
    let title: String
    let authors: [String]
    let issuedYear: String
    let journal: String?
}

private enum ZoteroMetadataResolver {
    private static let session: URLSession = {
        let config = URLSessionConfiguration.ephemeral
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        return URLSession(configuration: config)
    }()

    static func resolveMetadata(for descriptor: ZoteroPublicationDescriptor,
                                completion: @escaping (Result<ZoteroResolvedMetadata, Error>) -> Void) {
        if let arxivID = descriptor.arxivID, !arxivID.isEmpty {
            fetchArxivMetadata(arxivID: arxivID) { result in
                switch result {
                case .success(let meta):
                    completion(.success(merge(descriptor: descriptor, arxiv: meta)))
                case .failure:
                    completion(.success(fallbackMetadata(from: descriptor)))
                }
            }
            return
        }

        if let doi = descriptor.doi, !doi.isEmpty {
            fetchDOIMetadata(doi: doi) { result in
                switch result {
                case .success(let meta):
                    completion(.success(merge(descriptor: descriptor, doi: meta)))
                case .failure:
                    completion(.success(fallbackMetadata(from: descriptor)))
                }
            }
            return
        }

        completion(.success(fallbackMetadata(from: descriptor)))
    }

    private static func merge(descriptor: ZoteroPublicationDescriptor, arxiv: ZoteroArxivMeta) -> ZoteroResolvedMetadata {
        let title = arxiv.title.isEmpty ? (descriptor.title ?? "Untitled") : arxiv.title
        let creators = buildCreators(from: arxiv.authors.isEmpty ? descriptor.authors : arxiv.authors)
        let year = extractYearFromDateString(arxiv.published) ?? descriptor.year ?? ""
        let doi = arxiv.doi ?? descriptor.doi
        let itemType = (arxiv.journalRef?.isEmpty == false) ? "journalArticle" : "preprint"
        return ZoteroResolvedMetadata(
            itemType: itemType,
            title: title,
            creators: creators,
            date: year,
            doi: doi,
            arxivID: descriptor.arxivID,
            arxivURL: arxiv.absURL ?? descriptor.arxivURL,
            journal: arxiv.journalRef,
            abstractText: arxiv.summary.isEmpty ? descriptor.abstractText : arxiv.summary
        )
    }

    private static func merge(descriptor: ZoteroPublicationDescriptor, doi: ZoteroDOIMeta) -> ZoteroResolvedMetadata {
        let title = doi.title.isEmpty ? (descriptor.title ?? "Untitled") : doi.title
        let creators = buildCreators(from: doi.authors.isEmpty ? descriptor.authors : doi.authors)
        let year = doi.issuedYear.isEmpty ? (descriptor.year ?? "") : doi.issuedYear
        return ZoteroResolvedMetadata(
            itemType: "journalArticle",
            title: title,
            creators: creators,
            date: year,
            doi: descriptor.doi,
            arxivID: descriptor.arxivID,
            arxivURL: descriptor.arxivURL,
            journal: doi.journal,
            abstractText: descriptor.abstractText
        )
    }

    private static func fallbackMetadata(from descriptor: ZoteroPublicationDescriptor) -> ZoteroResolvedMetadata {
        let title = descriptor.title ?? "Untitled"
        let creators = buildCreators(from: descriptor.authors)
        let year = descriptor.year ?? ""
        let itemType = (descriptor.arxivID != nil) ? "preprint" : "journalArticle"
        return ZoteroResolvedMetadata(
            itemType: itemType,
            title: title,
            creators: creators,
            date: year,
            doi: descriptor.doi,
            arxivID: descriptor.arxivID,
            arxivURL: descriptor.arxivURL,
            journal: nil,
            abstractText: descriptor.abstractText
        )
    }

    private static func buildCreators(from authors: [String]) -> [[String: String]] {
        guard !authors.isEmpty else { return [] }
        return authors.compactMap { author in
            let parts = splitAuthorName(author)
            if parts.first.isEmpty && parts.last.isEmpty { return nil }
            return [
                "creatorType": "author",
                "firstName": parts.first,
                "lastName": parts.last
            ]
        }
    }

    private static func splitAuthorName(_ author: String) -> (first: String, last: String) {
        let cleaned = author.trimmingCharacters(in: .whitespacesAndNewlines)
        if let comma = cleaned.firstIndex(of: ",") {
            let last = cleaned[..<comma].trimmingCharacters(in: .whitespacesAndNewlines)
            let first = cleaned[cleaned.index(after: comma)...].trimmingCharacters(in: .whitespacesAndNewlines)
            return (first: String(first), last: String(last))
        }
        let tokens = cleaned.split(separator: " ")
        guard let last = tokens.last else { return (first: cleaned, last: "") }
        let first = tokens.dropLast().joined(separator: " ")
        return (first: first, last: String(last))
    }

    private static func fetchArxivMetadata(arxivID: String,
                                           completion: @escaping (Result<ZoteroArxivMeta, Error>) -> Void) {
        let encoded = arxivID.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? arxivID
        guard let url = URL(string: "https://export.arxiv.org/api/query?id_list=\(encoded)") else {
            completion(.failure(ZoteroAPIError(message: "Invalid arXiv ID.", statusCode: nil)))
            return
        }
        let task = session.dataTask(with: url) { data, _, error in
            if let error {
                completion(.failure(error))
                return
            }
            guard let data else {
                completion(.failure(ZoteroAPIError(message: "Empty arXiv response.", statusCode: nil)))
                return
            }
            let parser = ArxivXMLParser()
            if parser.parse(data: data) {
                if let meta = parser.metadata {
                    completion(.success(meta))
                } else {
                    completion(.failure(ZoteroAPIError(message: "No arXiv metadata found.", statusCode: nil)))
                }
            } else {
                completion(.failure(ZoteroAPIError(message: "Failed to parse arXiv metadata.", statusCode: nil)))
            }
        }
        task.resume()
    }

    private static func fetchDOIMetadata(doi: String,
                                         completion: @escaping (Result<ZoteroDOIMeta, Error>) -> Void) {
        let doiPath = doi.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? doi
        guard let url = URL(string: "https://doi.org/\(doiPath)") else {
            completion(.failure(ZoteroAPIError(message: "Invalid DOI URL.", statusCode: nil)))
            return
        }
        var request = URLRequest(url: url)
        request.setValue("application/vnd.citationstyles.csl+json", forHTTPHeaderField: "Accept")
        request.setValue("AstroStack", forHTTPHeaderField: "User-Agent")
        let task = session.dataTask(with: request) { data, response, error in
            if let error {
                completion(.failure(error))
                return
            }
            guard let data,
                  let http = response as? HTTPURLResponse,
                  (200...299).contains(http.statusCode) else {
                completion(.failure(ZoteroAPIError(message: "DOI metadata unavailable.", statusCode: nil)))
                return
            }
            guard let obj = (try? JSONSerialization.jsonObject(with: data)) as? [String: Any] else {
                completion(.failure(ZoteroAPIError(message: "Invalid DOI metadata.", statusCode: nil)))
                return
            }
            let title = (obj["title"] as? String) ?? (obj["title"] as? [String])?.first ?? ""
            var authors: [String] = []
            if let authorArr = obj["author"] as? [[String: Any]] {
                for a in authorArr {
                    let given = (a["given"] as? String) ?? ""
                    let family = (a["family"] as? String) ?? ""
                    let name = "\(given) \(family)".trimmingCharacters(in: .whitespacesAndNewlines)
                    if !name.isEmpty { authors.append(name) }
                }
            }
            var issuedYear = ""
            if let issued = obj["issued"] as? [String: Any],
               let parts = issued["date-parts"] as? [[Int]],
               let first = parts.first,
               let year = first.first {
                issuedYear = String(year)
            }
            let journal = (obj["container-title"] as? String) ?? (obj["container-title"] as? [String])?.first
            completion(.success(ZoteroDOIMeta(title: title, authors: authors, issuedYear: issuedYear, journal: journal)))
        }
        task.resume()
    }

    private static func extractYearFromDateString(_ date: String) -> String? {
        let s = date.trimmingCharacters(in: .whitespacesAndNewlines)
        if let re = try? NSRegularExpression(pattern: #"\b(19|20)\d{2}\b"#) {
            let range = NSRange(location: 0, length: (s as NSString).length)
            if let m = re.firstMatch(in: s, range: range) {
                return (s as NSString).substring(with: m.range)
            }
        }
        return nil
    }
}

private final class ArxivXMLParser: NSObject, XMLParserDelegate {
    private var currentElement: String = ""
    private var currentText: String = ""
    private var insideEntry = false
    private var insideAuthor = false
    private var authors: [String] = []
    private var title: String = ""
    private var summary: String = ""
    private var published: String = ""
    private var doi: String?
    private var journalRef: String?
    private var absURL: String?

    private(set) var metadata: ZoteroArxivMeta?

    func parse(data: Data) -> Bool {
        let parser = XMLParser(data: data)
        parser.delegate = self
        return parser.parse()
    }

    func parser(_ parser: XMLParser,
                didStartElement elementName: String,
                namespaceURI: String?,
                qualifiedName qName: String?,
                attributes attributeDict: [String: String] = [:]) {
        currentElement = qName ?? elementName
        currentText = ""
        if elementName == "entry" {
            insideEntry = true
        } else if elementName == "author" {
            insideAuthor = true
        }
    }

    func parser(_ parser: XMLParser, foundCharacters string: String) {
        guard insideEntry else { return }
        currentText += string
    }

    func parser(_ parser: XMLParser,
                didEndElement elementName: String,
                namespaceURI: String?,
                qualifiedName qName: String?) {
        guard insideEntry else { return }
        let name = qName ?? elementName
        let trimmed = currentText.trimmingCharacters(in: .whitespacesAndNewlines)

        switch name {
        case "title":
            if title.isEmpty { title = trimmed }
        case "summary":
            if summary.isEmpty { summary = trimmed }
        case "published":
            if published.isEmpty { published = trimmed }
        case "id":
            if absURL == nil, trimmed.contains("arxiv.org/abs/") {
                absURL = trimmed
            }
        case "name":
            if insideAuthor && !trimmed.isEmpty {
                authors.append(trimmed)
            }
        case "arxiv:doi", "doi":
            if doi == nil, !trimmed.isEmpty { doi = trimmed }
        case "arxiv:journal_ref", "journal_ref":
            if journalRef == nil, !trimmed.isEmpty { journalRef = trimmed }
        case "author":
            insideAuthor = false
        case "entry":
            insideEntry = false
            metadata = ZoteroArxivMeta(
                title: title,
                authors: authors,
                summary: summary,
                published: published,
                doi: doi,
                journalRef: journalRef,
                absURL: absURL
            )
        default:
            break
        }
    }
}

private func extractDOI(from text: String) -> String? {
    let s = text.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !s.isEmpty else { return nil }
    guard let re = try? NSRegularExpression(pattern: #"\b10\.\d{4,9}/[-._;()/:A-Z0-9]+\b"#,
                                            options: [.caseInsensitive]) else { return nil }
    let range = NSRange(s.startIndex..<s.endIndex, in: s)
    if let match = re.firstMatch(in: s, range: range),
       let r = Range(match.range, in: s) {
        return normalizeDOI(String(s[r]))
    }
    return nil
}

private func normalizeDOI(_ doi: String) -> String {
    var s = doi.trimmingCharacters(in: .whitespacesAndNewlines)
    let lower = s.lowercased()
    if lower.hasPrefix("doi:") {
        s = String(s.dropFirst(4)).trimmingCharacters(in: .whitespacesAndNewlines)
    }
    let lowered = s.lowercased()
    let prefixes = ["https://doi.org/", "http://doi.org/", "https://dx.doi.org/", "http://dx.doi.org/"]
    for p in prefixes where lowered.hasPrefix(p) {
        s = String(s.dropFirst(p.count))
        break
    }
    s = s.trimmingCharacters(in: CharacterSet(charactersIn: " .,:;()[]{}<>"))
    return s
}

private func extractDOI(from document: PDFDocument?) -> String? {
    guard let document else { return nil }
    if let attrs = document.documentAttributes {
        for value in attrs.values {
            if let text = value as? String,
               let doi = extractDOI(from: text) {
                return doi
            }
        }
    }
    let pageCount = min(document.pageCount, 2)
    guard pageCount > 0 else { return nil }
    for i in 0..<pageCount {
        if let page = document.page(at: i),
           let text = page.string,
           let doi = extractDOI(from: text) {
            return doi
        }
    }
    return nil
}

private func pdfDocumentTitle(_ document: PDFDocument?) -> String? {
    guard let document else { return nil }
    if let attrs = document.documentAttributes,
       let title = attrs[PDFDocumentAttribute.titleAttribute] as? String,
       !title.isEmpty {
        return title.trimmingCharacters(in: .whitespacesAndNewlines)
    }
    if let first = document.page(at: 0)?.string {
        let lines = first.split(separator: "\n")
        if let line = lines.first {
            let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty { return trimmed }
        }
    }
    return nil
}

private func pdfDocumentAuthors(_ document: PDFDocument?) -> [String] {
    guard let document else { return [] }
    if let attrs = document.documentAttributes,
       let author = attrs[PDFDocumentAttribute.authorAttribute] as? String,
       !author.isEmpty {
        return parseAuthorList(from: author)
    }
    return []
}

private func md5Hex(_ data: Data) -> String {
    let digest = Insecure.MD5.hash(data: data)
    return digest.map { String(format: "%02x", $0) }.joined()
}

