}

private let layoutDefaultsKeys: [String] = [
    "astroStack.sidebarWidth",
    "astroStack.sidebarVisible",
    "astroStack.chatWidth",
    "arxivPicker.sidebarWidth",
    "arxivPicker.sidebarVisible",
    "arxivPicker.chatWidth"
]

func clearLayoutDefaults() {
    let defaults = UserDefaults.standard
    layoutDefaultsKeys.forEach { defaults.removeObject(forKey: $0) }
}

struct AppSettings: Codable, Equatable {
    static let currentSchemaVersion: Int = 1

    struct Appearance: Codable, Equatable {
        enum AppAppearanceOverride: String, Codable {
            case followSystem
            case light
            case dark
        }

        enum AccentMode: String, Codable {
            case system
            case custom
        }

        enum GlassTintSource: String, Codable {
            case none
            case appAccent
            case custom
        }

        enum GlassStyle: String, Codable {
            case followApp
            case light
            case dark
        }

        enum TablePanelBackgroundMode: String, Codable {
            case automatic
            case custom
        }

        struct Fonts: Codable, Equatable {
            var uiFontName: String = ""
            var uiFontSize: Double = 12.8
            var htmlFontName: String = ""
            var htmlFontSize: Double = 0
        }

        struct HTMLImages: Codable, Equatable {
            var leftPath: String = HEADER_IMAGE_LEFT_PATH
            var centerPath: String = HEADER_IMAGE_CENTER_PATH
            var rightPath: String = HEADER_IMAGE_RIGHT_PATH
        }

        var appearanceOverride: AppAppearanceOverride = .followSystem
        var accentMode: AccentMode = .system
        var customAccentHex: String = LIQUID_GLASS_TINT_HEX
        var liquidGlassEnabled: Bool = true
        var windowTintEnabled: Bool = true
        var glassTintSourceEnabled: Bool = true
        var customGlassTintEnabled: Bool = true
        var glassStyleEnabled: Bool = true
        var liquidGlassTintStrength: Double = 0.10
        var glassTintSource: GlassTintSource = .appAccent
        var customGlassTintHex: String = LIQUID_GLASS_TINT_HEX
        var glassStyle: GlassStyle = .dark
        var leftPanelGlassEnabled: Bool = true
        var leftPanelTintHex: String = "#000000"
        var leftPanelTintAlpha: Double = 0.10
        var leftTablePanelBackgroundMode: TablePanelBackgroundMode = .automatic
        var leftTablePanelBackgroundHex: String = ""
        var rightAuxGlassEnabled: Bool = true
        var rightAuxTintHex: String = "#000000"
        var rightAuxTintAlpha: Double = 0.10
        var annotationListGlassEnabled: Bool = true
        var annotationListTintHex: String = ""
        var annotationListTintStrength: Double = 0.0
        var annotationComposerTintHex: String = ""
        var annotationComposerTintStrength: Double = 1.0
        var fonts: Fonts = Fonts()
        var htmlImages: HTMLImages = HTMLImages()
    }

    struct LayoutPanels: Codable, Equatable {
        // Intentionally minimal; layout resets are explicit actions (not automatic behavior changes).
        var reserved: Bool = false
    }

    struct DocumentsPDF: Codable, Equatable {
        struct CustomPalette: Codable, Equatable {
            var id: String = ""
            var name: String = ""
            var colors: [String] = []
            var colorLabels: [String] = []
        }

        var reserved: Bool = false
        var annotationPaletteID: String = "system-tint"
        // Custom overrides per palette ID (hex colors, max 6 per palette).
        var annotationPaletteOverrides: [String: [String]] = [:]
        // Optional custom display labels for each palette ID.
        var annotationPaletteLabels: [String: String] = [:]
        // User-defined palettes (up to 6).
        var customPalettes: [CustomPalette] = DocumentsPDF.makeDefaultCustomPalettes()

        static func defaultCustomPalette(at index: Int) -> CustomPalette {
            CustomPalette(
                id: customAnnotationPaletteID(index),
                name: customAnnotationPaletteDefaultName(index),
                colors: normalizedPaletteHexColors([], fallback: customAnnotationPaletteDefaultHex),
                colorLabels: normalizedPaletteLabels([], fallback: customAnnotationPaletteDefaultLabels())
            )
        }

        static func makeDefaultCustomPalettes() -> [CustomPalette] {
            (0..<customAnnotationPaletteCount).map { defaultCustomPalette(at: $0) }
        }

        mutating func normalize() {
            if !annotationPaletteOverrides.isEmpty {
                var cleaned: [String: [String]] = [:]
                for (key, values) in annotationPaletteOverrides {
                    let trimmed = values.map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
                        .filter { !$0.isEmpty }
                    if !trimmed.isEmpty {
                        cleaned[key] = Array(trimmed.prefix(6))
                    }
                }
                annotationPaletteOverrides = cleaned
            }
            if !annotationPaletteLabels.isEmpty {
                var cleanedLabels: [String: String] = [:]
                for (key, value) in annotationPaletteLabels {
                    let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
                    if !trimmed.isEmpty {
                        cleanedLabels[key] = trimmed
                    }
                }
                annotationPaletteLabels = cleanedLabels
            }
            if customPalettes.count != customAnnotationPaletteCount {
                if customPalettes.count < customAnnotationPaletteCount {
                    let start = customPalettes.count
                    customPalettes.append(contentsOf: (start..<customAnnotationPaletteCount).map { DocumentsPDF.defaultCustomPalette(at: $0) })
                } else if customPalettes.count > customAnnotationPaletteCount {
                    customPalettes = Array(customPalettes.prefix(customAnnotationPaletteCount))
                }
            }
            if !customPalettes.isEmpty {
                for index in customPalettes.indices {
                    var palette = customPalettes[index]
                    let defaults = DocumentsPDF.defaultCustomPalette(at: index)
                    let trimmedName = palette.name.trimmingCharacters(in: .whitespacesAndNewlines)
                    palette.id = defaults.id
                    palette.name = trimmedName.isEmpty ? defaults.name : trimmedName
                    palette.colors = normalizedPaletteHexColors(palette.colors, fallback: defaults.colors)
                    palette.colorLabels = normalizedPaletteLabels(palette.colorLabels, fallback: defaults.colorLabels)
                    customPalettes[index] = palette
                }
                if !annotationPaletteLabels.isEmpty {
                    let customIDs = Set(customPalettes.map { $0.id })
                    annotationPaletteLabels = annotationPaletteLabels.filter { !customIDs.contains($0.key) }
                }
            }
        }
    }

    struct Search: Codable, Equatable {
        var reserved: Bool = false
    }

    struct AppleIntelligence: Codable, Equatable {
        struct Button: Codable, Equatable {
            var label: String = ""
            var prompt: String = ""
            var shortcutName: String = ""
        }

        private static func makeDefaultButton(label: String, prompt: String) -> Button {
            Button(label: label, prompt: prompt, shortcutName: "AstroStack: \(label)")
        }

        static let defaultButtons: [Button] = AppSettingsDefaults.appleIntelligenceButtons

        var buttons: [Button] = AppleIntelligence.defaultButtons
        var useShortcuts: Bool = false

        mutating func normalize() {
            if buttons.count == Self.defaultButtons.count { return }
            if buttons.count < Self.defaultButtons.count {
                buttons.append(contentsOf: Self.defaultButtons[buttons.count...])
            } else if buttons.count > Self.defaultButtons.count {
                buttons = Array(buttons.prefix(Self.defaultButtons.count))
            }
        }

        func resolvedButton(at index: Int) -> Button {
            let fallback = Self.defaultButtons[min(index, Self.defaultButtons.count - 1)]
            guard index >= 0, index < buttons.count else { return fallback }
            var button = buttons[index]
            let label = button.label.trimmingCharacters(in: .whitespacesAndNewlines)
            let prompt = button.prompt.trimmingCharacters(in: .whitespacesAndNewlines)
            let shortcutName = button.shortcutName.trimmingCharacters(in: .whitespacesAndNewlines)
            if label.isEmpty { button.label = fallback.label }
            if prompt.isEmpty { button.prompt = fallback.prompt }
            button.shortcutName = shortcutName
            return button
        }
    }

    struct SharingExport: Codable, Equatable {
        struct EmailDefaults: Codable, Equatable {
            var defaultEmailAppBundleID: String = ""
            var defaultSubjectTemplate: String = "New Paper: {{title}}"
            var defaultToAddress: String = ""
            var defaultBodyTemplate: String = """
Hey,

Did you see this new paper?

{{title}}
{{url}}
"""
            var defaultFromAddress: String = "name@example.com"
        }

        var reserved: Bool = false
        var email: EmailDefaults = EmailDefaults()
    }

    struct Shortcuts: Codable, Equatable {
        // Name must match exactly as shown in the Shortcuts app.
        var shortcutName: String = "My Shortcut"
        // Advanced: use x-callback-url variant.
        var useXCallback: Bool = false
        // Optional: include input=text&text=<payload> when available.
        var inputTextMode: Bool = false
    }

    struct Zotero: Codable, Equatable {
        enum LibraryType: String, Codable {
            case user
            case group
        }

        var userID: String = ""
        var username: String = ""
        var libraryType: LibraryType = .user
        var libraryID: String = ""
        var libraryName: String = ""
        var lastCollectionKey: String = ""
        var defaultCollectionKey: String = ""
        var promptForCollectionsOnSave: Bool = false
        var useNormalizedKeyForRequests: Bool = true
    }

    struct AdvancedDeveloper: Codable, Equatable {
        // Defensive: defaults reproduce current behavior exactly.
        // These flags are read once at controller init, so changes require relaunch.
        var enableUIDebug: Bool = false
        var enableToolbarGlassDebug: Bool = false
    }

    var schemaVersion: Int = AppSettings.currentSchemaVersion
    var hasInitializedAppearanceDefaults: Bool = false
    var hasInitializedAppleIntelligenceDefaults: Bool = false
    var hasInitializedSharingDefaults: Bool = false
    var appearance: Appearance = Appearance()
    var layoutPanels: LayoutPanels = LayoutPanels()
    var documentsPDF: DocumentsPDF = DocumentsPDF()
    var search: Search = Search()
    var appleIntelligence: AppleIntelligence = AppleIntelligence()
    var appleIntelligenceDefaults: AppleIntelligence = AppleIntelligence()
    var sharingExport: SharingExport = SharingExport()
    var sharingDefaults: SharingExport = SharingExport()
    var shortcuts: Shortcuts = Shortcuts()
    var shortcutsDefaults: Shortcuts = Shortcuts()
    var zotero: Zotero = Zotero()
    var advancedDeveloper: AdvancedDeveloper = AdvancedDeveloper()

    // Backward-compatible decoding: allows additive fields without breaking users' stored settings.
    private enum CodingKeys: String, CodingKey {
        case schemaVersion
        case hasInitializedAppearanceDefaults
        case hasInitializedAppleIntelligenceDefaults
        case hasInitializedSharingDefaults
        case appearance
        case layoutPanels
        case documentsPDF
        case search
        case appleIntelligence
        case appleIntelligenceDefaults
        case sharingExport
        case sharingDefaults
        case shortcuts
        case shortcutsDefaults
        case zotero
        case advancedDeveloper
    }

    init() {}

    init(from decoder: Decoder) throws {
        let c = try decoder.container(keyedBy: CodingKeys.self)
        schemaVersion = try c.decodeIfPresent(Int.self, forKey: .schemaVersion) ?? AppSettings.currentSchemaVersion
        hasInitializedAppearanceDefaults = try c.decodeIfPresent(Bool.self, forKey: .hasInitializedAppearanceDefaults) ?? false
        hasInitializedAppleIntelligenceDefaults = try c.decodeIfPresent(Bool.self, forKey: .hasInitializedAppleIntelligenceDefaults) ?? false
        hasInitializedSharingDefaults = try c.decodeIfPresent(Bool.self, forKey: .hasInitializedSharingDefaults) ?? false
        appearance = try c.decodeIfPresent(Appearance.self, forKey: .appearance) ?? Appearance()
        layoutPanels = try c.decodeIfPresent(LayoutPanels.self, forKey: .layoutPanels) ?? LayoutPanels()
        documentsPDF = try c.decodeIfPresent(DocumentsPDF.self, forKey: .documentsPDF) ?? DocumentsPDF()
        search = try c.decodeIfPresent(Search.self, forKey: .search) ?? Search()
        appleIntelligence = try c.decodeIfPresent(AppleIntelligence.self, forKey: .appleIntelligence) ?? AppleIntelligence()
        appleIntelligenceDefaults = try c.decodeIfPresent(AppleIntelligence.self, forKey: .appleIntelligenceDefaults) ?? AppleIntelligence()
        sharingExport = try c.decodeIfPresent(SharingExport.self, forKey: .sharingExport) ?? SharingExport()
        sharingDefaults = try c.decodeIfPresent(SharingExport.self, forKey: .sharingDefaults) ?? SharingExport()
        shortcuts = try c.decodeIfPresent(Shortcuts.self, forKey: .shortcuts) ?? Shortcuts()
        shortcutsDefaults = try c.decodeIfPresent(Shortcuts.self, forKey: .shortcutsDefaults) ?? Shortcuts()
        zotero = try c.decodeIfPresent(Zotero.self, forKey: .zotero) ?? Zotero()
        advancedDeveloper = try c.decodeIfPresent(AdvancedDeveloper.self, forKey: .advancedDeveloper) ?? AdvancedDeveloper()
        appleIntelligence.normalize()
        appleIntelligenceDefaults.normalize()
        documentsPDF.normalize()
    }

    func encode(to encoder: Encoder) throws {
        var c = encoder.container(keyedBy: CodingKeys.self)
        try c.encode(schemaVersion, forKey: .schemaVersion)
        try c.encode(hasInitializedAppearanceDefaults, forKey: .hasInitializedAppearanceDefaults)
        try c.encode(hasInitializedAppleIntelligenceDefaults, forKey: .hasInitializedAppleIntelligenceDefaults)
        try c.encode(hasInitializedSharingDefaults, forKey: .hasInitializedSharingDefaults)
        try c.encode(appearance, forKey: .appearance)
        try c.encode(layoutPanels, forKey: .layoutPanels)
        try c.encode(documentsPDF, forKey: .documentsPDF)
        try c.encode(search, forKey: .search)
        try c.encode(appleIntelligence, forKey: .appleIntelligence)
        try c.encode(appleIntelligenceDefaults, forKey: .appleIntelligenceDefaults)
        try c.encode(sharingExport, forKey: .sharingExport)
        try c.encode(sharingDefaults, forKey: .sharingDefaults)
        try c.encode(shortcuts, forKey: .shortcuts)
        try c.encode(shortcutsDefaults, forKey: .shortcutsDefaults)
        try c.encode(zotero, forKey: .zotero)
        try c.encode(advancedDeveloper, forKey: .advancedDeveloper)
    }
}

