final class AppSettingsStore {
    static let shared = AppSettingsStore()

    private struct Persistence {
        static let defaultsKey = "astroStack.settings.v1"
    }

    private let lock = NSLock()
    private var cached: AppSettings = AppSettings()
    private var loaded = false
    private var loadedFromDisk = false
    private var pendingPostLoadPersist = false

    private init() {}

    var current: AppSettings {
        var snapshot: AppSettings
        var needsPersist = false
        lock.lock()
        ensureLoadedLocked()
        if pendingPostLoadPersist {
            pendingPostLoadPersist = false
            needsPersist = true
        }
        if cached.schemaVersion != AppSettings.currentSchemaVersion {
            // Defensive: if schema drifts, fall back to defaults rather than attempting risky migration.
            cached = AppSettingsDefaults.make()
            needsPersist = true
        }
        snapshot = cached
        lock.unlock()
        if needsPersist {
            persist(snapshot)
        }
        return snapshot
    }

    func update(_ mutate: (inout AppSettings) -> Void) {
        var snapshot: AppSettings?
        var needsNotify = false
        lock.lock()
        ensureLoadedLocked()
        if pendingPostLoadPersist {
            pendingPostLoadPersist = false
            needsNotify = true
        }
        var next = cached
        mutate(&next)
        if next != cached {
            cached = next
            snapshot = next
            needsNotify = true
        } else if needsNotify {
            snapshot = cached
        }
        lock.unlock()
        guard let persisted = snapshot else { return }
        // Persist outside the lock to avoid re-entrancy via UserDefaults.didChangeNotification.
        persist(persisted)
        if needsNotify {
            let notify = {
                NotificationCenter.default.post(name: .astroStackSettingsDidChange, object: nil)
            }
            if Thread.isMainThread {
                notify()
            } else {
                DispatchQueue.main.async(execute: notify)
            }
        }
    }

    func resetToDefaults() {
        lock.lock()
        cached = AppSettingsDefaults.make()
        loaded = true
        loadedFromDisk = false
        pendingPostLoadPersist = false
        lock.unlock()
        UserDefaults.standard.removeObject(forKey: Persistence.defaultsKey)
        let notify = {
            NotificationCenter.default.post(name: .astroStackSettingsDidChange, object: nil)
        }
        if Thread.isMainThread {
            notify()
        } else {
            DispatchQueue.main.async(execute: notify)
        }
    }

    private func loadLocked() -> (settings: AppSettings?, hadStoredSettings: Bool) {
        guard let data = UserDefaults.standard.data(forKey: Persistence.defaultsKey) else {
            return (nil, false)
        }
        do {
            let decoder = JSONDecoder()
            let decoded = try decoder.decode(AppSettings.self, from: data)
            return (decoded, true)
        } catch {
            return (nil, false)
        }
    }

    private func persist(_ settings: AppSettings) {
        do {
            let encoder = JSONEncoder()
            if #available(macOS 10.13, *) {
                encoder.outputFormatting = [.sortedKeys]
            }
            let data = try encoder.encode(settings)
            UserDefaults.standard.set(data, forKey: Persistence.defaultsKey)
        } catch {
            // Persistence failures are non-fatal; keep in-memory copy.
        }
    }

    private func ensureLoadedLocked() {
        guard !loaded else { return }
        let loadedResult = loadLocked()
        if let settings = loadedResult.settings {
            cached = settings
            loadedFromDisk = true
            loaded = true
        } else {
            cached = AppSettingsDefaults.make()
            loadedFromDisk = false
            loaded = true
            pendingPostLoadPersist = true
            return
        }

        if !cached.hasInitializedAppearanceDefaults {
            cached.hasInitializedAppearanceDefaults = true
            pendingPostLoadPersist = true
        }

        if cached.appleIntelligenceDefaults != AppSettingsDefaults.appleIntelligence {
            cached.appleIntelligenceDefaults = AppSettingsDefaults.appleIntelligence
            pendingPostLoadPersist = true
        }
        if !cached.hasInitializedAppleIntelligenceDefaults {
            cached.hasInitializedAppleIntelligenceDefaults = true
            pendingPostLoadPersist = true
        }

        if cached.sharingDefaults != AppSettingsDefaults.sharingExport {
            cached.sharingDefaults = AppSettingsDefaults.sharingExport
            pendingPostLoadPersist = true
        }
        if cached.shortcutsDefaults != AppSettingsDefaults.shortcuts {
            cached.shortcutsDefaults = AppSettingsDefaults.shortcuts
            pendingPostLoadPersist = true
        }
        if !cached.hasInitializedSharingDefaults {
            cached.hasInitializedSharingDefaults = true
            pendingPostLoadPersist = true
        }
    }
}

enum AppSettingsBootstrap {
    static func applyAppAppearanceOverrideIfNeeded(_ app: NSApplication) {
        let settings = AppSettingsStore.shared.current
        switch settings.appearance.appearanceOverride {
        case .followSystem:
            app.appearance = nil
        case .light:
            app.appearance = NSAppearance(named: .aqua)
        case .dark:
            app.appearance = NSAppearance(named: .darkAqua)
        }
    }
}

enum SettingsMenuIntegrator {
    static func installIfNeeded() {
        let appName = ProcessInfo.processInfo.processName

        if NSApp.mainMenu == nil {
            let main = NSMenu(title: "Main")

            let appItem = NSMenuItem()
            let appMenu = NSMenu(title: appName)
            appItem.submenu = appMenu
            main.addItem(appItem)

            // Basic, standard app menu items. Keep minimal; do not alter other menus.
            appMenu.addItem(withTitle: "About \(appName)", action: #selector(NSApplication.orderFrontStandardAboutPanel(_:)), keyEquivalent: "")
            appMenu.addItem(NSMenuItem.separator())

            // Settings item is inserted below.
            let servicesItem = NSMenuItem(title: "Services", action: nil, keyEquivalent: "")
            let services = NSMenu(title: "Services")
            servicesItem.submenu = services
            NSApp.servicesMenu = services
            appMenu.addItem(servicesItem)
            appMenu.addItem(NSMenuItem.separator())
            appMenu.addItem(withTitle: "Hide \(appName)", action: #selector(NSApplication.hide(_:)), keyEquivalent: "h")
            let hideOthers = NSMenuItem(title: "Hide Others", action: #selector(NSApplication.hideOtherApplications(_:)), keyEquivalent: "h")
            hideOthers.keyEquivalentModifierMask = [.command, .option]
            appMenu.addItem(hideOthers)
            appMenu.addItem(withTitle: "Show All", action: #selector(NSApplication.unhideAllApplications(_:)), keyEquivalent: "")
            appMenu.addItem(NSMenuItem.separator())
            appMenu.addItem(withTitle: "Quit \(appName)", action: #selector(NSApplication.terminate(_:)), keyEquivalent: "q")

            NSApp.mainMenu = main
        }

        guard let mainMenu = NSApp.mainMenu else { return }
        ensureEditMenu(in: mainMenu)
        let appMenuItem = mainMenu.items.first(where: { $0.submenu != nil }) ?? mainMenu.item(at: 0)
        guard let appMenu = appMenuItem?.submenu else { return }

        let wantsSettingsTitle: String
        if #available(macOS 13.0, *) {
            wantsSettingsTitle = "Settings…"
        } else {
            wantsSettingsTitle = "Preferences…"
        }

        if appMenu.items.contains(where: { $0.title == wantsSettingsTitle }) {
            return
        }

        let settingsItem = NSMenuItem(title: wantsSettingsTitle, action: #selector(SettingsWindowController.openSettings(_:)), keyEquivalent: ",")
        settingsItem.keyEquivalentModifierMask = [.command]
        settingsItem.target = SettingsWindowController.shared

        // Insert after About + separator if present.
        let insertIndex: Int = {
            if let aboutIndex = appMenu.items.firstIndex(where: { $0.action == #selector(NSApplication.orderFrontStandardAboutPanel(_:)) }) {
                return min(appMenu.items.count, aboutIndex + 2)
            }
            return min(appMenu.items.count, 1)
        }()

        appMenu.insertItem(settingsItem, at: insertIndex)

        // Ensure standard separation from Services/Hide/Quit groups.
        let settingsIndex = insertIndex
        if appMenu.items.indices.contains(settingsIndex + 1), !appMenu.items[settingsIndex + 1].isSeparatorItem {
            appMenu.insertItem(.separator(), at: settingsIndex + 1)
        }
    }

    private static func ensureEditMenu(in mainMenu: NSMenu) {
        let editMenuItem = mainMenu.items.first(where: { $0.title == "Edit" || $0.submenu?.title == "Edit" })
        let editMenu: NSMenu

        if let item = editMenuItem, let submenu = item.submenu {
            editMenu = submenu
        } else {
            let item = NSMenuItem(title: "Edit", action: nil, keyEquivalent: "")
            let menu = NSMenu(title: "Edit")
            item.submenu = menu
            let insertIndex = min(mainMenu.items.count, 1)
            mainMenu.insertItem(item, at: insertIndex)
            editMenu = menu
        }

        ensureStandardEditAction(title: "Cut", action: #selector(NSText.cut(_:)), keyEquivalent: "x", in: editMenu)
        ensureStandardEditAction(title: "Copy", action: #selector(NSText.copy(_:)), keyEquivalent: "c", in: editMenu)
        ensureStandardEditAction(title: "Paste", action: #selector(NSText.paste(_:)), keyEquivalent: "v", in: editMenu)
    }

    private static func ensureStandardEditAction(
        title: String,
        action: Selector,
        keyEquivalent: String,
        in menu: NSMenu
    ) {
        let existing = menu.items.first(where: { $0.action == action || $0.title == title })
        let item = existing ?? NSMenuItem(title: title, action: action, keyEquivalent: keyEquivalent)
        item.title = title
        item.action = action
        item.keyEquivalent = keyEquivalent
        item.keyEquivalentModifierMask = [.command]
        item.target = nil
        if existing == nil {
            menu.addItem(item)
        }
    }
}

final class SettingsWindowController: NSWindowController, NSWindowDelegate {
    static let shared = SettingsWindowController()

    private weak var previouslyKeyWindow: NSWindow?

    private init() {
        super.init(window: nil)
    }

    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    @objc func openSettings(_ sender: Any?) {
        if window == nil {
            let tabVC = SettingsTabViewController()

            let w = NSWindow(contentRect: NSRect(x: 0, y: 0, width: 720, height: 520),
                             styleMask: [.titled, .closable, .miniaturizable, .resizable],
                             backing: .buffered,
                             defer: false)
            w.title = "Settings"
            w.isReleasedWhenClosed = false
            w.contentViewController = tabVC
            w.delegate = self
            if #available(macOS 11.0, *) {
                w.toolbarStyle = .preference
            }
            self.window = w
        }

        previouslyKeyWindow = NSApp.keyWindow
        window?.center()
        showWindow(sender)
        window?.makeKeyAndOrderFront(sender)
        NSApp.activate(ignoringOtherApps: true)
    }

    func windowWillClose(_ notification: Notification) {
        // Restore focus to the previously key window when possible.
        if let prev = previouslyKeyWindow, prev.isVisible {
            prev.makeKeyAndOrderFront(nil)
            NSApp.activate(ignoringOtherApps: true)
        }
        previouslyKeyWindow = nil
    }
}

private final class SettingsTabViewController: NSTabViewController {
    override func viewDidLoad() {
        super.viewDidLoad()
        tabStyle = .toolbar

        addTab(.appearance)
        addTab(.documentsPDF)
        addTab(.sharing)
        addTab(.appleIntelligence)
        addTab(.zotero)
        addTab(.advancedDeveloper)
        addTab(.help)
    }

    private func addTab(_ kind: SettingsPaneViewController.Kind) {
        let vc = SettingsPaneViewController(kind: kind)
        let item = NSTabViewItem(viewController: vc)
        item.label = kind.title
        item.image = kind.image
        addTabViewItem(item)
    }
}

