    init(kind: Kind) {
        self.kind = kind
        super.init(nibName: nil, bundle: nil)
        self.title = kind.title
    }

    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    override func loadView() {
        view = NSView(frame: .zero)
        view.translatesAutoresizingMaskIntoConstraints = true
    }

    override func viewDidLoad() {
        super.viewDidLoad()

        let palette = settingsTextPalette()

        let stack = NSStackView()
        stack.orientation = .vertical
        stack.alignment = .leading
        stack.distribution = .fill
        stack.spacing = 12
        stack.translatesAutoresizingMaskIntoConstraints = false

        let introValue = introText()
        if !introValue.isEmpty {
            let intro = NSTextField(wrappingLabelWithString: introValue)
            intro.textColor = palette.secondary
            intro.font = NSFont.systemFont(ofSize: 12)
            intro.translatesAutoresizingMaskIntoConstraints = false

            stack.addArrangedSubview(intro)
            stack.setCustomSpacing(24, after: intro)
        }

        buildControls(into: stack, palette: palette)

        let settingsInset: CGFloat = 28

        let scroll = NSScrollView()
        scroll.translatesAutoresizingMaskIntoConstraints = false
        scroll.drawsBackground = false
        scroll.hasVerticalScroller = true
        scroll.hasHorizontalScroller = false
        scroll.autohidesScrollers = true
        scroll.borderType = .noBorder
        let contentView = FlippedView()
        contentView.translatesAutoresizingMaskIntoConstraints = false
        scroll.documentView = contentView
        contentView.addSubview(stack)

        view.addSubview(scroll)
        let clip = scroll.contentView
        let stackBottom = stack.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -settingsInset)
        stackBottom.priority = .defaultLow
        NSLayoutConstraint.activate([
            scroll.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scroll.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scroll.topAnchor.constraint(equalTo: view.topAnchor),
            scroll.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            contentView.leadingAnchor.constraint(equalTo: clip.leadingAnchor),
            contentView.trailingAnchor.constraint(equalTo: clip.trailingAnchor),
            contentView.topAnchor.constraint(equalTo: clip.topAnchor),
            contentView.bottomAnchor.constraint(greaterThanOrEqualTo: clip.bottomAnchor),
            contentView.widthAnchor.constraint(equalTo: clip.widthAnchor),
            stack.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: settingsInset),
            stack.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -settingsInset),
            stack.topAnchor.constraint(equalTo: contentView.topAnchor, constant: settingsInset),
            contentView.bottomAnchor.constraint(greaterThanOrEqualTo: stack.bottomAnchor, constant: settingsInset),
            stackBottom
        ])
    }

    private func introText() -> String {
        switch kind {
        case .appearance:
            return "Defaults reproduce the current look exactly. Appearance changes apply immediately where possible."
        case .layoutPanels:
            return "Defaults preserve current layout behavior. Layout resets are explicit and require confirmation."
        case .documentsPDF:
            return "Adjust PDF annotation colors and palettes. Performance-sensitive rendering defaults remain unchanged."
        case .search:
            return "Defaults preserve current search dropdown sizing, alignment, and glass appearance."
        case .appleIntelligence:
            return "Customize the six toolbar prompts. Labels become tooltips for the circular buttons. Optionally route each button to a Shortcuts action."
        case .sharing:
            return "Customize the Share button behavior and Shortcuts integration."
        case .help:
            return "Reporting Mode captures diagnostic logs only while active."
        case .zotero:
            return ""
        case .advancedDeveloper:
            return "Developer options are opt-in and safe to disable. Changes take effect on next launch."
        }
    }

    private struct SettingsTextPalette {
        let primary: NSColor
        let secondary: NSColor
        let tertiary: NSColor
    }

    private func settingsTextPalette() -> SettingsTextPalette {
        return SettingsTextPalette(
            primary: NSColor.labelColor,
            secondary: NSColor.secondaryLabelColor,
            tertiary: NSColor.tertiaryLabelColor
        )
    }

    private func appearanceDefaultButton(_ field: AppearanceDefaultField) -> NSButton {
        let button = NSButton(title: "Default", target: self, action: #selector(onAppearanceDefaultButton(_:)))
        button.identifier = NSUserInterfaceItemIdentifier(field.rawValue)
        button.setContentHuggingPriority(.required, for: .horizontal)
        return button
    }

