            libraryRow.addArrangedSubview(refreshButton)
            zoteroLibraryRefreshButton = refreshButton

            stack.addArrangedSubview(libraryRow)

            let collectionRow = NSStackView()
            collectionRow.orientation = .horizontal
            collectionRow.alignment = .centerY
            collectionRow.distribution = .fill
            collectionRow.spacing = 10
            collectionRow.translatesAutoresizingMaskIntoConstraints = false

            let collectionLabel = NSTextField(labelWithString: "Default Collection")
            collectionLabel.font = NSFont.systemFont(ofSize: 12.5, weight: .regular)
            collectionLabel.textColor = palette.primary
            collectionLabel.setContentHuggingPriority(.required, for: .horizontal)
            collectionRow.addArrangedSubview(collectionLabel)

            let collectionPop = NSPopUpButton(frame: .zero, pullsDown: false)
            collectionPop.target = self
            collectionPop.action = #selector(onZoteroCollectionChanged(_:))
            collectionPop.translatesAutoresizingMaskIntoConstraints = false
            collectionPop.widthAnchor.constraint(equalToConstant: 320).isActive = true
            collectionRow.addArrangedSubview(collectionPop)
            zoteroCollectionPopup = collectionPop

            let refreshCollections = NSButton(title: "Refresh", target: self, action: #selector(onRefreshZoteroCollections(_:)))
            collectionRow.addArrangedSubview(refreshCollections)
            zoteroCollectionRefreshButton = refreshCollections

            stack.addArrangedSubview(collectionRow)

            let promptToggle = NSButton(checkboxWithTitle: "Prompt for collection each time you save", target: self, action: #selector(onToggleZoteroCollectionPrompt(_:)))
            promptToggle.state = AppSettingsStore.shared.current.zotero.promptForCollectionsOnSave ? .on : .off
            stack.addArrangedSubview(promptToggle)
            zoteroPromptCollectionsCheckbox = promptToggle

            let zoteroNote = NSTextField(wrappingLabelWithString: "If prompting is off, saves go to the default collection above (or to the library root when no collection is selected).")
            zoteroNote.textColor = palette.secondary
            zoteroNote.font = NSFont.systemFont(ofSize: 12)
            stack.addArrangedSubview(zoteroNote)

            syncZoteroSettingsUI()
            refreshZoteroLibrariesIfNeeded()
            refreshZoteroCollectionsIfNeeded()

        case .advancedDeveloper:
            let label = NSTextField(labelWithString: "Debug")
            label.font = NSFont.systemFont(ofSize: 13, weight: .semibold)
            label.textColor = palette.primary
            stack.addArrangedSubview(label)

            stack.setCustomSpacing(10, after: label)

            let uiDebug = NSButton(checkboxWithTitle: "Enable UI debug overlays (next launch)", target: self, action: #selector(onToggleDeveloperCheckbox(_:)))
            uiDebug.identifier = NSUserInterfaceItemIdentifier("dev.ui")

            let glassDebug = NSButton(checkboxWithTitle: "Enable toolbar glass debug logging (next launch)", target: self, action: #selector(onToggleDeveloperCheckbox(_:)))
            glassDebug.identifier = NSUserInterfaceItemIdentifier("dev.glass")

            syncDeveloperCheckboxes([uiDebug, glassDebug])

            let debugGroup = NSStackView()
            debugGroup.orientation = .vertical
            debugGroup.alignment = .leading
            debugGroup.distribution = .fill
            debugGroup.spacing = 6
            debugGroup.translatesAutoresizingMaskIntoConstraints = false
            debugGroup.addArrangedSubview(uiDebug)
            debugGroup.addArrangedSubview(glassDebug)

            let resetRow = NSStackView()
            resetRow.orientation = .horizontal
            resetRow.alignment = .centerY
            resetRow.distribution = .fill
            resetRow.spacing = 10
            resetRow.translatesAutoresizingMaskIntoConstraints = false

            let reset = NSButton(title: "Reset All Settings…", target: self, action: #selector(onResetAllSettings(_:)))
            resetRow.addArrangedSubview(reset)

            debugGroup.setCustomSpacing(10, after: glassDebug)
            debugGroup.addArrangedSubview(resetRow)
            stack.addArrangedSubview(debugGroup)
        }
    }

    private func buildAppearanceControls(into stack: NSStackView, palette: SettingsTextPalette) {
        appearancePopup = nil
        accentModePopup = nil
        accentColorWell = nil
        accentSystemSwatch = nil
        accentSystemNote = nil
        liquidGlassToggle = nil
        windowTintToggle = nil
        glassTintSourceToggle = nil
        customGlassTintToggle = nil
        glassStyleToggle = nil
        liquidGlassTintSlider = nil
        liquidGlassTintValueLabel = nil
        liquidGlassTintSourcePopup = nil
        liquidGlassTintColorWell = nil
        liquidGlassTintColorRow = nil
        liquidGlassStylePopup = nil
        leftPanelGlassToggles.removeAll()
        leftPanelTintColorWell = nil
        leftPanelTintAlphaSlider = nil
        leftPanelTintAlphaValueLabel = nil
        leftTablePanelBackgroundPopup = nil
        leftTablePanelBackgroundColorWell = nil
        leftTablePanelBackgroundColorRow = nil
        rightAuxGlassToggles.removeAll()
        rightAuxTintColorWell = nil
        rightAuxTintAlphaSlider = nil
        rightAuxTintAlphaValueLabel = nil
        annotationListGlassToggles.removeAll()
        annotationListTintColorWell = nil
        annotationListTintStrengthSlider = nil
        annotationListTintStrengthValueLabel = nil
        annotationComposerTintColorWell = nil
        annotationComposerTintStrengthSlider = nil
        annotationComposerTintStrengthValueLabel = nil
        htmlImagePathFields.removeAll()
        htmlImageStatusLabels.removeAll()
        uiFontValueLabel = nil
        htmlFontValueLabel = nil

        let sectionSpacing: CGFloat = 24
        let glassSectionSpacing: CGFloat = sectionSpacing + 12
        let makeGlassToggle: (_ action: Selector, _ label: String) -> NSButton = { action, label in
            let toggle = NSButton(checkboxWithTitle: "", target: self, action: action)
            toggle.setContentHuggingPriority(.required, for: .horizontal)
            toggle.setContentCompressionResistancePriority(.required, for: .horizontal)
            toggle.setAccessibilityLabel(label)
            return toggle
        }

        let modeHeader = NSTextField(labelWithString: "Appearance Mode")
        modeHeader.font = NSFont.systemFont(ofSize: 13, weight: .semibold)
        modeHeader.textColor = palette.primary
        stack.addArrangedSubview(modeHeader)

        let pop = NSPopUpButton(frame: .zero, pullsDown: false)
        pop.addItems(withTitles: ["System", "Light", "Dark"])
        pop.target = self
        pop.action = #selector(onAppearancePopup(_:))
        pop.translatesAutoresizingMaskIntoConstraints = false
        pop.widthAnchor.constraint(equalToConstant: 220).isActive = true
        syncAppearancePopup(pop)
        let modeRow = NSStackView()
        modeRow.orientation = .horizontal
        modeRow.alignment = .centerY
        modeRow.distribution = .fill
        modeRow.spacing = 10
        modeRow.translatesAutoresizingMaskIntoConstraints = false
        modeRow.addArrangedSubview(pop)
        modeRow.addArrangedSubview(appearanceDefaultButton(.appearanceMode))
        stack.addArrangedSubview(modeRow)
        appearancePopup = pop

        let modeNote = NSTextField(wrappingLabelWithString: "System follows the current macOS appearance dynamically.")
        modeNote.textColor = palette.secondary
        modeNote.font = NSFont.systemFont(ofSize: 11)
        stack.addArrangedSubview(modeNote)
        stack.setCustomSpacing(sectionSpacing, after: modeNote)

        let accentHeader = NSTextField(labelWithString: "App Accent")
        accentHeader.font = NSFont.systemFont(ofSize: 13, weight: .semibold)
        accentHeader.textColor = palette.primary
        stack.addArrangedSubview(accentHeader)

        let accentModeRow = NSStackView()
        accentModeRow.orientation = .horizontal
        accentModeRow.alignment = .centerY
        accentModeRow.distribution = .fill
        accentModeRow.spacing = 10
        accentModeRow.translatesAutoresizingMaskIntoConstraints = false

        let accentModeLabel = NSTextField(labelWithString: "Accent source")
        accentModeLabel.font = NSFont.systemFont(ofSize: 12.5, weight: .regular)
        accentModeLabel.textColor = palette.primary
        accentModeLabel.setContentHuggingPriority(.required, for: .horizontal)
