    private func buildDocumentsPDFControls(into stack: NSStackView, palette: SettingsTextPalette) {
        let sectionSpacing: CGFloat = 24
        annotationPaletteButtons.removeAll()
        annotationPaletteSwatchStrips.removeAll()
        annotationPaletteColorWells.removeAll()
        annotationPaletteColorLabelFields.removeAll()
        annotationPaletteLabelFields.removeAll()
        annotationPaletteResetButton = nil
        annotationPaletteSystemNote = nil

        let header = NSTextField(labelWithString: "Annotation Colors")
        header.font = NSFont.systemFont(ofSize: 13, weight: .semibold)
        header.textColor = palette.primary
        stack.addArrangedSubview(header)

        let helper = NSTextField(wrappingLabelWithString: "Choose a preset palette or customize individual colors. Changes apply to new annotations only; existing annotations keep their current colors unless you update them.")
        helper.textColor = palette.secondary
        helper.font = NSFont.systemFont(ofSize: 12)
        stack.addArrangedSubview(helper)
        stack.setCustomSpacing(12, after: helper)

        let settings = AppSettingsStore.shared.current.documentsPDF
        let definitions = annotationPaletteDefinitions(using: settings)
        let defaultDefinitions = definitions.filter { $0.kind != .custom }
        let customDefinitions = definitions.filter { $0.kind == .custom }
        let radioFont = NSFont.systemFont(ofSize: 12.5, weight: .regular)
        let labelStrings = definitions.map { annotationPaletteDisplayName(for: $0, settings: settings) }
        let maxLabelWidth = labelStrings.map { ($0 as NSString).size(withAttributes: [.font: radioFont]).width }.max() ?? 120
        let labelColumnWidth = max(140, ceil(maxLabelWidth + 26))

        func buildPaletteRow(for def: AnnotationPaletteDefinition) -> NSStackView {
            let row = NSStackView()
            row.orientation = .horizontal
            row.alignment = .centerY
            row.distribution = .fill
            row.spacing = 10
            row.translatesAutoresizingMaskIntoConstraints = false

            let labelColumn = NSStackView()
            labelColumn.orientation = .horizontal
            labelColumn.alignment = .centerY
            labelColumn.distribution = .fill
            labelColumn.spacing = 6
            labelColumn.translatesAutoresizingMaskIntoConstraints = false

            let radio = NSButton(radioButtonWithTitle: "", target: self, action: #selector(onAnnotationPaletteSelected(_:)))
            radio.font = radioFont
            radio.identifier = NSUserInterfaceItemIdentifier(def.id)
            radio.translatesAutoresizingMaskIntoConstraints = false
            radio.setContentHuggingPriority(.required, for: .horizontal)
            labelColumn.addArrangedSubview(radio)
            annotationPaletteButtons.append(radio)

            let labelField = NSTextField(string: "")
            labelField.font = radioFont
            labelField.textColor = palette.primary
            labelField.isEditable = true
            labelField.isBordered = false
            labelField.drawsBackground = false
            labelField.usesSingleLineMode = true
            labelField.cell?.isScrollable = true
            labelField.focusRingType = .default
            labelField.delegate = self
            labelField.placeholderString = def.name
            labelField.identifier = NSUserInterfaceItemIdentifier("palette.label.\(def.id)")
            labelField.setContentHuggingPriority(.defaultLow, for: .horizontal)
            labelField.setContentCompressionResistancePriority(.defaultLow, for: .horizontal)
            labelColumn.addArrangedSubview(labelField)
            annotationPaletteLabelFields[def.id] = labelField

            labelColumn.widthAnchor.constraint(equalToConstant: labelColumnWidth).isActive = true
            labelColumn.setContentHuggingPriority(.required, for: .horizontal)
            row.addArrangedSubview(labelColumn)

            let colors = resolvedAnnotationPaletteColors(id: def.id,
                                                        settings: settings,
                                                        overrides: settings.annotationPaletteOverrides,
                                                        allowOverrides: def.kind == AnnotationPaletteKind.preset)
            let strip = PaletteSwatchStripView(colors: colors)
            strip.translatesAutoresizingMaskIntoConstraints = false
            row.addArrangedSubview(strip)
            annotationPaletteSwatchStrips[def.id] = strip
            return row
        }

        let paletteGrid = NSStackView()
        paletteGrid.orientation = .vertical
        paletteGrid.alignment = .leading
        paletteGrid.distribution = .fill
        paletteGrid.spacing = 8
        paletteGrid.translatesAutoresizingMaskIntoConstraints = false

        let rowCount = max(defaultDefinitions.count, customDefinitions.count)
        for index in 0..<rowCount {
            let row = NSStackView()
            row.orientation = .horizontal
            row.alignment = .centerY
            row.distribution = .fill
            row.spacing = 28
            row.translatesAutoresizingMaskIntoConstraints = false

            if index < defaultDefinitions.count {
                row.addArrangedSubview(buildPaletteRow(for: defaultDefinitions[index]))
            }
            if index < customDefinitions.count {
                row.addArrangedSubview(buildPaletteRow(for: customDefinitions[index]))
            }
            paletteGrid.addArrangedSubview(row)
        }

        stack.addArrangedSubview(paletteGrid)
        stack.setCustomSpacing(sectionSpacing, after: paletteGrid)

        let customHeader = NSTextField(labelWithString: "Customize Colors")
        customHeader.font = NSFont.systemFont(ofSize: 12.5, weight: .semibold)
        customHeader.textColor = palette.primary
        stack.addArrangedSubview(customHeader)

        let customColorStack = NSStackView()
        customColorStack.orientation = .horizontal
        customColorStack.alignment = .bottom
        customColorStack.distribution = .fillEqually
        customColorStack.spacing = 24
        customColorStack.translatesAutoresizingMaskIntoConstraints = false

        for idx in 0..<6 {
            let column = NSStackView()
            column.orientation = .vertical
            column.alignment = .centerX
            column.distribution = .fill
            column.spacing = 6
            column.translatesAutoresizingMaskIntoConstraints = false

            let well = NSColorWell()
            well.tag = idx
            well.target = self
            well.action = #selector(onAnnotationPaletteColorWell(_:))
            well.translatesAutoresizingMaskIntoConstraints = false
            well.widthAnchor.constraint(equalToConstant: 34).isActive = true
            well.heightAnchor.constraint(equalToConstant: 22).isActive = true
            column.addArrangedSubview(well)
            annotationPaletteColorWells.append(well)

            let field = NSTextField(string: "")
            field.tag = idx
            field.font = NSFont.systemFont(ofSize: 10.5, weight: .regular)
            field.textColor = palette.primary
            field.isEditable = true
            field.isBordered = false
            field.drawsBackground = false
            field.usesSingleLineMode = true
            field.cell?.isScrollable = true
            field.focusRingType = .default
            field.alignment = .center
            field.delegate = self
            field.placeholderString = "Color \(idx + 1)"
            field.identifier = NSUserInterfaceItemIdentifier("palette.colorlabel.\(idx)")
            field.translatesAutoresizingMaskIntoConstraints = false
            field.setContentHuggingPriority(.defaultLow, for: .horizontal)
            field.setContentCompressionResistancePriority(.required, for: .horizontal)
            field.widthAnchor.constraint(greaterThanOrEqualToConstant: 64).isActive = true
            annotationPaletteColorLabelFields.append(field)
            column.addArrangedSubview(field)

            customColorStack.addArrangedSubview(column)
        }

        stack.addArrangedSubview(customColorStack)

        let resetRow = NSStackView()
        resetRow.orientation = .horizontal
        resetRow.alignment = .centerY
        resetRow.distribution = .fill
        resetRow.spacing = 10
        resetRow.translatesAutoresizingMaskIntoConstraints = false

        let reset = NSButton(title: "Reset Palette", target: self, action: #selector(onResetAnnotationPalette(_:)))
        resetRow.addArrangedSubview(reset)
        annotationPaletteResetButton = reset
        stack.addArrangedSubview(resetRow)

        let systemNote = NSTextField(wrappingLabelWithString: "System Tint follows the macOS accent color and updates automatically.")
        systemNote.textColor = palette.tertiary
        systemNote.font = NSFont.systemFont(ofSize: 11)
        stack.addArrangedSubview(systemNote)
        annotationPaletteSystemNote = systemNote

        installAnnotationPaletteObserversIfNeeded()
        syncDocumentsPDFSettingsUI()
    }

    private func buildAppleIntelligenceControls(into stack: NSStackView, palette: SettingsTextPalette) {
        appleIntelligenceLabelFields.removeAll()
        appleIntelligencePromptViews.removeAll()
        appleIntelligenceShortcutFields.removeAll()
        appleIntelligenceShortcutToggle = nil
        let sectionSpacing: CGFloat = 24

        let header = NSTextField(labelWithString: "Toolbar prompts")
        header.font = NSFont.systemFont(ofSize: 13, weight: .semibold)
        header.textColor = palette.primary
        stack.addArrangedSubview(header)

        let resetRow = NSStackView()
        resetRow.orientation = .horizontal
        resetRow.alignment = .centerY
        resetRow.distribution = .fill
        resetRow.spacing = 10
        resetRow.translatesAutoresizingMaskIntoConstraints = false

        let reset = NSButton(title: "Restore Defaults", target: self, action: #selector(onResetAppleIntelligencePrompts(_:)))
        resetRow.addArrangedSubview(reset)
        stack.addArrangedSubview(resetRow)

        let helper = NSTextField(wrappingLabelWithString: "Edit each label and prompt. Labels become the tooltips for the six circular buttons.")
        helper.textColor = palette.secondary
        helper.font = NSFont.systemFont(ofSize: 12)
        stack.addArrangedSubview(helper)
        stack.setCustomSpacing(14, after: helper)

        var settings = AppSettingsStore.shared.current.appleIntelligence
        settings.normalize()
        let buttonCount = AppSettings.AppleIntelligence.defaultButtons.count

        let shortcutToggleRow = NSStackView()
        shortcutToggleRow.orientation = .horizontal
        shortcutToggleRow.alignment = .centerY
        shortcutToggleRow.distribution = .fill
        shortcutToggleRow.spacing = 10
        shortcutToggleRow.translatesAutoresizingMaskIntoConstraints = false

        let shortcutToggle = NSButton(checkboxWithTitle: "Use Shortcuts for toolbar buttons", target: self, action: #selector(onAppleIntelligenceShortcutToggle(_:)))
        shortcutToggle.state = settings.useShortcuts ? .on : .off
        shortcutToggleRow.addArrangedSubview(shortcutToggle)
        stack.addArrangedSubview(shortcutToggleRow)
        appleIntelligenceShortcutToggle = shortcutToggle

        let shortcutHelper = NSTextField(wrappingLabelWithString: "When enabled (or when a Shortcut name is set for a button), each button runs its configured Shortcut. Shortcuts run only when a PDF is visible and receive the current PDF file as input.")
        shortcutHelper.textColor = palette.secondary
        shortcutHelper.font = NSFont.systemFont(ofSize: 12)
        stack.addArrangedSubview(shortcutHelper)
        stack.setCustomSpacing(sectionSpacing, after: shortcutHelper)

        for index in 0..<buttonCount {
            let resolved = settings.resolvedButton(at: index)
            let group = NSStackView()
            group.orientation = .vertical
            group.alignment = .leading
            group.distribution = .fill
            group.spacing = 6
            group.translatesAutoresizingMaskIntoConstraints = false

            let title = NSTextField(labelWithString: "Button \(index + 1)")
            title.font = NSFont.systemFont(ofSize: 12.5, weight: .semibold)
            title.textColor = palette.primary
            group.addArrangedSubview(title)

            let labelRow = NSStackView()
            labelRow.orientation = .horizontal
            labelRow.alignment = .centerY
            labelRow.distribution = .fill
            labelRow.spacing = 10
            labelRow.translatesAutoresizingMaskIntoConstraints = false

            let labelLabel = NSTextField(labelWithString: "Label")
            labelLabel.font = NSFont.systemFont(ofSize: 12.5, weight: .regular)
            labelLabel.textColor = palette.primary
            labelLabel.setContentHuggingPriority(.required, for: .horizontal)
            labelRow.addArrangedSubview(labelLabel)

            let labelField = NSTextField(string: resolved.label)
            labelField.placeholderString = AppSettings.AppleIntelligence.defaultButtons[index].label
            labelField.tag = index
            labelField.target = self
            labelField.action = #selector(onAppleIntelligenceLabelField(_:))
            labelField.delegate = self
            labelField.textColor = palette.primary
            labelField.translatesAutoresizingMaskIntoConstraints = false
            labelField.widthAnchor.constraint(equalToConstant: 220).isActive = true
            labelRow.addArrangedSubview(labelField)
            appleIntelligenceLabelFields.append(labelField)

            group.addArrangedSubview(labelRow)

            let promptLabel = NSTextField(labelWithString: "Prompt")
            promptLabel.font = NSFont.systemFont(ofSize: 12.5, weight: .regular)
            promptLabel.textColor = palette.primary
            group.addArrangedSubview(promptLabel)

            let promptScroll = NSScrollView(frame: .zero)
            promptScroll.hasVerticalScroller = true
            promptScroll.borderType = .bezelBorder
            promptScroll.drawsBackground = false
            promptScroll.translatesAutoresizingMaskIntoConstraints = false
            promptScroll.widthAnchor.constraint(equalToConstant: 520).isActive = true
            promptScroll.heightAnchor.constraint(equalToConstant: 86).isActive = true

            let promptView = NSTextView(frame: .zero)
            promptView.string = resolved.prompt
            promptView.font = NSFont.systemFont(ofSize: 12.5, weight: .regular)
            promptView.textColor = palette.primary
            promptView.isEditable = true
            promptView.isSelectable = true
            promptView.isRichText = false
            promptView.isHorizontallyResizable = false
            promptView.isVerticallyResizable = true
            promptView.autoresizingMask = [.width]
            promptView.textContainerInset = NSSize(width: 6, height: 6)
            promptView.textContainer?.widthTracksTextView = true
            promptView.delegate = self
            promptScroll.documentView = promptView

            appleIntelligencePromptViews.append(promptView)
            group.addArrangedSubview(promptScroll)

            let shortcutRow = NSStackView()
            shortcutRow.orientation = .horizontal
            shortcutRow.alignment = .centerY
            shortcutRow.distribution = .fill
            shortcutRow.spacing = 10
            shortcutRow.translatesAutoresizingMaskIntoConstraints = false

            let shortcutLabel = NSTextField(labelWithString: "Shortcut")
            shortcutLabel.font = NSFont.systemFont(ofSize: 12.5, weight: .regular)
            shortcutLabel.textColor = palette.primary
            shortcutLabel.setContentHuggingPriority(.required, for: .horizontal)
            shortcutRow.addArrangedSubview(shortcutLabel)

            let shortcutField = NSTextField(string: resolved.shortcutName)
            shortcutField.placeholderString = "e.g. Ask AstroStack AI"
            shortcutField.tag = index
            shortcutField.target = self
            shortcutField.action = #selector(onAppleIntelligenceShortcutField(_:))
            shortcutField.delegate = self
            shortcutField.textColor = palette.primary
            shortcutField.translatesAutoresizingMaskIntoConstraints = false
            shortcutField.widthAnchor.constraint(equalToConstant: 320).isActive = true
            shortcutRow.addArrangedSubview(shortcutField)
            appleIntelligenceShortcutFields.append(shortcutField)

            group.addArrangedSubview(shortcutRow)

            stack.addArrangedSubview(group)
            stack.setCustomSpacing(sectionSpacing, after: group)
        }

        let restoreAllRow = NSStackView()
        restoreAllRow.orientation = .horizontal
        restoreAllRow.alignment = .centerY
        restoreAllRow.distribution = .fill
        restoreAllRow.spacing = 10
        restoreAllRow.translatesAutoresizingMaskIntoConstraints = false

        let restoreAll = NSButton(title: "Restore All Apple Intelligence Settings to Defaults", target: self, action: #selector(onRestoreAppleIntelligenceDefaults(_:)))
        restoreAllRow.addArrangedSubview(restoreAll)
        stack.addArrangedSubview(restoreAllRow)
    }

    private func installAppearanceSettingsObserversIfNeeded() {
        guard kind == .appearance else { return }
        guard appearanceSettingsObservers.isEmpty else { return }
        let center = NotificationCenter.default
        appearanceSettingsObservers.append(center.addObserver(
            forName: .astroStackSettingsDidChange,
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.syncAppearanceSettingsUI()
        })
        appearanceSettingsObservers.append(center.addObserver(
            forName: .arxivAppearanceDidChange,
            object: AppearanceManager.shared,
            queue: .main
        ) { [weak self] _ in
            self?.syncAppearanceSettingsUI()
        })
        appearanceSettingsObservers.append(center.addObserver(
            forName: NSColor.systemColorsDidChangeNotification,
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.syncAppearanceSettingsUI()
        })
        appearanceSettingsObservers.append(center.addObserver(
            forName: UserDefaults.didChangeNotification,
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.syncAppearanceSettingsUI()
        })
    }

    private func syncAppearanceSettingsUI() {
        guard kind == .appearance else { return }
        if isSyncingAppearanceUI { return }
        isSyncingAppearanceUI = true
        defer { isSyncingAppearanceUI = false }
        let palette = settingsTextPalette()
        let settings = AppSettingsStore.shared.current.appearance
        if let pop = appearancePopup {
            syncAppearancePopup(pop)
        }
        if let pop = accentModePopup {
            switch settings.accentMode {
            case .system: pop.selectItem(at: 0)
            case .custom: pop.selectItem(at: 1)
            }
        }
        if let swatch = accentSystemSwatch {
            let color = resolvedSystemAccentDisplayColor()
            swatch.layer?.backgroundColor = (color.usingColorSpace(.deviceRGB) ?? color).withAlphaComponent(1.0).cgColor
        }
        if let note = accentSystemNote {
            note.stringValue = "Using macOS accent color."
        }
        if let well = accentColorWell {
            if let color = colorFromHex(settings.customAccentHex) {
                well.color = color
            } else {
                well.color = resolvedAppAccentColor()
            }
            well.isEnabled = settings.accentMode == .custom
        }
        if let toggle = liquidGlassToggle {
            toggle.state = settings.liquidGlassEnabled ? .on : .off
        }
        if let toggle = windowTintToggle {
            toggle.state = settings.windowTintEnabled ? .on : .off
        }
        if let toggle = glassTintSourceToggle {
            toggle.state = settings.glassTintSourceEnabled ? .on : .off
        }
        if let toggle = customGlassTintToggle {
            toggle.state = settings.customGlassTintEnabled ? .on : .off
        }
        if let toggle = glassStyleToggle {
            toggle.state = settings.glassStyleEnabled ? .on : .off
        }
        for toggle in leftPanelGlassToggles {
            toggle.state = settings.leftPanelGlassEnabled ? .on : .off
        }
        for toggle in rightAuxGlassToggles {
            toggle.state = settings.rightAuxGlassEnabled ? .on : .off
        }
        for toggle in annotationListGlassToggles {
            toggle.state = settings.annotationListGlassEnabled ? .on : .off
        }
        if let slider = liquidGlassTintSlider {
            let value = max(0.0, min(2.0, settings.liquidGlassTintStrength))
            let effective = (settings.liquidGlassEnabled
                             && settings.windowTintEnabled
                             && settings.glassTintSourceEnabled
                             && settings.glassTintSource != .none) ? value : 0.0
            slider.doubleValue = effective
            slider.isEnabled = settings.liquidGlassEnabled
                && settings.windowTintEnabled
                && settings.glassTintSourceEnabled
                && settings.glassTintSource != .none
        }
        if let label = liquidGlassTintValueLabel {
            if settings.liquidGlassEnabled
                && settings.windowTintEnabled
                && settings.glassTintSourceEnabled
                && settings.glassTintSource != .none {
                let pct = Int(round(max(0.0, min(2.0, settings.liquidGlassTintStrength)) * 100.0))
                label.stringValue = "\(pct)%"
            } else {
                label.stringValue = "Off"
            }
        }

        if let pop = liquidGlassTintSourcePopup {
            switch settings.glassTintSource {
            case .none: pop.selectItem(at: 0)
            case .appAccent: pop.selectItem(at: 1)
            case .custom: pop.selectItem(at: 2)
            }
            pop.isEnabled = settings.glassTintSourceEnabled
        }
        if let well = liquidGlassTintColorWell {
            if let color = colorFromHex(settings.customGlassTintHex) {
                well.color = color
            } else {
                well.color = resolvedAppAccentColor()
            }
            well.isEnabled = settings.glassTintSourceEnabled
                && settings.customGlassTintEnabled
                && settings.glassTintSource == .custom
        }
        if let row = liquidGlassTintColorRow {
            row.isHidden = !(settings.glassTintSource == .custom)
        }
        if let pop = liquidGlassStylePopup {
            switch settings.glassStyle {
            case .followApp: pop.selectItem(at: 0)
            case .light: pop.selectItem(at: 1)
            case .dark: pop.selectItem(at: 2)
            }
            pop.isEnabled = settings.glassStyleEnabled
        }
        if let well = leftPanelTintColorWell {
            let trimmed = settings.leftPanelTintHex.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
                well.color = color
            } else {
                let isDark = resolvedGlassAppearanceIsDark()
                let fallback: NSColor
                switch settings.glassTintSource {
                case .none:
                    let base = resolvedSystemColor(.windowBackgroundColor)
                    let neutral = isDark ? NSColor.black : NSColor.white
                    fallback = blend(base, neutral, t: isDark ? 0.35 : 0.18)
                case .appAccent:
                    fallback = resolvedAppAccentColor()
                case .custom:
                    if let color = colorFromHex(settings.customGlassTintHex) {
                        fallback = color
                    } else {
                        fallback = resolvedAppAccentColor()
                    }
                }
                well.color = fallback
            }
            well.isEnabled = settings.leftPanelGlassEnabled
        }
        if let slider = leftPanelTintAlphaSlider {
            let value = max(0.0, min(1.0, settings.leftPanelTintAlpha))
            slider.doubleValue = value
            slider.isEnabled = settings.leftPanelGlassEnabled
        }
        if let label = leftPanelTintAlphaValueLabel {
            let value = max(0.0, min(1.0, settings.leftPanelTintAlpha))
            let pct = Int(round(value * 100.0))
            label.stringValue = settings.leftPanelGlassEnabled ? "\(pct)%" : "Off"
        }
        if let pop = leftTablePanelBackgroundPopup {
            switch settings.leftTablePanelBackgroundMode {
            case .automatic: pop.selectItem(at: 0)
            case .custom: pop.selectItem(at: 1)
            }
        }
        if let well = leftTablePanelBackgroundColorWell {
            let trimmed = settings.leftTablePanelBackgroundHex.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
                well.color = color
            } else {
                well.color = tablePanelAutomaticTintPreviewColor()
            }
            well.isEnabled = settings.leftTablePanelBackgroundMode == .custom
        }
        if let row = leftTablePanelBackgroundColorRow {
            row.isHidden = settings.leftTablePanelBackgroundMode != .custom
        }
        if let well = rightAuxTintColorWell {
            let trimmed = settings.rightAuxTintHex.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
                well.color = color
            } else {
                well.color = NSColor(white: RIGHT_AUX_GLASS_TINT_WHITE, alpha: 1.0)
            }
            well.isEnabled = settings.rightAuxGlassEnabled
        }
        if let slider = rightAuxTintAlphaSlider {
            let value = max(0.0, min(1.0, settings.rightAuxTintAlpha))
            slider.doubleValue = value
            slider.isEnabled = settings.rightAuxGlassEnabled
        }
        if let label = rightAuxTintAlphaValueLabel {
            let value = max(0.0, min(1.0, settings.rightAuxTintAlpha))
            let pct = Int(round(value * 100.0))
            label.stringValue = settings.rightAuxGlassEnabled ? "\(pct)%" : "Off"
        }
        if let well = annotationListTintColorWell {
            let trimmed = settings.annotationListTintHex.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
                well.color = color
            } else {
                well.color = resolvedSystemColor(.textBackgroundColor)
            }
            well.isEnabled = settings.annotationListGlassEnabled
        }
        if let slider = annotationListTintStrengthSlider {
            let value = max(0.0, min(1.0, settings.annotationListTintStrength))
            slider.doubleValue = value
            slider.isEnabled = settings.annotationListGlassEnabled
        }
        if let label = annotationListTintStrengthValueLabel {
            let value = max(0.0, min(1.0, settings.annotationListTintStrength))
            let pct = Int(round(value * 100.0))
            label.stringValue = settings.annotationListGlassEnabled ? "\(pct)%" : "Off"
        }
        if let well = annotationComposerTintColorWell {
            let trimmed = settings.annotationComposerTintHex.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty, let color = colorFromHex(trimmed) {
                well.color = color
            } else {
                well.color = resolvedAppAccentDisplayColor()
            }
        }
        if let slider = annotationComposerTintStrengthSlider {
            let value = max(0.0, min(1.0, settings.annotationComposerTintStrength))
            slider.doubleValue = value
        }
        if let label = annotationComposerTintStrengthValueLabel {
            let value = max(0.0, min(1.0, settings.annotationComposerTintStrength))
            let pct = Int(round(value * 100.0))
            label.stringValue = "\(pct)%"
        }

        let fallbackPaths: [String: String] = [
            "html.left": AppearanceDefaults.defaults.htmlImages.leftPath,
            "html.center": AppearanceDefaults.defaults.htmlImages.centerPath,
            "html.right": AppearanceDefaults.defaults.htmlImages.rightPath
        ]
        let storedPaths: [String: String] = [
            "html.left": settings.htmlImages.leftPath,
            "html.center": settings.htmlImages.centerPath,
            "html.right": settings.htmlImages.rightPath
        ]
        for (key, field) in htmlImagePathFields {
            let stored = storedPaths[key] ?? ""
            if field.stringValue != stored {
                field.stringValue = stored
            }
            let trimmed = stored.trimmingCharacters(in: .whitespacesAndNewlines)
            let fallback = fallbackPaths[key] ?? ""
            let status = htmlImageStatusLabels[key]
            if trimmed.isEmpty {
                field.textColor = palette.primary
                status?.stringValue = "Using default: \(fallback)"
                status?.textColor = palette.tertiary
                status?.isHidden = false
            } else {
                let expanded = (trimmed as NSString).expandingTildeInPath
                let fallbackExpanded = (fallback as NSString).expandingTildeInPath
                let normalizedStored = URL(fileURLWithPath: expanded).standardized.path
                let normalizedFallback = URL(fileURLWithPath: fallbackExpanded).standardized.path
                let isDefaultPath = !fallback.isEmpty && normalizedStored == normalizedFallback
                if FileManager.default.fileExists(atPath: expanded) {
                    field.textColor = palette.primary
                    if isDefaultPath {
                        status?.stringValue = "Using default: \(fallback)"
                        status?.textColor = palette.tertiary
                        status?.isHidden = false
                    } else {
                        status?.isHidden = true
                    }
                } else {
                    field.textColor = resolvedSystemColor(.systemRed)
                    status?.stringValue = "File not found"
                    status?.textColor = resolvedSystemColor(.systemRed)
                    status?.isHidden = false
                }
            }
        }

        if let label = uiFontValueLabel {
            let fonts = AppSettingsStore.shared.current.appearance.fonts
            let base = resolvedUIFontFromSettings(defaultSize: 12.75, weight: .regular)
            let name = base.displayName ?? base.fontName
            if fonts.uiFontName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                label.stringValue = "System (\(String(format: "%.1f", base.pointSize)) pt)"
            } else {
                label.stringValue = "\(name) (\(String(format: "%.1f", base.pointSize)) pt)"
            }
        }
        if let label = htmlFontValueLabel {
            let fonts = AppSettingsStore.shared.current.appearance.fonts
            if let override = resolvedHTMLFontOverride() {
                let name = override.font.displayName ?? override.font.fontName
                label.stringValue = "\(name) (\(String(format: "%.1f", override.font.pointSize)) pt)"
            } else if fonts.htmlFontName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                label.stringValue = "System default"
            } else {
                label.stringValue = "Unavailable font"
            }
        }
    }

    private struct EmailAppOption {
        let title: String
        let bundleID: String
    }

    private func emailAppOptions() -> [EmailAppOption] {
        var ids = Set<String>()
        if let raw = LSCopyAllHandlersForURLScheme("mailto" as CFString)?.takeRetainedValue() as? [String] {
            ids.formUnion(raw)
        }
        ids.insert("com.apple.mail")

        var options: [EmailAppOption] = []
        for id in ids {
            guard let url = NSWorkspace.shared.urlForApplication(withBundleIdentifier: id) else { continue }
            let name = FileManager.default.displayName(atPath: url.path)
            options.append(EmailAppOption(title: name, bundleID: id))
        }
        options.sort { $0.title.localizedCaseInsensitiveCompare($1.title) == .orderedAscending }
        return options
    }

    private func populateEmailAppPopup() {
        guard let popup = emailAppPopup else { return }
        popup.removeAllItems()
        popup.addItem(withTitle: "System Default")
        popup.lastItem?.representedObject = ""
        for option in emailAppOptions() {
            popup.addItem(withTitle: option.title)
            popup.lastItem?.representedObject = option.bundleID
        }
    }

    private func syncSharingSettingsUI() {
        guard kind == .sharing else { return }
        if isSyncingSharingUI { return }
        isSyncingSharingUI = true
        defer { isSyncingSharingUI = false }
        let current = AppSettingsStore.shared.current
        let settings = current.sharingExport.email
        if let field = shortcutNameField {
            field.stringValue = current.shortcuts.shortcutName
        }
        if let toggle = shortcutXCallbackToggle {
            toggle.state = current.shortcuts.useXCallback ? .on : .off
        }
        if let toggle = shortcutInputToggle {
            toggle.state = current.shortcuts.inputTextMode ? .on : .off
        }
        if let popup = emailAppPopup {
            let target = settings.defaultEmailAppBundleID.trimmingCharacters(in: .whitespacesAndNewlines)
            var found = false
            for item in popup.itemArray {
                if (item.representedObject as? String) == target {
                    popup.select(item)
                    found = true
                    break
                }
            }
            if !found {
                popup.selectItem(at: 0)
            }
        }
        if let field = emailSubjectField {
            field.stringValue = settings.defaultSubjectTemplate
        }
        if let field = emailToField {
            field.stringValue = settings.defaultToAddress
        }
        if let field = emailFromField {
            field.stringValue = settings.defaultFromAddress
        }
        if let view = emailBodyView {
            if view.string != settings.defaultBodyTemplate {
                view.string = settings.defaultBodyTemplate
            }
        }
    }

    private func scheduleAnnotationPaletteSync() {
        guard !annotationPaletteSyncScheduled else { return }
        annotationPaletteSyncScheduled = true
        DispatchQueue.main.async { [weak self] in
            guard let self else { return }
            self.annotationPaletteSyncScheduled = false
            self.syncDocumentsPDFSettingsUI()
        }
    }

    private func installAnnotationPaletteObserversIfNeeded() {
        guard kind == .documentsPDF else { return }
        guard annotationPaletteObservers.isEmpty else { return }
        let center = NotificationCenter.default
        annotationPaletteObservers.append(center.addObserver(
            forName: .astroStackSettingsDidChange,
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.scheduleAnnotationPaletteSync()
        })
        annotationPaletteObservers.append(center.addObserver(
            forName: NSColor.systemColorsDidChangeNotification,
            object: nil,
            queue: .main
        ) { [weak self] _ in
            self?.scheduleAnnotationPaletteSync()
        })
        annotationPaletteObservers.append(center.addObserver(
            forName: .arxivAppearanceDidChange,
            object: AppearanceManager.shared,
            queue: .main
        ) { [weak self] _ in
            self?.scheduleAnnotationPaletteSync()
        })
        annotationPaletteObservers.append(center.addObserver(
            forName: UserDefaults.didChangeNotification,
            object: nil,
            queue: .main
        ) { [weak self] _ in
            guard let self else { return }
            if self.isSyncingAnnotationPaletteUI { return }
            let now = ProcessInfo.processInfo.systemUptime
            if now - self.lastAnnotationPaletteSyncTime < 0.25 { return }
            self.scheduleAnnotationPaletteSync()
        })
    }

    private func syncDocumentsPDFSettingsUI() {
        guard kind == .documentsPDF else { return }
        if isSyncingAnnotationPaletteUI { return }
        isSyncingAnnotationPaletteUI = true
        defer { isSyncingAnnotationPaletteUI = false }
        lastAnnotationPaletteSyncTime = ProcessInfo.processInfo.systemUptime
        let settings = AppSettingsStore.shared.current.documentsPDF
        let resolved = resolvedAnnotationPalette(using: settings)

        for button in annotationPaletteButtons {
            if button.identifier?.rawValue == resolved.definition.id {
                button.state = .on
            } else {
                button.state = .off
            }
        }

        let definitions = annotationPaletteDefinitions(using: settings)
        for def in definitions {
            let displayName = annotationPaletteDisplayName(for: def, settings: settings)
            if let field = annotationPaletteLabelFields[def.id] {
                if field.currentEditor() == nil, field.stringValue != displayName {
                    field.stringValue = displayName
                }
                field.placeholderString = def.name
            }
            if let radio = annotationPaletteButtons.first(where: { $0.identifier?.rawValue == def.id }) {
                radio.setAccessibilityLabel(displayName)
                radio.toolTip = nil
                if #available(macOS 10.13, *) {
                    radio.setAccessibilityLabel(displayName)
                }
            }
            guard let strip = annotationPaletteSwatchStrips[def.id] else { continue }
            let colors = resolvedAnnotationPaletteColors(id: def.id,
                                                        settings: settings,
                                                        overrides: settings.annotationPaletteOverrides,
                                                        allowOverrides: def.kind == AnnotationPaletteKind.preset)
            strip.colors = colors
        }

        let colors = resolved.colors
        for (idx, well) in annotationPaletteColorWells.enumerated() {
            if idx < colors.count {
                let next = colors[idx]
                if !paletteColorsMatch(well.color, next) {
                    well.color = next
                }
            }
        }

        let allowOverrides = (resolved.definition.kind == AnnotationPaletteKind.preset ||
                              resolved.definition.kind == AnnotationPaletteKind.custom)
        for well in annotationPaletteColorWells {
            well.isEnabled = allowOverrides
        }
        let allowLabelEdit = (resolved.definition.kind == .custom)
        let colorNames = resolved.colorNames
        for (idx, field) in annotationPaletteColorLabelFields.enumerated() {
            if idx < colorNames.count {
                if field.currentEditor() == nil, field.stringValue != colorNames[idx] {
                    field.stringValue = colorNames[idx]
                }
            } else if field.currentEditor() == nil {
                field.stringValue = ""
            }
            field.isEnabled = allowLabelEdit
        }
        switch resolved.definition.kind {
        case .preset:
            annotationPaletteResetButton?.isEnabled = (settings.annotationPaletteOverrides[resolved.definition.id] != nil)
        case .custom:
            annotationPaletteResetButton?.isEnabled = true
        case .system:
            annotationPaletteResetButton?.isEnabled = false
        }
        annotationPaletteSystemNote?.isHidden = (resolved.definition.kind != .system)
    }

