    @objc private func onTestRunShortcut(_ sender: Any?) {
        let settings = AppSettingsStore.shared.current
        let name = settings.shortcuts.shortcutName.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !name.isEmpty else {
            presentNonBlockingAlert(message: "No Shortcut set", informative: "Please set a Shortcut name in Settings.")
            return
        }
        let pickerController = NSApp.windows.compactMap { $0.windowController as? PickerWindowController }.first
        guard let controller = pickerController else {
            presentNonBlockingAlert(message: "No PDF available",
                                    informative: "Open a PDF paper before running this Shortcut.")
            return
        }

        let inputText: String? = {
            guard settings.shortcuts.inputTextMode else { return nil }
            return controller.currentDisplayedArxivURLString()
        }()

        controller.routePDFToShortcut(name: name,
                                      runningLabel: nil,
                                      inputText: inputText,
                                      onResult: { [weak self] result in
                                          guard let self else { return }
                                          if !result.isSuccess {
                                              let message = result.error.isEmpty ? "Shortcut failed." : result.error
                                              self.presentNonBlockingAlert(message: "Shortcut failed", informative: message)
                                          }
                                      },
                                      onRoutingError: { [weak self] error in
                                          guard let self else { return }
                                          self.presentNonBlockingAlert(message: error.alertTitle, informative: error.alertInfo)
                                      })
    }

