                                    informative: "Open the AstroStack window and try again.")
            return
        }
        controller.enterReportingMode(source: "settings")
    }

    private func syncZoteroSettingsUI() {
        guard kind == .zotero else { return }
        let settings = AppSettingsStore.shared.current
        let hasSavedKey = (resolvedZoteroAPIKey() != nil)
        let trimmedUsername = settings.zotero.username.trimmingCharacters(in: .whitespacesAndNewlines)
        let isConnected = hasSavedKey && !trimmedUsername.isEmpty
        zoteroStatusLabel?.stringValue = isConnected ? "Connected as \(trimmedUsername)" : "Not Connected"
        updateZoteroStatusIndicator(isConnected: isConnected)
        let hasLibrary = !settings.zotero.libraryID.isEmpty
        zoteroLibraryPopup?.isEnabled = hasSavedKey
        zoteroLibraryRefreshButton?.isEnabled = hasSavedKey
        zoteroCollectionPopup?.isEnabled = hasSavedKey && hasLibrary
        zoteroCollectionRefreshButton?.isEnabled = hasSavedKey && hasLibrary
        zoteroDisconnectButton?.isEnabled = hasSavedKey
        zoteroPromptCollectionsCheckbox?.isEnabled = hasSavedKey
        zoteroPromptCollectionsCheckbox?.state = settings.zotero.promptForCollectionsOnSave ? .on : .off
        if let field = zoteroAPIKeyField {
            if field.stringValue.isEmpty, let storedKey = ZoteroKeychain.readAPIKey() {
                field.stringValue = storedKey
            }
            if field.stringValue.isEmpty {
                field.placeholderString = hasSavedKey ? "Key stored in Keychain" : "Paste key from zotero.org/settings/keys"
            } else {
                field.placeholderString = ""
            }
        }
        updateZoteroRequestKeyPreview()
    }

    private func updateZoteroStatusIndicator(isConnected: Bool) {
        guard let indicator = zoteroStatusIndicator else { return }
        let color = isConnected ? NSColor.systemGreen : NSColor.systemRed
        indicator.layer?.backgroundColor = color.cgColor
        indicator.layer?.shadowColor = color.cgColor
    }

    private func refreshZoteroLibrariesIfNeeded() {
        guard kind == .zotero else { return }
        guard resolvedZoteroAPIKey() != nil else { return }
        refreshZoteroLibraries()
    }

    private func refreshZoteroLibraries() {
        guard kind == .zotero else { return }
        guard let apiKey = resolvedZoteroAPIKeyForRequest(context: "refresh_libraries") else {
            syncZoteroSettingsUI()
            return
        }
        let settings = AppSettingsStore.shared.current
        let userID = settings.zotero.userID
        let username = settings.zotero.username
        ZoteroAPIClient.fetchLibraries(apiKey: apiKey, userID: userID, username: username) { [weak self] result in
            DispatchQueue.main.async {
                guard let self else { return }
                switch result {
                case .success(let libraries):
                    self.populateZoteroLibraryPopup(libraries)
                case .failure(let error):
                    if let apiError = error as? ZoteroAPIError,
                       apiError.message == "Zotero user ID missing." {
                        self.syncZoteroSettingsUI()
                        return
                    }
                    self.presentNonBlockingAlert(message: "Zotero Library Load Failed", informative: error.localizedDescription)
                }
            }
        }
    }

    private func refreshZoteroCollectionsIfNeeded() {
        guard kind == .zotero else { return }
        guard resolvedZoteroAPIKey() != nil else { return }
        let settings = AppSettingsStore.shared.current
        guard !settings.zotero.libraryID.isEmpty else { return }
        refreshZoteroCollections()
    }

    private func refreshZoteroCollections() {
        guard kind == .zotero else { return }
        guard let apiKey = resolvedZoteroAPIKeyForRequest(context: "refresh_collections") else {
            syncZoteroSettingsUI()
            return
        }
        let settings = AppSettingsStore.shared.current
        guard !settings.zotero.libraryID.isEmpty else {
            zoteroCollectionPopup?.removeAllItems()
            syncZoteroSettingsUI()
            return
        }
        let name = settings.zotero.libraryName.isEmpty
            ? (settings.zotero.libraryType == .user ? "Personal Library" : "Group Library")
            : settings.zotero.libraryName
        let library = ZoteroLibrary(type: settings.zotero.libraryType, id: settings.zotero.libraryID, name: name)
        ZoteroAPIClient.fetchCollections(apiKey: apiKey, library: library) { [weak self] result in
            DispatchQueue.main.async {
                guard let self else { return }
                switch result {
                case .success(let collections):
                    self.populateZoteroCollectionPopup(collections)
                case .failure(let error):
                    self.presentNonBlockingAlert(message: "Zotero Collection Load Failed", informative: error.localizedDescription)
                }
            }
        }
    }

    private func populateZoteroLibraryPopup(_ libraries: [ZoteroLibrary]) {
        guard let pop = zoteroLibraryPopup else { return }
        pop.removeAllItems()
        for library in libraries {
            pop.addItem(withTitle: library.name)
            pop.lastItem?.representedObject = library
        }

        let settings = AppSettingsStore.shared.current
        if let match = libraries.firstIndex(where: { $0.type == settings.zotero.libraryType && $0.id == settings.zotero.libraryID }) {
            pop.selectItem(at: match)
        } else if let idx = libraries.firstIndex(where: { $0.type == .user }) {
            pop.selectItem(at: idx)
            if let library = pop.selectedItem?.representedObject as? ZoteroLibrary {
                applyZoteroLibrarySelection(library)
            }
        }
        syncZoteroSettingsUI()
        refreshZoteroCollectionsIfNeeded()
    }

    private func collectionDisplayNames(for collections: [ZoteroCollection]) -> [(collection: ZoteroCollection, displayName: String)] {
        var map: [String: ZoteroCollection] = [:]
        for collection in collections {
            map[collection.key] = collection
        }
        func buildName(_ collection: ZoteroCollection) -> String {
            var names: [String] = [collection.name]
            var parentKey = collection.parentKey
            var visited: Set<String> = []
            while let key = parentKey, let parent = map[key], !visited.contains(key) {
                visited.insert(key)
                names.insert(parent.name, at: 0)
                parentKey = parent.parentKey
            }
            return names.joined(separator: " / ")
        }
        var out: [(collection: ZoteroCollection, displayName: String)] = []
        for collection in collections {
            out.append((collection: collection, displayName: buildName(collection)))
        }
        return out.sorted { $0.displayName.localizedCaseInsensitiveCompare($1.displayName) == .orderedAscending }
    }

    private func populateZoteroCollectionPopup(_ collections: [ZoteroCollection]) {
        guard let pop = zoteroCollectionPopup else { return }
        pop.removeAllItems()
        pop.addItem(withTitle: "Library root (no collection)")
        pop.lastItem?.representedObject = nil

        let display = collectionDisplayNames(for: collections)
        for entry in display {
            pop.addItem(withTitle: entry.displayName)
            pop.lastItem?.representedObject = entry.collection
        }

        let settings = AppSettingsStore.shared.current
        let key = settings.zotero.defaultCollectionKey
        if key.isEmpty {
            pop.selectItem(at: 0)
        } else if let idx = display.firstIndex(where: { $0.collection.key == key }) {
            pop.selectItem(at: idx + 1)
        } else {
            pop.selectItem(at: 0)
        }
        syncZoteroSettingsUI()
    }

