    private func applyZoteroLibrarySelection(_ library: ZoteroLibrary) {
        AppSettingsStore.shared.update { s in
            if s.zotero.libraryID != library.id || s.zotero.libraryType != library.type {
                s.zotero.defaultCollectionKey = ""
                s.zotero.lastCollectionKey = ""
            }
            s.zotero.libraryType = library.type
            s.zotero.libraryID = library.id
            s.zotero.libraryName = library.name
        }
        refreshZoteroCollectionsIfNeeded()
    }

