    @objc private func onSaveZoteroAPIKey(_ sender: Any?) {
        guard let field = zoteroAPIKeyField else { return }
        let apiKey = field.stringValue
        guard !apiKey.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return }
        logZoteroAPIKeyDiagnostics(context: "settings_save_submit", key: apiKey)
        maybeEnableNormalizedZoteroKeyIfNeeded(for: apiKey)
        connectZotero(apiKey: apiKey, userIDHint: nil)
    }

    @objc private func onDiagnoseZoteroAPIKey(_ sender: Any?) {
        guard let field = zoteroAPIKeyField else { return }
        let apiKey = field.stringValue
        let diagnostics = makeZoteroAPIKeyDiagnostics(apiKey)
        let summary = zoteroAPIKeyDiagnosticsSummary(diagnostics)
        let visualized = zoteroAPIKeyVisualized(apiKey)

        let alert = NSAlert()
        alert.messageText = "Zotero API Key Diagnostics"
        alert.informativeText = summary
        alert.addButton(withTitle: "OK")

        let textView = NSTextView(frame: .zero)
        textView.isEditable = false
        textView.isSelectable = true
        textView.isRichText = false
        textView.string = "visualized_key=\n\(visualized)"
        textView.font = NSFont.monospacedSystemFont(ofSize: 11, weight: .regular)
        textView.textColor = NSColor.labelColor
        textView.textContainerInset = NSSize(width: 6, height: 6)

        let scroll = NSScrollView(frame: NSRect(x: 0, y: 0, width: 460, height: 140))
        scroll.hasVerticalScroller = true
        scroll.borderType = .bezelBorder
        scroll.documentView = textView
        alert.accessoryView = scroll

        if let w = view.window {
            alert.beginSheetModal(for: w, completionHandler: nil)
        } else {
            _ = alert.runModal()
        }
    }

    @objc private func onToggleZoteroKeyNormalization(_ sender: NSButton) {
        let isOn = (sender.state == .on)
        AppSettingsStore.shared.update { s in
            s.zotero.useNormalizedKeyForRequests = isOn
        }
        updateZoteroRequestKeyPreview()
    }

    private func updateZoteroRequestKeyPreview() {
        guard kind == .zotero else { return }
        guard let previewField = zoteroRequestKeyPreviewField else { return }
        let raw = zoteroAPIKeyField?.stringValue
            ?? ZoteroKeychain.readAPIKey()
            ?? ""
        guard !raw.isEmpty else {
            previewField.stringValue = ""
            zoteroNormalizeKeyToggle?.state = AppSettingsStore.shared.current.zotero.useNormalizedKeyForRequests ? .on : .off
            return
        }
        let diagnostics = makeZoteroAPIKeyDiagnostics(raw)
        let mode = zoteroAPIKeyRequestMode(for: diagnostics)
        let preview = (mode == .raw) ? raw : normalizeZoteroAPIKeyForRequest(raw).key
        previewField.stringValue = preview
        switch mode {
        case .normalizedExplicit:
            zoteroNormalizeKeyToggle?.state = .on
        case .normalizedAuto:
            zoteroNormalizeKeyToggle?.state = .mixed
        case .raw:
            zoteroNormalizeKeyToggle?.state = .off
        }
    }

    private func markZoteroVerifiedSession(rawKey: String, requestKey: String, info: ZoteroKeyInfo) {
        // Settings pane doesn't keep a separate in-memory auth session; settings updates handle persistence.
        _ = rawKey
        _ = requestKey
        _ = info
    }

    private func clearZoteroVerifiedSession() {
        // No-op for settings pane.
    }

    private func maybeEnableNormalizedZoteroKeyIfNeeded(for raw: String) {
        let diag = makeZoteroAPIKeyDiagnostics(raw)
        guard zoteroAPIKeyNeedsNormalization(diag) else { return }
        updateZoteroRequestKeyPreview()
    }

    private func connectZotero(apiKey: String, userIDHint: String?) {
        logZoteroAPIKeyDiagnostics(context: "connect", key: apiKey)
        let trimmedKey = apiKey.trimmingCharacters(in: .whitespacesAndNewlines)
        fetchZoteroKeyInfoWithFallback(rawKey: trimmedKey, userIDHint: userIDHint, context: "connect") { [weak self] result in
            DispatchQueue.main.async {
                guard let self else { return }
                switch result {
                case .success(let auth):
                    persistZoteroAPIKey(trimmedKey)
                    self.markZoteroVerifiedSession(rawKey: trimmedKey, requestKey: auth.apiKey, info: auth.info)
                    AppSettingsStore.shared.update { s in
                        s.zotero.userID = auth.info.userID
                        s.zotero.username = auth.info.username
                        if s.zotero.libraryID.isEmpty {
                            s.zotero.libraryType = .user
                            s.zotero.libraryID = auth.info.userID
                            s.zotero.libraryName = auth.info.username.isEmpty ? "Personal Library" : auth.info.username
                        }
                    }
                    self.syncZoteroSettingsUI()
                    self.refreshZoteroLibrariesIfNeeded()
                    self.refreshZoteroCollectionsIfNeeded()
                case .failure(let error):
                    self.clearZoteroVerifiedSession()
                    self.syncZoteroSettingsUI()
                    var info = error.localizedDescription
                    if ZoteroKeyDiagnosticsLog.isEnabled {
                        let diag = makeZoteroAPIKeyDiagnostics(trimmedKey)
                        info += "\n\nKey diagnostics (debug):\n" + zoteroAPIKeyDiagnosticsSummary(diag)
                        let candidates = zoteroRequestKeyCandidates(for: trimmedKey)
                        if candidates.count > 1 {
                            let lines = candidates.map { candidate in
                                let masked = zoteroMaskedKey(candidate.key)
                                return "\(candidate.mode.rawValue)=\(masked) fp=\(zoteroAPIKeyFingerprint(candidate.key))"
                            }
                            info += "\n\nRequest candidates (masked):\n" + lines.joined(separator: "\n")
                        }
                    }
                    self.presentNonBlockingAlert(message: "Zotero Connection Failed", informative: info)
                }
            }
        }
    }

    @objc private func onConnectZotero(_ sender: Any?) {
        guard let field = zoteroAPIKeyField, let window = view.window else { return }
        window.makeFirstResponder(field)
        field.selectText(nil)
    }

    @objc private func onDisconnectZotero(_ sender: Any?) {
        _ = ZoteroKeychain.deleteAPIKey()
        cacheZoteroAPIKey(nil)
        clearZoteroVerifiedSession()
        AppSettingsStore.shared.update { s in
            s.zotero.userID = ""
            s.zotero.username = ""
            s.zotero.libraryID = ""
            s.zotero.libraryName = ""
            s.zotero.lastCollectionKey = ""
            s.zotero.defaultCollectionKey = ""
        }
        zoteroLibraryPopup?.removeAllItems()
        zoteroCollectionPopup?.removeAllItems()
        zoteroAPIKeyField?.stringValue = ""
        syncZoteroSettingsUI()
    }

