    @objc private func onHTMLImagePathFieldChanged(_ sender: NSTextField) {
        if isSyncingAppearanceUI { return }
        guard let id = sender.identifier?.rawValue else { return }
        let trimmed = sender.stringValue.trimmingCharacters(in: .whitespacesAndNewlines)
        AppSettingsStore.shared.update { s in
            switch id {
            case "html.left": s.appearance.htmlImages.leftPath = trimmed
            case "html.center": s.appearance.htmlImages.centerPath = trimmed
            case "html.right": s.appearance.htmlImages.rightPath = trimmed
            default: break
            }
        }
        syncAppearanceSettingsUI()
    }

