    @objc private func onChooseHTMLImagePath(_ sender: NSButton) {
        if isSyncingAppearanceUI { return }
        guard let id = sender.identifier?.rawValue else { return }
        let panel = NSOpenPanel()
        panel.canChooseFiles = true
        panel.canChooseDirectories = false
        panel.allowsMultipleSelection = false
        panel.resolvesAliases = true
        panel.prompt = "Choose"
        panel.beginSheetModal(for: view.window ?? NSApp.mainWindow ?? NSWindow()) { [weak self] response in
            guard response == .OK else { return }
            guard let url = panel.url else { return }
            let path = url.path
            AppSettingsStore.shared.update { s in
                switch id {
                case "html.left": s.appearance.htmlImages.leftPath = path
                case "html.center": s.appearance.htmlImages.centerPath = path
                case "html.right": s.appearance.htmlImages.rightPath = path
                default: break
                }
            }
            self?.syncAppearanceSettingsUI()
        }
    }

    @objc private func onSelectUIFont(_ sender: Any?) {
        if isSyncingAppearanceUI { return }
        fontSelectionKind = .ui
        let base = resolvedUIFontFromSettings(defaultSize: 12.75, weight: .regular)
        let manager = NSFontManager.shared
        manager.target = self
        manager.setSelectedFont(base, isMultiple: false)
        manager.orderFrontFontPanel(sender)
    }

    @objc private func onRestoreUIFont(_ sender: Any?) {
        if isSyncingAppearanceUI { return }
        AppSettingsStore.shared.update { s in
            s.appearance.fonts.uiFontName = AppearanceDefaults.defaults.fonts.uiFontName
            s.appearance.fonts.uiFontSize = AppearanceDefaults.defaults.fonts.uiFontSize
        }
        syncAppearanceSettingsUI()
    }

    @objc private func onSelectHTMLFont(_ sender: Any?) {
        if isSyncingAppearanceUI { return }
        fontSelectionKind = .html
        let current = resolvedHTMLFontOverride()?.font ?? NSFont.systemFont(ofSize: 14)
        let manager = NSFontManager.shared
        manager.target = self
        manager.setSelectedFont(current, isMultiple: false)
        manager.orderFrontFontPanel(sender)
    }

    @objc private func onRestoreHTMLFont(_ sender: Any?) {
        if isSyncingAppearanceUI { return }
        AppSettingsStore.shared.update { s in
            s.appearance.fonts.htmlFontName = AppearanceDefaults.defaults.fonts.htmlFontName
            s.appearance.fonts.htmlFontSize = AppearanceDefaults.defaults.fonts.htmlFontSize
        }
        syncAppearanceSettingsUI()
    }

    @objc func changeFont(_ sender: Any?) {
        if isSyncingAppearanceUI { return }
        guard let manager = sender as? NSFontManager else { return }
        guard let kind = fontSelectionKind else { return }
        switch kind {
        case .ui:
            let base = resolvedUIFontFromSettings(defaultSize: 12.75, weight: .regular)
            let next = manager.convert(base)
            AppSettingsStore.shared.update { s in
                s.appearance.fonts.uiFontName = next.fontName
                s.appearance.fonts.uiFontSize = Double(next.pointSize)
            }
        case .html:
            let base = resolvedHTMLFontOverride()?.font ?? NSFont.systemFont(ofSize: 14)
            let next = manager.convert(base)
            AppSettingsStore.shared.update { s in
                s.appearance.fonts.htmlFontName = next.fontName
                s.appearance.fonts.htmlFontSize = Double(next.pointSize)
            }
        }
        syncAppearanceSettingsUI()
    }

