    @objc private func onResetAllSettings(_ sender: Any?) {
        let alert = NSAlert()
        alert.messageText = "Reset All Settings?"
        alert.informativeText = "This resets AstroStack settings to defaults and clears stored panel layout preferences. It does not delete cached PDFs or other temporary files."
        alert.addButton(withTitle: "Reset")
        alert.addButton(withTitle: "Cancel")
        alert.alertStyle = .warning
        let response = alert.runModal()
        guard response == .alertFirstButtonReturn else { return }
        AppSettingsStore.shared.resetToDefaults()
        clearLayoutDefaults()
    }

    @objc private func onResetLayout(_ sender: Any?) {
        let alert = NSAlert()
        alert.messageText = "Reset Layout & Panels?"
        alert.informativeText = "This clears stored panel widths and visibility preferences and will take effect on next launch."
        alert.addButton(withTitle: "Reset")
        alert.addButton(withTitle: "Cancel")
        alert.alertStyle = .warning
        let response = alert.runModal()
        guard response == .alertFirstButtonReturn else { return }

        // Clear known layout keys (new + legacy) without touching other subsystems.
        clearLayoutDefaults()
    }

    func textDidChange(_ notification: Notification) {
        guard let textView = notification.object as? NSTextView else { return }
        if kind == .appleIntelligence {
            guard let index = appleIntelligencePromptViews.firstIndex(where: { $0 === textView }) else { return }
            AppSettingsStore.shared.update { s in
                guard s.appleIntelligence.buttons.indices.contains(index) else { return }
                s.appleIntelligence.buttons[index].prompt = textView.string
            }
            return
        }
        if kind == .sharing, textView === emailBodyView {
            if isSyncingSharingUI { return }
            let body = textView.string
            AppSettingsStore.shared.update { s in
                s.sharingExport.email.defaultBodyTemplate = body
            }
        }
    }

    func controlTextDidChange(_ obj: Notification) {
        guard let field = obj.object as? NSTextField else { return }
        if kind == .zotero, field === zoteroAPIKeyField {
            updateZoteroRequestKeyPreview()
            return
        }
        if kind == .documentsPDF {
            if isSyncingAnnotationPaletteUI { return }
            let labelPrefix = "palette.label."
            let colorLabelPrefix = "palette.colorlabel."
            if let raw = field.identifier?.rawValue {
                if raw.hasPrefix(colorLabelPrefix) {
                    let index = field.tag
                    let settings = AppSettingsStore.shared.current.documentsPDF
                    let def = annotationPaletteDefinition(for: settings.annotationPaletteID, using: settings)
                    guard def.kind == .custom,
                          let paletteIndex = customAnnotationPaletteIndex(for: def.id, in: settings) else {
                        return
                    }
                    let trimmed = field.stringValue.trimmingCharacters(in: .whitespacesAndNewlines)
                    let defaults = AppSettings.DocumentsPDF.defaultCustomPalette(at: paletteIndex).colorLabels
                    let value = trimmed.isEmpty ? (defaults.indices.contains(index) ? defaults[index] : "Color \(index + 1)") : trimmed
                    AppSettingsStore.shared.update { s in
                        guard s.documentsPDF.customPalettes.indices.contains(paletteIndex) else { return }
                        var labels = s.documentsPDF.customPalettes[paletteIndex].colorLabels
                        labels = normalizedPaletteLabels(labels, fallback: defaults)
                        if labels.indices.contains(index) {
                            labels[index] = value
                        } else if index >= 0 && index < 6 {
                            while labels.count <= index {
                                labels.append("Color \(labels.count + 1)")
                            }
                            labels[index] = value
                        }
                        s.documentsPDF.customPalettes[paletteIndex].colorLabels = labels
                    }
                    return
                }
                if raw.hasPrefix(labelPrefix) {
                    let id = String(raw.dropFirst(labelPrefix.count))
                    let trimmed = field.stringValue.trimmingCharacters(in: .whitespacesAndNewlines)
                    let settings = AppSettingsStore.shared.current.documentsPDF
                    if let paletteIndex = customAnnotationPaletteIndex(for: id, in: settings) {
                        let value = trimmed.isEmpty ? customAnnotationPaletteDefaultName(paletteIndex) : trimmed
                        AppSettingsStore.shared.update { s in
                            guard s.documentsPDF.customPalettes.indices.contains(paletteIndex) else { return }
                            s.documentsPDF.customPalettes[paletteIndex].name = value
                        }
                    } else {
                        AppSettingsStore.shared.update { s in
                            if trimmed.isEmpty {
                                s.documentsPDF.annotationPaletteLabels.removeValue(forKey: id)
                            } else {
                                s.documentsPDF.annotationPaletteLabels[id] = trimmed
                            }
                        }
                    }
                    return
                }
            }
        }
        if kind == .appleIntelligence {
            if let index = appleIntelligenceLabelFields.firstIndex(where: { $0 === field }) {
                let trimmed = field.stringValue.trimmingCharacters(in: .whitespacesAndNewlines)
                AppSettingsStore.shared.update { s in
                    guard s.appleIntelligence.buttons.indices.contains(index) else { return }
                    s.appleIntelligence.buttons[index].label = trimmed
                }
                return
            }
            if let index = appleIntelligenceShortcutFields.firstIndex(where: { $0 === field }) {
                let trimmed = field.stringValue.trimmingCharacters(in: .whitespacesAndNewlines)
                AppSettingsStore.shared.update { s in
                    guard s.appleIntelligence.buttons.indices.contains(index) else { return }
                    s.appleIntelligence.buttons[index].shortcutName = trimmed
                }
            }
            return
        }
        if kind == .sharing {
            if isSyncingSharingUI { return }
            if field === emailSubjectField {
                let trimmed = field.stringValue
                AppSettingsStore.shared.update { s in
                    s.sharingExport.email.defaultSubjectTemplate = trimmed
                }
            } else if field === emailToField {
                let trimmed = field.stringValue
                AppSettingsStore.shared.update { s in
                    s.sharingExport.email.defaultToAddress = trimmed
                }
            } else if field === emailFromField {
                let trimmed = field.stringValue
                AppSettingsStore.shared.update { s in
                    s.sharingExport.email.defaultFromAddress = trimmed
                }
            }
        }
    }

    deinit {
        for obs in annotationPaletteObservers {
            NotificationCenter.default.removeObserver(obs)
        }
        annotationPaletteObservers.removeAll()
        for obs in appearanceSettingsObservers {
            NotificationCenter.default.removeObserver(obs)
        }
        appearanceSettingsObservers.removeAll()
    }
}
